def output_url(path):
    if not path:
        return ""
    path_str = str(path).replace("\\", "/")
    if path_str.startswith(f"{OUTPUT_URL_PREFIX}/"):
        return path_str
    if path_str.startswith("/output/"):
        path_str = path_str.replace("/output/", f"{OUTPUT_URL_PREFIX}/", 1)
        return path_str
    try:
        relative_path = os.path.relpath(path_str, BASE_OUTPUT).replace("\\", "/")
    except ValueError:
        return path_str
    if relative_path.startswith(".."):
        return path_str
    return f"{OUTPUT_URL_PREFIX}/{relative_path}"


def zip_analysis_output(repo_id: str, output_repo_dir=None):
    output_dir = Path(output_repo_dir) if output_repo_dir else BASE_OUTPUT / repo_id
    if not output_dir.exists() or not output_dir.is_dir():
        raise FileNotFoundError(f"Analysis output folder not found: {output_dir}")
    output_dir = output_dir.resolve()
    base_output = BASE_OUTPUT.resolve()
    if output_dir == base_output or base_output not in output_dir.parents:
        raise RuntimeError(f"Refusing to zip output directory outside BASE_OUTPUT: {output_dir}")
    zip_path = (BASE_OUTPUT / f"{repo_id}.zip").resolve()
    skip_dirs = {"src", "upload", "__pycache__", "cache"}
    with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        for root, dirs, files in os.walk(output_dir):
            root_path = Path(root).resolve()
            dirs[:] = [
                directory
                for directory in dirs
                if directory not in skip_dirs
                and not directory.startswith(".")
                and not is_generated_output_dir_name(directory)
            ]
            for filename in files:
                path = (root_path / filename).resolve()
                if path == zip_path or path.suffix.lower() == ".zip":
                    continue
                try:
                    rel_path = path.relative_to(output_dir)
                except ValueError:
                    continue
                if any(is_generated_output_dir_name(part) for part in rel_path.parts):
                    continue
                archive.write(path, rel_path.as_posix())
    return str(zip_path)

