def supabase_restore_scim_generated_artifacts(client, run: dict, artifact_types: set[str] | None = None):
    repository = run.get("codeval_repositories") or run.get("repository") or {}
    owner = repository.get("owner_name") or (run.get("analysis_response") or {}).get("owner_name") or ""
    repo = repository.get("repo_name") or (run.get("analysis_response") or {}).get("repo_name") or ""
    if not owner or not repo:
        return {"restored": 0, "reason": "repository owner/repo missing"}
    output_dir = repo_output_dir(owner, repo)
    output_dir.mkdir(parents=True, exist_ok=True)
    restore_types = sorted(artifact_types or SUPABASE_SCIM_RESTORE_TYPES)
    response = supabase_execute(
        "SCIM generated artifact lookup",
        lambda: client.table("codeval_artifacts")
        .select("artifact_type,storage_bucket,storage_path,filename,metadata,created_at")
        .eq("analysis_run_id", run.get("id", ""))
        .in_("artifact_type", restore_types)
        .execute(),
    )
    rows = getattr(response, "data", None) or []
    restored = []
    errors = []
    output_root = output_dir.resolve()
    for row in rows:
        artifact_type = row.get("artifact_type") or ""
        storage_path = row.get("storage_path") or ""
        metadata = row.get("metadata") or {}
        rel_path = str(metadata.get("relative_path") or row.get("filename") or "").replace("\\", "/").strip("/")
        if not artifact_type or not storage_path or not rel_path:
            continue
        try:
            target = (output_dir / rel_path).resolve()
            if output_root not in target.parents and target != output_root:
                errors.append({"artifact_type": artifact_type, "error": "unsafe relative path"})
                continue
            source_time = (
                parse_iso_datetime(row.get("updated_at"))
                or parse_iso_datetime(row.get("created_at"))
                or parse_iso_datetime((metadata or {}).get("generated_at"))
            )
            if target.exists() and source_time:
                local_time = datetime.fromtimestamp(target.stat().st_mtime, tz=source_time.tzinfo)
                if local_time > source_time:
                    restored.append({
                        "artifact_type": artifact_type,
                        "relative_path": rel_path,
                        "skipped": True,
                        "reason": "local artifact is newer than Supabase copy",
                        "source_created_at": row.get("created_at") or "",
                        "source_updated_at": row.get("updated_at") or "",
                    })
                    continue
            target.parent.mkdir(parents=True, exist_ok=True)
            bucket = row.get("storage_bucket") or supabase_artifact_bucket()
            content = client.storage.from_(bucket).download(storage_path)
            if isinstance(content, str):
                target.write_text(content, encoding="utf-8")
            else:
                target.write_bytes(bytes(content or b""))
            restored.append({
                "artifact_type": artifact_type,
                "relative_path": rel_path,
                "restored_at": datetime.now().isoformat(),
                "source_created_at": row.get("created_at") or "",
                "source_updated_at": row.get("updated_at") or "",
            })
        except Exception as e:
            errors.append({"artifact_type": artifact_type, "storage_path": storage_path, "error": str(e)[:500]})
    indexed = {}
    if restored:
        try:
            indexed = index_typed_scim_evidence(output_dir)
            write_scim_layer_manifest(output_dir, indexed)
        except Exception as e:
            indexed = {"indexed": 0, "error": str(e)}
    return {
        "restored": len(restored),
        "restored_artifacts": restored[:50],
        "error_count": len(errors),
        "errors": errors[:10],
        "indexed": indexed,
    }


def supabase_restore_analysis_payload(client, run: dict, expires_in: int = 60 * 60, github_user_id: str | int | None = None):
    payload = dict(run.get("analysis_response") or {})
    if not payload:
        payload = {
            "timestamp": run.get("completed_at") or run.get("created_at") or datetime.now().isoformat(),
            "graphs": {},
        }
    repository = run.get("codeval_repositories") or run.get("repository") or {}
    if repository:
        payload.setdefault("owner_name", repository.get("owner_name", ""))
        payload.setdefault("repo_name", repository.get("repo_name", ""))
        payload.setdefault("repo", repository.get("codeval_repo_key", ""))
        payload.setdefault("repo_id", repository.get("codeval_repo_key", ""))
    payload["restored_from_supabase"] = True
    payload["supabase_analysis_run_id"] = run.get("id", "")
    payload.setdefault("completed_at", run.get("completed_at") or "")
    payload.setdefault("created_at", run.get("created_at") or "")
    for column in (
        "product_name",
        "product_description",
        "feature_names",
        "feature_descriptions",
        "product_metadata_updated_at",
        "product_description_updated_at",
        "feature_names_updated_at",
        "feature_descriptions_updated_at",
    ):
        if run.get(column) is not None:
            target_key = {
                "feature_descriptions": "feature_summaries",
                "feature_descriptions_updated_at": "feature_summaries_updated_at",
            }.get(column, column)
            payload.setdefault(target_key, run.get(column))
    restore_github_user_id = github_user_id or run.get("github_user_id")
    if not payload.get("feature_summaries") and run.get("repository_id"):
        summary_payload = supabase_find_previous_feature_summaries(
            client,
            run.get("repository_id"),
            current_run_id=run.get("id", ""),
            github_user_id=restore_github_user_id,
            limit=50,
        )
        if summary_payload.get("feature_summary_restore_debug"):
            payload["feature_summary_restore_debug"] = summary_payload.get("feature_summary_restore_debug")
        if summary_payload.get("feature_summaries"):
            payload.update(summary_payload)
    restored_scim = supabase_restore_scim_generated_artifacts(client, run)
    owner_name = payload.get("owner_name", "")
    repo_name = payload.get("repo_name", "")
    restored_daily = supabase_restore_daily_commit_snapshots(
        client,
        run.get("repository_id") or (run.get("codeval_repositories") or {}).get("id") or (run.get("repository") or {}).get("id") or "",
        owner_name=owner_name,
        repo_name=repo_name,
        analysis_run_id=run.get("id", ""),
    )
    if restored_daily:
        for key, value in restored_daily.items():
            if key.startswith("daily_"):
                payload[key] = value
            else:
                payload.setdefault(key, value)
    if owner_name and repo_name:
        try:
            artifact_root = artifact_root_for_output(repo_output_dir(owner_name, repo_name))
            if not payload.get("ui_feature_seeds"):
                repo_text_for_seeds = payload.get("repo_text") if isinstance(payload.get("repo_text"), dict) else {}
                repo_text_path = repo_text_artifact_path(artifact_root, "repo_text.json", legacy_ok=True)
                if not repo_text_for_seeds and repo_text_path.exists():
                    try:
                        repo_text_for_seeds = json.loads(repo_text_path.read_text(encoding="utf-8"))
                    except Exception:
                        repo_text_for_seeds = {}
                if repo_text_for_seeds:
                    try:
                        pass
                    except Exception as seed_error:
                        logger.warning("Unable to hydrate UI feature seeds from restored analysis: %s", seed_error)
            feature_summaries, feature_summary_path, features_text_path = load_persisted_feature_summaries(artifact_root)
            if feature_summaries:
                local_generated_at = ""
                try:
                    local_data = json.loads(Path(feature_summary_path).read_text(encoding="utf-8"))
                    local_generated_at = str(local_data.get("generated_at") or "")
                except Exception:
                    local_generated_at = ""
                if (
                    payload.get("feature_summaries")
                    and payload.get("feature_summaries_updated_at")
                    and local_generated_at
                    and not timestamp_is_newer_or_equal(local_generated_at, payload.get("feature_summaries_updated_at"))
                ):
                    payload["feature_summary_restore_skipped"] = "Local feature_summaries.json is older than saved analysis_response feature summaries."
                else:
                    payload["feature_summaries"] = feature_summaries
                    payload["feature_summary_count"] = sum(1 for item in feature_summaries if item.get("description"))
                    payload["feature_summary_url"] = output_url(feature_summary_path)
                    payload["features_text_url"] = output_url(features_text_path)
                    if local_generated_at:
                        payload.setdefault("feature_summaries_updated_at", local_generated_at)
        except Exception as e:
            logger.warning("Unable to hydrate generated feature summaries from restored artifacts: %s", e)
    by_type, signed_artifacts = supabase_artifact_url_map(client, run.get("id", ""), expires_in)
    graphs = dict(payload.get("graphs") or {})
    for artifact_type, keys in ARTIFACT_TYPE_GRAPH_KEYS.items():
        signed_url = by_type.get(artifact_type)
        if not signed_url:
            continue
        for key in keys:
            graphs[key] = signed_url
    if not by_type.get("file_graph_navigatable_html"):
        graphs.pop("file_graph_navigatable_html", None)
        graphs.pop("navigatable_file_callgraph_html", None)
    for key in (
        "feature_catalog",
        "feature_catalog_url",
        "feature_summaries",
        "feature_summary_count",
        "feature_summary_url",
        "feature_summary_restore_debug",
        "feature_summary_restore_skipped",
        "feature_summaries_updated_at",
        "features_text_url",
        "ui_feature_seeds",
    ):
        payload.pop(key, None)
    payload["graphs"] = graphs
    payload["supabase"] = {
        "analysis_run_id": run.get("id", ""),
        "repository_id": run.get("repository_id", ""),
        "artifact_count": len(signed_artifacts),
        "signed_artifacts": signed_artifacts[:20],
        "scim_generated_artifact_restore": restored_scim,
        "restored": True,
    }
    restore_token = mint_search_restore_token(run, owner_name, repo_name, restore_github_user_id)
    if restore_token:
        payload["supabase_search_restore_token"] = restore_token
    return payload


def restore_latest_analysis_artifacts_for_user_repo(
    github_user_id,
    owner: str,
    repo: str,
    artifact_types: set[str] | None = None,
    description: str = "latest saved analysis artifact restore",
):
    """Restore local artifacts from the latest completed analysis run for a
    known GitHub user + repository, without needing a live request/session.

    Shared by /search's restore (session-derived user) and /analyze's
    restore-before-rebuild (user derived from the request session or, for
    background jobs, from the github_context captured at job launch).
    """
    if not github_user_id:
        return {"restored": False, "reason": "no github user id available"}
    client = supabase_runtime_client()
    if not client:
        return {"restored": False, "reason": "Supabase is not configured"}
    repo_response = supabase_execute(
        "restore repository lookup",
        lambda: client.table("codeval_repositories")
        .select("id")
        .eq("owner_name", owner)
        .eq("repo_name", repo)
        .limit(1)
        .execute(),
    )
    repo_rows = getattr(repo_response, "data", None) or []
    repository_ids = [row["id"] for row in repo_rows if row.get("id")]
    if not repository_ids:
        return {"restored": False, "reason": "repository was not found in saved analyses"}
    response = supabase_analysis_runs_for_user(
        client,
        github_user_id,
        "*,codeval_repositories(owner_name,repo_name,full_name,html_url,default_branch,codeval_repo_key)",
        repository_ids=repository_ids,
        completed_only=True,
        limit=1,
        description=description,
    )
    rows = getattr(response, "data", None) or []
    if not rows:
        return {"restored": False, "reason": "no completed saved analysis for this GitHub user and repository"}
    restored_scim = supabase_restore_scim_generated_artifacts(
        client,
        rows[0],
        artifact_types=artifact_types,
    )
    return {
        "restored": True,
        "analysis_run_id": rows[0].get("id", ""),
        "scim_generated_artifact_restore": restored_scim,
    }


def restore_latest_analysis_artifacts_for_search(request: Request, owner: str, repo: str):
    """Restore local artifacts required by /search from the latest saved run.

    Dashboard restore can display signed Supabase URLs without local files, but
    server-side search needs local SCIM/function metadata and graph JSON.
    """
    try:
        _, session = github_session_from_request(request)
        github_user_id = github_session_user_id(session)
    except Exception as e:
        return {"restored": False, "reason": f"github session unavailable: {e}"}
    return restore_latest_analysis_artifacts_for_user_repo(
        github_user_id,
        owner,
        repo,
        artifact_types=SUPABASE_SEARCH_RESTORE_TYPES,
        description="latest saved analysis artifact restore for search",
    )


def restore_analysis_artifacts_for_search_run_id(run_id: str, owner: str, repo: str, request: Request, restore_token: str = ""):
    run_id = str(run_id or "").strip()
    if not run_id:
        return {"restored": False, "reason": "analysis run id was not provided"}
    client = supabase_runtime_client()
    if not client:
        return {"restored": False, "reason": "Supabase is not configured"}
    response = supabase_execute(
        "saved analysis artifact restore by run id",
        lambda: client.table("codeval_analysis_runs")
        .select("*,codeval_repositories(owner_name,repo_name,full_name,html_url,default_branch,codeval_repo_key)")
        .eq("id", run_id)
        .eq("status", "completed")
        .limit(1)
        .execute(),
    )
    rows = getattr(response, "data", None) or []
    if not rows:
        return {"restored": False, "reason": "saved completed analysis run was not found"}
    run = rows[0]
    repository = run.get("codeval_repositories") or run.get("repository") or {}
    run_owner = str(repository.get("owner_name") or "").strip()
    run_repo = str(repository.get("repo_name") or "").strip()
    if run_owner != owner or run_repo != repo:
        return {
            "restored": False,
            "reason": "saved analysis run does not match the selected repository",
            "run_owner": run_owner,
            "run_repo": run_repo,
        }
    token_ok = False
    token_reason = ""
    if restore_token:
        token_ok, token_reason = search_restore_token_authorizes(restore_token, run, owner, repo)
    session_ok, session_reason, github_user_id = github_request_authorizes_analysis_run(request, client, run)
    if not token_ok and not session_ok:
        return {
            "restored": False,
            "reason": "not authorized to restore this saved analysis",
            "token_reason": token_reason or "restore token was not provided",
            "session_reason": session_reason,
        }
    restored_scim = supabase_restore_scim_generated_artifacts(
        client,
        run,
        artifact_types=SUPABASE_SEARCH_RESTORE_TYPES,
    )
    return {
        "restored": True,
        "analysis_run_id": run.get("id", ""),
        "restore_source": "signed_analysis_run_id" if token_ok else "github_authorized_analysis_run_id",
        "authorized_github_user_id": github_user_id if session_ok else "",
        "scim_generated_artifact_restore": restored_scim,
    }


def search_local_artifact_status(output_repo_dir: Path):
    artifact_root = artifact_root_for_output(output_repo_dir)
    paths = [
        artifact_root / "scim" / "vectors.sqlite",
        artifact_root / "scim" / "functions.jsonl",
        artifact_root / "combined_callgraph" / "combined_ordered_call_sequence.json",
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "combined_callgraph" / "combined_navigatable_callgraph.json",
        artifact_root / "python" / "python_ordered_call_sequence.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_ordered_call_sequence.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "csharp" / "csharp_ordered_call_sequence.json",
        artifact_root / "csharp" / "csharp_callgraph.json",
        artifact_root / "javalang" / "javalang_callgraph.json",
        artifact_root / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        artifact_root / "java_merged" / "java_merged_callgraph.json",
    ]
    return {
        "output_repo_dir": str(output_repo_dir),
        "artifact_root": str(artifact_root),
        "paths": [{"path": str(path), "exists": path.exists()} for path in paths],
    }


def search_zero_result_diagnostics(output_repo_dir: Path, query: str, scim_error: str = ""):
    output_repo_dir = Path(output_repo_dir)
    artifact_root = artifact_root_for_output(output_repo_dir)
    query_terms = sorted(search_query_terms(query))
    src_dir = find_cached_source_dir(output_repo_dir)
    ga_artifacts = [
        artifact_root / "ga_interactions.json",
        artifact_root / "ga_ordered_interaction_graph.json",
        artifact_root / "ga_navigatable_ordered_graph.json",
        artifact_root / "ga_event_callgraph_map.json",
        artifact_root / "ga_analysis_graph.json",
    ]
    source_files_checked = False
    if src_dir:
        for root, dirs, files in os.walk(src_dir):
            dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), src_dir)]
            if any(
                os.path.splitext(filename)[1].lower() in SEARCH_TEXT_EXTENSIONS
                and search_text_path_allowed(os.path.relpath(os.path.join(root, filename), src_dir).replace("\\", "/"))
                for filename in files
            ):
                source_files_checked = True
                break

    reasons = []
    if not query_terms:
        reasons.append("The query did not contain searchable terms after stopword filtering.")
    if is_explicit_ga_behavior_query(query, query_terms) and not any(path.exists() for path in ga_artifacts):
        reasons.append("This is an analytics query, but this repo has no saved GA evidence artifacts yet.")
    if not src_dir:
        reasons.append("No cached source directory was available locally, so literal text search had nothing to scan.")
    elif not source_files_checked:
        reasons.append("The cached source directory did not contain searchable text/code files after filters.")
    if not (artifact_root / "scim" / "vectors.sqlite").exists():
        reasons.append("The code embedding index scim/vectors.sqlite was not available locally.")
    if scim_error:
        reasons.append(f"Semantic code search reported: {scim_error}")
    if not reasons:
        reasons.append("No indexed code unit, saved analytics evidence, or scanned source text matched the query terms.")

    return {
        "query_terms": query_terms,
        "source_dir": str(src_dir) if src_dir else "",
        "source_files_checked": source_files_checked,
        "is_analytics_query": is_explicit_ga_behavior_query(query, query_terms),
        "ga_artifacts": [{"path": str(path), "exists": path.exists()} for path in ga_artifacts],
        "scim_vectors_exists": (artifact_root / "scim" / "vectors.sqlite").exists(),
        "scim_functions_exists": (artifact_root / "scim" / "functions.jsonl").exists(),
        "reasons": reasons,
    }


def analysis_payload_is_current(payload: dict):
    if not isinstance(payload, dict):
        return False
    try:
        return int(payload.get("analysis_schema_version", 0) or 0) >= ANALYSIS_SCHEMA_VERSION
    except Exception:
        return False


def github_session_user_id(session: dict):
    user = (session or {}).get("user") or {}
    github_user_id = str(user.get("github_user_id") or user.get("id") or "").strip()
    if not github_user_id:
        raise HTTPException(status_code=401, detail="GitHub user ID is not available. Reconnect GitHub.")
    return int(github_user_id) if github_user_id.isdigit() else github_user_id


def env_truthy(name: str) -> bool:
    return normalize_env_value(os.getenv(name, "")).lower() in {"1", "true", "yes", "on"}


def env_csv_set(name: str) -> set[str]:
    value = normalize_env_value(os.getenv(name, ""))
    return {part.strip().lower() for part in value.split(",") if part.strip()}


def require_debug_enabled(request: Request):
    if not env_truthy("CODEVAL_ENABLE_DEBUG_ROUTES"):
        raise HTTPException(status_code=404, detail="Not found")
    _, session = github_session_from_request(request)
    user = (session or {}).get("user") or {}
    github_user_id = str(user.get("github_user_id") or user.get("id") or "").strip().lower()
    login = str(user.get("login") or "").strip().lower()
    allowed_ids = env_csv_set("CODEVAL_DEBUG_ADMIN_GITHUB_IDS")
    allowed_logins = env_csv_set("CODEVAL_DEBUG_ADMIN_GITHUB_LOGINS")
    if not allowed_ids and not allowed_logins:
        raise HTTPException(status_code=403, detail="Debug routes require CODEVAL_DEBUG_ADMIN_GITHUB_IDS or CODEVAL_DEBUG_ADMIN_GITHUB_LOGINS.")
    if github_user_id not in allowed_ids and login not in allowed_logins:
        raise HTTPException(status_code=403, detail="GitHub user is not authorized for debug routes.")
    return session


def github_private_key():
    raw_key = normalize_env_value(os.getenv("GITHUB_PRIVATE_KEY", ""))
    key_path = normalize_env_value(os.getenv("GITHUB_PRIVATE_KEY_PATH", ""))
    if raw_key:
        return raw_key.replace("\\n", "\n")
    if key_path and Path(key_path).exists():
        return Path(key_path).read_text(encoding="utf-8")
    raise HTTPException(status_code=503, detail="GitHub App private key is not configured")


def github_app_jwt():
    try:
        import jwt
    except Exception:
        raise HTTPException(status_code=503, detail="PyJWT is required for GitHub App installation tokens")
    app_id = normalize_env_value(os.getenv("GITHUB_APP_ID", ""))
    if not app_id:
        raise HTTPException(status_code=503, detail="GITHUB_APP_ID is not configured")
    now = int(datetime.utcnow().timestamp())
    payload = {
        "iat": now - 60,
        "exp": now + 9 * 60,
        "iss": app_id,
    }
    return jwt.encode(payload, github_private_key(), algorithm="RS256")


def github_installation_token(installation_id: str):
    if not installation_id:
        raise HTTPException(status_code=400, detail="installation_id is required")
    response = requests.post(
        f"https://api.github.com/app/installations/{installation_id}/access_tokens",
        headers={
            "Accept": "application/vnd.github+json",
            "X-GitHub-Api-Version": "2022-11-28",
            "Authorization": f"Bearer {github_app_jwt()}",
            "User-Agent": "CodeVal",
        },
        timeout=GITHUB_REQUEST_TIMEOUT,
    )
    response.raise_for_status()
    token = response.json().get("token", "")
    if not token:
        raise HTTPException(status_code=502, detail="GitHub did not return an installation token")
    return token

