def normalize_github_token(token=None):
    token = (os.getenv("GITHUB_TOKEN") if token is None else token) or ""
    token = str(token).strip()
    if (token.startswith('"') and token.endswith('"')) or (token.startswith("'") and token.endswith("'")):
        token = token[1:-1].strip()
    lowered = token.lower()
    if lowered.startswith("bearer "):
        token = token[7:].strip()
    elif lowered.startswith("token "):
        token = token[6:].strip()
    return token


def github_headers(token=None):
    token = normalize_github_token(token)
    headers = {
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
        "User-Agent": "CodeVal",
    }
    if token:
        headers["Authorization"] = f"Bearer {token}"
    return headers


def github_token_log_info(token=None):
    token = normalize_github_token(token)
    if not token:
        return {"configured": False, "length": 0, "fingerprint": ""}
    fingerprint = hashlib.sha256(token.encode("utf-8", errors="ignore")).hexdigest()[:8]
    return {"configured": True, "length": len(token), "fingerprint": fingerprint}


