@app.get("/artifact/render")
def render_external_html_artifact(url: str = ""):
    artifact_url = str(url or "").strip()
    parsed = urlparse(artifact_url)
    host = parsed.netloc.lower()
    path = parsed.path.lower()
    is_supabase_storage = (
        parsed.scheme == "https"
        and (host.endswith(".supabase.co") or host.endswith(".supabase.in"))
        and (
            "/storage/v1/object/sign/" in path
            or "/storage/v1/object/public/" in path
        )
    )
    if not artifact_url or not is_supabase_storage or not path.endswith(".html"):
        raise HTTPException(status_code=400, detail="Only Supabase HTML artifact URLs can be rendered.")
    try:
        response = requests.get(artifact_url, timeout=(10, 30))
    except requests.RequestException as e:
        raise HTTPException(status_code=502, detail=f"Unable to fetch artifact: {e}") from e
    if response.status_code >= 400:
        raise HTTPException(status_code=response.status_code, detail="Supabase artifact could not be fetched.")
    text = response.text
    if not re.search(r"^\s*(?:<!doctype html|<html[\s>])", text, re.I):
        raise HTTPException(status_code=415, detail="Artifact is not HTML.")
    return Response(content=text, media_type="text/html; charset=utf-8")


@app.get("/debug/output/{repo}/{folder}/{filename}")
def debug_output_file(request: Request, repo: str, folder: str, filename: str):
    require_debug_enabled(request)
    target = (BASE_OUTPUT / repo / folder / filename).resolve()
    output_root = BASE_OUTPUT.resolve()
    if output_root not in target.parents:
        raise HTTPException(status_code=400, detail="Invalid output path")

    exists = target.exists()
    info = {
        "path": str(target),
        "url": output_url(target),
        "exists": exists,
        "size": target.stat().st_size if exists else 0,
    }
    if exists and target.suffix.lower() == ".json":
        try:
            with open(target, "r", encoding="utf-8") as f:
                data = json.load(f)
            info["json_type"] = type(data).__name__
            info["items"] = len(data) if isinstance(data, list) else len(data.keys()) if isinstance(data, dict) else None
            info["sample"] = data[:3] if isinstance(data, list) else data
        except Exception as e:
            info["json_error"] = str(e)
    elif exists and target.suffix.lower() == ".html":
        with open(target, "r", encoding="utf-8", errors="ignore") as f:
            html = f.read()
        info["contains_json_path"] = f"{OUTPUT_URL_PREFIX}/" in html or "/output/" in html
        info["contains_cdn_fallback"] = "unpkg.com/cytoscape" in html
        info["contains_render_error"] = "Cytoscape render error" in html
        info["contains_embedded_data"] = "EMBEDDED_GRAPH_DATA" in html
        info["preview"] = html[:5000]
    return info

