@app.get("/github/login")
def github_login(request: Request, next: str = "", fresh: str = ""):
    client_id, _ = github_oauth_config()
    next_path = safe_local_redirect(next, "") if next else ""
    state = create_github_oauth_state(next_path)
    params = {
        "client_id": client_id,
        "redirect_uri": github_oauth_redirect_uri(request),
        "state": state,
        "scope": "read:user user:email",
        "allow_signup": "true",
    }
    if str(fresh or "").lower() in {"1", "true", "yes", "select_account"}:
        params["prompt"] = "select_account"
    response = RedirectResponse(f"https://github.com/login/oauth/authorize?{urlencode(params)}")
    response.set_cookie(
        GITHUB_STATE_COOKIE,
        state,
        httponly=True,
        samesite="lax",
        max_age=600,
    )
    if next_path:
        response.set_cookie(
            GITHUB_NEXT_COOKIE,
            next_path,
            httponly=True,
            samesite="lax",
            max_age=600,
        )
    return response


@app.get("/github/reconnect")
def github_reconnect(request: Request, next: str = "", source: str = ""):
    session_id = request.cookies.get(GITHUB_SESSION_COOKIE, "")
    if session_id:
        with GITHUB_SESSIONS_GUARD:
            GITHUB_SESSIONS.pop(session_id, None)
    source_returns = {
        "demo": "/demo#setup-workflow",
        "sample": "/sample#setup-workflow",
        "dashboard": "/dashboard#setup-workflow",
    }
    if not next and str(source or "").strip().lower() in source_returns:
        next = source_returns[str(source).strip().lower()]
    login_path = "/github/login?fresh=1"
    if next:
        login_path += f"&next={quote(safe_local_redirect(next, '/'))}"
    response = RedirectResponse(login_path)
    response.delete_cookie(GITHUB_SESSION_COOKIE)
    response.delete_cookie(GITHUB_STATE_COOKIE)
    response.delete_cookie(GITHUB_NEXT_COOKIE)
    return response


