@app.get("/github/callback")
def github_callback(
    request: Request,
    code: str = "",
    state: str = "",
    error: str = "",
    installation_id: str = "",
    setup_action: str = "",
):
    state_payload = decode_github_oauth_state(state)
    state_next = state_payload.get("next", "")
    if error:
        next_path = state_next or request.cookies.get(GITHUB_NEXT_COOKIE, "")
        response = RedirectResponse(safe_local_redirect(next_path, "/?github_error=1#github-repos"))
        response.delete_cookie(GITHUB_STATE_COOKIE)
        response.delete_cookie(GITHUB_NEXT_COOKIE)
        return response
    expected_state = request.cookies.get(GITHUB_STATE_COOKIE, "")
    valid_state = bool(state_payload) or bool(state and expected_state and secrets.compare_digest(state, expected_state))
    installation_callback = bool(installation_id and code)
    if not code:
        if installation_id:
            return RedirectResponse("/github/reconnect")
        raise HTTPException(status_code=400, detail="GitHub OAuth code is missing")
    if not valid_state and not installation_callback:
        raise HTTPException(status_code=400, detail="Invalid GitHub OAuth state")

    client_id, client_secret = github_oauth_config()
    token_response = requests.post(
        "https://github.com/login/oauth/access_token",
        headers={"Accept": "application/json", "User-Agent": "CodeVal"},
        data={
            "client_id": client_id,
            "client_secret": client_secret,
            "code": code,
            "redirect_uri": github_oauth_redirect_uri(request),
        },
        timeout=20,
    )
    token_response.raise_for_status()
    token_payload = token_response.json()
    access_token = token_payload.get("access_token")
    if not access_token:
        raise HTTPException(status_code=400, detail="GitHub did not return an access token")

    user_response = requests.get(
        "https://api.github.com/user",
        headers=github_user_headers(access_token),
        timeout=GITHUB_REQUEST_TIMEOUT,
    )
    user_response.raise_for_status()
    user = user_response.json()
    session_id = create_github_session({
        "access_token": access_token,
        "scope": token_payload.get("scope", ""),
        "token_type": token_payload.get("token_type", ""),
        "installation_id": installation_id,
        "setup_action": setup_action,
        "user": {
            "github_user_id": user.get("id", ""),
            "login": user.get("login", ""),
            "name": user.get("name", ""),
            "avatar_url": user.get("avatar_url", ""),
            "html_url": user.get("html_url", ""),
        },
    })
    next_path = safe_local_redirect(
        state_next or request.cookies.get(GITHUB_NEXT_COOKIE, ""),
        "/?github=connected#github-repos",
    )
    response = RedirectResponse(next_path)
    response.delete_cookie(GITHUB_STATE_COOKIE)
    response.delete_cookie(GITHUB_NEXT_COOKIE)
    response.set_cookie(
        GITHUB_SESSION_COOKIE,
        session_id,
        httponly=True,
        samesite="lax",
        max_age=60 * 60 * 24 * 14,
    )
    return response


