@app.get("/github/repos")
def github_repos(request: Request):
    _, session = github_session_from_request(request)
    repos = []
    installation_count = 0
    errors = []

    try:
        installations_response = requests.get(
            "https://api.github.com/user/installations",
            headers=github_user_headers(session["access_token"]),
            params={"per_page": 100},
            timeout=GITHUB_REQUEST_TIMEOUT,
        )
        installations_response.raise_for_status()
        installations = installations_response.json().get("installations", [])
        installation_count = len(installations)
        for installation in installations:
            installation_id = str(installation.get("id", ""))
            repo_response = requests.get(
                f"https://api.github.com/user/installations/{installation_id}/repositories",
                headers=github_user_headers(session["access_token"]),
                params={"per_page": 100},
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            repo_response.raise_for_status()
            for repo in repo_response.json().get("repositories", []):
                repos.append(github_repo_summary(repo, installation_id))
    except Exception as e:
        errors.append(f"installation repos: {type(e).__name__}: {e}")

    if not repos:
        try:
            response = requests.get(
                "https://api.github.com/user/repos",
                headers=github_user_headers(session["access_token"]),
                params={
                    "visibility": "all",
                    "affiliation": "owner,collaborator,organization_member",
                    "sort": "updated",
                    "per_page": 100,
                },
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            response.raise_for_status()
            repos = [github_repo_summary(repo) for repo in response.json()]
            repo_source = "user_repos_fallback"
        except Exception as e:
            errors.append(f"user repos: {type(e).__name__}: {e}")
            repo_source = "none"
    else:
        repo_source = "github_app_installations"

    deduped = {}
    for repo in repos:
        deduped[repo["full_name"]] = repo
    repos = sorted(deduped.values(), key=lambda item: item.get("updated_at") or item.get("pushed_at") or "", reverse=True)
    return {
        "count": len(repos),
        "repos": repos,
        "installation_count": installation_count,
        "repo_source": repo_source,
        "errors": errors[:3],
    }


@app.get("/github/saved-analyses")
def github_saved_analyses(request: Request, owner: str = "", repo: str = "", limit: int = 20):
    _, session = github_session_from_request(request)
    github_user_id = github_session_user_id(session)
    client = supabase_runtime_client()
    if not client:
        return {"ok": False, "configured": False, "analyses": []}

    repository_ids = None
    if owner and repo:
        repo_response = supabase_execute(
            "saved analysis repository lookup",
            lambda: client.table("codeval_repositories")
            .select("id")
            .eq("owner_name", owner)
            .eq("repo_name", repo)
            .limit(1)
            .execute(),
        )
        repo_rows = getattr(repo_response, "data", None) or []
        repository_ids = [row["id"] for row in repo_rows if row.get("id")]
        if not repository_ids:
            return {"ok": True, "configured": True, "analyses": []}

    response = supabase_analysis_runs_for_user(
        client,
        github_user_id,
        "id,repository_id,job_id,status,source_kind,branch,commit_sha,output_prefix,files_reviewed,language_count,extension_count,mapped_items,connection_count,started_at,completed_at,created_at,codeval_repositories(owner_name,repo_name,full_name,html_url,default_branch,codeval_repo_key)",
        repository_ids=repository_ids,
        limit=limit,
        description="saved analyses lookup",
    )
    rows = getattr(response, "data", None) or []
    return {"ok": True, "configured": True, "count": len(rows), "analyses": rows}


