PUBLIC_SAMPLE_ANALYSIS_REPOS = {
    ("medusajs", "dtc-starter"),
}


@app.get("/sample-analysis")
def sample_analysis(owner: str = "", repo: str = ""):
    requested_owner = str(owner or "").strip()
    requested_repo = str(repo or "").strip()
    sample_owner = requested_owner or "pranaysad"
    sample_repo = requested_repo or "nextjs-starter-medusa"
    if (sample_owner, sample_repo) not in PUBLIC_SAMPLE_ANALYSIS_REPOS:
        return {"ok": False, "configured": True, "analysis": None, "message": "This repository is not configured as a public demo analysis."}
    sample_display_repo = f"{sample_owner}/{sample_repo}"
    client = supabase_runtime_client()
    if not client:
        return {"ok": False, "configured": False, "analysis": None}

    repo_response = supabase_execute(
        "sample analysis repository lookup",
        lambda: client.table("codeval_repositories")
        .select("id")
        .eq("owner_name", sample_owner)
        .eq("repo_name", sample_repo)
        .limit(1)
        .execute(),
    )
    repo_rows = getattr(repo_response, "data", None) or []
    repository_ids = [row["id"] for row in repo_rows if row.get("id")]
    if not repository_ids:
        return {"ok": True, "configured": True, "analysis": None, "message": "Sample analysis repository was not found."}

    response = supabase_execute(
        "sample latest saved analysis lookup",
        lambda: client.table("codeval_analysis_runs")
        .select("*,codeval_repositories(owner_name,repo_name,full_name,html_url,default_branch,codeval_repo_key)")
        .eq("status", "completed")
        .in_("repository_id", repository_ids)
        .order("completed_at", desc=True)
        .order("created_at", desc=True)
        .limit(1)
        .execute(),
    )
    rows = getattr(response, "data", None) or []
    if not rows:
        return {"ok": True, "configured": True, "analysis": None, "message": "No completed sample analysis was found."}

    restored = supabase_restore_analysis_payload(client, rows[0], github_user_id=rows[0].get("github_user_id"))
    if not analysis_payload_is_current(restored):
        return {
            "ok": True,
            "configured": True,
            "analysis": None,
            "stale": True,
            "message": "The saved sample analysis is older than the current parser version.",
        }
    restored["sample_display_repo"] = sample_display_repo
    restored["sample_source_repo"] = sample_display_repo
    restored["sample_saved_repo"] = f"{sample_owner}/{sample_repo}"
    return {
        "ok": True,
        "configured": True,
        "analysis_run": {
            "id": rows[0].get("id"),
            "repository_id": rows[0].get("repository_id"),
            "completed_at": rows[0].get("completed_at"),
            "created_at": rows[0].get("created_at"),
        },
        "analysis": restored,
    }


def parse_owner_repo_from_full_name(full_name: str):
    if "/" not in (full_name or ""):
        raise ValueError("Repository must be owner/name")
    owner, repo = (full_name or "").strip().split("/", 1)
    if not owner or not repo:
        raise ValueError("Repository must be owner/name")
    return owner, repo


def github_daily_commits_for_token(owner: str, repo: str, days: int = 1, installation_id: str = "", token: str = ""):
    days = max(1, min(int(days or 1), 30))
    since = (datetime.utcnow() - timedelta(days=days)).isoformat(timespec="seconds") + "Z"
    commits_url = f"https://api.github.com/repos/{owner}/{repo}/commits"
    token = normalize_github_token(token)

    def fetch_commit_items(params: dict):
        response = requests.get(
            commits_url,
            headers=github_headers(token),
            params=params,
            timeout=GITHUB_REQUEST_TIMEOUT,
        )
        if response.status_code >= 400:
            response_message = safe_response_text(response, 300)
            logger.warning(
                "GitHub commits request failed for %s/%s: status=%s token_configured=%s params=%s message=%s",
                owner,
                repo,
                response.status_code,
                bool(token),
                params,
                response_message,
            )
            if response.status_code == 403 and "rate limit" in response_message.lower():
                auth_hint = (
                    "The request was unauthenticated. Connect GitHub or set a valid GITHUB_TOKEN in the server environment."
                    if not token
                    else "The configured GitHub token was used, but GitHub still returned a rate limit."
                )
                raise HTTPException(
                    status_code=429,
                    detail=f"GitHub API rate limit exceeded while loading commits for {owner}/{repo}. {auth_hint}",
                )
            if response.status_code == 401:
                raise HTTPException(
                    status_code=401,
                    detail=f"GitHub token was rejected while loading commits for {owner}/{repo}. Reconnect GitHub or update GITHUB_TOKEN.",
                )
        response.raise_for_status()
        return response.json() or []

    def normalize_commit_items(items):
        commits = []
        for item in items:
            commit = item.get("commit") or {}
            author = commit.get("author") or {}
            commits.append({
                "sha": item.get("sha", ""),
                "short_sha": str(item.get("sha", ""))[:7],
                "message": str(commit.get("message", "")).splitlines()[0][:180],
                "author": author.get("name", ""),
                "date": author.get("date", ""),
                "html_url": item.get("html_url", ""),
            })
        return commits

    window_items = fetch_commit_items({"since": since, "per_page": 100})
    commits = normalize_commit_items(window_items)
    fallback_used = False
    fallback_reason = ""
    fallback_limit = 10
    if not commits:
        fallback_used = True
        fallback_reason = f"No commits found in the last {days} day{'s' if days != 1 else ''}; showing the {fallback_limit} most recent commits."
        commits = normalize_commit_items(fetch_commit_items({"per_page": fallback_limit}))

    return {
        "owner": owner,
        "repo": repo,
        "days": days,
        "since": since,
        "count": len(commits),
        "commits": commits,
        "installation_id": str(installation_id or ""),
        "fallback_used": fallback_used,
        "fallback_reason": fallback_reason,
        "commit_window": "recent" if fallback_used else "since",
        "fallback_limit": fallback_limit if fallback_used else 0,
    }


@app.get("/github/daily-commits")
def github_daily_commits(request: Request, owner: str, repo: str, days: int = 1, installation_id: str = ""):
    _, session = github_session_from_request(request)
    token = github_installation_token(installation_id) if installation_id else session["access_token"]
    return github_daily_commits_for_token(owner, repo, days, installation_id, token)


@app.get("/github/daily-commit-graph")
def github_daily_commit_graph(request: Request, owner: str, repo: str, days: int = 1, installation_id: str = ""):
    commit_payload = github_daily_commits(request, owner, repo, days, installation_id)
    commits = list(reversed(commit_payload.get("commits", [])))
    output_repo_dir = repo_output_dir(owner, repo)
    if not commits:
        return {**commit_payload, "graph_url": "", "message": "No commits found in the selected window."}

    node_labels = [
        f"{item.get('short_sha')} {item.get('message')}".strip()
        for item in commits
    ]
    edges = [
        (node_labels[index - 1], node_labels[index], index, None)
        for index in range(1, len(node_labels))
    ]
    graph_url = build_generic_cytoscape_graph(
        node_labels,
        edges,
        str(output_repo_dir),
        graph_name="daily_commit_graph",
        graph_title=f"Daily Commit Graph: {owner}/{repo}",
    )
    return {**commit_payload, "graph_url": graph_url}


def changed_file_function_index(owner: str, repo: str):
    output_repo_dir = repo_output_dir(owner, repo)
    artifact_root = artifact_root_for_output(output_repo_dir)
    functions_path = find_scim_functions_path(output_repo_dir)
    file_to_functions = defaultdict(list)
    if functions_path:
        try:
            with functions_path.open("r", encoding="utf-8") as handle:
                for line in handle:
                    try:
                        record = json.loads(line)
                    except json.JSONDecodeError:
                        continue
                    path = str(record.get("path") or "").replace("\\", "/").lstrip("/")
                    symbol = str(record.get("symbol") or "")
                    if path and symbol:
                        try:
                            start_line = int(record.get("start_line") or 0)
                        except (TypeError, ValueError):
                            start_line = 0
                        try:
                            end_line = int(record.get("end_line") or start_line or 0)
                        except (TypeError, ValueError):
                            end_line = start_line
                        file_to_functions[path].append({
                            "symbol": symbol,
                            "path": path,
                            "start_line": start_line,
                            "end_line": max(start_line, end_line),
                        })
        except Exception as e:
            logger.warning("Unable to load functions for daily change graph: %s", e)

    callgraph_edges = set()
    outgoing = defaultdict(list)
    incoming = defaultdict(list)
    try:
        callgraph, _ = load_search_callgraph(output_repo_dir)
        _, _, outgoing, incoming, _ = callgraph_indexes(callgraph)
        for src, targets in outgoing.items():
            for dst in targets:
                callgraph_edges.add((src, dst))
    except Exception:
        for graph_path in ga_mapping_graph_paths(artifact_root):
            _, edges = _load_edge_graph(str(graph_path))
            callgraph_edges.update(edges)
    return file_to_functions, callgraph_edges, outgoing, incoming


def changed_lines_from_patch(patch: str):
    changed_lines = set()
    if not patch:
        return changed_lines
    new_line = None
    for line in str(patch).splitlines():
        hunk = re.match(r"@@\s+-\d+(?:,\d+)?\s+\+(\d+)(?:,(\d+))?\s+@@", line)
        if hunk:
            new_line = int(hunk.group(1))
            continue
        if new_line is None:
            continue
        if line.startswith("+") and not line.startswith("+++"):
            changed_lines.add(new_line)
            new_line += 1
        elif line.startswith("-") and not line.startswith("---"):
            # Deleted lines have no new-file line number. Use the next surviving
            # line as an approximate anchor so deletions inside a function still
            # map to that function range.
            changed_lines.add(max(1, new_line))
            continue
        else:
            new_line += 1
    return changed_lines


def changed_line_ranges(lines):
    ordered = sorted(int(line) for line in lines or [] if int(line) > 0)
    if not ordered:
        return []
    ranges = []
    start = previous = ordered[0]
    for line in ordered[1:]:
        if line == previous + 1:
            previous = line
            continue
        ranges.append({"start": start, "end": previous})
        start = previous = line
    ranges.append({"start": start, "end": previous})
    return ranges


def patch_evidence_from_patch(filename: str, patch: str, max_items: int = 24):
    filename = str(filename or "")
    patch = str(patch or "")
    removed = []
    added = []
    hunks = []
    current_hunk = None
    for line in patch.splitlines():
        hunk = re.match(r"@@\s+-(\d+)(?:,\d+)?\s+\+(\d+)(?:,\d+)?\s+@@\s*(.*)", line)
        if hunk:
            current_hunk = {
                "old_start": int(hunk.group(1)),
                "new_start": int(hunk.group(2)),
                "context": hunk.group(3).strip(),
                "added": [],
                "removed": [],
            }
            hunks.append(current_hunk)
            continue
        if line.startswith("+++") or line.startswith("---"):
            continue
        if line.startswith("+"):
            text = line[1:].strip()
            if text:
                added.append(text)
                if current_hunk is not None and len(current_hunk["added"]) < 8:
                    current_hunk["added"].append(text)
        elif line.startswith("-"):
            text = line[1:].strip()
            if text:
                removed.append(text)
                if current_hunk is not None and len(current_hunk["removed"]) < 8:
                    current_hunk["removed"].append(text)

    css_property_pattern = re.compile(r"^\s*([A-Za-z-]+)\s*:\s*([^;]+);?")
    removed_props = defaultdict(list)
    added_props = defaultdict(list)
    for text in removed:
        match = css_property_pattern.match(text)
        if match:
            removed_props[match.group(1)].append(match.group(2).strip())
    for text in added:
        match = css_property_pattern.match(text)
        if match:
            added_props[match.group(1)].append(match.group(2).strip())
    css_changes = []
    for prop in sorted(set(removed_props) | set(added_props)):
        before = removed_props.get(prop, [])
        after = added_props.get(prop, [])
        count = max(len(before), len(after))
        for index in range(count):
            css_changes.append({
                "property": prop,
                "before": before[index] if index < len(before) else "",
                "after": after[index] if index < len(after) else "",
            })
            if len(css_changes) >= max_items:
                break
        if len(css_changes) >= max_items:
            break

    changed_identifiers = sorted(set(
        token
        for text in added + removed
        for token in re.findall(r"[.#][A-Za-z_][A-Za-z0-9_-]*|\b[A-Za-z_][A-Za-z0-9_-]*(?=\s*\{)", text)
    ))[:max_items]
    code_keywords = sorted(set(
        token
        for text in added + removed
        for token in re.findall(r"\b(function|class|def|async|await|fetch|return|if|else|for|while|try|catch|except|import|from)\b", text)
    ))
    file_kind = Path(filename).suffix.lower().lstrip(".") or "file"
    return {
        "file": filename,
        "file_kind": file_kind,
        "hunks": hunks[:8],
        "removed_samples": removed[:max_items],
        "added_samples": added[:max_items],
        "css_property_changes": css_changes,
        "changed_identifiers": changed_identifiers,
        "code_keywords": code_keywords,
        "change_shape": {
            "added_line_count": len(added),
            "removed_line_count": len(removed),
            "css_property_change_count": len(css_changes),
            "hunk_count": len(hunks),
        },
    }


def function_intersects_changed_lines(function_record: dict, changed_lines: set[int]):
    start_line = int(function_record.get("start_line") or 0)
    end_line = int(function_record.get("end_line") or start_line or 0)
    if start_line <= 0 or end_line <= 0:
        return False
    return any(start_line <= line <= end_line for line in changed_lines)


def functions_for_changed_file(filename: str, file_to_functions: dict, changed_lines=None, fallback_to_file=False):
    normalized = str(filename or "").replace("\\", "/").lstrip("/")
    if not normalized:
        return []
    candidate_records = list(file_to_functions.get(normalized, []))
    if not candidate_records:
        suffix = f"/{normalized}"
        for path, records in file_to_functions.items():
            if path.endswith(suffix) or normalized.endswith(f"/{path}"):
                candidate_records.extend(records)
    changed_lines = {int(line) for line in (changed_lines or set()) if int(line) > 0}
    if changed_lines:
        candidate_records = [
            record for record in candidate_records
            if function_intersects_changed_lines(record, changed_lines)
        ]
    elif not fallback_to_file:
        candidate_records = []

    by_symbol = {}
    for record in candidate_records:
        symbol = str(record.get("symbol") or "")
        if symbol:
            by_symbol[symbol] = record
    return sorted(by_symbol.values(), key=lambda item: (item.get("start_line") or 0, item.get("symbol") or ""))[:20]


def github_commit_impact_score(commit_message: str, changed_file_count: int, changed_function_count: int, neighbor_count: int, edge_count: int):
    message = str(commit_message or "").lower()
    is_minor_text = bool(re.search(r"\b(doc|docs|readme|typo|comment|format|style|whitespace|lint)\b", message))
    is_feature = bool(re.search(r"\b(feat|feature|product|workflow|release|enable|disable|support|upgrade|implement|add|remove|migrate|refactor)\b", message))
    score = changed_function_count * 12 + neighbor_count * 5 + edge_count * 8 + changed_file_count * 3
    if score == 0:
        score = max(3, min(18, changed_file_count * 4))
    if is_minor_text and changed_function_count <= 1:
        score = min(score, 24)
    if is_feature:
        score += 8
    return max(5, min(100, int(score)))


def github_commit_impact_label(commit_message: str, changed_file_count: int, changed_function_count: int, neighbor_count: int, edge_count: int, impact_score: int):
    message = str(commit_message or "").lower()
    is_minor_text = bool(re.search(r"\b(doc|docs|readme|typo|comment|format|style|whitespace|lint)\b", message))
    is_feature = bool(re.search(r"\b(feat|feature|product|workflow|release|enable|disable|support|upgrade|implement|add|remove|migrate|refactor)\b", message))
    if is_minor_text and changed_function_count <= 1:
        return "Minor documentation/text change"
    if changed_function_count == 0 and changed_file_count <= 2:
        return "Minor file-level change"
    if is_feature and impact_score >= 20:
        return "Feature/product change"
    if edge_count >= 5 or neighbor_count >= 8 or changed_function_count >= 8:
        return "High impact change"
    if edge_count >= 2 or neighbor_count >= 4 or changed_function_count >= 4:
        return "Moderate change"
    return "Localized change"


def display_callgraph_symbol(symbol: str) -> str:
    label = str(symbol or "").strip()
    label = re.sub(r"^(author|commit|file|function):", "", label)
    label = label.replace("\\", "/")
    label = re.sub(r"\*\*([^*]+)\*\*", r"\1", label)
    label = re.sub(r"\s+\.", ".", label)
    label = re.sub(r"\.\s+", ".", label)
    if not label:
        return label

    # HTML/SCIM symbols can carry generated repo prefixes such as
    # owner_repo_sha_static_dashboard_html.button. Keep the useful file/function tail.
    html_match = re.search(r"(?:^|_)([^_./]+)_html[._]([^./]+)$", label)
    if html_match:
        return f"{html_match.group(1)}.html.{html_match.group(2)}"

    # Drop long hash-like prefixes from generated symbols.
    parts = [part for part in re.split(r"[._/]+", label) if part]
    parts = [part for part in parts if not re.fullmatch(r"[0-9a-f]{7,}", part, flags=re.IGNORECASE)]
    if len(parts) >= 3 and parts[-2].lower() == "html":
        return ".".join(parts[-3:])
    if len(parts) >= 2:
        if "." in label and "/" not in label:
            module_path, function_name = label.rsplit(".", 1)
            if module_path and function_name:
                return f"{module_path}\n{function_name}"
        return ".".join(parts[-2:])
    return parts[0] if parts else label


def daily_summary_text_context(output_repo_dir: Path, changed_files: list[dict], limit: int = 12):
    changed_names = {str(item.get("filename") or "").replace("\\", "/") for item in changed_files or []}
    rows = []

    def add_row(source, file_name, text, line=""):
        text = " ".join(str(text or "").split())
        if not text:
            return
        rows.append({
            "source": source,
            "file": str(file_name or ""),
            "line": line,
            "text": text[:500],
        })

    for path_name, key in (("repo_text.json", "text_items"), ("repo_comments.json", "text_items")):
        path = repo_text_artifact_path(output_repo_dir, path_name, legacy_ok=True)
        if not path.exists():
            continue
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        candidates = data.get(key) if isinstance(data, dict) else data
        if not isinstance(candidates, list):
            continue
        for item in candidates:
            if not isinstance(item, dict):
                continue
            file_name = str(item.get("file") or item.get("path") or "").replace("\\", "/")
            if changed_names and file_name and not any(file_name.endswith(name) or name.endswith(file_name) for name in changed_names):
                continue
            add_row(path_name, file_name, item.get("text") or item.get("content") or item.get("line_text"), item.get("line", ""))
            if len(rows) >= limit:
                return rows
    return rows[:limit]


def daily_summary_function_context(owner: str, repo: str, changed_functions: list[str], max_functions: int = 12):
    output_repo_dir = repo_output_dir(owner, repo)
    functions_path = find_scim_functions_path(output_repo_dir)
    records = {}
    if functions_path:
        records = load_scim_function_records(functions_path.parent)

    snippets = []
    for symbol in changed_functions[:max_functions]:
        record = records.get(symbol) or {}
        code = str(record.get("code") or "")
        code_lines = code.splitlines()
        word_count = len(re.findall(r"\w+", code))
        include_full_code = bool(code) and (len(code) <= 4000 or len(code_lines) <= 80 or word_count <= 500)
        snippets.append({
            "symbol": symbol,
            "path": record.get("path", ""),
            "start_line": record.get("start_line", ""),
            "end_line": record.get("end_line", ""),
            "code_strategy": "full_function" if include_full_code else "excerpt",
            "code_line_count": len(code_lines),
            "code_word_count": word_count,
            "code": code if include_full_code else code[:1400],
        })

    graph_rows = []
    try:
        callgraph, source = load_search_callgraph(output_repo_dir)
        _, _, outgoing, incoming, _ = callgraph_indexes(callgraph)
        for symbol in changed_functions[:max_functions]:
            graph_rows.append({
                "symbol": symbol,
                "callgraph_source": source,
                "callers": sorted(incoming.get(symbol, []))[:8],
                "callees": sorted(outgoing.get(symbol, []))[:8],
            })
    except Exception:
        pass
    return snippets, graph_rows


def diff_lines_for_ranges(patch: str, ranges: list[dict], max_chars: int = 5000):
    patch = str(patch or "")
    if not patch or not ranges:
        return ""
    range_pairs = [
        (int(item.get("start") or 0), int(item.get("end") or item.get("start") or 0))
        for item in ranges
        if isinstance(item, dict) and int(item.get("start") or 0) > 0
    ]
    if not range_pairs:
        return ""
    output = []
    new_line = None
    include_hunk = False
    for line in patch.splitlines():
        hunk = re.match(r"@@\s+-\d+(?:,\d+)?\s+\+(\d+)(?:,\d+)?\s+@@", line)
        if hunk:
            new_line = int(hunk.group(1))
            include_hunk = False
            continue
        if new_line is None:
            continue
        line_number = new_line
        if line.startswith("+") and not line.startswith("+++"):
            new_line += 1
        elif line.startswith("-") and not line.startswith("---"):
            line_number = max(1, new_line)
        else:
            new_line += 1
        if any(start <= line_number <= end for start, end in range_pairs):
            if not include_hunk:
                output.append(f"@@ changed around new line {line_number} @@")
                include_hunk = True
            output.append(line)
        if sum(len(item) + 1 for item in output) >= max_chars:
            output.append("...diff truncated...")
            break
    return "\n".join(output)[:max_chars]


def build_commit_evidence_plan(owner: str, repo: str, daily_payload: dict, budget_chars: int = DAILY_COMMIT_EVIDENCE_MAX_CHARS):
    changed_files = [item for item in (daily_payload.get("changed_files") or []) if isinstance(item, dict)]
    changed_functions = daily_payload.get("changed_functions") or []
    changed_function_details = [item for item in (daily_payload.get("changed_function_details") or []) if isinstance(item, dict)]
    function_snippets, graph_rows = daily_summary_function_context(owner, repo, changed_functions)
    snippets_by_symbol = {item.get("symbol"): item for item in function_snippets}
    graph_by_symbol = {item.get("symbol"): item for item in graph_rows}
    files_by_name = {item.get("filename"): item for item in changed_files}
    evidence = []

    for commit in (daily_payload.get("commits") or [])[:20]:
        evidence.append({
            "type": "commit",
            "priority": 1,
            "id": f"commit:{commit.get('short_sha') or str(commit.get('sha') or '')[:7]}",
            "summary": {
                "sha": commit.get("short_sha") or str(commit.get("sha") or "")[:7],
                "message": commit.get("message"),
                "author": commit.get("author"),
                "date": commit.get("date"),
                "impact": commit.get("impact_label"),
                "url": commit.get("html_url"),
            },
        })

    for item in changed_files[:30]:
        patch = str(item.get("patch_excerpt") or "")
        changes = int(item.get("changes") or 0)
        full_small_diff = patch if patch and changes <= 180 and len(patch) <= 12000 else ""
        evidence.append({
            "type": "changed_file",
            "priority": 2,
            "id": f"file:{item.get('filename')}",
            "summary": {
                "filename": item.get("filename"),
                "status": item.get("status"),
                "additions": item.get("additions"),
                "deletions": item.get("deletions"),
                "changes": changes,
                "changed_line_ranges": item.get("changed_line_ranges", [])[:80],
            },
            "patch_evidence": item.get("patch_evidence", {}),
            "exact_diff": full_small_diff,
            "diff_strategy": "full_small_file_diff" if full_small_diff else "structured_patch_only_or_large_diff",
        })

    for detail in changed_function_details[:30]:
        symbol = detail.get("symbol")
        file_item = files_by_name.get(detail.get("path")) or files_by_name.get(str(detail.get("path") or "").replace("\\", "/"))
        function_ranges = []
        for changed_range in detail.get("changed_line_ranges", []) or []:
            if not isinstance(changed_range, dict):
                continue
            start = max(int(changed_range.get("start") or 0), int(detail.get("start_line") or 0))
            end = min(int(changed_range.get("end") or start), int(detail.get("end_line") or start))
            if start and end and start <= end:
                function_ranges.append({"start": start, "end": end})
        exact_function_diff = diff_lines_for_ranges(file_item.get("patch_excerpt", "") if file_item else "", function_ranges)
        snippet = snippets_by_symbol.get(symbol, {})
        graph = graph_by_symbol.get(symbol, {})
        evidence.append({
            "type": "changed_function",
            "priority": 3,
            "id": f"function:{symbol}",
            "summary": {
                "symbol": symbol,
                "path": detail.get("path"),
                "function_lines": {"start": detail.get("start_line"), "end": detail.get("end_line")},
                "changed_lines_inside_function": function_ranges,
                "mapping_strategy": detail.get("mapping_strategy"),
            },
            "exact_function_diff": exact_function_diff,
            "function_code": snippet,
            "direct_callgraph_neighbors": {
                "callers": graph.get("callers", [])[:8],
                "callees": graph.get("callees", [])[:8],
                "source": graph.get("callgraph_source", ""),
            },
        })

    if not changed_function_details:
        for item in changed_files[:12]:
            evidence.append({
                "type": "file_level_fallback",
                "priority": 4,
                "id": f"file_fallback:{item.get('filename')}",
                "summary": "No function-level range mapped for this file. Use exact_diff and patch_evidence as the primary evidence.",
                "filename": item.get("filename"),
                "patch_evidence": item.get("patch_evidence", {}),
                "exact_diff": item.get("patch_excerpt", "") if int(item.get("changes") or 0) <= 180 else "",
            })

    selected = []
    used = 0
    for item in sorted(evidence, key=lambda row: row.get("priority", 99)):
        encoded = json.dumps(item, indent=2)
        if used + len(encoded) > budget_chars and selected:
            continue
        if len(encoded) > budget_chars:
            item = dict(item)
            if "exact_diff" in item:
                item["exact_diff"] = str(item.get("exact_diff") or "")[:4000] + "\n...truncated..."
            if "exact_function_diff" in item:
                item["exact_function_diff"] = str(item.get("exact_function_diff") or "")[:3000] + "\n...truncated..."
            if isinstance(item.get("function_code"), dict):
                item["function_code"] = {
                    key: value for key, value in item["function_code"].items()
                    if key != "code"
                } | {"code": str(item["function_code"].get("code") or "")[:3000] + "\n...truncated..."}
            encoded = json.dumps(item, indent=2)
        selected.append(item)
        used += len(encoded)
        if used >= budget_chars:
            break
    return {
        "strategy": "commit -> changed files -> changed line ranges -> changed functions/sections -> exact diff -> callgraph neighbors -> LLM summary",
        "budget_chars": budget_chars,
        "used_chars": used,
        "evidence_count": len(selected),
        "evidence": selected,
    }


def daily_summary_retrieval_query(daily_payload: dict):
    pieces = []
    for commit in (daily_payload.get("commits") or [])[:20]:
        if isinstance(commit, dict):
            pieces.extend([
                str(commit.get("message") or ""),
                str(commit.get("impact_label") or ""),
            ])
    for item in (daily_payload.get("changed_files") or [])[:30]:
        if isinstance(item, dict):
            pieces.append(str(item.get("filename") or ""))
            patch_evidence = item.get("patch_evidence") or {}
            pieces.extend(str(value or "") for value in (patch_evidence.get("changed_identifiers") or [])[:12])
    pieces.extend(str(symbol or "") for symbol in (daily_payload.get("changed_functions") or [])[:30])
    for detail in (daily_payload.get("changed_function_details") or [])[:30]:
        if isinstance(detail, dict):
            pieces.extend([
                str(detail.get("symbol") or ""),
                str(detail.get("path") or ""),
                str(detail.get("mapping_strategy") or ""),
            ])
    query = " ".join(piece for piece in pieces if piece).strip()
    return re.sub(r"\s+", " ", query)[:2000]


def daily_summary_vector_context(owner: str, repo: str, daily_payload: dict, limit: int = 8):
    output_repo_dir = repo_output_dir(owner, repo)
    artifact_root = artifact_root_for_output(output_repo_dir)
    vector_db_path = artifact_root / "scim" / "vectors.sqlite"
    query = daily_summary_retrieval_query(daily_payload)
    context = {
        "source": "scim/vectors.sqlite",
        "available": vector_db_path.exists(),
        "query": query,
        "matches": [],
        "evidence_cards": [],
        "retrieval_strategy": {},
        "note": "",
    }
    if not query:
        context["note"] = "No commit/file/function terms were available for vector retrieval."
        return context
    if not vector_db_path.exists():
        context["note"] = "SCIM vector index was not available, so this prompt uses commit, diff, function, text, and callgraph evidence only."
        return context
    try:
        scim_payload = search_scim_dataset(output_repo_dir, query, limit=limit) or {}
    except Exception as e:
        logger.warning("Daily summary vector retrieval failed for %s/%s: %s", owner, repo, e)
        context["note"] = f"SCIM vector retrieval failed: {str(e)[:300]}"
        return context
    matches = []
    for item in (scim_payload.get("results") or [])[:limit]:
        if not isinstance(item, dict):
            continue
        matches.append({
            "source_type": item.get("source_type") or "code_function",
            "symbol": item.get("symbol") or item.get("fullName") or "",
            "path": item.get("path") or "",
            "line_range": {"start": item.get("start_line") or "", "end": item.get("end_line") or ""},
            "score": item.get("score"),
            "text_score": item.get("text_score"),
            "matched_terms": item.get("matched_terms") or [],
            "match_source": item.get("match_source") or "",
            "match_snippet": item.get("match_snippet") or "",
            "callgraph_neighbors": {
                "callers": (item.get("calledBy") or [])[:8],
                "callees": (item.get("calls") or [])[:8],
            },
        })
    retrieval_context = scim_payload.get("retrieval_context") or {}
    context.update({
        "matches": matches,
        "evidence_cards": (retrieval_context.get("evidence_cards") or [])[:8],
        "retrieval_strategy": scim_payload.get("retrieval_strategy") or retrieval_context.get("retrieval_strategy") or {},
        "note": "Semantic/code search matches from scim/vectors.sqlite. Treat these as supporting context, not as proof of a changed line.",
    })
    return context


def daily_summary_artifact_context(output_repo_dir: Path, daily_payload: dict):
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    artifacts = []

    def add(label, url="", path=None):
        path_obj = Path(path) if path else None
        artifacts.append({
            "label": label,
            "url": url or (output_url(str(path_obj)) if path_obj and path_obj.exists() else ""),
            "path": str(path_obj) if path_obj else "",
            "exists": bool(path_obj.exists()) if path_obj else bool(url),
        })

    add("daily_change_graph_html", daily_payload.get("graph_url") or "")
    add("daily_change_graph_json", daily_payload.get("graph_json_url") or "")
    add("daily_change_cache", daily_payload.get("daily_change_cache_url") or "", Path(output_repo_dir) / "daily_change_cache.json")
    add("static_quality_signals", path=Path(output_repo_dir) / "static_quality_signals.json")
    add("scim_functions_index", path=artifact_root / "scim" / "functions.jsonl")
    add("scim_vectors_index", path=artifact_root / "scim" / "vectors.sqlite")
    add("combined_callgraph_json", path=artifact_root / "combined_callgraph" / "combined_callgraph.json")
    return {
        "artifacts": artifacts,
        "note": "Artifact references tell the model what generated evidence exists; only JSON/text included elsewhere in the prompt should be treated as directly inspected content.",
    }


def daily_summary_evidence_coverage(daily_payload: dict, evidence_plan: dict, vector_context: dict, graph_rows: list[dict]):
    changed_function_details = daily_payload.get("changed_function_details") or []
    changed_files = daily_payload.get("changed_files") or []
    return {
        "commit_count": len(daily_payload.get("commits") or []),
        "changed_file_count": len(changed_files),
        "changed_function_count": len(changed_function_details),
        "function_level_mapping_available": bool(changed_function_details),
        "exact_diff_items": sum(1 for item in (evidence_plan.get("evidence") or []) if item.get("exact_diff") or item.get("exact_function_diff")),
        "callgraph_context_available": bool(graph_rows),
        "vector_context_available": bool(vector_context.get("matches")),
        "vector_match_count": len(vector_context.get("matches") or []),
        "coverage_warning": (
            "No function-level line range could be mapped; use file-level patch evidence."
            if changed_files and not changed_function_details
            else ""
        ),
    }


def build_daily_summary_prompt(owner: str, repo: str, daily_payload: dict):
    output_repo_dir = repo_output_dir(owner, repo)
    changed_files = daily_payload.get("changed_files") or []
    changed_functions = daily_payload.get("changed_functions") or []
    changed_function_details = daily_payload.get("changed_function_details") or []
    function_snippets, graph_rows = daily_summary_function_context(owner, repo, changed_functions)
    text_rows = daily_summary_text_context(output_repo_dir, changed_files)
    evidence_plan = build_commit_evidence_plan(owner, repo, daily_payload)
    vector_context = daily_summary_vector_context(owner, repo, daily_payload)
    artifact_context = daily_summary_artifact_context(output_repo_dir, daily_payload)
    evidence_coverage = daily_summary_evidence_coverage(daily_payload, evidence_plan, vector_context, graph_rows)
    compact_payload = {
        "owner": owner,
        "repo": repo,
        "days": daily_payload.get("days"),
        "commit_count": daily_payload.get("count"),
        "author_count": daily_payload.get("author_count"),
        "commits": (daily_payload.get("commits") or [])[:20],
        "changed_files": changed_files[:30],
        "changed_functions": changed_functions[:30],
        "changed_function_details": changed_function_details[:50],
        "daily_change_graph_url": daily_payload.get("graph_url", ""),
    }
    patch_evidence = [
        {
            "filename": item.get("filename"),
            "status": item.get("status"),
            "changed_line_ranges": item.get("changed_line_ranges", [])[:40],
            "patch_evidence": item.get("patch_evidence", {}),
        }
        for item in changed_files[:20]
        if isinstance(item, dict)
    ]
    return f"""You are an expert software engineering analyst.
Create a specific, evidence-backed daily product change and commit summary in plain English using ONLY the evidence below.
The evidence is JSON so you can inspect exact commits, files, functions, diffs, and callgraph neighbors.
Do not reproduce the JSON, do not wrap the answer in a fenced code block, and do not output a JSON object.

Repository: {owner}/{repo}

Daily change payload:
{json.dumps(compact_payload, indent=2)}

Commit evidence plan, ordered from strongest to weakest evidence:
{json.dumps(evidence_plan, indent=2)}

Changed function code snippets:
{json.dumps(function_snippets, indent=2)}

Callgraph context for changed functions:
{json.dumps(graph_rows, indent=2)}

Relevant SCIM vector/code matches from scim/vectors.sqlite:
{json.dumps(vector_context, indent=2)}

Generated artifact references:
{json.dumps(artifact_context, indent=2)}

Evidence coverage:
{json.dumps(evidence_coverage, indent=2)}

Structured patch evidence:
{json.dumps(patch_evidence, indent=2)}

Repository text/comment evidence from changed files:
{json.dumps(text_rows, indent=2)}

Instructions:
- Follow the evidence plan order. Start from commit metadata, changed files, line ranges, changed functions/sections, exact diff, then callgraph neighbors.
- Treat exact_diff and exact_function_diff as primary evidence when present.
- Explain what changed in the latest commits in simple English, but be concrete: cite exact before/after values from patch_evidence when available.
- Group the update by likely feature, workflow, or capability when evidence supports it.
- Mention which authors made commits.
- List changed functions and explain what their callgraph context suggests they affect.
- Use SCIM vector/code matches only as supporting context. Do not claim a vector match changed unless it is also in changed_files, changed_functions, exact_diff, or changed_function_details.
- Mention generated artifacts only when their URL/path is present in the artifact references; do not imply you opened artifact URLs unless their contents are included in the prompt.
- When a code snippet has code_strategy=full_function, use the whole function body as evidence because the changed area is small enough to review directly.
- Use patch_evidence and patch_excerpt fields to explain the exact changed lines when they are present.
- For UI/CSS/HTML-only commits with no changed functions, summarize the concrete UI impact from changed selectors, CSS properties, spacing, typography, layout, and added/removed HTML text. Do not merely say "visual layout changed".
- Describe user scenarios or product behaviors that may be affected, but only when grounded in changed files, function names, code snippets, commit messages, or text evidence.
- If function-level mapping is incomplete, still use structured patch evidence to provide a precise file-level explanation, and say which parts are only file-level evidence.
- Cite commit short SHAs, files, and functions where relevant.
- Do not invent product behavior not supported by the evidence.
- Your final answer must be human-readable markdown prose. Never echo the raw evidence JSON.

Return concise markdown with these sections:
1. Daily Summary
2. Commits and Authors
3. Changed Functions and Callgraph Impact
4. Features or User Scenarios Affected
5. Evidence Gaps
"""


def generate_daily_product_summary_from_prompt(prompt: str):
    prompt = str(prompt or "")
    if not prompt:
        return {
            "answer": "No daily product change or commit evidence was available to summarize.",
            "prompt": "",
            "prompt_chars": 0,
            "original_prompt_chars": 0,
            "prompt_truncated": False,
        }
    truncated = len(prompt) > OPENAI_SEARCH_PROMPT_MAX_CHARS
    prompt_for_model = (
        prompt[:OPENAI_SEARCH_PROMPT_MAX_CHARS]
        + "\n\n[Evidence truncated by CodeVal to keep daily summary generation within production timeout limits.]"
        if truncated else prompt
    )
    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        return {
            "answer": "Daily product change and commit summary generation is not configured because OPENAI_API_KEY is not set.",
            "prompt": prompt_for_model,
            "prompt_chars": len(prompt_for_model),
            "original_prompt_chars": len(prompt),
            "prompt_truncated": truncated,
            "error": "OPENAI_API_KEY is not set.",
        }
    model = os.getenv("OPENAI_DAILY_SUMMARY_MODEL", os.getenv("OPENAI_SUMMARY_MODEL", os.getenv("OPENAI_SEARCH_MODEL", "gpt-4o-mini")))
    try:
        response = requests.post(
            "https://api.openai.com/v1/chat/completions",
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
            },
            json={
                "model": model,
                "messages": [
                    {
                        "role": "system",
                        "content": (
                            "You write concise English product change and commit summaries from commit, diff, function, and callgraph evidence. "
                            "Never echo raw JSON, never return fenced code, and never invent unsupported behavior."
                        ),
                    },
                    {"role": "user", "content": prompt_for_model},
                ],
                "max_tokens": min(1200, OPENAI_SEARCH_MAX_TOKENS),
                "temperature": 0.2,
            },
            timeout=(10, OPENAI_REQUEST_TIMEOUT_SECONDS),
        )
        response.raise_for_status()
        data = response.json()
        answer = (data["choices"][0]["message"]["content"] or "").strip()
        if answer.startswith("```"):
            answer = re.sub(r"^```(?:json|markdown|md)?\s*", "", answer.strip(), flags=re.IGNORECASE)
            answer = re.sub(r"\s*```$", "", answer.strip())
        return {
            "answer": answer,
            "prompt": prompt_for_model,
            "prompt_chars": len(prompt_for_model),
            "original_prompt_chars": len(prompt),
            "prompt_truncated": truncated,
            "model": model,
        }
    except requests.exceptions.Timeout:
        return {
            "answer": (
                f"Daily product change and commit summary generation timed out after {OPENAI_REQUEST_TIMEOUT_SECONDS} seconds. "
                "The commit evidence is still available; try a smaller date range or a single commit."
            ),
            "prompt": prompt_for_model,
            "prompt_chars": len(prompt_for_model),
            "original_prompt_chars": len(prompt),
            "prompt_truncated": truncated,
            "error": "timeout",
            "model": model,
        }
    except Exception as e:
        return {
            "answer": f"Error generating daily product change and commit summary: {str(e)}",
            "prompt": prompt_for_model,
            "prompt_chars": len(prompt_for_model),
            "original_prompt_chars": len(prompt),
            "prompt_truncated": truncated,
            "error": str(e),
            "model": model,
        }


def daily_summary_evidence_ids(daily_payload: dict):
    ids = ["repo_overview:evidence.repo.overview", "callgraph_summary:evidence.callgraph.summary"]
    for commit in (daily_payload.get("commits") or [])[:20]:
        sha = commit.get("short_sha") or str(commit.get("sha") or "")[:7]
        if sha:
            ids.append(f"github_commit:{sha}")
    for file_item in (daily_payload.get("changed_files") or [])[:50]:
        file_name = file_item.get("filename") if isinstance(file_item, dict) else file_item
        ids.append(f"changed_file:{file_name}")
    for symbol in (daily_payload.get("changed_functions") or [])[:50]:
        ids.append(f"code_function:{symbol}")
    for item in (daily_payload.get("changed_function_details") or [])[:50]:
        if isinstance(item, dict) and item.get("symbol"):
            ids.append(f"changed_function_range:{item.get('symbol')}:{item.get('start_line')}-{item.get('end_line')}")
    graph_url = daily_payload.get("graph_url") or ""
    if graph_url:
        ids.append(f"daily_change_graph:{graph_url}")
    return list(dict.fromkeys(ids))


def build_github_daily_change_graph_payload(owner: str, repo: str, days: int = 1, installation_id: str = "", sha: str = "", token: str = "", request: Request | None = None):
    days = max(1, min(int(days or 1), 30))
    installation_id = str(installation_id or "")
    commit_payload = github_daily_commits_for_token(owner, repo, days, installation_id, token)
    commits = list(reversed(commit_payload.get("commits", [])))
    selected_sha = str(sha or "").strip()
    if selected_sha:
        commits = [
            commit for commit in commits
            if str(commit.get("sha") or "").startswith(selected_sha) or str(commit.get("short_sha") or "") == selected_sha[:7]
        ]
    output_repo_dir = repo_output_dir(owner, repo)
    if not commits:
        return {**commit_payload, "graph_url": "", "message": "No commits found in the selected window.", "changed_files": [], "changed_functions": []}

    file_to_functions, callgraph_edges, outgoing, incoming = changed_file_function_index(owner, repo)
    nodes = set()
    edges = []
    edge_order = 1
    node_labels = {}
    changed_files = {}
    changed_functions = set()
    changed_function_details = {}

    def function_display_label(symbol: str) -> str:
        return display_callgraph_symbol(symbol)

    author_nodes = {}
    commit_nodes = {}
    for index, commit in enumerate(commits, start=1):
        sha = commit.get("sha", "")
        short_sha = commit.get("short_sha") or sha[:7]
        commit_node = f"commit:{short_sha}"
        author = commit.get("author") or "unknown author"
        author_node = f"author:{author}"
        commit_message = str(commit.get("message") or "").strip()
        commit_date = str(commit.get("date") or "").split("T", 1)[0]
        author_nodes[author] = author_node
        commit_nodes[short_sha] = commit_node
        nodes.update([author_node, commit_node])
        node_labels[author_node] = f"author: {author}"
        node_labels[commit_node] = " ".join(part for part in [short_sha, commit_message, commit_date] if part)
        edges.append((author_node, commit_node, edge_order, None))
        edge_order += 1

        commit_changed_functions = set()
        commit_changed_function_details = {}
        commit_changed_file_details = []
        commit_changed_files = 0
        try:
            detail_response = requests.get(
                f"https://api.github.com/repos/{owner}/{repo}/commits/{sha}",
                headers=github_headers(token),
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            if detail_response.status_code >= 400:
                logger.warning(
                    "GitHub commit detail request failed for %s/%s %s: status=%s token_configured=%s message=%s",
                    owner,
                    repo,
                    short_sha,
                    detail_response.status_code,
                    bool(normalize_github_token(token)),
                    safe_response_text(detail_response, 300),
                )
            detail_response.raise_for_status()
            detail = detail_response.json()
        except Exception as e:
            logger.warning("Unable to fetch commit detail for %s/%s %s: %s", owner, repo, short_sha, e)
            commit["impact_score"] = 5
            commit["impact_label"] = "Unknown change impact"
            commit["changed_function_count"] = 0
            commit["callgraph_neighbor_count"] = 0
            commit["callgraph_edge_count"] = 0
            commit["changed_functions"] = []
            commit["changed_function_details"] = []
            continue

        for file_item in detail.get("files", []) or []:
            filename = str(file_item.get("filename") or "").replace("\\", "/")
            if not filename:
                continue
            patch_text = str(file_item.get("patch") or "")
            changed_lines = changed_lines_from_patch(patch_text)
            line_ranges = changed_line_ranges(changed_lines)
            file_node = filename
            nodes.add(file_node)
            node_labels[file_node] = filename
            edges.append((commit_node, file_node, edge_order, None))
            edge_order += 1
            commit_changed_files += 1
            changed_files[filename] = {
                "filename": filename,
                "status": file_item.get("status", ""),
                "additions": file_item.get("additions", 0),
                "deletions": file_item.get("deletions", 0),
                "changes": file_item.get("changes", 0),
                "changed_line_ranges": line_ranges,
                "line_mapping_strategy": "patch_line_range_intersection" if changed_lines else "file_level_only_no_patch_lines",
                "patch_excerpt": patch_text[:12000] if int(file_item.get("changes") or 0) <= 180 else "",
                "patch_evidence": patch_evidence_from_patch(filename, patch_text),
            }
            commit_changed_file_details.append(changed_files[filename])
            changed_function_records = functions_for_changed_file(filename, file_to_functions, changed_lines)
            for function_record in changed_function_records:
                function_symbol = function_record["symbol"]
                function_node = function_symbol
                nodes.add(function_node)
                node_labels[function_node] = (
                    f"{function_display_label(function_symbol)} "
                    f"L{function_record.get('start_line')}-{function_record.get('end_line')}"
                )
                commit_changed_functions.add(function_symbol)
                detail = {
                    "symbol": function_symbol,
                    "path": function_record.get("path") or filename,
                    "start_line": function_record.get("start_line"),
                    "end_line": function_record.get("end_line"),
                    "changed_line_ranges": line_ranges,
                    "commit": short_sha,
                    "mapping_strategy": "patch_line_range_intersection",
                }
                commit_changed_function_details[function_symbol] = detail
                changed_function_details[function_symbol] = detail
                edges.append((file_node, function_node, edge_order, function_record.get("start_line")))
                edge_order += 1

        neighbor_functions = set()
        for function_symbol in commit_changed_functions:
            neighbor_functions.update(outgoing.get(function_symbol, []))
            neighbor_functions.update(incoming.get(function_symbol, []))

        internal_edge_count = 0
        for function_symbol in commit_changed_functions:
            for target in outgoing.get(function_symbol, []):
                if target in commit_changed_functions:
                    internal_edge_count += 1

        commit["changed_function_count"] = len(commit_changed_functions)
        commit["changed_file_count"] = commit_changed_files
        commit["changed_files"] = sorted(commit_changed_file_details, key=lambda item: item.get("filename") or "")
        commit["changed_functions"] = sorted(commit_changed_functions)
        commit["changed_function_details"] = sorted(
            commit_changed_function_details.values(),
            key=lambda item: (item.get("path") or "", item.get("start_line") or 0, item.get("symbol") or ""),
        )
        commit["callgraph_neighbor_count"] = len(neighbor_functions - commit_changed_functions)
        commit["callgraph_edge_count"] = internal_edge_count
        commit["impact_score"] = github_commit_impact_score(
            commit_message,
            commit_changed_files,
            len(commit_changed_functions),
            len(neighbor_functions - commit_changed_functions),
            internal_edge_count,
        )
        commit["impact_label"] = github_commit_impact_label(
            commit_message,
            commit_changed_files,
            len(commit_changed_functions),
            len(neighbor_functions - commit_changed_functions),
            internal_edge_count,
            commit["impact_score"],
        )
        if commit_changed_functions and not commit.get("sha"):
            commit["sha"] = sha

        changed_functions.update(commit_changed_functions)

    for src, dst in sorted(callgraph_edges):
        if src in changed_functions and dst in changed_functions:
            nodes.update([src, dst])
            edges.append((src, dst, edge_order, None))
            edge_order += 1

    core_change_edge_end_order = edge_order
    if selected_sha:
        neighbor_edge_limit = 160
        neighbor_edges_added = 0
        for function_symbol in sorted(changed_functions):
            for target in sorted(outgoing.get(function_symbol, set())):
                if neighbor_edges_added >= neighbor_edge_limit:
                    break
                nodes.update([function_symbol, target])
                node_labels.setdefault(target, function_display_label(target))
                edges.append((function_symbol, target, edge_order, None))
                edge_order += 1
                neighbor_edges_added += 1
            for source in sorted(incoming.get(function_symbol, set())):
                if neighbor_edges_added >= neighbor_edge_limit:
                    break
                nodes.update([source, function_symbol])
                node_labels.setdefault(source, function_display_label(source))
                edges.append((source, function_symbol, edge_order, None))
                edge_order += 1
                neighbor_edges_added += 1
            if neighbor_edges_added >= neighbor_edge_limit:
                break
    graph_name = f"daily_change_graph_{safe_filename(selected_sha[:12])}" if selected_sha else "daily_change_graph"
    graph_title = (
        f"Commit Change Graph: {owner}/{repo} {commits[0].get('short_sha')}"
        if selected_sha and commits
        else f"Daily Change Graph: {owner}/{repo}"
    )
    initial_nodes = set()
    initial_edges = []
    selected_commit_nodes = set(commit_nodes.values())
    for src, dst, order, line in edges:
        if (order or 0) < core_change_edge_end_order and (
            str(src).startswith("author:")
            or src in selected_commit_nodes
            or dst in selected_commit_nodes
            or src in changed_files
            or dst in changed_files
            or src in changed_functions
            or dst in changed_functions
        ):
            initial_nodes.update([src, dst])
            initial_edges.append((src, dst, order, line))
    if len(initial_nodes) > 80:
        initial_edges = initial_edges[:80]
        initial_nodes = {node for src, dst, _, _ in initial_edges for node in (src, dst)}
    initial_root = next(iter(commit_nodes.values()), "") or (sorted(nodes)[0] if nodes else "")
    graph_url = build_navigatable_cytoscape_graph(
        sorted(nodes),
        edges,
        output_repo_dir,
        graph_name=graph_name,
        graph_title=graph_title,
        initial_roots=[initial_root] if initial_root else None,
        entry_points=sorted(selected_commit_nodes),
        node_labels=node_labels,
        initial_visible_nodes=sorted(initial_nodes),
        initial_visible_edges=initial_edges,
    )
    process_graph_url = ""
    def commit_timestamp(item):
        try:
            return datetime.fromisoformat(
                str(item.get("date") or item.get("committed_at") or item.get("author_date") or "").replace("Z", "+00:00")
            ).timestamp()
        except Exception:
            return 0

    try:
        latest_commit = max(
            commits,
            key=commit_timestamp,
        )
    except Exception:
        latest_commit = commits[0] if commits else {}
    if latest_commit:
        latest_sha = latest_commit.get("sha", "")
        latest_short_sha = latest_commit.get("short_sha") or str(latest_sha)[:7] or "commit"
        latest_commit_node = f"commit:{latest_short_sha}"
        process_nodes = {latest_commit_node}
        process_edges = []
        process_labels = {
            latest_commit_node: " ".join(
                part for part in [
                    f"commit {latest_short_sha}",
                    str(latest_commit.get("message") or "").strip(),
                    str(latest_commit.get("date") or "").split("T", 1)[0],
                ] if part
            )
        }
        process_order = 1
        latest_files = latest_commit.get("changed_files") or []
        latest_function_details = latest_commit.get("changed_function_details") or []
        functions_by_file = defaultdict(list)
        for item in latest_function_details:
            if not isinstance(item, dict):
                continue
            functions_by_file[str(item.get("path") or "").replace("\\", "/")].append(item)
        for file_item in latest_files:
            if not isinstance(file_item, dict):
                continue
            filename = str(file_item.get("filename") or file_item.get("path") or "").replace("\\", "/")
            if not filename:
                continue
            file_node = f"file:{filename}"
            process_nodes.add(file_node)
            process_labels[file_node] = filename
            process_edges.append((latest_commit_node, file_node, process_order, None))
            process_order += 1
            matching_functions = list(functions_by_file.get(filename) or [])
            if not matching_functions:
                matching_functions = [
                    item for item in latest_function_details
                    if isinstance(item, dict) and file_path_matches(str(item.get("path") or ""), filename)
                ]
            for function_item in matching_functions:
                symbol = str(function_item.get("symbol") or "")
                if not symbol:
                    continue
                function_node = f"function:{symbol}"
                process_nodes.add(function_node)
                process_labels[function_node] = display_callgraph_symbol(symbol)
                process_edges.append((file_node, function_node, process_order, function_item.get("start_line")))
                process_order += 1
        if not process_edges:
            impact_node = f"impact:{latest_short_sha}"
            process_nodes.add(impact_node)
            process_labels[impact_node] = latest_commit.get("impact_label") or "No changed files mapped"
            process_edges.append((latest_commit_node, impact_node, process_order, None))
        process_graph_url = build_ordered_process_cytoscape_graph(
            sorted(process_nodes),
            process_edges,
            output_repo_dir,
            graph_name=f"daily_change_process_{safe_filename(str(latest_short_sha))}",
            graph_title=f"Latest Commit Process: {owner}/{repo} {latest_short_sha}",
            root=latest_commit_node,
            node_labels=process_labels,
        )
    response_payload = {
        **commit_payload,
        "daily_change_graph_version": DAILY_CHANGE_GRAPH_VERSION,
        "owner": owner,
        "repo": repo,
        "selected_sha": selected_sha,
        "commits": commits,
        "count": len(commits),
        "graph_url": graph_url,
        "graph_json_url": graph_url[:-5] + ".json" if graph_url.endswith(".html") else "",
        "process_graph_url": process_graph_url,
        "process_graph_json_url": process_graph_url[:-5] + ".json" if process_graph_url.endswith(".html") else "",
        "changed_files": sorted(changed_files.values(), key=lambda item: item["filename"]),
        "changed_functions": sorted(changed_functions),
        "changed_function_details": sorted(
            changed_function_details.values(),
            key=lambda item: (item.get("path") or "", item.get("start_line") or 0, item.get("symbol") or ""),
        ),
        "author_count": len(author_nodes),
        "message": f"Built {'commit' if selected_sha else 'daily'} change graph for {len(commits)} commits, {len(changed_files)} files, and {len(changed_functions)} mapped functions.",
    }
    if commit_payload.get("fallback_used") and not selected_sha:
        response_payload["message"] = (
            f"Built recent change graph for {len(commits)} commits, {len(changed_files)} files, "
            f"and {len(changed_functions)} mapped functions. {commit_payload.get('fallback_reason') or ''}".strip()
        )
    if not selected_sha:
        try:
            cache_path = Path(output_repo_dir) / "daily_change_cache.json"
            cache_path.write_text(json.dumps(response_payload, indent=2), encoding="utf-8")
            response_payload["daily_change_cache_url"] = output_url(str(cache_path))
            if request is not None:
                response_payload["supabase_cache"] = supabase_cache_latest_analysis_fields(
                    request,
                    owner,
                    repo,
                    {"daily_change_cache": response_payload, "daily_change_cache_updated_at": datetime.now().isoformat()},
                )
                response_payload["supabase_daily_snapshots"] = supabase_persist_daily_commit_snapshots(
                    request,
                    owner,
                    repo,
                    response_payload,
                )
        except Exception as e:
            logger.warning("Unable to cache daily change payload for %s/%s: %s", owner, repo, e)
            response_payload["supabase_cache"] = {"cached": False, "reason": str(e)[:500]}
    return response_payload


