@app.post("/github/daily-summary")
def github_daily_summary(request: Request, payload: dict):
    owner = str(payload.get("owner") or payload.get("owner_name") or "").strip()
    repo = str(payload.get("repo") or payload.get("repo_name") or "").strip()
    if not owner or not repo:
        raise HTTPException(status_code=400, detail="owner and repo are required")
    days = int(payload.get("days") or 1)
    installation_id = str(payload.get("installation_id") or payload.get("installationId") or "").strip()
    sha = str(payload.get("sha") or "").strip()
    daily_payload = payload.get("daily_change") if isinstance(payload.get("daily_change"), dict) else None
    if not daily_payload:
        daily_payload = github_daily_change_graph(request, owner, repo, days, installation_id, sha)
    prompt = str(payload.get("prompt") or "") or build_daily_summary_prompt(owner, repo, daily_payload)
    summary = generate_daily_product_summary_from_prompt(prompt)
    if not isinstance(summary, dict):
        summary = {"answer": str(summary or ""), "prompt": prompt, "prompt_chars": len(prompt), "original_prompt_chars": len(prompt)}
    snapshot_result = supabase_persist_daily_commit_snapshots(
        request,
        owner,
        repo,
        daily_payload,
        daily_summary=str(summary.get("answer") or ""),
    )
    return {
        **summary,
        "owner": owner,
        "repo": repo,
        "days": daily_payload.get("days", days),
        "daily_change": daily_payload,
        "graph_url": daily_payload.get("graph_url", ""),
        "retrieved_evidence_ids": daily_summary_evidence_ids(daily_payload),
        "supabase_daily_snapshots": snapshot_result,
    }


@app.post("/github/analyze")
def github_analyze_selected(request: Request, req: dict):
    repo_url = str(req.get("repoUrl") or "").strip()
    full_name = str(req.get("full_name") or req.get("fullName") or "").strip()
    installation_id = str(req.get("installation_id") or req.get("installationId") or "").strip()
    force_refresh = bool(req.get("force_refresh") or req.get("forceRefresh"))
    session = {}
    try:
        _, session = github_session_from_request(request)
    except HTTPException:
        if not installation_id:
            raise
    if not repo_url and full_name:
        owner, repo = parse_owner_repo_from_full_name(full_name)
        repo_url = f"https://github.com/{owner}/{repo}"
    if not repo_url:
        raise HTTPException(status_code=400, detail="repoUrl or full_name is required")
    try:
        owner, repo = parse_repo_url(repo_url)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    job_id = uuid.uuid4().hex
    repo_id = short_id(owner, repo)
    update_analyze_job(
        job_id,
        status="queued",
        message=f"The analysis journey for {owner}/{repo} has started.",
        owner_name=owner,
        repo_name=repo,
        repo=repo_id,
        created_at=datetime.now(timezone.utc).isoformat(),
    )
    thread = threading.Thread(
        target=run_analyze_job,
        args=(
            job_id,
            repo_url,
            github_installation_token(installation_id) if installation_id else session.get("access_token", ""),
            {
                "auth_source": "github_connected",
                "installation_id": installation_id or session.get("installation_id", ""),
                "user": session.get("user", {}),
            },
            force_refresh,
        ),
        daemon=True,
    )
    thread.start()
    return {"job_id": job_id, "status": "queued", "message": f"The analysis journey for {owner}/{repo} has started."}


@app.get("/google-analytics/login")
def google_analytics_login(request: Request, next: str = ""):
    client_id, _ = google_analytics_oauth_config()
    state = secrets.token_urlsafe(24)
    params = {
        "client_id": client_id,
        "redirect_uri": google_analytics_oauth_redirect_uri(request),
        "response_type": "code",
        "scope": GOOGLE_ANALYTICS_SCOPES,
        "access_type": "offline",
        "include_granted_scopes": "true",
        "prompt": "consent",
        "state": state,
    }
    response = RedirectResponse(f"https://accounts.google.com/o/oauth2/v2/auth?{urlencode(params)}")
    response.set_cookie(
        GOOGLE_ANALYTICS_STATE_COOKIE,
        state,
        httponly=True,
        samesite="lax",
        max_age=600,
    )
    if next:
        response.set_cookie(
            GOOGLE_ANALYTICS_NEXT_COOKIE,
            safe_local_redirect(next, "/"),
            httponly=True,
            samesite="lax",
            max_age=600,
        )
    return response


@app.get("/google-analytics/reconnect")
def google_analytics_reconnect(request: Request, next: str = ""):
    session_id = request.cookies.get(GOOGLE_ANALYTICS_SESSION_COOKIE, "")
    if session_id:
        with GOOGLE_ANALYTICS_SESSIONS_GUARD:
            GOOGLE_ANALYTICS_SESSIONS.pop(session_id, None)
    login_path = "/google-analytics/login"
    if next:
        login_path += f"?next={quote(safe_local_redirect(next, '/'))}"
    response = RedirectResponse(login_path)
    response.delete_cookie(GOOGLE_ANALYTICS_SESSION_COOKIE)
    response.delete_cookie(GOOGLE_ANALYTICS_STATE_COOKIE)
    response.delete_cookie(GOOGLE_ANALYTICS_NEXT_COOKIE)
    return response


