@app.get("/google-analytics/callback")
def google_analytics_callback(request: Request, code: str = "", state: str = "", error: str = ""):
    if error:
        next_path = safe_local_redirect(request.cookies.get(GOOGLE_ANALYTICS_NEXT_COOKIE, ""), "/?google_analytics_error=1#analytics-connect")
        response = RedirectResponse(next_path)
        response.delete_cookie(GOOGLE_ANALYTICS_STATE_COOKIE)
        response.delete_cookie(GOOGLE_ANALYTICS_NEXT_COOKIE)
        return response
    expected_state = request.cookies.get(GOOGLE_ANALYTICS_STATE_COOKIE, "")
    if not code:
        raise HTTPException(status_code=400, detail="Google OAuth code is missing")
    if not state or not expected_state or not secrets.compare_digest(state, expected_state):
        raise HTTPException(status_code=400, detail="Invalid Google OAuth state")

    client_id, client_secret = google_analytics_oauth_config()
    token_response = requests.post(
        "https://oauth2.googleapis.com/token",
        data={
            "client_id": client_id,
            "client_secret": client_secret,
            "code": code,
            "grant_type": "authorization_code",
            "redirect_uri": google_analytics_oauth_redirect_uri(request),
        },
        timeout=20,
    )
    token_response.raise_for_status()
    token_payload = token_response.json()
    access_token = token_payload.get("access_token", "")
    if not access_token:
        raise HTTPException(status_code=400, detail="Google did not return an access token")

    user = {}
    try:
        user_response = requests.get(
            "https://openidconnect.googleapis.com/v1/userinfo",
            headers=google_analytics_headers(access_token),
            timeout=20,
        )
        if user_response.ok:
            user = user_response.json()
    except Exception:
        user = {}

    session_id = create_google_analytics_session({
        "access_token": access_token,
        "refresh_token": token_payload.get("refresh_token", ""),
        "scope": token_payload.get("scope", ""),
        "token_type": token_payload.get("token_type", ""),
        "expires_at": datetime.utcnow().timestamp() + int(token_payload.get("expires_in") or 3600),
        "user": {
            "email": user.get("email", ""),
            "name": user.get("name", ""),
            "picture": user.get("picture", ""),
        },
    })
    next_path = safe_local_redirect(request.cookies.get(GOOGLE_ANALYTICS_NEXT_COOKIE, ""), "/?google_analytics=connected#analytics-connect")
    response = RedirectResponse(next_path)
    response.delete_cookie(GOOGLE_ANALYTICS_STATE_COOKIE)
    response.delete_cookie(GOOGLE_ANALYTICS_NEXT_COOKIE)
    response.set_cookie(
        GOOGLE_ANALYTICS_SESSION_COOKIE,
        session_id,
        httponly=True,
        samesite="lax",
        max_age=60 * 60 * 24 * 14,
    )
    return response


