@app.post("/google-analytics/register-error-dimensions")
def google_analytics_register_error_dimensions(request: Request, req: dict):
    session_id, session = google_analytics_session_from_request(request)
    property_id = normalize_google_analytics_property_id(
        req.get("property_id") or req.get("propertyId") or req.get("property") or ""
    )
    if not property_id:
        raise HTTPException(status_code=400, detail="property_id is required")

    scope = str(session.get("scope") or "")
    if "https://www.googleapis.com/auth/analytics.edit" not in scope:
        raise HTTPException(
            status_code=403,
            detail="Google Analytics edit scope is required. Reconnect Google Analytics, then try again.",
        )

    access_token = refresh_google_analytics_token(session_id, session)
    selected_properties = fetch_google_analytics_property_summaries(access_token)
    selected_property = next((prop for prop in selected_properties if prop.get("property_id") == property_id), None)
    if not selected_property:
        raise HTTPException(
            status_code=400,
            detail=(
                f"Selected GA4 property {property_id} was not found in the currently connected Google Analytics account. "
                "Reconnect Google Analytics, choose the property from the dropdown, and try again."
            ),
        )
    requested_resource = str(req.get("property_resource") or req.get("propertyResource") or "").strip()
    if requested_resource and requested_resource != selected_property.get("property"):
        raise HTTPException(
            status_code=400,
            detail=(
                f"Selected GA4 property mismatch. The browser selected {requested_resource}, "
                f"but property_id resolves to {selected_property.get('property')}."
            ),
        )
    headers = {**google_analytics_headers(access_token), "Content-Type": "application/json"}
    base_url = f"https://analyticsadmin.googleapis.com/v1beta/properties/{property_id}/customDimensions"
    property_resource = f"properties/{property_id}"
    logger.info(
        "Registering GA custom dimensions for selected property %s (%s) from account %s",
        property_id,
        selected_property.get("display_name", ""),
        selected_property.get("account_name", ""),
    )

    def list_custom_dimensions():
        dimensions = {}
        page_token = ""
        while True:
            params = {"pageSize": 200}
            if page_token:
                params["pageToken"] = page_token
            list_response = requests.get(
                base_url,
                headers=headers,
                params=params,
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            list_response.raise_for_status()
            payload = list_response.json()
            for dimension in payload.get("customDimensions", []) or []:
                parameter_name = dimension.get("parameterName", "")
                if parameter_name:
                    dimensions[parameter_name] = dimension
            page_token = payload.get("nextPageToken", "")
            if not page_token:
                break
        return dimensions

    try:
        existing = list_custom_dimensions()
    except requests.HTTPError as e:
        status_code = e.response.status_code if e.response is not None else 500
        detail = "Unable to list GA4 custom dimensions."
        if status_code in {401, 403}:
            detail = (
                "Unable to list GA4 custom dimensions. Reconnect Google Analytics with edit access "
                "and make sure your Google account can edit this GA4 property."
            )
        raise HTTPException(status_code=status_code, detail=detail)

    created = []
    already_exists = []
    errors = []
    for dimension in GA_ERROR_CUSTOM_DIMENSIONS:
        parameter_name = dimension["parameterName"]
        if parameter_name in existing:
            already_exists.append({
                "parameterName": parameter_name,
                "name": existing[parameter_name].get("name", ""),
                "displayName": existing[parameter_name].get("displayName", ""),
                "scope": existing[parameter_name].get("scope", ""),
                "archived": bool(existing[parameter_name].get("archived")),
            })
            continue
        body = {
            "parameterName": parameter_name,
            "displayName": dimension["displayName"],
            "description": dimension["description"],
            "scope": "EVENT",
        }
        try:
            create_response = requests.post(
                base_url,
                headers=headers,
                json=body,
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            if create_response.status_code == 409:
                already_exists.append({
                    "parameterName": parameter_name,
                    "displayName": dimension["displayName"],
                    "name": "",
                    "scope": "EVENT",
                    "archived": False,
                    "conflict": True,
                })
                continue
            create_response.raise_for_status()
            created_dimension = create_response.json()
            created.append({
                "parameterName": parameter_name,
                "name": created_dimension.get("name", ""),
                "displayName": created_dimension.get("displayName", dimension["displayName"]),
                "scope": created_dimension.get("scope", ""),
                "archived": bool(created_dimension.get("archived")),
            })
        except requests.HTTPError as e:
            errors.append({
                "parameterName": parameter_name,
                "status": e.response.status_code if e.response is not None else 500,
                "detail": safe_response_text(e.response) if e.response is not None else str(e),
            })

    try:
        verified = list_custom_dimensions()
    except Exception as e:
        verified = {}
        errors.append({
            "parameterName": "__verification__",
            "status": 500,
            "detail": f"Unable to verify custom dimensions after setup: {e}",
        })
    requested_names = [dimension["parameterName"] for dimension in GA_ERROR_CUSTOM_DIMENSIONS]
    verified_requested = [name for name in requested_names if name in verified]
    archived_requested = []
    missing_requested = [name for name in requested_names if name not in verified]
    return {
        "ok": not errors,
        "property_id": property_id,
        "property_resource": property_resource,
        "selected_property": selected_property,
        "admin_api_custom_dimensions_url": base_url,
        "created": created,
        "already_exists": already_exists,
        "errors": errors,
        "dimensions": requested_names,
        "requested_count": len(requested_names),
        "existing_active_count_before": len(existing),
        "existing_including_archived_count_before": len(existing),
        "active_custom_dimension_count_after": len(verified),
        "including_archived_custom_dimension_count_after": len(verified),
        "verified_active_dimensions": verified_requested,
        "archived_requested_dimensions": archived_requested,
        "missing_requested_dimensions": missing_requested,
        "archived_lookup_warning": "",
        "note": "GA4 can take time to expose newly created custom dimensions in Data API reports. Generate fresh events after registration.",
    }


def parse_ga_report_rows(response_json: dict):
    dimension_names = [item.get("name", "") for item in response_json.get("dimensionHeaders", [])]
    metric_names = [item.get("name", "") for item in response_json.get("metricHeaders", [])]
    rows = []
    for row in response_json.get("rows", []) or []:
        parsed = {}
        for index, value in enumerate(row.get("dimensionValues", []) or []):
            parsed[dimension_names[index] if index < len(dimension_names) else f"dimension_{index}"] = value.get("value", "")
        for index, value in enumerate(row.get("metricValues", []) or []):
            raw_value = value.get("value", "0")
            try:
                parsed[metric_names[index] if index < len(metric_names) else f"metric_{index}"] = int(raw_value)
            except ValueError:
                parsed[metric_names[index] if index < len(metric_names) else f"metric_{index}"] = raw_value
        rows.append(parsed)
    return rows


def ga_rows_have_custom_values(rows, keys):
    for row in rows or []:
        if any(ga_value_is_useful(row.get(key, "")) for key in keys):
            return True
    return False


def ga_mapping_graph_paths(artifact_root: Path):
    return [
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "html_ui" / "html_ui_graph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "java_merged" / "java_merged_callgraph.json",
        artifact_root / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        artifact_root / "javalang" / "javalang_callgraph.json",
        artifact_root / "joern" / "reduced_joern_callgraph.json",
        artifact_root / "joern" / "joern_callgraph.json",
    ]


def ga_value_is_useful(value):
    value = str(value or "").strip()
    return bool(value and value.lower() not in {"(not set)", "not set", "none", "null", "undefined", "#"})


def is_ga_collection_endpoint(value):
    text = str(value or "").lower()
    return (
        "analytics.google.com/g/collect" in text
        or "google-analytics.com/g/collect" in text
        or "google-analytics.com/collect" in text
        or "googletagmanager.com/gtag/js" in text
    )


def is_autotrack_analytics_beacon_row(row: dict):
    if not isinstance(row, dict):
        return False
    label = str(row.get("customEvent:button_name") or row.get("button_name") or "").lower()
    values = [
        row.get("customEvent:callgraph_node") or row.get("callgraph_node") or "",
        row.get("customEvent:function_name") or row.get("function_name") or "",
        row.get("customEvent:endpoint") or row.get("endpoint") or "",
    ]
    return "backend error" in label and any(is_ga_collection_endpoint(value) for value in values)


def ga_candidate_aliases(value: str):
    value = str(value or "").strip()
    if not ga_value_is_useful(value):
        return []
    candidates = [value]
    if value.startswith("js."):
        candidates.append(value[3:])
    else:
        candidates.append(f"js.{value}")
    if re.match(r"^[A-Za-z_$][\w$]*$", value):
        for suffix in ("Button", "Link", "Input", "Select", "Form"):
            if value.endswith(suffix) and len(value) > len(suffix):
                base = value[:-len(suffix)]
                candidates.extend([base, f"js.{base}"])
    compact = re.sub(r"[^A-Za-z0-9_$]+", " ", value).strip()
    if compact and compact != value:
        camel = "".join(part[:1].upper() + part[1:] for part in compact.split())
        if camel:
            camel = camel[:1].lower() + camel[1:]
            candidates.extend([camel, f"js.{camel}"])
    deduped = []
    for candidate in candidates:
        if candidate and candidate not in deduped:
            deduped.append(candidate)
    return deduped


DASHBOARD_GA_ID_FUNCTION_ALIASES = {
    "dashboardGaFetchButton": "fetchDashboardGaInteractions",
    "dashboardGaRegisterDimensionsButton": "registerDashboardGaErrorDimensions",
    "dashboardGithubAnalyzeButton": "analyzeDashboardGitHubRepo",
    "selfHealingAnalyzeButton": "analyzeLatestGaError",
    "dailyChangeButton": "fetchDailyChangeGraph",
    "dailySummarySendButton": "sendDailySummaryToLlm",
}

DASHBOARD_GA_LABEL_FUNCTION_ALIASES = {
    "analyze selected product": "analyzeDashboardGitHubRepo",
    "analyze selected repo": "analyzeDashboardGitHubRepo",
    "fetch ga interactions": "fetchDashboardGaInteractions",
    "load user activity": "fetchDashboardGaInteractions",
    "set up activity tracking": "registerDashboardGaErrorDimensions",
}

DASHBOARD_GA_FUNCTION_ROUTE_ALIASES = {
    "analyzeDashboardGitHubRepo": ("api.github_analyze", "api.analyze_start"),
    "fetchDashboardGaInteractions": ("api.google-analytics_callgraph-events",),
    "registerDashboardGaErrorDimensions": ("api.google-analytics_register-error-dimensions",),
    "analyzeLatestGaError": ("api.self-healing_analyze",),
    "fetchDailyChangeGraph": ("api.github_daily-change-graph",),
    "sendDailySummaryToLlm": ("api.github_daily-summary-prompt",),
}


def ga_endpoint_route_node(value: str):
    candidates = ga_endpoint_route_candidates(value)
    return candidates[0] if candidates else ""


def ga_endpoint_path(value: str):
    value = str(value or "").strip()
    if not ga_value_is_useful(value):
        return ""
    try:
        parsed = urlparse(value)
        path = parsed.path if parsed.scheme or parsed.netloc else value.split("?", 1)[0]
    except Exception:
        path = value.split("?", 1)[0]
    path = str(path or "").strip()
    if not path.startswith("/"):
        return ""
    if path.startswith(("/static/", "/lib/", "/output/", "/sample/")):
        return ""
    if path.lower().endswith((".html", ".css", ".js", ".json", ".png", ".jpg", ".jpeg", ".svg", ".ico")):
        return ""
    return path


def ga_locale_like_path_segment(segment: str):
    segment = str(segment or "").strip().strip("[]{}:")
    return bool(re.match(r"^[A-Za-z]{2}(?:[-_][A-Za-z]{2})?$", segment))


def ga_endpoint_route_paths(value: str):
    path = ga_endpoint_path(value)
    if not path:
        return []
    paths = [path]
    segments = [segment for segment in path.strip("/").split("/") if segment]
    if len(segments) > 1 and ga_locale_like_path_segment(segments[0]) and segments[0].lower() not in {"api"}:
        rest = "/" + "/".join(segments[1:])
        paths.extend([
            rest,
            "/[locale]" + rest,
            "/:locale" + rest,
            "/{locale}" + rest,
        ])
    deduped = []
    for candidate in paths:
        if candidate and candidate not in deduped:
            deduped.append(candidate)
    return deduped


def ga_route_module_symbol(route_path: str, method: str = ""):
    segments = [segment.strip("[]{}:") for segment in str(route_path or "").strip("/").split("/") if segment]
    if not segments:
        return ""
    clean_segments = [
        re.sub(r"[^A-Za-z0-9_$]+", "_", segment).strip("_") or "route"
        for segment in segments
    ]
    tail = ".route"
    method = str(method or "").strip().upper()
    if method in {"GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS", "HEAD"}:
        tail += f".{method}"
    return "app." + ".".join(clean_segments) + tail


def ga_endpoint_route_candidates(value: str, method: str = ""):
    candidates = []
    for route_path in ga_endpoint_route_paths(value):
        slug = js_route_slug(route_path, "root")
        route_candidates = [
            api_route_symbol(route_path),
            f"next.page.{slug}",
            f"route.{slug}",
            f"url.{slug}",
            ga_route_module_symbol(route_path, method),
        ]
        for candidate in route_candidates:
            if candidate and candidate not in candidates:
                candidates.append(candidate)
    return candidates


def ga_route_match_tokens_for_row(row: dict):
    tokens = set()
    method = str(row.get("customEvent:method") or row.get("method") or "").strip()
    for key in (
        "customEvent:endpoint", "endpoint",
        "customEvent:fetch_url", "fetch_url",
        "customEvent:request_path", "request_path",
        "customEvent:request_url", "request_url",
        "customEvent:page_path", "page_path",
        "customEvent:callgraph_node", "callgraph_node",
        "customEvent:function_name", "function_name",
    ):
        value = str(row.get(key, "") or "").strip()
        for route_path in ga_endpoint_route_paths(value):
            segments = [
                segment.strip("[]{}:").lower()
                for segment in route_path.strip("/").split("/")
                if segment.strip("[]{}:")
            ]
            for segment in segments:
                if ga_locale_like_path_segment(segment) or segment in {"api", "app", "pages", "page", "route"}:
                    continue
                tokens.add(segment)
        if ga_endpoint_route_candidates(value, method):
            for candidate in ga_endpoint_route_candidates(value, method):
                for part in re.split(r"[^A-Za-z0-9_$]+", candidate.lower()):
                    if len(part) > 2 and part not in {"api", "app", "page", "route", "next", "url"}:
                        tokens.add(part)
    return tokens


def ga_route_fallback_nodes_for_row(row: dict, nodes: list[str] | set[str], limit: int = 12):
    tokens = ga_route_match_tokens_for_row(row)
    if not tokens:
        return []
    method = str(row.get("customEvent:method") or row.get("method") or "").strip().lower()
    scored = []
    for node in nodes or []:
        text = str(node or "")
        lowered = text.lower()
        searchable = re.sub(r"[^a-z0-9]+", " ", lowered)
        matched = [token for token in tokens if token and re.search(rf"(^|[^a-z0-9]){re.escape(token)}([^a-z0-9]|$)", searchable)]
        if not matched:
            continue
        score = len(set(matched)) * 10
        if method and method in searchable:
            score += 6
        if any(marker in lowered for marker in ("route", "page", "api", "handler", "controller")):
            score += 3
        if lowered.startswith(("api.", "next.page.", "app.", "pages.")):
            score += 2
        scored.append((score, len(text), text))
    return [node for _, _, node in sorted(scored, key=lambda item: (-item[0], item[1], item[2]))[:limit]]


def ga_add_mapping_terms(terms: set[str], value: str):
    if not ga_value_is_useful(value):
        return
    value = str(value).strip()
    for candidate in ga_candidate_aliases(value):
        terms.add(str(candidate).lower())
        if str(candidate).startswith("js."):
            terms.add(str(candidate)[3:].lower())
        alias = DASHBOARD_GA_ID_FUNCTION_ALIASES.get(str(candidate))
        if alias:
            terms.add(alias.lower())
            terms.add(f"js.{alias}".lower())
    label_alias = DASHBOARD_GA_LABEL_FUNCTION_ALIASES.get(value.lower())
    if label_alias:
        terms.add(label_alias.lower())
        terms.add(f"js.{label_alias}".lower())


def ga_row_mapping_terms(row: dict):
    terms = set()
    direct_keys = (
        "customEvent:callgraph_node", "callgraph_node",
        "customEvent:function_name", "function_name",
        "customEvent:click_id", "click_id",
        "customEvent:input_value", "input_value",
    )
    endpoint_keys = (
        "customEvent:endpoint", "endpoint",
        "customEvent:fetch_url", "fetch_url",
        "customEvent:request_path", "request_path",
        "customEvent:request_url", "request_url",
        "customEvent:page_path", "page_path",
    )
    candidate_keys = direct_keys + endpoint_keys + (
        "customEvent:button_name", "button_name",
        "customEvent:click_text", "click_text",
    )
    for key in candidate_keys:
        value = str(row.get(key, "") or "").strip()
        method = str(row.get("customEvent:method") or row.get("method") or "").strip()
        route_nodes = ga_endpoint_route_candidates(value, method)
        if route_nodes:
            for route_node in route_nodes:
                ga_add_mapping_terms(terms, route_node)
            continue
        if value.startswith(("http://", "https://", "/")):
            continue
        ga_add_mapping_terms(terms, value)
    return terms


def callgraph_nodes_for_mapping(owner_name: str, repo_name: str):
    if not owner_name or not repo_name:
        return []
    nodes = set()

    def add_value(value):
        if value:
            nodes.add(str(value))

    def walk(value):
        if isinstance(value, dict):
            for key in ("id", "label", "name", "fullName", "symbol", "method", "caller", "callee", "source", "target", "callee_fullName"):
                add_value(value.get(key))
            for call in value.get("calls") or []:
                walk(call)
        elif isinstance(value, list):
            if len(value) == 2 and all(isinstance(item, str) for item in value):
                add_value(value[0])
                add_value(value[1])
            else:
                for item in value:
                    walk(item)
        elif isinstance(value, str):
            add_value(value)

    output_repo_dir = repo_output_dir(owner_name, repo_name)
    artifact_root = artifact_root_for_output(output_repo_dir)
    try:
        callgraph, _ = load_search_callgraph(output_repo_dir)
        walk(callgraph)
    except Exception:
        pass

    try:
        functions_path = find_scim_functions_path(output_repo_dir)
        if functions_path:
            records = load_scim_function_records(functions_path.parent)
            for symbol, record in records.items():
                add_value(symbol)
                path = str(record.get("path") or "").replace("\\", "/")
                if path:
                    add_value(path)
    except Exception:
        pass

    for graph_path in ga_mapping_graph_paths(artifact_root):
        graph_nodes, graph_edges = _load_edge_graph(str(graph_path))
        nodes.update(graph_nodes)
        for src, dst in graph_edges:
            add_value(src)
            add_value(dst)

    return sorted(nodes)


def map_ga_rows_to_callgraph(rows: list[dict], owner_name: str = "", repo_name: str = ""):
    nodes = callgraph_nodes_for_mapping(owner_name, repo_name)
    if not nodes:
        return {"node_count": 0, "matches": []}
    lowered_nodes = [(node.lower(), node) for node in nodes]
    matches_by_node = defaultdict(int)
    evidence_by_node = defaultdict(list)
    for row in rows:
        matched_nodes = ga_matching_nodes_for_row(row, lowered_nodes)
        count = int(row.get("eventCount") or 0)
        if not matched_nodes or not count:
            continue
        for node in matched_nodes:
            matches_by_node[node] += count
            if len(evidence_by_node[node]) < 3:
                evidence_by_node[node].append(row)
    matches = [
        {"node": node, "event_count": count, "evidence": evidence_by_node[node]}
        for node, count in sorted(matches_by_node.items(), key=lambda item: item[1], reverse=True)
    ]
    return {"node_count": len(nodes), "matches": matches[:100]}


def load_ga_mapping_network(output_repo_dir):
    artifact_root = artifact_root_for_output(output_repo_dir)
    graph_nodes = set()
    graph_edges = set()

    try:
        callgraph, _ = load_search_callgraph(output_repo_dir)
        _, _, outgoing, _, _ = callgraph_indexes(callgraph)
        for src, targets in outgoing.items():
            graph_nodes.add(src)
            for dst in targets:
                graph_nodes.add(dst)
                graph_edges.add((src, dst))
    except Exception:
        pass

    for graph_path in ga_mapping_graph_paths(artifact_root):
        nodes, edges = _load_edge_graph(str(graph_path))
        graph_nodes.update(nodes)
        graph_edges.update(edges)

    try:
        functions_path = find_scim_functions_path(output_repo_dir)
        if functions_path:
            graph_nodes.update(load_scim_function_records(functions_path.parent).keys())
    except Exception:
        pass

    outgoing = defaultdict(set)
    incoming = defaultdict(set)
    for src, dst in graph_edges:
        outgoing[src].add(dst)
        incoming[dst].add(src)
    return graph_nodes, graph_edges, outgoing, incoming


def load_ga_mapping_network_with_meta(output_repo_dir):
    artifact_root = artifact_root_for_output(output_repo_dir)
    graph_nodes = set()
    graph_edges = set()
    edge_meta = {}
    node_labels = {}

    try:
        callgraph, _ = load_search_callgraph(output_repo_dir)
        _, _, outgoing, _, _ = callgraph_indexes(callgraph)
        for src, targets in outgoing.items():
            graph_nodes.add(src)
            for dst in targets:
                graph_nodes.add(dst)
                graph_edges.add((src, dst))
    except Exception:
        pass

    for graph_path in ga_mapping_graph_paths(artifact_root):
        nodes, edges, meta = _load_edge_graph_with_meta(str(graph_path))
        graph_nodes.update(nodes)
        graph_edges.update(edges)
        node_labels.update(_load_graph_node_labels(str(graph_path)))
        for edge, value in meta.items():
            previous = edge_meta.get(edge)
            order = value.get("order")
            if previous is None or (order is not None and order < (previous.get("order") or order)):
                edge_meta[edge] = value

    try:
        functions_path = find_scim_functions_path(output_repo_dir)
        if functions_path:
            for symbol, record in load_scim_function_records(functions_path.parent).items():
                graph_nodes.add(symbol)
                path = str(record.get("path") or "").replace("\\", "/")
                if path:
                    node_labels.setdefault(symbol, f"{symbol} ({path})")
    except Exception:
        pass

    outgoing = defaultdict(set)
    incoming = defaultdict(set)
    for src, dst in graph_edges:
        outgoing[src].add(dst)
        incoming[dst].add(src)
    return graph_nodes, graph_edges, outgoing, incoming, edge_meta, node_labels


def ga_row_label(row: dict):
    for key in (
        "customEvent:button_name", "button_name",
        "customEvent:click_text", "click_text",
        "customEvent:function_name", "function_name",
        "customEvent:callgraph_node", "callgraph_node",
        "pagePath", "pageTitle",
    ):
        value = str(row.get(key, "") or "").strip()
        if ga_value_is_useful(value):
            return value[:80]
    return "GA interaction"


def ga_row_sort_key(row: dict):
    def int_value(*keys):
        for key in keys:
            raw = str(row.get(key, "") or "").strip()
            if raw.isdigit():
                return int(raw)
        return 0

    return (
        str(row.get("dateHourMinute") or row.get("dateHour") or row.get("date") or ""),
        int_value("customEvent:batch_page_id", "batch_page_id"),
        int_value("customEvent:batch_ordering_id", "batch_ordering_id"),
        ga_row_label(row).lower(),
    )


GA_DEDUPE_TIME_KEYS = {"dateHourMinute", "dateHour", "date", "hour", "minute"}
GA_DEDUPE_METRIC_KEYS = {"eventCount", "event_count", "time_buckets", "first_time_bucket", "last_time_bucket"}
GA_STORED_EVENT_LIMIT = max(25, min(int(os.getenv("CODEVAL_GA_STORED_EVENT_LIMIT", "50") or "50"), 1000))


def ga_row_time_bucket(row: dict):
    return str(row.get("dateHourMinute") or row.get("dateHour") or row.get("date") or "").strip()


def ga_interaction_identity_key(row: dict):
    if not isinstance(row, dict):
        return ""
    parts = []
    for key in sorted(row.keys()):
        if key in GA_DEDUPE_TIME_KEYS or key in GA_DEDUPE_METRIC_KEYS:
            continue
        value = row.get(key)
        if value in (None, ""):
            continue
        parts.append(f"{key}={str(value).strip()}")
    return "\n".join(parts)


def unique_ga_interaction_rows(rows: list[dict]):
    merged = {}
    order = []
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        key = ga_interaction_identity_key(row)
        if not key:
            key = json.dumps(
                {k: v for k, v in row.items() if k not in (GA_DEDUPE_TIME_KEYS | GA_DEDUPE_METRIC_KEYS)},
                sort_keys=True,
                default=str,
            )
        if key not in merged:
            merged[key] = {
                **row,
                "eventCount": 0,
                "time_buckets": [],
                "first_time_bucket": "",
                "last_time_bucket": "",
            }
            order.append(key)
        try:
            merged[key]["eventCount"] = int(merged[key].get("eventCount") or 0) + int(row.get("eventCount") or 0)
        except (TypeError, ValueError):
            pass
        bucket = ga_row_time_bucket(row)
        if bucket and bucket not in merged[key]["time_buckets"]:
            merged[key]["time_buckets"].append(bucket)
        if bucket and (not merged[key]["first_time_bucket"] or bucket < merged[key]["first_time_bucket"]):
            merged[key]["first_time_bucket"] = bucket
        if bucket and (not merged[key]["last_time_bucket"] or bucket > merged[key]["last_time_bucket"]):
            merged[key]["last_time_bucket"] = bucket
    return [merged[key] for key in order]


def ga_row_int(row: dict, key: str, default=0):
    try:
        return int(row.get(key) or default)
    except (TypeError, ValueError):
        return default


def ga_row_signal_score(row: dict):
    if not isinstance(row, dict):
        return 0
    score = ga_row_int(row, "eventCount")
    for key in (
        "customEvent:error_message", "error_message",
        "customEvent:ui_message", "ui_message",
        "customEvent:severity", "severity",
        "customEvent:status", "status",
        "customEvent:response_body", "response_body",
    ):
        if ga_value_is_useful(row.get(key)):
            score += 250
    for key in (
        "customEvent:callgraph_node", "callgraph_node",
        "customEvent:function_name", "function_name",
        "customEvent:endpoint", "endpoint",
        "customEvent:request_url", "request_url",
    ):
        if ga_value_is_useful(row.get(key)):
            score += 90
    return score


def limit_ga_interaction_rows(rows: list[dict], limit: int = GA_STORED_EVENT_LIMIT):
    rows = [row for row in rows or [] if isinstance(row, dict)]
    if len(rows) <= limit:
        return rows, 0
    ranked = sorted(
        rows,
        key=lambda row: (
            ga_row_signal_score(row),
            ga_row_int(row, "eventCount"),
            str(row.get("last_time_bucket") or ga_row_time_bucket(row)),
        ),
        reverse=True,
    )
    return ranked[:limit], len(rows) - limit


def ga_matching_nodes_for_row(row: dict, lowered_nodes):
    terms = ga_row_mapping_terms(row)
    matches = []
    if terms:
        for lower_node, node in lowered_nodes:
            tail = lower_node.rsplit(".", 1)[-1]
            if lower_node in terms or (tail and tail in terms):
                matches.append(node)
    if not matches:
        nodes = [node for _, node in lowered_nodes]
        matches.extend(ga_route_fallback_nodes_for_row(row, nodes))
    return matches


def build_ga_analysis_graph(owner_name: str, repo_name: str, rows: list[dict], depth: int = 1):
    if not owner_name or not repo_name or not rows:
        return "", {"node_count": 0, "matches": []}

    mapping = map_ga_rows_to_callgraph(rows, owner_name, repo_name)
    root_nodes = [item.get("node") for item in mapping.get("matches", []) if item.get("node")]
    if not root_nodes:
        return "", mapping

    output_repo_dir = repo_output_dir(owner_name, repo_name)
    _, _, outgoing, incoming = load_ga_mapping_network(output_repo_dir)

    selected_nodes = set(root_nodes)
    selected_edges = set()
    queue = deque((node, 0) for node in root_nodes)
    seen = set(root_nodes)
    while queue and len(selected_nodes) < 160:
        node, distance = queue.popleft()
        if distance >= depth:
            continue
        for neighbor in sorted(outgoing.get(node, set()) | incoming.get(node, set())):
            if neighbor in outgoing.get(node, set()):
                selected_edges.add((node, neighbor))
            if neighbor in incoming.get(node, set()):
                selected_edges.add((neighbor, node))
            selected_nodes.add(neighbor)
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append((neighbor, distance + 1))

    graph_name = "ga_analysis_graph"
    graph_url = build_generic_cytoscape_graph(
        sorted(selected_nodes),
        [(src, dst) for src, dst in sorted(selected_edges)],
        output_repo_dir,
        graph_name=graph_name,
        graph_title="GA Analysis Graph",
    )
    return graph_url, mapping


def build_ga_ordered_interaction_graph(owner_name: str, repo_name: str, rows: list[dict]):
    if not owner_name or not repo_name or not rows:
        return ""
    nodes = callgraph_nodes_for_mapping(owner_name, repo_name)
    if not nodes:
        return ""
    lowered_nodes = [(node.lower(), node) for node in nodes]

    ordered_items = []
    for row in sorted(rows, key=ga_row_sort_key):
        count = int(row.get("eventCount") or 0)
        matched_nodes = ga_matching_nodes_for_row(row, lowered_nodes)
        if not count or not matched_nodes:
            continue
        ordered_items.append({
            "row": row,
            "count": count,
            "label": ga_row_label(row),
            "matched_nodes": matched_nodes[:3],
        })

    if not ordered_items:
        return ""

    output_repo_dir = repo_output_dir(owner_name, repo_name)
    graph_nodes = set()
    graph_edges = []
    previous_event_node = ""
    edge_order = 1

    for index, item in enumerate(ordered_items[:120], start=1):
        label = re.sub(r"[^A-Za-z0-9_.-]+", "_", item["label"]).strip("_")[:40] or "interaction"
        event_node = f"ga.step_{index:03d}.{label}"
        graph_nodes.add(event_node)
        if previous_event_node:
            graph_edges.append((previous_event_node, event_node, edge_order, None))
            edge_order += 1
        previous_event_node = event_node
        for matched_node in item["matched_nodes"]:
            graph_nodes.add(matched_node)
            graph_edges.append((event_node, matched_node, edge_order, None))
            edge_order += 1

    return build_generic_cytoscape_graph(
        sorted(graph_nodes),
        graph_edges,
        output_repo_dir,
        graph_name="ga_ordered_interaction_graph",
        graph_title="GA Ordered Interaction Graph",
    )


def build_ga_events_only_graph(property_id: str, event_name: str, rows: list[dict]):
    if not rows:
        return ""
    output_dir = BASE_OUTPUT / "ga_activity" / stable_text_id(f"{property_id}:{event_name}")[:16]
    output_dir.mkdir(parents=True, exist_ok=True)
    graph_nodes = set()
    graph_edges = []
    node_labels = {}
    previous_event_node = ""
    edge_order = 1
    for index, row in enumerate(sorted(rows, key=ga_row_sort_key)[:160], start=1):
        count = int(row.get("eventCount") or 0)
        if not count:
            continue
        label = ga_row_label(row)
        node_id = f"ga.step_{index:03d}.{stable_text_id(ga_interaction_identity_key(row) or label)[:10]}"
        graph_nodes.add(node_id)
        node_labels[node_id] = f"{label} ({count})"
        if previous_event_node:
            graph_edges.append((previous_event_node, node_id, edge_order, None))
            edge_order += 1
        previous_event_node = node_id
    if not graph_nodes:
        return ""
    return build_generic_cytoscape_graph(
        sorted(graph_nodes),
        graph_edges,
        output_dir,
        graph_name="ga_events_map",
        graph_title="GA Events Map",
        node_labels=node_labels,
    )


def build_ga_event_callgraph_map(owner_name: str, repo_name: str, rows: list[dict], mapping: Optional[dict] = None):
    if not owner_name or not repo_name or not rows:
        return ""
    nodes = callgraph_nodes_for_mapping(owner_name, repo_name)
    if not nodes:
        return ""
    lowered_nodes = [(node.lower(), node) for node in nodes]
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    graph_nodes = set()
    graph_edges = []
    node_labels = {}
    edge_order = 1

    for index, row in enumerate(sorted(rows, key=ga_row_sort_key)[:160], start=1):
        count = int(row.get("eventCount") or 0)
        if not count:
            continue
        matched_nodes = ga_matching_nodes_for_row(row, lowered_nodes)
        if not matched_nodes:
            continue
        label = ga_row_label(row)
        event_node = f"ga.event.{index:03d}.{stable_text_id(ga_interaction_identity_key(row) or label)[:10]}"
        graph_nodes.add(event_node)
        node_labels[event_node] = f"GA event: {label} ({count})"
        for matched_node in matched_nodes[:8]:
            graph_nodes.add(matched_node)
            node_labels.setdefault(matched_node, matched_node)
            graph_edges.append((event_node, matched_node, count or edge_order, None))
            edge_order += 1

    if not graph_edges:
        return ""
    return build_generic_cytoscape_graph(
        sorted(graph_nodes),
        graph_edges,
        output_repo_dir,
        graph_name="ga_event_callgraph_map",
        graph_title="GA Event to Callgraph Map",
        node_labels=node_labels,
    )


def build_navigatable_cytoscape_graph(
    nodes,
    edges,
    output_repo_dir,
    graph_name,
    graph_title="Navigable Graph",
    initial_roots=None,
    entry_points=None,
    node_labels=None,
    initial_visible_nodes=None,
    initial_visible_edges=None,
    edge_labels=None,
    highlight_data=None,
    preserve_initial_order=False,
):
    output_repo_dir = Path(output_repo_dir)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    json_path = output_repo_dir / f"{graph_name}.json"
    html_path = output_repo_dir / f"{graph_name}.html"
    node_set = set(nodes or [])
    initial_roots = [root for root in (initial_roots or []) if root in node_set]
    if not initial_roots and nodes:
        initial_roots = nodes[:1]
    if not initial_visible_nodes and initial_roots:
        edge_pairs = [(edge[0], edge[1]) for edge in edges if len(edge) >= 2]
        preview_nodes, preview_edges = navigatable_initial_preview(nodes, edge_pairs, initial_roots[0], max_nodes=12)
        if preview_nodes:
            edge_meta_by_pair = {}
            for edge in edges:
                if len(edge) >= 4:
                    edge_meta_by_pair[(edge[0], edge[1])] = (edge[2], edge[3])
            initial_visible_nodes = preview_nodes
            initial_visible_edges = [
                (src, dst, *edge_meta_by_pair.get((src, dst), (None, None)))
                for src, dst in preview_edges
            ]
    if preserve_initial_order:
        initial_visible_nodes = list(dict.fromkeys(initial_visible_nodes or []))
    else:
        initial_visible_nodes = sorted(set(initial_visible_nodes or []))
    graph_data = {
        "mode": "navigatable_ordered_ga_graph",
        "title": graph_title,
        "nodes": sorted(set(nodes)),
        "edges": [[src, dst, order, line] for src, dst, order, line in edges],
        "initial_roots": initial_roots,
        "entry_points": sorted(set(entry_points or initial_roots or [])),
        "initial_visible_nodes": initial_visible_nodes,
        "initial_visible_edges": [[src, dst, order, line] for src, dst, order, line in (initial_visible_edges or [])],
        "node_labels": node_labels or {},
        "edge_labels": edge_labels or {},
        "highlight": highlight_data or {},
        "instructions": "Click a node to reveal the next connected node or edge.",
    }
    json_path.write_text(json.dumps(graph_data, indent=2), encoding="utf-8")
    relative_json = os.path.relpath(json_path, BASE_OUTPUT).replace("\\", "/")
    graph_json_url = f"{OUTPUT_URL_PREFIX}/{relative_json}"
    embedded = json.dumps(graph_data, separators=(",", ":"))
    html = f"""<!DOCTYPE html>
<html>
<head>
  <meta charset=\"utf-8\" />
  <title>{graph_title}</title>
  <style>
    html, body {{ width:100%; height:100%; margin:0; overflow:hidden; font-family:Arial, sans-serif; background:#ffffff; color:#111827; }}
    #cy {{ position:absolute; inset:0; min-height:100%; background:#ffffff; }}
    #status {{ position:absolute; left:8px; top:8px; z-index:10; max-width:calc(100% - 200px); font-size:13px; color:#334155; }}
    #status summary {{ display:flex; align-items:center; gap:6px; cursor:pointer; list-style:none; background:rgba(255,255,255,.94); border:1px solid #dbe3ef; border-radius:6px; padding:7px 9px; line-height:1.35; }}
    #status summary::-webkit-details-marker {{ display:none; }}
    #status summary::after {{ content:""; width:0; height:0; border-left:4px solid transparent; border-right:4px solid transparent; border-top:5px solid #475569; flex:0 0 auto; }}
    #status[open] summary::after {{ border-top:0; border-bottom:5px solid #475569; }}
    #statusBody {{ margin-top:6px; background:rgba(255,255,255,.94); border:1px solid #dbe3ef; border-radius:6px; padding:7px 9px; line-height:1.35; }}
    #statusBody:empty {{ display:none; }}
    #legend {{ position:absolute; right:8px; bottom:8px; z-index:11; width:min(300px, calc(100% - 16px)); font-size:12px; color:#334155; display:flex; flex-direction:column-reverse; }}
    #legend summary {{ display:flex; justify-content:space-between; align-items:center; gap:8px; width:max-content; max-width:100%; margin-left:auto; cursor:pointer; list-style:none; background:rgba(255,255,255,.96); border:1px solid #dbe3ef; border-radius:6px; padding:7px 10px; color:#111827; font-weight:700; box-shadow:0 8px 24px rgba(15,23,42,.08); }}
    #legend summary::-webkit-details-marker {{ display:none; }}
    #legend summary::after {{ content:""; width:0; height:0; border-left:4px solid transparent; border-right:4px solid transparent; border-bottom:5px solid #475569; }}
    #legend[open] summary::after {{ border-bottom:0; border-top:5px solid #475569; }}
    #legendPanel {{ margin-bottom:6px; background:rgba(255,255,255,.96); border:1px solid #dbe3ef; border-radius:6px; padding:8px 10px; box-shadow:0 12px 30px rgba(15,23,42,.12); }}
    #legend .legend-row {{ display:flex; gap:6px; align-items:flex-start; margin-top:4px; line-height:1.25; }}
    #legend .legend-key {{ min-width:78px; color:#dc2626; font-weight:700; display:flex; align-items:center; gap:5px; }}
    #legend .legend-note {{ color:#64748b; }}
    #legend .legend-dot {{ width:9px; height:9px; border-radius:50%; flex:0 0 auto; }}
    #nodeLegendRows:not(:empty) {{ padding-bottom:6px; margin-bottom:4px; border-bottom:1px solid #dbe3ef; }}
    @media (max-width: 640px) {{
      #status {{ left:8px; right:8px; max-width:none; }}
    }}
  </style>
</head>
<body>
  <details id=\"status\" open><summary id=\"statusSummary\">Loading {graph_title}...</summary><div id=\"statusBody\"></div></details>
  <details id=\"legend\"><summary>Legend</summary><div id=\"legendPanel\"><div id=\"nodeLegendRows\"></div><div id=\"legendRows\">Loading relationships...</div></div></details>
  <div id=\"cy\"></div>
  <script>
    const GRAPH_JSON = \"{graph_json_url}\";
    const CODEVAL_NAV_LAYOUT_VERSION = \"single-root-progressive-v6\";
    const EMBEDDED_GRAPH_DATA = {embedded};
    const statusEl = document.getElementById(\"status\");
    const statusSummaryEl = document.getElementById(\"statusSummary\");
    const statusBodyEl = document.getElementById(\"statusBody\");
    function setStatus(summary, body) {{
      statusSummaryEl.textContent = summary;
      statusBodyEl.textContent = body || \"\";
    }}
    function showGraphError(err) {{
      document.documentElement.style.background = \"#ffffff\";
      document.body.style.background = \"#ffffff\";
      const message = err && err.message ? err.message : String(err || \"Unknown graph render error\");
      statusEl.open = true;
      setStatus(\"Graph render error\", message);
      console.error(err);
    }}
    window.addEventListener(\"error\", event => showGraphError(event.error || event.message));
    window.addEventListener(\"unhandledrejection\", event => showGraphError(event.reason));
    function loadScript(src) {{
      return new Promise((resolve, reject) => {{
        const script = document.createElement(\"script\");
        script.src = src;
        script.onload = resolve;
        script.onerror = () => reject(new Error(`Failed to load script ${{src}}`));
        document.head.appendChild(script);
      }});
    }}
    function loadCytoscape() {{
      return loadScript(\"/lib/cytoscape/cytoscape.min.js\")
        .catch(() => loadScript(\"https://unpkg.com/cytoscape@3.28.1/dist/cytoscape.min.js\"));
    }}
    let nodeLabels = {{}};
      function compactLabel(raw) {{
        const label = String(raw || \"\");
        function limit(value) {{
          value = String(value || \"\")
            .replace(/\*\*([^*]+)\*\*/g, \"$1\")
            .replace(/\s+\./g, \".\")
            .replace(/\.\s+/g, \".\");
        return value.length > 76 ? `${{value.slice(0, 34)}}...${{value.slice(-34)}}` : value;
        }}
        if (nodeLabels[label]) return limit(nodeLabels[label]);
      const dottedParts = label.split(\".\");
      if (dottedParts.length >= 3 && !label.includes(\"/\") && !label.startsWith(\"api.\") && !label.startsWith(\"url.\")) {{
        return limit(`${{dottedParts.slice(0, -1).join(\".\")}}\\n${{dottedParts[dottedParts.length - 1]}}`);
      }}
      const stepMatch = label.match(/^ga\\.step_(\\d+)\\.(.+)$/);
      if (stepMatch) {{
        return limit(`step ${{Number(stepMatch[1])}}: ${{stepMatch[2].replace(/_/g, \" \")}}`);
      }}
      if (label.startsWith(\"api.\")) {{
        const route = label.slice(4);
        if (route === \"root\" || route === \"api\" || route === \"item\") return \"/\";
        return limit(`/${{route.replace(/_/g, \"/\")}}`);
      }}
      if (label.startsWith(\"url.\")) return limit(label.slice(4).replace(/_/g, \"/\"));
      if (label.includes(\"/\")) {{
        const parts = label.split(\"/\").filter(Boolean);
        if (parts.length > 3) {{
          return limit(`${{parts.slice(0, -2).join(\"/\")}}/\\n${{parts.slice(-2).join(\"/\")}}`);
        }}
      }}
      return limit(label);
    }}
    function sanitize(raw) {{ return String(raw).replace(/[^a-zA-Z0-9_]/g, \"_\"); }}
    function countLabel(count, singular, plural) {{
      return `${{count}} ${{count === 1 ? singular : plural}}`;
    }}
    function loadGraphData() {{
      return fetch(GRAPH_JSON).then(r => r.ok ? r.json() : Promise.reject(new Error(`Failed to load ${{GRAPH_JSON}}`))).catch(() => EMBEDDED_GRAPH_DATA);
    }}
    loadCytoscape().then(loadGraphData).then(data => {{
      const rawEdges = Array.isArray(data.edges) ? data.edges : [];
      const rawNodes = Array.isArray(data.nodes) ? data.nodes : [];
      nodeLabels = data.node_labels && typeof data.node_labels === \"object\" ? data.node_labels : {{}};
      const edgeLabels = data.edge_labels && typeof data.edge_labels === \"object\" ? data.edge_labels : {{}};
      const highlight = data.highlight && typeof data.highlight === \"object\" ? data.highlight : {{}};
      function highlightIdSet(values) {{
        return new Set((Array.isArray(values) ? values : []).map(value => sanitize(value)).filter(Boolean));
      }}
      const rootHighlightIds = highlightIdSet(highlight.changed_nodes || highlight.roots || []);
      const affectedHighlightIds = highlightIdSet(highlight.affected_nodes || []);
      const fileHighlightIds = highlightIdSet(highlight.file_nodes || []);
      const legendDefinitions = {{
        \"defines\": \"file or module defines this symbol\",
        \"imports\": \"module imports another symbol or module\",
        \"renders component\": \"React/JSX component renders another component\",
        \"inferred call\": \"static parser inferred a likely call edge\",
        \"calls\": \"function or handler calls another code unit\",
        \"reads\": \"code reads from this field, store, or source\",
        \"writes\": \"code writes to this field, store, or sink\",
        \"handles\": \"handler receives an event, route, or action\",
        \"maps to\": \"analytics, UI, or search evidence maps to code\",
        \"#n\": \"ordered call or sequence edge when no semantic label is available\"
      }};
      function normalizeLegendLabel(label) {{
        const text = String(label || \"\").trim().toLowerCase();
        if (/^#\\d+$/.test(text)) return \"#n\";
        return text;
      }}
      function renderLegend() {{
        const labels = new Set();
        rawEdges.forEach(([srcRaw, dstRaw, order]) => {{
          const edgeLabel = edgeLabels[`${{srcRaw}}->${{dstRaw}}`] || edgeLabels[`${{sanitize(srcRaw)}}->${{sanitize(dstRaw)}}`] || (order ? `#${{order}}` : \"\");
          const normalized = normalizeLegendLabel(edgeLabel);
          if (normalized) labels.add(normalized);
        }});
        const ordered = [\"defines\", \"imports\", \"renders component\", \"inferred call\", \"calls\", \"reads\", \"writes\", \"handles\", \"maps to\", \"#n\"]
          .filter(label => labels.has(label));
        const extra = [...labels].filter(label => !ordered.includes(label)).sort();
        const rows = [...ordered, ...extra].slice(0, 10).map(label => {{
          const description = legendDefinitions[label] || \"relationship label from parsed source evidence\";
          const display = label === \"#n\" ? \"#n\" : label;
          return `<div class=\"legend-row\"><span class=\"legend-key\">${{display}}</span><span class=\"legend-note\">${{description}}</span></div>`;
        }});
        const legendRows = document.getElementById(\"legendRows\");
        if (legendRows) legendRows.innerHTML = rows.length ? rows.join(\"\") : `<div class=\"legend-note\">No labeled edges in this view.</div>`;
      }}
      renderLegend();
      const nodeById = new Map();
      const outgoing = new Map();
      const incoming = new Map();
      rawNodes.forEach(raw => nodeById.set(sanitize(raw), raw));
      function fallbackOrder(order, index) {{
        const value = Number(order);
        return Number.isFinite(value) && value > 0 ? value : index + 1;
      }}
      rawEdges.forEach(([srcRaw, dstRaw, order, line], index) => {{
        const src = sanitize(srcRaw);
        const dst = sanitize(dstRaw);
        nodeById.set(src, srcRaw);
        nodeById.set(dst, dstRaw);
        if (!outgoing.has(src)) outgoing.set(src, []);
        if (!incoming.has(dst)) incoming.set(dst, []);
        const edgeLabel = edgeLabels[`${{srcRaw}}->${{dstRaw}}`] || edgeLabels[`${{src}}->${{dst}}`] || \"\";
        const effectiveOrder = fallbackOrder(order, index);
        const sourceOrder = Number.isFinite(Number(order)) && Number(order) > 0 ? Number(order) : \"\";
        outgoing.get(src).push({{ src, dst, order: effectiveOrder, sourceOrder, line: line || \"\", label: edgeLabel }});
        incoming.get(dst).push({{ src, dst, order: effectiveOrder, sourceOrder, line: line || \"\", label: edgeLabel }});
      }});
      function edgeOrderValue(edge) {{
        const value = Number(edge && edge.order);
        return Number.isFinite(value) ? value : Number.MAX_SAFE_INTEGER;
      }}
      function compareEdgesByOrder(a, b) {{
        return edgeOrderValue(a) - edgeOrderValue(b) ||
          compactLabel(nodeById.get(a.dst) || a.dst).localeCompare(compactLabel(nodeById.get(b.dst) || b.dst)) ||
          compactLabel(nodeById.get(a.src) || a.src).localeCompare(compactLabel(nodeById.get(b.src) || b.src));
      }}
      outgoing.forEach(list => list.sort(compareEdgesByOrder));
      incoming.forEach(list => list.sort(compareEdgesByOrder));
      function nodeElement(id) {{
        const raw = nodeById.get(id) || id;
        return {{ group:\"nodes\", data: {{ id, label: compactLabel(raw), fullLabel: String(raw) }} }};
      }}
      function edgeElement(edge) {{
        const edgeId = `${{edge.src}}->${{edge.dst}}`;
        const hasSourceOrder = Number.isFinite(Number(edge.sourceOrder)) && Number(edge.sourceOrder) > 0;
        return {{ group:\"edges\", data: {{ id: edgeId, source: edge.src, target: edge.dst, order: Number(edge.order) || \"\", sourceOrder: hasSourceOrder ? Number(edge.sourceOrder) : \"\", line: edge.line || \"\", label: edge.label || (hasSourceOrder ? `#${{edge.sourceOrder}}` : \"\") }} }};
      }}
      function explicitInitialElements() {{
        const elements = [];
        const seenNodes = new Set();
        const seenEdges = new Set();
        const visibleNodes = Array.isArray(data.initial_visible_nodes) ? data.initial_visible_nodes : [];
        const visibleEdges = Array.isArray(data.initial_visible_edges) ? data.initial_visible_edges : [];
        visibleNodes.forEach(raw => {{
          const id = sanitize(raw);
          if (!seenNodes.has(id)) {{
            seenNodes.add(id);
            elements.push(nodeElement(id));
          }}
        }});
        visibleEdges.forEach(([srcRaw, dstRaw, order, line], index) => {{
          const sourceOrder = Number.isFinite(Number(order)) && Number(order) > 0 ? Number(order) : \"\";
          const edge = {{ src: sanitize(srcRaw), dst: sanitize(dstRaw), order: fallbackOrder(order, index), sourceOrder, line: line || \"\", label: edgeLabels[`${{srcRaw}}->${{dstRaw}}`] || \"\" }};
          [edge.src, edge.dst].forEach(id => {{
            if (!seenNodes.has(id)) {{
              seenNodes.add(id);
              elements.push(nodeElement(id));
            }}
          }});
          const edgeId = `${{edge.src}}->${{edge.dst}}`;
          if (!seenEdges.has(edgeId)) {{
            seenEdges.add(edgeId);
            elements.push(edgeElement(edge));
          }}
        }});
        return elements;
      }}
      function flowElementsFor(id, depth = 1, maxNodes = 80) {{
        const elements = [];
        const seenNodes = new Set();
        const seenEdges = new Set();
        function addNode(idToAdd) {{
          if (seenNodes.has(idToAdd)) return;
          seenNodes.add(idToAdd);
          elements.push(nodeElement(idToAdd));
        }}
        function addEdge(edge) {{
          const edgeId = `${{edge.src}}->${{edge.dst}}`;
          addNode(edge.src);
          addNode(edge.dst);
          if (!seenEdges.has(edgeId)) {{
            seenEdges.add(edgeId);
            elements.push(edgeElement(edge));
          }}
        }}
        const queue = [{{ id, distance: 0 }}];
        addNode(id);
        while (queue.length && seenNodes.size < maxNodes) {{
          const current = queue.shift();
          if (current.distance >= depth) continue;
          const neighbors = [...(incoming.get(current.id) || []), ...(outgoing.get(current.id) || [])].sort(compareEdgesByOrder);
          neighbors.forEach(edge => {{
            if (seenNodes.size >= maxNodes) return;
            const nextIds = [edge.src, edge.dst].filter(nextId => nextId !== current.id && !seenNodes.has(nextId));
            addEdge(edge);
            if (seenNodes.size >= maxNodes) return;
            nextIds.forEach(nextId => {{
              const alreadyQueued = queue.some(item => item.id === nextId);
              if (!alreadyQueued && current.distance + 1 < depth) queue.push({{ id: nextId, distance: current.distance + 1 }});
            }});
          }});
        }}
        return elements;
      }}
      const expansionCursor = new Map();
      function oneStepElementsFor(id) {{
        const incident = [...(outgoing.get(id) || []), ...(incoming.get(id) || [])].sort(compareEdgesByOrder);
        if (!incident.length) return [];
        const start = expansionCursor.get(id) || 0;
        for (let offset = 0; offset < incident.length; offset += 1) {{
          const index = (start + offset) % incident.length;
          const edge = incident[index];
          const edgeId = `${{edge.src}}->${{edge.dst}}`;
          const otherId = edge.src === id ? edge.dst : edge.src;
          const isNewEdge = !cy.getElementById(edgeId).length;
          const isNewNode = !cy.getElementById(otherId).length;
          if (isNewEdge || isNewNode) {{
            expansionCursor.set(id, index + 1);
            return [nodeElement(edge.src), nodeElement(edge.dst), edgeElement(edge)];
          }}
        }}
        expansionCursor.set(id, incident.length);
        return [];
      }}
      const roots = Array.isArray(data.initial_roots) && data.initial_roots.length ? data.initial_roots : rawNodes.slice(0, 1);
      const firstRoot = roots
        .map(root => sanitize(root))
        .find(root => (incoming.get(root) || []).length || (outgoing.get(root) || []).length)
        || Array.from(nodeById.keys()).find(id => (incoming.get(id) || []).length || (outgoing.get(id) || []).length)
        || sanitize(roots[0] || rawNodes[0] || \"root\");
      const explicitElements = explicitInitialElements();
      const initialElements = explicitElements.length ? explicitElements : flowElementsFor(firstRoot, 1, 16);
      const cy = cytoscape({{
        container: document.getElementById(\"cy\"),
        elements: initialElements.length ? initialElements : [nodeElement(firstRoot)],
        style: [
          {{ selector: \"node\", style: {{ \"label\":\"data(label)\", \"background-color\":\"#3267e3\", \"color\":\"#111827\", \"font-size\":\"11px\", \"text-valign\":\"bottom\", \"text-halign\":\"center\", \"text-margin-y\":8, \"text-max-width\":148, \"text-wrap\":\"wrap\", \"text-background-color\":\"#ffffff\", \"text-background-opacity\":0.88, \"text-background-padding\":2, \"width\":16, \"height\":16, \"border-width\":1, \"border-color\":\"#1d4ed8\", \"min-zoomed-font-size\":7 }} }},
          {{ selector: \"node.impact-root\", style: {{ \"background-color\":\"#dc2626\", \"border-color\":\"#7f1d1d\", \"border-width\":4, \"width\":24, \"height\":24, \"font-weight\":\"700\", \"text-background-opacity\":1 }} }},
          {{ selector: \"node.impact-affected\", style: {{ \"background-color\":\"#f59e0b\", \"border-color\":\"#92400e\", \"border-width\":3, \"width\":20, \"height\":20, \"font-weight\":\"700\", \"text-background-opacity\":1 }} }},
          {{ selector: \"node.impact-file\", style: {{ \"background-color\":\"#10b981\", \"border-color\":\"#047857\", \"border-width\":3, \"width\":19, \"height\":19, \"font-weight\":\"700\", \"text-background-opacity\":1 }} }},
          {{ selector: \"node:selected\", style: {{ \"width\":16, \"height\":16, \"overlay-opacity\":0.08, \"border-width\":2 }} }},
          {{ selector: \"node:active\", style: {{ \"width\":16, \"height\":16, \"overlay-opacity\":0.05 }} }},
          {{ selector: \"edge\", style: {{ \"label\":\"data(label)\", \"width\":1.7, \"line-color\":\"#64748b\", \"target-arrow-color\":\"#64748b\", \"target-arrow-shape\":\"triangle\", \"arrow-scale\":1.35, \"curve-style\":\"bezier\", \"font-size\":\"10px\", \"color\":\"#dc2626\", \"font-weight\":\"600\", \"text-background-color\":\"#ffffff\", \"text-background-opacity\":0.9, \"text-background-padding\":2, \"text-margin-y\":0, \"min-zoomed-font-size\":7 }} }},
          {{ selector: \"edge.impact-edge\", style: {{ \"width\":3, \"line-color\":\"#f59e0b\", \"target-arrow-color\":\"#f59e0b\", \"z-index\":20 }} }},
          {{ selector: \"edge[curveDistance][curveWeight]\", style: {{ \"curve-style\":\"unbundled-bezier\", \"control-point-distances\":\"data(curveDistance)\", \"control-point-weights\":\"data(curveWeight)\" }} }},
          {{ selector: \"edge[labelOffset]\", style: {{ \"text-margin-y\":\"data(labelOffset)\" }} }}
        ],
        layout: {{ name:\"preset\", animate:false }}
      }});
      function renderNodeLegend() {{
        const rows = [];
        if (rootHighlightIds.size) {{
          rows.push([\"#dc2626\", \"Changed\", \"the function whose code changed\"]);
        }}
        if (affectedHighlightIds.size) {{
          rows.push([\"#f59e0b\", \"Blast radius\", \"functions affected by the change (direct + transitive callers)\"]);
        }}
        if (fileHighlightIds.size) {{
          rows.push([\"#10b981\", \"File-mapped\", \"evidence tied to a changed file rather than a direct call edge\"]);
        }}
        const nodeLegendRows = document.getElementById(\"nodeLegendRows\");
        if (nodeLegendRows) {{
          nodeLegendRows.innerHTML = rows.map(([color, label, note]) =>
            `<div class=\"legend-row\"><span class=\"legend-key\"><span class=\"legend-dot\" style=\"background:${{color}}\"></span>${{label}}</span><span class=\"legend-note\">${{note}}</span></div>`
          ).join(\"\");
        }}
      }}
      renderNodeLegend();
      function applyHighlightClasses() {{
        cy.nodes().forEach(node => {{
          const id = node.id();
          node.toggleClass(\"impact-root\", rootHighlightIds.has(id));
          node.toggleClass(\"impact-affected\", !rootHighlightIds.has(id) && affectedHighlightIds.has(id));
          node.toggleClass(\"impact-file\", !rootHighlightIds.has(id) && !affectedHighlightIds.has(id) && fileHighlightIds.has(id));
        }});
        cy.edges().forEach(edge => {{
          const sourceHighlighted = rootHighlightIds.has(edge.source().id()) || affectedHighlightIds.has(edge.source().id()) || fileHighlightIds.has(edge.source().id());
          const targetHighlighted = rootHighlightIds.has(edge.target().id()) || affectedHighlightIds.has(edge.target().id()) || fileHighlightIds.has(edge.target().id());
          edge.toggleClass(\"impact-edge\", sourceHighlighted && targetHighlighted);
        }});
      }}
      applyHighlightClasses();
      const expandedNodes = new Set([firstRoot]);
      function addMissingElements(elements) {{
        const additions = [];
        elements.forEach(element => {{
          const id = element.data && element.data.id;
          if (!id || cy.getElementById(id).length) return;
          additions.push(element);
        }});
        if (additions.length) {{
          cy.add(additions);
          applyHighlightClasses();
        }}
        return additions.length;
      }}
      function placeRows(items, baseY, xSpacing = 280, ySpacing = 132) {{
        const count = items.length;
        if (!count) return;
        const columns = Math.max(1, Math.min(5, Math.ceil(Math.sqrt(count * 1.65))));
        const rows = Math.ceil(count / columns);
        items.forEach((item, index) => {{
          const row = Math.floor(index / columns);
          const rowStart = row * columns;
          const rowCount = Math.min(columns, count - rowStart);
          const col = index - rowStart;
          const x = (col - (rowCount - 1) / 2) * xSpacing;
          const y = baseY + row * ySpacing;
          item.node.position({{ x, y }});
        }});
      }}
      function edgeOrder(edge) {{
        const raw = edge.data(\"order\");
        const value = Number(raw);
        return Number.isFinite(value) ? value : Number.MAX_SAFE_INTEGER;
      }}
      function orderItems(items) {{
        return items.sort((a, b) => (
          (Number.isFinite(a.order) ? 0 : 1) - (Number.isFinite(b.order) ? 0 : 1) ||
          (Number.isFinite(a.order) && Number.isFinite(b.order) ? a.order - b.order : 0) ||
          compactLabel(nodeById.get(a.node.id()) || a.node.id()).localeCompare(compactLabel(nodeById.get(b.node.id()) || b.node.id()))
        ));
      }}
      function visibleSources() {{
        const indegree = new Map();
        cy.nodes().forEach(node => indegree.set(node.id(), 0));
        cy.edges().forEach(edge => indegree.set(edge.target().id(), (indegree.get(edge.target().id()) || 0) + 1));
        const sources = cy.nodes().filter(node => (indegree.get(node.id()) || 0) === 0);
        return sources.length ? sources : cy.collection().union(cy.getElementById(firstRoot));
      }}
      function sortIncidentEdges(edges, rootId, direction) {{
        return edges.map(edge => {{
          const other = direction === \"incoming\" ? edge.source() : edge.target();
          return {{ edge, node: other, order: edgeOrder(edge) }};
        }}).sort((a, b) => (
          (Number.isFinite(a.order) ? 0 : 1) - (Number.isFinite(b.order) ? 0 : 1) ||
          (Number.isFinite(a.order) && Number.isFinite(b.order) ? a.order - b.order : 0) ||
          compactLabel(nodeById.get(a.node.id()) || a.node.id()).localeCompare(compactLabel(nodeById.get(b.node.id()) || b.node.id()))
        ));
      }}
      function placeOrderedFan(items, rootNode, side) {{
        const count = items.length;
        if (!count) return;
        const maxColumns = 10;
        const columns = Math.max(1, Math.min(maxColumns, count));
        const xSpacing = 285;
        const ySpacing = 168;
        const baseY = rootNode.position(\"y\") + (side === \"incoming\" ? -230 : 230);
        items.forEach((item, index) => {{
          const row = Math.floor(index / columns);
          const rowStart = row * columns;
          const rowCount = Math.min(columns, count - rowStart);
          const col = index - rowStart;
          const centeredCol = col - (rowCount - 1) / 2;
          const x = rootNode.position(\"x\") + centeredCol * xSpacing;
          const y = baseY + (side === \"incoming\" ? -row * ySpacing : row * ySpacing);
          item.node.position({{ x, y }});
          const spread = centeredCol * 24;
          item.edge.data(\"curveDistance\", spread);
          item.edge.data(\"curveWeight\", side === \"incoming\" ? 0.62 : 0.38);
          item.edge.data(\"labelOffset\", side === \"incoming\" ? -18 : 18);
        }});
      }}
      function applyFocusedRootLayout(focusId) {{
        const root = cy.getElementById(focusId);
        if (!root.length || cy.nodes().length < 3) return false;
        const incomingEdges = sortIncidentEdges(root.incomers(\"edge\"), focusId, \"incoming\");
        const outgoingEdges = sortIncidentEdges(root.outgoers(\"edge\"), focusId, \"outgoing\");
        const incidentNodeIds = new Set([focusId]);
        incomingEdges.forEach(item => incidentNodeIds.add(item.node.id()));
        outgoingEdges.forEach(item => incidentNodeIds.add(item.node.id()));
        if (incidentNodeIds.size < Math.min(cy.nodes().length, 3)) return false;
        root.position({{ x: 0, y: 0 }});
        placeOrderedFan(incomingEdges, root, \"incoming\");
        placeOrderedFan(outgoingEdges, root, \"outgoing\");
        const remaining = cy.nodes().filter(node => !incidentNodeIds.has(node.id())).map(node => ({{ node, order: Number.NaN }}));
        if (remaining.length) placeRows(orderItems(remaining), 620, 280, 150);
        return true;
      }}
      function applyRoadLayout() {{
        if (!cy.nodes().length) return false;
        if (applyFocusedRootLayout(firstRoot)) return true;
        const levels = new Map();
        const queue = [];
        visibleSources().forEach(node => {{
          levels.set(node.id(), 0);
          queue.push(node.id());
        }});
        while (queue.length) {{
          const id = queue.shift();
          const level = levels.get(id) || 0;
          cy.edges(`[source = \"${{id}}\"]`).sort((a, b) => edgeOrder(a) - edgeOrder(b)).forEach(edge => {{
            const targetId = edge.target().id();
            const nextLevel = level + 1;
            if (!levels.has(targetId) || nextLevel > levels.get(targetId)) {{
              levels.set(targetId, nextLevel);
              if (nextLevel < 24) queue.push(targetId);
            }}
          }});
        }}
        cy.nodes().forEach(node => {{
          if (!levels.has(node.id())) levels.set(node.id(), 0);
        }});
        const groups = new Map();
        cy.nodes().forEach(node => node.removeData(\"incomingOrder\"));
        cy.edges().forEach(edge => {{
          edge.target().data(\"incomingOrder\", Math.min(Number(edge.target().data(\"incomingOrder\") || Number.MAX_SAFE_INTEGER), edgeOrder(edge)));
        }});
        cy.nodes().forEach(node => {{
          const level = levels.get(node.id()) || 0;
          if (!groups.has(level)) groups.set(level, []);
          const rawOrder = Number(node.data(\"incomingOrder\"));
          groups.get(level).push({{ node, order: Number.isFinite(rawOrder) && rawOrder < Number.MAX_SAFE_INTEGER ? rawOrder : Number.NaN }});
        }});
        let currentY = 0;
        [...groups.keys()].sort((a, b) => a - b).forEach(level => {{
          const items = orderItems(groups.get(level));
          placeRows(items, currentY);
          const columns = Math.max(1, Math.min(5, Math.ceil(Math.sqrt(items.length * 1.65))));
          const rows = Math.ceil(items.length / columns);
          currentY += Math.max(170, rows * 132 + 82);
        }});
        return true;
      }}
      function fitVisibleGraph() {{
        if (!cy.nodes().length) return;
        cy.resize();
        cy.fit(cy.elements(':visible'), 54);
        cy.zoom(Math.min(cy.zoom(), 1.15));
        cy.center(cy.elements(':visible'));
      }}
      function scheduleFit(retries = 4) {{
        requestAnimationFrame(() => {{
          fitVisibleGraph();
          if (retries > 0) {{
            setTimeout(() => scheduleFit(retries - 1), 120);
          }}
        }});
      }}
      function relayout(shouldFit, focusId) {{
        cy.resize();
        if (!applyRoadLayout()) {{
          cy.layout({{ name:\"breadthfirst\", directed:true, padding:72, spacingFactor:1.4, animate:false }}).run();
        }} else {{
          cy.layout({{ name:\"preset\", animate:false, fit:false }}).run();
        }}
        if (shouldFit) {{
          scheduleFit();
        }} else if (focusId && cy.getElementById(focusId).length) {{
          requestAnimationFrame(() => {{
            cy.resize();
            cy.center(cy.getElementById(focusId));
          }});
        }}
      }}

      // ----------------------------------------
      // find next node to expand when current is exhausted
      // ----------------------------------------
      function findNextExpansionTarget(fromId) {{
        // BFS outward from fromId through the FULL graph data
        // find first node that has unexpanded edges
        const visited = new Set([fromId]);
        const queue = [fromId];
        while (queue.length) {{
          const current = queue.shift();
          const neighbors = [
            ...(outgoing.get(current) || []).map(e => e.dst),
            ...(incoming.get(current) || []).map(e => e.src),
          ];
          for (const neighbor of neighbors) {{
            if (visited.has(neighbor)) continue;
            visited.add(neighbor);
            // does this neighbor have any edge not yet in the graph?
            const incident = [
              ...(outgoing.get(neighbor) || []),
              ...(incoming.get(neighbor) || []),
            ];
            const hasHidden = incident.some(edge => {{
              const edgeId = `${{edge.src}}->${{edge.dst}}`;
              const otherId = edge.src === neighbor ? edge.dst : edge.src;
              return !cy.getElementById(edgeId).length || !cy.getElementById(otherId).length;
            }});
            if (hasHidden) return neighbor;
            queue.push(neighbor);
          }}
        }}
        // fallback: any node in the full graph with hidden edges
        for (const [nodeId] of nodeById) {{
          if (visited.has(nodeId)) continue;
          const incident = [
            ...(outgoing.get(nodeId) || []),
            ...(incoming.get(nodeId) || []),
          ];
          const hasHidden = incident.some(edge => {{
            const edgeId = `${{edge.src}}->${{edge.dst}}`;
            const otherId = edge.src === nodeId ? edge.dst : edge.src;
            return !cy.getElementById(edgeId).length || !cy.getElementById(otherId).length;
          }});
          if (hasHidden) return nodeId;
        }}
        return null;
      }}

      cy.on(\"tap\", \"node\", evt => {{
        const id = evt.target.id();
        expandedNodes.add(id);
        const added = addMissingElements(oneStepElementsFor(id));
        if (added) {{
          relayout(true, id);
          setStatus(
            `${{countLabel(cy.nodes().length, "node", "nodes")}}, ${{countLabel(cy.edges().length, "edge", "edges")}}`,
            `Added the next link from ${{compactLabel(nodeById.get(id) || id)}}. Click again to continue.`
          );
          return;
        }}
        const next = findNextExpansionTarget(id);
        if (next) {{
          expandedNodes.add(next);
          addMissingElements(oneStepElementsFor(next));
          relayout(true, next);
          setStatus(
            `${{countLabel(cy.nodes().length, "node", "nodes")}}, ${{countLabel(cy.edges().length, "edge", "edges")}}`,
            `${{compactLabel(nodeById.get(id) || id)}} is fully expanded. Continuing from ${{compactLabel(nodeById.get(next) || next)}}. Click to keep going.`
          );
        }} else {{
          setStatus(
            `${{countLabel(cy.nodes().length, "node", "nodes")}}, ${{countLabel(cy.edges().length, "edge", "edges")}}`,
            `All reachable nodes from ${{compactLabel(nodeById.get(id) || id)}} are now visible.`
          );
        }}
      }});

      const highlightCount = rootHighlightIds.size + affectedHighlightIds.size + fileHighlightIds.size;
      const highlightText = highlightCount ? ` · ${{rootHighlightIds.size}} changed, ${{affectedHighlightIds.size}} affected${{fileHighlightIds.size ? `, ${{fileHighlightIds.size}} file-mapped` : \"\"}}` : \"\";
      setStatus(
        `${{countLabel(cy.nodes().length, "node", "nodes")}}, ${{countLabel(cy.edges().length, "edge", "edges")}}${{highlightText}}`,
        `Showing connections from ${{compactLabel(nodeById.get(firstRoot) || firstRoot)}}. Click a node to reveal the next connected node or edge.`
      );
      requestAnimationFrame(() => relayout(true, firstRoot));
      if (window.ResizeObserver) {{
        const observer = new ResizeObserver(() => scheduleFit(2));
        observer.observe(document.getElementById(\"cy\"));
      }}
      window.addEventListener(\"resize\", () => scheduleFit(2));
    
    }}).catch(err => {{
      showGraphError(err);
    }});
  </script>
</body>
</html>
"""
    html_path.write_text(html, encoding="utf-8")
    relative_html = os.path.relpath(html_path, BASE_OUTPUT).replace("\\", "/")
    return f"{OUTPUT_URL_PREFIX}/{relative_html}"


def build_ordered_process_cytoscape_graph(
    nodes,
    edges,
    output_repo_dir,
    graph_name,
    graph_title="Ordered Process Graph",
    root="",
    node_labels=None,
):
    output_repo_dir = Path(output_repo_dir)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    json_path = output_repo_dir / f"{graph_name}.json"
    html_path = output_repo_dir / f"{graph_name}.html"
    graph_data = {
        "mode": "ordered_process_graph",
        "title": graph_title,
        "nodes": sorted(set(nodes)),
        "edges": [[src, dst, order, line] for src, dst, order, line in edges],
        "root": root,
        "node_labels": node_labels or {},
    }
    json_path.write_text(json.dumps(graph_data, indent=2), encoding="utf-8")
    relative_json = os.path.relpath(json_path, BASE_OUTPUT).replace("\\", "/")
    graph_json_url = f"{OUTPUT_URL_PREFIX}/{relative_json}"
    embedded = json.dumps(graph_data, separators=(",", ":"))
    html = f"""<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <title>{graph_title}</title>
  <style>
    html, body {{ width:100%; height:100%; margin:0; overflow:hidden; font-family:Arial, sans-serif; background:#fff; }}
    #cy {{ position:absolute; inset:0; }}
    #status {{ position:absolute; left:8px; top:8px; z-index:10; max-width:calc(100% - 16px); background:rgba(255,255,255,.94); border:1px solid #dbe3ef; border-radius:6px; padding:7px 9px; color:#334155; font-size:13px; }}
  </style>
</head>
<body>
  <div id="status">Loading {graph_title}...</div>
  <div id="cy"></div>
  <script>
    const GRAPH_JSON = "{graph_json_url}";
    const EMBEDDED_GRAPH_DATA = {embedded};
    const statusEl = document.getElementById("status");
    function loadScript(src) {{
      return new Promise((resolve, reject) => {{
        const script = document.createElement("script");
        script.src = src;
        script.onload = resolve;
        script.onerror = () => reject(new Error(`Failed to load script ${{src}}`));
        document.head.appendChild(script);
      }});
    }}
    function loadCytoscape() {{
      return loadScript("/lib/cytoscape/cytoscape.min.js")
        .catch(() => loadScript("https://unpkg.com/cytoscape@3.28.1/dist/cytoscape.min.js"));
    }}
    function loadGraphData() {{
      return fetch(GRAPH_JSON).then(r => r.ok ? r.json() : Promise.reject(new Error(`Failed to load ${{GRAPH_JSON}}`))).catch(() => EMBEDDED_GRAPH_DATA);
    }}
    function sanitize(raw) {{ return String(raw || "").replace(/[^a-zA-Z0-9_]/g, "_"); }}
    function compactLabel(raw) {{
      const label = String(raw || "");
      if (label.length <= 72) return label;
      return `${{label.slice(0, 32)}}...${{label.slice(-32)}}`;
    }}
    loadCytoscape().then(loadGraphData).then(data => {{
      const labels = data.node_labels && typeof data.node_labels === "object" ? data.node_labels : {{}};
      const rawEdges = Array.isArray(data.edges) ? data.edges : [];
      const rawNodes = Array.isArray(data.nodes) ? data.nodes : [];
      const nodeIds = new Set(rawNodes.map(String));
      rawEdges.forEach(edge => {{
        if (Array.isArray(edge) && edge.length >= 2) {{
          nodeIds.add(String(edge[0]));
          nodeIds.add(String(edge[1]));
        }}
      }});
      const rootRaw = data.root || rawEdges[0]?.[0] || rawNodes[0] || "root";
      const root = sanitize(rootRaw);
      const rawById = new Map();
      [...nodeIds].forEach(node => rawById.set(sanitize(node), node));
      const edgeRows = rawEdges
        .filter(edge => Array.isArray(edge) && edge.length >= 2)
        .map((edge, index) => {{
          const order = Number(edge[2]);
          return {{
            src: sanitize(edge[0]),
            dst: sanitize(edge[1]),
            rawSrc: String(edge[0]),
            rawDst: String(edge[1]),
            order: Number.isFinite(order) ? order : index + 1,
            line: edge[3] || null,
          }};
        }})
        .sort((a, b) => a.order - b.order || a.rawDst.localeCompare(b.rawDst));
      const children = new Map();
      const parents = new Map();
      edgeRows.forEach(edge => {{
        if (!children.has(edge.src)) children.set(edge.src, []);
        children.get(edge.src).push(edge);
        if (!parents.has(edge.dst)) parents.set(edge.dst, []);
        parents.get(edge.dst).push(edge);
      }});
      const levels = new Map([[root, 0]]);
      const queue = [root];
      while (queue.length) {{
        const current = queue.shift();
        const nextLevel = (levels.get(current) || 0) + 1;
        (children.get(current) || []).forEach(edge => {{
          if (!levels.has(edge.dst) || nextLevel < levels.get(edge.dst)) {{
            levels.set(edge.dst, nextLevel);
            if (nextLevel < 8) queue.push(edge.dst);
          }}
        }});
      }}
      [...nodeIds].map(sanitize).forEach(id => {{
        if (!levels.has(id)) levels.set(id, 1);
      }});
      const levelGroups = new Map();
      levels.forEach((level, id) => {{
        if (!levelGroups.has(level)) levelGroups.set(level, []);
        const incomingOrder = Math.min(...(parents.get(id) || []).map(edge => edge.order), Number.MAX_SAFE_INTEGER);
        levelGroups.get(level).push({{ id, incomingOrder }});
      }});
      const positions = new Map();
      [...levelGroups.keys()].sort((a, b) => a - b).forEach(level => {{
        const group = levelGroups.get(level).sort((a, b) => a.incomingOrder - b.incomingOrder || a.id.localeCompare(b.id));
        const x = 110 + level * 330;
        group.forEach((item, index) => {{
          positions.set(item.id, {{ x, y: 90 + index * 118 }});
        }});
      }});
      const elements = [];
      [...nodeIds].forEach(raw => {{
        const id = sanitize(raw);
        const label = compactLabel(labels[raw] || raw);
        elements.push({{ data: {{ id, label }}, position: positions.get(id) || {{ x: 110, y: 90 }} }});
      }});
      edgeRows.forEach(edge => {{
        elements.push({{
          data: {{
            id: `${{edge.src}}__${{edge.dst}}__${{edge.order}}`,
            source: edge.src,
            target: edge.dst,
            label: `#${{edge.order}}${{edge.line ? " L" + edge.line : ""}}`,
            order: edge.order,
          }}
        }});
      }});
      const cy = cytoscape({{
        container: document.getElementById("cy"),
        elements,
        style: [
          {{ selector: "node", style: {{ "label":"data(label)", "background-color":"#3267e3", "border-color":"#1d4ed8", "border-width":1, "width":18, "height":18, "color":"#111827", "font-size":"11px", "font-weight":"600", "text-wrap":"wrap", "text-max-width":160, "text-valign":"center", "text-halign":"right", "text-margin-x":-12, "text-background-color":"#ffffff", "text-background-opacity":0.9, "text-background-padding":2 }} }},
          {{ selector: `node[id = "${{root}}"]`, style: {{ "background-color":"#7047eb", "border-color":"#4c1d95", "width":22, "height":22, "text-halign":"right", "font-size":"12px" }} }},
          {{ selector: "edge", style: {{ "label":"data(label)", "width":1.8, "line-color":"#64748b", "target-arrow-color":"#64748b", "target-arrow-shape":"triangle", "curve-style":"taxi", "taxi-direction":"rightward", "taxi-turn":70, "font-size":"10px", "font-weight":"700", "color":"#dc2626", "text-background-color":"#ffffff", "text-background-opacity":0.92, "text-background-padding":2 }} }}
        ],
        layout: {{ name:"preset", animate:false }}
      }});
      statusEl.textContent = `${{data.title}}: ordered process view (${{cy.nodes().length}} nodes, ${{cy.edges().length}} edges). Edges are sorted top-to-bottom by their # order.`;
      setTimeout(() => cy.fit(undefined, 50), 80);
    }}).catch(err => {{
      statusEl.textContent = err.message;
      console.error(err);
    }});
  </script>
</body>
</html>
"""
    html_path.write_text(html, encoding="utf-8")
    relative_html = os.path.relpath(html_path, BASE_OUTPUT).replace("\\", "/")
    return f"{OUTPUT_URL_PREFIX}/{relative_html}"


def build_ordered_lr_callgraph(
    nodes,
    edges,
    output_repo_dir,
    graph_name,
    graph_title="Ordered Left-to-Right Callgraph",
    root="",
    node_labels=None,
):
    output_repo_dir = Path(output_repo_dir)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    json_path = output_repo_dir / f"{graph_name}.json"
    html_path = output_repo_dir / f"{graph_name}.html"
    graph_data = {
        "mode": "ordered_lr_callgraph",
        "title": graph_title,
        "nodes": sorted(set(nodes)),
        "edges": [[src, dst, order, line] for src, dst, order, line in edges],
        "root": root,
        "node_labels": node_labels or {},
        "instructions": "Callers are left of the selected node, callees are right of it, and edge rows are ordered top-to-bottom by edge number.",
    }
    json_path.write_text(json.dumps(graph_data, indent=2), encoding="utf-8")
    relative_json = os.path.relpath(json_path, BASE_OUTPUT).replace("\\", "/")
    graph_json_url = f"{OUTPUT_URL_PREFIX}/{relative_json}"
    embedded = json.dumps(graph_data, separators=(",", ":"))
    html = f"""<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <title>{graph_title}</title>
  <style>
    html, body {{ width:100%; height:100%; margin:0; overflow:hidden; font-family:Arial, sans-serif; background:#fff; }}
    #cy {{ position:absolute; inset:0; }}
    #status {{ position:absolute; left:8px; top:8px; z-index:10; max-width:calc(100% - 16px); background:rgba(255,255,255,.94); border:1px solid #dbe3ef; border-radius:6px; padding:7px 9px; color:#334155; font-size:13px; }}
  </style>
</head>
<body>
  <div id="status">Loading {graph_title}...</div>
  <div id="cy"></div>
  <script>
    const GRAPH_JSON = "{graph_json_url}";
    const EMBEDDED_GRAPH_DATA = {embedded};
    const statusEl = document.getElementById("status");
    function loadScript(src) {{
      return new Promise((resolve, reject) => {{
        const script = document.createElement("script");
        script.src = src;
        script.onload = resolve;
        script.onerror = () => reject(new Error(`Failed to load script ${{src}}`));
        document.head.appendChild(script);
      }});
    }}
    function loadCytoscape() {{
      return loadScript("/lib/cytoscape/cytoscape.min.js")
        .catch(() => loadScript("https://unpkg.com/cytoscape@3.28.1/dist/cytoscape.min.js"));
    }}
    function loadGraphData() {{
      return fetch(GRAPH_JSON).then(r => r.ok ? r.json() : Promise.reject(new Error(`Failed to load ${{GRAPH_JSON}}`))).catch(() => EMBEDDED_GRAPH_DATA);
    }}
    function sanitize(raw) {{ return String(raw || "").replace(/[^a-zA-Z0-9_]/g, "_"); }}
    function compactLabel(raw) {{
      const label = String(raw || "");
      if (label.length <= 74) return label;
      return `${{label.slice(0, 34)}}...${{label.slice(-34)}}`;
    }}
    function edgeOrder(edge) {{
      const value = Number(edge && edge.order);
      return Number.isFinite(value) ? value : Number.MAX_SAFE_INTEGER;
    }}
    loadCytoscape().then(loadGraphData).then(data => {{
      const labels = data.node_labels && typeof data.node_labels === "object" ? data.node_labels : {{}};
      const rawEdges = Array.isArray(data.edges) ? data.edges : [];
      const rawNodes = Array.isArray(data.nodes) ? data.nodes : [];
      const nodeIds = new Set(rawNodes.map(String));
      const edgeRows = rawEdges
        .filter(edge => Array.isArray(edge) && edge.length >= 2)
        .map((edge, index) => {{
          const order = Number(edge[2]);
          const srcRaw = String(edge[0]);
          const dstRaw = String(edge[1]);
          nodeIds.add(srcRaw);
          nodeIds.add(dstRaw);
          return {{
            src: sanitize(srcRaw),
            dst: sanitize(dstRaw),
            srcRaw,
            dstRaw,
            order: Number.isFinite(order) ? order : index + 1,
            line: edge[3] || null,
          }};
        }})
        .sort((a, b) => edgeOrder(a) - edgeOrder(b) || a.srcRaw.localeCompare(b.srcRaw) || a.dstRaw.localeCompare(b.dstRaw));
      const rootRaw = data.root || rawEdges[0]?.[0] || rawNodes[0] || "root";
      const root = sanitize(rootRaw);
      const outgoing = new Map();
      const incoming = new Map();
      edgeRows.forEach(edge => {{
        if (!outgoing.has(edge.src)) outgoing.set(edge.src, []);
        if (!incoming.has(edge.dst)) incoming.set(edge.dst, []);
        outgoing.get(edge.src).push(edge);
        incoming.get(edge.dst).push(edge);
      }});
      const levels = new Map([[root, 0]]);
      const queue = [root];
      while (queue.length) {{
        const current = queue.shift();
        const currentLevel = levels.get(current) || 0;
        (outgoing.get(current) || []).forEach(edge => {{
          const nextLevel = currentLevel + 1;
          if (!levels.has(edge.dst) || Math.abs(nextLevel) < Math.abs(levels.get(edge.dst))) {{
            levels.set(edge.dst, nextLevel);
            if (Math.abs(nextLevel) < 8) queue.push(edge.dst);
          }}
        }});
        (incoming.get(current) || []).forEach(edge => {{
          const nextLevel = currentLevel - 1;
          if (!levels.has(edge.src) || Math.abs(nextLevel) < Math.abs(levels.get(edge.src))) {{
            levels.set(edge.src, nextLevel);
            if (Math.abs(nextLevel) < 8) queue.push(edge.src);
          }}
        }});
      }}
      [...nodeIds].map(sanitize).forEach(id => {{
        if (!levels.has(id)) levels.set(id, 0);
      }});
      const nodeOrder = new Map();
      edgeRows.forEach(edge => {{
        nodeOrder.set(edge.src, Math.min(nodeOrder.get(edge.src) || Number.MAX_SAFE_INTEGER, edge.order));
        nodeOrder.set(edge.dst, Math.min(nodeOrder.get(edge.dst) || Number.MAX_SAFE_INTEGER, edge.order));
      }});
      const groups = new Map();
      levels.forEach((level, id) => {{
        if (!groups.has(level)) groups.set(level, []);
        groups.get(level).push(id);
      }});
      const positions = new Map();
      const sortedGroups = new Map();
      [...groups.keys()].sort((a, b) => a - b).forEach(level => {{
        const group = groups.get(level).sort((a, b) => (nodeOrder.get(a) || Number.MAX_SAFE_INTEGER) - (nodeOrder.get(b) || Number.MAX_SAFE_INTEGER) || a.localeCompare(b));
        sortedGroups.set(level, group);
        const x = 520 + level * 300;
        const yStart = 90;
        group.forEach((id, index) => {{
          positions.set(id, {{ x, y: yStart + index * 92 }});
        }});
      }});
      const elements = [];
      [...nodeIds].forEach(raw => {{
        const id = sanitize(raw);
        elements.push({{
          data: {{ id, label: compactLabel(labels[raw] || raw) }},
          position: positions.get(id) || {{ x: 520, y: 90 }},
        }});
      }});
      edgeRows.forEach(edge => {{
        elements.push({{
          data: {{
            id: `${{edge.src}}__${{edge.dst}}__${{edge.order}}`,
            source: edge.src,
            target: edge.dst,
            label: `#${{edge.order}}${{edge.line ? " L" + edge.line : ""}}`,
            order: edge.order,
          }}
        }});
      }});
      const cy = cytoscape({{
        container: document.getElementById("cy"),
        elements,
        style: [
          {{ selector: "node", style: {{ "label":"data(label)", "background-color":"#ffffff", "border-color":"#111827", "border-width":2, "width":8, "height":8, "color":"#111827", "font-size":"11px", "text-wrap":"wrap", "text-max-width":180, "text-valign":"center", "text-halign":"right", "text-margin-x":-8, "text-background-color":"#ffffff", "text-background-opacity":0.88, "text-background-padding":2 }} }},
          {{ selector: `node[id = "${{root}}"]`, style: {{ "background-color":"#3267e3", "border-color":"#1d4ed8", "width":14, "height":14, "font-weight":"700" }} }},
          {{ selector: "edge", style: {{ "label":"data(label)", "width":2, "line-color":"#079669", "target-arrow-color":"#079669", "target-arrow-shape":"triangle", "curve-style":"taxi", "taxi-direction":"rightward", "taxi-turn":70, "font-size":"10px", "font-weight":"700", "color":"#dc2626", "text-background-color":"#ffffff", "text-background-opacity":0.94, "text-background-padding":2 }} }}
        ],
        layout: {{ name:"preset", animate:false }}
      }});
      let selectedId = root;
      function focusNode(id) {{
        const node = cy.getElementById(id);
        if (!node.length) return;
        cy.nodes().unselect();
        node.select();
        selectedId = id;
        cy.animate({{ center: {{ eles: node }}, duration: 120 }});
        statusEl.textContent = `${{data.title}}: selected ${{node.data("label")}}. Arrow keys move left/right by call direction and up/down by ordered rows.`;
      }}
      function closestByY(ids, y) {{
        return ids
          .filter(id => id !== selectedId)
          .map(id => ({{ id, distance: Math.abs((positions.get(id) || {{ y: 0 }}).y - y) }}))
          .sort((a, b) => a.distance - b.distance || a.id.localeCompare(b.id))[0]?.id || "";
      }}
      function moveVertical(delta) {{
        const level = levels.get(selectedId) || 0;
        const group = sortedGroups.get(level) || [];
        const index = group.indexOf(selectedId);
        if (index < 0 || !group.length) return;
        const next = group[Math.max(0, Math.min(group.length - 1, index + delta))];
        if (next && next !== selectedId) focusNode(next);
      }}
      function moveHorizontal(delta) {{
        const level = levels.get(selectedId) || 0;
        const nextLevel = level + delta;
        const group = sortedGroups.get(nextLevel) || [];
        const currentY = (positions.get(selectedId) || {{ y: 0 }}).y;
        const next = closestByY(group, currentY);
        if (next) focusNode(next);
      }}
      window.addEventListener("keydown", event => {{
        if (event.key === "ArrowUp") {{ event.preventDefault(); moveVertical(-1); }}
        if (event.key === "ArrowDown") {{ event.preventDefault(); moveVertical(1); }}
        if (event.key === "ArrowLeft") {{ event.preventDefault(); moveHorizontal(-1); }}
        if (event.key === "ArrowRight") {{ event.preventDefault(); moveHorizontal(1); }}
      }});
      cy.on("tap", "node", event => focusNode(event.target.id()));
      statusEl.textContent = `${{data.title}}: left-to-right ordered view (${{cy.nodes().length}} nodes, ${{cy.edges().length}} edges). Edge # labels read top-to-bottom. Use arrow keys to navigate.`;
      focusNode(root);
      setTimeout(() => cy.fit(undefined, 46), 80);
    }}).catch(err => {{
      statusEl.textContent = err.message;
      console.error(err);
    }});
  </script>
</body>
</html>
"""
    html_path.write_text(html, encoding="utf-8")
    relative_html = os.path.relpath(html_path, BASE_OUTPUT).replace("\\", "/")
    return f"{OUTPUT_URL_PREFIX}/{relative_html}"


def navigatable_initial_preview(nodes, edges, root, max_nodes=0):
    if not root or not max_nodes or max_nodes <= 1:
        return [], []
    selected_nodes = [root]
    selected_node_set = {root}
    selected_edges = []
    incident = sorted(
        [edge for edge in edges if edge[0] == root or edge[1] == root],
        key=lambda edge: (edge[0] != root, str(edge[1] if edge[0] == root else edge[0]), str(edge)),
    )
    for edge in incident:
        other = edge[1] if edge[0] == root else edge[0]
        if other not in selected_node_set:
            selected_node_set.add(other)
            selected_nodes.append(other)
        selected_edges.append(edge)
        if len(selected_nodes) >= max_nodes:
            break
    if len(selected_nodes) < max_nodes:
        ranked_nodes = sorted(
            nodes,
            key=lambda node: (
                0 if node in selected_node_set else 1,
                0 if str(node).lower().endswith(("main.py", "index.html", "app.py", "server.js")) else 1,
                str(node),
            ),
        )
        for node in ranked_nodes:
            if node in selected_node_set:
                continue
            selected_node_set.add(node)
            selected_nodes.append(node)
            if len(selected_nodes) >= max_nodes:
                break
    selected_edge_set = set(selected_edges)
    for edge in sorted(edges, key=lambda item: (str(item[0]), str(item[1]))):
        if edge[0] in selected_node_set and edge[1] in selected_node_set:
            selected_edge_set.add(edge)
    return selected_nodes, sorted(selected_edge_set)


def build_navigatable_graph_from_json(graph_json_path, output_repo_dir, graph_name, graph_title="Navigable Callgraph", initial_preview_node_count=0):
    nodes, edges, edge_meta = _load_edge_graph_with_meta(str(graph_json_path))
    if not nodes and not edges:
        return ""
    graph_edges = [
        (src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line"))
        for src, dst in sorted(edges)
    ]
    entry_points = _load_graph_entry_points(str(graph_json_path), nodes)
    node_labels = _load_graph_node_labels(str(graph_json_path))
    edge_labels = _load_graph_edge_labels(str(graph_json_path))
    degree = Counter()
    outgoing_degree = Counter()
    for src, dst in edges:
        degree[src] += 1
        degree[dst] += 1
        outgoing_degree[src] += 1
    fallback_candidates = sorted(
        nodes,
        key=lambda node: (
            0 if degree[node] else 1,
            0 if str(node).startswith(("main.", "js.", "api.")) else 1,
            -outgoing_degree[node],
            -degree[node],
            str(node),
        ),
    )
    root_candidates = entry_points or fallback_candidates
    initial_visible_nodes = []
    initial_visible_edges = []
    if initial_preview_node_count and root_candidates:
        initial_visible_nodes, preview_edges = navigatable_initial_preview(
            nodes,
            edges,
            root_candidates[0],
            max_nodes=initial_preview_node_count,
        )
        initial_visible_edges = [
            (src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line"))
            for src, dst in preview_edges
        ]
    return build_navigatable_cytoscape_graph(
        sorted(nodes),
        graph_edges,
        output_repo_dir,
        graph_name=graph_name,
        graph_title=graph_title,
        initial_roots=root_candidates[:1],
        entry_points=entry_points,
        node_labels=node_labels,
        edge_labels=edge_labels,
        initial_visible_nodes=initial_visible_nodes,
        initial_visible_edges=initial_visible_edges,
    )


def diff_file_entries_from_result(result: dict) -> list[dict]:
    entries = []
    seen = set()

    def add(path, status="modified"):
        clean = str(path or "").replace("\\", "/").strip()
        if not clean or clean.startswith("+") or clean.startswith("risk signal:") or clean.startswith("deleted folder:"):
            return
        key = (status, clean)
        if key in seen:
            return
        seen.add(key)
        entries.append({"path": clean, "status": status})

    def parse_label(label):
        text = str(label or "").strip()
        match = re.match(r"^(added|modified|deleted|renamed|changed):\s+(.+)$", text, re.IGNORECASE)
        if not match:
            add(text)
            return
        status = match.group(1).lower()
        path = match.group(2)
        if " -> " in path:
            path = path.split(" -> ")[-1]
        add(path, status)

    if result.get("file"):
        add(result.get("file"))
    for path in result.get("impact_files") if isinstance(result.get("impact_files"), list) else []:
        add(path)
    change_card = result.get("change_card") if isinstance(result.get("change_card"), dict) else {}
    for label in change_card.get("evidence") if isinstance(change_card.get("evidence"), list) else []:
        parse_label(label)
    return entries


def file_graph_aliases_for_changed_path(path_value: str) -> set[str]:
    normalized = str(path_value or "").replace("\\", "/").strip()
    aliases = {normalized} if normalized else set()
    if not normalized:
        return aliases
    suffix = Path(normalized).suffix
    without_ext = normalized[: -len(suffix)] if suffix else normalized
    name = Path(normalized).name
    stem = Path(normalized).stem
    aliases.update({without_ext, name, stem})
    parts = [part for part in without_ext.split("/") if part]
    for marker in ("java", "kotlin", "scala", "src", "main"):
        if marker in parts:
            tail = "/".join(parts[parts.index(marker) + 1:])
            if tail:
                aliases.add(tail)
    if len(parts) >= 2:
        aliases.add("/".join(parts[-2:]))
    return {alias for alias in aliases if alias}


def resolve_diff_file_graph_nodes(changed_path: str, node_set: set[str]) -> set[str]:
    aliases = file_graph_aliases_for_changed_path(changed_path)
    if not aliases:
        return set()
    resolved = {alias for alias in aliases if alias in node_set}
    if resolved:
        return resolved
    stems = {Path(alias).stem for alias in aliases if alias}
    suffixes = {alias for alias in aliases if "/" in alias}
    for node in node_set:
        node_text = str(node).replace("\\", "/")
        node_stem = Path(node_text).stem
        if node_stem in stems or any(node_text.endswith(f"/{suffix}") or node_text == suffix for suffix in suffixes):
            resolved.add(node)
    return resolved


def build_diff_file_graph(output_repo_dir, diff_entries):
    output_repo_dir = Path(output_repo_dir)
    graph_json_path = output_repo_dir / "file_graph" / "file_graph.json"
    nodes, edges, edge_meta = _load_edge_graph_with_meta(str(graph_json_path))
    changed_files = [entry["path"] for entry in diff_entries if entry.get("path")]
    if not changed_files:
        return ""

    node_set = set(nodes)
    edge_pairs = {(src, dst) for src, dst in edges}
    changed_graph_nodes = set()
    graph_node_to_changed_file = {}
    for file_path in changed_files:
        mapped = resolve_diff_file_graph_nodes(file_path, node_set)
        if not mapped:
            mapped = {file_path}
        for node in mapped:
            changed_graph_nodes.add(node)
            graph_node_to_changed_file[node] = file_path
    selected = set(changed_graph_nodes)
    selected_edges = set()
    for src, dst in edge_pairs:
        if src in changed_graph_nodes or dst in changed_graph_nodes:
            selected.update([src, dst])
            selected_edges.add((src, dst))
    selected.update(changed_graph_nodes)

    graph_edges = [
        (src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line"))
        for src, dst in sorted(selected_edges)
    ]
    status_by_file = {entry["path"]: entry.get("status", "modified") for entry in diff_entries if entry.get("path")}
    node_labels = _load_graph_node_labels(str(graph_json_path))
    for graph_node, file_path in graph_node_to_changed_file.items():
        status = status_by_file.get(file_path, "modified")
        node_labels[graph_node] = f"{status}: {file_path}"
    for file_path, status in status_by_file.items():
        if file_path in selected:
            node_labels[file_path] = f"{status}: {file_path}"
    edge_labels = _load_graph_edge_labels(str(graph_json_path))
    initial_roots = sorted(changed_graph_nodes)[:12]
    return build_navigatable_cytoscape_graph(
        sorted(selected),
        graph_edges,
        output_repo_dir / "diff_graph",
        graph_name="diff_file_graph",
        graph_title="Diff File Graph",
        initial_roots=initial_roots,
        entry_points=initial_roots,
        node_labels=node_labels,
        edge_labels=edge_labels,
        initial_visible_nodes=initial_roots + sorted(selected - set(initial_roots))[:24],
        initial_visible_edges=graph_edges[:120],
        highlight_data={
            "changed_nodes": sorted(changed_graph_nodes),
            "affected_nodes": sorted(selected - changed_graph_nodes),
            "affected_files": changed_files,
        },
        preserve_initial_order=True,
    )


def navigatable_graph_html_current(html_path):
    if not html_path or not os.path.exists(html_path):
        return False
    try:
        with open(html_path, "r", encoding="utf-8", errors="ignore") as f:
            html = f.read(32768)
    except OSError:
        return False
    return (
        "Click a node to reveal the next connected node or edge" in html
        and "applyRoadLayout" in html
        and "single-root-progressive-v6" in html
        and "node_labels" in html
        and "order: edge.order" in html
        and '"font-size":"11px"' in html
    )


HTTP_ROUTE_DECORATORS = {"get", "post", "put", "patch", "delete", "options", "head", "api_route"}


def api_route_symbol(route_path: str):
    route_path = str(route_path or "").strip()
    if route_path in {"", "/"}:
        return "api.root"
    return f"api.{html_ui_slug(route_path.strip('/'), 'route')}"


def api_route_label(route_path: str):
    route_path = str(route_path or "").strip()
    return route_path if route_path.startswith("/") else f"/{route_path}" if route_path else "/"


def combined_callgraph_source_paths(output_repo_dir, results=None):
    output_repo_dir = Path(output_repo_dir)
    results = results or {}
    candidates = [
        results.get("python_callgraph_json_path"),
        results.get("javascript_callgraph_json_path"),
        results.get("csharp_callgraph_json_path"),
        results.get("html_ui_graph_json_path"),
        results.get("java_merged_json_path"),
        results.get("tree_sitter_java_json_path"),
        results.get("callgraph_javalang_json_path"),
        results.get("reduced_joern_callgraph_json_path"),
        results.get("joern_callgraph.json"),
        output_repo_dir / "html_ui" / "html_ui_graph.json",
        output_repo_dir / "javascript" / "javascript_callgraph.json",
        output_repo_dir / "csharp" / "csharp_callgraph.json",
        output_repo_dir / "python" / "python_callgraph.json",
        output_repo_dir / "java_merged" / "java_merged_callgraph.json",
        output_repo_dir / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        output_repo_dir / "javalang" / "javalang_callgraph.json",
        output_repo_dir / "joern" / "reduced_joern_callgraph.json",
        output_repo_dir / "joern" / "joern_callgraph.json",
    ]
    paths = []
    seen = set()
    for candidate in candidates:
        if not candidate:
            continue
        path = Path(candidate)
        if not path.exists():
            continue
        resolved = str(path.resolve())
        if resolved in seen:
            continue
        seen.add(resolved)
        paths.append(path)
    return paths


def _python_module_name_for_route(repo_src: Path, path: Path):
    rel = os.path.relpath(path, repo_src).replace("\\", "/")
    if not rel.endswith(".py"):
        return ""
    parts = rel[:-3].split("/")
    if parts and parts[-1] == "__init__":
        parts = parts[:-1]
    return ".".join(parts) if parts else "__init__"


def _decorator_route_path(decorator):
    call_node = decorator if isinstance(decorator, ast.Call) else None
    func_node = call_node.func if call_node else decorator
    method_name = ""
    if isinstance(func_node, ast.Attribute):
        method_name = func_node.attr
    elif isinstance(func_node, ast.Name):
        method_name = func_node.id
    if method_name not in HTTP_ROUTE_DECORATORS:
        return ""
    if call_node and call_node.args:
        first_arg = call_node.args[0]
        if isinstance(first_arg, ast.Constant) and isinstance(first_arg.value, str):
            return first_arg.value
    return ""


def extract_python_api_route_edges(repo_src, function_nodes):
    if not repo_src:
        return set(), set(), {}
    repo_src = Path(repo_src or "")
    if not repo_src.exists():
        return set(), set(), {}
    nodes = set()
    edges = set()
    node_labels = {}
    function_nodes = set(function_nodes or [])
    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), str(repo_src))]
        for filename in files:
            if not filename.endswith(".py"):
                continue
            path = Path(root) / filename
            if should_skip_path(str(path), str(repo_src)):
                continue
            try:
                tree = ast.parse(path.read_text(encoding="utf-8", errors="ignore"), filename=str(path))
            except Exception:
                continue
            module_name = _python_module_name_for_route(repo_src, path)
            for item in ast.walk(tree):
                if not isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    continue
                route_paths = [
                    route_path
                    for route_path in (_decorator_route_path(decorator) for decorator in item.decorator_list)
                    if route_path
                ]
                if not route_paths:
                    continue
                target = f"{module_name}.{item.name}" if module_name else item.name
                if target not in function_nodes:
                    suffix_matches = [node for node in function_nodes if str(node).endswith(f".{item.name}")]
                    if len(suffix_matches) == 1:
                        target = suffix_matches[0]
                if target not in function_nodes:
                    continue
                nodes.add(target)
                for route_path in route_paths:
                    route_node = api_route_symbol(route_path)
                    nodes.add(route_node)
                    node_labels[route_node] = api_route_label(route_path)
                    edges.add((route_node, target))
    return nodes, edges, node_labels


def iter_javascript_function_bodies(text: str):
    patterns = [
        re.compile(r"\b(?:async\s+)?function\s+([A-Za-z_$][\w$]*)\s*\([^)]*\)\s*\{"),
        re.compile(r"\b(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*=\s*(?:async\s*)?\([^)]*\)\s*=>\s*\{"),
        re.compile(r"\b(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*=\s*(?:async\s*)?function\s*\([^)]*\)\s*\{"),
    ]
    starts = []
    for pattern in patterns:
        for match in pattern.finditer(text or ""):
            starts.append((match.start(), match.end() - 1, match.group(1)))
    for _, brace_index, name in sorted(starts):
        depth = 0
        quote = ""
        escape = False
        for index in range(brace_index, len(text)):
            char = text[index]
            if quote:
                if escape:
                    escape = False
                elif char == "\\":
                    escape = True
                elif char == quote:
                    quote = ""
                continue
            if char in {"'", '"', "`"}:
                quote = char
            elif char == "{":
                depth += 1
            elif char == "}":
                depth -= 1
                if depth == 0:
                    yield name, text[brace_index + 1:index]
                    break


def extract_javascript_api_route_edges(repo_src, function_nodes):
    if not repo_src:
        return set(), set(), {}
    repo_src = Path(repo_src)
    if not repo_src.exists():
        return set(), set(), {}
    nodes = set()
    edges = set()
    node_labels = {}
    function_nodes = set(function_nodes or [])
    route_literal = re.compile(r"(?<![A-Za-z0-9_.-])(/(?:[A-Za-z0-9_.~!$&'()*+,;=:@%-]+/?)+)")
    ignored_prefixes = ("/lib/", "/output/", "/static/", "/assets/", "/css/", "/js/")
    ignored_suffixes = (".html", ".css", ".js", ".json", ".png", ".jpg", ".jpeg", ".svg", ".ico")
    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), str(repo_src))]
        for filename in files:
            ext = Path(filename).suffix.lower()
            if ext not in JS_SOURCE_EXTENSIONS and ext not in {".html", ".htm"}:
                continue
            path = Path(root) / filename
            if should_skip_path(str(path), str(repo_src)):
                continue
            text = path.read_text(encoding="utf-8", errors="ignore")
            for function_name, body in iter_javascript_function_bodies(text):
                if "fetch(" not in body and "new URL(" not in body:
                    continue
                source = (
                    resolve_graph_entry_symbol(f"js.{function_name}", function_nodes)
                    or resolve_graph_entry_symbol(function_name, function_nodes)
                    or f"js.{function_name}"
                )
                for match in route_literal.finditer(body):
                    route_path = match.group(1)
                    if route_path.startswith(ignored_prefixes) or route_path.lower().endswith(ignored_suffixes):
                        continue
                    route_node = api_route_symbol(route_path)
                    nodes.update([source, route_node])
                    node_labels[route_node] = api_route_label(route_path)
                    edges.add((source, route_node))
    return nodes, edges, node_labels


def add_ui_alias_edges(nodes, edges):
    nodes = set(nodes)
    edges = set(edges)
    js_aliases = [node for node in nodes if str(node).startswith("js.")]
    for alias in js_aliases:
        handler = str(alias).split(".", 1)[1]
        matches = [
            node for node in nodes
            if node != alias and (
                str(node).endswith(f".{handler}") or
                str(node).endswith(f".{handler}.<anonymous>") or
                str(node) == handler
            )
        ]
        if len(matches) == 1:
            edges.add((alias, matches[0]))
    return nodes, edges


def resolve_graph_entry_symbol(symbol, nodes):
    symbol = str(symbol or "").strip()
    if not symbol:
        return ""
    node_set = set(nodes or [])
    if symbol in node_set:
        return symbol
    candidates = []
    if symbol.startswith("js."):
        candidates.append(symbol[3:])
    else:
        candidates.append(f"js.{symbol}")
    candidates.extend([
        f"main.{symbol}",
        symbol.replace("/", ".").replace("\\", "."),
    ])
    tail = symbol.split(".")[-1]
    if tail and tail != symbol:
        candidates.append(tail)
    for candidate in candidates:
        if candidate in node_set:
            return candidate
    suffixes = [f".{symbol}", f".{tail}"] if tail else [f".{symbol}"]
    matches = [
        node for node in node_set
        if any(str(node).endswith(suffix) for suffix in suffixes)
    ]
    return sorted(matches, key=lambda node: (len(str(node)), str(node)))[0] if len(matches) == 1 else ""


def collect_topology_entry_points(nodes, edges):
    incoming = Counter()
    outgoing = Counter()
    for src, dst in edges:
        outgoing[src] += 1
        incoming[dst] += 1
    entries = set()
    for node in nodes:
        text = str(node)
        if text in {"api.root", "api.api", "api.docs", "url.root", "url.api", "url.docs"}:
            continue
        if outgoing[node] and not incoming[node] and (
            text.startswith(("api.", "url.", "event."))
            or re.search(r"(?:^|_)(button|form|input|select|textarea|link|href|onclick|submit)(?:_|$)", text, re.IGNORECASE)
        ):
            entries.add(node)
    return entries


def entry_point_priority(node, outgoing=None):
    text = str(node)
    outgoing = outgoing or Counter()
    synthetic = text.startswith(("api.", "url.", "event."))
    generic = text in {"api.root", "api.api", "api.docs", "url.root", "url.api", "url.docs"} or text.endswith((".root", ".api", ".docs"))
    return (
        3 if generic else 0,
        1 if synthetic else 0,
        0 if text.startswith("api.") and not generic else 1,
        -outgoing[text],
        len(text),
        text,
    )


def collect_python_entry_points(repo_src, nodes):
    entries = set()
    if not repo_src:
        return entries
    repo_src = Path(repo_src)
    if not repo_src.exists():
        return entries
    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), str(repo_src))]
        for filename in files:
            if not filename.endswith(".py"):
                continue
            path = Path(root) / filename
            if should_skip_path(str(path), str(repo_src)):
                continue
            try:
                tree = ast.parse(path.read_text(encoding="utf-8", errors="ignore"), filename=str(path))
            except Exception:
                continue
            module_name = _python_module_name_for_route(repo_src, path)
            for item in ast.walk(tree):
                if isinstance(item, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    function_symbol = f"{module_name}.{item.name}" if module_name else item.name
                    route_paths = [
                        route_path
                        for route_path in (_decorator_route_path(decorator) for decorator in item.decorator_list)
                        if route_path
                    ]
                    if route_paths:
                        for route_path in route_paths:
                            entries.add(api_route_symbol(route_path))
                        resolved = resolve_graph_entry_symbol(function_symbol, nodes)
                        if resolved:
                            entries.add(resolved)
                    elif item.name in {"main", "handler", "lambda_handler"}:
                        resolved = resolve_graph_entry_symbol(function_symbol, nodes) or resolve_graph_entry_symbol(item.name, nodes)
                        if resolved:
                            entries.add(resolved)
                elif isinstance(item, ast.If):
                    test = ast.unparse(item.test) if hasattr(ast, "unparse") else ""
                    if "__name__" in test and "__main__" in test:
                        for child in ast.walk(item):
                            if isinstance(child, ast.Call):
                                call_name = ""
                                if isinstance(child.func, ast.Name):
                                    call_name = child.func.id
                                elif isinstance(child.func, ast.Attribute):
                                    call_name = child.func.attr
                                resolved = resolve_graph_entry_symbol(f"{module_name}.{call_name}", nodes) or resolve_graph_entry_symbol(call_name, nodes)
                                if resolved:
                                    entries.add(resolved)
    return entries


def collect_java_entry_points(repo_src, nodes):
    entries = set()
    if not repo_src:
        return entries
    repo_src = Path(repo_src)
    if not repo_src.exists():
        return entries
    route_annotation = re.compile(r"@(GetMapping|PostMapping|PutMapping|PatchMapping|DeleteMapping|RequestMapping|Path)\b")
    method_decl = re.compile(r"(?:public|protected|private)?\s*(?:static\s+)?[\w<>\[\], ?]+\s+(\w+)\s*\(")
    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), str(repo_src))]
        for filename in files:
            if not filename.endswith(".java"):
                continue
            path = Path(root) / filename
            if should_skip_path(str(path), str(repo_src)):
                continue
            text = path.read_text(encoding="utf-8", errors="ignore")
            class_name = re.search(r"\bclass\s+(\w+)", text)
            class_name = class_name.group(1) if class_name else Path(filename).stem
            for match in re.finditer(r"public\s+static\s+void\s+main\s*\(", text):
                prefix = text[:match.start()]
                method = "main"
                resolved = resolve_graph_entry_symbol(f"{class_name}.{method}", nodes) or resolve_graph_entry_symbol(method, nodes)
                if resolved:
                    entries.add(resolved)
            lines = text.splitlines()
            for index, line in enumerate(lines):
                if not route_annotation.search(line):
                    continue
                lookahead = "\n".join(lines[index:index + 8])
                method_match = method_decl.search(lookahead)
                if method_match:
                    method = method_match.group(1)
                    resolved = resolve_graph_entry_symbol(f"{class_name}.{method}", nodes) or resolve_graph_entry_symbol(method, nodes)
                    if resolved:
                        entries.add(resolved)
    return entries


def collect_javascript_entry_points(repo_src, nodes):
    entries = set()
    if not repo_src:
        return entries
    repo_src = Path(repo_src)
    if not repo_src.exists():
        return entries
    route_call = re.compile(
        r"\b(?:app|router|server)\.(?:get|post|put|patch|delete|use|all)\s*\([^,\n]+,\s*([A-Za-z_$][\w$]*)",
        re.IGNORECASE,
    )
    export_handler = re.compile(r"\b(?:exports\.(\w+)|module\.exports\s*=\s*(\w+)|export\s+default\s+function\s+(\w+)|export\s+function\s+(\w+))")
    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), str(repo_src))]
        for filename in files:
            ext = Path(filename).suffix.lower()
            if ext not in JS_SOURCE_EXTENSIONS:
                continue
            path = Path(root) / filename
            if should_skip_path(str(path), str(repo_src)):
                continue
            text = path.read_text(encoding="utf-8", errors="ignore")
            for match in route_call.finditer(text):
                resolved = resolve_graph_entry_symbol(match.group(1), nodes)
                if resolved:
                    entries.add(resolved)
            for match in export_handler.finditer(text):
                name = next((group for group in match.groups() if group), "")
                if name:
                    resolved = resolve_graph_entry_symbol(name, nodes)
                    if resolved:
                        entries.add(resolved)
            for name in ("main", "handler"):
                if re.search(rf"\b(?:function\s+{name}|const\s+{name}\s*=|let\s+{name}\s*=|var\s+{name}\s*=)", text):
                    resolved = resolve_graph_entry_symbol(name, nodes)
                    if resolved:
                        entries.add(resolved)
    return entries


def collect_combined_entry_points(repo_src, nodes, edges):
    entries = set()
    outgoing = Counter()
    for src, _ in edges:
        outgoing[src] += 1
    entries.update(collect_topology_entry_points(nodes, edges))
    entries.update(collect_python_entry_points(repo_src, nodes))
    entries.update(collect_java_entry_points(repo_src, nodes))
    entries.update(collect_javascript_entry_points(repo_src, nodes))
    return sorted(entries, key=lambda node: entry_point_priority(node, outgoing))


def build_combined_navigatable_callgraph(output_repo_dir, results=None, repo_src=""):
    output_repo_dir = Path(output_repo_dir)
    results = results or {}
    nodes = set()
    edges = set()
    edge_meta = {}
    node_labels = {}
    edge_labels = {}
    sources = []
    for graph_path in combined_callgraph_source_paths(output_repo_dir, results):
        graph_nodes, graph_edges, graph_edge_meta = _load_edge_graph_with_meta(str(graph_path))
        if not graph_nodes and not graph_edges:
            continue
        nodes.update(graph_nodes)
        edges.update(graph_edges)
        node_labels.update(_load_graph_node_labels(str(graph_path)))
        edge_labels.update(_load_graph_edge_labels(str(graph_path)))
        for edge, meta in graph_edge_meta.items():
            previous = edge_meta.get(edge)
            order = meta.get("order")
            if previous is None or (order is not None and order < (previous.get("order") or order)):
                edge_meta[edge] = meta
        sources.append(os.path.relpath(graph_path, output_repo_dir).replace("\\", "/"))

    route_nodes, route_edges, node_labels = extract_python_api_route_edges(repo_src, nodes)
    nodes.update(route_nodes)
    edges.update(route_edges)
    js_route_nodes, js_route_edges, js_route_labels = extract_javascript_api_route_edges(repo_src, nodes)
    nodes.update(js_route_nodes)
    edges.update(js_route_edges)
    node_labels.update(js_route_labels)
    nodes, edges = add_ui_alias_edges(nodes, edges)
    entry_points = collect_combined_entry_points(repo_src, nodes, edges)

    if not nodes and not edges:
        return results

    combined_dir = output_repo_dir / "combined_callgraph"
    combined_dir.mkdir(parents=True, exist_ok=True)
    combined_json_path = combined_dir / "combined_callgraph.json"
    graph = {
        "mode": "combined_function_ui_callgraph",
        "version": 1,
        "sources": sources,
        "nodes": sorted(nodes),
        "edges": [
            [src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line")]
            if (src, dst) in edge_meta else [src, dst]
            for src, dst in sorted(edges)
        ],
        "entry_points": entry_points,
        "node_labels": node_labels,
        "edge_labels": edge_labels,
    }
    combined_json_path.write_text(json.dumps(graph, indent=2), encoding="utf-8")
    ordered_calls = [
        {
            "caller": src,
            "callee": dst,
            "order": edge_meta.get((src, dst), {}).get("order"),
            "line": edge_meta.get((src, dst), {}).get("line"),
        }
        for src, dst in sorted(edges, key=lambda edge: (
            edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
            edge[0],
            edge[1],
        ))
    ]
    if ordered_calls:
        write_ordered_call_sequence(
            ordered_calls,
            combined_dir / "combined_ordered_call_sequence.json",
            parser="combined",
            source_callgraph=os.path.basename(combined_json_path),
        )
    results["combined_callgraph_json_path"] = str(combined_json_path)
    results["combined_navigatable_callgraph_html_path"] = build_navigatable_graph_from_json(
        combined_json_path,
        combined_dir,
        graph_name="combined_navigatable_callgraph",
        graph_title="Navigable Merged Callgraph",
        initial_preview_node_count=16,
    )
    return results


def build_file_navigatable_graph(output_repo_dir, results):
    output_repo_dir = Path(output_repo_dir)
    file_graph_json = Path(results.get("file_graph_json_path") or output_repo_dir / "file_graph" / "file_graph.json")
    if not file_graph_json.exists():
        return results
    results["file_graph_navigatable_html_path"] = build_navigatable_graph_from_json(
        file_graph_json,
        file_graph_json.parent,
        graph_name="file_graph_navigatable",
        graph_title="Navigable File Call Graph",
        initial_preview_node_count=10,
    )
    return results


def build_ga_navigatable_ordered_interaction_graph(owner_name: str, repo_name: str, rows: list[dict]):
    if not owner_name or not repo_name or not rows:
        return ""
    nodes = callgraph_nodes_for_mapping(owner_name, repo_name)
    if not nodes:
        return ""
    lowered_nodes = [(node.lower(), node) for node in nodes]
    ordered_items = []
    for row in sorted(rows, key=ga_row_sort_key):
        count = int(row.get("eventCount") or 0)
        matched_nodes = ga_matching_nodes_for_row(row, lowered_nodes)
        if not count or not matched_nodes:
            continue
        ordered_items.append({
            "label": ga_row_label(row),
            "matched_nodes": matched_nodes[:3],
        })
    if not ordered_items:
        return ""
    graph_nodes = set()
    graph_edges = []
    previous_event_node = ""
    edge_order = 1
    first_event_node = ""
    for index, item in enumerate(ordered_items[:120], start=1):
        label = re.sub(r"[^A-Za-z0-9_.-]+", "_", item["label"]).strip("_")[:40] or "interaction"
        event_node = f"ga.step_{index:03d}.{label}"
        first_event_node = first_event_node or event_node
        graph_nodes.add(event_node)
        if previous_event_node:
            graph_edges.append((previous_event_node, event_node, edge_order, None))
            edge_order += 1
        previous_event_node = event_node
        for matched_node in item["matched_nodes"]:
            graph_nodes.add(matched_node)
            graph_edges.append((event_node, matched_node, edge_order, None))
            edge_order += 1
    return build_navigatable_cytoscape_graph(
        sorted(graph_nodes),
        graph_edges,
        repo_output_dir(owner_name, repo_name),
        graph_name="ga_navigatable_ordered_graph",
        graph_title="Navigable Ordered GA Graph",
        initial_roots=[first_event_node] if first_event_node else None,
    )


def ga_unique_action_key(row: dict):
    return (
        str(row.get("customEvent:function_name") or row.get("function_name") or "").strip(),
        str(row.get("customEvent:callgraph_node") or row.get("callgraph_node") or "").strip(),
        str(row.get("customEvent:button_name") or row.get("button_name") or ga_row_label(row)).strip(),
        str(row.get("customEvent:input_value") or row.get("input_value") or "").strip(),
    )


def ga_trace_label(row: dict):
    label = ga_row_label(row)
    if label and label != "GA interaction" and ga_value_is_useful(label) and not label.startswith(("http://", "https://", "/")):
        return label
    for key in (
        "customEvent:trigger_element", "trigger_element",
        "customEvent:function_name", "function_name",
        "customEvent:click_id", "click_id",
        "customEvent:endpoint", "endpoint",
    ):
        value = str(row.get(key, "") or "").strip()
        if ga_value_is_useful(value):
            return value
    return label or "GA interaction"


def ga_trace_step_label(step_index: int):
    return f"step_{int(step_index):03d}"


def ga_trace_flow_node_id(flow_index: int, label: str, step_indexes):
    steps = sorted({int(step) for step in (step_indexes or []) if step})
    if steps:
        step_part = "_".join(f"{step:03d}" for step in steps[:4])
        if len(steps) > 4:
            step_part = f"{step_part}_plus_{len(steps) - 4}"
        prefix = "steps" if len(steps) > 1 else "step"
        step_text = f"{prefix}_{step_part}"
    else:
        step_text = f"flow_{flow_index:03d}"
    slug = html_ui_slug(label, f"flow_{flow_index}", max_len=40)
    slug = re.sub(r"[^A-Za-z0-9_]+", "_", slug).strip("_") or f"flow_{flow_index}"
    return f"GA_{step_text}_{slug}_node"


def ga_trace_flow_node_label(label: str, step_indexes, event_count: int):
    steps = sorted({int(step) for step in (step_indexes or []) if step})
    step_text = ", ".join(ga_trace_step_label(step) for step in steps[:8])
    if len(steps) > 8:
        step_text = f"{step_text}, +{len(steps) - 8} more"
    suffix = f"GA steps: {step_text}" if step_text else "GA flow"
    return f"GA action: {label} ({suffix}; events: {event_count})"


def ga_trace_root_nodes_for_row(row: dict, graph_nodes, limit: int = 1):
    node_set = set(graph_nodes or [])
    roots = []

    def add_resolved(candidate):
        resolved = resolve_graph_entry_symbol(candidate, node_set)
        if resolved and resolved not in roots:
            roots.append(resolved)

    def add_candidate(value):
        value = str(value or "").strip()
        if not ga_value_is_useful(value):
            return
        method = str(row.get("customEvent:method") or row.get("method") or "").strip()
        route_nodes = ga_endpoint_route_candidates(value, method)
        if route_nodes:
            for route_node in route_nodes:
                add_resolved(route_node)
            return
        if value.startswith(("http://", "https://", "/")):
            return
        direct_alias = DASHBOARD_GA_ID_FUNCTION_ALIASES.get(value)
        if direct_alias:
            add_resolved(direct_alias)
            add_resolved(f"js.{direct_alias}")
        label_alias = DASHBOARD_GA_LABEL_FUNCTION_ALIASES.get(value.lower())
        if label_alias:
            add_resolved(label_alias)
            add_resolved(f"js.{label_alias}")
        for page_symbol in ("static_dashboard_html", "static_analyze_html", "static_index_html", "static_product_html"):
            add_resolved(f"{page_symbol}.{value}")
        for candidate in ga_candidate_aliases(value):
            add_resolved(candidate)

    for key in (
        "customEvent:endpoint", "endpoint",
        "customEvent:fetch_url", "fetch_url",
        "customEvent:request_path", "request_path",
        "customEvent:request_url", "request_url",
        "customEvent:page_path", "page_path",
        "customEvent:function_name", "function_name",
        "customEvent:callgraph_node", "callgraph_node",
        "customEvent:click_id", "click_id",
        "customEvent:source_element", "source_element",
        "customEvent:trigger_element", "trigger_element",
        "customEvent:button_name", "button_name",
        "customEvent:click_text", "click_text",
    ):
        add_candidate(row.get(key, ""))

    def root_priority(node):
        text = str(node)
        return (
            0 if text.startswith("js.") else
            1 if text.startswith("api.") else
            2 if text.startswith("url.") else
            3 if text.startswith("main.") else
            4,
            len(text),
            text,
        )

    try:
        root_limit = max(1, int(limit))
    except Exception:
        root_limit = 1
    return sorted(roots, key=root_priority)[:root_limit]


def ga_function_aliases_for_row(row: dict):
    aliases = []

    def add_alias(value):
        value = str(value or "").strip()
        if not ga_value_is_useful(value) or value.startswith(("http://", "https://", "/")):
            return
        if value.startswith("js."):
            value = value[3:]
        value = DASHBOARD_GA_ID_FUNCTION_ALIASES.get(value, value)
        value = DASHBOARD_GA_LABEL_FUNCTION_ALIASES.get(value.lower(), value)
        if value and re.match(r"^[A-Za-z_$][\w$]*$", value) and value not in aliases:
            aliases.append(value)

    for key in (
        "customEvent:function_name", "function_name",
        "customEvent:callgraph_node", "callgraph_node",
        "customEvent:click_id", "click_id",
        "customEvent:button_name", "button_name",
        "customEvent:click_text", "click_text",
    ):
        add_alias(row.get(key, ""))
    return aliases


def ga_trace_group_key(root_nodes):
    return tuple(sorted(root_nodes or []))


def walk_downstream_trace(root_nodes, outgoing, max_depth=10, max_nodes=220):
    selected_nodes = set(root_nodes or [])
    selected_edges = set()
    queue = deque((node, 0) for node in root_nodes or [])
    seen = set(root_nodes or [])
    while queue and len(selected_nodes) < max_nodes:
        node, distance = queue.popleft()
        if distance >= max_depth:
            continue
        for neighbor in sorted(outgoing.get(node, set())):
            selected_edges.add((node, neighbor))
            selected_nodes.add(neighbor)
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append((neighbor, distance + 1))
            if len(selected_nodes) >= max_nodes:
                break
    return selected_nodes, selected_edges


def walk_ga_event_trace(root_nodes, outgoing, max_depth=3, max_nodes=40):
    selected_nodes = set(root_nodes or [])
    selected_edges = set()
    queue = deque((node, 0) for node in root_nodes or [])
    seen = set(root_nodes or [])
    while queue and len(selected_nodes) < max_nodes:
        node, distance = queue.popleft()
        if distance >= max_depth:
            continue
        neighbors = sorted(outgoing.get(node, set()), key=ga_trace_neighbor_priority)
        if distance == 0:
            limit = 5
        elif distance == 1:
            limit = 3
        else:
            limit = 8 if str(node).startswith("api.") else 0
        for neighbor in neighbors[:limit]:
            selected_edges.add((node, neighbor))
            selected_nodes.add(neighbor)
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append((neighbor, distance + 1))
            if len(selected_nodes) >= max_nodes:
                break
    return selected_nodes, selected_edges


def walk_ga_event_context_trace(root_nodes, outgoing, incoming, max_depth=4, max_nodes=120):
    selected_nodes = set(root_nodes or [])
    selected_edges = set()
    queue = deque((node, 0) for node in root_nodes or [])
    seen = set(root_nodes or [])
    while queue and len(selected_nodes) < max_nodes:
        node, distance = queue.popleft()
        if distance >= max_depth:
            continue
        neighbors = []
        for neighbor in outgoing.get(node, set()):
            neighbors.append((ga_trace_context_neighbor_priority(neighbor, "out", distance), neighbor, node, neighbor))
        for neighbor in incoming.get(node, set()):
            neighbors.append((ga_trace_context_neighbor_priority(neighbor, "in", distance), neighbor, neighbor, node))
        if distance == 0:
            limit = 12
        elif distance == 1:
            limit = 10
        elif distance == 2:
            limit = 8
        else:
            limit = 4
        for _, neighbor, src, dst in sorted(neighbors)[:limit]:
            selected_edges.add((src, dst))
            selected_nodes.add(neighbor)
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append((neighbor, distance + 1))
            if len(selected_nodes) >= max_nodes:
                break
    return selected_nodes, selected_edges


def ga_event_initial_one_hop_graph(root_nodes, ga_node, trace_nodes, outgoing, incoming, edge_tuples):
    visible_nodes = set(root_nodes or []) | {ga_node}
    visible_edge_pairs = set()
    trace_node_set = set(trace_nodes or [])
    for root_node in root_nodes or []:
        for neighbor in outgoing.get(root_node, set()):
            if neighbor not in trace_node_set:
                continue
            visible_nodes.add(neighbor)
            visible_edge_pairs.add((root_node, neighbor))
        for neighbor in incoming.get(root_node, set()):
            if neighbor not in trace_node_set:
                continue
            visible_nodes.add(neighbor)
            visible_edge_pairs.add((neighbor, root_node))

    edge_by_pair = {
        (src, dst): (src, dst, order, line)
        for src, dst, order, line in edge_tuples or []
    }
    visible_edges = [
        edge_by_pair[pair]
        for pair in sorted(visible_edge_pairs)
        if pair in edge_by_pair
    ]
    bridge_edges = [(ga_node, root_node, None, None) for root_node in root_nodes or []]
    visible_edges.extend(bridge_edges)
    for src, dst, _, _ in visible_edges:
        visible_nodes.add(src)
        visible_nodes.add(dst)
    return sorted(visible_nodes), visible_edges


def ga_trace_neighbor_priority(node):
    text = str(node)
    generic = text.endswith((".root", ".api", ".docs"))
    return (
        5 if generic else 0,
        0 if text.startswith("api.") else
        1 if text.startswith(("route.", "url.")) else
        2 if re.search(r"(^|[._])(handler|controller|route|endpoint|view|action)([._]|$)", text, re.IGNORECASE) else
        3 if text.startswith("main.") else
        6,
        len(text),
        text,
    )


def ga_trace_context_neighbor_priority(node, direction: str, distance: int):
    text = str(node)
    return (
        0 if text.startswith("static_") else
        1 if text.startswith("js.") else
        2 if text.startswith("api.") else
        3 if text.startswith(("url.", "route.")) else
        4 if text.startswith("main.") else
        6,
        0 if direction == "in" and distance <= 1 and text.startswith("static_") else
        1 if direction == "out" and text.startswith(("api.", "main.")) else
        2,
        ga_trace_neighbor_priority(node),
    )


def build_ga_event_trace_graphs(owner_name: str, repo_name: str, rows: list[dict], mapping: Optional[dict] = None, max_events: int = 24):
    if not owner_name or not repo_name or not rows:
        return []
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    graph_nodes, graph_edges, outgoing, _, edge_meta, graph_node_labels = load_ga_mapping_network_with_meta(output_repo_dir)
    if not graph_nodes:
        return []
    fallback_roots_by_row = defaultdict(list)
    for match in (mapping or {}).get("matches", []) or []:
        node = match.get("node")
        if not node or node not in graph_nodes:
            continue
        for evidence in match.get("evidence") or []:
            if not isinstance(evidence, dict):
                continue
            key = ga_unique_action_key(evidence)
            if node not in fallback_roots_by_row[key]:
                fallback_roots_by_row[key].append(node)
    grouped = {}
    for row_index, row in enumerate(rows, start=1):
        count = int(row.get("eventCount") or 0)
        if not count:
            continue
        root_nodes = ga_trace_root_nodes_for_row(row, graph_nodes)
        if not root_nodes:
            root_nodes = fallback_roots_by_row.get(ga_unique_action_key(row), [])[:1]
        if not root_nodes:
            continue
        key = ga_trace_group_key(root_nodes)
        item = grouped.setdefault(key, {
            "label": ga_trace_label(row),
            "event_count": 0,
            "rows": [],
            "root_nodes": set(),
            "labels": Counter(),
            "ga_steps": set(),
        })
        item["event_count"] += count
        item["labels"][ga_trace_label(row)] += count
        item["ga_steps"].add(row_index)
        if len(item["rows"]) < 3:
            item["rows"].append(row)
        item["root_nodes"].update(root_nodes)

    event_graphs = []
    for index, item in enumerate(sorted(grouped.values(), key=lambda value: value["event_count"], reverse=True)[:max_events], start=1):
        root_nodes = sorted(item["root_nodes"])
        trace_nodes, trace_edges = walk_ga_event_trace(root_nodes, outgoing)
        if not root_nodes:
            continue
        item["label"] = item["labels"].most_common(1)[0][0] if item.get("labels") else item["label"]
        label_slug = html_ui_slug(item["label"], f"event_{index}", max_len=36)
        ga_node = ga_trace_flow_node_id(index, item["label"], item.get("ga_steps"))
        node_labels = dict(graph_node_labels)
        node_labels[ga_node] = ga_trace_flow_node_label(item["label"], item.get("ga_steps"), item["event_count"])
        for node in root_nodes:
            node_labels.setdefault(node, str(graph_node_labels.get(node) or node))
        navigatable_edges = [
            (
                src,
                dst,
                edge_meta.get((src, dst), {}).get("order"),
                edge_meta.get((src, dst), {}).get("line"),
            )
            for src, dst in sorted(graph_edges)
        ]
        bridge_edge_labels = {
            f"{ga_node}->{root_node}": "maps to"
            for root_node in root_nodes
        }
        navigatable_edges.extend((ga_node, root_node, None, None) for root_node in root_nodes)
        navigatable_nodes = sorted(set(graph_nodes) | {ga_node})
        initial_trace_nodes = set(root_nodes) | {ga_node}
        initial_trace_edges = {(ga_node, root_node) for root_node in root_nodes}
        graph_url = build_navigatable_cytoscape_graph(
            navigatable_nodes,
            navigatable_edges,
            output_repo_dir,
            graph_name=f"ga_event_trace_{index:02d}_{label_slug}",
            graph_title=f"GA Event Trace: {item['label']}",
            initial_roots=[ga_node],
            entry_points=[ga_node],
            node_labels=node_labels,
            edge_labels=bridge_edge_labels,
        )
        event_graphs.append({
            "label": item["label"],
            "event_count": item["event_count"],
            "ga_node": ga_node,
            "ga_steps": [ga_trace_step_label(step) for step in sorted(item.get("ga_steps") or [])],
            "root_nodes": root_nodes,
            "node_count": len(initial_trace_nodes),
            "edge_count": len(initial_trace_edges),
            "expandable_node_count": len(navigatable_nodes),
            "expandable_edge_count": len(navigatable_edges),
            "graph_url": graph_url,
            "graph_json_url": graph_url[:-5] + ".json" if graph_url.endswith(".html") else "",
        })
    return event_graphs


def build_single_ga_event_graph(owner_name: str, repo_name: str, row: dict):
    if not owner_name or not repo_name or not isinstance(row, dict):
        raise HTTPException(status_code=400, detail="owner_name, repo_name, and row are required")
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    graph_nodes, graph_edges, outgoing, incoming, edge_meta, graph_node_labels = load_ga_mapping_network_with_meta(output_repo_dir)
    if not graph_nodes:
        raise HTTPException(status_code=404, detail="No restored callgraph is available for this repository")
    root_nodes = ga_trace_root_nodes_for_row(row, graph_nodes, limit=8)
    if not root_nodes:
        mapping = map_ga_rows_to_callgraph([row], owner_name, repo_name)
        root_nodes = [
            item.get("node")
            for item in mapping.get("matches", [])
            if item.get("node") in graph_nodes
        ][:8]
    if not root_nodes:
        raise HTTPException(status_code=404, detail="This GA row did not match any restored callgraph node")
    function_aliases = ga_function_aliases_for_row(row)
    route_roots = {
        route_node
        for function_alias in function_aliases
        for route_node in DASHBOARD_GA_FUNCTION_ROUTE_ALIASES.get(function_alias, ())
        if route_node in graph_nodes
    }
    if route_roots:
        trace_nodes, trace_edges = set(root_nodes), set()
    else:
        trace_nodes, trace_edges = walk_ga_event_context_trace(root_nodes, outgoing, incoming, max_depth=4, max_nodes=120)
    bridge_edges = set()
    bridge_roots = set(root_nodes)
    for function_alias in function_aliases:
        js_node = f"js.{function_alias}"
        trace_nodes.add(js_node)
        for root_node in bridge_roots:
            if str(root_node).startswith("static_"):
                bridge_edges.add((root_node, js_node))
        for route_node in DASHBOARD_GA_FUNCTION_ROUTE_ALIASES.get(function_alias, ()):
            if route_node in graph_nodes:
                trace_nodes.add(route_node)
                route_roots.add(route_node)
                bridge_edges.add((js_node, route_node))
    if route_roots:
        route_nodes, route_edges = walk_downstream_trace(sorted(route_roots), outgoing, max_depth=3, max_nodes=90)
        trace_nodes.update(route_nodes)
        trace_edges.update(route_edges)
    trace_edges.update(bridge_edges)
    label = ga_row_label(row)
    count = int(row.get("eventCount") or 0)
    row_hash = stable_text_id(json.dumps(row, sort_keys=True, default=str))[:10]
    ga_node = f"GA_row_{row_hash}_{html_ui_slug(label, 'event', max_len=32)}"
    nodes = sorted(set(trace_nodes) | {ga_node})
    edges = [
        (
            src,
            dst,
            edge_meta.get((src, dst), {}).get("order"),
            edge_meta.get((src, dst), {}).get("line"),
        )
        for src, dst in sorted(trace_edges)
    ]
    bridge_edge_labels = {
        f"{ga_node}->{root_node}": "maps to"
        for root_node in root_nodes
    }
    edges.extend((ga_node, root_node, None, None) for root_node in root_nodes)
    initial_visible_nodes, initial_visible_edges = ga_event_initial_one_hop_graph(
        root_nodes,
        ga_node,
        trace_nodes,
        outgoing,
        incoming,
        edges,
    )
    node_labels = dict(graph_node_labels)
    node_labels[ga_node] = f"GA action: {label} ({count})"
    for function_alias in ga_function_aliases_for_row(row):
        node_labels.setdefault(f"js.{function_alias}", f"Dashboard JS: {function_alias}")
    for node in root_nodes:
        node_labels.setdefault(node, str(graph_node_labels.get(node) or node))
    graph_url = build_navigatable_cytoscape_graph(
        nodes,
        edges,
        output_repo_dir,
        graph_name=f"ga_event_on_demand_{row_hash}",
        graph_title=f"GA Event Map: {label}",
        initial_roots=[ga_node],
        entry_points=[ga_node],
        node_labels=node_labels,
        initial_visible_nodes=initial_visible_nodes,
        initial_visible_edges=initial_visible_edges,
        edge_labels=bridge_edge_labels,
    )
    return {
        "graph_url": graph_url,
        "graph_json_url": graph_url[:-5] + ".json" if graph_url.endswith(".html") else "",
        "root_nodes": root_nodes,
        "label": label,
        "event_count": count,
    }


def refresh_scim_for_generated_graphs(output_repo_dir, owner_name: str, repo_name: str, graph_urls: list[str]):
    graph_paths = []
    for graph_url in graph_urls:
        if not graph_url or not graph_url.endswith(".html"):
            continue
        try:
            relative_html = graph_url.replace(f"{OUTPUT_URL_PREFIX}/", "", 1).replace("/output/", "", 1)
            graph_json = (BASE_OUTPUT / relative_html).with_suffix(".json")
            if graph_json.exists():
                graph_paths.append(graph_json)
        except Exception:
            continue
    if not graph_paths:
        return {}
    manifest_path = architecture_dir_for_output(output_repo_dir) / "manifest.json"
    latest_graph_mtime = max(path.stat().st_mtime for path in graph_paths)
    if manifest_path.exists() and manifest_path.stat().st_mtime >= latest_graph_mtime:
        return {}
    if manifest_path.exists() and (datetime.now().timestamp() - manifest_path.stat().st_mtime) < 240:
        return {}
    logger.info("Refreshing SCIM after generated graph update: %s", ", ".join(path.name for path in graph_paths))
    repo_text = load_repo_text_artifact(output_repo_dir)
    source_dir = find_cached_source_dir(output_repo_dir)
    if not source_dir:
        logger.warning("Skipping SCIM refresh after generated graph update: source directory not found for %s", output_repo_dir)
        return {"scim_error": "Source directory not found for generated graph refresh."}
    return build_scim_artifacts(
        output_repo_dir,
        owner_name,
        repo_name,
        {},
        "",
        repo_text,
        source_dir=source_dir,
    )


def build_scim_artifacts(
    output_repo_dir,
    owner="",
    repo="",
    repo_info=None,
    default_branch="",
    repo_text=None,
    source_dir=None,
    progress_callback=None,
    **_ignored,
):
    scim_enabled = os.getenv("ENABLE_SCIM", "true").lower() not in {"0", "false", "no", "off"}
    if not scim_enabled:
        return {}
    try:
        from scim import feature_catalog_payload, write_dataset
    except Exception as e:
        logger.warning("SCIM import failed; skipping embedding artifacts: %s", e)
        return {"scim_error": str(e)}


    output_dir = Path(output_repo_dir) / "scim"
    if repo_text is None:
        repo_text = load_repo_text_artifact(output_repo_dir)
    repo_context = build_repo_context(owner, repo, repo_info, default_branch, repo_text)

    resolved_source = source_dir or find_cached_source_dir(output_repo_dir)
    if not resolved_source:
        raise RuntimeError(
            "No repository source directory found. "
            "Refusing to index artifact/output directory."
        )
    source_root = Path(resolved_source).resolve()
    project_root = PROJECT_ROOT.resolve()
    if str(source_root).startswith(str(project_root)):
        raise RuntimeError(f"Refusing to index PROJECT_ROOT: {source_root}")

    evidence_result = {}

    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file or "")
        except TypeError:
            progress_callback(message)

    try:
        progress("Building search and feature artifacts from source files.", current_file="")
        logger.info("SCIM indexing source_root=%s", source_root)
        write_dataset(
            input_root=source_root,
            output_dir=output_dir,
            include_code=True,
            backend="tfidf",
            make_vector_db=True,
            make_faiss=False,
            sbert_model=None,
            batch_size=32,
            generic_graphs=True,
            max_chunks_per_repo=int(os.getenv("SCIM_MAX_CHUNKS_PER_REPO", "3000")),
            max_file_bytes=int(os.getenv("SCIM_MAX_FILE_BYTES", "300000")),
            max_record_code_chars=int(os.getenv("SCIM_MAX_RECORD_CODE_CHARS", "2000")),
            progress_callback=progress,
        )
        progress("Deriving product feature summaries from the search model.", current_file="")
        feature_data = feature_catalog_payload(output_dir, None, examples=5, repo_context=repo_context)
        architecture_dir = architecture_dir_for_output(output_repo_dir)
        feature_path = architecture_dir / "feature_catalog.json"
        feature_path.write_text(json.dumps(feature_data, indent=2), encoding="utf-8")
        progress("Skipping disabled static quality signal generation.", current_file="")
        quality_signal_path = ensure_static_quality_signals(output_repo_dir)
        progress("Writing generated evidence as architecture artifacts.", current_file="")
        evidence_result = index_typed_scim_evidence(output_repo_dir)
        layer_manifest_path = write_scim_layer_manifest(Path(output_repo_dir), evidence_result)
        callgraph_code_result = build_callgraph_code_index(output_repo_dir)
    except Exception as e:
        logger.warning("SCIM artifact build failed; search will fall back to graph search: %s", e)
        return {"scim_error": str(e)}

    logger.info("SCIM artifacts written: %s", output_dir)
    return {
        "scim_dir": str(output_dir),
        "scim_manifest_path": str(architecture_dir_for_output(output_repo_dir) / "manifest.json"),
        "scim_vector_db_path": str(output_dir / "vectors.sqlite"),
        "scim_embedding_model_path": str(output_dir / "embedding_model.json"),
        "scim_functions_path": str(output_dir / "functions.jsonl"),
        "scim_train_pairs_path": str(architecture_dir_for_output(output_repo_dir) / "train_pairs.jsonl"),
        "feature_catalog_path": str(architecture_dir_for_output(output_repo_dir) / "feature_catalog.json"),
        "typed_evidence_indexed": evidence_result.get("indexed", 0) if isinstance(evidence_result, dict) else 0,
        "scim_layer_manifest_path": layer_manifest_path,
        "callgraph_code_index_path": callgraph_code_result.get("path", "") if isinstance(callgraph_code_result, dict) else "",
        "callgraph_code_index_jsonl_path": callgraph_code_result.get("jsonl_path", "") if isinstance(callgraph_code_result, dict) else "",
        "callgraph_code_indexed": callgraph_code_result.get("indexed", 0) if isinstance(callgraph_code_result, dict) else 0,
        "static_quality_signals_path": quality_signal_path,
    }


def persist_ga_interactions(output_repo_dir, property_id: str, event_name: str, rows: list[dict], mapping: dict, graph_urls: dict):
    output_repo_dir = Path(output_repo_dir)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    raw_row_count = len(rows or [])
    deduped_rows = unique_ga_interaction_rows(rows or [])
    unique_row_count = len(deduped_rows)
    unique_rows, capped_row_count = limit_ga_interaction_rows(deduped_rows)
    ordered_rows = sorted(unique_rows, key=ga_row_sort_key)
    payload = {
        "generated_at": datetime.now().isoformat(),
        "property_id": property_id,
        "event_name": event_name or "all",
        "row_count": len(unique_rows),
        "raw_row_count": raw_row_count,
        "unique_row_count": unique_row_count,
        "duplicate_row_count": max(0, raw_row_count - unique_row_count),
        "capped_row_count": capped_row_count,
        "stored_event_limit": GA_STORED_EVENT_LIMIT,
        "dedupe_policy": "unique_by_event_identity_excluding_time_bucket_sum_eventCount",
        "retention_policy": "store_only_top_signal_deduped_events_errors_mapped_code_highest_counts",
        "rows": unique_rows,
        "ordered_rows": ordered_rows,
        "mapping": mapping or {},
        "graphs": graph_urls,
        "summary": [
            {
                "order": index,
                "button_name": row.get("customEvent:button_name") or row.get("button_name") or "",
                "function_name": row.get("customEvent:function_name") or row.get("function_name") or "",
                "callgraph_node": row.get("customEvent:callgraph_node") or row.get("callgraph_node") or "",
                "input_value": row.get("customEvent:input_value") or row.get("input_value") or "",
                "endpoint": row.get("customEvent:endpoint") or row.get("endpoint") or "",
                "method": row.get("customEvent:method") or row.get("method") or "",
                "trigger_element": row.get("customEvent:trigger_element") or row.get("trigger_element") or "",
                "error_message": row.get("customEvent:error_message") or row.get("error_message") or "",
                "ui_message": row.get("customEvent:ui_message") or row.get("ui_message") or "",
                "source_element": row.get("customEvent:source_element") or row.get("source_element") or "",
                "status": row.get("customEvent:status") or row.get("status") or "",
                "status_text": row.get("customEvent:status_text") or row.get("status_text") or "",
                "severity": row.get("customEvent:severity") or row.get("severity") or "",
                "event_count": row.get("eventCount") or 0,
                "time_bucket": row.get("dateHourMinute") or row.get("dateHour") or row.get("date") or "",
                "first_time_bucket": row.get("first_time_bucket") or "",
                "last_time_bucket": row.get("last_time_bucket") or "",
                "time_bucket_count": len(row.get("time_buckets") or []),
            }
            for index, row in enumerate(ordered_rows, start=1)
            if isinstance(row, dict)
        ],
    }
    path = output_repo_dir / "ga_interactions.json"
    path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    write_ga_user_actions_scim_document(output_repo_dir, payload)
    index_typed_scim_evidence(output_repo_dir)
    return path


def write_ga_user_actions_scim_document(output_repo_dir, payload: dict):
    """Write GA behavior as searchable source text so SCIM embeds observed user actions."""
    output_repo_dir = Path(output_repo_dir)
    generated_dir = output_repo_dir / "src" / "codeval_generated"
    generated_dir.mkdir(parents=True, exist_ok=True)
    path = generated_dir / "ga_user_actions.md"
    rows = [row for row in payload.get("summary", []) or [] if isinstance(row, dict)]
    lines = [
        "# Google Analytics user actions",
        "",
        "This generated artifact summarizes observed Google Analytics interactions for SCIM search.",
        f"Generated at: {payload.get('generated_at', '')}",
        f"Property: {payload.get('property_id', '')}",
        f"Event name: {payload.get('event_name', '')}",
        f"Rows: {len(rows)}",
        "",
    ]
    for row in rows:
        order = row.get("order") or ""
        button = row.get("button_name") or "Unknown action"
        function_name = row.get("function_name") or ""
        callgraph_node = row.get("callgraph_node") or ""
        endpoint = row.get("endpoint") or ""
        method = row.get("method") or ""
        trigger = row.get("trigger_element") or ""
        error_message = row.get("error_message") or row.get("ui_message") or ""
        source_element = row.get("source_element") or ""
        status = row.get("status") or ""
        status_text = row.get("status_text") or ""
        severity = row.get("severity") or ""
        input_value = row.get("input_value") or ""
        event_count = row.get("event_count") or 0
        time_bucket = row.get("time_bucket") or ""
        lines.extend([
            f"## GA step {order}: {button}",
            f"- Event count: {event_count}",
            f"- Time bucket: {time_bucket}",
            f"- Frontend function: {function_name}",
            f"- Callgraph node: {callgraph_node}",
            f"- Endpoint: {method} {endpoint}".strip(),
            f"- Trigger element: {trigger}",
            f"- UI error message: {error_message}",
            f"- Error source element: {source_element}",
            f"- Error status: {status} {status_text}".strip(),
            f"- Severity: {severity}",
            f"- Input value: {input_value}",
            "",
            f"Observed user action summary: users performed {button} {event_count} time(s). "
            f"This action maps to frontend function {function_name or 'unknown'} and callgraph node {callgraph_node or 'unknown'}"
            f"{f' and endpoint {method} {endpoint}' if endpoint else ''}.",
            f"Observed UI error summary: {error_message}" if error_message else "",
            "",
        ])
    path.write_text("\n".join(lines), encoding="utf-8")
    return path


# ============================================================
# Mixpanel activity integration (parallel workflow to Google Analytics).
# GA auth is per-browser-session OAuth with no natural persistence, so GA
# connection state lives in memory (GOOGLE_ANALYTICS_SESSIONS). Mixpanel uses
# static project/service-account credentials instead, which do need to
# persist across page loads, so those are stored in Supabase, encrypted.
# Loaded events are NOT stored in Supabase (GA doesn't do that either) -
# they're written as a generated markdown doc into src/codeval_generated/,
# the same mechanism GA uses so events become searchable/answerable
# alongside code through the existing /search pipeline.
# ============================================================

MIXPANEL_API_HOSTS = {
    "US": {"export": "https://data.mixpanel.com/api/2.0/export", "import": "https://api.mixpanel.com"},
    "EU": {"export": "https://data-eu.mixpanel.com/api/2.0/export", "import": "https://api-eu.mixpanel.com"},
}


def codeval_secret_encryption_key() -> bytes:
    """Shared symmetric key for at-rest encryption of third-party integration
    credentials (Mixpanel service account secret, Sentry auth token, etc.)."""
    secret = normalize_env_value(
        os.getenv("CODEVAL_SECRET_ENCRYPTION_KEY", "")
        or os.getenv("CODEVAL_MIXPANEL_SECRET_KEY", "")
        or search_restore_token_secret()
    )
    if not secret:
        raise HTTPException(
            status_code=503,
            detail="Secret storage is not configured. Set CODEVAL_SECRET_ENCRYPTION_KEY (or SECRET_KEY).",
        )
    return base64.urlsafe_b64encode(hashlib.sha256(secret.encode("utf-8")).digest())


def encrypt_secret(value: str) -> str:
    from cryptography.fernet import Fernet
    return Fernet(codeval_secret_encryption_key()).encrypt(str(value or "").encode("utf-8")).decode("ascii")


def decrypt_secret(token: str) -> str:
    from cryptography.fernet import Fernet
    try:
        return Fernet(codeval_secret_encryption_key()).decrypt(str(token or "").encode("ascii")).decode("utf-8")
    except Exception as e:
        raise HTTPException(status_code=401, detail=f"Stored secret could not be decrypted: {e}")


class MixpanelConnectRequest(BaseModel):
    owner_name: str = ""
    repo_name: str = ""
    project_id: str = ""
    project_token: str = ""
    service_account_username: str = ""
    service_account_secret: str = ""
    region: str = "US"


class MixpanelLoadActivityRequest(BaseModel):
    owner_name: str = ""
    repo_name: str = ""
    days: int = 7


def mixpanel_connection_row(owner_name: str, repo_name: str) -> dict:
    client = supabase_runtime_client()
    if not client:
        return {}
    response = supabase_execute(
        "fetch Mixpanel connection",
        lambda: client.table("codeval_mixpanel_connections")
        .select("*")
        .eq("owner_name", owner_name)
        .eq("repo_name", repo_name)
        .limit(1)
        .execute(),
    )
    rows = getattr(response, "data", None) or []
    return rows[0] if rows else {}


def mixpanel_export_request(connection: dict, from_date: str, to_date: str, limit: int = 0):
    region = str(connection.get("region") or "US").upper()
    host = MIXPANEL_API_HOSTS.get(region, MIXPANEL_API_HOSTS["US"])["export"]
    params = {"project_id": connection.get("project_id"), "from_date": from_date, "to_date": to_date}
    if limit:
        params["limit"] = limit
    secret = decrypt_secret(connection.get("encrypted_service_account_secret", ""))
    return requests.get(
        host,
        params=params,
        auth=(connection.get("service_account_username", ""), secret),
        timeout=120,
    )


@app.post("/mixpanel/connect")
def mixpanel_connect(req: MixpanelConnectRequest):
    owner_name = req.owner_name.strip()
    repo_name = req.repo_name.strip()
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    if not req.project_id.strip() or not req.project_token.strip():
        raise HTTPException(status_code=400, detail="Missing Mixpanel project id or project token")
    if not req.service_account_username.strip() or not req.service_account_secret.strip():
        raise HTTPException(status_code=400, detail="Missing Mixpanel service account credentials")
    region = req.region.strip().upper() if req.region.strip().upper() in MIXPANEL_API_HOSTS else "US"

    today = date.today()
    test_response = mixpanel_export_request(
        {
            "project_id": req.project_id.strip(),
            "region": region,
            "service_account_username": req.service_account_username.strip(),
            "encrypted_service_account_secret": encrypt_secret(req.service_account_secret.strip()),
        },
        (today - timedelta(days=1)).isoformat(),
        today.isoformat(),
        limit=1,
    )
    if test_response.status_code in (401, 403):
        raise HTTPException(status_code=test_response.status_code, detail=f"Mixpanel rejected the service account credentials: {test_response.text[:300]}")
    if test_response.status_code not in (200, 400):
        raise HTTPException(status_code=test_response.status_code, detail=test_response.text[:300])

    client = supabase_runtime_client()
    if not client:
        raise HTTPException(status_code=503, detail="Supabase is not configured, so the Mixpanel connection cannot be saved.")
    row = {
        "owner_name": owner_name,
        "repo_name": repo_name,
        "project_id": req.project_id.strip(),
        "project_token": req.project_token.strip(),
        "service_account_username": req.service_account_username.strip(),
        "encrypted_service_account_secret": encrypt_secret(req.service_account_secret.strip()),
        "region": region,
        "updated_at": datetime.now().isoformat(),
    }
    supabase_execute(
        "save Mixpanel connection",
        lambda: client.table("codeval_mixpanel_connections").upsert(row, on_conflict="owner_name,repo_name").execute(),
    )
    return {
        "ok": True,
        "source": "mixpanel",
        "owner_name": owner_name,
        "repo_name": repo_name,
        "project_id": req.project_id.strip(),
        "region": region,
        "message": "Mixpanel connected.",
    }


@app.get("/mixpanel/connection-status")
def mixpanel_connection_status(owner_name: str = "", repo_name: str = ""):
    if not owner_name or not repo_name:
        return {"connected": False}
    connection = mixpanel_connection_row(owner_name.strip(), repo_name.strip())
    if not connection:
        return {"connected": False}
    return {
        "connected": True,
        "project_id": connection.get("project_id", ""),
        "region": connection.get("region", "US"),
        "connected_at": connection.get("connected_at", ""),
    }


MIXPANEL_EVENT_PROPERTY_KEYS = [
    "button_name", "callgraph_node", "function_name", "file_path", "symbol_name",
    "input_value", "endpoint", "method", "request_url", "trigger_element",
    "error_message", "ui_message", "source_element", "source", "lineno", "colno",
    "stack", "top_frame", "stack_hash", "response_body", "status", "status_text", "severity",
    "page_path", "url", "repository_owner", "repository_name",
]


def normalize_mixpanel_event(raw: dict, owner_name: str, repo_name: str) -> dict:
    props = raw.get("properties") if isinstance(raw.get("properties"), dict) else {}
    event_time = props.get("time")
    normalized = {
        "source": "mixpanel",
        "event_name": raw.get("event") or "",
        "event_time": event_time,
        "eventCount": 1,
        "distinct_id": props.get("distinct_id") or "",
        "repository_owner": props.get("repository_owner") or owner_name,
        "repository_name": props.get("repository_name") or repo_name,
    }
    try:
        timestamp = int(event_time or 0)
        if timestamp > 10_000_000_000:
            timestamp = timestamp // 1000
        if timestamp > 0:
            normalized["dateHourMinute"] = datetime.fromtimestamp(timestamp).strftime("%Y%m%d%H%M")
    except Exception:
        pass
    for key in MIXPANEL_EVENT_PROPERTY_KEYS:
        if key not in normalized:
            normalized[key] = props.get(key, "")
    return normalized


def annotate_mixpanel_events_with_callgraph(events: list[dict], owner_name: str, repo_name: str) -> tuple[list[dict], dict]:
    mapping = map_ga_rows_to_callgraph(events, owner_name, repo_name)
    nodes = callgraph_nodes_for_mapping(owner_name, repo_name)
    lowered_nodes = [(node.lower(), node) for node in nodes]
    annotated = []
    for event in events or []:
        if not isinstance(event, dict):
            continue
        matched_nodes = ga_matching_nodes_for_row(event, lowered_nodes)[:8] if lowered_nodes else []
        annotated.append({
            **event,
            "mapped_callgraph_nodes": matched_nodes,
            "mapped_callgraph_node": matched_nodes[0] if matched_nodes else "",
        })
    return annotated, mapping


def write_mixpanel_user_actions_scim_document(output_repo_dir, events: list[dict]) -> Path:
    """Write Mixpanel activity as searchable source text, mirroring write_ga_user_actions_scim_document."""
    output_repo_dir = Path(output_repo_dir)
    generated_dir = output_repo_dir / "src" / "codeval_generated"
    generated_dir.mkdir(parents=True, exist_ok=True)
    path = generated_dir / "mixpanel_user_actions.md"
    lines = [
        "# Mixpanel user actions",
        "",
        "This generated artifact summarizes observed Mixpanel interactions for SCIM search.",
        f"Generated at: {datetime.now().isoformat()}",
        f"Rows: {len(events)}",
        "",
    ]
    for index, event in enumerate(events, start=1):
        button = event.get("button_name") or event.get("event_name") or "Unknown action"
        function_name = event.get("function_name") or ""
        mapped_nodes = event.get("mapped_callgraph_nodes") or []
        endpoint = event.get("endpoint") or ""
        method = event.get("method") or ""
        error_message = event.get("error_message") or event.get("ui_message") or ""
        lines.extend([
            f"## Mixpanel step {index}: {button}",
            f"- Event name: {event.get('event_name') or ''}",
            f"- Time: {event.get('event_time') or ''}",
            f"- Frontend function: {function_name}",
            f"- Mapped callgraph nodes: {', '.join(mapped_nodes)}",
            f"- Symbol: {event.get('symbol_name') or ''}",
            f"- File path: {event.get('file_path') or ''}",
            f"- Endpoint: {method} {endpoint}".strip(),
            f"- Page path: {event.get('page_path') or ''}",
            f"- UI error message: {error_message}",
            f"- Stack top frame: {event.get('top_frame') or ''}",
            "",
            f"Observed user action summary: users performed {button}. "
            f"This action maps to frontend function {function_name or 'unknown'}"
            f"{f' and callgraph node {mapped_nodes[0]}' if mapped_nodes else ''}"
            f"{f' and endpoint {method} {endpoint}' if endpoint else ''}.",
            f"Observed UI error summary: {error_message}" if error_message else "",
            "",
        ])
    path.write_text("\n".join(lines), encoding="utf-8")
    return path


def persist_mixpanel_interactions(output_repo_dir, events: list[dict], mapping: dict | None = None, graph_urls: dict | None = None) -> Path:
    output_repo_dir = Path(output_repo_dir)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    payload = {
        "generated_at": datetime.now().isoformat(),
        "source": "mixpanel",
        "row_count": len(events),
        "events": events,
        "mapping": mapping or {},
        "graphs": graph_urls or {},
    }
    path = output_repo_dir / "mixpanel_interactions.json"
    path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    write_mixpanel_user_actions_scim_document(output_repo_dir, events)
    index_typed_scim_evidence(output_repo_dir)
    return path


@app.post("/mixpanel/load-user-activity")
def mixpanel_load_user_activity(req: MixpanelLoadActivityRequest):
    owner_name = req.owner_name.strip()
    repo_name = req.repo_name.strip()
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    connection = mixpanel_connection_row(owner_name, repo_name)
    if not connection:
        raise HTTPException(status_code=404, detail="Mixpanel is not connected for this repository. Connect Mixpanel first.")

    days = max(1, min(int(req.days or 7), 90))
    to_date = date.today()
    from_date = to_date - timedelta(days=days)
    response = mixpanel_export_request(connection, from_date.isoformat(), to_date.isoformat())
    if response.status_code != 200:
        raise HTTPException(status_code=response.status_code, detail=response.text[:500])

    events = []
    for line in response.text.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            raw_event = json.loads(line)
        except ValueError:
            continue
        events.append(normalize_mixpanel_event(raw_event, owner_name, repo_name))

    output_repo_dir = repo_output_dir(owner_name, repo_name)
    events, mapping = annotate_mixpanel_events_with_callgraph(events, owner_name, repo_name)
    mapped_graph_rows = [event for event in events if event.get("mapped_callgraph_nodes")]
    latest_first = sorted(
        mapped_graph_rows or events,
        key=lambda event: int(event.get("event_time") or 0),
        reverse=True,
    )
    graph_rows = latest_first[:1]
    mixpanel_graph_url = ""
    mixpanel_ordered_graph_url = ""
    mixpanel_event_callgraph_map_url = ""
    if owner_name and repo_name and graph_rows:
        mixpanel_graph_url, mapping = build_ga_analysis_graph(owner_name, repo_name, graph_rows)
        mixpanel_ordered_graph_url = build_ga_ordered_interaction_graph(owner_name, repo_name, graph_rows)
        mixpanel_event_callgraph_map_url = build_ga_event_callgraph_map(owner_name, repo_name, graph_rows, mapping)
    graph_urls = {
        "mixpanel_analysis_graph_url": mixpanel_graph_url,
        "mixpanel_ordered_graph_url": mixpanel_ordered_graph_url,
        "mixpanel_event_callgraph_map_url": mixpanel_event_callgraph_map_url,
    }
    persist_mixpanel_interactions(output_repo_dir, events, mapping, graph_urls)
    if mixpanel_graph_url or mixpanel_ordered_graph_url or mixpanel_event_callgraph_map_url:
        refresh_scim_for_generated_graphs(
            output_repo_dir,
            owner_name,
            repo_name,
            [mixpanel_graph_url, mixpanel_ordered_graph_url, mixpanel_event_callgraph_map_url],
        )

    return {
        "ok": True,
        "source": "mixpanel",
        "owner_name": owner_name,
        "repo_name": repo_name,
        "days": days,
        "row_count": len(events),
        "rows": events[:200],
        "mapping": mapping,
        "mapped_callgraph_nodes": mapping.get("matches", [])[:100],
        "mixpanel_analysis_graph_url": mixpanel_graph_url,
        "mixpanel_analysis_graph_json_url": mixpanel_graph_url[:-5] + ".json" if mixpanel_graph_url.endswith(".html") else "",
        "mixpanel_ordered_graph_url": mixpanel_ordered_graph_url,
        "mixpanel_ordered_graph_json_url": mixpanel_ordered_graph_url[:-5] + ".json" if mixpanel_ordered_graph_url.endswith(".html") else "",
        "mixpanel_event_callgraph_map_url": mixpanel_event_callgraph_map_url,
        "mixpanel_event_callgraph_map_json_url": mixpanel_event_callgraph_map_url[:-5] + ".json" if mixpanel_event_callgraph_map_url.endswith(".html") else "",
        "message": f"Loaded {len(events)} Mixpanel events from the last {days} days.",
    }


# ============================================================
# Sentry production error integration.
# Unlike GA/Mixpanel custom event properties, Sentry stack frames are exact
# (filename, line, function), so errors are stored as real rows in
# codeval_analytics_events and matched deterministically against the SCIM
# function index + callgraph, instead of going through semantic search.
# ============================================================

class SentryConnectRequest(BaseModel):
    repo_url: str = ""
    repository_owner: str = ""
    repository_name: str = ""
    organization_slug: str = ""
    project_slug: str = ""
    auth_token: str = ""
    environment: str = "production"


class SentryLoadErrorsRequest(BaseModel):
    repo_url: str = ""
    repository_owner: str = ""
    repository_name: str = ""
    days: int = 7


class MapActivityToCodeRequest(BaseModel):
    repo_url: str = ""
    repository_owner: str = ""
    repository_name: str = ""
    source: str = "sentry"


def sentry_connection_row(owner_name: str, repo_name: str) -> dict:
    client = supabase_runtime_client()
    if not client:
        return {}
    response = supabase_execute(
        "fetch Sentry connection",
        lambda: client.table("codeval_sentry_connections")
        .select("*")
        .eq("owner_name", owner_name)
        .eq("repo_name", repo_name)
        .limit(1)
        .execute(),
    )
    rows = getattr(response, "data", None) or []
    return rows[0] if rows else {}


def sentry_headers(auth_token: str) -> dict:
    return {"Authorization": f"Bearer {auth_token}", "Accept": "application/json"}


@app.post("/sentry/connect")
def sentry_connect(req: SentryConnectRequest):
    owner_name = req.repository_owner.strip()
    repo_name = req.repository_name.strip()
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="repository_owner and repository_name are required")
    org_slug = req.organization_slug.strip()
    project_slug = req.project_slug.strip()
    auth_token = req.auth_token.strip()
    if not org_slug or not project_slug or not auth_token:
        raise HTTPException(status_code=400, detail="Missing Sentry organization slug, project slug, or auth token")
    environment = req.environment.strip() or "production"

    test_response = requests.get(
        f"https://sentry.io/api/0/projects/{org_slug}/{project_slug}/",
        headers=sentry_headers(auth_token),
        timeout=30,
    )
    if test_response.status_code in (401, 403):
        raise HTTPException(status_code=test_response.status_code, detail=f"Sentry rejected the auth token: {test_response.text[:300]}")
    if test_response.status_code == 404:
        raise HTTPException(status_code=404, detail=f"Sentry project {org_slug}/{project_slug} was not found or this token cannot access it.")
    if test_response.status_code != 200:
        raise HTTPException(status_code=test_response.status_code, detail=test_response.text[:300])

    client = supabase_runtime_client()
    if not client:
        raise HTTPException(status_code=503, detail="Supabase is not configured, so the Sentry connection cannot be saved.")
    row = {
        "owner_name": owner_name,
        "repo_name": repo_name,
        "organization_slug": org_slug,
        "project_slug": project_slug,
        "encrypted_auth_token": encrypt_secret(auth_token),
        "environment": environment,
        "updated_at": datetime.now().isoformat(),
    }
    supabase_execute(
        "save Sentry connection",
        lambda: client.table("codeval_sentry_connections").upsert(row, on_conflict="owner_name,repo_name").execute(),
    )
    return {
        "ok": True,
        "source": "sentry",
        "repository_owner": owner_name,
        "repository_name": repo_name,
        "organization_slug": org_slug,
        "project_slug": project_slug,
        "environment": environment,
        "message": "Sentry connected.",
    }


def sentry_issue_event_frames(org_slug: str, issue_id: str, auth_token: str) -> list[dict]:
    """Fetch the latest event for an issue and return its exception stack frames,
    ordered most-relevant-first (Sentry returns frames oldest -> newest; the
    crash site is the last frame, and in_app frames are more likely to be
    the user's own code than library frames)."""
    try:
        response = requests.get(
            f"https://sentry.io/api/0/organizations/{org_slug}/issues/{issue_id}/events/latest/",
            headers=sentry_headers(auth_token),
            timeout=30,
        )
    except requests.RequestException:
        return []
    if response.status_code != 200:
        return []
    try:
        payload = response.json()
    except ValueError:
        return []
    frames = []
    for entry in payload.get("entries", []) or []:
        if entry.get("type") != "exception":
            continue
        for value in (entry.get("data") or {}).get("values", []) or []:
            frames.extend((value.get("stacktrace") or {}).get("frames", []) or [])
    frames = list(reversed(frames))
    in_app = [f for f in frames if f.get("inApp") or f.get("in_app")]
    other = [f for f in frames if f not in in_app]
    return in_app + other


def normalize_sentry_issue(issue: dict, frames: list[dict], environment: str) -> dict:
    metadata = issue.get("metadata") or {}
    top_frame = frames[0] if frames else {}
    return {
        "source": "sentry",
        "event_name": issue.get("title") or metadata.get("type") or "",
        "issue_id": str(issue.get("id") or ""),
        "message": metadata.get("value") or issue.get("culprit") or issue.get("title") or "",
        "culprit": issue.get("culprit") or "",
        "filename": top_frame.get("filename") or metadata.get("filename") or "",
        "abs_path": top_frame.get("absPath") or top_frame.get("abs_path") or "",
        "function_name": top_frame.get("function") or metadata.get("function") or "",
        "lineno": top_frame.get("lineNo") or top_frame.get("lineno"),
        "colno": top_frame.get("colNo") or top_frame.get("colno"),
        "environment": environment,
        "release": (issue.get("lastRelease") or {}).get("version") or "",
        "severity": issue.get("level") or "",
        "stack_frames": frames,
        "event_time": issue.get("lastSeen") or "",
        "raw_event": issue,
    }


@app.post("/sentry/load-errors")
def sentry_load_errors(req: SentryLoadErrorsRequest):
    owner_name = req.repository_owner.strip()
    repo_name = req.repository_name.strip()
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="repository_owner and repository_name are required")
    connection = sentry_connection_row(owner_name, repo_name)
    if not connection:
        raise HTTPException(status_code=404, detail="Sentry is not connected for this repository. Connect Sentry first.")

    days = max(1, min(int(req.days or 7), 90))
    org_slug = connection.get("organization_slug", "")
    project_slug = connection.get("project_slug", "")
    environment = connection.get("environment") or "production"
    auth_token = decrypt_secret(connection.get("encrypted_auth_token", ""))

    response = requests.get(
        f"https://sentry.io/api/0/projects/{org_slug}/{project_slug}/issues/",
        headers=sentry_headers(auth_token),
        params={
            "statsPeriod": f"{days}d",
            "query": f"is:unresolved environment:{environment}" if environment else "is:unresolved",
            "limit": 25,
        },
        timeout=60,
    )
    if response.status_code != 200:
        raise HTTPException(status_code=response.status_code, detail=response.text[:500])
    issues = response.json() if response.content else []
    if not isinstance(issues, list):
        issues = []

    events = []
    for issue in issues:
        issue_id = str(issue.get("id") or "")
        frames = sentry_issue_event_frames(org_slug, issue_id, auth_token) if issue_id else []
        events.append(normalize_sentry_issue(issue, frames, environment))

    client = supabase_runtime_client()
    if client and events:
        rows = [
            {
                "source": event["source"],
                "owner_name": owner_name,
                "repo_name": repo_name,
                "event_name": event["event_name"],
                "issue_id": event["issue_id"],
                "message": event["message"],
                "culprit": event["culprit"],
                "filename": event["filename"],
                "abs_path": event["abs_path"],
                "function_name": event["function_name"],
                "lineno": event["lineno"],
                "colno": event["colno"],
                "environment": event["environment"],
                "release": event["release"],
                "severity": event["severity"],
                "stack_frames": event["stack_frames"],
                "raw_event": event["raw_event"],
                "event_time": event["event_time"] or None,
                "mapped": False,
            }
            for event in events
        ]
        supabase_execute(
            "save Sentry events",
            lambda: client.table("codeval_analytics_events")
            .upsert(rows, on_conflict="issue_id")
            .execute(),
        )

    return {
        "ok": True,
        "source": "sentry",
        "repository_owner": owner_name,
        "repository_name": repo_name,
        "days": days,
        "row_count": len(events),
        "rows": events,
        "message": f"Loaded {len(events)} Sentry issues from the last {days} days.",
    }


def sentry_match_event_to_code(event: dict, function_records: dict, callgraph_nodes: set):
    """Match by filename/abs_path first, then function_name, walking the stack
    frames if the top frame doesn't resolve to anything in the index."""
    candidate_frames = [{"filename": event.get("filename"), "abs_path": event.get("abs_path"), "function": event.get("function_name")}]
    candidate_frames.extend(event.get("stack_frames") or [])

    for frame in candidate_frames:
        filename = str(frame.get("filename") or frame.get("absPath") or frame.get("abs_path") or "").replace("\\", "/").lstrip("/")
        if filename:
            filename_lower = filename.lower()
            base_name = filename_lower.rsplit("/", 1)[-1]
            for symbol, record in function_records.items():
                path = record_source_path(record).lower()
                if not path:
                    continue
                if path == filename_lower or path.endswith("/" + filename_lower) or path.endswith(filename_lower):
                    return symbol, record, "filename"
            for symbol, record in function_records.items():
                path = record_source_path(record).lower()
                if path and path.rsplit("/", 1)[-1] == base_name:
                    return symbol, record, "filename_basename"

    for frame in candidate_frames:
        function_name = str(frame.get("function") or frame.get("function_name") or "").strip()
        if not function_name:
            continue
        target_lower = function_name.lower()
        for symbol, record in function_records.items():
            if _callgraph_symbol_matches(symbol, target_lower, target_lower):
                return symbol, record, "function_name"
        resolved = resolve_unused_callgraph_symbol(function_name, callgraph_nodes)
        if resolved:
            return resolved, function_records.get(resolved, {}), "callgraph_symbol"

    return "", {}, ""


@app.post("/analytics/map-activity-to-code")
def analytics_map_activity_to_code(req: MapActivityToCodeRequest):
    owner_name = req.repository_owner.strip()
    repo_name = req.repository_name.strip()
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="repository_owner and repository_name are required")
    source = req.source.strip() or "sentry"

    client = supabase_runtime_client()
    if not client:
        raise HTTPException(status_code=503, detail="Supabase is not configured, so analytics events cannot be loaded.")
    response = supabase_execute(
        "load analytics events for mapping",
        lambda: client.table("codeval_analytics_events")
        .select("*")
        .eq("owner_name", owner_name)
        .eq("repo_name", repo_name)
        .eq("source", source)
        .order("event_time", desc=True)
        .limit(50)
        .execute(),
    )
    events = getattr(response, "data", None) or []
    if not events:
        return {"ok": True, "source": source, "repository_owner": owner_name, "repository_name": repo_name, "matched": [], "unmatched_count": 0, "message": f"No {source} events loaded yet for this repository. Use Load Production Errors first."}

    output_repo_dir = repo_output_dir(owner_name, repo_name)
    artifact_root = artifact_root_for_output(output_repo_dir)
    functions_path = find_scim_functions_path(output_repo_dir)
    function_records = load_scim_function_records(functions_path.parent) if functions_path else {}
    nodes, edges, incoming, outgoing, edge_meta, graph_sources = collect_quality_callgraph(artifact_root)

    matched = []
    unmatched = 0
    for event in events:
        symbol, record, match_kind = sentry_match_event_to_code(event, function_records, nodes)
        if not symbol:
            unmatched += 1
            continue
        callers = sorted(incoming.get(symbol, []))[:8]
        callees = sorted(outgoing.get(symbol, []))[:8]
        matched.append({
            "issue_id": event.get("issue_id"),
            "event_name": event.get("event_name"),
            "message": event.get("message"),
            "matched_symbol": symbol,
            "matched_path": record_source_path(record),
            "matched_line": record.get("start_line") or record.get("line"),
            "match_kind": match_kind,
            "callers": callers,
            "callees": callees,
        })

    if matched:
        matched_issue_ids = [item["issue_id"] for item in matched if item.get("issue_id")]
        if matched_issue_ids:
            supabase_execute(
                "mark analytics events mapped",
                lambda: client.table("codeval_analytics_events")
                .update({"mapped": True})
                .in_("issue_id", matched_issue_ids)
                .execute(),
            )

    return {
        "ok": True,
        "source": source,
        "repository_owner": owner_name,
        "repository_name": repo_name,
        "matched_count": len(matched),
        "unmatched_count": unmatched,
        "matched": matched,
        "message": f"Matched {len(matched)} of {len(events)} {source} events to code.",
    }










def scim_evidence_ids_from_payload(results=None, retrieval_context=None, text_results=None):
    ids = []
    for item in results or []:
        symbol = item.get("symbol") or item.get("fullName") or item.get("name") or ""
        source_type = item.get("source_type") or "code_function"
        if symbol:
            ids.append(f"{source_type}:{symbol}")
    for unit in (retrieval_context or {}).get("code_units", []) or []:
        symbol = unit.get("symbol") or ""
        role = unit.get("role") or "context"
        if symbol:
            ids.append(f"{role}:{symbol}")
    for item in text_results or []:
        file_name = item.get("file") or ""
        line = item.get("line") or ""
        kind = item.get("kind") or "text"
        if file_name:
            ids.append(f"{kind}:{file_name}:{line}")
    return list(dict.fromkeys(ids))


def derived_answer_confidence(answer: str, evidence_ids: list[str], retrieval_plan: Optional[dict] = None):
    answer_text = str(answer or "")
    if not answer_text or search_answer_is_error(answer_text):
        return 0.0
    score = 0.35
    if evidence_ids:
        score += min(0.35, len(evidence_ids) * 0.04)
    if any(prefix in " ".join(evidence_ids) for prefix in ("ga_summary:", "ga_event:", "ga_trace:", "code_function:", "callgraph_summary:", "feature_summary:", "repo_overview:")):
        score += 0.15
    if retrieval_plan and retrieval_plan.get("intents"):
        score += 0.05
    if re.search(r"\b(not available|no information|cannot be reconstructed|unknown)\b", answer_text, re.IGNORECASE):
        score -= 0.15
    return max(0.0, min(1.0, round(score, 3)))


def search_answer_is_error(answer: str) -> bool:
    answer_text = str(answer or "").strip()
    return (
        not answer_text
        or answer_text.startswith("Error generating search answer")
        or answer_text.startswith("Search answer generation timed out")
    )


def derived_memory_paths(output_repo_dir: Path):
    artifact_root = artifact_root_for_output(output_repo_dir)
    memory_dir = architecture_dir_for_output(artifact_root) / "derived_memory"
    memory_dir.mkdir(parents=True, exist_ok=True)
    return memory_dir, memory_dir / "answers.jsonl", memory_dir / "feedback.jsonl"


def store_derived_answer_memory(output_repo_dir, payload: dict, answer: str, prompt: str):
    output_repo_path = Path(output_repo_dir)
    memory_dir, answers_path, _ = derived_memory_paths(output_repo_path)
    retrieval_plan = payload.get("retrieval_plan") or plan_scim_retrieval(payload.get("query", ""))
    evidence_ids = payload.get("retrieved_evidence_ids") or scim_evidence_ids_from_payload(
        payload.get("results") or [],
        payload.get("retrieval_context") or {},
        payload.get("text_results") or [],
    )
    confidence = float(payload.get("confidence") or derived_answer_confidence(answer, evidence_ids, retrieval_plan))
    record_id = stable_text_id(f"{payload.get('query', '')}\n{answer}\n{datetime.now().isoformat()}")
    record = {
        "id": record_id,
        "created_at": datetime.now().isoformat(),
        "query": payload.get("query", ""),
        "intent": payload.get("intent") or retrieval_plan.get("intents", []),
        "retrieval_plan": retrieval_plan,
        "retrieved_evidence_ids": evidence_ids,
        "answer": answer,
        "prompt_chars": len(prompt or ""),
        "confidence": confidence,
        "user_feedback": payload.get("user_feedback") or "",
        "approved": bool(payload.get("approved", False)),
        "source": "llm_search_answer",
        "truth_status": "derived_not_original_truth",
    }
    with answers_path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(record, ensure_ascii=False) + "\n")
    indexed = {}
    if should_index_derived_answer(record):
        indexed = index_derived_answer_memory(output_repo_path, [record])
    generated_store = {}
    try:
        generated_store = store_generated_answer_overlay(output_repo_path, payload, answer, prompt, record)
    except Exception as e:
        logger.warning("Unable to store generated answer overlay: %s", e)
        generated_store = {"error": str(e)}
    return {**record, "memory_path": str(answers_path), "indexed": indexed, "generated_store": generated_store}


def should_index_derived_answer(record: dict):
    if record.get("approved"):
        return bool(record.get("retrieved_evidence_ids"))
    return float(record.get("confidence") or 0) >= float(os.getenv("SCIM_DERIVED_MEMORY_MIN_CONFIDENCE", "0.78")) and bool(record.get("retrieved_evidence_ids"))


def index_derived_answer_memory(output_repo_dir, records: Optional[list[dict]] = None):
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    scim_dir = artifact_root / "scim"
    vector_db_path = scim_dir / "vectors.sqlite"
    if not vector_db_path.exists():
        return {"indexed": 0, "reason": "SCIM vector index is not available yet"}
    if records is None:
        _, answers_path, _ = derived_memory_paths(artifact_root)
        records = []
        if answers_path.exists():
            for line in answers_path.read_text(encoding="utf-8").splitlines():
                try:
                    item = json.loads(line)
                except Exception:
                    continue
                if should_index_derived_answer(item):
                    records.append(item)
    with sqlite3.connect(vector_db_path) as connection:
        connection.execute("DELETE FROM vectors WHERE json_extract(metadata, '$.is_derived_memory') = 1")
        connection.commit()
    return {
        "indexed": 0,
        "records": len(records or []),
        "note": "Derived answer memory is saved under architecture/derived_memory only; it is not embedded into scim/vectors.sqlite.",
    }


GENERATED_STORE_VERSION = 1


def generated_store_paths(output_repo_dir: Path):
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    architecture_dir = architecture_dir_for_output(artifact_root)
    docs_dir = artifact_root / "docs"
    architecture_dir.mkdir(parents=True, exist_ok=True)
    docs_dir.mkdir(parents=True, exist_ok=True)
    return {
        "function_summaries": architecture_dir / "function_summaries.sqlite",
        "knowledge": architecture_dir / "knowledge.sqlite",
        "docs": docs_dir / "docs.sqlite",
    }


def configured_top_function_summary_limit() -> int:
    raw = os.getenv("SUMMARIZE_N", os.getenv("FUNCTION_SUMMARIZE_N", "0"))
    try:
        return max(0, min(int(raw or 0), 100))
    except (TypeError, ValueError):
        return 0


def local_text_embedding_blob(text: str) -> bytes:
    try:
        from scim import CODE_DIM, hashed_embedding, tokenize_code, vector_to_blob

        return vector_to_blob(hashed_embedding(tokenize_code(str(text or "")), CODE_DIM, "derived"))
    except Exception:
        return b""


def init_function_summaries_db(path: Path) -> sqlite3.Connection:
    path.parent.mkdir(parents=True, exist_ok=True)
    connection = sqlite3.connect(path)
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS function_summaries (
            id TEXT PRIMARY KEY,
            chunk_id TEXT,
            repo_id TEXT,
            symbol TEXT NOT NULL,
            path TEXT,
            start_line INTEGER,
            end_line INTEGER,
            summary_text TEXT NOT NULL,
            summary_embedding BLOB,
            summary_type TEXT,
            prompt_hash TEXT,
            evidence_ids TEXT,
            model TEXT,
            created_at TEXT NOT NULL,
            updated_at TEXT NOT NULL,
            truth_status TEXT NOT NULL DEFAULT 'derived_not_original_truth',
            metadata TEXT NOT NULL DEFAULT '{}'
        )
        """
    )
    connection.execute("CREATE INDEX IF NOT EXISTS idx_function_summaries_symbol ON function_summaries(symbol)")
    connection.execute("CREATE INDEX IF NOT EXISTS idx_function_summaries_chunk ON function_summaries(chunk_id)")
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS store_metadata (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("policy", "Generated function summaries only. Source code embeddings stay in scim/vectors.sqlite."),
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("version", str(GENERATED_STORE_VERSION)),
    )
    return connection


def init_knowledge_db(path: Path) -> sqlite3.Connection:
    path.parent.mkdir(parents=True, exist_ok=True)
    connection = sqlite3.connect(path)
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS knowledge (
            id TEXT PRIMARY KEY,
            query TEXT,
            answer_text TEXT NOT NULL,
            answer_embedding BLOB,
            knowledge_type TEXT NOT NULL,
            prompt_hash TEXT,
            evidence_ids TEXT,
            model TEXT,
            created_at TEXT NOT NULL,
            truth_status TEXT NOT NULL DEFAULT 'derived_not_original_truth',
            metadata TEXT NOT NULL DEFAULT '{}'
        )
        """
    )
    connection.execute("CREATE INDEX IF NOT EXISTS idx_knowledge_type ON knowledge(knowledge_type)")
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS store_metadata (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("policy", "Generated knowledge only. Do not treat rows as source truth."),
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("version", str(GENERATED_STORE_VERSION)),
    )
    return connection


def init_docs_db(path: Path) -> sqlite3.Connection:
    path.parent.mkdir(parents=True, exist_ok=True)
    connection = sqlite3.connect(path)
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS documents (
            id TEXT PRIMARY KEY,
            source_type TEXT NOT NULL,
            path TEXT NOT NULL,
            line INTEGER,
            text TEXT NOT NULL,
            embedding BLOB,
            metadata TEXT NOT NULL DEFAULT '{}',
            created_at TEXT NOT NULL,
            truth_status TEXT NOT NULL DEFAULT 'original_source_truth'
        )
        """
    )
    connection.execute("CREATE INDEX IF NOT EXISTS idx_docs_path ON documents(path)")
    connection.execute("CREATE INDEX IF NOT EXISTS idx_docs_source_type ON documents(source_type)")
    connection.execute(
        """
        CREATE TABLE IF NOT EXISTS store_metadata (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("policy", "Original documentation/config/comment text only. No generated LLM answers."),
    )
    connection.execute(
        "INSERT OR REPLACE INTO store_metadata(key, value) VALUES (?, ?)",
        ("version", str(GENERATED_STORE_VERSION)),
    )
    return connection


def build_docs_sqlite_from_repo_text(output_repo_dir, repo_text: dict | None = None):
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    if repo_text is None:
        repo_text = load_repo_text_artifact(artifact_root)
    if not isinstance(repo_text, dict):
        return {"indexed": 0, "reason": "repo_text is unavailable"}
    docs_path = generated_store_paths(artifact_root)["docs"]
    now = datetime.now().isoformat()
    rows = []
    for source_key, source_type in (
        ("readme_items", "readme"),
        ("document_items", "document"),
        ("text_items", "file_text_or_comment"),
        ("ui_text_items", "ui_text"),
    ):
        for item in repo_text.get(source_key) or []:
            if not isinstance(item, dict):
                continue
            text = str(item.get("text") or "").strip()
            path = str(item.get("file") or "").strip()
            if not text or not path:
                continue
            line = int(item.get("line") or 1)
            row_id = stable_text_id(f"{source_type}:{path}:{line}:{text[:200]}")
            rows.append((
                row_id,
                source_type,
                path,
                line,
                text,
                local_text_embedding_blob(text),
                json.dumps({key: value for key, value in item.items() if key not in {"text"}}, ensure_ascii=False),
                now,
                "original_source_truth",
            ))
    connection = init_docs_db(docs_path)
    with connection:
        connection.execute("DELETE FROM documents")
        connection.executemany(
            """
            INSERT OR REPLACE INTO documents
            (id, source_type, path, line, text, embedding, metadata, created_at, truth_status)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            rows,
        )
    connection.close()
    return {"indexed": len(rows), "path": str(docs_path)}


def answer_summary_type(payload: dict, answer: str = "") -> str:
    query = str((payload or {}).get("query") or "").lower()
    intents = " ".join(str(item) for item in ((payload or {}).get("retrieval_plan") or {}).get("intents", [])).lower()
    text = f"{query} {intents} {str(answer or '').lower()[:500]}"
    if any(term in text for term in ("flow", "sequence", "call path", "execution")):
        return "flow"
    if any(term in text for term in ("risk", "bug", "issue", "fix", "self heal")):
        return "analysis"
    return "description"


def function_record_from_payload(output_repo_dir, payload: dict) -> dict:
    results = (payload or {}).get("results") or []
    query = str((payload or {}).get("query") or "")
    target_terms = search_call_targets(query)
    query_terms = search_query_terms(query)
    candidates = []
    for item in results:
        if not isinstance(item, dict):
            continue
        source_type = str(item.get("source_type") or "code_function")
        symbol = str(item.get("symbol") or item.get("fullName") or "")
        if not symbol or source_type not in {"code_function", "function", "method", "class"}:
            continue
        tail = symbol_tail(symbol)
        score = 0
        if item.get("match_source") == "exact function target":
            score += 100
        if target_terms and any(term == tail or term in symbol.lower() for term in target_terms):
            score += 80
        if query_terms and any(term == tail or term in symbol.lower() for term in query_terms):
            score += 30
        if query_terms and any(term in f"{symbol} {item.get('path') or ''}".lower() for term in query_terms):
            score += 50
        score += int(item.get("text_score") or 0)
        score += int(float(item.get("score") or 0) * 10)
        candidates.append((score, item))
    if not candidates and target_terms:
        for unit in ((payload or {}).get("retrieval_context") or {}).get("code_units", []) or []:
            if isinstance(unit, dict) and unit.get("symbol"):
                tail = symbol_tail(unit.get("symbol") or "")
                if any(term == tail or term in str(unit.get("symbol") or "").lower() for term in target_terms):
                    candidates.append((80, unit))
    if not candidates:
        evidence_ids = (payload or {}).get("retrieved_evidence_ids") or []
        for evidence_id in evidence_ids:
            text = str(evidence_id or "")
            if not text.startswith("code_function:"):
                continue
            symbol = text.split(":", 1)[1].strip()
            if symbol:
                candidates.append((80, {"symbol": symbol, "source_type": "code_function"}))
                break
    if not candidates:
        return {}
    best_score, best = sorted(candidates, key=lambda pair: pair[0], reverse=True)[0]
    if best_score < 80:
        return {}
    symbol = str(best.get("symbol") or best.get("fullName") or "")
    dataset_dir = artifact_root_for_output(Path(output_repo_dir)) / "scim"
    record = {}
    try:
        record = load_scim_function_record_subset(dataset_dir, [symbol]).get(symbol, {})
    except Exception:
        record = {}
    return {
        "chunk_id": record.get("chunk_id") or best.get("chunk_id") or "",
        "repo_id": record.get("repo_id") or best.get("repo_id") or "",
        "symbol": symbol,
        "path": record.get("path") or best.get("path") or "",
        "start_line": int(record.get("start_line") or best.get("start_line") or 0) or None,
        "end_line": int(record.get("end_line") or best.get("end_line") or 0) or None,
        "metadata": {"match_source": best.get("match_source") or "", "source_type": best.get("source_type") or "code_function"},
    }


def payload_has_doc_evidence(payload: dict) -> bool:
    evidence = " ".join(str(item) for item in (payload or {}).get("retrieved_evidence_ids") or [])
    if any(token in evidence.lower() for token in ("readme", "document", "source text", "source_text", "file_text", "docs/", ".md", ".rst", ".adoc")):
        return True
    for item in (payload or {}).get("text_results") or []:
        kind = str(item.get("kind") or "").lower()
        file_name = str(item.get("file") or "").lower()
        if kind or file_name.endswith((".md", ".markdown", ".mdx", ".rst", ".adoc", ".txt", ".yaml", ".yml", ".json", ".xml")):
            return True
    return False


def store_generated_answer_overlay(output_repo_dir, payload: dict, answer: str, prompt: str, record: dict):
    paths = generated_store_paths(Path(output_repo_dir))
    now = record.get("created_at") or datetime.now().isoformat()
    prompt_hash = stable_text_id(prompt or "")
    evidence_ids = record.get("retrieved_evidence_ids") or []
    function_record = function_record_from_payload(output_repo_dir, payload)
    model = os.getenv("OPENAI_SEARCH_MODEL", os.getenv("OPENAI_SUMMARY_MODEL", "gpt-4o-mini"))
    if function_record.get("symbol"):
        summary_id = stable_text_id(f"{function_record.get('chunk_id') or function_record.get('symbol')}:{answer}:{now}")
        connection = init_function_summaries_db(paths["function_summaries"])
        with connection:
            connection.execute(
                """
                INSERT OR REPLACE INTO function_summaries
                (id, chunk_id, repo_id, symbol, path, start_line, end_line, summary_text, summary_embedding,
                 summary_type, prompt_hash, evidence_ids, model, created_at, updated_at, truth_status, metadata)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    summary_id,
                    function_record.get("chunk_id") or "",
                    function_record.get("repo_id") or "",
                    function_record.get("symbol") or "",
                    function_record.get("path") or "",
                    function_record.get("start_line"),
                    function_record.get("end_line"),
                    answer,
                    local_text_embedding_blob(answer),
                    answer_summary_type(payload, answer),
                    prompt_hash,
                    json.dumps(evidence_ids, ensure_ascii=False),
                    model,
                    now,
                    now,
                    "derived_not_original_truth",
                    json.dumps(function_record.get("metadata") or {}, ensure_ascii=False),
                ),
            )
        connection.close()
        return {"store": "function_summaries", "path": str(paths["function_summaries"]), "id": summary_id}

    knowledge_type = "documentation_answer" if payload_has_doc_evidence({**(payload or {}), "retrieved_evidence_ids": evidence_ids}) else "general_answer"
    knowledge_id = stable_text_id(f"{knowledge_type}:{record.get('query', '')}:{answer}:{now}")
    connection = init_knowledge_db(paths["knowledge"])
    with connection:
        connection.execute(
            """
            INSERT OR REPLACE INTO knowledge
            (id, query, answer_text, answer_embedding, knowledge_type, prompt_hash, evidence_ids, model, created_at, truth_status, metadata)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                knowledge_id,
                record.get("query") or (payload or {}).get("query") or "",
                answer,
                local_text_embedding_blob(answer),
                knowledge_type,
                prompt_hash,
                json.dumps(evidence_ids, ensure_ascii=False),
                model,
                now,
                "derived_not_original_truth",
                json.dumps({"reason": "No single function mapping found."}, ensure_ascii=False),
            ),
        )
    connection.close()
    return {"store": "knowledge", "path": str(paths["knowledge"]), "id": knowledge_id, "knowledge_type": knowledge_type}


def search_terms_for_generated_store(query: str) -> list[str]:
    terms = sorted(search_query_terms(query or ""), key=len, reverse=True)
    return [term for term in terms if len(term) >= 3][:8]


def read_stored_function_summaries(output_repo_dir, query: str, results: list[dict], limit: int = 6) -> list[dict]:
    path = generated_store_paths(Path(output_repo_dir))["function_summaries"]
    if not path.exists():
        return []
    symbols = []
    for item in results or []:
        symbol = str(item.get("symbol") or item.get("fullName") or "").strip()
        if symbol:
            symbols.append(symbol)
    terms = search_terms_for_generated_store(query)
    rows = []
    connection = None
    try:
        connection = sqlite3.connect(path)
        connection.row_factory = sqlite3.Row
        if symbols:
            placeholders = ",".join("?" for _ in symbols[:50])
            rows.extend(connection.execute(
                f"""
                SELECT id, chunk_id, repo_id, symbol, path, start_line, end_line,
                       summary_text, summary_type, evidence_ids, model, created_at,
                       updated_at, truth_status, metadata
                FROM function_summaries
                WHERE symbol IN ({placeholders})
                ORDER BY updated_at DESC
                LIMIT ?
                """,
                [*symbols[:50], limit],
            ).fetchall())
        if len(rows) < limit and terms:
            clauses = []
            params = []
            for term in terms:
                like = f"%{term}%"
                clauses.append("(LOWER(symbol) LIKE ? OR LOWER(path) LIKE ? OR LOWER(summary_text) LIKE ?)")
                params.extend([like, like, like])
            rows.extend(connection.execute(
                f"""
                SELECT id, chunk_id, repo_id, symbol, path, start_line, end_line,
                       summary_text, summary_type, evidence_ids, model, created_at,
                       updated_at, truth_status, metadata
                FROM function_summaries
                WHERE {" OR ".join(clauses)}
                ORDER BY updated_at DESC
                LIMIT ?
                """,
                [*params, limit],
            ).fetchall())
    except Exception as e:
        logger.warning("Unable to read function_summaries.sqlite: %s", e)
        return []
    finally:
        if connection is not None:
            connection.close()
    seen = set()
    items = []
    result_symbols = {str(symbol).lower() for symbol in symbols}
    for row in rows:
        item = dict(row)
        if item["id"] in seen:
            continue
        seen.add(item["id"])
        symbol_lower = str(item.get("symbol") or "").lower()
        score = 100 if symbol_lower in result_symbols else 0
        score += sum(20 for term in terms if term in symbol_lower or term in str(item.get("path") or "").lower())
        score += sum(5 for term in terms if term in str(item.get("summary_text") or "").lower())
        item.update({
            "source_type": "stored_function_summary",
            "truth_status": item.get("truth_status") or "derived_not_original_truth",
            "score": score,
        })
        items.append(item)
    items.sort(key=lambda item: (item.get("score", 0), item.get("updated_at") or ""), reverse=True)
    return items[:limit]


def read_stored_knowledge(output_repo_dir, query: str, text_results: list[dict] | None = None, limit: int = 6) -> list[dict]:
    path = generated_store_paths(Path(output_repo_dir))["knowledge"]
    if not path.exists():
        return []
    terms = search_terms_for_generated_store(query)
    normalized_query = str(query or "").strip().lower()
    if not terms and not normalized_query:
        return []
    rows = []
    connection = None
    try:
        connection = sqlite3.connect(path)
        connection.row_factory = sqlite3.Row
        if normalized_query:
            rows.extend(connection.execute(
                """
                SELECT id, query, answer_text, knowledge_type, evidence_ids, model,
                       created_at, truth_status, metadata
                FROM knowledge
                WHERE LOWER(TRIM(query)) = ?
                ORDER BY created_at DESC
                LIMIT ?
                """,
                [normalized_query, limit],
            ).fetchall())
        if len(rows) < limit and terms:
            clauses = []
            params = []
            for term in terms:
                like = f"%{term}%"
                clauses.append("(LOWER(query) LIKE ? OR LOWER(answer_text) LIKE ? OR LOWER(evidence_ids) LIKE ?)")
                params.extend([like, like, like])
            rows.extend(connection.execute(
                f"""
                SELECT id, query, answer_text, knowledge_type, evidence_ids, model,
                       created_at, truth_status, metadata
                FROM knowledge
                WHERE {" OR ".join(clauses)}
                ORDER BY created_at DESC
                LIMIT ?
                """,
                [*params, limit],
            ).fetchall())
    except Exception as e:
        logger.warning("Unable to read knowledge.sqlite: %s", e)
        return []
    finally:
        if connection is not None:
            connection.close()
    text_paths = " ".join(str(item.get("file") or "") for item in text_results or []).lower()
    items = []
    seen = set()
    for row in rows:
        item = dict(row)
        if item.get("id") in seen:
            continue
        seen.add(item.get("id"))
        searchable = f"{item.get('query') or ''} {item.get('answer_text') or ''} {item.get('evidence_ids') or ''}".lower()
        score = sum(15 for term in terms if term in searchable)
        if normalized_query and str(item.get("query") or "").strip().lower() == normalized_query:
            score += 1000
        score += sum(10 for term in terms if term in text_paths)
        item.update({
            "source_type": "stored_knowledge",
            "truth_status": item.get("truth_status") or "derived_not_original_truth",
            "score": score,
        })
        items.append(item)
    items.sort(key=lambda item: (item.get("score", 0), item.get("created_at") or ""), reverse=True)
    return items[:limit]


def load_all_function_summaries(output_repo_dir, limit: int = 50) -> list[dict]:
    path = generated_store_paths(Path(output_repo_dir))["function_summaries"]
    if not path.exists():
        return []
    rows = []
    try:
        connection = sqlite3.connect(path)
        connection.row_factory = sqlite3.Row
        rows = connection.execute(
            """
            SELECT id, chunk_id, repo_id, symbol, path, start_line, end_line,
                   summary_text, summary_type, evidence_ids, model, created_at,
                   updated_at, truth_status, metadata
            FROM function_summaries
            ORDER BY updated_at DESC
            LIMIT ?
            """,
            [max(1, min(int(limit or 50), 500))],
        ).fetchall()
    except Exception as e:
        logger.warning("Unable to load function_summaries.sqlite: %s", e)
        return []
    finally:
        try:
            connection.close()
        except Exception:
            pass
    items = []
    for row in rows:
        item = dict(row)
        try:
            item["metadata"] = json.loads(item.get("metadata") or "{}")
        except Exception:
            item["metadata"] = {}
        items.append(item)
    return items


def function_summary_current_hashes(output_repo_dir) -> dict[str, str]:
    hashes = {}
    for item in load_all_function_summaries(output_repo_dir, limit=1000):
        metadata = item.get("metadata") if isinstance(item.get("metadata"), dict) else {}
        function_hash = str(metadata.get("function_hash") or "")
        symbol = str(item.get("symbol") or "")
        if symbol and function_hash:
            hashes[symbol] = function_hash
    return hashes


def function_content_hash(record: dict) -> str:
    return stable_text_id(
        "\n".join(
            str(record.get(key) or "")
            for key in ("symbol", "path", "start_line", "end_line", "signature", "code")
        )
    )


def path_summary_priority(path: str) -> int:
    lowered = str(path or "").replace("\\", "/").lower()
    if not lowered:
        return 0
    if any(part in lowered for part in ("/node_modules/", "/vendor/", "/dist/", "/build/", "/coverage/", "/.next/", "/generated/")):
        return -500
    if (
        lowered.startswith(("test/", "tests/", "__tests__/"))
        or any(part in lowered for part in ("/test/", "/tests/", "__tests__", ".spec.", ".test.", "/fixtures/", "/mocks/"))
    ):
        return -120
    if "/src/" in lowered or lowered.startswith("src/") or "/app/" in lowered or "/lib/" in lowered:
        return 40
    return 5


def rank_top_function_records_for_summary(output_repo_dir, limit: int) -> list[dict]:
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    dataset_dir = artifact_root / "scim"
    records = list(load_scim_function_records(dataset_dir).values())
    ranked = []
    for record in records:
        path = str(record.get("path") or "")
        priority = path_summary_priority(path)
        if priority <= -500:
            continue
        code = str(record.get("code") or "").strip()
        symbol = str(record.get("symbol") or "")
        if not symbol or not code:
            continue
        in_degree = int(record.get("in_degree") or 0)
        out_degree = int(record.get("out_degree") or 0)
        line_count = int(record.get("line_count") or 0)
        graph_degree = in_degree + out_degree
        score = (in_degree * 4) + (out_degree * 2) + priority + min(line_count, 80) / 10
        ranked.append((graph_degree > 0, score, record))
    ranked.sort(key=lambda item: (item[0], item[1], str(item[2].get("symbol") or "")), reverse=True)
    return [record for _, _, record in ranked[: max(0, int(limit or 0))]]


def build_top_function_summary_prompt(record: dict) -> str:
    callees = ", ".join((record.get("callees") or [])[:12]) if isinstance(record.get("callees"), list) else ""
    callers = ", ".join((record.get("callers") or [])[:12]) if isinstance(record.get("callers"), list) else ""
    code = str(record.get("code") or "")[:3500]
    return f"""Summarize this function for a codebase understanding cache.
Use simple English. Return exactly 1-2 sentences, max 80 words.
Mention the main responsibility and important direct calls only when visible.
Do not invent behavior not shown in the code.

SYMBOL: {record.get('symbol', '')}
FILE: {record.get('path', '')}:{record.get('start_line', '')}-{record.get('end_line', '')}
SIGNATURE: {record.get('signature', '')}
CALLERS: {callers or 'not provided'}
CALLEES: {callees or 'not provided'}
CODE:
{code}
"""


def generate_top_function_summary(prompt: str) -> str:
    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        raise ValueError("OPENAI_API_KEY is not set.")
    model = os.getenv("OPENAI_FUNCTION_SUMMARY_MODEL", os.getenv("OPENAI_SUMMARY_MODEL", os.getenv("OPENAI_SEARCH_MODEL", "gpt-4o-mini")))
    response = requests.post(
        "https://api.openai.com/v1/chat/completions",
        headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
        json={
            "model": model,
            "messages": [{"role": "user", "content": prompt}],
            "max_tokens": int(os.getenv("FUNCTION_SUMMARY_MAX_TOKENS", "140") or 140),
            "temperature": 0.1,
        },
        timeout=(10, max(30, min(int(os.getenv("FUNCTION_SUMMARY_TIMEOUT_SECONDS", "60") or 60), 180))),
    )
    response.raise_for_status()
    data = response.json()
    return (data["choices"][0]["message"]["content"] or "").strip()


def store_top_function_summary(output_repo_dir, record: dict, summary: str, prompt: str, function_hash: str):
    paths = generated_store_paths(Path(output_repo_dir))
    now = datetime.now().isoformat()
    summary_id = stable_text_id(f"top_function_summary:{record.get('symbol', '')}:{function_hash}")
    in_degree = int(record.get("in_degree") or 0)
    out_degree = int(record.get("out_degree") or 0)
    graph_degree = in_degree + out_degree
    metadata = {
        "source": "top_n_function_summary",
        "function_hash": function_hash,
        "in_degree": in_degree,
        "out_degree": out_degree,
        "graph_degree": graph_degree,
        "graph_connected": graph_degree > 0,
        "selection_reason": "callgraph_connected" if graph_degree > 0 else "source_coverage_fallback",
        "line_count": record.get("line_count", 0),
    }
    connection = init_function_summaries_db(paths["function_summaries"])
    with connection:
        connection.execute(
            """
            INSERT OR REPLACE INTO function_summaries
            (id, chunk_id, repo_id, symbol, path, start_line, end_line, summary_text, summary_embedding,
             summary_type, prompt_hash, evidence_ids, model, created_at, updated_at, truth_status, metadata)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                summary_id,
                record.get("chunk_id") or "",
                record.get("repo_id") or "",
                record.get("symbol") or "",
                record.get("path") or "",
                int(record.get("start_line") or 0) or None,
                int(record.get("end_line") or 0) or None,
                summary,
                local_text_embedding_blob(summary),
                "top_function_summary",
                stable_text_id(prompt or ""),
                json.dumps([f"code_function:{record.get('symbol', '')}"], ensure_ascii=False),
                os.getenv("OPENAI_FUNCTION_SUMMARY_MODEL", os.getenv("OPENAI_SUMMARY_MODEL", os.getenv("OPENAI_SEARCH_MODEL", "gpt-4o-mini"))),
                now,
                now,
                "derived_not_original_truth",
                json.dumps(metadata, ensure_ascii=False),
            ),
        )
    connection.close()
    return {"id": summary_id, "symbol": record.get("symbol", ""), "path": str(paths["function_summaries"])}


def summarize_top_functions_for_repo(output_repo_dir, limit: Optional[int] = None, progress_callback=None) -> dict:
    limit = configured_top_function_summary_limit() if limit is None else int(limit or 0)
    if limit <= 0:
        return {"enabled": False, "requested": 0, "created": 0, "skipped": 0, "items": []}
    records = rank_top_function_records_for_summary(output_repo_dir, limit)
    existing_hashes = function_summary_current_hashes(output_repo_dir)
    created = []
    skipped = 0
    llm_calls_made = 0
    errors = []
    for index, record in enumerate(records, start=1):
        function_hash = function_content_hash(record)
        symbol = str(record.get("symbol") or "")
        if existing_hashes.get(symbol) == function_hash:
            skipped += 1
            continue
        if progress_callback:
            progress_callback(f"Summarizing function summary candidate {index}/{len(records)}.", symbol)
        prompt = build_top_function_summary_prompt(record)
        try:
            llm_calls_made += 1
            summary = generate_top_function_summary(prompt)
            created.append(store_top_function_summary(output_repo_dir, record, summary, prompt, function_hash))
        except Exception as e:
            logger.warning("Top function summary failed for %s: %s", symbol, e)
            errors.append({"symbol": symbol, "error": str(e)})
    return {
        "enabled": True,
        "requested": limit,
        "candidate_count": len(records),
        "created": len(created),
        "skipped": skipped,
        "llm_calls_made": llm_calls_made,
        "errors": errors[:10],
        "items": created,
        "store_path": str(generated_store_paths(Path(output_repo_dir))["function_summaries"]),
    }


def update_top_function_summary_job(repo_id: str, **updates) -> dict:
    with TOP_FUNCTION_SUMMARY_JOBS_GUARD:
        job = TOP_FUNCTION_SUMMARY_JOBS.setdefault(repo_id, {})
        job.update(updates)
        job["updated_at"] = datetime.now().isoformat()
        return dict(job)


def top_function_summary_job(repo_id: str) -> dict:
    with TOP_FUNCTION_SUMMARY_JOBS_GUARD:
        return dict(TOP_FUNCTION_SUMMARY_JOBS.get(repo_id) or {})


def run_top_function_summary_job(owner: str, repo: str, repo_id: str, output_repo_dir: str, limit: int, analysis_job_id: str = ""):
    update_top_function_summary_job(
        repo_id,
        status="running",
        owner_name=owner,
        repo_name=repo,
        requested=limit,
        started_at=datetime.now().isoformat(),
        message=f"Summarizing {limit} function summary candidates in the background.",
    )

    def progress(message, current_file=None):
        update_top_function_summary_job(repo_id, status="running", message=message, current_file=current_file or "")

    try:
        result = summarize_top_functions_for_repo(output_repo_dir, limit=limit, progress_callback=progress)
        update_top_function_summary_job(
            repo_id,
            status="completed",
            message=f"Function summaries complete: {result.get('created', 0)} created, {result.get('skipped', 0)} skipped.",
            result=result,
            completed_at=datetime.now().isoformat(),
            current_file="",
        )
        logger.info("Top function summary background job complete for %s/%s: %s", owner, repo, result)
    except Exception as e:
        logger.exception("Top function summary background job failed for %s/%s", owner, repo)
        update_top_function_summary_job(
            repo_id,
            status="error",
            message=f"Function summary job failed: {e}",
            error=str(e),
            completed_at=datetime.now().isoformat(),
            current_file="",
        )


def schedule_top_function_summaries(owner: str, repo: str, repo_id: str, output_repo_dir: str, analysis_job_id: str = "") -> dict:
    limit = configured_top_function_summary_limit()
    if limit <= 0:
        return {"enabled": False, "requested": 0, "status": "disabled"}
    existing = top_function_summary_job(repo_id)
    if existing.get("status") in {"queued", "running"}:
        return {"enabled": True, "requested": limit, "status": existing.get("status"), "message": existing.get("message", "")}
    update_top_function_summary_job(
        repo_id,
        status="queued",
        owner_name=owner,
        repo_name=repo,
        requested=limit,
        message=f"Queued {limit} function summary candidates.",
        analysis_job_id=analysis_job_id,
    )
    thread = threading.Thread(
        target=run_top_function_summary_job,
        args=(owner, repo, repo_id, str(output_repo_dir), limit, analysis_job_id),
        daemon=True,
    )
    thread.start()
    return {"enabled": True, "requested": limit, "status": "queued", "message": f"Queued {limit} function summary candidates."}


def stored_generated_context(output_repo_dir, query: str, results: list[dict], text_results: list[dict] | None = None) -> dict:
    function_summaries = read_stored_function_summaries(output_repo_dir, query, results)
    knowledge = read_stored_knowledge(output_repo_dir, query, text_results)
    exact_query = str(query or "").strip().lower()
    exact_knowledge = next(
        (
            item for item in knowledge
            if exact_query and str(item.get("query") or "").strip().lower() == exact_query
        ),
        None,
    )
    best = exact_knowledge
    best_answer = ""
    if best:
        best_answer = str(best.get("answer_text") or "")
    return {
        "function_summaries": function_summaries,
        "knowledge": knowledge,
        "best_answer": best_answer,
        "best_source_type": str((best or {}).get("source_type") or ""),
        "truth_status": "derived_not_original_truth" if best else "",
    }


def attach_stored_generated_context(output_repo_dir, query: str, retrieval_context: dict, results: list[dict], text_results: list[dict] | None = None) -> dict:
    context = dict(retrieval_context or {})
    stored = stored_generated_context(output_repo_dir, query, results, text_results)
    context["stored_generated_answers"] = stored
    return context


def store_search_interaction(output_repo_dir, payload: dict):
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    search_dir = artifact_root / "scim" / "search_history"
    search_dir.mkdir(parents=True, exist_ok=True)
    now = datetime.now().isoformat()
    query = str(payload.get("query") or "")
    search_id = hashlib.sha1(f"{now}:{query}".encode("utf-8", errors="ignore")).hexdigest()[:16]
    results = payload.get("results") or []
    text_results = payload.get("text_results") or []
    record = {
        "id": search_id,
        "created_at": now,
        "query": query,
        "intent": payload.get("intent") or {},
        "search_backend": payload.get("search_backend") or "",
        "retrieval_plan": payload.get("retrieval_plan") or {},
        "result_count": len(results),
        "text_count": len(text_results),
        "retrieved_evidence_ids": [
            str(item.get("symbol") or item.get("fullName") or item.get("file") or item.get("title") or "")
            for item in results[:25]
        ],
        "text_evidence_ids": [
            f"{item.get('file', '')}:{item.get('line', '')}"
            for item in text_results[:25]
        ],
        "search_graph_url": payload.get("search_graph_url") or "",
        "search_graph_error": payload.get("search_graph_error") or "",
        "answer_prompt_chars": payload.get("answer_prompt_chars") or len(str(payload.get("answer_prompt") or "")),
        "feedback": "",
    }
    history_jsonl = search_dir / "search_history.jsonl"
    with history_jsonl.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(record, ensure_ascii=False, separators=(",", ":")) + "\n")
    return {"search_id": search_id, "path": str(history_jsonl)}


def update_derived_answer_feedback(output_repo_dir, answer_id: str, feedback: str = "", approved: Optional[bool] = None):
    output_repo_path = Path(output_repo_dir)
    _, answers_path, feedback_path = derived_memory_paths(output_repo_path)
    feedback_record = {
        "created_at": datetime.now().isoformat(),
        "answer_id": answer_id,
        "feedback": feedback,
        "approved": approved,
    }
    with feedback_path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(feedback_record, ensure_ascii=False) + "\n")
    updated = None
    if answers_path.exists() and answer_id:
        rows = []
        for line in answers_path.read_text(encoding="utf-8").splitlines():
            try:
                item = json.loads(line)
            except Exception:
                continue
            if item.get("id") == answer_id:
                item["user_feedback"] = feedback
                if approved is not None:
                    item["approved"] = bool(approved)
                item["updated_at"] = datetime.now().isoformat()
                updated = item
            rows.append(item)
        answers_path.write_text("\n".join(json.dumps(item, ensure_ascii=False) for item in rows) + ("\n" if rows else ""), encoding="utf-8")
    indexed = index_derived_answer_memory(output_repo_path, [updated]) if updated and should_index_derived_answer(updated) else {}
    return {"ok": True, "answer_id": answer_id, "feedback_path": str(feedback_path), "updated": bool(updated), "indexed": indexed}


def ga_error_message_from_row(row: dict):
    return (
        row.get("customEvent:error_message")
        or row.get("error_message")
        or row.get("customEvent:ui_message")
        or row.get("ui_message")
        or row.get("customEvent:status_text")
        or row.get("status_text")
        or ""
    )


def ga_row_is_error(row: dict):
    if not isinstance(row, dict) or is_autotrack_analytics_beacon_row(row):
        return False
    label = str(row.get("customEvent:button_name") or row.get("button_name") or "").lower()
    if any(term in label for term in ("error", "failed", "failure", "exception")):
        return True
    if ga_value_is_useful(ga_error_message_from_row(row)):
        return True
    status = str(row.get("customEvent:status") or row.get("status") or "").strip()
    return status.isdigit() and int(status) >= 400


def ga_error_rows_from_payload(payload: dict):
    rows = payload.get("ordered_rows") or payload.get("rows") or []
    errors = []
    for index, row in enumerate(rows, start=1):
        if not ga_row_is_error(row):
            continue
        label = ga_row_label(row)
        errors.append({
            "index": index,
            "label": label,
            "event_count": row.get("eventCount") or 0,
            "time_bucket": row.get("dateHourMinute") or row.get("dateHour") or row.get("date") or "",
            "error_message": ga_error_message_from_row(row),
            "button_name": row.get("customEvent:button_name") or row.get("button_name") or "",
            "function_name": row.get("customEvent:function_name") or row.get("function_name") or "",
            "callgraph_node": row.get("customEvent:callgraph_node") or row.get("callgraph_node") or "",
            "file_path": row.get("customEvent:file_path") or row.get("file_path") or "",
            "endpoint": row.get("customEvent:endpoint") or row.get("endpoint") or "",
            "request_url": row.get("customEvent:request_url") or row.get("request_url") or "",
            "method": row.get("customEvent:method") or row.get("method") or "",
            "status": row.get("customEvent:status") or row.get("status") or "",
            "status_text": row.get("customEvent:status_text") or row.get("status_text") or "",
            "source_element": row.get("customEvent:source_element") or row.get("source_element") or "",
            "source": row.get("customEvent:source") or row.get("source") or "",
            "lineno": row.get("customEvent:lineno") or row.get("lineno") or "",
            "colno": row.get("customEvent:colno") or row.get("colno") or "",
            "stack": row.get("customEvent:stack") or row.get("stack") or "",
            "top_frame": row.get("customEvent:top_frame") or row.get("top_frame") or "",
            "stack_hash": row.get("customEvent:stack_hash") or row.get("stack_hash") or "",
            "response_body": row.get("customEvent:response_body") or row.get("response_body") or "",
            "trigger_element": row.get("customEvent:trigger_element") or row.get("trigger_element") or "",
            "row": row,
        })
    return errors


def self_heal_load_source_file(output_repo_dir: Path, file_path: str, max_chars=12000):
    src_dir = find_cached_source_dir(output_repo_dir)
    if not src_dir or not file_path:
        return "", ""
    normalized = str(file_path).replace("\\", "/").lstrip("/")
    candidates = [
        Path(src_dir) / normalized,
        Path(src_dir) / normalized.replace("static/", "", 1),
        Path(src_dir) / normalized.rsplit("/", 1)[-1],
    ]
    for candidate in candidates:
        try:
            if candidate.exists() and candidate.is_file() and not should_skip_path(str(candidate), str(src_dir)):
                return os.path.relpath(candidate, src_dir).replace("\\", "/"), candidate.read_text(encoding="utf-8", errors="ignore")[:max_chars]
        except Exception:
            continue
    return "", ""


def self_heal_callgraph_context(output_repo_dir: Path, root_nodes: list[str], depth=2):
    try:
        callgraph, source = load_search_callgraph(artifact_root_for_output(output_repo_dir))
        _, _, outgoing, incoming, _ = callgraph_indexes(callgraph)
    except Exception:
        return {"source": "", "roots": root_nodes, "edges": [], "nodes": []}
    seen = set(root_nodes)
    frontier = list(root_nodes)
    edges = []
    for _ in range(depth):
        next_frontier = []
        for node in frontier:
            for callee in sorted(outgoing.get(node, []))[:12]:
                edges.append({"source": node, "target": callee, "direction": "callee"})
                if callee not in seen:
                    seen.add(callee)
                    next_frontier.append(callee)
            for caller in sorted(incoming.get(node, []))[:12]:
                edges.append({"source": caller, "target": node, "direction": "caller"})
                if caller not in seen:
                    seen.add(caller)
                    next_frontier.append(caller)
        frontier = next_frontier
    return {"source": source, "roots": root_nodes, "nodes": sorted(seen), "edges": edges[:80]}


def self_heal_code_snippets(output_repo_dir: Path, nodes: list[str], file_path: str = ""):
    artifact_root = artifact_root_for_output(output_repo_dir)
    functions_path = artifact_root / "scim" / "functions.jsonl"
    records = load_scim_function_records(functions_path.parent) if functions_path.exists() else {}
    snippets = []
    lower_to_symbol = {str(symbol).lower(): symbol for symbol in records}
    for node in nodes[:20]:
        record = records.get(node)
        if not record:
            tail = str(node).lower().split(".")[-1]
            match = next((symbol for lowered, symbol in lower_to_symbol.items() if lowered.endswith(tail)), "")
            record = records.get(match)
        if not record:
            continue
        snippets.append({
            "symbol": record.get("symbol", node),
            "path": record.get("path", ""),
            "start_line": record.get("start_line", ""),
            "end_line": record.get("end_line", ""),
            "code": str(record.get("code") or "")[:3000],
        })
        if len(snippets) >= 8:
            break
    if not snippets and file_path:
        rel_path, text = self_heal_load_source_file(output_repo_dir, file_path)
        if text:
            snippets.append({"symbol": rel_path, "path": rel_path, "start_line": 1, "end_line": "", "code": text[:5000]})
    return snippets


def build_self_heal_prompt(error_item: dict, mapping: dict, callgraph_context: dict, snippets: list[dict], scim_results: list[dict]):
    return f"""You are a senior software repair assistant.
Use ONLY the supplied GA error, callgraph, SCIM evidence, and code snippets.

Task:
- Identify the most likely failing file/function.
- Explain both the frontend stack trace/top frame and the static callgraph path that led to the error.
- If stack/top_frame/stack_hash are present, use them to group and diagnose the frontend failure.
- Propose a minimal code fix.
- If you can safely identify the exact file edit, include a unified diff in a fenced ```diff block.
- Do not claim the fix was applied. This is a proposed fix only.
- If evidence is insufficient, say what is missing and give the safest likely fix.

Return concise markdown with sections:
1. Likely Root Cause
2. Evidence
3. Proposed Code Snippet
4. Why This Should Help
5. Remaining Checks
6. Patch

GA error row:
{json.dumps(error_item, indent=2)}

Mapped callgraph nodes:
{json.dumps(mapping.get("matches", [])[:8], indent=2)}

Callgraph context:
{json.dumps(callgraph_context, indent=2)}

Code snippets:
{json.dumps(snippets, indent=2)}

SCIM supporting evidence:
{json.dumps(scim_results[:8], indent=2)}
"""


def extract_unified_diff_from_text(text: str):
    raw = str(text or "")
    fenced = re.findall(r"```(?:diff|patch)?\s*(.*?)```", raw, flags=re.IGNORECASE | re.DOTALL)
    candidates = fenced or [raw]
    for candidate in candidates:
        body = candidate.strip()
        if ("--- " in body and "+++ " in body and "@@" in body) or body.startswith("diff --git "):
            return body + ("\n" if not body.endswith("\n") else "")
    return ""


def validate_unified_diff_paths(diff_text: str):
    paths = []
    for line in str(diff_text or "").splitlines():
        if not (line.startswith("--- ") or line.startswith("+++ ")):
            continue
        path = line[4:].strip().split("\t", 1)[0]
        if path == "/dev/null":
            continue
        if path.startswith(("a/", "b/")):
            path = path[2:]
        normalized = Path(path)
        if normalized.is_absolute() or ".." in normalized.parts:
            raise HTTPException(status_code=400, detail=f"Unsafe patch path: {path}")
        paths.append(str(normalized).replace("\\", "/"))
    return sorted(set(paths))


def apply_unified_diff_to_source(output_repo_dir: Path, diff_text: str):
    source_dir = find_cached_source_dir(output_repo_dir)
    if not source_dir:
        raise HTTPException(status_code=400, detail="Cached source directory not found for this analysis.")
    diff_text = extract_unified_diff_from_text(diff_text)
    if not diff_text:
        raise HTTPException(status_code=400, detail="No unified diff was found in the proposed fix.")
    touched_paths = validate_unified_diff_paths(diff_text)
    if not touched_paths:
        raise HTTPException(status_code=400, detail="Patch does not include any editable file paths.")
    check = subprocess.run(
        ["git", "apply", "--check", "-"],
        input=diff_text,
        text=True,
        cwd=str(source_dir),
        capture_output=True,
        timeout=30,
    )
    if check.returncode != 0:
        raise HTTPException(status_code=400, detail=f"Patch could not be applied cleanly: {check.stderr.strip() or check.stdout.strip()}")
    apply_result = subprocess.run(
        ["git", "apply", "-"],
        input=diff_text,
        text=True,
        cwd=str(source_dir),
        capture_output=True,
        timeout=30,
    )
    if apply_result.returncode != 0:
        raise HTTPException(status_code=400, detail=f"Patch apply failed: {apply_result.stderr.strip() or apply_result.stdout.strip()}")
    return {
        "source_dir": str(source_dir),
        "touched_paths": touched_paths,
    }


@app.get("/self-healing/ga-errors")
def self_healing_ga_errors(owner_name: str = "", repo_name: str = ""):
    if not owner_name or not repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    payload, _ = load_saved_ga_interactions(output_repo_dir)
    errors = ga_error_rows_from_payload(payload)
    return {
        "owner_name": owner_name,
        "repo_name": repo_name,
        "error_count": len(errors),
        "errors": errors[:50],
        "ga_interactions_path": str(output_repo_dir / "ga_interactions.json"),
    }


@app.post("/self-healing/analyze")
def self_healing_analyze(payload: dict):
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    if not owner or not repo:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    output_repo_dir = repo_output_dir(owner, repo)
    saved_payload, _ = load_saved_ga_interactions(output_repo_dir)
    errors = ga_error_rows_from_payload(saved_payload)
    if not errors:
        raise HTTPException(status_code=404, detail="No GA error rows found. Fetch GA interactions after generating an error.")
    requested_index = payload.get("error_index")
    selected = errors[0]
    if requested_index not in (None, ""):
        try:
            requested_index = int(requested_index)
            selected = next((item for item in errors if int(item.get("index", -1)) == requested_index), errors[max(0, min(requested_index, len(errors) - 1))])
        except Exception:
            selected = errors[0]
    row = selected.get("row") or {}
    mapping = map_ga_rows_to_callgraph([row], owner, repo)
    root_nodes = [item.get("node", "") for item in mapping.get("matches", []) if item.get("node")]
    if not root_nodes:
        fallback_node = selected.get("callgraph_node") or selected.get("function_name")
        if fallback_node:
            root_nodes = [fallback_node]
    callgraph_context = self_heal_callgraph_context(output_repo_dir, root_nodes)
    snippets = self_heal_code_snippets(output_repo_dir, callgraph_context.get("nodes") or root_nodes, selected.get("file_path", ""))
    query = " ".join([
        "fix error",
        selected.get("error_message", ""),
        selected.get("button_name", ""),
        selected.get("function_name", ""),
        selected.get("callgraph_node", ""),
        selected.get("file_path", ""),
    ])
    scim_payload = search_scim_dataset(output_repo_dir, query, limit=8) or {}
    scim_results = scim_payload.get("results", [])
    prompt = build_self_heal_prompt(selected, mapping, callgraph_context, snippets, scim_results)
    proposal = generate_search_answer_from_prompt(prompt)
    evidence_ids = [f"ga_error:{selected.get('index')}", *[f"code_function:{node}" for node in root_nodes]]
    evidence_ids.extend(scim_evidence_ids_from_payload(scim_results, scim_payload.get("retrieval_context") or {}, []))
    memory = store_derived_answer_memory(
        output_repo_dir,
        {
            "query": f"Propose self-healing fix for GA error: {selected.get('label', '')}",
            "intent": ["error_debug", "function_flow"],
            "retrieval_plan": {"intents": ["error_debug", "function_flow"], "source_boosts": {**SCIM_SOURCE_TYPE_GROUPS.get("error_debug", {}), **SCIM_SOURCE_TYPE_GROUPS.get("function_flow", {})}},
            "retrieved_evidence_ids": list(dict.fromkeys(evidence_ids)),
        },
        proposal,
        prompt,
    )
    return {
        "owner_name": owner,
        "repo_name": repo,
        "error": {key: value for key, value in selected.items() if key != "row"},
        "mapped_callgraph_nodes": mapping.get("matches", []),
        "callgraph_context": callgraph_context,
        "code_snippets": snippets,
        "scim_results": scim_results,
        "proposal": proposal,
        "patch_available": bool(extract_unified_diff_from_text(proposal)),
        "prompt_chars": len(prompt),
        "derived_memory": memory,
    }


