@app.get("/google-analytics/callgraph-events")
def google_analytics_callgraph_events(
    request: Request,
    property_id: str,
    days: int = 7,
    event_name: str = CODEVAL_GA_ACTIVITY_EVENT_NAME,
    owner_name: str = "",
    repo_name: str = "",
):
    session_id, session = google_analytics_session_from_request(request)
    access_token = refresh_google_analytics_token(session_id, session)
    property_id = normalize_google_analytics_property_id(property_id)
    if not property_id:
        raise HTTPException(status_code=400, detail="property_id is required")
    days = max(1, min(int(days or 7), 90))
    raw_event_name = str(event_name or CODEVAL_GA_ACTIVITY_EVENT_NAME).strip()[:80]
    event_name = "" if raw_event_name.lower() in {"*", "all", "any", "none", "null"} else raw_event_name

    endpoint = f"https://analyticsdata.googleapis.com/v1beta/properties/{property_id}:runReport"
    page_limit = 10000

    def fetch_ga_report_pages(body: dict):
        combined_json = None
        last_response = None
        offset = 0
        for _ in range(25):
            page_body = {**body, "limit": page_limit, "offset": offset}
            last_response = requests.post(
                endpoint,
                headers={**google_analytics_headers(access_token), "Content-Type": "application/json"},
                json=page_body,
                timeout=GITHUB_REQUEST_TIMEOUT,
            )
            if not last_response.ok:
                return last_response, page_body, None
            page_json = last_response.json()
            page_rows = page_json.get("rows", []) or []
            if combined_json is None:
                combined_json = {**page_json, "rows": []}
            combined_json["rows"].extend(page_rows)
            try:
                total_rows = int(page_json.get("rowCount") or 0)
            except (TypeError, ValueError):
                total_rows = 0
            if not page_rows or (total_rows and len(combined_json["rows"]) >= total_rows):
                break
            offset += len(page_rows)
        if combined_json is None:
            combined_json = {"rows": [], "dimensionHeaders": [], "metricHeaders": [], "rowCount": 0}
        combined_json["returnedRowCount"] = len(combined_json.get("rows", []) or [])
        return last_response, body, combined_json

    request_body = {
        "dateRanges": [{"startDate": f"{days}daysAgo", "endDate": "today"}],
        "dimensions": [
            {"name": "dateHourMinute"},
            {"name": "eventName"},
            {"name": "customEvent:button_name"},
            {"name": "customEvent:callgraph_node"},
            {"name": "customEvent:function_name"},
            {"name": "customEvent:file_path"},
            {"name": "customEvent:input_value"},
            {"name": "customEvent:endpoint"},
            {"name": "customEvent:method"},
            {"name": "customEvent:request_url"},
            {"name": "customEvent:trigger_element"},
            {"name": "customEvent:error_message"},
            {"name": "customEvent:ui_message"},
            {"name": "customEvent:source_element"},
            {"name": "customEvent:source"},
            {"name": "customEvent:lineno"},
            {"name": "customEvent:colno"},
            {"name": "customEvent:stack"},
            {"name": "customEvent:top_frame"},
            {"name": "customEvent:stack_hash"},
            {"name": "customEvent:response_body"},
            {"name": "customEvent:status"},
            {"name": "customEvent:status_text"},
            {"name": "customEvent:severity"},
        ],
        "metrics": [{"name": "eventCount"}],
        "orderBys": [
            {"dimension": {"dimensionName": "dateHourMinute"}, "desc": True},
        ],
        "limit": page_limit,
    }
    if event_name:
        request_body["dimensionFilter"] = {
            "filter": {
                "fieldName": "eventName",
                "stringFilter": {"matchType": "EXACT", "value": event_name},
            }
        }
    fallback_used = False
    dimension_retry_used = False
    requested_dimensions = [dimension["name"] for dimension in request_body["dimensions"]]
    active_request_body = request_body
    response, active_request_body, response_json = fetch_ga_report_pages(request_body)
    if not response.ok:
        dimension_retry_used = True
        retry_body = {
            **request_body,
            "dimensions": [
                dimension
                for dimension in request_body["dimensions"]
                if dimension.get("name") not in {
                    "customEvent:input_value",
                    "customEvent:endpoint",
                    "customEvent:method",
                    "customEvent:request_url",
                    "customEvent:trigger_element",
                    "customEvent:error_message",
                    "customEvent:ui_message",
                    "customEvent:source_element",
                    "customEvent:source",
                    "customEvent:lineno",
                    "customEvent:colno",
                    "customEvent:stack",
                    "customEvent:top_frame",
                    "customEvent:stack_hash",
                    "customEvent:response_body",
                    "customEvent:status",
                    "customEvent:status_text",
                    "customEvent:severity",
                }
            ],
        }
        response, active_request_body, response_json = fetch_ga_report_pages(retry_body)
    if not response.ok:
        fallback_used = True
        fallback_body = {
            "dateRanges": [{"startDate": f"{days}daysAgo", "endDate": "today"}],
            "dimensions": [{"name": "eventName"}, {"name": "pagePath"}, {"name": "pageTitle"}],
            "metrics": [{"name": "eventCount"}],
            "limit": page_limit,
        }
        if event_name:
            fallback_body["dimensionFilter"] = request_body["dimensionFilter"]
        response, active_request_body, response_json = fetch_ga_report_pages(fallback_body)
    response.raise_for_status()
    returned_dimensions = [item.get("name", "") for item in response_json.get("dimensionHeaders", [])]
    active_dimensions = [dimension.get("name", "") for dimension in active_request_body.get("dimensions", [])]
    missing_requested_dimensions = [dimension for dimension in requested_dimensions if dimension not in returned_dimensions]
    error_dimension_keys = [
        "customEvent:endpoint",
        "customEvent:method",
        "customEvent:request_url",
        "customEvent:trigger_element",
        "customEvent:error_message",
        "customEvent:ui_message",
        "customEvent:source_element",
        "customEvent:source",
        "customEvent:lineno",
        "customEvent:colno",
        "customEvent:stack",
        "customEvent:top_frame",
        "customEvent:stack_hash",
        "customEvent:response_body",
        "customEvent:status",
        "customEvent:status_text",
        "customEvent:severity",
    ]
    error_dimensions_returned = [
        dimension for dimension in error_dimension_keys if dimension in returned_dimensions
    ]
    raw_rows = parse_ga_report_rows(response_json)
    ignored_autotrack_beacon_rows = sum(1 for row in raw_rows if is_autotrack_analytics_beacon_row(row))
    display_rows = raw_rows
    storage_source_rows = [row for row in raw_rows if not is_autotrack_analytics_beacon_row(row)]
    deduped_rows = unique_ga_interaction_rows(storage_source_rows)
    unique_row_count = len(deduped_rows)
    stored_rows, capped_row_count = limit_ga_interaction_rows(deduped_rows)
    graph_rows = deduped_rows[: min(len(deduped_rows), GA_STORED_EVENT_LIMIT)]
    custom_dimension_keys = [
        "customEvent:button_name",
        "customEvent:callgraph_node",
        "customEvent:function_name",
        "customEvent:file_path",
        "customEvent:input_value",
        "customEvent:endpoint",
        "customEvent:method",
        "customEvent:request_url",
        "customEvent:trigger_element",
        "customEvent:error_message",
        "customEvent:ui_message",
        "customEvent:source_element",
        "customEvent:source",
        "customEvent:lineno",
        "customEvent:colno",
        "customEvent:stack",
        "customEvent:top_frame",
        "customEvent:stack_hash",
        "customEvent:response_body",
        "customEvent:status",
        "customEvent:status_text",
        "customEvent:severity",
    ]
    custom_dimensions_populated = ga_rows_have_custom_values(display_rows, custom_dimension_keys)
    diagnostic = ""
    if display_rows and not fallback_used and not custom_dimensions_populated:
        diagnostic = (
            f"GA4 returned {event_name or 'unfiltered'} rows, but the registered custom dimensions were blank. "
            "This usually means the events were collected before the latest frontend code deployed, "
            "the browser is still serving cached JavaScript, or GA4 has not yet processed the newly "
            "registered event-scoped custom dimensions. Click a current dashboard button after deploy, "
            "then test again after GA4 processing catches up."
        )
    if display_rows and not error_dimensions_returned:
        diagnostic = (
            (diagnostic + " " if diagnostic else "")
            + "GA4 did not return enough request/error context in this report. "
            "Register endpoint, method, request_url, trigger_element, error_message, ui_message, source_element, "
            "source, lineno, colno, stack, top_frame, stack_hash, response_body, status, status_text, and severity "
            "as event-scoped custom dimensions, deploy the latest autotrack.js, hard refresh the browser, "
            "then generate a fresh error event."
        )
    ga_graph_url = ""
    ga_ordered_graph_url = build_ga_events_only_graph(property_id, event_name, graph_rows)
    ga_navigatable_ordered_graph_url = ""
    ga_event_callgraph_map_url = ""
    ga_event_trace_graphs = []
    mapping = {"node_count": 0, "matches": []}
    if owner_name and repo_name:
        output_repo_dir = repo_output_dir(owner_name, repo_name)
        ga_graph_url, mapping = build_ga_analysis_graph(owner_name, repo_name, graph_rows)
        ga_ordered_graph_url = build_ga_ordered_interaction_graph(owner_name, repo_name, graph_rows) or ga_ordered_graph_url
        ga_navigatable_ordered_graph_url = build_ga_navigatable_ordered_interaction_graph(owner_name, repo_name, graph_rows)
        ga_event_callgraph_map_url = build_ga_event_callgraph_map(owner_name, repo_name, graph_rows, mapping)
        ga_event_trace_graphs = build_ga_event_trace_graphs(owner_name, repo_name, graph_rows, mapping)
        persist_ga_interactions(
            output_repo_dir,
            property_id,
            event_name,
            storage_source_rows,
            mapping,
            {
                "ga_analysis_graph_url": ga_graph_url,
                "ga_ordered_graph_url": ga_ordered_graph_url,
                "ga_navigatable_ordered_graph_url": ga_navigatable_ordered_graph_url,
                "ga_event_callgraph_map_url": ga_event_callgraph_map_url,
                "ga_event_trace_graphs": ga_event_trace_graphs,
            },
        )
        if ga_graph_url or ga_ordered_graph_url or ga_navigatable_ordered_graph_url or ga_event_callgraph_map_url or ga_event_trace_graphs:
            refresh_scim_for_generated_graphs(
                output_repo_dir,
                owner_name,
                repo_name,
                [ga_graph_url, ga_ordered_graph_url, ga_navigatable_ordered_graph_url, ga_event_callgraph_map_url]
                + [item.get("graph_url", "") for item in ga_event_trace_graphs],
            )
    return {
        "property_id": property_id,
        "event_name": event_name,
        "days": days,
        "row_count": len(display_rows),
        "display_row_count": len(display_rows),
        "stored_row_count": len(stored_rows),
        "graph_row_count": len(graph_rows),
        "raw_row_count": len(raw_rows),
        "filtered_row_count": len(storage_source_rows),
        "unique_row_count": unique_row_count,
        "duplicate_row_count": max(0, len(storage_source_rows) - unique_row_count),
        "capped_row_count": capped_row_count,
        "stored_event_limit": GA_STORED_EVENT_LIMIT,
        "dedupe_policy": "unique_by_event_identity_excluding_time_bucket_sum_eventCount",
        "retention_policy": "store_only_top_signal_deduped_events_errors_mapped_code_highest_counts",
        "ga_total_row_count": response_json.get("rowCount", len(raw_rows)),
        "ga_returned_row_count": response_json.get("returnedRowCount", len(raw_rows)),
        "ignored_autotrack_beacon_rows": ignored_autotrack_beacon_rows,
        "rows": display_rows,
        "row_order": "dateHourMinute_descending_when_available",
        "stored_rows_preview": stored_rows[:8],
        "fallback_used": fallback_used,
        "dimension_retry_used": dimension_retry_used,
        "requested_dimensions": requested_dimensions,
        "active_dimensions": active_dimensions,
        "returned_dimensions": returned_dimensions,
        "missing_requested_dimensions": missing_requested_dimensions,
        "error_dimensions_requested": error_dimension_keys,
        "error_dimensions_returned": error_dimensions_returned,
        "error_dimensions_available": len(error_dimensions_returned) == len(error_dimension_keys),
        "custom_dimensions_populated": custom_dimensions_populated,
        "diagnostic": diagnostic,
        "mapping": mapping,
        "ga_analysis_graph_url": ga_graph_url,
        "ga_analysis_graph_json_url": ga_graph_url[:-5] + ".json" if ga_graph_url.endswith(".html") else "",
        "ga_analysis_graph_callgraph_url": ga_graph_url[:-5] + "_callgraph.json" if ga_graph_url.endswith(".html") else "",
        "ga_ordered_graph_url": ga_ordered_graph_url,
        "ga_ordered_graph_json_url": ga_ordered_graph_url[:-5] + ".json" if ga_ordered_graph_url.endswith(".html") else "",
        "ga_ordered_graph_callgraph_url": ga_ordered_graph_url[:-5] + "_callgraph.json" if ga_ordered_graph_url.endswith(".html") else "",
        "ga_navigatable_ordered_graph_url": ga_navigatable_ordered_graph_url,
        "ga_navigatable_ordered_graph_json_url": ga_navigatable_ordered_graph_url[:-5] + ".json" if ga_navigatable_ordered_graph_url.endswith(".html") else "",
        "ga_event_callgraph_map_url": ga_event_callgraph_map_url,
        "ga_event_callgraph_map_json_url": ga_event_callgraph_map_url[:-5] + ".json" if ga_event_callgraph_map_url.endswith(".html") else "",
        "ga_event_callgraph_map_callgraph_url": ga_event_callgraph_map_url[:-5] + "_callgraph.json" if ga_event_callgraph_map_url.endswith(".html") else "",
        "ga_event_trace_graphs": ga_event_trace_graphs,
        "note": "Register button_name, callgraph_node, endpoint, error_message, file_path, function_name, input_value, method, request_url, source, lineno, colno, stack, top_frame, stack_hash, response_body, severity, source_element, status, status_text, trigger_element, and ui_message as GA4 event-scoped custom dimensions for full report detail.",
    }

