# Contact email settings
# Email delivery uses Mailjet's HTTPS Send API, which works on Render free services.
# Set these environment variables:
#   MAILJET_API_KEY=<your Mailjet API key>
#   MAILJET_SECRET_KEY=<your Mailjet secret key>
#   MAILJET_FROM_EMAIL=<verified sender email>
#   MAILJET_FROM_NAME=CodeVal
#   CONTACT_TO_EMAIL=<recipient email>
CONTACT_MESSAGES_PATH = BASE_OUTPUT / "contact_messages.jsonl"
CONTACT_TO_EMAIL = os.getenv("CONTACT_TO_EMAIL", "pranaysaani@gmail.com")


def _contact_email_debug_config() -> dict:
    from_email = os.getenv("MAILJET_FROM_EMAIL", "").strip()
    return {
        "provider": "mailjet",
        "contact_to_email_set": bool(os.getenv("CONTACT_TO_EMAIL", CONTACT_TO_EMAIL).strip()),
        "mailjet": {
            "api_key_set": bool(os.getenv("MAILJET_API_KEY", "").strip()),
            "secret_key_set": bool(os.getenv("MAILJET_SECRET_KEY", "").strip()),
            "from_email_set": bool(from_email),
            "from_name_set": bool(os.getenv("MAILJET_FROM_NAME", "").strip()),
            "endpoint": "https://api.mailjet.com/v3.1/send",
        },
    }


def _contact_email_failure_message(error: str) -> str:
    if "not configured" in error or "Set " in error:
        return f"Thanks. Your feedback was saved, but email is missing configuration: {error}"
    if "401" in error or "Unauthorized" in error:
        return "Thanks. Your feedback was saved, but Mailjet rejected the API credentials. Check MAILJET_API_KEY and MAILJET_SECRET_KEY."
    return f"Thanks. Your feedback was saved, but Mailjet email delivery failed: {error}"


def _build_contact_body(contact_record: dict) -> str:
    return "\n".join([
        "New CodeVal feedback",
        "",
        f"Time: {contact_record.get('timestamp', '')}",
        f"Name: {contact_record.get('name', '')}",
        f"Email: {contact_record.get('email', '')}",
        f"Phone: {contact_record.get('phone', '')}",
        f"Company: {contact_record.get('company', '')}",
        f"Source: {contact_record.get('source', '')}",
        "",
        "Message:",
        contact_record.get("message", ""),
    ])


def send_contact_email(contact_record: dict):
    subject_name = contact_record.get("name") or contact_record.get("email") or "Dashboard user"
    subject = f"CodeVal feedback from {subject_name}"
    body = _build_contact_body(contact_record)
    reply_to = contact_record.get("email", "").strip()
    recipient = os.getenv("CONTACT_TO_EMAIL", CONTACT_TO_EMAIL).strip()
    api_key = os.getenv("MAILJET_API_KEY", "").strip()
    secret_key = os.getenv("MAILJET_SECRET_KEY", "").strip()
    from_email = os.getenv("MAILJET_FROM_EMAIL", "").strip()
    from_name = os.getenv("MAILJET_FROM_NAME", "CodeVal").strip()
    missing = []
    if not api_key:
        missing.append("MAILJET_API_KEY")
    if not secret_key:
        missing.append("MAILJET_SECRET_KEY")
    if not from_email:
        missing.append("MAILJET_FROM_EMAIL")
    if not recipient:
        missing.append("CONTACT_TO_EMAIL")
    if missing:
        return False, f"Mailjet is not configured. Missing: {', '.join(missing)}."

    message = {
        "From": {"Email": from_email, "Name": from_name},
        "To": [{"Email": recipient}],
        "Subject": subject,
        "TextPart": body,
    }
    if reply_to:
        message["ReplyTo"] = {"Email": reply_to}

    try:
        response = requests.post(
            "https://api.mailjet.com/v3.1/send",
            auth=(api_key, secret_key),
            json={"Messages": [message]},
            timeout=20,
        )
        if response.status_code == 200:
            return True, ""
        return False, f"Mailjet error {response.status_code}: {response.text}"
    except Exception as e:
        logger.warning("Contact email delivery failed through Mailjet: %s", e)
        return False, f"{type(e).__name__}: {e}"


@app.post("/contact")
def contact(req: ContactRequest):
    if not req.message.strip():
        raise HTTPException(status_code=400, detail="Message is required")

    contact_record = {
        "timestamp": datetime.now().isoformat(),
        "name": req.name.strip(),
        "email": req.email.strip(),
        "phone": req.phone.strip(),
        "company": req.company.strip(),
        "message": req.message.strip(),
        "source": "dashboard_or_site",
    }

    CONTACT_MESSAGES_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(CONTACT_MESSAGES_PATH, "a", encoding="utf-8") as f:
        f.write(json.dumps(contact_record, ensure_ascii=True) + "\n")

    email_sent, email_error = send_contact_email(contact_record)
    if email_sent:
        return {"ok": True, "email_sent": True, "message": "Thanks. Your feedback was sent."}
    email_debug = _contact_email_debug_config()
    email_debug["error"] = email_error
    logger.warning("Contact feedback saved, but email was not sent. Debug: %s", email_debug)
    return {
        "ok": True,
        "email_sent": False,
        "message": _contact_email_failure_message(email_error),
        "email_error": email_error,
        "email_debug": email_debug,
    }


@app.post("/code-notes")
def add_code_note(req: CodeNoteRequest):
    if not req.owner_name or not req.repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    note_text = req.note.strip()
    if not note_text:
        raise HTTPException(status_code=400, detail="Note is required")

    repo_id = short_id(req.owner_name, req.repo_name)
    output_repo_dir = BASE_OUTPUT / repo_id
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    repo_comments_read_path = repo_text_artifact_path(output_repo_dir, "repo_comments.json", legacy_ok=True)
    repo_comments_path = repo_text_artifact_path(output_repo_dir, "repo_comments.json")

    if repo_comments_read_path.exists():
        with repo_comments_read_path.open("r", encoding="utf-8") as f:
            repo_comments = json.load(f)
    else:
        repo_comments = {
            "comment_count": 0,
            "todo_count": 0,
            "files_with_comments_count": 0,
            "supported_comment_forms": ["//", "#", "/* */", "<!-- -->", "dashboard note"],
            "comments": [],
            "todos": [],
            "text_items": [],
        }

    now = datetime.now().isoformat()
    note = {
        "kind": "note",
        "source": "dashboard",
        "timestamp": now,
        "query": req.query.strip(),
        "symbol": req.symbol.strip(),
        "file": req.file.strip(),
        "line": req.line,
        "text": note_text,
    }

    repo_comments.setdefault("user_notes", []).append(note)
    repo_comments.setdefault("text_items", []).append(note)
    repo_comments.setdefault("comments", []).append({
        "file": note["file"],
        "line": note["line"],
        "kind": "note",
        "text": note_text,
        "source": "dashboard",
        "symbol": note["symbol"],
        "timestamp": now,
    })
    repo_comments["comment_count"] = len(repo_comments.get("comments", []))
    repo_comments["text_item_count"] = len(repo_comments.get("text_items", []))

    repo_comments_path.parent.mkdir(parents=True, exist_ok=True)
    repo_comments_path.write_text(json.dumps(repo_comments, indent=2), encoding="utf-8")
    return {
        "ok": True,
        "note": note,
        "repo_comments": repo_comments,
        "repo_comments_url": output_url(repo_comments_path),
    }


def empty_repo_comments():
    return {
        "comment_count": 0,
        "todo_count": 0,
        "files_with_comments_count": 0,
        "supported_comment_forms": ["//", "#", "/* */", "<!-- -->", "dashboard note", "dashboard todo"],
        "comments": [],
        "todos": [],
        "text_items": [],
    }


def load_repo_comments_for_output(output_repo_dir: Path):
    repo_comments_read_path = repo_text_artifact_path(output_repo_dir, "repo_comments.json", legacy_ok=True)
    repo_comments_path = repo_text_artifact_path(output_repo_dir, "repo_comments.json")
    if repo_comments_read_path.exists():
        with repo_comments_read_path.open("r", encoding="utf-8") as f:
            return json.load(f), repo_comments_path
    return empty_repo_comments(), repo_text_artifact_path(output_repo_dir, "repo_comments.json")


def save_user_todo_artifacts(output_repo_dir: Path, repo_comments: dict):
    scim_dir = output_repo_dir / "scim"
    scim_dir.mkdir(parents=True, exist_ok=True)
    user_todos = [item for item in repo_comments.get("todos", []) if item.get("source") == "dashboard"]
    payload = {
        "kind": "user_todos",
        "updated_at": datetime.now().isoformat(),
        "count": len(user_todos),
        "items": user_todos,
    }
    todo_path = scim_dir / "user_todos.json"
    todo_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    jsonl_path = scim_dir / "user_todos.jsonl"
    with jsonl_path.open("w", encoding="utf-8") as handle:
        for item in user_todos:
            handle.write(json.dumps(item, separators=(",", ":")) + "\n")
    return todo_path, jsonl_path


def authorize_todo_analysis_run(request: Request, owner: str, repo: str, analysis_run_id: str, restore_token: str):
    analysis_run_id = str(analysis_run_id or "").strip()
    if not analysis_run_id:
        return None, None, "analysis_run_id is required for durable TODO storage"
    client = supabase_runtime_client()
    if not client:
        return None, None, "Supabase client is unavailable"
    run = supabase_run_by_id(client, analysis_run_id)
    if not run:
        return client, None, "saved analysis run was not found"
    repository = run.get("codeval_repositories") or {}
    if str(repository.get("owner_name") or "") != owner or str(repository.get("repo_name") or "") != repo:
        return client, None, "saved analysis run does not match the selected repository"
    token_ok, token_reason = search_restore_token_authorizes(restore_token, run, owner, repo)
    session_ok, session_reason, github_user_id = github_request_authorizes_analysis_run(request, client, run)
    if not token_ok and not session_ok:
        return client, None, f"not authorized to access TODOs: {token_reason or session_reason}"
    return client, {
        **run,
        "authorized_github_user_id": github_user_id if session_ok else run.get("github_user_id"),
    }, ""


def todo_target_url(repository: dict, scope: str, file_path: str = "", line: int | None = None):
    repo_url = str(repository.get("html_url") or "").rstrip("/")
    if not repo_url:
        return ""
    if scope == "product" or not file_path:
        return repo_url
    branch = str(repository.get("default_branch") or "main")
    encoded_path = "/".join(
        quote(part, safe="")
        for part in str(file_path).replace("\\", "/").split("/")
        if part
    )
    url = f"{repo_url}/blob/{quote(branch, safe='')}/{encoded_path}"
    if line:
        url += f"#L{int(line)}"
    return url


def supabase_todo_rows(client, run: dict):
    if not client or not run:
        return []
    response = supabase_execute(
        "TODO rows lookup",
        lambda: client.table("codeval_todos")
        .select("*")
        .eq("repository_id", run.get("repository_id"))
        .order("created_at")
        .execute(),
    )
    return getattr(response, "data", None) or []


def todo_row_to_comment(row: dict):
    return {
        "id": row.get("id"),
        "tag": "TODO",
        "kind": "todo",
        "scope": row.get("scope") or "product",
        "source": "dashboard",
        "timestamp": row.get("created_at") or row.get("updated_at"),
        "file": row.get("file_path") or "",
        "line": row.get("line"),
        "symbol": row.get("symbol") or "",
        "text": row.get("todo_text") or "",
        "target_url": row.get("target_url") or "",
        "supabase": True,
    }


def merge_supabase_todos_into_comments(repo_comments: dict, rows: list[dict]):
    merged = dict(repo_comments or empty_repo_comments())
    todos = list(merged.get("todos") or [])
    known_ids = {str(item.get("id") or "") for item in todos if item.get("id")}
    known_fingerprints = {
        (
            str(item.get("scope") or ""),
            str(item.get("file") or ""),
            str(item.get("symbol") or ""),
            str(item.get("text") or ""),
        )
        for item in todos
    }
    for row in rows or []:
        item = todo_row_to_comment(row)
        fingerprint = (item["scope"], item["file"], item["symbol"], item["text"])
        if str(item.get("id") or "") in known_ids or fingerprint in known_fingerprints:
            continue
        todos.append(item)
        known_ids.add(str(item.get("id") or ""))
        known_fingerprints.add(fingerprint)
    merged["todos"] = todos
    merged["todo_count"] = len(todos)
    return merged


@app.get("/todo-targets")
def todo_targets(
    request: Request,
    owner_name: str,
    repo_name: str,
    analysis_run_id: str = "",
    search_restore_token: str = "",
):
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    functions_path = find_scim_functions_path(output_repo_dir)
    restore_result = {}
    client = None
    run = None
    auth_error = ""
    if analysis_run_id:
        client, run, auth_error = authorize_todo_analysis_run(
            request,
            owner_name,
            repo_name,
            analysis_run_id,
            search_restore_token,
        )
    if not functions_path and analysis_run_id:
        restore_result = restore_analysis_artifacts_for_search_run_id(
            analysis_run_id,
            owner_name,
            repo_name,
            request,
            search_restore_token,
        )
        functions_path = find_scim_functions_path(output_repo_dir)
    records = load_scim_function_records(functions_path.parent) if functions_path else {}
    files = defaultdict(list)
    def line_sort_value(item):
        try:
            return int(item.get("start_line") or 0)
        except (TypeError, ValueError):
            return 0

    for symbol, record in records.items():
        path = str(record.get("path") or "").strip()
        if not path:
            continue
        files[path].append({
            "symbol": symbol,
            "path": path,
            "start_line": record.get("start_line"),
            "end_line": record.get("end_line"),
            "signature": first_code_line(record),
        })
    existing_symbols = {
        item.get("symbol")
        for functions in files.values()
        for item in functions
    }
    for path, symbols in load_graph_symbols_by_file(output_repo_dir).items():
        for symbol in sorted(symbols):
            if symbol in existing_symbols:
                continue
            files[path].append({
                "symbol": symbol,
                "path": path,
                "start_line": None,
                "end_line": None,
                "signature": "Graph node",
            })
            existing_symbols.add(symbol)
    repo_comments, _ = load_repo_comments_for_output(output_repo_dir)
    if client and run:
        repo_comments = merge_supabase_todos_into_comments(repo_comments, supabase_todo_rows(client, run))
    return {
        "count": len(records),
        "restore_result": restore_result,
        "authorization_error": auth_error,
        "repo_comments": repo_comments,
        "files": [
            {
                "path": path,
                "functions": sorted(functions, key=lambda item: (line_sort_value(item), item.get("symbol", ""))),
            }
            for path, functions in sorted(files.items())
        ],
    }


@app.post("/user-todos")
def add_user_todo(request: Request, req: UserTodoRequest):
    if not req.owner_name or not req.repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    todo_text = req.text.strip()
    if not todo_text:
        raise HTTPException(status_code=400, detail="TODO text is required")
    scope = req.scope.strip().lower()
    if scope not in {"product", "file", "function"}:
        raise HTTPException(status_code=400, detail="scope must be product, file, or function")
    if scope in {"file", "function"} and not req.file.strip():
        raise HTTPException(status_code=400, detail="file is required for file/function TODOs")
    if scope == "function" and not req.symbol.strip():
        raise HTTPException(status_code=400, detail="symbol is required for function TODOs")

    client, run, auth_error = authorize_todo_analysis_run(
        request,
        req.owner_name,
        req.repo_name,
        req.analysis_run_id,
        req.search_restore_token,
    )
    if auth_error:
        raise HTTPException(status_code=403 if client else 503, detail=auth_error)

    output_repo_dir = repo_output_dir(req.owner_name, req.repo_name)
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    repo_comments, repo_comments_path = load_repo_comments_for_output(output_repo_dir)
    now = datetime.now().isoformat()
    todo_id = str(uuid.uuid4())
    repository = run.get("codeval_repositories") or {}
    target_url = todo_target_url(repository, scope, req.file.strip(), req.line)
    todo = {
        "id": todo_id,
        "tag": "TODO",
        "kind": "todo",
        "scope": scope,
        "source": "dashboard",
        "timestamp": now,
        "file": req.file.strip(),
        "line": req.line,
        "symbol": req.symbol.strip(),
        "text": todo_text,
        "target_url": target_url,
        "supabase": True,
    }
    todo_row = {
        "id": todo_id,
        "analysis_run_id": run.get("id"),
        "repository_id": run.get("repository_id"),
        "github_user_id": run.get("authorized_github_user_id") or run.get("github_user_id"),
        "scope": scope,
        "file_path": todo["file"],
        "symbol": todo["symbol"],
        "line": todo["line"],
        "todo_text": todo_text,
        "target_url": target_url,
        "status": "open",
        "created_at": now,
        "updated_at": now,
    }
    todo_response = supabase_execute(
        "TODO insert",
        lambda: client.table("codeval_todos").insert(todo_row).execute(),
    )
    todo_rows = getattr(todo_response, "data", None) or []
    if not todo_rows:
        raise HTTPException(
            status_code=503,
            detail="TODO could not be saved to Supabase. Apply supabase_schema.sql so codeval_todos exists.",
        )
    repo_comments.setdefault("todos", []).append(todo)
    repo_comments.setdefault("text_items", []).append(todo)
    repo_comments.setdefault("comments", []).append({
        "file": todo["file"],
        "line": todo["line"],
        "kind": "todo",
        "scope": scope,
        "text": todo_text,
        "source": "dashboard",
        "symbol": todo["symbol"],
        "timestamp": now,
    })
    repo_comments["todo_count"] = len(repo_comments.get("todos", []))
    repo_comments["comment_count"] = len(repo_comments.get("comments", []))
    repo_comments["text_item_count"] = len(repo_comments.get("text_items", []))
    repo_comments_path.parent.mkdir(parents=True, exist_ok=True)
    repo_comments_path.write_text(json.dumps(repo_comments, indent=2), encoding="utf-8")
    todo_path, jsonl_path = save_user_todo_artifacts(output_repo_dir, repo_comments)
    return {
        "ok": True,
        "todo": todo,
        "repo_comments": repo_comments,
        "repo_comments_url": output_url(repo_comments_path),
        "user_todos_url": output_url(todo_path),
        "user_todos_jsonl_url": output_url(jsonl_path),
        "supabase_todo": todo_rows[0],
    }


@app.get("/user-todos")
def list_user_todos(
    request: Request,
    owner_name: str,
    repo_name: str,
    analysis_run_id: str = "",
    search_restore_token: str = "",
):
    client, run, auth_error = authorize_todo_analysis_run(
        request,
        owner_name,
        repo_name,
        analysis_run_id,
        search_restore_token,
    )
    if auth_error:
        raise HTTPException(status_code=403 if client else 503, detail=auth_error)
    rows = supabase_todo_rows(client, run)
    todos = [
        {
            "id": row.get("id"),
            "scope": row.get("scope") or "product",
            "file": row.get("file_path") or "",
            "symbol": row.get("symbol") or "",
            "line": row.get("line"),
            "text": row.get("todo_text") or "",
            "target_url": row.get("target_url") or "",
            "status": row.get("status") or "open",
            "created_at": row.get("created_at") or "",
        }
        for row in rows
        if str(row.get("status") or "open") != "deleted"
    ]
    return {"ok": True, "todos": todos, "count": len(todos)}


class DeleteUserTodoRequest(BaseModel):
    owner_name: str
    repo_name: str
    analysis_run_id: str = ""
    search_restore_token: str = ""
    todo_id: str


@app.post("/user-todos/delete")
def delete_user_todo(request: Request, req: DeleteUserTodoRequest):
    if not req.todo_id.strip():
        raise HTTPException(status_code=400, detail="todo_id is required")
    client, run, auth_error = authorize_todo_analysis_run(
        request,
        req.owner_name,
        req.repo_name,
        req.analysis_run_id,
        req.search_restore_token,
    )
    if auth_error:
        raise HTTPException(status_code=403 if client else 503, detail=auth_error)
    response = supabase_execute(
        "TODO delete",
        lambda: client.table("codeval_todos")
        .delete()
        .eq("id", req.todo_id.strip())
        .eq("repository_id", run.get("repository_id"))
        .execute(),
    )
    deleted_rows = getattr(response, "data", None) or []
    if not deleted_rows:
        raise HTTPException(status_code=404, detail="TODO not found for this repository")
    output_repo_dir = repo_output_dir(req.owner_name, req.repo_name)
    repo_comments, repo_comments_path = load_repo_comments_for_output(output_repo_dir)
    remaining_todos = [
        item for item in (repo_comments.get("todos") or [])
        if str(item.get("id") or "") != req.todo_id.strip()
    ]
    if len(remaining_todos) != len(repo_comments.get("todos") or []):
        repo_comments["todos"] = remaining_todos
        repo_comments["todo_count"] = len(remaining_todos)
        repo_comments_path.parent.mkdir(parents=True, exist_ok=True)
        repo_comments_path.write_text(json.dumps(repo_comments, indent=2), encoding="utf-8")
    return {"ok": True, "deleted_id": req.todo_id.strip()}


@app.post("/scoped-callgraph")
def scoped_callgraph(req: ScopedCallgraphRequest):
    if not req.owner_name or not req.repo_name:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    output_repo_dir = repo_output_dir(req.owner_name, req.repo_name)
    functions_path = find_scim_functions_path(output_repo_dir)
    records = load_scim_function_records(functions_path.parent) if functions_path else {}
    selected_file = req.file.strip()
    selected_symbol = req.symbol.strip()
    scope = str(getattr(req, "scope", "") or "related").strip().lower()
    current_file_only = scope in {"current_file", "file", "selected_file"}
    graph_symbols_by_file = load_graph_symbols_by_file(output_repo_dir)
    selected_graph_symbols = graph_symbols_for_selected_file(graph_symbols_by_file, selected_file)
    if (
        selected_file and
        not any(file_path_matches(str(record.get("path") or ""), selected_file) for record in records.values()) and
        not selected_graph_symbols
    ):
        raise HTTPException(status_code=404, detail=f"No functions found for file {selected_file}")

    callgraph, source = load_scoped_callgraph(output_repo_dir)
    _, functions, outgoing, incoming, edge_meta = callgraph_indexes(callgraph)
    file_symbols = [
        symbol for symbol, record in records.items()
        if not selected_file or file_path_matches(str(record.get("path") or ""), selected_file)
    ]
    if selected_file:
        file_symbols.extend(sorted(selected_graph_symbols))
    selected_graph_symbol = str(getattr(req, "graph_symbol", "") or "").strip()
    roots = [item for item in (selected_graph_symbol, selected_symbol) if item] if (selected_graph_symbol or selected_symbol) else file_symbols
    root_set = resolve_search_graph_roots(roots, functions)
    if selected_symbol and not root_set:
        root_set = resolve_search_graph_roots([selected_symbol.rsplit(".", 1)[-1]], functions)
    if selected_graph_symbol and not root_set:
        root_set = resolve_search_graph_roots([selected_graph_symbol.rsplit(".", 1)[-1]], functions)
    if not root_set:
        raise HTTPException(status_code=404, detail="Selected file/function did not match the callgraph.")
    allowed_nodes = set()
    if current_file_only:
        allowed_nodes.update(resolve_search_graph_roots(file_symbols, functions))
        allowed_nodes.update(symbol for symbol in selected_graph_symbols if symbol in functions)
        allowed_nodes.update(node for node in root_set if node in functions)
        if not allowed_nodes:
            raise HTTPException(status_code=404, detail="No graph nodes were found for the selected file.")

    def scoped_edge_allowed(src, dst):
        if not current_file_only:
            return True
        # Current-file scope means the selected file is the anchor. Keep direct
        # cross-file calls so a file with no same-file callees does not collapse
        # to a single node, but only expand traversal through selected-file nodes.
        return src in allowed_nodes or dst in allowed_nodes

    max_depth = max(1, min(int(req.depth or 1), 5))
    nodes = set()
    edges = set()
    start_node = ""
    if selected_symbol:
        queue = deque((root, 0) for root in root_set)
        nodes.update(root_set)
        visited = set(root_set)
        while queue and len(nodes) < 260:
            current, distance = queue.popleft()
            if distance >= max_depth:
                continue
            related = [(current, child) for child in outgoing.get(current, [])]
            related += [(parent, current) for parent in incoming.get(current, [])]
            related.sort(key=lambda edge: (
                edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
                edge[0],
                edge[1],
            ))
            for src, dst in related:
                if len(nodes) >= 260:
                    break
                if not scoped_edge_allowed(src, dst):
                    continue
                if not should_include_search_graph_node(src) or not should_include_search_graph_node(dst):
                    continue
                edges.add((src, dst))
                for node in (src, dst):
                    nodes.add(node)
                    if node not in visited and (not current_file_only or node in allowed_nodes):
                        visited.add(node)
                        queue.append((node, distance + 1))
    else:
        start_node = scoped_file_start_node(root_set, functions, outgoing, incoming)
        if not start_node:
            raise HTTPException(status_code=404, detail="No start node was found for the selected file.")
        root_set = {start_node}
        nodes.add(start_node)
        queue = deque([(start_node, 0)])
        visited = {start_node}
        while queue and len(nodes) < 260:
            current, distance = queue.popleft()
            if distance >= max_depth:
                continue
            related = [(current, child) for child in outgoing.get(current, [])]
            related += [(parent, current) for parent in incoming.get(current, [])]
            related.sort(key=lambda edge: (
                edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
                edge[0],
                edge[1],
            ))
            for src, dst in related:
                if len(nodes) >= 260:
                    break
                if not scoped_edge_allowed(src, dst):
                    continue
                if not should_include_search_graph_node(src) or not should_include_search_graph_node(dst):
                    continue
                edges.add((src, dst))
                for node in (src, dst):
                    nodes.add(node)
                    if node not in visited and (not current_file_only or node in allowed_nodes):
                        visited.add(node)
                        queue.append((node, distance + 1))

    if not nodes:
        raise HTTPException(status_code=404, detail="No scoped callgraph nodes were found.")

    full_nodes = {
        node
        for node in functions
        if should_include_search_graph_node(node)
    }
    full_edge_pairs = {
        (src, dst)
        for src, children in outgoing.items()
        for dst in children
        if should_include_search_graph_node(src) and should_include_search_graph_node(dst)
    }
    if current_file_only:
        full_edge_pairs = {
            (src, dst)
            for src, dst in full_edge_pairs
            if scoped_edge_allowed(src, dst)
        }
        adjacent_nodes = {node for edge in full_edge_pairs for node in edge}
        full_nodes = {node for node in full_nodes if node in allowed_nodes or node in adjacent_nodes}
        nodes = {node for node in nodes if node in allowed_nodes or node in adjacent_nodes}
        edges = {
            (src, dst)
            for src, dst in edges
            if scoped_edge_allowed(src, dst)
        }
        if not nodes:
            nodes.update(sorted(root_set & allowed_nodes)[:1] or sorted(allowed_nodes)[:1])
    graph_edges = [
        (src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line"))
        for src, dst in sorted(edges, key=lambda edge: (
            edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
            edge[0],
            edge[1],
        ))
    ]
    full_graph_edges = [
        (src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line"))
        for src, dst in sorted(full_edge_pairs, key=lambda edge: (
            edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
            edge[0],
            edge[1],
        ))
    ]
    process_root = start_node or sorted(root_set)[0]
    process_steps = []
    process_incoming_steps = []
    process_edges = [
        (process_root, child)
        for child in outgoing.get(process_root, [])
        if (process_root, child) in full_edge_pairs
        and should_include_search_graph_node(child)
        and scoped_edge_allowed(process_root, child)
    ]
    process_edges.sort(key=lambda edge: (
        edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
        edge_meta.get(edge, {}).get("line") if edge_meta.get(edge, {}).get("line") is not None else 10**12,
        edge[1],
    ))
    seen_process_children = set()
    for src, dst in process_edges:
        if dst in seen_process_children:
            continue
        seen_process_children.add(dst)
        meta = edge_meta.get((src, dst), {})
        process_steps.append({
            "source": src,
            "target": dst,
            "label": display_callgraph_symbol(dst),
            "order": meta.get("order"),
            "line": meta.get("line"),
        })
        if len(process_steps) >= 80:
            break
    incoming_process_edges = [
        (parent, process_root)
        for parent in incoming.get(process_root, [])
        if (parent, process_root) in full_edge_pairs
        and should_include_search_graph_node(parent)
        and scoped_edge_allowed(parent, process_root)
    ]
    incoming_process_edges.sort(key=lambda edge: (
        edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
        edge_meta.get(edge, {}).get("line") if edge_meta.get(edge, {}).get("line") is not None else 10**12,
        edge[0],
    ))
    seen_process_parents = set()
    for src, dst in incoming_process_edges:
        if src in seen_process_parents:
            continue
        seen_process_parents.add(src)
        meta = edge_meta.get((src, dst), {})
        process_incoming_steps.append({
            "source": src,
            "target": dst,
            "label": display_callgraph_symbol(src),
            "order": meta.get("order"),
            "line": meta.get("line"),
        })
        if len(process_incoming_steps) >= 80:
            break

    label = selected_symbol or selected_file or "scoped_callgraph"
    scope_label = "Current File" if current_file_only else "Related"
    graph_slug = re.sub(r"[^A-Za-z0-9_.-]+", "_", f"{scope_label}_{label}").strip("_")[:80] or "scoped_callgraph"
    graph_url = build_navigatable_cytoscape_graph(
        sorted(full_nodes or nodes),
        full_graph_edges or graph_edges,
        output_repo_dir,
        graph_name=f"scoped_callgraph_{graph_slug}",
        graph_title=f"Scoped Callgraph ({scope_label}): {label}",
        initial_roots=[start_node] if start_node else sorted(root_set)[:1],
        entry_points=sorted(root_set),
        initial_visible_nodes=sorted(nodes),
        initial_visible_edges=graph_edges,
    )
    ordered_lr_graph_url = build_ordered_lr_callgraph(
        sorted(nodes),
        graph_edges,
        output_repo_dir,
        graph_name=f"scoped_ordered_lr_callgraph_{graph_slug}",
        graph_title=f"Ordered L-R Callgraph ({scope_label}): {label}",
        root=process_root,
        node_labels={node: display_callgraph_symbol(node) for node in nodes},
    )
    return {
        "ok": True,
        "source": source,
        "file": selected_file,
        "symbol": selected_symbol,
        "root_nodes": sorted(root_set),
        "node_count": len(nodes),
        "edge_count": len(edges),
        "depth": max_depth,
        "scope": "current_file" if current_file_only else "related",
        "process_root": process_root,
        "process_root_label": display_callgraph_symbol(process_root),
        "process_steps": process_steps,
        "process_incoming_steps": process_incoming_steps,
        "process_direction": "outgoing" if process_steps else ("incoming" if process_incoming_steps else "none"),
        "graph_url": graph_url,
        "graph_json_url": graph_url[:-5] + ".json" if graph_url.endswith(".html") else "",
        "ordered_lr_graph_url": ordered_lr_graph_url,
        "ordered_lr_graph_json_url": ordered_lr_graph_url[:-5] + ".json" if ordered_lr_graph_url.endswith(".html") else "",
    }


def repo_output_dir(owner_name: str, repo_name: str):
    return BASE_OUTPUT / short_id(owner_name, repo_name)


def analysis_artifact_belongs_to_repo(candidate_dir: Path, owner_name: str, repo_name: str) -> bool:
    candidate_dir = Path(candidate_dir)
    expected_full_name = f"{owner_name}/{repo_name}"
    repo_stats_path = ensure_repo_text_artifact_path(candidate_dir, "repo_stats.json")
    if repo_stats_path.exists():
        try:
            stats = json.loads(repo_stats_path.read_text(encoding="utf-8", errors="ignore"))
            full_name = str(
                stats.get("repo_full_name")
                or (stats.get("known_from_github_repo_metadata") or {}).get("full_name")
                or ""
            ).strip()
            if full_name == expected_full_name:
                return True
        except Exception as e:
            logger.warning("Unable to validate mirrored repo_stats.json at %s: %s", repo_stats_path, e)

    code_md_path = candidate_dir / "CODE.md"
    if code_md_path.exists():
        try:
            preview = code_md_path.read_text(encoding="utf-8", errors="ignore")[:1000]
            return f"Generated for {expected_full_name} " in preview
        except Exception as e:
            logger.warning("Unable to validate mirrored CODE.md at %s: %s", code_md_path, e)
    return False


def materialize_mirrored_analysis_output(
    mirror_dir_value: str,
    output_repo_dir: Path,
    owner_name: str,
    repo_name: str,
):
    """Adopt a workspace .codemd mirror for local companion-server graphing.

    The VS Code extension can generate artifacts with the one-shot CLI and
    mirror them into the workspace, then later start a fresh FastAPI companion
    whose private BASE_OUTPUT cache is empty. Copying the validated mirror back
    under BASE_OUTPUT keeps the existing /.codemd static URL behavior.
    """
    mirror_dir_value = str(mirror_dir_value or "").strip()
    if not mirror_dir_value:
        return {"materialized": False, "reason": "no mirror path provided"}

    mirror_dir = Path(mirror_dir_value).expanduser()
    if not mirror_dir.exists() or not mirror_dir.is_dir():
        return {"materialized": False, "reason": "mirror path does not exist", "mirror_dir": str(mirror_dir)}
    if not analysis_artifact_belongs_to_repo(mirror_dir, owner_name, repo_name):
        return {
            "materialized": False,
            "reason": "mirror metadata does not match selected repository",
            "mirror_dir": str(mirror_dir),
        }

    artifact_root = artifact_root_for_output(mirror_dir)
    if not any(
        (artifact_root / rel_path).exists()
        for rel_path in (
            Path("combined_callgraph") / "combined_callgraph.json",
            Path("python") / "python_callgraph.json",
            Path("javascript") / "javascript_callgraph.json",
            Path("html_ui") / "html_ui_graph.json",
        )
    ):
        return {
            "materialized": False,
            "reason": "mirror does not contain a usable callgraph artifact",
            "mirror_dir": str(mirror_dir),
        }

    output_repo_dir = Path(output_repo_dir)
    try:
        if mirror_dir.resolve() == output_repo_dir.resolve():
            return {"materialized": True, "reason": "mirror already is output directory", "mirror_dir": str(mirror_dir)}
    except Exception:
        pass

    output_repo_dir.parent.mkdir(parents=True, exist_ok=True)
    shutil.copytree(mirror_dir, output_repo_dir, dirs_exist_ok=True)
    return {
        "materialized": True,
        "reason": "copied workspace mirror into companion output cache",
        "mirror_dir": str(mirror_dir),
        "output_repo_dir": str(output_repo_dir),
    }


def output_has_usable_search_callgraph(output_repo_dir: Path) -> bool:
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    return any(
        (artifact_root / rel_path).exists()
        for rel_path in (
            Path("combined_callgraph") / "combined_ordered_call_sequence.json",
            Path("combined_callgraph") / "combined_callgraph.json",
            Path("combined_callgraph") / "combined_navigatable_callgraph.json",
            Path("python") / "python_ordered_call_sequence.json",
            Path("python") / "python_callgraph.json",
            Path("javascript") / "javascript_ordered_call_sequence.json",
            Path("javascript") / "javascript_callgraph.json",
            Path("html_ui") / "html_ui_graph.json",
        )
    )





from pathlib import Path


def source_root_for_output(output_repo_dir):

    output_repo_path = Path(output_repo_dir)

    # ----------------------------------------
    # preferred extracted source dir
    # ----------------------------------------

    candidate = output_repo_path / "src"

    if candidate.exists() and candidate.is_dir():
        return candidate

    # ----------------------------------------
    # nested source dir
    # ----------------------------------------

    nested = (
        output_repo_path
        / output_repo_path.name
        / "src"
    )

    if nested.exists() and nested.is_dir():
        return nested

    # ----------------------------------------
    # fallback
    # ----------------------------------------

    return output_repo_path


def find_scim_functions_path(output_repo_dir: Path):
    artifact_root = artifact_root_for_output(output_repo_dir)
    candidates = [
        artifact_root / "scim" / "functions.jsonl",
        output_repo_dir / "scim" / "functions.jsonl",
        output_repo_dir / output_repo_dir.name / "scim" / "functions.jsonl",
    ]
    for candidate in candidates:
        if candidate.exists():
            return candidate
    return None


def load_graph_symbols_by_file(output_repo_dir: Path):
    artifact_root = artifact_root_for_output(output_repo_dir)
    paths = [
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "csharp" / "csharp_callgraph.json",
        artifact_root / "java_merged" / "java_merged_callgraph.json",
        artifact_root / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        artifact_root / "javalang" / "javalang_callgraph.json",
        artifact_root / "html_ui" / "html_ui_graph.json",
    ]
    by_file = defaultdict(set)
    for path in paths:
        if not path.exists():
            continue
        try:
            graph = json.loads(path.read_text(encoding="utf-8", errors="ignore"))
        except Exception:
            continue
        function_files = graph.get("function_files", {}) if isinstance(graph, dict) else {}
        for symbol, file_path in function_files.items():
            if symbol and file_path:
                by_file[str(file_path).replace("\\", "/")].add(str(symbol))

        if path.name == "html_ui_graph.json" and isinstance(graph, dict):
            for element in graph.get("elements") or []:
                if not isinstance(element, dict):
                    continue
                file_path = str(element.get("file") or "").replace("\\", "/")
                symbol = str(element.get("symbol") or "")
                if file_path and symbol:
                    by_file[file_path].add(symbol)
            for detail in graph.get("edge_details") or []:
                if not isinstance(detail, dict):
                    continue
                file_path = str(detail.get("file") or "").replace("\\", "/")
                if not file_path:
                    continue
                for key in ("source", "target"):
                    symbol = str(detail.get(key) or "")
                    if symbol:
                        by_file[file_path].add(symbol)
    return by_file


def file_path_matches(candidate: str, selected_file: str):
    candidate = str(candidate or "").replace("\\", "/").strip("/")
    selected_file = str(selected_file or "").replace("\\", "/").strip("/")
    return bool(
        candidate and
        selected_file and
        (
            candidate == selected_file or
            candidate.endswith(f"/{selected_file}") or
            selected_file.endswith(f"/{candidate}")
        )
    )


def graph_symbols_for_selected_file(graph_symbols_by_file: dict, selected_file: str):
    symbols = set()
    for path, path_symbols in graph_symbols_by_file.items():
        if file_path_matches(path, selected_file):
            symbols.update(path_symbols or set())
    return symbols


def scoped_file_start_node(file_symbols, functions, outgoing, incoming):
    candidates = [
        symbol for symbol in sorted(set(file_symbols or []))
        if symbol in functions and should_include_search_graph_node(symbol)
    ]
    if not candidates:
        return ""

    preferred_names = {
        "main", "app", "start", "run", "handler", "route", "index",
        "search", "analyze", "dispatch", "execute", "process",
    }

    def score(symbol):
        tail = str(symbol).rsplit(".", 1)[-1].lower()
        out_degree = len(outgoing.get(symbol, []))
        in_degree = len(incoming.get(symbol, []))
        return (
            1 if tail in preferred_names else 0,
            1 if out_degree > 0 else 0,
            1 if in_degree == 0 else 0,
            min(out_degree, 60),
            -in_degree,
            -len(str(symbol)),
        )

    return max(candidates, key=score)


def unused_ok_path(output_repo_dir: Path):
    return output_repo_dir / "unused_functions_ok.json"


def load_unused_ok(output_repo_dir: Path):
    path = unused_ok_path(output_repo_dir)
    if not path.exists():
        return set()
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
        return set(data.get("symbols", []))
    except Exception:
        return set()


def save_unused_ok(output_repo_dir: Path, symbols):
    output_repo_dir.mkdir(parents=True, exist_ok=True)
    path = unused_ok_path(output_repo_dir)
    path.write_text(
        json.dumps({"symbols": sorted(symbols), "updated_at": datetime.now().isoformat()}, indent=2),
        encoding="utf-8",
    )


def unused_record_method_name(record):
    method_name = str(record.get("method_name", "") or "")
    if method_name and method_name != "<file>":
        return method_name
    symbol = str(record.get("symbol", "") or "")
    return symbol.rsplit(".", 1)[-1] if symbol else ""


def is_unused_function_candidate(record):
    symbol = str(record.get("symbol", "") or "")
    path = str(record.get("path", "") or "")
    method_name = unused_record_method_name(record)
    suffix = Path(path).suffix.lower()
    if not symbol or method_name == "<file>" or symbol.endswith(".<file>"):
        return False
    if suffix == ".py":
        if method_name.startswith(("visit_", "leave_", "enter_")):
            return False
        if method_name.startswith("__") and method_name.endswith("__"):
            return False
    if suffix not in {".py", ".java", ".kt", ".kts", ".js", ".jsx", ".ts", ".tsx", ".go", ".c", ".cc", ".cpp", ".h", ".hpp"}:
        return False
    return True


def has_python_decorator(record, artifact_root: Path):
    path = str(record.get("path", "") or "")
    if Path(path).suffix.lower() != ".py":
        return False
    try:
        start_line = int(record.get("start_line") or 0)
    except (TypeError, ValueError):
        return False
    if start_line <= 1:
        return False

    source_path = artifact_root / "src" / path
    if not source_path.exists():
        return False
    try:
        lines = source_path.read_text(encoding="utf-8", errors="ignore").splitlines()
    except OSError:
        return False

    index = min(start_line - 2, len(lines) - 1)
    while index >= 0:
        stripped = lines[index].strip()
        if not stripped:
            index -= 1
            continue
        return stripped.startswith("@")
    return False


def is_react_context_or_provider_record(record, artifact_root: Path):
    path = record_source_path(record)
    suffix = Path(path).suffix.lower()
    if suffix not in {".js", ".jsx", ".ts", ".tsx"}:
        return False
    symbol = str(record.get("symbol") or "")
    method_name = unused_record_method_name(record)
    if not symbol and not method_name:
        return False
    text, _ = read_source_text_for_record(record, artifact_root)
    if not text:
        return False
    name = method_name or function_tail(symbol)
    identity = f"{symbol} {method_name} {path}".lower()
    if name.endswith("Context") and re.search(rf"\b{re.escape(name)}\s*=\s*createContext\b", text):
        return True
    if name.endswith("Provider") and re.search(rf"\b{name}\b", text) and (".Provider" in text or "createContext" in text):
        return True
    if name.startswith("use") and re.match(r"^use[A-Z0-9_]", name):
        if "useContext(" in text or "createContext" in text or re.search(rf"\b{re.escape(name)}\s*\(", text):
            return True
    if "context" in identity and ("createContext" in text or ".Provider" in text or "useContext(" in text):
        return True
    return False


def is_dynamic_or_framework_entrypoint(record, artifact_root: Path):
    if has_python_decorator(record, artifact_root):
        return True
    if is_react_context_or_provider_record(record, artifact_root):
        return True
    return False


JS_DIRECTIVE_FRAMEWORK_ENTRYPOINT_RE = re.compile(r'^\s*["\']use (server|client)["\'];?\s*$', re.MULTILINE)


def file_has_directive_framework_entrypoint(source_root, rel_path: str) -> bool:
    """True if a JS/TS file opens with a `"use server"`/`"use client"` directive.
    Next.js treats every export in such a file as a framework-invoked entry point
    (a Server Action or a client boundary), so the absence of static incoming edges
    from other parsed code is expected, not a sign of dead/orphaned code."""
    if not source_root:
        return False
    suffix = Path(rel_path).suffix.lower()
    if suffix not in {".js", ".jsx", ".ts", ".tsx", ".mjs", ".cjs"}:
        return False
    try:
        candidate = Path(source_root) / rel_path
        text = candidate.read_text(encoding="utf-8", errors="ignore")[:200]
    except OSError:
        return False
    return bool(JS_DIRECTIVE_FRAMEWORK_ENTRYPOINT_RE.search(text))


def load_unused_callgraph_index(artifact_root: Path):
    graph_paths = [
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "java_merged" / "java_merged_callgraph.json",
        artifact_root / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        artifact_root / "javalang" / "javalang_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "joern" / "reduced_joern_callgraph.json",
        artifact_root / "joern" / "joern_callgraph_ordered.json",
        artifact_root / "joern" / "joern_callgraph.json",
    ]
    nodes = set()
    incoming = defaultdict(set)
    outgoing = defaultdict(set)
    sources = []

    def add_ordered_joern_nodes(path: Path):
        try:
            data = json.loads(path.read_text(encoding="utf-8", errors="ignore"))
        except Exception:
            return set()
        ordered_nodes = set()
        if not isinstance(data, list):
            return ordered_nodes
        for item in data:
            if not isinstance(item, dict):
                continue
            method = item.get("method") or item.get("fullName")
            if method:
                ordered_nodes.add(str(method))
            for call in item.get("calls") or []:
                if not isinstance(call, dict):
                    continue
                callee = (
                    call.get("callee_fullName")
                    or call.get("callee")
                    or call.get("target")
                )
                if callee:
                    ordered_nodes.add(str(callee))
        return ordered_nodes

    for graph_path in graph_paths:
        if not graph_path.exists():
            continue
        graph_nodes, graph_edges = _load_edge_graph(str(graph_path))
        graph_nodes.update(add_ordered_joern_nodes(graph_path))
        for src, dst in graph_edges:
            outgoing[src].add(dst)
            incoming[dst].add(src)
        if graph_nodes:
            nodes.update(graph_nodes)
            sources.append(str(graph_path.relative_to(artifact_root)).replace("\\", "/"))

    return nodes, incoming, outgoing, sources


def resolve_unused_callgraph_symbol(symbol, callgraph_nodes):
    if not symbol or not callgraph_nodes:
        return ""
    if symbol in callgraph_nodes:
        return symbol
    matches = resolve_search_graph_roots([symbol], callgraph_nodes)
    return sorted(matches, key=len)[0] if matches else ""


