def extract_inline_comments(src):
    comments = []
    for tok in tokenize.generate_tokens(StringIO(src).readline):
        if tok.type == tokenize.COMMENT:
            comments.append({
                "line": tok.start[0],
                "text": tok.string.strip()
            })
    return comments


def extract_top_comments(src):
    top_comments = []
    lines = src.splitlines()

    for line in lines:
        stripped = line.strip()
        if stripped.startswith("#"):
            top_comments.append(stripped.lstrip("# ").strip())
        elif stripped == "":
            continue
        else:
            break

    return top_comments


def collect_user_defined_functions(ast_dir):
    user_funcs = set()
    for root, _, files in os.walk(ast_dir):
        for f in files:
            if not f.endswith(".ast.json"):
                continue
            path = os.path.join(root, f)
            try:
                with open(path, "r", encoding="utf-8", errors="ignore") as fh:
                    data = json.load(fh)
                for fn in data.get("functions", []):
                    user_funcs.add(fn)
            except Exception as e:
                print("Skipping bad AST file:", path, e)
    return user_funcs

def normalize(name: str) -> str:
    # Remove <metaClassAdapter>, <iterator>, <module>, etc.
    if "<" in name:
        name = name.split("<")[0]
    return name.strip()

def is_internal(name: str) -> bool:
    # Ignore Joern internal nodes
    return (
        name == "" or
        name.startswith("<") or
        name in {"module", "iterator"}
    )

def trim_callgraph_with_ast(output_dir, ast_dir):
    """
    Trim callgraph.json to keep only user-defined functions.
    Remove synthetic/internal calls like <module>, <iterator>, <lambda>0, <metaClassCallHandler>.
    """
    callgraph_path = os.path.join(output_dir, "callgraph.json")
    trimmed_path = os.path.join(output_dir, "callgraph_trim.json")

    if not os.path.exists(callgraph_path):
        print("callgraph.json not found!")
        return

    edges = json.load(open(callgraph_path, "r", encoding="utf-8"))
    user_funcs = collect_user_defined_functions(ast_dir)

    def is_valid_fn(name):
        if not name:
            return False
        if name in user_funcs:
            return True
        # filter synthetic / internal nodes
        return not name.startswith("<") and not name.startswith("_") and not name.startswith("lambda")

    trimmed_edges = []

    for e in edges:
        caller = normalize(e.get("caller", ""))
        callee = normalize(e.get("callee", ""))

        if not is_valid_fn(caller):
            continue
        if not is_valid_fn(callee):
            continue

        trimmed_edges.append({"caller": caller, "callee": callee})

    print("Sample Joern edges (raw):", edges[:20])
    print("Sample trimmed edges:", trimmed_edges[:20])

    with open(trimmed_path, "w", encoding="utf-8", errors="ignore") as f:
        json.dump(trimmed_edges, f, indent=2)

    print("Trimmed callgraph saved:", trimmed_path)
    print("User-defined functions:", len(user_funcs))
    print("Edges kept:", len(trimmed_edges))




def build_function_graph(output_dir):

    callgraph = json.load(open(
        os.path.join(output_dir, "callgraph_trim.json"),
        "r",
        encoding="utf-8"
    ))

    graph = {
        "nodes": set(),
        "edges": []
    }

    for e in callgraph:

        caller = e["caller"]
        callee = e["callee"]

        graph["nodes"].add(caller)
        graph["nodes"].add(callee)

        graph["edges"].append({
            "from": caller,
            "to": callee
        })

    graph["nodes"] = list(graph["nodes"])

    out = os.path.join(output_dir, "function_graph.json")

    json.dump(graph, open(out, "w", encoding="utf-8"), indent=2)

    print("Function graph written:", out)


def build_function_dependency_tree(output_dir):
    callgraph = json.load(open(
        os.path.join(output_dir, "callgraph_trim.json"),
        "r",
        encoding="utf-8"
    ))
    tree = {}
    for e in callgraph:
        caller = e["caller"]
        callee = e["callee"]
        if caller not in tree:
            tree[caller] = []

        tree[caller].append(callee)
    out = os.path.join(output_dir, "function_dependency_tree.json")
    json.dump(tree, open(out, "w", encoding="utf-8"), indent=2)
    print("Function dependency tree written:", out)
    return tree

