class CodeAnalyzer(ast.NodeVisitor):

    def __init__(self):
        self.functions = []              # includes class methods
        self.classes = []
        self.imports = []
        self.calls = []
        self.current_function = None
        self.function_docstrings = {}
        self.function_linenos = {}       # start/end/loc per function

    def visit_Import(self, node):
        for n in node.names:
            self.imports.append(n.name)

    def visit_ImportFrom(self, node: cst.ImportFrom):
        if isinstance(node.names, cst.ImportStar):
            # handle: from x import *
            print("Star import detected")
        else:
            # handle: from x import a, b
            for n in node.names:
                print(n.name.value)

    def visit_FunctionDef(self, node):
        fn_name = node.name
        self.functions.append(fn_name)

        fn_doc = ast.get_docstring(node)
        if fn_doc:
            self.function_docstrings[fn_name] = fn_doc.strip()

        self.function_linenos[fn_name] = {
            "start": node.lineno,
            "end": node.end_lineno,
            "loc": node.end_lineno - node.lineno + 1
        }

        prev = self.current_function
        self.current_function = fn_name
        self.generic_visit(node)
        self.current_function = prev

    def visit_ClassDef(self, node):
        class_name = node.name
        self.classes.append(class_name)

        for body_item in node.body:
            if isinstance(body_item, ast.FunctionDef):
                method_name = f"{class_name}.{body_item.name}"
                self.functions.append(method_name)

                fn_doc = ast.get_docstring(body_item)
                if fn_doc:
                    self.function_docstrings[method_name] = fn_doc.strip()

                self.function_linenos[method_name] = {
                    "start": body_item.lineno,
                    "end": body_item.end_lineno,
                    "loc": body_item.end_lineno - body_item.lineno + 1
                }

                prev = self.current_function
                self.current_function = method_name
                self.visit(body_item)
                self.current_function = prev

        self.generic_visit(node)

    def visit_Call(self, node):
        callee = self._resolve_callee(node.func)

        self.calls.append({
            "caller": self.current_function,
            "callee": callee
        })

        self.generic_visit(node)

    def _resolve_callee(self, func):
        if isinstance(func, ast.Name):
            return func.id
        if isinstance(func, ast.Attribute):
            return f"{self._resolve_name(func.value)}.{func.attr}"
        return "unknown"

    def _resolve_name(self, node):
        if isinstance(node, ast.Name):
            return node.id
        if isinstance(node, ast.Attribute):
            return f"{self._resolve_name(node.value)}.{node.attr}"
        return "unknown"




class FunctionCallAnalyzer(ast.NodeVisitor):

    def __init__(self):
        self.file_functions = {}
        self.function_calls = {}
        self.current_function = None

    def visit_FunctionDef(self, node):
        fname = node.name

        if fname not in self.function_calls:
            self.function_calls[fname] = []

        prev = self.current_function
        self.current_function = fname

        self.generic_visit(node)

        self.current_function = prev

    def visit_Call(self, node):

        if self.current_function is None:
            return

        if isinstance(node.func, ast.Name):
            callee = node.func.id

        elif isinstance(node.func, ast.Attribute):
            callee = node.func.attr

        else:
            callee = None

        if callee:
            self.function_calls[self.current_function].append(callee)

        self.generic_visit(node)




def cst_to_dict(node):
    if isinstance(node, cst.CSTNode):
        result = {"_type": node.__class__.__name__}
        for field in node._fields:
            value = getattr(node, field)
            result[field] = cst_to_dict(value)
        return result

    elif isinstance(node, list):
        return [cst_to_dict(item) for item in node]

    elif node is None:
        return None

    else:
        return str(node)




import libcst as cst
from libcst.metadata import PositionProvider, MetadataWrapper


# Helper to get full dotted name from an Attribute or Name
def get_full_name(node):
    if isinstance(node, cst.Name):
        return node.value
    elif isinstance(node, cst.Attribute):
        return get_full_name(node.value) + "." + node.attr.value
    return "<unknown>"

def analyze_code(src: str):
    """
    JSON-safe, libcst-based analyzer.
    Produces per-function call tracking for call graph construction.
    """
    # --- Parse safely ---
    try:
        module = cst.parse_module(src)
    except Exception:
        try:
            module = cst.parse_module(src, partial=True)
        except Exception:
            return {
                "functions": [],
                "classes": [],
                "imports": [],
                "calls": [],
                "function_calls": {},
                "dependencies": [],
                "module_docstring": None,
                "function_docstrings": {},
                "function_linenos": {},
                "inline_comments": [],
                "top_comments": [],
                "combined_file_description": None,
            }

    # --- Wrap module for metadata ---
    wrapper = MetadataWrapper(module)

    try:
        pos_map = wrapper.resolve(PositionProvider)
    except Exception:
        pos_map = {}

    functions = []
    classes = []
    imports = []
    calls = []
    function_calls = {}
    function_docstrings = {}
    function_linenos = {}

    # --- Extract comments ---
    inline_comments = []
    top_comments = []

    for line in src.splitlines():
        stripped = line.strip()
        if stripped.startswith("#"):
            top_comments.append(stripped[1:].strip())
        elif "#" in line:
            inline_comments.append(line.split("#", 1)[1].strip())

    # --- Extract module docstring ---
    module_doc = None
    if module.body and isinstance(module.body[0], cst.SimpleStatementLine):
        stmt = module.body[0].body[0]
        if isinstance(stmt, cst.Expr) and isinstance(stmt.value, cst.SimpleString):
            module_doc = stmt.value.evaluated_value

    # --- CST Visitor ---
    class Visitor(cst.CSTVisitor):
        METADATA_DEPENDENCIES = (PositionProvider,)
        
        def __init__(self):
            self.fn_stack = []
            self.class_stack = []
            self.calls = []
            self.function_calls = {}

        def visit_ClassDef(self, node):
            self.class_stack.append(node.name.value)
            classes.append(node.name.value)

        def leave_ClassDef(self, node):
            self.class_stack.pop()

        def visit_FunctionDef(self, node):
            # Compose name with class if inside class
            if self.class_stack:
                name = f"{self.class_stack[-1]}.{node.name.value}"
            else:
                name = node.name.value

            functions.append(name)
            self.fn_stack.append(name)
            self.function_calls[name] = []

            # Track decorator calls
            for dec in node.decorators:
                if isinstance(dec.decorator, cst.Call):
                    callee_name = get_full_name(dec.decorator.func)
                    self.calls.append(callee_name)
                    self.function_calls[name].append(callee_name)

        def leave_FunctionDef(self, node):
            self.fn_stack.pop()

        def visit_Call(self, node):
            try:
                callee_name = get_full_name(node.func)
                self.calls.append(callee_name)
                if self.fn_stack:
                    self.function_calls[self.fn_stack[-1]].append(callee_name)
            except Exception:
                pass




    # ✅ OUTSIDE CLASS
    visitor = Visitor()
    wrapper.visit(visitor)
    calls = visitor.calls
    function_calls = visitor.function_calls

    # Map calls outside any function to a <module> pseudo-function
    top_level_fn = "<module>"
    if top_level_fn not in function_calls:
        function_calls[top_level_fn] = []

    # Go through all calls and assign top-level calls
    for c in visitor.calls:
        # If call is already mapped in a function, skip
        if not any(c in v for k, v in function_calls.items() if k != top_level_fn):
            function_calls[top_level_fn].append(c)


    combined_file_description = []

    # Module docstring first
    if module_doc:
        combined_file_description.append(module_doc)

    # Top comments
    if top_comments:
        combined_file_description.append(" ".join(top_comments))

    # Maybe include functions
    if functions:
        combined_file_description.append("Functions: " + ", ".join(functions))

    combined_file_description = " ".join(combined_file_description) if combined_file_description else None

    return {
        "functions": functions,
        "classes": classes,
        "imports": imports,
        "calls": calls,
        "function_calls": function_calls,
        "dependencies": [],
        "module_docstring": module_doc,
        "function_docstrings": function_docstrings,
        "function_linenos": function_linenos,
        "inline_comments": inline_comments,
        "top_comments": top_comments,
        "combined_file_description": combined_file_description,
    } 


