def extract_zip(zip_path, extract_dir=None):
    """
    Safe ZIP extraction for GitHub repos.
    Handles:
    - missing parent dirs
    - illegal Windows characters
    - deep nested paths
    - zip-slip protection
    - overly long path components
    """
    if extract_dir is None:
        extract_dir = os.path.join(os.path.dirname(zip_path), "extracted")

    extract_root = os.path.abspath(extract_dir)
    os.makedirs(extract_root, exist_ok=True)

    def long_path(path):
        # Windows MAX_PATH is 260 chars; deeply nested archives (e.g. .gradle
        # caches) routinely exceed this even with sanitized components. The
        # \\?\ prefix opts into the extended-length path API so makedirs/open
        # don't fail with a misleading FileNotFoundError.
        if os.name != "nt":
            return path
        if path.startswith("\\\\?\\"):
            return path
        if path.startswith("\\\\"):
            return "\\\\?\\UNC\\" + path[2:]
        return "\\\\?\\" + path

    def sanitize_component(name, max_len=150):
        safe = re.sub(r'[<>:"\\|?*\x00-\x1f]', "_", str(name)).strip()
        safe = safe.rstrip(" .")
        if not safe or safe in {".", ".."}:
            safe = "_"
        if len(safe) <= max_len:
            return safe
        stem, suffix = os.path.splitext(safe)
        digest = hashlib.sha1(safe.encode("utf-8", errors="ignore")).hexdigest()[:12]
        suffix = suffix[:24]
        keep = max(1, max_len - len(digest) - len(suffix) - 1)
        return f"{stem[:keep]}_{digest}{suffix}"

    def safe_member_parts(member_name):
        parts = []
        normalized = str(member_name).replace("\\", "/")
        for part in normalized.split("/"):
            if not part or part in {".", ".."}:
                continue
            parts.append(sanitize_component(part))
        return parts

    with zipfile.ZipFile(zip_path, "r") as z:
        for member in z.infolist():
            safe_parts = safe_member_parts(member.filename)
            if not safe_parts:
                continue

            target_path = os.path.abspath(os.path.normpath(os.path.join(extract_root, *safe_parts)))

            # ZIP-slip protection
            if os.path.commonpath([extract_root, target_path]) != extract_root:
                continue

            # Directory
            if member.is_dir():
                os.makedirs(long_path(target_path), exist_ok=True)
                continue

            # Ensure parent directory exists
            parent = os.path.dirname(target_path)
            os.makedirs(long_path(parent), exist_ok=True)

            # Extract file
            with z.open(member, "r") as src, open(long_path(target_path), "wb") as dst:
                dst.write(src.read())

    # Detect GitHub-style top-level folder
    entries = [e.path for e in os.scandir(extract_root) if e.is_dir()]
    return entries[0] if len(entries) == 1 else extract_root





