def trim_callgraph_and_cfg(output_dir):
    """
    Keep only user-defined functions in callgraph.json.
    Remove calls to external functions, built-ins, or libraries.
    """
    callgraph_path = os.path.join(output_dir, "callgraph.json")
    trimmed_callgraph_path = os.path.join(output_dir, "callgraph_trim.json")

    if not os.path.exists(callgraph_path):
        print("callgraph.json not found!")
        return

    # Load callgraph edges
    with open(callgraph_path, "r", encoding="utf-8") as f:
        edges = json.load(f)

    # Step 1: collect all user-defined functions as callers
    user_functions = set(e["caller"] for e in edges if e.get("caller"))

    # Step 2: filter edges to keep only calls between user-defined functions
    trimmed_edges = [
        {"caller": e["caller"], "callee": e["callee"]}
        for e in edges
        if e.get("caller") in user_functions and e.get("callee") in user_functions
    ]

    # Step 3: save trimmed callgraph
    with open(trimmed_callgraph_path, "w", encoding="utf-8", errors="ignore") as f:
        json.dump(trimmed_edges, f, indent=2)

    print(f"Trimmed callgraph with user-defined functions saved to {trimmed_callgraph_path}")
    print(f"User-defined functions count: {len(user_functions)}")
    print(f"Edges count: {len(trimmed_edges)}")



