def build_pyvis_callgraph_old(callgraph_path, html_output):
    if not os.path.exists(callgraph_path):
        logger.warning(f"No callgraph.json at {callgraph_path}")
        return

    with open(callgraph_path, "r", encoding="utf-8") as f:
        edges = json.load(f)

    net = Network(
        height="100%",
        width="100%",
        directed=True,
        bgcolor="#ffffff",
        font_color="#222222"
    )

    net.set_options("""
    {
      "physics": {
        "enabled": false
      },
      "edges": {
        "smooth": {
          "type": "curvedCW",
          "roundness": 0.2
        },
        "color": { "color": "#00aaff" },
        "width": 2
      },
      "nodes": {
        "shape": "box",
        "margin": 10,
        "font": { "size": 18 }
      }
    }
    """)

    FILE_COLOR = "#4a90e2"
    nodes = set()

    # FIXED: edges is a list of dicts, not tuples
    for edge in edges:
        src = edge.get("caller")
        dst = edge.get("callee")
        if src:
            nodes.add(src)
        if dst:
            nodes.add(dst)

    # Add nodes
    for fpath in nodes:
        label = str(fpath).replace("\\", "/").replace("/", "\n")
        net.add_node(fpath, label=label, title=str(fpath), color=FILE_COLOR)

    # Add edges
    for edge in edges:
        src = edge.get("caller")
        dst = edge.get("callee")
        if src and dst:
            net.add_edge(src, dst)

    net.write_html(html_output)
    logger.info(f"Callgraph HTML saved to {html_output}")




