def build_unified_ast(repo_dir):

    unified = {
        "functions": set(),
        "classes": set(),
        "files": {}
    }

    for root, _, files in os.walk(repo_dir):

        for f in files:
            if not f.endswith(".ast.json"):
                continue

            path = os.path.join(root, f)

            data = json.load(open(path, "r", encoding="utf-8"))

            file_path = data.get("file")

            funcs = data.get("functions", [])
            classes = data.get("classes", [])

            unified["functions"].update(funcs)
            unified["classes"].update(classes)

            unified["files"][file_path] = funcs

    unified["functions"] = list(unified["functions"])
    unified["classes"] = list(unified["classes"])

    out_path = os.path.join(repo_dir, "unified_ast.json")

    json.dump(unified, open(out_path, "w", encoding="utf-8"), indent=2)

    print("Unified AST written:", out_path)

    return unified





def build_pyvis_ast_overview(ast_root_dir, html_output):
    from pyvis.network import Network
    import os, json

    net = Network(
        height="100%",
        width="100%",
        directed=True,
        bgcolor="#ffffff",
        font_color="#222222"
    )

    # Inject physics toggle button + JS
    net.html += """
    <button onclick="togglePhysics()">Toggle Physics</button>
    <script>
    function togglePhysics() {
        if (!window.network) return;
        var enabled = window.network.physics.options.enabled;
        window.network.setOptions({ physics: { enabled: !enabled } });
    }
    </script>
    """

    # IMPORTANT FIX:
    # Expose the network object globally after PyVis creates it
    net.set_options("""
    {
      "layout": {
        "hierarchical": false,
        "improvedLayout": false
      },
      "physics": { "enabled": false },
      "nodes": {
        "shape": "box",
        "margin": 10,
        "font": { "size": 18 }
      },
      "edges": { "smooth": false },
      "interaction": {
        "dragNodes": true
      }
    }
    """)

    # This JS is appended automatically by PyVis, so we patch it:
    net.html = net.html.replace(
        "var network = new vis.Network(container, data, options);",
        "var network = new vis.Network(container, data, options);\nwindow.network = network;"
    )

    FILE_COLOR = "#4a90e2"
    FUNC_COLOR = "#7ed321"

    # Layout parameters
    trees_per_row = 10
    tree_width = 500
    tree_height = 500
    func_y_offset = 120
    func_x_spacing = 120

    # Collect AST entries
    file_entries = []
    for root, _, files in os.walk(ast_root_dir):
        for fname in files:
            if fname.endswith(".ast.json"):
                with open(os.path.join(root, fname), "r", encoding="utf-8") as f:
                    data = json.load(f)
                file_rel = data.get("file", fname).replace("\\", "/")
                functions = data.get("functions", [])
                file_entries.append((file_rel, functions))

    row_offset = 0

    for index, (file_rel, functions) in enumerate(file_entries):

        # If previous file had >20 functions, force next file to new row
        if index > 0:
            prev_funcs = file_entries[index - 1][1]
            if len(prev_funcs) > 40:
                row_offset += 1

        col = index % trees_per_row
        row = index // trees_per_row + row_offset

        base_x = col * tree_width
        base_y = row * tree_height

        file_id = f"file::{file_rel}"
        label = file_rel.replace("/", "\n")

        # File node (middle row)
        net.add_node(
            file_id,
            label=label,
            title=file_rel,
            color=FILE_COLOR,
            x=base_x,
            y=base_y,
            fixed=True
        )

        n = len(functions)
        if n == 0:
            continue

        # Compute horizontal fan-out
        total_width = (n - 1) * func_x_spacing
        start_x = base_x - total_width / 2

        # Place functions: even → top row, odd → bottom row
        for i, fn in enumerate(functions):
            fn_name = fn if isinstance(fn, str) else str(fn)
            fn_id = f"func::{file_rel}::{fn_name}"

            fx = start_x + i * func_x_spacing

            if i % 2 == 0:
                fy = base_y - func_y_offset
            else:
                fy = base_y + func_y_offset

            net.add_node(
                fn_id,
                label=fn_name,
                title=fn_name,
                color=FUNC_COLOR,
                x=fx,
                y=fy,
                fixed=True
            )

            net.add_edge(file_id, fn_id)

    net.write_html(html_output)








def build_ast_html(ast_json_path, html_output_path):
    with open(ast_json_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    net = Network(height="100%", width="100%", directed=True)

    for node in data.get("nodes", []):
        net.add_node(
            node["id"],
            label=node.get("label", node["id"]),
            title=node.get("type", ""),
            color="#4a90e2"
        )

    for edge in data.get("edges", []):
        net.add_edge(edge["src"], edge["dst"])

    os.makedirs(os.path.dirname(html_output_path), exist_ok=True)
    net.write_html(html_output_path)


def generate_folder_indexes(ast_root):
    for root, dirs, files in os.walk(ast_root):
        html_files = [f for f in files if f.endswith(".ast.html")]
        if not html_files:
            continue

        index_path = os.path.join(root, "index.html")

        links = "\n".join(
            f'<li><a href="{fname}">{fname}</a></li>'
            for fname in sorted(html_files)
        )

        html = f"""
        <html>
        <head><title>AST Folder Index</title></head>
        <body>
            <h2>AST Files in {root}</h2>
            <ul>
                {links}
            </ul>
        </body>
        </html>
        """

        with open(index_path, "w", encoding="utf-8", errors="ignore") as f:
            f.write(html)





def download_repo_zip(zip_url):
    response = requests.get(zip_url, stream=True, timeout=GITHUB_REQUEST_TIMEOUT)
    response.raise_for_status()

    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".zip")
    for chunk in response.iter_content(chunk_size=8192):
        tmp.write(chunk)
    tmp.close()

    return tmp.name

