def normalize_name(fullname: str) -> str:
    if not fullname:
        return fullname
    # Remove return type and parameters
    if ":" in fullname:
        fullname = fullname.split(":")[0]
    # Remove <init> and <clinit>
    fullname = fullname.replace("<init>", "").replace("<clinit>", "")
    # Remove trailing dots
    fullname = fullname.rstrip(".")
    return fullname

def clean_edges(edges):
    cleaned = []
    for e in edges:
        name = normalize_name(e)
        if name and name not in cleaned:
            cleaned.append(name)
    return sorted(cleaned)

def clean_function(fn):
    return {
        "name": normalize_name(fn["name"]),
        "fullName": normalize_name(fn["fullName"])
    }

from pyvis.network import Network


def build_search_graph(search_data, output_html="search_graph.html"):
    """
    search_data = {
        "query": "...",
        "results": [
            {
                "function": {"name": "...", "fullName": "..."},
                "callers": [...],
                "callees": [...]
            }
        ]
    }
    """

    results = search_data.get("results", None)
    if results == None:
        print("No results to graph.")
        return

    # Only draw if small enough
    if len(results) > 100:
        print("Too many nodes, skipping graph.")
        return

    net = Network(
        height="100%",
        width="100%",
        directed=True,
        bgcolor="#ffffff",  
        font_color="#222222"
    )


    net.set_options("""
{
  "layout": {
    "hierarchical": {
      "enabled": true,
      "direction": "UD",
      "sortMethod": "directed",
      "levelSeparation": 200,
      "nodeSpacing": 200
    }
  },
  "physics": {
    "enabled": false
  },
  "nodes": {
    "shape": "box",
    "margin": 10,
    "widthConstraint": {
      "minimum": 10,
      "maximum": 150
    },
    "font": {
      "size": 20,
      "multi": true
    }
  },
  "edges": {
    "smooth": false
  }
}
""")
    

    def wrap_on_dot(label: str) -> str:
        if "." in label:
            parts = label.rsplit(".", 1)  # split only on the last dot
            return f"{parts[0]}.<br>{parts[1]}"
        return label

    BASE = 1000  # keeps levels positive and avoids normalization
    # Add a HIDDEN root node for better layout
    ROOT = "__ROOT__"
    net.add_node(ROOT, label="", hidden=True, level=BASE-100)
    # Build nodes + edges    
    for item in results:
        fn = item["function"]["fullName"]
        # Main function node
        net.add_node(fn, label=wrap_on_dot(fn), title=fn, color="#88c", level=BASE, shape="box")
        # Add callers with staggered levels
        for i, caller in enumerate(item["callers"]):
            net.add_node(caller, title=caller, label=wrap_on_dot(caller), color="#c88", level=BASE - (i + 1))
            net.add_edge(ROOT, caller)
            # ⭐ NEW: ordered label for caller → fn
            label = ""
            if "order_index" in search_data:
                label = str(search_data["order_index"].get((caller, fn), ""))
            net.add_edge(caller, fn,label=label)
        # Add callees with staggered levels
        for j, callee in enumerate(item["callees"]):
            
            net.add_node(callee, title=callee, label=wrap_on_dot(callee), color="#8c8", level=BASE + (j + 1))
            net.add_edge(ROOT, callee)
            # ⭐ NEW: ordered label for fn → callee
            label = ""
            if "order_index" in search_data:
                label = str(search_data["order_index"].get((fn, callee), ""))
            net.add_edge(fn, callee, label=label)

    # Save graph
    net.write_html(output_html)
    print(f"Graph saved to {output_html}")

    #Enable physics once the graph is built
    with open(output_html, "r") as f:
        html = f.read()
    # Auto-enable physics after graph loads

    injection = """
    <script>
    // Wait for the graph to finish initializing
    setTimeout(function() {
        if (typeof network !== 'undefined') {
        network.setOptions({
            physics: { enabled: true, stabilization: false },
            layout: { hierarchical: false }
        });

        // 🔥 THIS FIXES YOUR CUT-OFF ISSUE
        network.fit();
        }
    }, 200);
    </script>
    """
    
    html = html.replace("</body>", injection + "</body>")
    with open(output_html, "w", encoding="utf-8", errors="ignore") as f:
        f.write(html)



def extract_tokens(fn):
    tokens = set()
    # function name
    tokens.update(re.findall(r"[A-Za-z]+", fn["name"]))
    # full name
    tokens.update(re.findall(r"[A-Za-z]+", fn["fullName"]))
    # comments/docstrings if available
    if "doc" in fn and fn["doc"]:
        tokens.update(re.findall(r"[A-Za-z]+", fn["doc"]))
    # comments.json lookup
    # PSTODO : Need to fix COMMENTS
    #if fn["fullName"] in COMMENTS:
    #    tokens.update(re.findall(r"[A-Za-z]+", COMMENTS[fn["fullName"]]))
    return {t.lower() for t in tokens}


def extract_query_tokens(q: str, name_index, full_index, keyword_index):
    """
    Extract all tokens from a natural-language query that match
    any function name, fullName, or keyword.
    """
    q = q.lower()
    q = re.sub(r"[^a-z0-9_\.]", " ", q)
    tokens = q.split()

    matches = set()

    for t in tokens:
        # exact simple name match
        if t in name_index:
            matches.add(t)

        # exact fullName match
        if t in full_index:
            matches.add(t)

        # keyword match
        if t in keyword_index:
            matches.add(t)

        # ---------------------------------------------------------
        # ⭐ CHANGE ADDED HERE: substring match against all names ⭐
        # ---------------------------------------------------------
        for fn in name_index.keys():
            if t in fn:      # <-- THIS is the new behavior
                matches.add(fn)
        # ---------------------------------------------------------

    return list(matches)









def normalize_query(q: str):
    q = q.strip().lower()

    # If the query contains "callgraph for X", extract X
    m = re.search(r"callgraph\s+for\s+(.+)", q)
    if m:
        return m.group(1).strip()

    return q

import re


def parse_intent(query: str):
    q = query.lower().strip()

    # -----------------------------
    # 1. Callgraph
    # -----------------------------
    m = re.search(r"(callgraph|cg|graph)\s+(for|of)\s+(.+)", q)
    if m:
        return {"intent": "callgraph", "target": m.group(3).strip()}

    # -----------------------------
    # 2. Reverse callgraph
    # -----------------------------
    m = re.search(r"(who\s+calls|callers\s+of)\s+(.+)", q)
    if m:
        return {"intent": "reverse_callgraph", "target": m.group(2).strip()}

    # -----------------------------
    # 3. Definition lookup
    # -----------------------------
    m = re.search(r"(where\s+is|definition\s+of|def\s+of)\s+(.+)", q)
    if m:
        return {"intent": "definition", "target": m.group(2).strip()}

    # -----------------------------
    # 4. File lookup
    # -----------------------------
    m = re.search(r"(show\s+file\s+for|open\s+file\s+for)\s+(.+)", q)
    if m:
        return {"intent": "file", "target": m.group(2).strip()}

    # -----------------------------
    # 5. List functions
    # -----------------------------
    if "list functions" in q or "show functions" in q:
        return {"intent": "list_functions"}

    # -----------------------------
    # 6. List files
    # -----------------------------
    if "list files" in q or "show files" in q:
        return {"intent": "list_files"}

    # -----------------------------
    # 7. Fallback: keyword search
    # -----------------------------
    return {"intent": "search", "keywords": q.split()}



def build_generic_cytoscape_graph(nodes, edges, output_repo_dir, graph_name, graph_title="Graph", node_labels=None):
    """
    nodes: list of function fullNames
    edges: list of [caller, callee] or [caller, callee, order, line]
    output_repo_dir: e.g. C:/DATA/Code/Progduct/output/owner_repo/
    graph_name: e.g. "search_graph"
    """

    # 1. Build JSON + HTML paths
    json_path = os.path.join(output_repo_dir, f"{graph_name}.json")
    static_json_path = os.path.join(output_repo_dir, f"{graph_name}_callgraph.json")
    ordered_json_path = os.path.join(output_repo_dir, f"{graph_name}_ordered.json")
    html_path = os.path.join(output_repo_dir, f"{graph_name}.html")

    # ---------------------------------------------------------
    # Convert edges → Cytoscape elements
    # ---------------------------------------------------------
    static_edges = set()
    ordered_calls = []
    cy_edges = []
    for edge in edges:
        # Expecting: [src, dst, order, line]
        if len(edge) == 4:
            src, dst, order, line = edge
        elif len(edge) == 3:
            src, dst, order = edge
            line = None
        else:
            src, dst = edge
            order = None
            line = None

        static_edges.add((src, dst))
        if order is not None or line is not None:
            ordered_calls.append({
                "source": src,
                "target": dst,
                "order": order,
                "line": line,
            })

        if line is not None and order is not None:
            label = f"L{line} (#{order})"
        elif order is not None:
            label = f"#{order}"
        else:
            label = ""

        cy_edges.append({
            "data": {
                "id": f"{src}->{dst}",
                "source": src,
                "target": dst,
                "order": order,
                "line": line,
                "label": label
            }
        })

    node_labels = {str(key): str(value) for key, value in (node_labels or {}).items() if key and value}

    static_graph_data = {
        "mode": "static_call_graph",
        "title": graph_title,
        "nodes": sorted(set(nodes)),
        "edges": [[src, dst] for src, dst in sorted(static_edges)],
        "node_labels": node_labels,
    }
    ordered_graph_data = {
        "mode": "ordered_call_sequence",
        "title": graph_title,
        "calls": sorted(
            ordered_calls,
            key=lambda item: (
                item.get("line") if item.get("line") is not None else 0,
                item.get("order") if item.get("order") is not None else 0,
                item.get("source") or "",
                item.get("target") or "",
            ),
        ),
    }
    graph_data = {
        "mode": "search_graph",
        "title": graph_title,
        "purpose": "visualization_merge",
        "nodes": sorted(set(nodes)),
        "edges": cy_edges,
        "node_labels": node_labels,
        "static_callgraph_file": os.path.basename(static_json_path),
        "ordered_call_sequence_file": os.path.basename(ordered_json_path),
    }

    # ---------------------------------------------------------
    # Write JSON (Cytoscape expects this format)
    # 2. Write JSON
    # ---------------------------------------------------------
    with open(static_json_path, "w", encoding="utf-8") as f:
        json.dump(static_graph_data, f, indent=2)

    with open(ordered_json_path, "w", encoding="utf-8") as f:
        json.dump(ordered_graph_data, f, indent=2)

    with open(json_path, "w", encoding="utf-8") as f:
        json.dump(graph_data, f, indent=2)

    # 3. Build HTML using template
    output_root = BASE_OUTPUT
    relative_json = os.path.relpath(json_path, output_root).replace("\\", "/")

    with open(CYTOSCAPE_TEMPLATE_HTML_PATH, "r", encoding="utf-8") as f:
        html = f.read()

    html = html.replace("__JSON_PATH__", f"{OUTPUT_URL_PREFIX}/{relative_json}")
    html = html.replace("__GRAPH_TITLE__", graph_title)
    html = html.replace("__GRAPH_DATA__", json.dumps(graph_data, separators=(",", ":")))

    with open(html_path, "w", encoding="utf-8") as f:
        f.write(html)

    # 4. Return URL to HTML
    relative_html = os.path.relpath(html_path, output_root).replace("\\", "/")
    print ("relative_html:", relative_html)

    return f"{OUTPUT_URL_PREFIX}/{relative_html}"



logger = logging.getLogger(__name__)


def is_real_call(call):
    if not isinstance(call, dict):
        return False
    name = (call.get("call_name") or "").lower()
    callee = (call.get("callee_fullName") or "").lower()
    # drop synthetic AST ops
    if name in {"alloc", "assignment", "fieldaccess", "addition"}:
        return False
    # drop <init> unless it has a real callee
    if name.startswith("<") and not callee:
        return False
    return True


def is_real_function(name: str) -> bool:
    return not name.startswith("<operator>")


def find_components(nodes, adj):
    visited = set()
    components = []

    for n in nodes:
        if n not in visited:
            queue = deque([n])
            comp = set()

            while queue:
                cur = queue.popleft()
                if cur in visited:
                    continue
                visited.add(cur)
                comp.add(cur)
                queue.extend(adj[cur])

            components.append(comp)

    return components


def load_search_callgraph(output_repo_dir):
    ordered_sequence_candidates = [
        ("combined-ordered", os.path.join(output_repo_dir, "combined_callgraph", "combined_ordered_call_sequence.json")),
        ("joern-normalized", os.path.join(output_repo_dir, "joern", "joern_ordered_call_sequence.json")),
        ("java-merged-ordered", os.path.join(output_repo_dir, "java_merged", "java_merged_ordered_call_sequence.json")),
        ("tree-sitter-java-ordered", os.path.join(output_repo_dir, "tree_sitter_java", "tree_sitter_java_ordered_call_sequence.json")),
        ("javalang-ordered", os.path.join(output_repo_dir, "javalang", "javalang_ordered_call_sequence.json")),
        ("python-ast-ordered", os.path.join(output_repo_dir, "python", "python_ordered_call_sequence.json")),
        ("javascript-ordered", os.path.join(output_repo_dir, "javascript", "javascript_ordered_call_sequence.json")),
        ("csharp-regex-ordered", os.path.join(output_repo_dir, "csharp", "csharp_ordered_call_sequence.json")),
    ]
    for source, ordered_path in ordered_sequence_candidates:
        if not os.path.exists(ordered_path):
            continue
        print("ORDERED_CALL_SEQUENCE_PATH:", ordered_path)
        with open(ordered_path, "r", encoding="utf-8") as f:
            payload = json.load(f)
        by_method = {}
        for call in payload.get("calls", []) or []:
            if not isinstance(call, dict):
                continue
            caller = call.get("caller")
            callee = call.get("callee")
            if not caller or not callee:
                continue
            by_method.setdefault(caller, {"method": caller, "calls": []})["calls"].append({
                "callee_fullName": callee,
                "line": call.get("line"),
                "order": call.get("order"),
                "call_code": call.get("call_text", ""),
                "call_name": str(callee).split(".")[-1],
            })
            by_method.setdefault(callee, {"method": callee, "calls": []})
        return list(by_method.values()), source

    joern_path = os.path.join(output_repo_dir, "joern", "joern_callgraph_ordered.json")
    if os.path.exists(joern_path):
        print("CALLGRAPH_PATH:", joern_path)
        with open(joern_path, "r", encoding="utf-8") as f:
            callgraph = json.load(f)
        return callgraph, "joern"

    edge_graph_candidates = [
        ("combined", os.path.join(output_repo_dir, "combined_callgraph", "combined_callgraph.json")),
        ("combined-navigatable", os.path.join(output_repo_dir, "combined_callgraph", "combined_navigatable_callgraph.json")),
        ("html-ui", os.path.join(output_repo_dir, "html_ui", "html_ui_graph.json")),
        ("java-merged", os.path.join(output_repo_dir, "java_merged", "java_merged_callgraph.json")),
        ("tree-sitter-java", os.path.join(output_repo_dir, "tree_sitter_java", "tree_sitter_java_callgraph.json")),
        ("javalang", os.path.join(output_repo_dir, "javalang", "javalang_callgraph.json")),
        ("python-ast", os.path.join(output_repo_dir, "python", "python_callgraph.json")),
        ("javascript", os.path.join(output_repo_dir, "javascript", "javascript_callgraph.json")),
        ("csharp-regex", os.path.join(output_repo_dir, "csharp", "csharp_callgraph.json")),
    ]
    for source, graph_path in edge_graph_candidates:
        if not os.path.exists(graph_path):
            continue
        print("CALLGRAPH_PATH:", graph_path)
        with open(graph_path, "r", encoding="utf-8") as f:
            graph = json.load(f)
        edges = graph.get("edges", graph) if isinstance(graph, dict) else graph
        edges = edges if isinstance(edges, list) else []
        methods = set()
        raw_nodes = graph.get("nodes", []) if isinstance(graph, dict) else []
        for node in raw_nodes or []:
            if isinstance(node, str):
                methods.add(node)
            elif isinstance(node, dict):
                data = node.get("data") if isinstance(node.get("data"), dict) else node
                node_id = data.get("id") or data.get("name") or data.get("label")
                if node_id:
                    methods.add(str(node_id))
        for edge in edges:
            if isinstance(edge, list) and len(edge) >= 2:
                methods.add(edge[0])
                methods.add(edge[1])
            elif isinstance(edge, dict):
                data = edge.get("data") if isinstance(edge.get("data"), dict) else edge
                caller = data.get("source") or data.get("from") or data.get("caller")
                callee = data.get("target") or data.get("to") or data.get("callee")
                if caller and callee:
                    methods.add(str(caller))
                    methods.add(str(callee))
        callgraph = [{"method": method, "calls": []} for method in sorted(methods)]
        by_method = {item["method"]: item for item in callgraph}
        for edge in edges:
            if isinstance(edge, list) and len(edge) >= 2:
                caller, callee = edge[0], edge[1]
                by_method.setdefault(caller, {"method": caller, "calls": []})["calls"].append({
                    "callee_fullName": callee,
                    "line": None,
                    "order": None,
                    "call_code": "",
                    "call_name": callee.split(".")[-1],
                })
            elif isinstance(edge, dict):
                data = edge.get("data") if isinstance(edge.get("data"), dict) else edge
                caller = data.get("source") or data.get("from") or data.get("caller")
                callee = data.get("target") or data.get("to") or data.get("callee")
                if caller and callee:
                    caller = str(caller)
                    callee = str(callee)
                    by_method.setdefault(caller, {"method": caller, "calls": []})["calls"].append({
                        "callee_fullName": callee,
                        "line": None,
                        "order": None,
                        "call_code": "",
                        "call_name": callee.split(".")[-1],
                    })
        return list(by_method.values()), source

    raise FileNotFoundError(
        f"No callgraph found. Expected combined, HTML UI, Joern, tree-sitter/javalang, Python, JavaScript, or C# graph JSON. Run Analyze first."
    )


