def loose_symbol_text(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()


def loose_symbol_key(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", str(value or "").lower())


def loose_symbol_match(query: str, symbol: str) -> bool:
    query_key = loose_symbol_key(query)
    symbol_key = loose_symbol_key(symbol)
    if query_key and symbol_key and query_key in symbol_key:
        return True
    query_text = loose_symbol_text(query)
    symbol_text = loose_symbol_text(symbol)
    return bool(query_text and symbol_text and query_text in symbol_text)


def resolve_search_functions(query, functions, name_index, full_name_index):
    parsed = parse_intent(query)
    target = (
        parsed.get("target")
        or " ".join(parsed.get("keywords", []))
        or query
    ).lower().strip()
    target = target.strip(" ?.,:;!()[]{}\"'")

    results = []
    if target in full_name_index:
        results.append(full_name_index[target])
    if target in name_index:
        results.append(name_index[target])
    for fn in functions:
        full_lower = fn["fullName"].lower()
        name_lower = fn["name"].lower()
        if target and (target in full_lower or target in name_lower or loose_symbol_match(target, fn["fullName"]) or loose_symbol_match(target, fn["name"])):
            results.append(fn)

    seen = set()
    unique = []
    for fn in results:
        if fn["fullName"] not in seen:
            seen.add(fn["fullName"])
            unique.append(fn)
    return parsed, unique


def callgraph_indexes(callgraph):
    ordered_calls = {
        item["method"]: item.get("calls", [])
        for item in callgraph
        if isinstance(item, dict) and item.get("method")
    }
    functions = set()
    outgoing = defaultdict(list)
    incoming = defaultdict(list)
    edge_meta = {}

    for item in callgraph:
        if not isinstance(item, dict):
            continue
        caller = item.get("method")
        if not caller:
            continue
        functions.add(caller)
        for call in item.get("calls", []) or []:
            if not isinstance(call, dict):
                continue
            if not is_real_call(call):
                continue
            callee = call.get("callee_fullName")
            if not callee:
                continue
            functions.add(callee)
            outgoing[caller].append(callee)
            incoming[callee].append(caller)
            edge_meta[(caller, callee)] = {
                "order": call.get("order"),
                "line": call.get("line"),
            }

    return ordered_calls, functions, outgoing, incoming, edge_meta


