def is_api_exposure_query(query: str, terms: set[str] | None = None) -> bool:
    lowered = str(query or "").lower()
    query_terms = set(terms or search_query_terms(query))
    if not (query_terms & {"api", "apis", "endpoint", "endpoints", "route", "routes"}):
        return False
    exposure_terms = {"exposed", "expose", "public", "internet", "external", "rest", "accessible", "endpoint", "endpoints"}
    if query_terms & exposure_terms:
        return True
    return any(
        phrase in lowered
        for phrase in (
            "internet exposed",
            "externally exposed",
            "public api",
            "public endpoint",
            "rest api",
            "api endpoint",
            "api endpoints",
        )
    )


def is_api_exposure_candidate(symbol: str, path: str = "", metadata: dict | None = None) -> bool:
    symbol_text = str(symbol or "").lower()
    rel_path = str(path or "").replace("\\", "/").lower()
    metadata = metadata or {}
    evidence_text = str(metadata.get("evidence_text") or metadata.get("code") or "").lower()
    if symbol_text.startswith("api."):
        return True
    if re.search(r"(^|/)(api|routes?|controllers?|handlers?)(/|$)", rel_path):
        return True
    if re.search(r"(^|/)app/api(?:/.*)?/route\.(js|jsx|ts|tsx)$", rel_path):
        return True
    if re.search(r"(^|/)pages/api(?:/|$)", rel_path):
        return True
    if re.search(r"@\w+\.(get|post|put|patch|delete|options|head|api_route)\s*\(", evidence_text):
        return True
    if re.search(r"\b(app|router)\.(get|post|put|patch|delete|options|head|use|route)\s*\(", evidence_text):
        return True
    if re.search(r"\bexport\s+(async\s+)?function\s+(GET|POST|PUT|PATCH|DELETE|OPTIONS|HEAD)\b", evidence_text):
        return True
    if re.search(r"@\s*(get|post|put|patch|delete|request|route)mapping\b", evidence_text):
        return True
    if re.search(r"\[\s*(httpget|httppost|httpput|httppatch|httpdelete|route|apicontroller)\b", evidence_text):
        return True
    if re.search(r"\b(route|router)::(get|post|put|patch|delete|any|match)\s*\(", evidence_text):
        return True
    if re.search(r"\b(http\.handlefunc|mux\.handlefunc|handlefunc)\s*\(", evidence_text):
        return True
    return False


def is_non_api_next_page_candidate(symbol: str, path: str = "") -> bool:
    symbol_text = str(symbol or "").lower()
    rel_path = str(path or "").replace("\\", "/").lower()
    if symbol_text.startswith("next.page."):
        return True
    if re.search(r"(^|/)app/.+/(page|layout|template|loading|error|not-found)\.(js|jsx|ts|tsx)$", rel_path):
        return True
    return False


def is_data_flow_query(query: str, terms: set[str] | None = None) -> bool:
    lowered = str(query or "").lower()
    query_terms = set(terms or search_query_terms(query))
    source_terms = {"input", "user", "request", "body", "form", "param", "params", "query", "payload"}
    sink_terms = {"database", "db", "sql", "sqlite", "supabase", "table", "insert", "update", "delete", "write", "save", "persist"}
    if any(phrase in lowered for phrase in (
        "user input to the database",
        "input to the database",
        "trace input",
        "trace user input",
        "taint",
        "sql injection",
    )):
        return True
    return bool((query_terms & source_terms) and (query_terms & sink_terms))


DATA_FLOW_SOURCE_PATTERNS = (
    r"\brequest\.(json|form|body|args|get_json|query_params|path_params)\b",
    r"\b(req|request)\.(body|query|params|files|form)\b",
    r"\b(formdata|form_data|searchparams|urlsearchparams)\b",
    r"\b(input|textarea|select|form|uploadfile)\b",
    r"\b(process\.argv|argparse|click\.option|typer\.option|sys\.argv)\b",
)


DATA_FLOW_SINK_PATTERNS = (
    r"\bsupabase\b",
    r"\b(client|db|conn|connection|cursor)\.(execute|executemany|commit|insert|update|delete|upsert|table|from_)\b",
    r"\b(table|from_)\s*\(",
    r"\b(insert|update|delete|upsert|save|persist|execute|executemany)\s*\(",
    r"\b(sqlite|sqlalchemy|prisma|sequelize|typeorm|mongoose|postgres|mysql|database)\b",
)


def data_flow_record_text(record: dict | None, symbol: str = "") -> str:
    if not isinstance(record, dict):
        return str(symbol or "")
    return "\n".join(
        str(value or "")
        for value in (
            symbol,
            record.get("symbol"),
            record.get("path"),
            record.get("class_name"),
            record.get("method_name"),
            record.get("signature"),
            record.get("code"),
        )
    ).lower()


def data_flow_node_kind(symbol: str, record: dict | None = None) -> str:
    text = data_flow_record_text(record, symbol)
    symbol_text = str(symbol or "").lower()
    path = str((record or {}).get("path") or "").replace("\\", "/").lower() if isinstance(record, dict) else ""
    if (
        symbol_text.startswith(("static_", "html_", "ui.", "event."))
        or "html_ui" in symbol_text
        or path.endswith((".html", ".htm"))
        or re.search(r"(^|/)(pages?|app|templates?|static)(/|$)", path)
        or any(re.search(pattern, text) for pattern in DATA_FLOW_SOURCE_PATTERNS)
    ):
        return "source"
    if (
        symbol_text.startswith("api.")
        or re.search(r"(^|/)(api|routes?|controllers?|handlers?)(/|$)", path)
    ):
        return "entrypoint"
    if any(re.search(pattern, text) for pattern in DATA_FLOW_SINK_PATTERNS):
        return "sink"
    return ""


def collect_data_flow_paths(output_repo_dir: Path, max_paths: int = 10, max_depth: int = 8) -> dict:
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    dataset_dir = artifact_root / "scim"
    records = load_scim_function_records(dataset_dir)
    graph_paths = [
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "html_ui" / "html_ui_graph.json",
        artifact_root / "file_graph" / "file_graph.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "csharp" / "csharp_callgraph.json",
    ]
    outgoing = defaultdict(set)
    incoming = defaultdict(set)
    graph_sources = []
    nodes = set(records)
    for graph_path in graph_paths:
        graph_nodes, edges = _load_edge_graph(str(graph_path))
        if graph_nodes or edges:
            graph_sources.append(str(graph_path))
        nodes.update(graph_nodes)
        for src, dst in edges:
            outgoing[src].add(dst)
            incoming[dst].add(src)
            nodes.update([src, dst])

    def record_for_node(node: str) -> dict:
        if node in records:
            return records[node]
        node_tail = str(node or "").lower().split(".")[-1]
        return next(
            (
                record for symbol, record in records.items()
                if str(symbol).lower().endswith(node_tail) or node_tail.endswith(str(symbol).lower().split(".")[-1])
            ),
            {},
        )

    sources = []
    sinks = []
    entrypoints = []
    for node in sorted(nodes):
        record = record_for_node(node)
        kind = data_flow_node_kind(node, record)
        if kind == "source":
            sources.append(node)
        elif kind == "sink":
            sinks.append(node)
        elif kind == "entrypoint":
            entrypoints.append(node)
    source_seeds = sources[:80] or entrypoints[:80]
    sink_set = set(sinks)

    paths = []
    for source in source_seeds:
        queue = deque([(source, [source])])
        seen = {source}
        while queue and len(paths) < max_paths:
            node, path = queue.popleft()
            if node in sink_set and len(path) > 1:
                paths.append(path)
                break
            if len(path) > max_depth:
                continue
            for nxt in sorted(outgoing.get(node, set()))[:30]:
                if nxt in seen:
                    continue
                seen.add(nxt)
                queue.append((nxt, path + [nxt]))
        if len(paths) >= max_paths:
            break

    def node_payload(node: str) -> dict:
        record = record_for_node(node)
        return {
            "symbol": node,
            "kind": data_flow_node_kind(node, record),
            "path": record.get("path", "") if isinstance(record, dict) else "",
            "start_line": record.get("start_line", "") if isinstance(record, dict) else "",
            "first_code_line": first_code_line(record) if isinstance(record, dict) else "",
            "out_degree": len(outgoing.get(node, set())),
            "in_degree": len(incoming.get(node, set())),
        }

    return {
        "strategy": "static source-to-sink graph walk from UI/API/CLI/input-like nodes to database/storage sink-like nodes",
        "graph_sources": graph_sources,
        "source_count": len(sources),
        "entrypoint_count": len(entrypoints),
        "sink_count": len(sinks),
        "connected_path_count": len(paths),
        "paths": [[node_payload(node) for node in path] for path in paths],
        "source_samples": [node_payload(node) for node in sources[:12]],
        "entrypoint_samples": [node_payload(node) for node in entrypoints[:12]],
        "sink_samples": [node_payload(node) for node in sinks[:12]],
    }


