def generate_search_answer_from_prompt(prompt):
    if not prompt:
        return "No grounded code context was available for this question."
    try:
        prompt = str(prompt or "")
        if len(prompt) > OPENAI_SEARCH_PROMPT_MAX_CHARS:
            prompt = (
                prompt[:OPENAI_SEARCH_PROMPT_MAX_CHARS]
                + "\n\n[Prompt truncated by CodeVal to keep answer generation within production timeout limits.]"
            )
        api_key = os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise ValueError("OPENAI_API_KEY is not set.")
        model = os.getenv("OPENAI_SEARCH_MODEL", os.getenv("OPENAI_SUMMARY_MODEL", "gpt-4o-mini"))
        if prompt.startswith("You are analyzing software service architecture"):
            model = os.getenv("OPENAI_ARCHITECTURE_MODEL", model)
        elif prompt.startswith("You are analyzing observed product/user activity"):
            model = os.getenv("OPENAI_ACTIVITY_MODEL", model)
        elif prompt.startswith("You are analyzing source-to-sink data flow"):
            model = os.getenv("OPENAI_SECURITY_MODEL", model)

        def request_answer(prompt_text, max_tokens, timeout_seconds):
            return requests.post(
                "https://api.openai.com/v1/chat/completions",
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                },
                json={
                    "model": model,
                    "messages": [{"role": "user", "content": prompt_text}],
                    "max_tokens": max_tokens,
                    "temperature": 0.2,
                },
                timeout=(10, timeout_seconds),
            )

        try:
            response = request_answer(prompt, OPENAI_SEARCH_MAX_TOKENS, OPENAI_REQUEST_TIMEOUT_SECONDS)
        except requests.exceptions.Timeout:
            retry_prompt = prompt
            if len(retry_prompt) > OPENAI_SEARCH_RETRY_PROMPT_MAX_CHARS:
                retry_prompt = (
                    retry_prompt[:OPENAI_SEARCH_RETRY_PROMPT_MAX_CHARS]
                    + "\n\n[Prompt shortened by CodeVal after the first answer-generation timeout. Use only the evidence above.]"
                )
            response = request_answer(
                retry_prompt,
                min(800, OPENAI_SEARCH_MAX_TOKENS),
                max(45, OPENAI_REQUEST_TIMEOUT_SECONDS),
            )
        response.raise_for_status()
        data = response.json()
        return (data["choices"][0]["message"]["content"] or "").strip()
    except requests.exceptions.Timeout:
        return (
            f"Search answer generation timed out after {OPENAI_REQUEST_TIMEOUT_SECONDS} seconds. "
            "The search results, evidence cards, and search graph are still available; try a more specific question or reduce graph/detail depth."
        )
    except Exception as e:
        return f"Error generating search answer: {str(e)}"


def generate_search_answer(user_question, retrieval_context, results, text_results=None, prompt_template=""):
    prompt = build_search_answer_prompt(user_question, retrieval_context, results, text_results, prompt_template=prompt_template)
    return generate_search_answer_from_prompt(prompt)


def scim_record_match_score(symbol, path, metadata, record, query_terms):
    if not query_terms:
        return 0, [], ""

    identity_text = " ".join(
        str(value or "")
        for value in (
            symbol,
            path,
            metadata.get("class_name"),
            metadata.get("method_name"),
            record.get("class_name") if record else "",
            record.get("method_name") if record else "",
        )
    ).lower()
    code_text = str((record or {}).get("code") or "").lower()
    combined = f"{identity_text}\n{code_text}"
    matched = sorted(term for term in query_terms if term in combined)
    if not matched:
        return 0, [], ""

    score = 0
    source = "code text"
    for term in matched:
        if term in identity_text:
            score += 14
            source = "symbol/path"
        if re.search(rf"\b{re.escape(term)}\b", identity_text):
            score += 6
            source = "symbol/path"
        code_hits = len(re.findall(rf"\b{re.escape(term)}\b", code_text))
        if code_hits:
            score += min(12, code_hits * 3)
            if source != "symbol/path":
                source = "function body"
    return score, matched, source


def query_requires_literal_evidence(query_terms):
    if not query_terms:
        return False
    known_technical_terms = {
        "api", "ast", "auth", "cache", "class", "fastapi", "github", "graph",
        "java", "joern", "json", "parser", "python", "scim", "sqlite", "tree",
        "supabase", "zip",
    }
    technical_terms = {
        term for term in query_terms
        if "_" in term or any(ch.isdigit() for ch in term) or term in known_technical_terms
    }
    return bool(technical_terms)


def first_matching_code_line(record, query_terms, default_line):
    code = str((record or {}).get("code") or "")
    if not code or not query_terms:
        return "", default_line
    base_line = int((record or {}).get("start_line") or default_line or 1)
    for offset, line in enumerate(code.splitlines()):
        line_lower = line.lower()
        if any(term in line_lower for term in query_terms):
            return line.strip()[:500], base_line + offset
    return "", default_line


def exact_ui_label_record_matches(dataset_dir: Path, labels: list[str]) -> dict[str, list[str]]:
    functions_path = Path(dataset_dir) / "functions.jsonl"
    if not functions_path.exists() or not labels:
        return {}
    variants = {
        variant.lower(): variant
        for label in labels
        for variant in ui_label_search_variants(label)
        if variant
    }
    matches = defaultdict(list)
    with functions_path.open("r", encoding="utf-8", errors="ignore") as handle:
        for line in handle:
            try:
                record = json.loads(line)
            except json.JSONDecodeError:
                continue
            symbol = str(record.get("symbol") or "")
            path = str(record.get("path") or "")
            code = str(record.get("code") or "")
            ui_haystack = f"{symbol}\n{path}\n{code}".lower()
            if not any(marker in ui_haystack for marker in (
                "html ui element:",
                "<button",
                "<a ",
                "role=\"button\"",
                "role='button'",
                "onclick",
                "href:",
                "aria-label",
            )):
                continue
            matched = [original for lowered, original in variants.items() if lowered in ui_haystack]
            if symbol and matched:
                matches[symbol].extend(matched)
    return {
        symbol: list(dict.fromkeys(values))
        for symbol, values in matches.items()
    }


def search_scim_dataset(output_repo_dir, query, limit=10):
    artifact_root = artifact_root_for_output(output_repo_dir)
    dataset_dir = artifact_root / "scim"
    model_path = dataset_dir / "embedding_model.json"
    vector_db_path = dataset_dir / "vectors.sqlite"
    if not model_path.exists() or not vector_db_path.exists():
        return None

    try:
        import numpy as np
        from scim import EmbeddingModel, blob_to_vector, cosine_np
    except Exception as e:
        logger.warning("SCIM search import failed: %s", e)
        return None

    model = EmbeddingModel.load(model_path)
    retrieval_plan = plan_scim_retrieval(query)
    vocabulary = build_scim_repo_vocabulary(dataset_dir, artifact_root)
    query_brain = rewrite_scim_query_with_vocabulary(query, retrieval_plan, vocabulary)
    ui_labels = ui_label_query_phrases(query)
    exact_ui_records = exact_ui_label_record_matches(dataset_dir, ui_labels)
    ui_variant_terms = []
    for label in ui_labels:
        ui_variant_terms.extend(ui_label_search_variants(label))
    if ui_variant_terms:
        ui_variant_terms.extend(["onClick", "onSubmit", "button", "aria-label", "title", "placeholder", "data-testid"])
    ui_label_query = " ".join(dict.fromkeys(ui_variant_terms))
    retrieval_queries = list(dict.fromkeys([
        ui_label_query.strip(),
        str(query_brain.get("focus_query") or "").strip(),
        str(query or "").strip(),
        str(query_brain.get("rewritten_query") or "").strip(),
    ]))
    query_vectors = [
        np.asarray(model.embed_query(item), dtype=np.float32)
        for item in retrieval_queries
        if item
    ]
    query_terms = search_query_terms(" ".join([query, ui_label_query]) if ui_label_query else query)
    target_terms = search_call_targets(query)
    require_literal = bool(retrieval_plan.get("requires_literal"))
    exact_target = extract_search_target(query)
    exact_symbol_target_required = bool(
        exact_target
        and re.search(r"[A-Z_.]|_[A-Za-z0-9]", exact_target)
    )
    api_exposure_query = "api_exposure" in (retrieval_plan.get("intents") or []) or (
        (retrieval_plan.get("retrieval_strategy") or {}).get("query_type") == "api_exposure"
    )
    try:
        max_candidates = max(50, min(int(os.getenv("SCIM_SEARCH_MAX_CANDIDATES", "250") or "250"), 1000))
    except (TypeError, ValueError):
        max_candidates = 250
    graph_candidates = [
        os.path.join(artifact_root, "combined_callgraph", "combined_callgraph.json"),
        os.path.join(artifact_root, "python", "python_callgraph.json"),
        os.path.join(artifact_root, "javascript", "javascript_callgraph.json"),
        os.path.join(artifact_root, "csharp", "csharp_callgraph.json"),
        os.path.join(artifact_root, "html_ui", "html_ui_graph.json"),
        os.path.join(artifact_root, "java_merged", "java_merged_callgraph.json"),
        os.path.join(artifact_root, "tree_sitter_java", "tree_sitter_java_callgraph.json"),
        os.path.join(artifact_root, "javalang", "javalang_callgraph.json"),
    ]
    outgoing = defaultdict(set)
    incoming = defaultdict(set)
    callgraph_nodes = set()
    for graph_path in graph_candidates:
        nodes, edges = _load_edge_graph(graph_path)
        callgraph_nodes.update(nodes)
        for src, dst in edges:
            outgoing[src].add(dst)
            incoming[dst].add(src)
            callgraph_nodes.add(src)
            callgraph_nodes.add(dst)
    resolve_graph_symbol = callgraph_suffix_resolver(callgraph_nodes)

    scored = []
    with sqlite3.connect(vector_db_path) as connection:
        rows = connection.execute(
            "SELECT repo_id, symbol, path, start_line, end_line, embedding, metadata FROM vectors"
        )
        for repo_id, symbol, path, start_line, end_line, blob, metadata_json in rows:
            metadata = json.loads(metadata_json or "{}")
            source_type = metadata.get("source_type") or ("code_function" if not metadata.get("is_typed_evidence") else "evidence")
            if metadata.get("is_typed_evidence") or metadata.get("is_derived_memory"):
                continue
            if source_type in {
                "evidence",
                "generated_feature_summary",
                "feature_summary",
                "derived_summary",
                "repo_overview",
                "callgraph_summary",
                "graph_artifact",
                "ga_summary",
                "ga_event",
                "ga_trace",
                "commit_history",
                "quality_signal",
                "artifact_text",
            }:
                continue
            evidence_text = str(metadata.get("evidence_text") or "")
            title = str(metadata.get("title") or "")
            api_candidate = is_api_exposure_candidate(symbol, path, metadata)
            non_api_page_candidate = is_non_api_next_page_candidate(symbol, path)
            if api_exposure_query and not api_candidate:
                if non_api_page_candidate:
                    continue
                if not re.search(r"\b(fetch|axios|graphql|trpc|grpc|webhook|http)\b", f"{symbol} {path} {title} {evidence_text}".lower()):
                    continue
            candidate_vector = blob_to_vector(blob)
            semantic_score = max((cosine_np(query_vector, candidate_vector) for query_vector in query_vectors), default=0.0)
            text_score, matched_terms = scim_text_match_score(symbol, path, metadata, query_terms)
            record_score, record_terms, match_source = 0, [], ""
            evidence_terms = sorted(
                term for term in query_terms
                if term in f"{source_type} {title} {symbol} {path} {evidence_text}".lower()
            )
            evidence_score = 0
            if evidence_terms:
                evidence_score = len(evidence_terms) * 18
                if source_type != "code_function":
                    match_source = "typed evidence"
            source_boost = int((retrieval_plan.get("source_boosts") or {}).get(source_type, 0))
            all_matched_terms = sorted(set(matched_terms) | set(record_terms) | set(evidence_terms))
            exact_ui_matches = exact_ui_records.get(str(symbol), [])
            if exact_ui_matches:
                all_matched_terms = sorted(set(all_matched_terms) | set(exact_ui_matches))
                match_source = "exact UI label"
            tail = symbol_tail(symbol)
            target_match = bool(target_terms and any(
                term == tail
                or (len(term) >= 4 and term in tail)
                or (len(tail) >= 4 and tail in term)
                for term in target_terms
            ))
            target_text = f"{source_type} {title} {symbol} {path} {evidence_text}".lower()
            target_text_match = bool(target_terms and any(term in target_text for term in target_terms))
            effective_source_boost = source_boost if (all_matched_terms or not require_literal) else 0
            literal_score = text_score + record_score + evidence_score + effective_source_boost
            if exact_ui_matches:
                literal_score += 600 + sum(len(value) for value in exact_ui_matches)
            if api_exposure_query:
                if api_candidate:
                    literal_score += 420
                    all_matched_terms = sorted(set(all_matched_terms) | {"api", "exposed", "route"})
                    match_source = match_source or "api route boundary"
                else:
                    literal_score -= 160
            if target_terms:
                if target_match:
                    literal_score += 180
                    all_matched_terms = sorted(set(all_matched_terms) | {tail} | set(target_terms))
                    match_source = "exact function target"
                elif source_type in {"generated_feature_summary", "feature_summary", "repo_overview", "derived_summary", "artifact_text"}:
                    if not target_text_match:
                        continue
                    literal_score -= 80
                elif exact_symbol_target_required:
                    continue
                elif not target_match and query_terms <= {"main"}:
                    continue
            if require_literal and not all_matched_terms:
                continue
            if query_terms and not all_matched_terms and semantic_score < 0.35 and not effective_source_boost:
                continue
            graph_symbol = resolve_graph_symbol(symbol)
            snippet = ""
            match_line = start_line
            scored.append({
                "score": float(semantic_score),
                "text_score": int(literal_score),
                "matched_terms": all_matched_terms,
                "match_source": match_source or ("symbol/path" if matched_terms else "semantic"),
                "match_snippet": snippet,
                "match_line": int(match_line or start_line or 0) or "",
                "source_type": source_type,
                "title": title,
                "evidence_text": evidence_text,
                "retrieval_intents": retrieval_plan.get("intents", []),
                "source_boost": int(effective_source_boost or 0),
                "repo_id": repo_id,
                "name": str(symbol).split(".")[-1],
                "fullName": symbol,
                "symbol": symbol,
                "graph_symbol": graph_symbol,
                "path": path,
                "start_line": int(start_line or 0) or "",
                "end_line": int(end_line or 0) or "",
                "line_count": int(metadata.get("line_count") or 0) or "",
                "in_degree": int(metadata.get("in_degree") or 0) if str(metadata.get("in_degree") or "").isdigit() else metadata.get("in_degree"),
                "out_degree": int(metadata.get("out_degree") or 0) if str(metadata.get("out_degree") or "").isdigit() else metadata.get("out_degree"),
                "calls": sorted(outgoing.get(graph_symbol or symbol, set()))[:20],
                "calledBy": sorted(incoming.get(graph_symbol or symbol, set()))[:20],
                "orderedExecution": [],
            })
            if len(scored) > max_candidates * 2:
                scored = sorted(
                    scored,
                    key=lambda item: float(item.get("score") or 0) * 100 + int(item.get("text_score") or 0),
                    reverse=True,
                )[:max_candidates]

    scored = rerank_scim_results(scored, query_brain)
    scored = scored[:max_candidates]
    candidate_symbols = [item.get("symbol") for item in scored[: max(limit * 4, 40)]]
    functions_path = Path(dataset_dir) / "functions.jsonl"
    function_records = load_scim_function_record_subset(dataset_dir, candidate_symbols)
    for item in scored[: max(limit * 4, 40)]:
        record = function_records.get(item.get("symbol"), {})
        record_score, record_terms, record_source = scim_record_match_score(
            item.get("symbol"),
            item.get("path"),
            {"class_name": record.get("class_name", ""), "method_name": record.get("method_name", "")},
            record,
            query_terms,
        )
        if record_score:
            item["text_score"] = int(item.get("text_score") or 0) + int(record_score)
            item["matched_terms"] = sorted(set(item.get("matched_terms") or []) | set(record_terms))
            item["match_source"] = record_source or item.get("match_source") or "function body"
        snippet, match_line = first_matching_code_line(record, query_terms, item.get("start_line"))
        item["match_snippet"] = snippet
        item["match_line"] = int(match_line or item.get("start_line") or 0) or ""
    scored = rerank_scim_results(scored, query_brain)
    results = scored[:limit]
    evidence_cards = build_scim_evidence_cards(results, [], limit=12)
    retrieval_context = build_retrieval_context(
        query,
        results,
        function_records,
        outgoing,
        incoming,
        resolve_graph_symbol,
    )
    if "data_flow" in (retrieval_plan.get("intents") or []):
        retrieval_context["data_flow_paths"] = collect_data_flow_paths(output_repo_dir)
    retrieval_context["query_brain"] = query_brain
    retrieval_context["retrieval_strategy"] = retrieval_plan.get("retrieval_strategy") or classify_retrieval_strategy(query, terms=query_terms)
    retrieval_context["evidence_cards"] = evidence_cards
    retrieval_context["scim_function_lookup"] = {
        "functions_path": str(functions_path),
        "functions_path_exists": functions_path.exists(),
        "candidate_symbol_count": len([symbol for symbol in candidate_symbols if symbol]),
        "loaded_function_record_count": len(function_records),
        "missing_symbols_sample": [
            symbol for symbol in candidate_symbols if symbol and symbol not in function_records
        ][:12],
    }
    return {
        "results": results,
        "retrieval_context": retrieval_context,
        "retrieval_plan": retrieval_plan,
        "retrieval_strategy": retrieval_context["retrieval_strategy"],
        "query_brain": query_brain,
    }




def _callgraph_symbol_matches(candidate, target_lower: str, target_tail_lower: str) -> bool:
    candidate_str = str(candidate or "")
    if not candidate_str:
        return False
    candidate_lower = candidate_str.lower()
    return candidate_lower == target_lower or candidate_lower.rsplit(".", 1)[-1] == target_tail_lower


def find_callers(output_dir: str, symbol: str) -> list[dict]:
    """Return all nodes in the callgraph that call `symbol`."""
    try:
        callgraph, _ = load_search_callgraph(output_dir)
    except Exception:
        return []

    # Real callgraph symbols are dotted, mixed-case qualified names
    # (e.g. "apps.storefront.src.lib.data.cart.getOrSetCart"), so match
    # case-insensitively against either the full name or its trailing component.
    target_lower = str(symbol or "").lower()
    target_tail_lower = function_tail(symbol).lower()

    callers = []
    if isinstance(callgraph, dict):
        for caller, callees in callgraph.items():
            if any(_callgraph_symbol_matches(callee, target_lower, target_tail_lower) for callee in callees):
                callers.append({"caller": caller, "callee": symbol})
        return callers

    # Modern load_search_callgraph() shape: a list of {"method", "calls": [...]}.
    for entry in callgraph or []:
        if not isinstance(entry, dict):
            continue
        caller = entry.get("method")
        for call in entry.get("calls", []) or []:
            if isinstance(call, dict) and _callgraph_symbol_matches(call.get("callee_fullName"), target_lower, target_tail_lower):
                callers.append({"caller": caller, "callee": call.get("callee_fullName")})
    return callers

def find_callees(output_dir: str, symbol: str) -> list[dict]:
    """Return all nodes that `symbol` calls."""
    try:
        callgraph, _ = load_search_callgraph(output_dir)
    except Exception:
        return []

    target_lower = str(symbol or "").lower()
    target_tail_lower = function_tail(symbol).lower()

    if isinstance(callgraph, dict):
        for caller, callees in callgraph.items():
            if _callgraph_symbol_matches(caller, target_lower, target_tail_lower):
                return [{"caller": caller, "callee": callee} for callee in callees]
        return []

    # Modern load_search_callgraph() shape: a list of {"method", "calls": [...]}.
    for entry in callgraph or []:
        if isinstance(entry, dict) and _callgraph_symbol_matches(entry.get("method"), target_lower, target_tail_lower):
            return [
                {"caller": entry.get("method"), "callee": call.get("callee_fullName")}
                for call in entry.get("calls", []) or []
                if isinstance(call, dict) and call.get("callee_fullName")
            ]
    return []


#============================================================
# --- feature_explanation handler ---
#============================================================

# callgraph_adjacency/_traverse_callgraph_bfs/traverse_forward/traverse_backward
# live in features/core/helpers.py (not here) so lightweight callers — like the
# deletion/blast-radius PostToolUse hook — can use them without paying the cost
# of importing this whole module (FastAPI app, Joern/ML deps, ...): that import
# alone takes ~2.5s, which is too slow for a hook that fires after every edit.
callgraph_adjacency = core_helpers.callgraph_adjacency
_traverse_callgraph_bfs = core_helpers._traverse_callgraph_bfs
traverse_forward = core_helpers.traverse_forward
traverse_backward = core_helpers.traverse_backward
get_function_spans = core_helpers.get_function_spans
get_impact_radius = core_helpers.get_impact_radius


def feature_explanation_resolve_roots(target: str, callgraph) -> list[str]:
    """Find callgraph node names matching a free-text target. Tries the exact/tail
    match used elsewhere in the codebase first; feature-level concepts (e.g.
    "checkout") are often a module segment rather than a function tail
    (app.routes.checkout.start_checkout), so fall back to substring containment
    against the dotted path when the precise match finds nothing."""
    if not target:
        return []
    target_lower = target.lower()
    target_tail_lower = function_tail(target).lower()
    forward, backward = callgraph_adjacency(callgraph)
    all_nodes = set(forward) | set(backward)
    for callees in forward.values():
        all_nodes |= callees

    exact_matches = sorted(node for node in all_nodes if _callgraph_symbol_matches(node, target_lower, target_tail_lower))
    if exact_matches:
        return exact_matches
    if len(target_lower) < 3:
        return []
    return sorted(node for node in all_nodes if target_lower in node.lower())


def feature_explanation_symbol_index_fallback(output_repo_dir, target: str, limit: int = 8) -> list[dict]:
    """Fall back to the SCIM symbol index when no callgraph nodes match the target."""
    if not target:
        return []
    functions_path = find_scim_functions_path(Path(output_repo_dir))
    if not functions_path:
        return []
    records = load_scim_function_records(functions_path.parent)
    target_lower = target.lower()
    target_tail_lower = function_tail(target).lower()
    matches = [
        {"symbol": symbol, "path": record_source_path(record), "line": record.get("start_line")}
        for symbol, record in records.items()
        if _callgraph_symbol_matches(symbol, target_lower, target_tail_lower)
    ]
    return matches[:limit]


def feature_explanation_node_locations(nodes, output_repo_dir) -> dict[str, dict]:
    """Resolve callgraph node names to {path, line} via the SCIM symbol index, for
    building file lists and showing readers where each step actually lives."""
    if not nodes:
        return {}
    functions_path = find_scim_functions_path(Path(output_repo_dir))
    if not functions_path:
        return {}
    records = load_scim_function_records(functions_path.parent)
    locations = {}
    for node in nodes:
        record = records.get(node)
        if record:
            locations[node] = {"path": record_source_path(record), "line": record.get("start_line")}
    return locations


FEATURE_EXPLANATION_MAX_CONTEXT_CHARS = 4000 * 4  # ~4000 tokens at ~4 chars/token; no tokenizer dependency available


def build_feature_explanation_context(
    target: str,
    forward_walk: dict,
    backward_walk: dict,
    node_locations: dict,
    recent_commits: list[dict],
    fallback_matches: list[dict],
) -> str:
    lines = [f"FEATURE/TARGET: {target or '(not extracted from query)'}"]

    if fallback_matches:
        lines.append("\nSYMBOL INDEX MATCHES (no callgraph edges found; falling back to symbol search):")
        for match in fallback_matches:
            lines.append(f"- {match['symbol']} ({match.get('path') or 'unknown file'}:{match.get('line') or '?'})")

    if backward_walk.get("nodes"):
        lines.append(f"\nCALLERS (up to {backward_walk.get('max_depth_reached', 0)} levels back, what calls this):")
        for node in backward_walk["nodes"][:60]:
            location = node_locations.get(node) or {}
            lines.append(f"- {node} ({location.get('path') or 'unknown file'}:{location.get('line') or '?'})")

    if forward_walk.get("nodes"):
        lines.append(f"\nCALLEES (up to {forward_walk.get('max_depth_reached', 0)} levels forward, what this calls):")
        for node in forward_walk["nodes"][:60]:
            location = node_locations.get(node) or {}
            lines.append(f"- {node} ({location.get('path') or 'unknown file'}:{location.get('line') or '?'})")

    if forward_walk.get("edges"):
        lines.append("\nCALL EDGES (caller -> callee, ordered by traversal):")
        for caller, callee in forward_walk["edges"][:80]:
            lines.append(f"- {caller} -> {callee}")

    if recent_commits:
        lines.append("\nRECENT REPOSITORY COMMITS:")
        for commit in recent_commits[:10]:
            lines.append(f"- {commit.get('short_sha', '')} {commit.get('message', '')} ({commit.get('author', '')}, {commit.get('date', '')})")

    context = "\n".join(lines)
    if len(context) > FEATURE_EXPLANATION_MAX_CONTEXT_CHARS:
        context = context[:FEATURE_EXPLANATION_MAX_CONTEXT_CHARS] + "\n\n[Context truncated by CodeVal to stay within the answer-generation budget.]"
    return context


def build_feature_explanation_prompt(query: str, context: str) -> str:
    return f"""You are explaining how a feature works in a software repository.
Use ONLY the evidence below. Do not invent files, functions, or behavior that is not shown.
If the evidence is too thin to answer part of the question, say so explicitly instead of guessing.

QUESTION:
{query}

EVIDENCE:
{context}

Answer with these sections, in this order:
1. Entry point - where execution for this feature starts.
2. Step by step flow - the ordered sequence of what happens.
3. Key functions - for each important function: name, file, and its purpose.
4. Data touched - what is read and what is written (variables, database, cache, files).
5. External dependencies - third-party services, APIs, or libraries involved.
6. Recent changes - anything from the commit evidence relevant to this feature, or note if none was found.
"""


def handle_feature_explanation(owner_name: str, repo_name: str, query: str) -> str:
    """Handler for the "feature_explanation" query type: explain HOW something
    works, grounded in callgraph traversal (5 levels forward, 3 back) plus
    recent commit history, instead of a single-hop location lookup."""
    output_repo_dir = repo_output_dir(owner_name, repo_name)
    target = extract_search_target(query)

    try:
        callgraph, _source = load_search_callgraph(artifact_root_for_output(Path(output_repo_dir)))
    except Exception:
        callgraph = []

    roots = feature_explanation_resolve_roots(target, callgraph)
    fallback_matches = []
    if not roots:
        fallback_matches = feature_explanation_symbol_index_fallback(output_repo_dir, target)
        roots = [match["symbol"] for match in fallback_matches]

    forward_walk = traverse_forward(roots, callgraph, max_depth=5) if roots else {"nodes": [], "edges": [], "max_depth_reached": 0}
    backward_walk = traverse_backward(roots, callgraph, max_depth=3) if roots else {"nodes": [], "edges": [], "max_depth_reached": 0}

    touched_nodes = set(roots) | set(forward_walk.get("nodes") or []) | set(backward_walk.get("nodes") or [])
    node_locations = feature_explanation_node_locations(touched_nodes, output_repo_dir)

    recent_commits = []
    try:
        commit_payload = github_daily_commits_for_token(owner_name, repo_name, days=14)
        recent_commits = commit_payload.get("commits") or []
    except Exception as e:
        logger.info("feature_explanation: recent commit lookup skipped for %s/%s: %s", owner_name, repo_name, e)

    context = build_feature_explanation_context(
        target, forward_walk, backward_walk, node_locations, recent_commits, fallback_matches,
    )
    prompt = build_feature_explanation_prompt(query, context)
    return generate_search_answer_from_prompt(prompt)


#============================================================
# --- module level, before @app.post("/search") ---
#============================================================

def _inject_caller_data(payload: dict, output_dir: str, caller_symbol: str | None, callee_symbol: str | None) -> dict:
    if caller_symbol:
        payload["caller_symbol"] = caller_symbol
        payload["caller_results"] = find_callers(output_dir, caller_symbol)
    
    if callee_symbol:
        payload["callee_symbol"] = callee_symbol
        payload["callee_results"] = find_callees(output_dir, callee_symbol)

    if caller_symbol and callee_symbol:
        payload["query_type"] = "callers_and_callees"
    elif caller_symbol:
        payload["query_type"] = "callers"
    elif callee_symbol:
        payload["query_type"] = "callees"
        
    return payload



def load_all_symbols(output_repo_dir: Path):
    symbols = set()

    # 1. Load current SCIM function records, plus older top-level function indexes.
    artifact_root = artifact_root_for_output(output_repo_dir)
    for functions_path in (artifact_root / "scim" / "functions.jsonl", output_repo_dir / "functions.jsonl"):
        if functions_path.exists():
            try:
                with open(functions_path, "r", encoding="utf-8") as f:
                    for line in f:
                        try:
                            obj = json.loads(line)
                            full = obj.get("symbol") or obj.get("full_name") or obj.get("name")
                            if full:
                                symbols.add(full)
                        except Exception:
                            continue
            except Exception:
                pass

    # 2. Load current graph nodes, plus older top-level callgraph indexes.
    graph_paths = [
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "csharp" / "csharp_callgraph.json",
        artifact_root / "html_ui" / "html_ui_graph.json",
        artifact_root / "java_merged" / "java_merged_callgraph.json",
        artifact_root / "tree_sitter_java" / "tree_sitter_java_callgraph.json",
        artifact_root / "javalang" / "javalang_callgraph.json",
        output_repo_dir / "callgraph.json",
    ]
    for graph_path in graph_paths:
        if graph_path.exists():
            try:
                nodes, edges = _load_edge_graph(str(graph_path))
                symbols.update(nodes)
                for src, dst in edges:
                    symbols.add(src)
                    symbols.add(dst)
            except Exception:
                pass

    # 3. Load architecture feature catalog.
    scim_catalog_path = core_helpers.feature_catalog_path_for_output(output_repo_dir)
    if scim_catalog_path.exists():
        try:
            with open(scim_catalog_path, "r", encoding="utf-8") as f:
                catalog = json.load(f)
                for feat in catalog:
                    name = feat.get("name")
                    if name:
                        symbols.add(name)
        except:
            pass

    return sorted(symbols)


def lookup_symbol_info(symbol: str, output_repo_dir: Path):
    artifact_root = artifact_root_for_output(output_repo_dir)
    graph_symbol = ""
    calls = []
    called_by = []
    try:
        callgraph, _ = load_search_callgraph(artifact_root)
        _, functions, outgoing, incoming, _ = callgraph_indexes(callgraph)
        root_set = resolve_search_graph_roots([symbol], functions)
        graph_symbol = sorted(root_set)[0] if root_set else ""
        if graph_symbol:
            calls = sorted(outgoing.get(graph_symbol, []))[:20]
            called_by = sorted(incoming.get(graph_symbol, []))[:20]
    except Exception:
        graph_symbol = ""
        calls = []
        called_by = []

    # 1. Look in current SCIM function records, plus older top-level function indexes.
    for functions_path in (artifact_root / "scim" / "functions.jsonl", output_repo_dir / "functions.jsonl"):
        if functions_path.exists():
            try:
                with open(functions_path, "r", encoding="utf-8") as f:
                    for line in f:
                        try:
                            obj = json.loads(line)
                            obj_symbol = obj.get("symbol") or obj.get("full_name") or obj.get("name")
                            if obj_symbol == symbol:
                                return {
                                    "type": "function",
                                    "symbol": symbol,
                                    "fullName": symbol,
                                    "name": str(symbol).split(".")[-1],
                                    "path": obj.get("path") or obj.get("file"),
                                    "file": obj.get("path") or obj.get("file"),
                                    "start_line": obj.get("start_line") or obj.get("line"),
                                    "line": obj.get("start_line") or obj.get("line"),
                                    "end_line": obj.get("end_line"),
                                    "signature": obj.get("signature"),
                                    "docstring": obj.get("docstring"),
                                    "match_source": "symbol/path",
                                    "graph_symbol": graph_symbol,
                                    "calls": calls,
                                    "calledBy": called_by,
                                }
                        except Exception:
                            continue
            except Exception:
                pass

    # 2. Look in architecture feature catalog
    scim_path = core_helpers.feature_catalog_path_for_output(output_repo_dir)
    if scim_path.exists():
        try:
            with open(scim_path, "r", encoding="utf-8") as f:
                catalog = json.load(f)
                for feat in catalog:
                    if feat.get("name") == symbol:
                        return {
                            "type": "scim_feature",
                            "symbol": symbol,
                            "description": feat.get("description"),
                            "source": feat.get("source"),
                        }
        except Exception:
            pass

    # 3. Look in callgraph.json
    callgraph_path = output_repo_dir / "callgraph.json"
    if callgraph_path.exists():
        try:
            with open(callgraph_path, "r", encoding="utf-8") as f:
                cg = json.load(f)
                for node in cg.get("nodes", []):
                    if node.get("id") == symbol:
                        return {
                            "type": "callgraph_node",
                            "symbol": symbol,
                            "callers": node.get("callers", []),
                            "callees": node.get("callees", []),
                        }
        except Exception:
            pass

    # 4. Fallback
    return {
        "type": "callgraph_node" if graph_symbol else "unknown_symbol",
        "symbol": graph_symbol or symbol,
        "fullName": graph_symbol or symbol,
        "name": str(graph_symbol or symbol).split(".")[-1],
        "graph_symbol": graph_symbol,
        "calls": calls,
        "calledBy": called_by,
        "match_source": "callgraph symbol" if graph_symbol else "symbol/path",
    }


def scoped_callgraph_results_for_target(output_repo_dir: Path, target: str, callgraph: list[dict]):
    ORDERED_CALLS, FUNCTION_SET, outgoing, incoming, _ = callgraph_indexes(callgraph)
    resolved_roots = resolve_search_graph_roots([target], FUNCTION_SET)
    if not resolved_roots:
        return [], set()

    results = []
    for root in sorted(resolved_roots):
        symbol_info = lookup_symbol_info(root, output_repo_dir) or {}
        ordered = []
        for call in ORDERED_CALLS.get(root, []) or []:
            if not is_real_call(call):
                continue
            try:
                line = int(call.get("line")) if call.get("line") is not None else None
            except (TypeError, ValueError):
                line = None
            try:
                order = int(call.get("order")) if call.get("order") is not None else None
            except (TypeError, ValueError):
                order = None
            ordered.append({
                "callee_fullName": call.get("callee_fullName"),
                "line": line,
                "order": order,
                "call_code": call.get("call_code"),
                "call_name": call.get("call_name"),
            })
        ordered.sort(key=lambda item: (
            item["line"] if item["line"] is not None else 0,
            item["order"] if item["order"] is not None else 0,
            str(item.get("callee_fullName") or ""),
        ))
        results.append({
            **symbol_info,
            "type": symbol_info.get("type") if symbol_info.get("type") != "unknown_symbol" else "function",
            "symbol": root,
            "fullName": root,
            "name": symbol_info.get("name") or str(root).split(".")[-1],
            "graph_symbol": root,
            "calls": sorted(outgoing.get(root, []))[:50],
            "calledBy": sorted(incoming.get(root, []))[:50],
            "orderedExecution": ordered,
            "match_source": symbol_info.get("match_source") or "callgraph symbol",
        })
    return results, resolved_roots


def scoped_callgraph_code_units(output_repo_dir: Path, resolved_roots: set[str], results: list[dict], max_related=6):
    artifact_root = artifact_root_for_output(output_repo_dir)
    function_records = load_scim_function_records(artifact_root / "scim")
    if not function_records:
        return []

    by_lower = {str(symbol).lower(): symbol for symbol in function_records}

    def resolve_record(symbol):
        symbol = str(symbol or "")
        if symbol in function_records:
            return function_records[symbol]
        lowered = symbol.lower()
        if lowered in by_lower:
            return function_records[by_lower[lowered]]
        suffix_matches = [
            candidate for candidate in function_records
            if str(candidate).lower().endswith(f".{lowered}") or str(candidate).lower().endswith(f"_{lowered}")
        ]
        if suffix_matches:
            suffix_matches.sort(key=len)
            return function_records[suffix_matches[0]]
        return {}

    units = []
    seen = set()

    def add(symbol, role):
        record = resolve_record(symbol)
        record_symbol = str(record.get("symbol") or symbol or "")
        if not record or record_symbol in seen:
            return
        unit = code_unit_summary(record, role)
        if unit:
            seen.add(record_symbol)
            units.append(unit)

    for root in sorted(resolved_roots or []):
        add(root, "match")

    for item in results or []:
        for symbol in item.get("calledBy") or []:
            if len(units) >= max_related + len(resolved_roots or []):
                break
            add(symbol, "caller")
        for symbol in item.get("calls") or []:
            if len(units) >= (max_related * 2) + len(resolved_roots or []):
                break
            add(symbol, "callee")
    return units




def match_feature_catalog_entry(query: str, artifact_root: Path, min_similarity: float = 0.34):
    """Match a 'where is feature X implemented' question against the repo's catalogued
    feature names before falling back to generic text/symbol search. Without this, a
    question naming a feature by its UI display name (e.g. "Ask CodeVal") can collide
    with unrelated identifiers that merely share a substring with the product name."""
    catalog_path = core_helpers.feature_catalog_path_for_output(Path(artifact_root))
    if not catalog_path or not os.path.exists(catalog_path):
        return None
    try:
        with open(catalog_path, "r", encoding="utf-8") as f:
            catalog = json.load(f)
    except (OSError, ValueError):
        return None
    if not isinstance(catalog, dict):
        return None

    candidates = [str(query or "")]
    target = extract_search_target(query)
    if target:
        candidates.append(target)
    candidates.extend(ui_label_query_phrases(query))

    pool = []
    for feature in (catalog.get("features") or []):
        if not isinstance(feature, dict):
            continue
        name = str(feature.get("feature") or feature.get("name") or "").strip()
        if name:
            pool.append((name, feature.get("evidence") or [], feature.get("source") or "feature_catalog"))
    for seed in (catalog.get("ui_feature_seeds") or []):
        seed_name = str(seed or "").strip()
        if seed_name:
            pool.append((seed_name, [], "ui_feature_seed"))

    best = None
    best_score = 0.0
    normalized_query = " ".join(re.findall(r"[a-z0-9]+", str(query or "").lower()))
    for name, evidence, source in pool:
        for candidate in candidates:
            if not str(candidate or "").strip():
                continue
            normalized_name = " ".join(re.findall(r"[a-z0-9]+", name.lower()))
            exact_phrase_match = bool(
                normalized_name
                and re.search(rf"(?:^|\s){re.escape(normalized_name)}(?:\s|$)", normalized_query)
            )
            score = 1.0 if exact_phrase_match else feature_graph_similarity(candidate, name)
            if score > best_score:
                best_score = score
                best = {"feature": name, "evidence": evidence, "source": source}

    if not best or best_score < min_similarity:
        return None
    best["score"] = best_score
    return best


def feature_catalog_match_to_text_results(match: dict):
    results = []
    for item in (match.get("evidence") or [])[:6]:
        if not isinstance(item, dict):
            continue
        path = str(item.get("path") or "")
        line = item.get("start_line") or item.get("line")
        symbol = str(item.get("symbol") or "")
        if not path and not symbol:
            continue
        snippet = f"Catalogued feature \"{match.get('feature')}\" is implemented by {symbol or 'this code'}".strip()
        results.append({
            "kind": "catalogued feature match",
            "file": path,
            "line": line,
            "text": snippet,
            "matched_terms": [match.get("feature")],
            "_score": 10_000 + int((match.get("score") or 0) * 100),
        })
    return results


def structured_anchor_from_exact_ui(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    labels = ui_label_query_phrases(query)
    if not labels:
        return {}
    dataset_dir = artifact_root / "scim"
    symbol_matches = exact_ui_label_record_matches(dataset_dir, labels)
    if not symbol_matches:
        return {}
    records = load_scim_function_record_subset(dataset_dir, symbol_matches.keys())
    anchors = []
    text_results = []
    for symbol, matched_labels in symbol_matches.items():
        record = records.get(symbol) or {}
        path = record.get("path") or ""
        line = record.get("start_line") or ""
        code = str(record.get("code") or "")
        anchors.append({
            "type": "ui_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": record.get("end_line") or line,
            "match_line": line,
            "match_snippet": code[:1200],
            "match_source": "exact UI label",
            "matched_terms": matched_labels,
            "evidence_tag": "MARKUP",
            "evidence_strength": hybrid_evidence_strength("MARKUP", exact=True),
        })
        text_results.append({
            "kind": "ui label exact match",
            "file": path,
            "line": line,
            "text": code[:1200],
            "matched_terms": matched_labels,
            "evidence_tag": "MARKUP",
            "evidence_strength": hybrid_evidence_strength("MARKUP", exact=True),
        })
    return {
        "provider": "exact_ui",
        "priority": 100,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"labels": labels},
    }


def structured_anchor_from_exact_symbol(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    target = extract_search_target(query)
    if not target or target.lower() in CALLGRAPH_SYMBOL_STOPWORDS:
        return {}
    try:
        callgraph, _ = load_search_callgraph(artifact_root)
    except Exception:
        return {}
    _, functions, outgoing, incoming, _ = callgraph_indexes(callgraph)
    resolved = resolve_search_graph_roots([target], functions)
    exact_tail = str(target).lower().split(".")[-1]
    resolved = {
        symbol for symbol in resolved
        if str(symbol).lower() == str(target).lower()
        or str(symbol).lower().split(".")[-1] == exact_tail
    }
    if not resolved:
        return {}
    anchors = []
    text_results = []
    for symbol in sorted(resolved):
        info = lookup_symbol_info(symbol, output_repo_dir) or {}
        path = info.get("path") or info.get("file") or ""
        line = info.get("start_line") or info.get("line") or ""
        anchors.append({
            **info,
            "type": "exact_symbol_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "graph_symbol": symbol,
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": info.get("end_line") or line,
            "calls": sorted(outgoing.get(symbol, set()))[:50],
            "calledBy": sorted(incoming.get(symbol, set()))[:50],
            "match_source": "exact function target",
            "matched_terms": [target],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
        text_results.append({
            "kind": "exact symbol match",
            "file": path,
            "line": line,
            "text": f"{symbol} is defined in {path or 'the callgraph symbol index'}.",
            "matched_terms": [target],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
    return {
        "provider": "exact_symbol",
        "priority": 98,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"target": target},
    }


def structured_anchor_from_test_references(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    lowered = str(query or "").lower()
    if not any(phrase in lowered for phrase in ("tests cover", "test covers", "test coverage")):
        return {}
    target = extract_search_target(query)
    if not target or target.lower() in CALLGRAPH_SYMBOL_STOPWORDS:
        return {}
    target_variants = search_identifier_variants(target) | {str(target).lower()}
    records = load_scim_function_records(artifact_root / "scim")
    anchors = []
    text_results = []
    for symbol, record in records.items():
        path = str(record.get("path") or "").replace("\\", "/")
        code = str(record.get("code") or "")
        searchable = f"{symbol}\n{path}\n{code}".lower()
        is_test_record = bool(
            re.search(r"(^|/)(tests?|specs?|__tests__)(/|$)", path.lower())
            or re.search(r"(?:^|[._])(test|spec)(?:[._]|$)", str(symbol).lower())
            or re.search(r"(?:^|[._-])(test|spec)\.[^.]+$", path.lower())
        )
        matched = sorted(variant for variant in target_variants if variant and variant in searchable)
        if not is_test_record or not matched:
            continue
        line = record.get("start_line") or ""
        snippet = next(
            (source_line.strip() for source_line in code.splitlines() if any(item in source_line.lower() for item in matched)),
            first_code_line(record),
        )
        anchors.append({
            "type": "test_reference_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": record.get("end_line") or line,
            "match_line": line,
            "match_snippet": snippet,
            "match_source": "exact test reference",
            "matched_terms": matched,
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True) + 50,
        })
        text_results.append({
            "kind": "exact test reference",
            "file": path,
            "line": line,
            "text": f"{symbol}: {snippet}",
            "matched_terms": matched,
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True) + 50,
        })
    return {
        "provider": "test_references",
        "priority": 99,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"target": target, "match_count": len(anchors)},
    } if anchors else {}


def structured_anchor_from_api_routes(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    if not is_api_exposure_query(query):
        return {}
    dataset_dir = artifact_root / "scim"
    records = load_scim_function_records(dataset_dir)
    graph_entry_points = set()
    try:
        callgraph_payload = load_json_file(
            artifact_root / "combined_callgraph" / "combined_callgraph.json",
            {},
        )
        graph_entry_points.update(str(item) for item in callgraph_payload.get("entry_points") or [] if item)
    except Exception:
        pass
    anchors = []
    text_results = []
    for symbol, record in records.items():
        path = str(record.get("path") or "")
        code = str(record.get("code") or "")
        route_boundary = is_api_exposure_candidate(symbol, path, {"code": code})
        graph_boundary = (
            symbol in graph_entry_points
            and str(symbol).lower().split(".")[-1] not in {"main", "cli"}
            and str(path).lower().endswith(
            (".py", ".js", ".jsx", ".ts", ".tsx", ".java", ".cs", ".go", ".rb", ".php")
            )
        )
        if not route_boundary and not graph_boundary:
            continue
        line = record.get("start_line") or ""
        route_line = next(
            (
                source_line.strip()
                for source_line in code.splitlines()
                if re.search(
                    r"@\w+\.(?:get|post|put|patch|delete|options|head|api_route)\s*\(|"
                    r"\b(?:app|router)\.(?:get|post|put|patch|delete|options|head|use|route)\s*\(|"
                    r"\bexport\s+(?:async\s+)?function\s+(?:GET|POST|PUT|PATCH|DELETE|OPTIONS|HEAD)\b",
                    source_line,
                    re.IGNORECASE,
                )
            ),
            (
                f"Graph entry point: {symbol}"
                if graph_boundary
                else first_code_line(record)
            ),
        )
        anchors.append({
            "type": "api_route_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "graph_symbol": symbol,
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": record.get("end_line") or line,
            "match_line": line,
            "match_snippet": route_line,
            "match_source": "exact API route boundary" if route_boundary else "graph entrypoint API boundary",
            "matched_terms": ["api", "route", "internet exposed"],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
        text_results.append({
            "kind": "API route boundary",
            "file": path,
            "line": line,
            "text": f"{symbol}: {route_line}",
            "matched_terms": ["api", "route"],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
    return {
        "provider": "api_routes",
        "priority": 96,
        "anchors": anchors[:100],
        "text_results": text_results[:100],
        "metadata": {"route_count": len(anchors)},
    } if anchors else {}


def structured_anchor_from_route(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    routes = extract_hybrid_query_entities(query).get("routes") or []
    if not routes:
        return {}
    try:
        callgraph, _ = load_search_callgraph(artifact_root)
    except Exception:
        return {}
    _, functions, outgoing, incoming, _ = callgraph_indexes(callgraph)
    entry_points = set()
    callgraph_path = artifact_root / "combined_callgraph" / "combined_callgraph.json"
    callgraph_payload = load_json_file(callgraph_path, {})
    entry_points.update(str(item) for item in callgraph_payload.get("entry_points") or [] if item)
    anchors = []
    text_results = []
    for route in routes:
        route_terms = [
            term.lower()
            for term in re.findall(r"[A-Za-z0-9]+", route)
            if term.lower() not in {"api", "v1", "v2"}
        ]
        if not route_terms:
            continue
        candidates = []
        for symbol in entry_points or functions:
            tail_terms = re.findall(r"[A-Za-z0-9]+", str(symbol).split(".")[-1].replace("_", " "))
            normalized_tail = "".join(term.lower() for term in tail_terms)
            normalized_route = "".join(route_terms)
            if normalized_route == normalized_tail or all(term in normalized_tail for term in route_terms):
                candidates.append(symbol)
        for symbol in sorted(candidates, key=lambda item: (len(str(item)), str(item)))[:4]:
            info = lookup_symbol_info(symbol, output_repo_dir) or {}
            path = info.get("path") or info.get("file") or ""
            line = info.get("start_line") or info.get("line") or ""
            anchors.append({
                **info,
                "type": "route_anchor",
                "symbol": symbol,
                "fullName": symbol,
                "name": str(symbol).split(".")[-1],
                "graph_symbol": symbol,
                "path": path,
                "file": path,
                "start_line": line,
                "end_line": info.get("end_line") or line,
                "calls": sorted(outgoing.get(symbol, set()))[:50],
                "calledBy": sorted(incoming.get(symbol, set()))[:50],
                "match_source": "exact route entrypoint",
                "matched_terms": [route],
                "evidence_tag": "SOURCE",
                "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
            })
            text_results.append({
                "kind": "exact route entrypoint",
                "file": path,
                "line": line,
                "text": f"{route} resolves to {symbol}.",
                "matched_terms": [route],
                "evidence_tag": "SOURCE",
                "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
            })
    return {
        "provider": "exact_route",
        "priority": 99,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"routes": routes},
    } if anchors else {}


def extract_named_api_entities(query: str) -> list[str]:
    text = str(query or "").strip()
    if not text:
        return []
    entities = []
    patterns = (
        r"\b([A-Za-z][A-Za-z0-9_.:-]*(?:\s+[A-Za-z][A-Za-z0-9_.:-]*){0,3})\s+(?:API|service|client|integration)\b",
        r"\b(?:api|service|client|integration)\s+(?:for|called|named)\s+([A-Za-z][A-Za-z0-9_.:-]*(?:\s+[A-Za-z][A-Za-z0-9_.:-]*){0,3})\b",
    )
    leading_noise = {
        "the", "this", "that", "user", "users", "program", "app", "application",
        "api", "service", "client", "integration", "when", "what", "happens",
        "click", "clicks", "clicked", "calls", "call", "trace", "show",
    }
    trailing_noise = {"api", "service", "client", "integration"}
    for pattern in patterns:
        for match in re.finditer(pattern, text, re.IGNORECASE):
            words = [word.strip(" ?.,:;!()[]{}\"'") for word in re.split(r"\s+", match.group(1)) if word.strip()]
            while words and words[0].lower() in leading_noise:
                words.pop(0)
            while words and words[-1].lower() in trailing_noise:
                words.pop()
            if words:
                entities.append(" ".join(words))
    return list(dict.fromkeys(entity for entity in entities if loose_symbol_key(entity)))


def named_api_entity_variants(entity: str) -> set[str]:
    key = loose_symbol_key(entity)
    variants = {entity, key}
    words = re.findall(r"[A-Za-z0-9]+", str(entity or ""))
    if words:
        variants.add(" ".join(words))
        variants.add("_".join(word.lower() for word in words))
        variants.add("-".join(word.lower() for word in words))
        variants.add("".join(words))
    return {variant for variant in variants if loose_symbol_key(variant)}


def named_api_candidate_score(entity_variants: set[str], symbol: str, path: str = "", text: str = "", outgoing_count: int = 0, incoming_count: int = 0) -> int:
    symbol_key = loose_symbol_key(symbol)
    path_text = str(path or "").replace("\\", "/")
    path_key = loose_symbol_key(path_text)
    text_key = loose_symbol_key(text[:2000])
    score = 0
    for variant in entity_variants:
        variant_key = loose_symbol_key(variant)
        if not variant_key:
            continue
        if variant_key == symbol_key or symbol_key.endswith(variant_key):
            score = max(score, 120)
        elif variant_key in symbol_key:
            score = max(score, 100)
        if variant_key in path_key:
            score = max(score, 95)
        if variant_key in text_key:
            score = max(score, 70)
    lower_path = path_text.lower()
    lower_symbol = str(symbol or "").lower()
    if lower_symbol.startswith("api."):
        score += 35
    if re.search(r"(^|/)(api|routes?|controllers?|handlers?)(/|$)", lower_path):
        score += 25
    if lower_path.endswith(("-openapi.json", "openapi.json", "swagger.json")):
        score += 20
    if outgoing_count:
        score += min(outgoing_count, 8) * 3
    if incoming_count:
        score += min(incoming_count, 8) * 2
    return score


def structured_anchor_from_named_api(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    entities = extract_named_api_entities(query)
    if not entities:
        return {}
    dataset_dir = artifact_root / "scim"
    records = load_scim_function_records(dataset_dir)
    try:
        callgraph, callgraph_source = load_search_callgraph(artifact_root)
    except Exception:
        callgraph = []
        callgraph_source = ""
    _, functions, outgoing, incoming, _ = callgraph_indexes(callgraph)
    candidate_symbols = set(functions) | set(records)
    candidates = []
    for entity in entities:
        variants = named_api_entity_variants(entity)
        for symbol in candidate_symbols:
            record = records.get(symbol) or {}
            path = str(record.get("path") or record.get("file") or "")
            text = "\n".join(
                str(value or "")
                for value in (
                    symbol,
                    path,
                    record.get("signature"),
                    record.get("docstring"),
                    record.get("code"),
                )
            )
            score = named_api_candidate_score(
                variants,
                symbol,
                path,
                text,
                outgoing_count=len(outgoing.get(symbol, [])),
                incoming_count=len(incoming.get(symbol, [])),
            )
            if score >= 95:
                candidates.append((score, entity, symbol, record))
        for symbol in list(candidate_symbols):
            symbol_key = loose_symbol_key(symbol)
            for caller in incoming.get(symbol, [])[:25]:
                caller_record = records.get(caller) or {}
                caller_path = str(caller_record.get("path") or caller_record.get("file") or "")
                caller_score = named_api_candidate_score(
                    variants,
                    caller,
                    caller_path,
                    f"{caller}\n{caller_path}",
                    outgoing_count=len(outgoing.get(caller, [])),
                    incoming_count=len(incoming.get(caller, [])),
                )
                if caller_score >= 95 or any(loose_symbol_key(variant) in symbol_key for variant in variants):
                    candidates.append((max(caller_score, 96), entity, caller, caller_record))

    seen = set()
    anchors = []
    text_results = []
    for score, entity, symbol, record in sorted(candidates, key=lambda item: (-item[0], len(str(item[2])), str(item[2])))[:30]:
        if symbol in seen:
            continue
        seen.add(symbol)
        info = lookup_symbol_info(symbol, output_repo_dir) or {}
        path = info.get("path") or info.get("file") or record.get("path") or record.get("file") or ""
        line = info.get("start_line") or info.get("line") or record.get("start_line") or ""
        code = str(record.get("code") or "")
        snippet = first_code_line(record) if record else (info.get("match_snippet") or "")
        anchors.append({
            **info,
            "type": "named_api_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "graph_symbol": info.get("graph_symbol") or symbol,
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": info.get("end_line") or record.get("end_line") or line,
            "match_line": line,
            "match_snippet": snippet,
            "match_source": "exact named API/service graph anchor",
            "matched_terms": [entity],
            "evidence_tag": "GRAPH" if symbol in functions else "SOURCE",
            "evidence_strength": hybrid_evidence_strength("GRAPH" if symbol in functions else "SOURCE", exact=True) + min(score, 40),
            "calls": sorted(outgoing.get(symbol, []))[:50],
            "calledBy": sorted(incoming.get(symbol, []))[:50],
        })
        text_results.append({
            "kind": "exact named API/service anchor",
            "file": path,
            "line": line,
            "text": f"{entity} resolves to {symbol}. {snippet}",
            "matched_terms": [entity],
            "evidence_tag": "GRAPH" if symbol in functions else "SOURCE",
            "evidence_strength": hybrid_evidence_strength("GRAPH" if symbol in functions else "SOURCE", exact=True) + min(score, 40),
        })
    return {
        "provider": "named_api",
        "priority": 98,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"entities": entities, "callgraph_source": callgraph_source, "match_count": len(anchors)},
    } if anchors else {}


def structured_anchor_from_code_boundaries(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    lowered = str(query or "").lower()
    category = ""
    patterns = ()
    if any(phrase in lowered for phrase in ("database writes", "value saved", "value not being saved")):
        category = "database write"
        patterns = DATA_FLOW_SINK_PATTERNS
    elif any(phrase in lowered for phrase in ("sql quer", "sql injection", "raw sql", "sql execution")):
        category = "SQL execution"
        patterns = (
            r"\.(?:execute|executemany|raw|query)\s*\(",
            r"\b(?:select|insert|update|delete|replace|create|alter|drop)\b.+\b(?:from|into|table|where)\b",
        )
    elif any(phrase in lowered for phrase in (
        "authentication checked",
        "authentication implemented",
        "authentication implementation",
        "auth implemented",
        "auth implementation",
        "handles authentication",
        "authentication-related code",
    )):
        category = "authentication check"
        patterns = (
            r"\b(?:require|check|verify|validate|authenticate|authorize)[A-Za-z0-9_]*(?:auth|session|token|user|permission)",
            r"\b(?:auth|session|token|permission)[A-Za-z0-9_]*(?:from_request|check|verify|validate|required)",
            r"\bHTTPException\s*\(\s*status_code\s*=\s*(?:401|403)",
            r"\bcompare_digest\s*\(",
            r"\brequest\.cookies\b",
        )
    elif "filesystem write" in lowered:
        category = "filesystem write"
        patterns = (
            r"\.(?:write_text|write_bytes|mkdir|touch|rename|replace|unlink)\s*\(",
            r"\bopen\s*\([^)]*,\s*['\"][wax+]",
            r"\b(?:json\.dump|shutil\.(?:copy|copy2|copytree|move)|os\.replace)\s*\(",
        )
    elif "user input handled" in lowered:
        category = "user input source"
        patterns = DATA_FLOW_SOURCE_PATTERNS
    elif any(phrase in lowered for phrase in ("secrets or tokens", "secret used", "token used", "secrets used", "tokens used")):
        category = "secret or token usage"
        patterns = (
            r"\bos\.getenv\s*\(",
            r"\benviron(?:ment)?\s*\[",
            r"\b(?:secret|token|api[_-]?key|credential|password|private[_-]?key)\b",
            r"\b(?:authorization|bearer)\b",
        )
    elif "without validation" in lowered:
        category = "user input validation"
        patterns = DATA_FLOW_SOURCE_PATTERNS
    if not category:
        return {}

    records = load_scim_function_records(artifact_root / "scim")
    ranked = []
    for symbol, record in records.items():
        code = str(record.get("code") or "")
        haystack = f"{symbol}\n{record.get('path') or ''}\n{code}"
        matched_patterns = [pattern for pattern in patterns if re.search(pattern, haystack, re.IGNORECASE | re.DOTALL)]
        if not matched_patterns:
            continue
        matching_line = next(
            (
                line.strip()
                for line in code.splitlines()
                if any(re.search(pattern, line, re.IGNORECASE) for pattern in matched_patterns)
            ),
            first_code_line(record),
        )
        score = len(matched_patterns) * 100
        symbol_lower = str(symbol).lower()
        if category == "database write" and any(term in symbol_lower for term in ("supabase", "persist", "save", "insert", "update", "upsert")):
            score += 80
        if category == "SQL execution" and any(term in symbol_lower for term in ("execute", "query", "sql")):
            score += 80
        if category == "authentication check" and any(term in symbol_lower for term in ("session_from_request", "require", "verify", "auth")):
            score += 80
        ranked.append((score, symbol, record, matching_line))
    ranked.sort(key=lambda item: (item[0], item[1]), reverse=True)

    anchors = []
    text_results = []
    for score, symbol, record, matching_line in ranked[:40]:
        path = str(record.get("path") or "")
        line = record.get("start_line") or ""
        anchors.append({
            "type": "code_boundary_anchor",
            "symbol": symbol,
            "fullName": symbol,
            "name": str(symbol).split(".")[-1],
            "graph_symbol": symbol,
            "path": path,
            "file": path,
            "start_line": line,
            "end_line": record.get("end_line") or line,
            "match_line": line,
            "match_snippet": matching_line,
            "match_source": f"exact {category} pattern",
            "matched_terms": [category],
            "text_score": score,
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
        text_results.append({
            "kind": f"{category} source match",
            "file": path,
            "line": line,
            "text": f"{symbol}: {matching_line}",
            "matched_terms": [category],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
        })
    return {
        "provider": "code_boundaries",
        "priority": 97,
        "anchors": anchors,
        "text_results": text_results,
        "metadata": {"category": category, "match_count": len(ranked)},
    } if anchors else {}


def structured_anchor_from_feature_catalog(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    target = extract_search_target(query)
    if target and ("_" in target or "." in target or re.search(r"[a-z][A-Z]", target)):
        return {}
    match = match_feature_catalog_entry(query, artifact_root)
    if not match:
        return {}
    anchors = []
    for evidence in match.get("evidence") or []:
        if not isinstance(evidence, dict):
            continue
        symbol = str(evidence.get("symbol") or "")
        path = str(evidence.get("path") or "")
        if not symbol and not path:
            continue
        info = lookup_symbol_info(symbol, output_repo_dir) if symbol else {}
        anchors.append({
            **info,
            "type": "feature_catalog_anchor",
            "symbol": symbol or info.get("symbol") or match.get("feature"),
            "fullName": symbol or info.get("fullName") or match.get("feature"),
            "name": str(symbol or match.get("feature") or "").split(".")[-1],
            "path": path or info.get("path") or "",
            "file": path or info.get("file") or "",
            "start_line": evidence.get("start_line") or evidence.get("line") or info.get("start_line") or "",
            "end_line": evidence.get("end_line") or info.get("end_line") or "",
            "match_source": "feature catalog exact match" if match.get("score") == 1.0 else "feature catalog match",
            "matched_terms": [match.get("feature")],
            "evidence_tag": "SOURCE",
            "evidence_strength": hybrid_evidence_strength("SOURCE", exact=match.get("score") == 1.0),
        })
    return {
        "provider": "feature_catalog",
        "priority": 90,
        "anchors": anchors,
        "text_results": feature_catalog_match_to_text_results(match),
        "metadata": {
            "feature": match.get("feature"),
            "score": match.get("score"),
            "source": match.get("source"),
        },
    }


STRUCTURED_ANCHOR_PROVIDERS = (
    structured_anchor_from_exact_ui,
    structured_anchor_from_test_references,
    structured_anchor_from_exact_symbol,
    structured_anchor_from_route,
    structured_anchor_from_named_api,
    structured_anchor_from_api_routes,
    structured_anchor_from_code_boundaries,
)


def resolve_structured_anchors(query: str, output_repo_dir: Path, artifact_root: Path) -> dict:
    matches = []
    anchors = []
    text_results = []
    for provider in STRUCTURED_ANCHOR_PROVIDERS:
        try:
            result = provider(query, output_repo_dir, artifact_root) or {}
        except Exception as error:
            logger.warning("Structured anchor provider %s failed: %s", provider.__name__, error)
            continue
        if not result:
            continue
        matches.append({
            "provider": result.get("provider") or provider.__name__,
            "priority": int(result.get("priority") or 0),
            "metadata": result.get("metadata") or {},
        })
        anchors.extend(result.get("anchors") or [])
        text_results.extend(result.get("text_results") or [])
    matches.sort(key=lambda item: item["priority"], reverse=True)
    return {
        "matches": matches,
        "anchors": rank_hybrid_results(anchors),
        "text_results": sorted(
            text_results,
            key=lambda item: int(item.get("evidence_strength") or 0),
            reverse=True,
        ),
    }


def extract_hybrid_query_entities(query: str) -> dict:
    query = str(query or "").strip()
    lowered = query.lower()
    ui_labels = ui_label_query_phrases(query)
    target = extract_search_target(query)
    files = extract_file_entities(query)
    routes = list(dict.fromkeys(re.findall(r"(?<!\w)/(?:[A-Za-z0-9_.:{}-]+/?)+", query)))
    commit_refs = list(dict.fromkeys(re.findall(r"\b[0-9a-f]{7,40}\b", query, re.IGNORECASE)))
    quoted = quoted_query_phrases(query)
    named_apis = extract_named_api_entities(query)
    direction = "both"
    if any(phrase in lowered for phrase in ("what happens when", "what happens after", "calls from", "forward", "downstream", "callees")):
        direction = "forward"
    elif any(phrase in lowered for phrase in ("what happens before", "who calls", "callers", "upstream")):
        direction = "backward"
    return {
        "ui_labels": ui_labels,
        "symbols": [target] if target else [],
        "files": files,
        "routes": routes,
        "named_apis": named_apis,
        "commit_refs": commit_refs,
        "quoted_text": quoted,
        "error_terms": error_debug_terms(query) if is_debugging_query(query) else [],
        "analytics": is_explicit_ga_behavior_query(query),
        "change_history": "commit_history" in set(classify_question_intents(query).get("intents") or []),
        "direction": direction,
    }


def build_hybrid_operation_plan(query: str, retrieval_plan: dict | None = None) -> dict:
    retrieval_plan = retrieval_plan or plan_scim_retrieval(query)
    entities = extract_hybrid_query_entities(query)
    strategy = retrieval_plan.get("retrieval_strategy") or {}
    operations = ["exact_source", "semantic"]
    if (
        entities["ui_labels"]
        or entities["symbols"]
        or entities["routes"]
        or entities.get("named_apis")
        or strategy.get("query_type") in {"call_trace", "dependency", "data_flow", "ui_feature_location", "api_exposure"}
    ):
        operations.append("graph_traversal")
    if entities["analytics"]:
        operations.append("analytics")
    if entities["change_history"] or entities["commit_refs"]:
        operations.append("git_history")
    return {
        "mode": "hybrid",
        "entities": entities,
        "operations": list(dict.fromkeys(operations)),
        "strategy": strategy,
        "fallback_policy": "deterministic entities first; LLM entity extraction only when deterministic anchors are absent",
    }


def hybrid_entities_are_ambiguous(entities: dict) -> bool:
    return not any(
        entities.get(key)
        for key in ("ui_labels", "symbols", "files", "routes", "named_apis", "commit_refs", "quoted_text", "error_terms")
    ) and not entities.get("analytics") and not entities.get("change_history")


def extract_hybrid_entities_with_llm(query: str) -> dict:
    if os.getenv("CODEVAL_LLM_ENTITY_EXTRACTION", "true").strip().lower() in {"0", "false", "no", "off"}:
        return {}
    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        return {}
    prompt = f"""Extract retrieval entities from this software-engineering question.
Return ONLY one JSON object with these keys:
ui_labels (array of visible labels), symbols (array), files (array), routes (array),
commit_refs (array), quoted_text (array), error_terms (array),
analytics (boolean), change_history (boolean), direction (forward|backward|both).
Do not invent names not present or strongly implied by the question.

QUESTION:
{query}
"""
    try:
        response = requests.post(
            "https://api.openai.com/v1/chat/completions",
            headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
            json={
                "model": os.getenv("OPENAI_ENTITY_MODEL", os.getenv("OPENAI_SEARCH_MODEL", "gpt-4o-mini")),
                "messages": [{"role": "user", "content": prompt}],
                "max_tokens": 250,
                "temperature": 0,
                "response_format": {"type": "json_object"},
            },
            timeout=(5, 20),
        )
        response.raise_for_status()
        content = response.json()["choices"][0]["message"]["content"]
        payload = json.loads(content)
    except Exception as error:
        logger.info("Optional LLM entity extraction was unavailable: %s", error)
        return {}
    return {
        "ui_labels": list(payload.get("ui_labels") or [])[:8],
        "symbols": list(payload.get("symbols") or [])[:8],
        "files": list(payload.get("files") or [])[:8],
        "routes": list(payload.get("routes") or [])[:8],
        "commit_refs": list(payload.get("commit_refs") or [])[:8],
        "quoted_text": list(payload.get("quoted_text") or [])[:8],
        "error_terms": list(payload.get("error_terms") or [])[:12],
        "analytics": bool(payload.get("analytics")),
        "change_history": bool(payload.get("change_history")),
        "direction": payload.get("direction") if payload.get("direction") in {"forward", "backward", "both"} else "both",
    }


def enrich_hybrid_plan_with_llm(query: str, plan: dict) -> dict:
    entities = dict(plan.get("entities") or {})
    if not hybrid_entities_are_ambiguous(entities):
        return plan
    llm_entities = extract_hybrid_entities_with_llm(query)
    if not llm_entities:
        return plan
    merged = dict(entities)
    for key, value in llm_entities.items():
        if value not in (None, "", [], False):
            merged[key] = value
    operations = list(plan.get("operations") or [])
    if any(merged.get(key) for key in ("ui_labels", "symbols", "routes")) and "graph_traversal" not in operations:
        operations.append("graph_traversal")
    if merged.get("analytics") and "analytics" not in operations:
        operations.append("analytics")
    if (merged.get("change_history") or merged.get("commit_refs")) and "git_history" not in operations:
        operations.append("git_history")
    return {
        **plan,
        "entities": merged,
        "operations": operations,
        "entity_extraction": "deterministic_then_llm_fallback",
    }


def hybrid_evidence_tag(source: str) -> str:
    source = str(source or "").lower()
    if any(token in source for token in ("ui label", "markup", "html ui", "source text", "catalogued feature")):
        return "MARKUP"
    if any(token in source for token in ("callgraph", "graph", "caller", "callee")):
        return "GRAPH"
    if any(token in source for token in ("commit", "git", "diff", "change")):
        return "GIT"
    if any(token in source for token in ("ga", "analytics", "mixpanel", "sentry")):
        return "ANALYTICS"
    if any(token in source for token in ("semantic", "scim", "embedding", "vector")):
        return "SEMANTIC"
    return "SOURCE"


def hybrid_evidence_strength(tag: str, exact: bool = False) -> int:
    base = {
        "MARKUP": 1000,
        "SOURCE": 900,
        "GRAPH": 760,
        "GIT": 700,
        "ANALYTICS": 680,
        "SEMANTIC": 300,
    }.get(tag, 100)
    return base + (100 if exact else 0)


def saved_commit_text_results(output_repo_dir: Path, query: str, limit: int = 20) -> list[dict]:
    artifact_root = artifact_root_for_output(output_repo_dir)
    path = artifact_root / "daily_change_cache.json"
    payload = load_json_file(path, {})
    if not payload:
        return []
    terms = search_query_terms(query)
    lowered = str(query or "").lower()
    broad_history_query = any(phrase in lowered for phrase in (
        "what changed recently",
        "recent changes",
        "summarize today's commits",
        "summarise today's commits",
        "today's commits",
        "latest commits",
        "commit summary",
    ))
    rows = []
    for index, commit in enumerate(payload.get("commits") or [], start=1):
        if not isinstance(commit, dict):
            continue
        text = " ".join(str(commit.get(key) or "") for key in ("sha", "short_sha", "message", "author", "date", "html_url"))
        changed_files = commit.get("changed_files") or []
        changed_functions = commit.get("changed_functions") or []
        text = f"{text} changed files: {changed_files} changed functions: {changed_functions}"
        matched = sorted(term for term in terms if term in text.lower())
        if (
            terms
            and not broad_history_query
            and not matched
            and not any(ref in text.lower() for ref in extract_hybrid_query_entities(query)["commit_refs"])
        ):
            continue
        rows.append({
            "kind": "commit history",
            "file": "daily_change_cache.json",
            "line": index,
            "text": text[:1200],
            "matched_terms": matched,
            "evidence_tag": "GIT",
            "evidence_strength": hybrid_evidence_strength("GIT", exact=bool(matched)),
        })
    return rows[:limit]


def requires_saved_commit_evidence(query: str) -> bool:
    lowered = str(query or "").lower()
    return any(
        phrase in lowered
        for phrase in (
            "what changed recently",
            "latest change",
            "recent changes",
            "this commit",
            "latest commit",
            "changed near",
            "last change to",
            "summarize today's commits",
            "summarise today's commits",
            "today's commits",
        )
    )


def graph_traversal_results_for_anchors(output_repo_dir: Path, anchors: list[dict], direction: str = "both", limit: int = 20):
    try:
        callgraph, callgraph_source = load_search_callgraph(artifact_root_for_output(output_repo_dir))
    except Exception as error:
        return [], "", str(error)
    _, functions, outgoing, incoming, _ = callgraph_indexes(callgraph)
    roots = []
    for item in anchors or []:
        source = str(item.get("match_source") or item.get("source_type") or "").lower()
        strength = int(item.get("evidence_strength") or 0)
        is_resolved_anchor = (
            strength >= hybrid_evidence_strength("GRAPH", exact=True)
            or "exact" in source
            or "feature catalog" in source
            or "api route boundary" in source
        )
        if not is_resolved_anchor:
            continue
        for key in ("graph_symbol", "symbol", "fullName", "name"):
            if item.get(key):
                roots.append(item[key])
    resolved = resolve_search_graph_roots(roots, functions)
    results = []
    for root in sorted(resolved):
        info = lookup_symbol_info(root, output_repo_dir)
        calls = sorted(outgoing.get(root, []))[:limit] if direction in {"forward", "both"} else []
        called_by = sorted(incoming.get(root, []))[:limit] if direction in {"backward", "both"} else []
        results.append({
            **info,
            "symbol": root,
            "fullName": root,
            "name": str(root).split(".")[-1],
            "graph_symbol": root,
            "calls": calls,
            "calledBy": called_by,
            "match_source": "callgraph traversal",
            "evidence_tag": "GRAPH",
            "evidence_strength": hybrid_evidence_strength("GRAPH", exact=True),
        })
    return results, callgraph_source, ""


def rank_hybrid_results(results: list[dict]) -> list[dict]:
    deduped = {}
    for item in results or []:
        key = str(item.get("graph_symbol") or item.get("symbol") or item.get("fullName") or item.get("path") or item.get("name") or "")
        if not key:
            continue
        source = item.get("match_source") or item.get("source_type") or ""
        tag = item.get("evidence_tag") or hybrid_evidence_tag(source)
        exact = "exact" in str(source).lower()
        candidate = {
            **item,
            "evidence_tag": tag,
            "evidence_strength": int(item.get("evidence_strength") or hybrid_evidence_strength(tag, exact)),
        }
        current = deduped.get(key)
        if not current or candidate["evidence_strength"] > current["evidence_strength"]:
            deduped[key] = candidate
        elif current:
            current["calls"] = sorted(set(current.get("calls") or []) | set(candidate.get("calls") or []))[:50]
            current["calledBy"] = sorted(set(current.get("calledBy") or []) | set(candidate.get("calledBy") or []))[:50]
    return sorted(
        deduped.values(),
        key=lambda item: (
            int(item.get("evidence_strength") or 0),
            float(item.get("final_score") or item.get("text_score") or item.get("score") or 0),
        ),
        reverse=True,
    )


def build_hybrid_evidence_ledger(results: list[dict], text_results: list[dict]) -> list[dict]:
    ledger = []
    for item in results or []:
        tag = item.get("evidence_tag") or hybrid_evidence_tag(item.get("match_source") or item.get("source_type"))
        ledger.append({
            "tag": tag,
            "strength": int(item.get("evidence_strength") or hybrid_evidence_strength(tag)),
            "source": item.get("match_source") or item.get("source_type") or "",
            "symbol": item.get("symbol") or item.get("fullName") or "",
            "path": item.get("path") or item.get("file") or "",
            "line": item.get("match_line") or item.get("start_line") or item.get("line") or "",
            "evidence": item.get("match_snippet") or item.get("evidence_text") or "",
        })
    for item in text_results or []:
        tag = item.get("evidence_tag") or hybrid_evidence_tag(item.get("kind"))
        ledger.append({
            "tag": tag,
            "strength": int(item.get("evidence_strength") or hybrid_evidence_strength(tag, exact="exact" in str(item.get("kind") or ""))),
            "source": item.get("kind") or "",
            "symbol": "",
            "path": item.get("file") or "",
            "line": item.get("line") or "",
            "evidence": item.get("text") or "",
        })
    ledger.sort(key=lambda item: item["strength"], reverse=True)
    return ledger[:40]


#============================================================
#   SEARCH ROUTE
#============================================================

@app.post("/search")
def search(request: Request, payload: dict):
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    query = payload.get("query", "").strip()
    prompt_template = str(payload.get("prompt_template") or "").strip()
    analysis_run_id = str(payload.get("supabase_analysis_run_id") or payload.get("analysis_run_id") or "").strip()
    search_restore_token = str(payload.get("supabase_search_restore_token") or payload.get("search_restore_token") or "").strip()
    if not owner or not repo:
        return {
            "error": "owner_name and repo_name are required for repository search.",
            "results": [],
            "text_results": [],
            "answer": "",
        }

    logger.info(f"Analyzing {owner}/{repo}")

    repo_id = short_id(owner, repo)
    # This produces string
    #OUTPUT_REPO_DIR = os.path.join(BASE_OUTPUT, repo_id)
    #OUTPUT_REPO_SEARCH_DIR = os.path.join(OUTPUT_REPO_DIR, "search")

    # This is a path object
    OUTPUT_REPO_DIR = Path(BASE_OUTPUT) / repo_id
    OUTPUT_REPO_SEARCH_DIR = OUTPUT_REPO_DIR / "search"
    artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
    restore_result = None
    search_required_paths = [
        artifact_root / "scim" / "vectors.sqlite",
        artifact_root / "scim" / "functions.jsonl",
    ]
    search_graph_paths = [
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
        artifact_root / "csharp" / "csharp_callgraph.json",
        artifact_root / "html_ui" / "html_ui_graph.json",
    ]

    def restore_search_artifacts():
        result = (
            restore_analysis_artifacts_for_search_run_id(analysis_run_id, owner, repo, request, search_restore_token)
            if analysis_run_id
            else restore_latest_analysis_artifacts_for_search(request, owner, repo)
        )
        if not result.get("restored") and analysis_run_id:
            fallback = restore_latest_analysis_artifacts_for_search(request, owner, repo)
            return {
                "primary": result,
                "fallback": fallback,
                "restored": bool(fallback.get("restored")),
            }
        return result

    if (
        OUTPUT_REPO_DIR.exists()
        and (
            not all(path.exists() for path in search_required_paths)
            or not any(path.exists() for path in search_graph_paths)
        )
    ):
        logger.info("Search local artifacts missing for %s/%s; attempting Supabase restore.", owner, repo)
        restore_result = restore_search_artifacts()
        logger.info("Search artifact restore result for %s/%s: %s", owner, repo, restore_result)
    if not OUTPUT_REPO_DIR.exists():
        restore_result = materialize_mirrored_analysis_output(
            payload.get("artifact_root_path") or payload.get("mirror_artifact_dir") or "",
            OUTPUT_REPO_DIR,
            owner,
            repo,
        )
        logger.info("Search mirror materialization result for %s/%s: %s", owner, repo, restore_result)
    if not OUTPUT_REPO_DIR.exists():
        restore_result = restore_search_artifacts()
        logger.info("Search output restore result for %s/%s: %s", owner, repo, restore_result)
    if not OUTPUT_REPO_DIR.exists():
        restore_reason = ""
        if isinstance(restore_result, dict):
            restore_reason = restore_result.get("reason") or (restore_result.get("primary") or {}).get("reason") or (restore_result.get("fallback") or {}).get("reason") or ""
        return {
            "error": f"No analysis output exists for {owner}/{repo}. Analyze the selected repository first.",
            "restore_result": restore_result or {},
            "restore_reason": restore_reason,
            "owner_name": owner,
            "repo_name": repo,
            "results": [],
            "text_results": [],
            "answer": "",
        }

    os.makedirs(OUTPUT_REPO_SEARCH_DIR, exist_ok=True)

    try:
        search_limit = max(1, min(int(payload.get("limit", 10) or 10), 25))
    except (TypeError, ValueError):
        search_limit = 10
    graph_depth = graph_depth_from_payload(payload)
    graph_max_nodes = graph_max_nodes_from_payload(payload)
    query_terms = search_query_terms(query)
    retrieval_plan = plan_scim_retrieval(query)
    retrieval_strategy = retrieval_plan.get("retrieval_strategy") or classify_retrieval_strategy(query, terms=query_terms)
    text_search_limit = max(search_limit, 50) if is_explicit_ga_behavior_query(query, query_terms) else search_limit

    query_lower = query.lower().strip()
    clarification_needed = unresolved_search_reference(query)
    if clarification_needed:
        clarification = (
            f"This question does not identify a concrete {clarification_needed}. "
            f"Provide the {clarification_needed} so CodeVal can resolve exact source and graph evidence."
        )
        return {
            "query": query,
            "intent": {"intent": "clarification_required", "missing": clarification_needed},
            "search_backend": "clarification",
            "count": 0,
            "results": [],
            "text_count": 1,
            "text_results": [{
                "kind": "clarification required",
                "file": "",
                "line": "",
                "text": clarification,
                "matched_terms": [],
                "evidence_tag": "UNKNOWN",
                "evidence_strength": hybrid_evidence_strength("UNKNOWN"),
            }],
            "retrieval_context": {
                "query": query,
                "root": None,
                "strategy": "require a resolvable entity before repository retrieval",
                "retrieval_plan": retrieval_plan,
                "retrieval_strategy": retrieval_strategy,
                "code_units": [],
            },
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "answer": clarification,
            "answer_source": "clarification",
            "answer_truth_status": "missing_entity",
            "answer_prompt": "",
            "answer_prompt_chars": 0,
            "search_graph_url": "",
            "search_graph_error": "",
            "search_graph_result_index": None,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }

    # ---------------------------------------------------------
    # 1. CALLERS / CALLEES ROUTING (ALWAYS RETURN EARLY)
    # ---------------------------------------------------------

    caller_symbol = None
    callee_symbol = None

    caller_match = re.search(
        r"^(?:find|show|list)?\s*(?:all\s+)?callers(?:\s+of)?(?:\s+this)?(?:\s+function)?\s+([a-zA-Z0-9_\.]+)",
        query_lower
    )
    if caller_match and caller_match.group(1) not in CALLGRAPH_SYMBOL_STOPWORDS:
        caller_symbol = caller_match.group(1)
        return {
            "query_type": "callers",
            "retrieval_strategy": retrieval_strategy,
            "retrieval_plan": retrieval_plan,
            "symbol": caller_symbol,
            "results": find_callers(OUTPUT_REPO_DIR, caller_symbol)
        }

    callee_match = re.search(
        r"^(?:find|show|list)?\s*(?:all\s+)?callees(?:\s+of)?(?:\s+this)?(?:\s+function)?\s+([a-zA-Z0-9_\.]+)",
        query_lower
    )
    if callee_match and callee_match.group(1) not in CALLGRAPH_SYMBOL_STOPWORDS:
        callee_symbol = callee_match.group(1)
        return {
            "query_type": "callees",
            "retrieval_strategy": retrieval_strategy,
            "retrieval_plan": retrieval_plan,
            "symbol": callee_symbol,
            "results": find_callees(OUTPUT_REPO_DIR, callee_symbol)
        }

    # ---------------------------------------------------------
    # 2. TEXT SEARCH (ALWAYS RUN)
    # ---------------------------------------------------------
    try:
        text_results = search_repository_text_matches(OUTPUT_REPO_DIR, query, text_search_limit)
    except Exception as e:
        logger.exception("Repository text search failed for %s/%s query=%r", owner, repo, query)
        text_results = []
    if is_architecture_query(query, retrieval_plan):
        architecture_results = architecture_text_results(OUTPUT_REPO_DIR, query, limit=8)
        if architecture_results:
            text_results = architecture_results + [
                item for item in text_results
                if str(item.get("kind") or "") not in {"architecture summary", "architecture modules", "architecture entry points", "architecture dependencies", "architecture files"}
            ][: max(0, text_search_limit - len(architecture_results))]

    # NEW: feature_explanation routes to its own handler (callgraph traversal +
    # recent commits, narrated by the LLM) instead of the generic retrieval below.
    if retrieval_strategy.get("query_type") == "feature_explanation":
        feature_explanation_target = extract_search_target(query)
        feature_explanation_answer = handle_feature_explanation(owner, repo, query)
        return {
            "query": query,
            "intent": {"intent": "feature_explanation", "target": feature_explanation_target},
            "search_backend": "feature_explanation",
            "count": 0,
            "results": [],
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": {
                "query": query,
                "root": feature_explanation_target or None,
                "strategy": "callgraph traversal (5 levels forward / 3 back) plus recent commit history, narrated by the LLM",
                "retrieval_plan": retrieval_plan,
                "retrieval_strategy": retrieval_strategy,
                "code_units": [],
            },
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "answer": feature_explanation_answer,
            "answer_source": "feature_explanation_handler",
            "answer_prompt": "",
            "answer_prompt_chars": 0,
            "search_graph_url": "",
            "search_graph_error": "",
            "search_graph_result_index": None,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
            "response_type": "feature_explanation",  # NEW: tells the frontend to render this differently
        }

    requested_quality_types = quality_search_types(query)
    if requested_quality_types:
        quality_results, retrieval_context = quality_signal_search_results(
            OUTPUT_REPO_DIR,
            query,
            search_limit,
        )
        if not quality_results:
            text_results = [{
                "kind": "static quality signal summary",
                "file": retrieval_context.get("quality_signal_path") or "static_quality_signals.json",
                "line": "",
                "text": (
                    "No static quality findings matched the requested types: "
                    + ", ".join(sorted(requested_quality_types))
                    + "."
                ),
                "matched_terms": sorted(requested_quality_types),
                "evidence_tag": "SOURCE",
                "evidence_strength": hybrid_evidence_strength("SOURCE", exact=True),
            }]
        retrieval_context["retrieval_plan"] = retrieval_plan
        retrieval_context["retrieval_strategy"] = retrieval_strategy
        retrieval_context["evidence_cards"] = build_scim_evidence_cards(
            quality_results,
            text_results,
            limit=14,
        )
        answer_prompt = build_search_answer_prompt(
            query,
            retrieval_context,
            quality_results,
            text_results,
            OUTPUT_REPO_DIR,
            prompt_template=prompt_template,
        )
        return {
            "query": query,
            "intent": {
                "intent": "static_quality_signals",
                "finding_types": sorted(requested_quality_types),
            },
            "search_backend": "static_quality_signals",
            "count": len(quality_results),
            "results": quality_results,
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": retrieval_context,
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "evidence_cards": retrieval_context.get("evidence_cards", []),
            "answer": "",
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": "",
            "search_graph_error": "",
            "search_graph_result_index": None,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }

    if requires_saved_commit_evidence(query):
        commit_results = saved_commit_text_results(
            OUTPUT_REPO_DIR,
            query,
            limit=text_search_limit,
        )
        if not commit_results:
            text_results = [{
                "kind": "commit history availability",
                "file": "daily_change_cache.json",
                "line": "",
                "text": (
                    "No saved commit or diff evidence is available for this analyzed repository. "
                    "The answer must not infer recent changes from functions that merely implement commit analysis."
                ),
                "matched_terms": ["commit", "change", "unavailable"],
                "evidence_tag": "UNKNOWN",
                "evidence_strength": hybrid_evidence_strength("UNKNOWN"),
            }]
            retrieval_context = {
                "query": query,
                "root": None,
                "strategy": "saved commit and diff evidence required",
                "retrieval_plan": retrieval_plan,
                "retrieval_strategy": retrieval_strategy,
                "code_units": [],
                "evidence_cards": build_scim_evidence_cards([], text_results, limit=4),
            }
            answer_prompt = build_search_answer_prompt(
                query,
                retrieval_context,
                [],
                text_results,
                OUTPUT_REPO_DIR,
                prompt_template=prompt_template,
            )
            return {
                "query": query,
                "intent": {"intent": "commit_history_unavailable"},
                "search_backend": "commit_history",
                "count": 0,
                "results": [],
                "text_count": len(text_results),
                "text_results": text_results,
                "retrieval_context": retrieval_context,
                "retrieval_plan": retrieval_plan,
                "retrieval_strategy": retrieval_strategy,
                "evidence_cards": retrieval_context.get("evidence_cards", []),
                "answer": "",
                "answer_prompt": answer_prompt,
                "answer_prompt_chars": len(answer_prompt),
                "search_graph_url": "",
                "search_graph_error": "",
                "search_graph_result_index": None,
                "search_graph_depth": graph_depth,
                "search_graph_max_nodes": graph_max_nodes,
            }

    structured_anchors = resolve_structured_anchors(query, OUTPUT_REPO_DIR, artifact_root)
    if structured_anchors.get("text_results"):
        text_results = structured_anchors["text_results"] + text_results
    if structured_anchors.get("matches"):
        retrieval_strategy["structured_anchors"] = structured_anchors["matches"]

    if is_dependency_hotspot_query(query):
        hotspot_scope = dependency_hotspot_scope(query)
        hotspot_results, retrieval_context = dependency_hotspot_search_results(OUTPUT_REPO_DIR, search_limit, scope=hotspot_scope)
        retrieval_context["retrieval_plan"] = retrieval_plan
        retrieval_context["retrieval_strategy"] = retrieval_strategy
        retrieval_context["evidence_cards"] = build_scim_evidence_cards(hotspot_results, text_results, limit=14)
        retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, retrieval_context, hotspot_results, text_results)
        stored_context = retrieval_context.get("stored_generated_answers") or {}
        answer_prompt = build_search_answer_prompt(
            query,
            retrieval_context,
            hotspot_results,
            text_results,
            OUTPUT_REPO_DIR,
            prompt_template=prompt_template,
        )
        search_graph_url = ""
        search_graph_error = ""
        search_graph_result_index = None
        callgraph_source = ""
        try:
            callgraph, callgraph_source = load_search_callgraph(artifact_root)
            search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
                artifact_root,
                hotspot_results,
                callgraph,
                graph_name="search_results_graph",
                depth=graph_depth,
                max_nodes=graph_max_nodes,
            )
        except Exception as e:
            search_graph_error = str(e)
            logger.warning("Unable to build dependency hotspot search graph for %s/%s: %s", owner, repo, e)
        response_payload = {
            "query": query,
            "intent": {"intent": "dependency_hotspots", "target": query, "scope": hotspot_scope},
            "search_backend": "dependency_hotspots",
            "callgraph_source": callgraph_source,
            "count": len(hotspot_results),
            "results": hotspot_results,
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": retrieval_context,
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "evidence_cards": retrieval_context.get("evidence_cards", []),
            "answer": stored_context.get("best_answer") or "",
            "answer_source": stored_context.get("best_source_type") or "",
            "answer_truth_status": stored_context.get("truth_status") or "",
            "stored_generated_answers": stored_context,
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": search_graph_url,
            **search_graph_artifact_urls(search_graph_url),
            "search_graph_error": search_graph_error,
            "search_graph_result_index": search_graph_result_index,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
            logger.warning("Unable to store dependency hotspot search interaction for %s/%s: %s", owner, repo, e)
        return response_payload

    # ---------------------------------------------------------
    # HYBRID EVIDENCE PIPELINE
    # ---------------------------------------------------------
    hybrid_plan = enrich_hybrid_plan_with_llm(
        query,
        build_hybrid_operation_plan(query, retrieval_plan),
    )
    hybrid_plan["structured_anchors"] = structured_anchors.get("matches") or []
    if structured_anchors.get("anchors") and "graph_traversal" not in hybrid_plan["operations"]:
        hybrid_plan["operations"].append("graph_traversal")
    if "git_history" in hybrid_plan["operations"]:
        text_results = saved_commit_text_results(OUTPUT_REPO_DIR, query, limit=text_search_limit) + text_results
    for item in text_results:
        tag = item.get("evidence_tag") or hybrid_evidence_tag(item.get("kind"))
        item["evidence_tag"] = tag
        item["evidence_strength"] = int(
            item.get("evidence_strength")
            or hybrid_evidence_strength(tag, exact="exact" in str(item.get("kind") or "").lower())
        )

    try:
        hybrid_scim_payload = search_scim_dataset(OUTPUT_REPO_DIR, query, max(search_limit, 12))
    except Exception as e:
        logger.exception("Hybrid semantic retrieval failed for %s/%s query=%r", owner, repo, query)
        hybrid_scim_payload = None
        hybrid_scim_error = str(e)
    else:
        hybrid_scim_error = ""

    semantic_results = list((hybrid_scim_payload or {}).get("results") or [])
    for item in semantic_results:
        source = item.get("match_source") or "semantic"
        tag = hybrid_evidence_tag(source)
        item["evidence_tag"] = tag
        item["evidence_strength"] = hybrid_evidence_strength(tag, exact="exact" in str(source).lower())

    graph_results = []
    hybrid_callgraph_source = ""
    hybrid_graph_error = ""
    anchor_results = rank_hybrid_results([
        *(structured_anchors.get("anchors") or []),
        *semantic_results,
    ])
    if "graph_traversal" in hybrid_plan["operations"]:
        graph_results, hybrid_callgraph_source, hybrid_graph_error = graph_traversal_results_for_anchors(
            OUTPUT_REPO_DIR,
            anchor_results,
            direction=(hybrid_plan.get("entities") or {}).get("direction") or "both",
            limit=max(search_limit, 20),
        )

    hybrid_results = rank_hybrid_results([*anchor_results, *graph_results])
    if hybrid_results or text_results:
        retrieval_context = dict((hybrid_scim_payload or {}).get("retrieval_context") or {})
        retrieval_context["retrieval_plan"] = retrieval_plan
        retrieval_context["retrieval_strategy"] = retrieval_strategy
        retrieval_context["hybrid_plan"] = hybrid_plan
        retrieval_context["hybrid_evidence_ledger"] = build_hybrid_evidence_ledger(hybrid_results, text_results)
        retrieval_context["evidence_cards"] = build_scim_evidence_cards(hybrid_results, text_results, limit=18)
        retrieval_context = attach_stored_generated_context(
            OUTPUT_REPO_DIR,
            query,
            retrieval_context,
            hybrid_results,
            text_results,
        )
        stored_context = retrieval_context.get("stored_generated_answers") or {}
        search_graph_url = ""
        search_graph_result_index = None
        search_graph_error = hybrid_graph_error
        try:
            callgraph, graph_source = load_search_callgraph(artifact_root)
            hybrid_callgraph_source = hybrid_callgraph_source or graph_source
            search_graph_url, search_graph_result_index, graph_build_error = build_first_available_search_graph(
                artifact_root,
                hybrid_results,
                callgraph,
                graph_name="search_results_graph",
                depth=graph_depth,
                max_nodes=graph_max_nodes,
            )
            search_graph_error = search_graph_error or graph_build_error
        except Exception as e:
            search_graph_error = search_graph_error or str(e)
        answer_prompt = build_search_answer_prompt(
            query,
            retrieval_context,
            hybrid_results,
            text_results,
            OUTPUT_REPO_DIR,
            prompt_template=prompt_template,
        )
        response_payload = {
            "query": query,
            "intent": {
                "intent": "hybrid_evidence_search",
                "entities": hybrid_plan.get("entities") or {},
                "operations": hybrid_plan.get("operations") or [],
            },
            "search_backend": "hybrid",
            "callgraph_source": hybrid_callgraph_source,
            "count": len(hybrid_results),
            "results": hybrid_results[:search_limit],
            "text_count": len(text_results),
            "text_results": text_results[:text_search_limit],
            "retrieval_context": retrieval_context,
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "hybrid_plan": hybrid_plan,
            "evidence_ledger": retrieval_context.get("hybrid_evidence_ledger", []),
            "evidence_cards": retrieval_context.get("evidence_cards", []),
            "answer": stored_context.get("best_answer") or "",
            "answer_source": stored_context.get("best_source_type") or "",
            "answer_truth_status": stored_context.get("truth_status") or "",
            "stored_generated_answers": stored_context,
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": search_graph_url,
            **search_graph_artifact_urls(search_graph_url),
            "search_graph_error": search_graph_error,
            "scim_error": hybrid_scim_error,
            "search_graph_result_index": search_graph_result_index,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
            "restore_result": restore_result or {},
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
            logger.warning("Unable to store hybrid search interaction for %s/%s: %s", owner, repo, e)
        return response_payload

    # ---------------------------------------------------------
    # 3. SYMBOL-AWARE SEARCH (PREFIX / SUBSTRING)
    # ---------------------------------------------------------
    try:
        symbols = load_all_symbols(OUTPUT_REPO_DIR)
    except Exception as e:
        logger.exception("Symbol index search failed for %s/%s query=%r", owner, repo, query)
        symbols = []

    # 3A. Explicit function-flow questions return a scoped callgraph first.
    scoped_target = extract_search_target(query)
    if scoped_target and is_scoped_function_flow_query(query):
        try:
            artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
            callgraph, callgraph_source = load_search_callgraph(artifact_root)
            scoped_results, resolved_roots = scoped_callgraph_results_for_target(OUTPUT_REPO_DIR, scoped_target, callgraph)
            if scoped_results:
                scoped_depth = scoped_function_graph_depth(query, graph_depth)
                search_graph_url = ""
                search_graph_result_index = None
                search_graph_error = ""
                try:
                    search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
                        artifact_root,
                        scoped_results,
                        callgraph,
                        graph_name="search_results_graph",
                        depth=scoped_depth,
                        max_nodes=graph_max_nodes,
                    )
                except Exception as graph_error:
                    search_graph_error = str(graph_error)
                    logger.warning("Unable to build scoped function graph for %s/%s target=%s: %s", owner, repo, scoped_target, graph_error)
                retrieval_context = {
                    "query": query,
                    "root": sorted(resolved_roots)[0] if resolved_roots else scoped_target,
                    "strategy": "scoped callgraph around explicit function target",
                    "retrieval_strategy": retrieval_strategy,
                    "code_units": scoped_callgraph_code_units(OUTPUT_REPO_DIR, resolved_roots, scoped_results),
                }
                retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, retrieval_context, scoped_results, text_results)
                stored_context = retrieval_context.get("stored_generated_answers") or {}
                response_payload = {
                    "query": query,
                    "intent": {"intent": "scoped_function_callgraph", "target": scoped_target},
                    "search_backend": "scoped_callgraph",
                    "callgraph_source": callgraph_source,
                    "count": len(scoped_results),
                    "results": scoped_results,
                    "text_count": len(text_results),
                    "text_results": text_results,
                    "retrieval_context": retrieval_context,
                    "retrieval_plan": retrieval_plan,
                    "retrieval_strategy": retrieval_strategy,
                    "answer": stored_context.get("best_answer") or "",
                    "answer_source": stored_context.get("best_source_type") or "",
                    "answer_truth_status": stored_context.get("truth_status") or "",
                    "stored_generated_answers": stored_context,
                    "answer_prompt": build_search_answer_prompt(query, retrieval_context, scoped_results, text_results, OUTPUT_REPO_DIR, prompt_template=prompt_template),
                    "search_graph_url": search_graph_url,
                    **search_graph_artifact_urls(search_graph_url),
                    "search_graph_error": search_graph_error,
                    "search_graph_result_index": search_graph_result_index,
                    "search_graph_depth": scoped_depth,
                    "search_graph_max_nodes": graph_max_nodes,
                }
                try:
                    response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
                except Exception as e:
                    logger.warning("Unable to store scoped callgraph search interaction for %s/%s: %s", owner, repo, e)
                return response_payload
        except Exception as e:
            logger.warning("Scoped function search did not resolve for %s/%s target=%s: %s", owner, repo, scoped_target, e)

    if query_lower in {s.lower() for s in symbols} or loose_symbol_key(query_lower) in {loose_symbol_key(s) for s in symbols}:
        exact_symbol = True
    else:
        exact_symbol = False

    # 3B. Partial symbol → RETURN EARLY (NO SCIM)
    if not exact_symbol:
        partial_hits = [s for s in symbols if query_lower in s.lower() or loose_symbol_match(query, s)]
        if partial_hits:
            symbol_results = [
                item for item in (lookup_symbol_info(s, OUTPUT_REPO_DIR) for s in partial_hits[:search_limit])
                if item
            ]
            search_graph_url = ""
            search_graph_error = ""
            search_graph_result_index = None
            try:
                artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
                callgraph, _ = load_search_callgraph(artifact_root)
                search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
                    artifact_root,
                    symbol_results,
                    callgraph,
                    graph_name="search_results_graph",
                    depth=graph_depth,
                    max_nodes=graph_max_nodes,
                )
            except Exception as e:
                search_graph_error = str(e)
                logger.warning("Unable to build symbol search graph for %s/%s: %s", owner, repo, e)
            retrieval_context = {
                "query": query,
                "root": partial_hits[0] if partial_hits else None,
                "strategy": "symbol index lookup",
                "retrieval_strategy": retrieval_strategy,
                "code_units": [],
            }
            retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, retrieval_context, symbol_results, text_results)
            stored_context = retrieval_context.get("stored_generated_answers") or {}
            return {
                "query_type": "symbol_match",
                "query": query,
                "search_backend": "symbol_index",
                "symbols": partial_hits,
                "count": len(symbol_results),
                "results": symbol_results,
                "text_count": len(text_results),
                "text_results": text_results,
                "retrieval_context": retrieval_context,
                "retrieval_plan": retrieval_plan,
                "retrieval_strategy": retrieval_strategy,
                "answer": stored_context.get("best_answer") or "",
                "answer_source": stored_context.get("best_source_type") or "",
                "answer_truth_status": stored_context.get("truth_status") or "",
                "stored_generated_answers": stored_context,
                "answer_prompt": build_search_answer_prompt(
                    query,
                    retrieval_context,
                    symbol_results,
                    text_results,
                    OUTPUT_REPO_DIR,
                    prompt_template=prompt_template,
                ),
                "search_graph_url": search_graph_url,
                **search_graph_artifact_urls(search_graph_url),
                "search_graph_error": search_graph_error,
                "search_graph_result_index": search_graph_result_index,
                "search_graph_depth": graph_depth,
                "search_graph_max_nodes": graph_max_nodes,
            }

    # ---------------------------------------------------------
    # 4. SCIM SEMANTIC SEARCH (FALLBACK OR EXACT SYMBOL)
    # ---------------------------------------------------------
    try:
        scim_payload = search_scim_dataset(OUTPUT_REPO_DIR, query, search_limit)
    except Exception as e:
        logger.exception("SCIM search failed for %s/%s query=%r", owner, repo, query)
        scim_payload = None
        scim_error = str(e)
    else:
        scim_error = ""

    if scim_payload is not None:
        scim_results = scim_payload.get("results", [])
    else:
        scim_results = []

    if scim_payload is not None and (scim_results or text_results):
        retrieval_context = scim_payload.get("retrieval_context", {})
        retrieval_context["retrieval_plan"] = scim_payload.get("retrieval_plan", retrieval_plan)
        retrieval_context["retrieval_strategy"] = scim_payload.get("retrieval_strategy") or retrieval_strategy
        retrieval_context["evidence_cards"] = build_scim_evidence_cards(scim_results, text_results, limit=14)
        retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, retrieval_context, scim_results, text_results)
        stored_context = retrieval_context.get("stored_generated_answers") or {}

        answer_prompt = build_search_answer_prompt(
            query,
            retrieval_context,
            scim_results,
            text_results,
            OUTPUT_REPO_DIR,
            prompt_template=prompt_template,
        )

        artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
        search_graph_url = ""
        callgraph_source = ""
        search_graph_error = ""
        search_graph_result_index = None

        try:
            callgraph, callgraph_source = load_search_callgraph(artifact_root)
            search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
                artifact_root,
                scim_results,
                callgraph,
                graph_name="search_results_graph",
                depth=graph_depth,
                max_nodes=graph_max_nodes,
            )
        except Exception as e:
            search_graph_error = str(e)
            logger.warning("Unable to build semantic search graph for %s/%s: %s", owner, repo, e)

        response_payload = {
            "query": query,
            "intent": {"intent": "semantic_model_search", "target": query},
            "search_backend": "scim",
            "callgraph_source": callgraph_source,
            "count": len(scim_results),
            "results": scim_results,
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": retrieval_context,
            "retrieval_plan": scim_payload.get("retrieval_plan", {}),
            "retrieval_strategy": scim_payload.get("retrieval_strategy") or retrieval_strategy,
            "query_brain": scim_payload.get("query_brain", {}),
            "evidence_cards": retrieval_context.get("evidence_cards", []),
            "answer": stored_context.get("best_answer") or "",
            "answer_source": stored_context.get("best_source_type") or "",
            "answer_truth_status": stored_context.get("truth_status") or "",
            "stored_generated_answers": stored_context,
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": search_graph_url,
            **search_graph_artifact_urls(search_graph_url),
            "search_graph_error": search_graph_error,
            "scim_error": scim_error,
            "search_graph_result_index": search_graph_result_index,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }
        if not scim_results and not text_results:
            response_payload["zero_result_diagnostics"] = search_zero_result_diagnostics(
                OUTPUT_REPO_DIR,
                query,
                scim_error,
            )

        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
            logger.warning("Unable to store search interaction for %s/%s: %s", owner, repo, e)

        return response_payload

    # ---------------------------------------------------------
    # 5. EXPLICIT GA / USER-ACTIVITY SEARCH
    # ---------------------------------------------------------
    if should_answer_from_ga_flow(query, text_results):
        answer_prompt = build_search_answer_prompt(query, {}, [], text_results, prompt_template=prompt_template)
        response_payload = {
            "query": query,
            "intent": {"intent": "ga_user_flow_summary", "target": query},
            "search_backend": "ga_user_activity_search",
            "count": 0,
            "results": [],
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": {
                "query": query,
                "root": None,
                "strategy": "explicit GA/user-activity evidence search",
                "retrieval_strategy": retrieval_strategy,
                "code_units": [],
            },
            "retrieval_plan": retrieval_plan,
            "retrieval_strategy": retrieval_strategy,
            "answer": "",
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": "",
            "search_graph_error": "",
            "scim_error": scim_error,
            "search_graph_result_index": None,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
            logger.warning("Unable to store GA user-activity search interaction for %s/%s: %s", owner, repo, e)

        return response_payload

    # ---------------------------------------------------------
    # 6. CALLGRAPH FALLBACK (YOUR ORIGINAL LOGIC)
    # ---------------------------------------------------------
    try:
        artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
        CALLGRAPH, callgraph_source = load_search_callgraph(artifact_root)
    except Exception as e:
        logger.exception("Search failed to load callgraph for %s/%s", owner, repo)
        restore_result = restore_search_artifacts()
        logger.info("Search fallback artifact restore result for %s/%s: %s", owner, repo, restore_result)
        try:
            artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
            CALLGRAPH, callgraph_source = load_search_callgraph(artifact_root)
        except Exception as restored_error:
            artifact_status = search_local_artifact_status(OUTPUT_REPO_DIR)
            logger.exception(
                "Search still failed to load callgraph after restore for %s/%s. artifacts=%s",
                owner,
                repo,
                artifact_status,
            )
            response_payload = {
                "query": query,
                "count": 0,
                "results": [],
                "text_count": len(text_results),
                "text_results": text_results,
                "answer": "",
                "answer_prompt": build_search_answer_prompt(query, {}, [], text_results, prompt_template=prompt_template),
                "error": str(restored_error),
                "initial_error": str(e),
                "restore_result": restore_result,
                "local_artifacts": artifact_status,
                "search_graph_url": ""
            }
            if not text_results:
                response_payload["zero_result_diagnostics"] = search_zero_result_diagnostics(
                    OUTPUT_REPO_DIR,
                    query,
                    str(restored_error),
                )
            try:
                response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
            except Exception as store_error:
                logger.warning("Unable to store failed search interaction for %s/%s: %s", owner, repo, store_error)
            return response_payload

    if not CALLGRAPH:
        response_payload = {
            "query": query,
            "count": 0,
            "results": [],
            "text_count": len(text_results),
            "text_results": text_results,
            "answer": "",
            "answer_prompt": build_search_answer_prompt(query, {}, [], text_results, prompt_template=prompt_template),
            "error": "Callgraph was loaded but contained no functions.",
            "local_artifacts": search_local_artifact_status(OUTPUT_REPO_DIR),
            "search_graph_url": ""
        }
        if not text_results:
            response_payload["zero_result_diagnostics"] = search_zero_result_diagnostics(
                OUTPUT_REPO_DIR,
                query,
                scim_error,
            )
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as store_error:
            logger.warning("Unable to store failed search interaction for %s/%s: %s", owner, repo, store_error)
        return response_payload

    ORDERED_CALLS, FUNCTION_SET, CALLGRAPH_DICT, reverse_calls, _ = callgraph_indexes(CALLGRAPH)

    FUNCTIONS = [{"name": fn.split(".")[-1], "fullName": fn} for fn in FUNCTION_SET]
    name_functions_index = {fn["name"].lower(): fn for fn in FUNCTIONS}
    fullName_functions_index = {fn["fullName"].lower(): fn for fn in FUNCTIONS}

    parsed_intent, unique_results = resolve_search_functions(
        query,
        FUNCTIONS,
        name_functions_index,
        fullName_functions_index
    )

    enriched_results = []
    for fn in unique_results:
        full = fn["fullName"]
        raw = ORDERED_CALLS.get(full, [])
        clean = [c for c in raw if is_real_call(c)]

        clean_sorted = []
        for c in clean:
            try:
                line = int(c.get("line")) if c.get("line") is not None else None
            except:
                line = None
            try:
                order = int(c.get("order")) if c.get("order") is not None else None
            except:
                order = None

            clean_sorted.append({
                "callee_fullName": c["callee_fullName"],
                "line": line,
                "order": order,
                "call_code": c.get("call_code"),
                "call_name": c.get("call_name")
            })

        clean_sorted = sorted(clean_sorted, key=lambda c: (
            c["line"] if c["line"] is not None else 0,
            c["order"] if c["order"] is not None else 0
        ))

        enriched_results.append({
            "name": fn["name"],
            "fullName": full,
            "calls": CALLGRAPH_DICT.get(full, []),
            "calledBy": reverse_calls.get(full, []),
            "orderedExecution": clean_sorted
        })

    search_graph_url = ""
    search_graph_result_index = None
    search_graph_error = ""
    try:
        search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
            OUTPUT_REPO_DIR,
            enriched_results,
            CALLGRAPH,
            graph_name="search_results_graph",
            depth=graph_depth,
            max_nodes=graph_max_nodes,
        )
    except Exception as e:
        search_graph_error = str(e)
        logger.warning("Unable to build fallback search graph for %s/%s: %s", owner, repo, e)

    retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, {}, enriched_results, text_results)
    stored_context = retrieval_context.get("stored_generated_answers") or {}
    response_payload = {
        "query": query,
        "intent": parsed_intent,
        "search_backend": "callgraph_fallback",
        "callgraph_source": callgraph_source,
        "count": len(enriched_results),
        "results": enriched_results,
        "text_count": len(text_results),
        "text_results": text_results,
        "retrieval_context": retrieval_context,
        "answer": stored_context.get("best_answer") or "",
        "answer_source": stored_context.get("best_source_type") or "",
        "answer_truth_status": stored_context.get("truth_status") or "",
        "stored_generated_answers": stored_context,
        "answer_prompt": build_search_answer_prompt(query, retrieval_context, enriched_results, text_results, OUTPUT_REPO_DIR, prompt_template=prompt_template),
        "search_graph_url": search_graph_url,
        **search_graph_artifact_urls(search_graph_url),
        "search_graph_error": search_graph_error,
        "scim_error": scim_error,
        "search_graph_result_index": search_graph_result_index,
        "search_graph_depth": graph_depth,
        "search_graph_max_nodes": graph_max_nodes,
        "restore_result": restore_result or {},
    }
    if not enriched_results and not text_results:
        response_payload["zero_result_diagnostics"] = search_zero_result_diagnostics(
            OUTPUT_REPO_DIR,
            query,
            scim_error,
        )

    try:
        response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
    except Exception as e:
        logger.warning("Unable to store fallback search interaction for %s/%s: %s", owner, repo, e)

    return response_payload


@app.post("/search-result-graph")
def search_result_graph(payload: dict):
    """Build a callgraph subgraph centered on a single search result.

    Used when the user clicks a specific result in the search results list
    (as opposed to /search, which auto-picks the first graph-resolvable
    result out of the whole ranked list).
    """
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    result = payload.get("result") or {}
    if not owner or not repo:
        return {"error": "owner_name and repo_name are required.", "search_graph_url": ""}
    if not isinstance(result, dict):
        return {
            "error": "result must be an object.",
            "search_graph_url": "",
        }
    diff_entries = diff_file_entries_from_result(result)
    has_symbol_root = any(result.get(key) for key in ("graph_symbol", "fullName", "symbol", "name"))
    if not has_symbol_root and not diff_entries:
        return {
            "error": "result must include a graph symbol or changed file path.",
            "search_graph_url": "",
            "diff_graph_url": "",
        }

    repo_id = short_id(owner, repo)
    OUTPUT_REPO_DIR = Path(BASE_OUTPUT) / repo_id
    restore_result = {}
    mirror_artifact_path = payload.get("artifact_root_path") or payload.get("mirror_artifact_dir") or ""
    if mirror_artifact_path and (not OUTPUT_REPO_DIR.exists() or not output_has_usable_search_callgraph(OUTPUT_REPO_DIR)):
        restore_result = materialize_mirrored_analysis_output(
            mirror_artifact_path,
            OUTPUT_REPO_DIR,
            owner,
            repo,
        )
        logger.info("Search result graph mirror materialization result for %s/%s: %s", owner, repo, restore_result)
    if not OUTPUT_REPO_DIR.exists():
        return {
            "error": f"No analysis output exists for {owner}/{repo}. Analyze the selected repository first.",
            "restore_result": restore_result,
            "search_graph_url": "",
        }
    artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)

    graph_depth = graph_depth_from_payload(payload)
    graph_max_nodes = graph_max_nodes_from_payload(payload)

    if not has_symbol_root:
        diff_graph_url = ""
        diff_graph_error = ""
        try:
            diff_graph_url = build_diff_file_graph(artifact_root, diff_entries)
        except Exception as e:
            diff_graph_error = str(e)
            logger.warning("Unable to build diff file graph for %s/%s: %s", owner, repo, e)
        return {
            "owner_name": owner,
            "repo_name": repo,
            "callgraph_source": "file_graph",
            "search_graph_url": diff_graph_url,
            "diff_graph_url": diff_graph_url,
            "search_graph_error": diff_graph_error,
        }

    try:
        callgraph, callgraph_source = load_search_callgraph(artifact_root)
    except Exception as e:
        return {"error": f"Unable to load callgraph: {e}", "search_graph_url": ""}

    search_graph_url = ""
    search_graph_error = ""
    highlight_data = {
        "changed_nodes": [
            value for value in (
                result.get("graph_symbol"),
                result.get("fullName"),
                result.get("symbol"),
                result.get("name"),
            )
            if value
        ],
        "affected_nodes": result.get("impact_nodes") if isinstance(result.get("impact_nodes"), list) else [],
        "affected_files": result.get("impact_files") if isinstance(result.get("impact_files"), list) else [],
        "file_nodes": [result.get("file")] if result.get("file") else [],
    }
    try:
        search_graph_url, _, search_graph_error = build_first_available_search_graph(
            artifact_root,
            [result],
            callgraph,
            graph_name="search_results_graph",
            depth=graph_depth,
            max_nodes=graph_max_nodes,
            highlight_data=highlight_data,
        )
    except Exception as e:
        search_graph_error = str(e)
        logger.warning("Unable to build search graph for a single result for %s/%s: %s", owner, repo, e)

    return {
        "owner_name": owner,
        "repo_name": repo,
        "callgraph_source": callgraph_source,
        "search_graph_url": search_graph_url,
        **search_graph_artifact_urls(search_graph_url),
        "search_graph_error": search_graph_error,
    }


@app.get("/function-summaries")
def function_summaries(owner_name: str = "", repo_name: str = "", owner: str = "", repo: str = "", limit: int = 50):
    owner_value = (owner_name or owner or "").strip()
    repo_value = (repo_name or repo or "").strip()
    if not owner_value or not repo_value:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required.")
    output_dir = repo_output_dir(owner_value, repo_value)
    repo_id = short_id(owner_value, repo_value)
    summaries = load_all_function_summaries(output_dir, limit=limit)
    return {
        "owner_name": owner_value,
        "repo_name": repo_value,
        "count": len(summaries),
        "job": top_function_summary_job(repo_id),
        "store": str(generated_store_paths(output_dir)["function_summaries"]),
        "summaries": summaries,
    }


@app.post("/searchOLD")
def search(payload: dict):
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    query = payload.get("query", "").strip()
    if not owner or not repo:
        return {
            "error": "owner_name and repo_name are required for repository search.",
            "results": [],
            "text_results": [],
            "answer": "",
        }

    logger.info(f"Analyzing {owner}/{repo}")

    repo_id = short_id(owner, repo)
    OUTPUT_REPO_DIR = os.path.join(BASE_OUTPUT, repo_id)
    OUTPUT_REPO_SEARCH_DIR = os.path.join(OUTPUT_REPO_DIR, "search")
    os.makedirs(OUTPUT_REPO_SEARCH_DIR, exist_ok=True)

    search_limit = int(payload.get("limit", 10) or 10)
    graph_depth = graph_depth_from_payload(payload)
    graph_max_nodes = graph_max_nodes_from_payload(payload)
    query_terms = search_query_terms(query)
    text_search_limit = max(search_limit, 50) if is_explicit_ga_behavior_query(query, query_terms) else search_limit
    
    query_lower = query.lower().strip()

    caller_match = re.search(
        r"^(?:find|show|list)?\s*(?:all\s+)?callers(?:\s+of)?(?:\s+this)?(?:\s+function)?\s+([a-zA-Z0-9_\.]+)",
        query_lower
    )

    if caller_match and caller_match.group(1) not in CALLGRAPH_SYMBOL_STOPWORDS:
        caller_symbol = caller_match.group(1)

    callee_match = re.search(
        r"^(?:find|show|list)?\s*(?:all\s+)?callees(?:\s+of)?(?:\s+this)?(?:\s+function)?\s+([a-zA-Z0-9_\.]+)",
        query_lower
    )

    if callee_match and callee_match.group(1) not in CALLGRAPH_SYMBOL_STOPWORDS:
        callee_symbol = callee_match.group(1)


    text_results = search_repository_text_matches(OUTPUT_REPO_DIR, query, text_search_limit)

    # 2. Load all symbols for prefix/substring matching
    symbols = load_all_symbols(OUTPUT_REPO_DIR)

    # 3. Try symbol-based search BEFORE semantic search
    symbol_hits = [
        s for s in symbols
        if query_lower in s.lower() or loose_symbol_match(query, s)
    ]

    if symbol_hits:
        return {
            "query_type": "symbol_match",
            "symbols": symbol_hits,
            "results": [lookup_symbol_info(s, OUTPUT_REPO_DIR) for s in symbol_hits]
        }

    
    scim_payload = search_scim_dataset(OUTPUT_REPO_DIR, query, search_limit)
    
    if scim_payload is not None:
        scim_results = scim_payload.get("results", [])
        retrieval_context = scim_payload.get("retrieval_context", {})
        retrieval_context["evidence_cards"] = build_scim_evidence_cards(scim_results, text_results, limit=14)
        retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, retrieval_context, scim_results, text_results)
        stored_context = retrieval_context.get("stored_generated_answers") or {}
        answer_prompt = build_search_answer_prompt(
            query,
            retrieval_context,
            scim_results,
            text_results,
            OUTPUT_REPO_DIR,
            prompt_template=prompt_template,
        )
        artifact_root = artifact_root_for_output(OUTPUT_REPO_DIR)
        search_graph_url = ""
        callgraph_source = ""
        search_graph_error = ""
        search_graph_result_index = None
        try:
            callgraph, callgraph_source = load_search_callgraph(artifact_root)
            search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
                artifact_root,
                scim_results,
                callgraph,
                graph_name="search_results_graph",
                depth=graph_depth,
                max_nodes=graph_max_nodes,
            )
        except Exception as e:
            search_graph_error = str(e)
            logger.warning("Unable to build semantic search graph for %s/%s: %s", owner, repo, e)
        response_payload = {
            "query": query,
            "intent": {"intent": "semantic_model_search", "target": query},
            "search_backend": "scim",
            "callgraph_source": callgraph_source,
            "count": len(scim_results),
            "results": scim_results,
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": retrieval_context,
            "retrieval_plan": scim_payload.get("retrieval_plan", {}),
            "query_brain": scim_payload.get("query_brain", {}),
            "evidence_cards": retrieval_context.get("evidence_cards", []),
            "answer": stored_context.get("best_answer") or "",
            "answer_source": stored_context.get("best_source_type") or "",
            "answer_truth_status": stored_context.get("truth_status") or "",
            "stored_generated_answers": stored_context,
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": search_graph_url,
            **search_graph_artifact_urls(search_graph_url),
            "search_graph_error": search_graph_error,
            "search_graph_result_index": search_graph_result_index,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
            logger.warning("Unable to store search interaction for %s/%s: %s", owner, repo, e)
        return _inject_caller_data(response_payload, OUTPUT_REPO_DIR, caller_symbol, callee_symbol)  # ← changed

    if should_answer_from_ga_flow(query, text_results):
        answer_prompt = build_search_answer_prompt(query, {}, [], text_results, prompt_template=prompt_template)
        response_payload = {
            "query": query,
            "intent": {"intent": "ga_user_flow_summary", "target": query},
            "search_backend": "ga_user_activity_search",
            "count": 0,
            "results": [],
            "text_count": len(text_results),
            "text_results": text_results,
            "retrieval_context": {
                "query": query,
                "root": None,
                "strategy": "explicit GA/user-activity evidence search from ga_interactions.json and generated GA graphs",
                "code_units": [],
            },
            "answer": "",
            "answer_prompt": answer_prompt,
            "answer_prompt_chars": len(answer_prompt),
            "search_graph_url": "",
            "search_graph_error": "",
            "search_graph_result_index": None,
            "search_graph_depth": graph_depth,
            "search_graph_max_nodes": graph_max_nodes,
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as e:
    
    
            logger.warning("Unable to store GA user-activity search interaction for %s/%s: %s", owner, repo, e)
        return _inject_caller_data(response_payload, OUTPUT_REPO_DIR, caller_symbol, callee_symbol)

    try:
        CALLGRAPH, callgraph_source = load_search_callgraph(OUTPUT_REPO_DIR)
    except Exception as e:
        logger.exception("Search failed to load callgraph for %s/%s", owner, repo)
        response_payload = {
            "query": query,
            "count": 0,
            "results": [],
            "text_count": len(text_results),
            "text_results": text_results,
            "answer": "",
            "answer_prompt": build_search_answer_prompt(query, {}, [], text_results, prompt_template=prompt_template),
            "error": str(e),
            "search_graph_url": ""
        }
        try:
            response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
        except Exception as store_error:
            logger.warning("Unable to store failed search interaction for %s/%s: %s", owner, repo, store_error)
        return _inject_caller_data(response_payload, OUTPUT_REPO_DIR, caller_symbol, callee_symbol)

    
    ORDERED_CALLS, FUNCTION_SET, CALLGRAPH_DICT, reverse_calls, _ = callgraph_indexes(CALLGRAPH)

    # ---------------------------------------------------------
    # Build FUNCTIONS list
    # ---------------------------------------------------------
    FUNCTIONS = [
        {"name": fn.split(".")[-1], "fullName": fn}
        for fn in FUNCTION_SET
    ]

    # ---------------------------------------------------------
    # Build indexes
    # ---------------------------------------------------------
    name_functions_index = {fn["name"].lower(): fn for fn in FUNCTIONS}
    fullName_functions_index = {fn["fullName"].lower(): fn for fn in FUNCTIONS}

    # ---------------------------------------------------------
    # Perform search
    # ---------------------------------------------------------
    parsed_intent, unique_results = resolve_search_functions(
        query,
        FUNCTIONS,
        name_functions_index,
        fullName_functions_index
    )



    # ---------------------------------------------------------
    # Build enriched results (calls + calledBy + orderedExecution)
    # ---------------------------------------------------------
    enriched_results = []
    for fn in unique_results:
        full = fn["fullName"]

        # 1. Get raw ordered calls
        raw = ORDERED_CALLS.get(full, [])

        # 2. Filter out AST noise
        clean = [c for c in raw if is_real_call(c)]

        # 3. Normalize + sort by real execution order
        clean_sorted = []
        for c in clean:
            # Normalize line
            try:
                line = int(c.get("line")) if c.get("line") is not None else None
            except:
                line = None

            # Normalize order
            try:
                order = int(c.get("order")) if c.get("order") is not None else None
            except:
                order = None

            clean_sorted.append({
                "callee_fullName": c["callee_fullName"],
                "line": line,
                "order": order,
                "call_code": c.get("call_code"),
                "call_name": c.get("call_name")
            })

        # Sort by (line, order)
        clean_sorted = sorted(
            clean_sorted,
            key=lambda c: (
                c["line"] if c["line"] is not None else 0,
                c["order"] if c["order"] is not None else 0
            )
        )

        enriched_results.append({
            "name": fn["name"],
            "fullName": full,
            "calls": CALLGRAPH_DICT.get(full, []),      # outgoing (structural)
            "calledBy": reverse_calls.get(full, []),    # incoming
            "orderedExecution": clean_sorted            # outgoing (ordered)
        })

    search_graph_url, search_graph_result_index, search_graph_error = build_first_available_search_graph(
        OUTPUT_REPO_DIR,
        enriched_results,
        CALLGRAPH,
        graph_name="search_results_graph",
        depth=graph_depth,
        max_nodes=graph_max_nodes,
    )

    print("search_graph_url:", search_graph_url)
    
    #  ---------------------------------------------------------
    # Final response
    # ---------------------------------------------------------
    retrieval_context = attach_stored_generated_context(OUTPUT_REPO_DIR, query, {}, enriched_results, text_results)
    stored_context = retrieval_context.get("stored_generated_answers") or {}
    response_payload = {
        "query": query,
        "intent": parsed_intent,
        "callgraph_source": callgraph_source,
        "count": len(enriched_results),
        "results": enriched_results,
        "text_count": len(text_results),
        "text_results": text_results,
        "retrieval_context": retrieval_context,
        "answer": stored_context.get("best_answer") or "",
        "answer_source": stored_context.get("best_source_type") or "",
        "answer_truth_status": stored_context.get("truth_status") or "",
        "stored_generated_answers": stored_context,
        "answer_prompt": build_search_answer_prompt(query, retrieval_context, enriched_results, text_results, OUTPUT_REPO_DIR, prompt_template=prompt_template),
        "search_graph_url": search_graph_url,
        **search_graph_artifact_urls(search_graph_url),
        "search_graph_error": search_graph_error,
        "search_graph_result_index": search_graph_result_index,
        "search_graph_depth": graph_depth,
        "search_graph_max_nodes": graph_max_nodes
    }
    try:
        response_payload["search_history"] = store_search_interaction(OUTPUT_REPO_DIR, response_payload)
    except Exception as e:
        logger.warning("Unable to store fallback search interaction for %s/%s: %s", owner, repo, e)
    return response_payload




@app.post("/search-answer")
def search_answer(request: Request, payload: dict):
    try:
        original_prompt = str(payload.get("prompt") or "")
        prompt = original_prompt
        owner = payload.get("owner_name") or payload.get("owner") or ""
        repo = payload.get("repo_name") or payload.get("repo") or ""
        output_dir = repo_output_dir(owner, repo) if owner and repo else None
        if not prompt:
            prompt = build_search_answer_prompt(
                payload.get("query", ""),
                payload.get("retrieval_context") or {},
                payload.get("results") or [],
                payload.get("text_results") or [],
                output_dir,
                prompt_template=payload.get("prompt_template", ""),
            )
        truncated = len(prompt) > OPENAI_SEARCH_PROMPT_MAX_CHARS
        prompt_for_model = (
            prompt[:OPENAI_SEARCH_PROMPT_MAX_CHARS]
            + "\n\n[Prompt truncated by CodeVal to keep answer generation within production timeout limits.]"
            if truncated else prompt
        )
        answer = generate_search_answer_from_prompt(prompt_for_model)
        memory = {}
        if owner and repo and not search_answer_is_error(answer):
            try:
                memory = store_derived_answer_memory(output_dir, payload, answer, prompt_for_model)
                generated_store_path = (memory.get("generated_store") or {}).get("path", "") if isinstance(memory, dict) else ""
                memory["supabase_upload"] = supabase_upload_generated_artifacts_for_latest(
                    request,
                    owner,
                    repo,
                    output_dir,
                    [
                        memory.get("memory_path", ""),
                        generated_store_path,
                    ],
                    fields={
                        "latest_search_answer": {
                            "query": payload.get("query", ""),
                            "answer": answer,
                            "prompt_chars": len(prompt_for_model),
                            "generated_at": datetime.now().isoformat(),
                            "truth_status": "derived_not_original_truth",
                        }
                    },
                )
            except Exception as e:
                logger.warning("Unable to store derived search-answer memory: %s", e)
        return {
            "answer": answer,
            "prompt": prompt_for_model,
            "prompt_chars": len(prompt_for_model),
            "original_prompt_chars": len(prompt),
            "prompt_truncated": truncated,
            "derived_memory": memory,
        }
    except Exception as e:
        logger.exception("Search answer failed before JSON response could be returned")
        return JSONResponse(
            status_code=500,
            content={
                "answer": "",
                "error": f"Search answer failed: {type(e).__name__}: {e}",
                "prompt_chars": len(str(payload.get("prompt") or "")),
                "derived_memory": {},
            },
        )


@app.post("/search-answer-feedback")
def search_answer_feedback(payload: dict):
    owner = payload.get("owner_name") or payload.get("owner") or ""
    repo = payload.get("repo_name") or payload.get("repo") or ""
    answer_id = str(payload.get("answer_id") or "").strip()
    if not owner or not repo:
        raise HTTPException(status_code=400, detail="owner_name and repo_name are required")
    if not answer_id:
        raise HTTPException(status_code=400, detail="answer_id is required")
    approved = payload.get("approved")
    if approved is not None:
        approved = bool(approved)
    return update_derived_answer_feedback(
        repo_output_dir(owner, repo),
        answer_id,
        str(payload.get("feedback") or ""),
        approved,
    )

#============================================================
#   SUMMARY ROUTE
#============================================================

def compact_feature_for_llm(feature: dict, feature_id: str = "") -> dict:
    """Keep only feature-relevant evidence for user-facing descriptions."""
    evidence = []
    for item in (feature.get("evidence") or [])[:5]:
        evidence.append({
            "symbol": item.get("symbol", ""),
            "path": item.get("path", ""),
            "start_line": item.get("start_line", ""),
            "matched_terms": (item.get("matched_terms") or [])[:6],
        })

    subfeatures = []
    for item in (feature.get("subfeatures") or [])[:8]:
        subfeatures.append({
            "name": item.get("name", ""),
            "match_count": item.get("match_count", 0),
            "evidence": [
                {
                    "symbol": evidence_item.get("symbol", ""),
                    "path": evidence_item.get("path", ""),
                    "matched_terms": (evidence_item.get("matched_terms") or [])[:4],
                }
                for evidence_item in (item.get("evidence") or [])[:2]
            ],
        })

    comments = []
    for item in (feature.get("comment_evidence") or [])[:3]:
        comments.append({
            "file": item.get("file", ""),
            "line": item.get("line", ""),
            "text": str(item.get("text", ""))[:300],
            "matched_terms": (item.get("matched_terms") or [])[:6],
        })

    ui_evidence = [
        {
            "path": item.get("path", ""),
            "start_line": item.get("start_line", ""),
            "type": item.get("type", ""),
        }
        for item in (feature.get("ui_evidence") or [])[:4]
    ]
    anchor_counts = {
        anchor_type: len(rows)
        for anchor_type, rows in (feature.get("anchors") or {}).items()
        if isinstance(rows, list)
    }

    payload = {
        "feature": feature.get("feature", ""),
        "status": feature.get("status", "implemented"),
        "visibility": feature.get("visibility", ""),
        "match_count": feature.get("match_count", 0),
        "anchor_counts": anchor_counts,
        "subfeatures": subfeatures,
        "evidence": evidence,
        "comment_evidence": comments,
        "ui_evidence": ui_evidence,
    }
    if feature_id:
        payload["feature_id"] = feature_id
    return payload


def extract_json_object(text: str) -> dict:
    try:
        return json.loads(text)
    except Exception:
        pass
    match = re.search(r"\{.*\}", text or "", re.DOTALL)
    if not match:
        return {}
    try:
        return json.loads(match.group(0))
    except Exception:
        return {}


def short_feature_symbol(symbol: str) -> str:
    parts = [part for part in str(symbol or "").split(".") if part]
    if len(parts) >= 2:
        return ".".join(parts[-2:])
    return str(symbol or "")


def feature_evidence_references(feature: dict, limit: int = 3) -> list[dict]:
    references = []
    for item in (feature.get("evidence") or [])[:limit]:
        symbol = item.get("symbol", "")
        path = item.get("path", "")
        references.append({
            "symbol": symbol,
            "short_symbol": short_feature_symbol(symbol),
            "path": path,
            "file": Path(str(path)).name,
            "start_line": item.get("start_line", ""),
        })
    return references


def add_feature_reference_urls(summaries: list[dict], artifact_root):
    root = Path(artifact_root)
    for summary in summaries:
        for reference in summary.get("references", []) or []:
            rel_path = str(reference.get("path") or "").replace("\\", "/")
            if not rel_path or should_skip_path(rel_path):
                continue
            candidates = [
                root / "src" / rel_path,
                root / rel_path,
            ]
            for candidate in candidates:
                if candidate.exists():
                    reference["source_url"] = output_url(candidate)
                    break
    return summaries


def generate_feature_descriptions_old(features: list[dict], product_name: str = "", product_type: str = "", user_guidance: str = "", return_prompt: bool = False):
    compact_features = [
        compact_feature_for_llm(feature, f"feature_{index + 1}")
        for index, feature in enumerate(features[:12])
    ]
    if not compact_features:
        logger.info("Feature LLM skipped: no feature evidence supplied.")
        return ([], "") if return_prompt else []

    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        logger.warning("Feature LLM skipped: OPENAI_API_KEY is not set.")
        return ([], "") if return_prompt else []

    prompt = f"""
Write short user-facing feature descriptions from static code evidence.

Product name: {product_name}
Product type: {product_type}

User feature naming guidance:
{user_guidance or "None"}

Feature evidence:
{json.dumps(compact_features, indent=2)}

Return strict JSON only:
{{
  "features": [
    {{"feature_id": "feature_1", "feature": "clear user-facing capability name", "description": "one paragraph"}}
  ]
}}

Rules:
- The feature name must describe a real user-facing or developer-facing capability.
- Do NOT use repository owner names, usernames, package prefixes, filenames, project names, or random internal identifiers as feature names.
- Do NOT create feature names like "{product_name} Analysis", "Scim Pranaysaani Val", or names made only from repo/package tokens.
- If the evidence is only internal utility code, name it as an internal capability such as "Code Similarity Analysis", "Graph Indexing", "Feature Catalog Generation", or "Repository Metadata Inference".
- Prefer names based on actions and outcomes, not nouns from file paths.
- Follow the user feature naming guidance when it is provided, unless it conflicts with the supplied evidence.
- Write exactly one paragraph per feature, 35-75 words.
- Explain what the feature appears to do based only on supplied subfeatures, symbols, paths, UI evidence, and comments.
- Do not mention reachability, extracted graph gaps, incomplete signals, confidence, match counts, or static-analysis limitations.
- Do not use bullets or markdown in descriptions.
"""

    try:
        logger.info("Feature LLM request starting: features=%s model=%s", len(compact_features), os.getenv("OPENAI_SUMMARY_MODEL", "gpt-4o-mini"))
        response = requests.post(
            "https://api.openai.com/v1/chat/completions",
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
            },
            json={
                "model": os.getenv("OPENAI_SUMMARY_MODEL", "gpt-4o-mini"),
                "messages": [{"role": "user", "content": prompt}],
                "max_tokens": 2400,
                "temperature": 0.25,
            },
            timeout=GITHUB_REQUEST_TIMEOUT,
        )
        response.raise_for_status()
        data = response.json()
        parsed = extract_json_object((data["choices"][0]["message"]["content"] or "").strip())
        rows = parsed.get("features", []) if isinstance(parsed, dict) else []
        logger.info("Feature LLM response parsed: rows=%s", len(rows))
    except Exception as e:
        logger.warning("Unable to generate feature descriptions: %s", e)
        return ([], prompt) if return_prompt else []

    descriptions_by_id = {}
    descriptions_by_name = {}
    descriptions_by_index = {}
    names_by_id = {}
    names_by_index = {}
    parsed_rows = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        parsed_rows.append(row)
        feature_id = str(row.get("feature_id", "")).strip()
        name = str(row.get("feature", "")).strip()
        description = " ".join(str(row.get("description", "")).split())
        if name and description:
            descriptions_by_name[name] = description
        if feature_id and description:
            descriptions_by_id[feature_id] = description
        if feature_id and name:
            names_by_id[feature_id] = name
    for index, row in enumerate(parsed_rows):
        name = str(row.get("feature", "")).strip()
        description = " ".join(str(row.get("description", "")).split())
        if description:
            descriptions_by_index[index] = description
        if name:
            names_by_index[index] = name

    descriptions = []
    for index, feature in enumerate(compact_features):
        feature_id = feature.get("feature_id", "")
        feature_name = feature.get("feature", "")
        description = (
            descriptions_by_id.get(feature_id)
            or descriptions_by_name.get(feature_name)
            or descriptions_by_index.get(index, "")
        )
        descriptions.append({
            "feature_id": feature_id,
            "feature": names_by_id.get(feature_id) or names_by_index.get(index) or feature_name,
            "description": description,
            "status": feature.get("status", "implemented"),
            "visibility": feature.get("visibility", ""),
            "references": feature_evidence_references(feature),
        })
    return (descriptions, prompt) if return_prompt else descriptions


def persist_feature_summaries(artifact_root, summaries: list[dict]):
    architecture_dir = architecture_dir_for_output(artifact_root)
    json_path = architecture_dir / "feature_summaries.json"
    text_path = architecture_dir / "features.txt"
    payload = {
        "generated_at": datetime.now().isoformat(),
        "feature_summaries": summaries,
        "feature_summary_count": sum(1 for item in summaries if item.get("description")),
    }
    json_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    lines = []
    for item in summaries:
        if not item.get("description"):
            continue
        lines.append(str(item.get("feature") or "Feature"))
        lines.append(str(item.get("description", "")))
        references = [
            f"{ref.get('short_symbol') or ref.get('symbol')} ({ref.get('file') or ref.get('path')}:{ref.get('start_line')})"
            for ref in (item.get("references") or [])[:3]
            if ref.get("short_symbol") or ref.get("symbol")
        ]
        if references:
            lines.append("From: " + "; ".join(references))
        lines.append("")
    text_path.write_text("\n".join(lines).strip() + ("\n" if lines else ""), encoding="utf-8")
    return str(json_path), str(text_path)


def feature_summary_evidence_ids(features: list[dict], limit: int = 12):
    ids = ["feature_summary:evidence.features.summary"]
    for index, feature in enumerate((features or [])[:limit], start=1):
        ids.append(f"feature_candidate:feature_{index}:{feature.get('feature', '')}")
        for item in (feature.get("evidence") or [])[:5]:
            if isinstance(item, dict) and item.get("symbol"):
                ids.append(f"code_function:{item.get('symbol')}")
        for item in (feature.get("comment_evidence") or [])[:3]:
            if isinstance(item, dict) and item.get("file"):
                ids.append(f"source_text:{item.get('file')}:{item.get('line', '')}")
    return list(dict.fromkeys(ids))


def product_summary_evidence_ids(features: list[dict], todos: list[dict], comment_text_items: list[dict], callgraph_entries: int):
    ids = ["repo_overview:evidence.repo.overview", "feature_summary:evidence.features.summary", "callgraph_summary:evidence.callgraph.summary"]
    ids.extend(feature_summary_evidence_ids(features, limit=12))
    for item in (todos or [])[:10]:
        if isinstance(item, dict) and item.get("file"):
            ids.append(f"todo:{item.get('file')}:{item.get('line', '')}")
    for item in (comment_text_items or [])[:10]:
        if isinstance(item, dict) and item.get("file"):
            ids.append(f"source_text:{item.get('file')}:{item.get('line', '')}")
    if callgraph_entries:
        ids.append(f"callgraph_entries:{callgraph_entries}")
    return list(dict.fromkeys(ids))


def load_persisted_feature_summaries(artifact_root):
    artifact_root = Path(artifact_root)
    json_path = core_helpers.feature_summaries_path_for_output(artifact_root)
    if not json_path.exists():
        return [], "", ""
    try:
        data = json.loads(json_path.read_text(encoding="utf-8"))
    except Exception as e:
        logger.warning("Unable to load persisted feature summaries: %s", e)
        return [], "", ""
    summaries = data.get("feature_summaries", []) if isinstance(data, dict) else []
    if isinstance(summaries, list):
        for summary in summaries:
            if not isinstance(summary, dict):
                continue
            summary["references"] = [
                reference
                for reference in (summary.get("references") or [])
                if isinstance(reference, dict) and not should_skip_path(str(reference.get("path") or ""))
            ]
    text_path = core_helpers.features_text_path_for_output(artifact_root)
    return summaries if isinstance(summaries, list) else [], str(json_path), str(text_path) if text_path.exists() else ""


def normalize_feature_name_edits(value):
    rows = []
    if not isinstance(value, list):
        return rows
    for index, item in enumerate(value):
        if isinstance(item, dict):
            name = str(item.get("name") or item.get("feature") or "").strip()
            description = str(item.get("description") or item.get("summary") or "").strip()
            original = str(item.get("original") or item.get("original_name") or "").strip()
            feature_id = str(item.get("feature_id") or "").strip()
            source = str(item.get("source") or "").strip()
            deleted = bool(item.get("deleted"))
            evidence_context = item.get("evidence_context") if isinstance(item.get("evidence_context"), dict) else {}
            user_feedback = bool(
                item.get("user_feedback")
                or item.get("userFeedback")
                or description
                or source == "user_added"
                or (name and original and normalized_feature_key(name) != normalized_feature_key(original))
            )
        else:
            name = str(item or "").strip()
            description = ""
            original = ""
            feature_id = ""
            source = ""
            deleted = False
            evidence_context = {}
            user_feedback = False
        if not name and not deleted:
            continue
        rows.append({
            "index": index,
            "feature_id": feature_id,
            "original": original,
            "name": name[:160],
            "description": description[:8000],
            "source": source,
            "deleted": deleted,
            "user_feedback": user_feedback,
            "evidence_context": evidence_context,
        })
    return rows


def normalized_feature_key(value: str) -> str:
    return " ".join(re.findall(r"[a-z0-9]+", str(value or "").lower()))


def feature_blacklist_from_edits(feature_names: list[dict], extra_blacklist: list | None = None) -> list[dict]:
    rows = []
    seen = set()
    sources = [item for item in (feature_names or []) if isinstance(item, dict) and item.get("deleted")]
    if isinstance(extra_blacklist, list):
        for item in extra_blacklist:
            if isinstance(item, dict):
                sources.append(item)
            else:
                sources.append({"name": str(item or "")})
    for item in sources:
        name = str(item.get("original") or item.get("name") or item.get("feature") or "").strip()
        normalized_name = normalized_feature_key(name) or normalized_feature_key(item.get("normalized_name") or "")
        feature_id = str(item.get("feature_id") or "").strip()
        key = normalized_name or feature_id
        if not key or key in seen:
            continue
        seen.add(key)
        rows.append({
            "feature_id": feature_id,
            "name": name[:160],
            "normalized_name": normalized_name,
            "source": item.get("source") or "feature_list",
            "deleted": True,
        })
    return rows


def feature_is_blacklisted(feature: dict, feature_names: list[dict], feature_blacklist: list[dict] | None = None) -> bool:
    feature_id = str(feature.get("feature_id") or "")
    names = [
        feature.get("feature"),
        feature.get("name"),
        feature.get("original_feature"),
    ]
    feature_keys = {normalized_feature_key(name) for name in names if name}
    feature_keys.discard("")
    blacklist = feature_blacklist_from_edits(feature_names, feature_blacklist)
    for item in blacklist:
        blocked_id = str(item.get("feature_id") or "")
        blocked_key = normalized_feature_key(item.get("name") or item.get("original") or item.get("normalized_name") or "")
        if blocked_id and feature_id and blocked_id == feature_id:
            return True
        if blocked_key and blocked_key in feature_keys:
            return True
    return False


def apply_feature_name_edits(features: list[dict], feature_names: list[dict]):
    if not isinstance(features, list) or not feature_names:
        return features
    edited = [dict(feature) if isinstance(feature, dict) else feature for feature in features]
    deleted_ids = {item.get("feature_id") for item in feature_names if item.get("deleted") and item.get("feature_id")}
    deleted_names = {
        str(item.get("original") or item.get("name") or "").lower()
        for item in feature_names
        if item.get("deleted") and (item.get("original") or item.get("name"))
    }
    by_id = {item.get("feature_id"): item for item in feature_names if item.get("feature_id") and not item.get("deleted")}
    by_original = {str(item.get("original") or "").lower(): item for item in feature_names if item.get("original") and not item.get("deleted")}
    visible = []
    for index, feature in enumerate(edited):
        if not isinstance(feature, dict):
            visible.append(feature)
            continue
        feature_id = str(feature.get("feature_id") or "")
        feature_name = str(feature.get("feature") or feature.get("name") or "").lower()
        original_name = str(feature.get("original_feature") or feature.get("feature") or feature.get("name") or "").lower()
        if feature_id in deleted_ids or feature_name in deleted_names or original_name in deleted_names:
            continue
        item = by_id.get(str(feature.get("feature_id") or ""))
        if not item:
            item = by_original.get(str(feature.get("feature") or "").lower())
        if not item and index < len(feature_names):
            item = feature_names[index]
        if item and item.get("deleted"):
            continue
        if item and item.get("name"):
            feature["original_feature"] = feature.get("feature", "")
            feature["feature"] = item["name"]
        if item and item.get("description"):
            feature["description"] = item["description"]
        visible.append(feature)
    return visible


def filter_deleted_feature_rows(features: list[dict], feature_names: list[dict], feature_blacklist: list[dict] | None = None):
    if not isinstance(features, list) or (not feature_names and not feature_blacklist):
        return features
    visible = []
    for feature in features:
        if not isinstance(feature, dict):
            visible.append(feature)
            continue
        if feature_is_blacklisted(feature, feature_names, feature_blacklist):
            continue
        visible.append(feature)
    return visible


def ui_seed_feature_terms(text: str) -> set[str]:
    return {
        term
        for term in re.findall(r"[A-Za-z][A-Za-z0-9]+", str(text or "").lower())
        if len(term) >= 3 and term not in {
            "the", "and", "for", "with", "from", "this", "that", "your",
            "html", "static", "panel", "section", "button", "link", "page",
        }
    }


MAX_VISIBLE_FEATURE_CANDIDATES = int(os.getenv("FEATURE_CANDIDATE_LIMIT", "25") or "25")


def feature_confidence_weight(feature: dict) -> float:
    if not isinstance(feature, dict):
        return 0.0
    anchors = feature.get("anchors") if isinstance(feature.get("anchors"), dict) else {}
    ui_anchor_count = sum(
        len(rows)
        for anchor_type, rows in anchors.items()
        if anchor_type in {"html_ui", "android_ui_xml", "frontend_ui_component", "ui_logic", "api_route"}
        and isinstance(rows, list)
    )
    ui_evidence_count = len(feature.get("ui_evidence") or [])
    evidence_count = len(feature.get("evidence") or [])
    comment_count = len(feature.get("comment_evidence") or [])
    subfeature_count = len(feature.get("subfeatures") or [])
    match_count = int(feature.get("match_count") or 0)
    static_counts = feature.get("static_counts") if isinstance(feature.get("static_counts"), dict) else {}
    function_count = int(static_counts.get("functions") or match_count or 0)
    isolated = int(static_counts.get("isolated_in_extracted_graph") or 0)
    connected_ratio = 0.0 if function_count <= 0 else max(0.0, 1.0 - (isolated / max(1, function_count)))

    score = 0.0
    if feature.get("source") == "ui_feature_seed":
        score += 0.55
    if ui_anchor_count or ui_evidence_count:
        score += 0.22
    if evidence_count:
        score += min(0.18, evidence_count * 0.04)
    if comment_count:
        score += min(0.08, comment_count * 0.03)
    if subfeature_count:
        score += min(0.08, subfeature_count * 0.02)
    if match_count:
        score += min(0.18, math.log1p(match_count) / 16)
    if connected_ratio:
        score += min(0.14, connected_ratio * 0.14)
    if feature.get("reachability") in {"entrypoint", "reachable", "ui_reachable"}:
        score += 0.10
    if feature.get("incomplete_signals"):
        score -= 0.08
    return round(max(0.05, min(score, 0.98)), 3)


def feature_priority_for_confidence(confidence: float) -> tuple[int, str]:
    if confidence >= 0.80:
        return 0, "high"
    if confidence >= 0.55:
        return 1, "medium"
    if confidence >= 0.35:
        return 2, "low"
    return 3, "candidate"


def rank_feature_candidates(features: list[dict], limit: int | None = MAX_VISIBLE_FEATURE_CANDIDATES) -> list[dict]:
    ranked = []
    for index, feature in enumerate(features or []):
        if not isinstance(feature, dict):
            continue
        row = dict(feature)
        confidence = float(row.get("confidence_weight") or row.get("confidence") or feature_confidence_weight(row))
        priority, priority_label = feature_priority_for_confidence(confidence)
        row["confidence_weight"] = round(confidence, 3)
        row["confidence"] = priority_label
        row["priority"] = priority
        row["candidate_status"] = priority_label
        row["_rank_index"] = index
        ranked.append(row)
    ranked.sort(key=lambda row: (
        0 if row.get("required_for_summary") else 1,
        0 if row.get("user_feedback") else 1,
        int(row.get("priority", 3)),
        -float(row.get("confidence_weight") or 0),
        -int(row.get("match_count") or 0),
        int(row.get("_rank_index") or 0),
        str(row.get("feature") or row.get("name") or "").lower(),
    ))
    if limit is not None and limit > 0:
        ranked = ranked[:limit]
    for row in ranked:
        row.pop("_rank_index", None)
    return ranked


def ui_first_feature_list(ui_feature_seeds: list[str], detected_features: list[dict], limit: int | None = None) -> list[dict]:
    if not ui_feature_seeds:
        return rank_feature_candidates(detected_features, limit)
    rows = []
    seeds = ui_feature_seeds if limit is None or limit <= 0 else ui_feature_seeds[:limit]
    for index, seed in enumerate(seeds, start=1):
        seed = re.sub(r"\s+", " ", str(seed or "")).strip()
        if not seed:
            continue
        rows.append({
            "feature_id": f"ui_feature_{index}",
            "feature": seed,
            "original_feature": seed,
            "source": "ui_feature_seed",
            "status": "detected_from_ui",
            "visibility": "UI-visible",
            "match_count": 0,
            "anchors": {},
            "evidence": [],
            "subfeatures": [],
            "comment_evidence": [],
            "ui_evidence": [],
            "evidence_match_status": "ui_label_only",
        })
    return rank_feature_candidates(rows or detected_features, limit)


def product_feature_metadata_fields(payload: dict, feature_catalog: dict | None = None):
    feature_catalog = feature_catalog or {}
    product_name = str(
        payload.get("product_name")
        or payload.get("productName")
        or feature_catalog.get("product_name")
        or ""
    ).strip()[:200]
    product_description = str(
        payload.get("product_description")
        or payload.get("productDescription")
        or payload.get("summary")
        or ""
    ).strip()[:8000]
    feature_names = normalize_feature_name_edits(payload.get("feature_names") or payload.get("features") or [])
    feature_blacklist = feature_blacklist_from_edits(
        feature_names,
        payload.get("feature_blacklist") or payload.get("featureBlacklist") or [],
    )
    feature_implementation_details = payload.get("feature_implementation_details")
    if not isinstance(feature_implementation_details, dict):
        feature_implementation_details = {}
    fields = {}
    if product_name:
        fields["product_name"] = product_name
    if product_description:
        fields["product_description"] = product_description
    if feature_names:
        fields["feature_names"] = feature_names
    if feature_blacklist:
        fields["feature_blacklist"] = feature_blacklist
    if feature_implementation_details:
        fields["feature_implementation_details"] = feature_implementation_details
    return fields


def feature_generation_controls(payload: dict) -> dict:
    """Controls allowed during LLM generation; excludes user descriptions."""
    blacklist = feature_blacklist_from_edits(
        normalize_feature_name_edits(payload.get("feature_names") or payload.get("features") or []),
        payload.get("feature_blacklist") or payload.get("featureBlacklist") or [],
    )
    required_targets = normalize_feature_name_edits(
        payload.get("required_feature_names")
        or payload.get("required_features")
        or []
    )
    required_targets = [
        {
            "index": item.get("index"),
            "feature_id": item.get("feature_id", ""),
            "original": item.get("original", ""),
            "name": item.get("name", ""),
            "description": item.get("description", ""),
            "user_description": item.get("user_description") or item.get("description", ""),
            "evidence_context": item.get("evidence_context") if isinstance(item.get("evidence_context"), dict) else {},
            "source": item.get("source", "feature_list"),
            "user_feedback": bool(item.get("user_feedback")),
        }
        for item in required_targets
        if item.get("name") and not item.get("deleted")
    ]
    return {
        "feature_blacklist": blacklist if blacklist else [],
        "required_feature_names": required_targets,
    }


def apply_required_feature_targets(features: list[dict], required_targets: list[dict]) -> list[dict]:
    if not required_targets:
        return features
    rows = [dict(feature) for feature in (features or []) if isinstance(feature, dict)]
    by_key = {}
    for index, feature in enumerate(rows):
        keys = {
            normalized_feature_key(feature.get("feature") or feature.get("name") or ""),
            normalized_feature_key(feature.get("original_feature") or ""),
            normalized_feature_key(feature.get("feature_id") or ""),
        }
        for key in keys:
            if key:
                by_key.setdefault(key, index)
    required_rows = []
    used_indexes = set()
    for index, target in enumerate(required_targets):
        name = re.sub(r"\s+", " ", str(target.get("name") or "")).strip()
        if not name:
            continue
        keys = [
            normalized_feature_key(target.get("feature_id") or ""),
            normalized_feature_key(target.get("original") or ""),
            normalized_feature_key(name),
        ]
        match_index = next((by_key[key] for key in keys if key and key in by_key), None)
        if match_index is not None:
            row = dict(rows[match_index])
            row["original_feature"] = row.get("original_feature") or target.get("original") or row.get("feature") or name
            row["feature"] = name
            row["name"] = name
            row["feature_id"] = target.get("feature_id") or row.get("feature_id") or f"required_feature_{index + 1}"
            row["source"] = row.get("source") or target.get("source") or "feature_list_required"
            row["required_for_summary"] = True
            row["user_feedback"] = bool(target.get("user_feedback") or row.get("user_feedback"))
            if target.get("description"):
                row["user_description"] = str(target.get("description") or "")[:8000]
            if target.get("evidence_context"):
                row["evidence_context"] = target.get("evidence_context")
                row["status"] = "implemented"
                row["visibility"] = row.get("visibility") or "code-backed"
            row["confidence_weight"] = max(float(row.get("confidence_weight") or 0), 0.99 if row["user_feedback"] else 0.98)
            row["confidence"] = "high"
            row["priority"] = 0
            required_rows.append(row)
            used_indexes.add(match_index)
            continue
        required_rows.append({
            "feature_id": target.get("feature_id") or f"required_feature_{index + 1}",
            "feature": name,
            "name": name,
            "original_feature": target.get("original") or name,
            "source": target.get("source") or "feature_list_required",
            "status": "selected_in_feature_list",
            "visibility": "UI-visible",
            "match_count": 0,
            "anchors": {},
            "evidence": [],
            "subfeatures": [],
            "comment_evidence": [],
            "ui_evidence": [],
            "required_for_summary": True,
            "user_feedback": bool(target.get("user_feedback")),
            "user_description": str(target.get("description") or target.get("user_description") or "")[:8000],
            "evidence_context": target.get("evidence_context") if isinstance(target.get("evidence_context"), dict) else {},
            "confidence_weight": 0.99 if target.get("user_feedback") else 0.98,
            "confidence": "high",
            "priority": 0,
        })
    remainder = [row for index, row in enumerate(rows) if index not in used_indexes]
    seen = set()
    merged = []
    for row in required_rows + remainder:
        key = normalized_feature_key(row.get("feature") or row.get("name") or row.get("feature_id") or "")
        if key and key in seen:
            continue
        if key:
            seen.add(key)
        merged.append(row)
    return merged


@app.post("/product-feature-metadata")
def product_feature_metadata(request: Request, payload: dict):
    owner = payload.get("owner_name", "")
    repo = payload.get("repo_name", "")
    if not owner or not repo:
        return {"ok": False, "error": "owner_name and repo_name are required."}
    fields = product_feature_metadata_fields(payload)
    feature_names = fields.get("feature_names") or []
    feature_blacklist = fields.get("feature_blacklist") or []
    feature_implementation_details = fields.get("feature_implementation_details") or {}
    fields["product_metadata_updated_at"] = datetime.now().isoformat()
    cache_result = supabase_cache_latest_analysis_fields(request, owner, repo, fields)
    graphs = {}
    graph_upload = {}
    try:
        artifact_root = artifact_root_for_output(repo_output_dir(owner, repo))
        graph_results = feature_callgraph_source_results(artifact_root, feature_names)
        if os.path.exists(graph_results.get("feature_catalog_path", "")):
            build_feature_callgraph_outputs(str(artifact_root), graph_results)
            graph_paths = []
            if graph_results.get("feature_callgraph_html_path"):
                graph_paths.append(Path(graph_results.get("feature_callgraph_html_path")))
                graphs["feature_callgraph_html"] = output_url(graph_results.get("feature_callgraph_html_path"))
                graphs["feature_implementation_graph_html"] = graphs["feature_callgraph_html"]
            if graph_results.get("feature_callgraph_json_path"):
                graph_paths.append(Path(graph_results.get("feature_callgraph_json_path")))
                graphs["feature_callgraph_json"] = output_url(graph_results.get("feature_callgraph_json_path"))
                graphs["feature_implementation_graph_json"] = graphs["feature_callgraph_json"]
            if graph_paths:
                graph_upload = supabase_upload_generated_artifacts_for_latest(
                    request,
                    owner,
                    repo,
                    artifact_root,
                    graph_paths,
                )
    except Exception as e:
        logger.warning("Unable to rebuild feature implementation graph from saved feature names: %s", e)
    return {
        "ok": True,
        "owner": owner,
        "repo": repo,
        "product_name": fields.get("product_name", ""),
        "product_description": fields.get("product_description", ""),
        "feature_names": feature_names,
        "feature_blacklist": feature_blacklist,
        "feature_implementation_details": feature_implementation_details,
        "graphs": graphs,
        "feature_graph_upload": graph_upload,
        "supabase": cache_result,
    }


@app.post("/feature-summary")
def feature_summary(request: Request, payload: dict):
    return {
        "feature_summaries": [],
        "feature_summary_count": 0,
        "disabled": True,
        "message": "Feature summaries are disabled. CODE.md now publishes deterministic truth-index artifacts only.",
    }
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    if not owner or not repo:
        return {"feature_summaries": [], "feature_summary_count": 0, "error": "owner_name and repo_name are required."}
    user_guidance = str(payload.get("feature_guidance") or "").strip()[:8000]
    logger.info("Feature summary endpoint called: owner=%s repo=%s", owner, repo)

    repo_id = short_id(owner, repo)
    output_repo_dir = os.path.join(BASE_OUTPUT, repo_id)
    nested_output_repo_dir = os.path.join(output_repo_dir, repo_id)
    artifact_root = nested_output_repo_dir if os.path.isdir(nested_output_repo_dir) else output_repo_dir
    feature_catalog_path = str(core_helpers.feature_catalog_path_for_output(artifact_root))

    if not os.path.exists(feature_catalog_path):
        logger.info("Feature summary skipped: catalog missing path=%s", feature_catalog_path)
        return {"feature_summaries": [], "feature_summary_count": 0, "error": "Feature catalog not found."}

    try:
        with open(feature_catalog_path, "r", encoding="utf-8") as f:
            feature_catalog = json.load(f)
    except Exception as e:
        logger.warning("Unable to load feature catalog for feature summary: %s", e)
        return {"feature_summaries": [], "feature_summary_count": 0, "error": str(e)}

    repo_text_for_seeds = load_repo_text_artifact(output_repo_dir)
    repo_context_for_seeds = build_repo_context(owner, repo, {}, "", repo_text_for_seeds)
    ui_feature_seeds = extract_ui_feature_seeds(repo_text_for_seeds, repo_context_for_seeds)
    if not ui_feature_seeds and isinstance(feature_catalog, dict):
        ui_feature_seeds = feature_catalog.get("ui_feature_seeds", []) or []

    generation_controls = feature_generation_controls(payload)
    feature_name_edits = normalize_feature_name_edits(payload.get("feature_names") or payload.get("features") or [])
    feature_blacklist = generation_controls.get("feature_blacklist") or []
    required_feature_names = generation_controls.get("required_feature_names") or []
    product_name = feature_catalog.get("product_name", "") if isinstance(feature_catalog, dict) else ""
    features = feature_catalog.get("features", []) if isinstance(feature_catalog, dict) else []
    features = ui_first_feature_list(ui_feature_seeds, features, limit=0)
    features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
    features = apply_required_feature_targets(features, required_feature_names)
    features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
    features = rank_feature_candidates(features, MAX_VISIBLE_FEATURE_CANDIDATES)
    total_feature_count = len(features)
    try:
        batch_start = max(0, int(payload.get("feature_summary_start", 0) or 0))
    except (TypeError, ValueError):
        batch_start = 0
    try:
        batch_limit = int(payload.get("feature_summary_limit", 0) or 0)
    except (TypeError, ValueError):
        batch_limit = 0
    batch_limit = max(0, min(batch_limit, 5))
    batch_end = min(total_feature_count, batch_start + batch_limit) if batch_limit else total_feature_count
    requested_features = features[batch_start:batch_end]
    logger.info(
        "Feature summary catalog loaded: owner=%s repo=%s features=%s batch=%s:%s",
        owner,
        repo,
        total_feature_count,
        batch_start,
        batch_end,
    )
    
    summaries, feature_prompt = generate_feature_descriptions(
        requested_features,
        product_name,
        feature_catalog.get("product_type", "") if isinstance(feature_catalog, dict) else "",
        "",
        ui_feature_seeds=ui_feature_seeds,
        return_prompt=True,
    )
    add_feature_reference_urls(summaries, artifact_root)
    existing_summaries = payload.get("feature_summary_existing")
    if not isinstance(existing_summaries, list):
        existing_summaries = []
    if batch_limit:
        merged_summaries = list(existing_summaries)
        if payload.get("feature_summary_merge_by_name"):
            existing_by_key = {
                normalized_feature_key(item.get("feature") or item.get("name") or ""): index
                for index, item in enumerate(merged_summaries)
                if isinstance(item, dict)
            }
            for summary in summaries:
                key = normalized_feature_key(summary.get("feature") or summary.get("name") or "")
                if key and key in existing_by_key:
                    merged_summaries[existing_by_key[key]] = summary
                else:
                    merged_summaries.append(summary)
        else:
            while len(merged_summaries) < batch_start:
                merged_summaries.append({})
            for index, summary in enumerate(summaries):
                target_index = batch_start + index
                if target_index < len(merged_summaries):
                    merged_summaries[target_index] = summary
                else:
                    merged_summaries.append(summary)
        summaries_to_save = [item for item in merged_summaries if isinstance(item, dict) and item.get("description")]
        response_summaries = merged_summaries
    else:
        summaries_to_save = summaries
        response_summaries = summaries
    summary_count = sum(1 for item in summaries_to_save if item.get("description"))
    feature_summary_json_path = ""
    feature_summary_text_path = ""
    if summary_count:
        feature_summary_json_path, feature_summary_text_path = persist_feature_summaries(artifact_root, summaries_to_save)
        try:
            evidence_result = index_typed_scim_evidence(artifact_root)
            write_scim_layer_manifest(Path(artifact_root), evidence_result)
        except Exception as e:
            logger.warning("Unable to index generated feature summaries into SCIM evidence: %s", e)
        try:
            supabase_upload_generated_artifacts_for_latest(
                request,
                owner,
                repo,
                artifact_root,
                [
                    feature_summary_json_path,
                    feature_summary_text_path,
                ],
                fields={
                    "feature_summaries": summaries_to_save,
                    "feature_summary_count": summary_count,
                    "feature_summary_url": output_url(feature_summary_json_path),
                    "features_text_url": output_url(feature_summary_text_path),
                },
            )
        except Exception as e:
            logger.warning("Unable to persist generated feature summaries to Supabase: %s", e)
    derived_memory = {}
    if summary_count:
        try:
            derived_memory = store_derived_answer_memory(
                artifact_root,
                {
                    "query": "Generate feature descriptions",
                    "intent": ["feature_summary"],
                    "retrieval_plan": {"intents": ["feature_summary"], "source_boosts": SCIM_SOURCE_TYPE_GROUPS.get("feature_summary", {})},
                    "retrieved_evidence_ids": feature_summary_evidence_ids(requested_features),
                    "approved": False,
                },
                json.dumps({"features": summaries_to_save}, ensure_ascii=False, indent=2),
                feature_prompt,
            )
            scim_dir = Path(artifact_root) / "scim"
            derived_memory_path = derived_memory.get("memory_path", "") if isinstance(derived_memory, dict) else ""
            generated_store_path = (derived_memory.get("generated_store") or {}).get("path", "") if isinstance(derived_memory, dict) else ""
            derived_memory["supabase_upload"] = supabase_upload_generated_artifacts_for_latest(
                request,
                owner,
                repo,
                artifact_root,
                [
                    feature_summary_json_path,
                    feature_summary_text_path,
                    derived_memory_path,
                    derived_memory_paths(artifact_root)[1],
                    generated_store_path,
                ],
                fields={
                    "feature_summaries": summaries_to_save,
                    "feature_summary_count": summary_count,
                    "feature_summary_url": output_url(feature_summary_json_path),
                    "features_text_url": output_url(feature_summary_text_path),
                },
            )
        except Exception as e:
            logger.warning("Unable to store generated feature summary side effects: %s", e)
            derived_memory = {"error": str(e)}
    logger.info("Feature summary endpoint completed: owner=%s repo=%s summaries=%s", owner, repo, summary_count)
    return {
        "owner": owner,
        "repo": repo,
        "feature_summaries": response_summaries,
        "feature_summary_count": summary_count,
        "feature_summary_batch_count": sum(1 for item in summaries if item.get("description")),
        "feature_summary_start": batch_start,
        "feature_summary_limit": batch_limit,
        "feature_summary_complete": batch_end >= total_feature_count,
        "feature_summary_url": output_url(feature_summary_json_path),
        "features_text_url": output_url(feature_summary_text_path),
        "product_name": product_name,
        "feature_names": feature_name_edits or required_feature_names,
        "feature_blacklist": feature_blacklist,
        "ui_feature_seeds": ui_feature_seeds,
        "feature_catalog": {**feature_catalog, "features": features, "product_name": product_name, "ui_feature_seeds": ui_feature_seeds} if isinstance(feature_catalog, dict) else feature_catalog,
        "feature_count": total_feature_count,
        "derived_memory": derived_memory,
    }


@app.post("/summary")
def summary(request: Request, payload: dict):
    return {
        "summary": "",
        "feature_summaries": [],
        "disabled": True,
        "message": "Derived product and feature summaries are disabled. Use CODE.md and graph artifacts for the deterministic truth index.",
    }
    owner = str(payload.get("owner_name") or payload.get("owner") or "").strip()
    repo = str(payload.get("repo_name") or payload.get("repo") or "").strip()
    if not owner or not repo:
        return {"summary": "", "feature_summaries": [], "error": "owner_name and repo_name are required."}

    repo_id = short_id(owner, repo)
    OUTPUT_REPO_DIR = os.path.join(BASE_OUTPUT, repo_id)
    nested_output_repo_dir = os.path.join(OUTPUT_REPO_DIR, repo_id)
    artifact_root = nested_output_repo_dir if os.path.isdir(nested_output_repo_dir) else OUTPUT_REPO_DIR
    scim_dir = os.path.join(artifact_root, "scim")
    feature_catalog_path = str(core_helpers.feature_catalog_path_for_output(artifact_root))
    repo_comments_path = repo_text_artifact_path(artifact_root, "repo_comments.json", legacy_ok=True)
    repo_text_path = repo_text_artifact_path(artifact_root, "repo_text.json", legacy_ok=True)
    feature_catalog = {}
    repo_comments = {}
    repo_text = {}

    if os.path.exists(feature_catalog_path):
        try:
            with open(feature_catalog_path, "r", encoding="utf-8") as f:
                feature_catalog = json.load(f)
        except Exception as e:
            logger.warning("Unable to load feature catalog for summary: %s", e)

    if os.path.exists(repo_comments_path):
        try:
            with open(repo_comments_path, "r", encoding="utf-8") as f:
                repo_comments = json.load(f)
        except Exception as e:
            logger.warning("Unable to load repo comments for summary: %s", e)

    if os.path.exists(repo_text_path):
        try:
            with open(repo_text_path, "r", encoding="utf-8") as f:
                repo_text = json.load(f)
        except Exception as e:
            logger.warning("Unable to load repo text for summary: %s", e)

    try:
        CALLGRAPH, callgraph_source = load_search_callgraph(OUTPUT_REPO_DIR)
    except Exception as e:
        return {"error": str(e)}

    # Format callgraph for LLM
    callgraph_str = json.dumps(CALLGRAPH, indent=2)

    # If too large, summarize key parts
    if len(callgraph_str) > 10000:
        # Take first 50 and last 50 entries
        summary_cg = CALLGRAPH[:50] + CALLGRAPH[-50:] if len(CALLGRAPH) > 100 else CALLGRAPH
        callgraph_str = json.dumps(summary_cg, indent=2) + f"\n... (truncated, total {len(CALLGRAPH)} entries)"

    generation_controls = feature_generation_controls(payload)
    feature_name_edits = []
    feature_blacklist = generation_controls.get("feature_blacklist") or []
    required_feature_names = generation_controls.get("required_feature_names") or []
    product_name = feature_catalog.get("product_name", "") if isinstance(feature_catalog, dict) else ""
    features = feature_catalog.get("features", []) if isinstance(feature_catalog, dict) else []
    features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
    features = apply_required_feature_targets(features, required_feature_names)
    features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
    features = rank_feature_candidates(features, MAX_VISIBLE_FEATURE_CANDIDATES)
    todos = repo_comments.get("todos", []) if isinstance(repo_comments, dict) else []
    comment_text_items = repo_comments.get("text_items", []) if isinstance(repo_comments, dict) else []
    repo_readme_items = repo_text.get("readme_items", []) if isinstance(repo_text, dict) else []
    repo_document_items = repo_text.get("document_items", []) if isinstance(repo_text, dict) else []
    repo_text_items = repo_text.get("text_items", []) if isinstance(repo_text, dict) else []
    repo_ui_text_items = repo_text.get("ui_text_items", []) if isinstance(repo_text, dict) else []
    compact_features = [
        compact_feature_for_llm(feature, f"feature_{index + 1}")
        for index, feature in enumerate(features[:12])
    ]
    feature_str = json.dumps(compact_features, indent=2)
    todo_str = json.dumps(todos[:20], indent=2)
    text_str = json.dumps(comment_text_items[:20], indent=2)
    repo_text_str = json.dumps(
        {
            "readme_items": repo_readme_items[:8],
            "document_items": repo_document_items[:12],
            "text_items": repo_text_items[:12],
            "ui_text_items": repo_ui_text_items[:16],
        },
        indent=2,
    )

    output_repo_dir = repo_output_dir(owner, repo)
    # ADD before the generate_feature_descriptions call:
    repo_text_for_seeds = load_repo_text_artifact(output_repo_dir)
    repo_context_for_seeds = build_repo_context(owner, repo, {}, "", repo_text_for_seeds)
    ui_feature_seeds = extract_ui_feature_seeds(repo_text_for_seeds, repo_context_for_seeds)
    if ui_feature_seeds:
        features = ui_first_feature_list(ui_feature_seeds, features, limit=0)
        features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
        features = apply_required_feature_targets(features, required_feature_names)
        features = filter_deleted_feature_rows(features, feature_name_edits, feature_blacklist)
        features = rank_feature_candidates(features, MAX_VISIBLE_FEATURE_CANDIDATES)
        compact_features = [
            compact_feature_for_llm(feature, f"feature_{index + 1}")
            for index, feature in enumerate(features[:12])
        ]
        feature_str = json.dumps(compact_features, indent=2)

    feature_descriptions, feature_prompt = generate_feature_descriptions(
        features,
        product_name,
        feature_catalog.get("product_type", "") if isinstance(feature_catalog, dict) else "",
        "",
        ui_feature_seeds=ui_feature_seeds,
        return_prompt=True,
    )
    add_feature_reference_urls(feature_descriptions, artifact_root)
    feature_summary_json_path = ""
    feature_summary_text_path = ""
    if feature_descriptions:
        feature_summary_json_path, feature_summary_text_path = persist_feature_summaries(artifact_root, feature_descriptions)
        try:
            evidence_result = index_typed_scim_evidence(artifact_root)
            write_scim_layer_manifest(Path(artifact_root), evidence_result)
        except Exception as e:
            logger.warning("Unable to index generated product feature summaries into SCIM evidence: %s", e)
        feature_memory = {}
        try:
            scim_dir = Path(artifact_root) / "scim"
            feature_memory = store_derived_answer_memory(
                artifact_root,
                {
                    "query": "Generate feature descriptions",
                    "intent": ["feature_summary"],
                    "retrieval_plan": {"intents": ["feature_summary"], "source_boosts": SCIM_SOURCE_TYPE_GROUPS.get("feature_summary", {})},
                    "retrieved_evidence_ids": feature_summary_evidence_ids(features),
                },
                json.dumps({"features": feature_descriptions}, ensure_ascii=False, indent=2),
                feature_prompt,
            )
            generated_store_path = (feature_memory.get("generated_store") or {}).get("path", "") if isinstance(feature_memory, dict) else ""
            supabase_upload_generated_artifacts_for_latest(
                request,
                owner,
                repo,
                artifact_root,
                [
                    feature_summary_json_path,
                    feature_summary_text_path,
                    feature_memory.get("memory_path", "") if isinstance(feature_memory, dict) else "",
                    derived_memory_paths(artifact_root)[1],
                    generated_store_path,
                ],
                fields={
                    "feature_summaries": feature_descriptions,
                    "feature_summary_count": sum(1 for item in feature_descriptions if item.get("description")),
                    "feature_summary_url": output_url(feature_summary_json_path),
                    "features_text_url": output_url(feature_summary_text_path),
                },
            )
        except Exception as e:
            logger.warning("Unable to upload generated product feature summaries to Supabase: %s", e)
            try:
                supabase_upload_generated_artifacts_for_latest(
                    request,
                    owner,
                    repo,
                    artifact_root,
                    [
                        feature_summary_json_path,
                        feature_summary_text_path,
                    ],
                    fields={
                        "feature_summaries": feature_descriptions,
                        "feature_summary_count": sum(1 for item in feature_descriptions if item.get("description")),
                        "feature_summary_url": output_url(feature_summary_json_path),
                        "features_text_url": output_url(feature_summary_text_path),
                    },
                )
            except Exception as cache_error:
                logger.warning("Unable to cache product feature summary fields in Supabase: %s", cache_error)

    prompt = f"""
Analyze this static code analysis output and provide a comprehensive summary.

Detected feature catalog:
{feature_str}

TODO items:
{todo_str}

Comments/docs/text evidence:
{text_str}

Repository README/docs/text files:
{repo_text_str}

Callgraph data:
{callgraph_str}

Please provide:
1. Product/Project Summary: What does this codebase do?
2. Key Features: Main functionalities based on the detected feature catalog, comments/docs, and graph evidence
3. Scenarios/Use Cases: What workflows are directly supported by the extracted graph
4. Architecture Overview: High-level structure visible in the graph
5. Static Evidence Gaps: What cannot be determined from this graph alone

Be concise. Do not estimate completion percentages, maturity, market position, or competition.
Do not mention feature reachability labels, incomplete signals, or graph gaps unless the user explicitly asks for static-analysis caveats.
"""

    try:
        api_key = os.getenv("OPENAI_API_KEY")
        if not api_key:
            raise ValueError("OPENAI_API_KEY is not set.")

        response = requests.post(
            "https://api.openai.com/v1/chat/completions",
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
            },
            json={
                "model": os.getenv("OPENAI_SUMMARY_MODEL", "gpt-4o-mini"),
                "messages": [{"role": "user", "content": prompt}],
                "max_tokens": 1000,
                "temperature": 0.3,
            },
            timeout=GITHUB_REQUEST_TIMEOUT,
        )
        response.raise_for_status()
        data = response.json()
        summary_text = (data["choices"][0]["message"]["content"] or "").strip()
    except Exception as e:
        summary_text = f"Error generating summary: {str(e)}"

    derived_memory = {}
    if summary_text and not summary_text.startswith("Error generating summary"):
        try:
            scim_dir = Path(artifact_root) / "scim"
            derived_memory = store_derived_answer_memory(
                artifact_root,
                {
                    "query": "Generate product/project summary",
                    "intent": ["repo_overview", "feature_summary", "function_flow"],
                    "retrieval_plan": {
                        "intents": ["repo_overview", "feature_summary", "function_flow"],
                        "source_boosts": {
                            **SCIM_SOURCE_TYPE_GROUPS.get("repo_overview", {}),
                            **SCIM_SOURCE_TYPE_GROUPS.get("feature_summary", {}),
                            **SCIM_SOURCE_TYPE_GROUPS.get("function_flow", {}),
                        },
                    },
                    "retrieved_evidence_ids": product_summary_evidence_ids(features, todos, comment_text_items, len(CALLGRAPH)),
                },
                summary_text,
                prompt,
            )
            generated_store_path = (derived_memory.get("generated_store") or {}).get("path", "") if isinstance(derived_memory, dict) else ""
            derived_memory["supabase_upload"] = supabase_upload_generated_artifacts_for_latest(
                request,
                owner,
                repo,
                artifact_root,
                [
                    derived_memory.get("memory_path", "") if isinstance(derived_memory, dict) else "",
                    derived_memory_paths(artifact_root)[1],
                    generated_store_path,
                ],
                fields={
                    "summary": summary_text,
                    "feature_summaries": feature_descriptions,
                    "feature_summary_count": sum(1 for item in feature_descriptions if item.get("description")),
                    "feature_summary_url": output_url(feature_summary_json_path),
                    "features_text_url": output_url(feature_summary_text_path),
                },
            )
        except Exception as e:
            logger.warning("Unable to upload generated product summary memory to Supabase: %s", e)
            derived_memory = {"error": str(e)}
            try:
                supabase_upload_generated_artifacts_for_latest(
                    request,
                    owner,
                    repo,
                    artifact_root,
                    [],
                    fields={
                        "summary": summary_text,
                        "feature_summaries": feature_descriptions,
                        "feature_summary_count": sum(1 for item in feature_descriptions if item.get("description")),
                        "feature_summary_url": output_url(feature_summary_json_path),
                        "features_text_url": output_url(feature_summary_text_path),
                    },
                )
            except Exception as cache_error:
                logger.warning("Unable to cache product summary fields in Supabase: %s", cache_error)

    return {
        "owner": owner,
        "repo": repo,
        "summary": summary_text,
        "feature_summaries": feature_descriptions,
        "feature_summary_count": sum(1 for item in feature_descriptions if item.get("description")),
        "feature_summary_url": output_url(feature_summary_json_path),
        "features_text_url": output_url(feature_summary_text_path),
        "product_name": product_name,
        "feature_blacklist": feature_blacklist,
        "ui_feature_seeds": ui_feature_seeds,
        "feature_catalog": {
            "features": features,
            "product_name": product_name,
            "product_type": feature_catalog.get("product_type", "") if isinstance(feature_catalog, dict) else "",
            "ui_feature_seeds": ui_feature_seeds,
        },
        "feature_count": len(features),
        "todo_count": len(todos),
        "text_count": len(comment_text_items),
        "repo_text_count": repo_text.get("item_count", 0) if isinstance(repo_text, dict) else 0,
        "callgraph_entries": len(CALLGRAPH),
        "derived_memory": derived_memory,
    }

















def search_functions(query, FUNCTIONS):
    q = query.lower()
    return [
        fn for fn in FUNCTIONS
        if q in fn["name"].lower() or q in fn["fullName"].lower()
    ]

def search_callgraph(fullname, CALLGRAPH):
    callers = [e["caller"] for e in CALLGRAPH if e["callee"] == fullname]
    callees = [e["callee"] for e in CALLGRAPH if e["caller"] == fullname]
    return callers, callees


def process_ordered_ast(repo_dir, ordered_ast_path):
    import json
    import os

    with open(ordered_ast_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    # Save a normalized version for downstream tools
    normalized_path = os.path.join(repo_dir, "ordered_calls_normalized.json")

    normalized = []

    for entry in data:
        method = entry.get("method")
        file = entry.get("file")
        calls = entry.get("calls", [])

        for c in calls:
            normalized.append({
                "method": method,
                "file": file,
                "call_code": c.get("call_code"),
                "call_name": c.get("call_name"),
                "callee_fullName": c.get("callee_fullName"),
                "line": c.get("line"),
                "order": int(c.get("order", 0))
            })

    with open(normalized_path, "w", encoding="utf-8") as f:
        json.dump(normalized, f, indent=2)

    print("Normalized ordered AST written to:", normalized_path)



def fetch_repo_info(owner: str, repo: str, token: str):
    """
    Fetch metadata for a GitHub repo.
    Returns (repo_info_json, default_branch) or raises an exception.
    """
    headers = github_headers(token)
    url = f"https://api.github.com/repos/{owner}/{repo}"
    resp = requests.get(url, headers=headers, timeout=GITHUB_REQUEST_TIMEOUT)
    token_configured = bool(normalize_github_token(token))
    auth_failure_detail = ""
    if token_configured and resp.status_code in (401, 403):
        try:
            auth_message = resp.json().get("message", "")
        except Exception:
            auth_message = resp.text[:160]
        auth_failure_detail = f"Authenticated request returned {resp.status_code}"
        if auth_message:
            auth_failure_detail = f"{auth_failure_detail}: {auth_message}"
        logger.warning(
            "GitHub repo metadata request failed with auth for %s/%s: status=%s message=%s",
            owner,
            repo,
            resp.status_code,
            auth_message,
        )

    if resp.status_code != 200:
        response_message = ""
        try:
            response_message = resp.json().get("message", "")
        except Exception:
            response_message = resp.text[:160]
        logger.warning(
            "GitHub repo metadata request failed for %s/%s: status=%s token_configured=%s message=%s",
            owner,
            repo,
            resp.status_code,
            token_configured,
            response_message,
        )
        detail = f"GitHub returned {resp.status_code}"
        if response_message:
            detail = f"{detail}: {response_message}"
        if resp.status_code == 403 and "rate limit" in response_message.lower():
            token_note = (
                f" {auth_failure_detail}."
                if auth_failure_detail
                else " The request was unauthenticated because GITHUB_TOKEN is not visible to this server process."
            )
            raise ValueError(f"GitHub API rate limit exceeded while checking {owner}/{repo} ({detail}).{token_note} Set a valid GITHUB_TOKEN in the server environment and restart the app.")
        if resp.status_code == 401 and token_configured:
            raise ValueError(f"GitHub token was rejected while checking {owner}/{repo} ({detail}). Update GITHUB_TOKEN and restart the app.")
        if auth_failure_detail:
            detail = f"{detail}; {auth_failure_detail}"
        raise ValueError(f"Repo not found or inaccessible: {owner}/{repo} ({detail})")

    data = resp.json()
    default_branch = data.get("default_branch", "main")
    logger.info(
        "GitHub repo metadata fetched for %s/%s: default_branch=%s size=%s stars=%s",
        owner,
        repo,
        default_branch,
        data.get("size"),
        data.get("stargazers_count"),
    )

    return data, default_branch



def visualize_callgraph_pycg(json_path, html_out="callgraph_pycg.html"):
    with open(json_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    edges = data.get("edges", [])

    net = Network(height="900px", width="100%", directed=True)

    # ⭐ The ONLY reliable way to prevent overlap:
    # Enable physics briefly → avoidOverlap → stabilize → freeze
    net.set_options("""
    {
      "physics": {
        "enabled": true,
        "solver": "forceAtlas2Based",
        "forceAtlas2Based": {
          "avoidOverlap": 1,
          "springLength": 1000,
          "springConstant": 0.0001
        },
        "centralGravity": 0.0,
        "gravity": -1000,
        "stabilization": {
          "enabled": true,
          "iterations": 10
        }
      },
      "layout": {
        "improvedLayout": true
      },
      "nodes": {
        "shape": "dot",
        "size": 8,
        "font": { "size": 15 }
      },
      "edges": {
        "width": 0.5,
        "arrows": { "to": { "enabled": true, "scaleFactor": 0.4 } },
        "smooth": false
      }
    }
    """)

    # Build node set from edges
    nodes = set()
    for caller, callee in edges:
        nodes.add(caller)
        nodes.add(callee)

    # Add nodes
    for n in nodes:
        net.add_node(n, label=n)

    # Add edges
    for caller, callee in edges:
        net.add_edge(caller, callee)

    # Write HTML (no browser open)
    net.write_html(html_out)
    return html_out




def make_json_safe(obj):
    if isinstance(obj, dict):
        return {k: make_json_safe(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [make_json_safe(v) for v in obj]
    if isinstance(obj, set):
        return [make_json_safe(v) for v in obj]
    return obj

"""
Run PyCG on a single entry file and write callgraph JSON.
Parameters
----------
entry_file : Path
    The Python entry file to analyze.
output_json : Path
    Where to write the callgraph JSON.
max_iter : int
    Max iterations for the analysis (PyCG param).
operation : str
    Operation mode for PyCG, usually 'callgraph' or 'cg'.
package : Optional[str]
    Optional package root for PyCG.
Returns
-------
Path
    The path to the generated JSON file.
"""

from collections import defaultdict  # used but not imported
import json                           # used but not imported
from pathlib import Path              # used but not imported

from parsers.python.python_analyzer import (
    PythonAnalyzer
)

def run_pycg(
    repo_root,
    output_json,
):

    """
    Run the unified Python analysis pipeline.

    Uses:
    - AST metadata extraction
    - PyCG semantic analysis
    - merged function graph
    - file graph
    - per-file graphs
    """

    repo_root = Path(repo_root).resolve()

    output_path = Path(output_json).resolve()

    output_path.parent.mkdir(
        parents=True,
        exist_ok=True
    )

    # =====================================================
    # RUN ANALYZER
    # =====================================================

    analyzer = PythonAnalyzer(
        repo_root
    )

    results = analyzer.analyze()

    function_graph = results["function_graph"]
    file_graph = results["file_graph"]
    per_file_graphs = results["per_file_graphs"]
    symbol_index = results["symbol_index"]

    def normalize_python_graph_symbol(symbol):
        return str(symbol or "").replace("\\", ".").replace("/", ".").strip(".")

    function_symbols = {
        normalize_python_graph_symbol(symbol)
        for symbol, metadata in symbol_index.items()
        if isinstance(metadata, dict) and metadata.get("type") == "function"
    } | {
        normalize_python_graph_symbol(node)
        for node in function_graph.nodes()
    }

    logger.debug("pycg nodes sample: %s", list(function_graph.nodes())[:5])
    logger.debug("AST symbols sample: %s", list(function_symbols)[:5])
    logger.debug("function_graph edges: %d", function_graph.number_of_edges())
    logger.debug("function_symbols count: %d", len(function_symbols))

    suffix_index = defaultdict(set)
    for function_symbol in function_symbols:
        parts = function_symbol.split(".")
        for width in range(2, min(len(parts), 6) + 1):
            suffix_index[".".join(parts[-width:])].add(function_symbol)

    def resolve_python_graph_symbol(symbol):
        normalized = normalize_python_graph_symbol(symbol)
        if normalized in function_symbols:
            return normalized
        parts = normalized.split(".")
        for width in range(min(len(parts), 6), 1, -1):
            matches = suffix_index.get(".".join(parts[-width:]), set())
            if len(matches) == 1:
                return next(iter(matches))
        return normalized

    function_files = {}
    node_metadata = {}
    for symbol, metadata in symbol_index.items():
        if not isinstance(metadata, dict):
            continue
        normalized_symbol = normalize_python_graph_symbol(symbol)
        file_path = str(metadata.get("file") or "")
        try:
            file_path = str(Path(file_path).resolve().relative_to(repo_root)).replace("\\", "/")
        except Exception:
            file_path = file_path.replace("\\", "/")
        if metadata.get("type") == "function":
            function_files[normalized_symbol] = file_path
        node_metadata[normalized_symbol] = {
            **metadata,
            "file": file_path,
        }

    edges = []
    ordered_calls = []
    for order, (src, dst) in enumerate(function_graph.edges(), start=1):
        src = resolve_python_graph_symbol(src)
        dst = resolve_python_graph_symbol(dst)
        
        # TODO - uncomment this - testing only
        # if function_symbols and (src not in function_symbols or dst not in function_symbols):
        #    continue
        
        if src == dst:
            continue
        edges.append([src, dst])
        ordered_calls.append({
            "caller": src,
            "callee": dst,
            "file": function_files.get(src, ""),
            "line": node_metadata.get(src, {}).get("lineno"),
            "order": order,
            "call_text": dst.rsplit(".", 1)[-1],
        })

    nodes = sorted(function_symbols or [normalize_python_graph_symbol(node) for node in function_graph.nodes()])
    connected = {node for edge in edges for node in edge[:2]}
    if connected:
        nodes = sorted(set(nodes) | connected)
    fallback_reason = ""
    
    if function_symbols and not edges and function_graph.number_of_edges() > 0:
        fallback_reason = (
            "Python semantic analyzer produced raw edges but none resolved to repository "
            "function symbols; falling back to AST parser."
        )
    elif function_symbols and len(function_symbols) > 1 and not edges:
        fallback_reason = "Python semantic analyzer produced no resolved edges; falling back to AST parser."
    if fallback_reason:
        raise RuntimeError(fallback_reason)

    payload = {
        "mode": "python_semantic",
        "parser": "python-analyzer-pycg",
        "version": 3,
        "nodes": nodes,
        "edges": edges,
        "ordered_calls": ordered_calls,
        "function_files": function_files,
        "node_metadata": node_metadata,
        "raw_node_count": function_graph.number_of_nodes(),
        "raw_edge_count": function_graph.number_of_edges(),
        "resolved_call_count": len(edges),
        "file_graph": {
            "nodes": sorted(str(node).replace("\\", "/") for node in file_graph.nodes()),
            "edges": [[str(src).replace("\\", "/"), str(dst).replace("\\", "/")] for src, dst in file_graph.edges()],
        },
        "per_file_graphs": {
            str(path).replace("\\", "/"): {
                "nodes": sorted(normalize_python_graph_symbol(node) for node in graph.nodes()),
                "edges": [[normalize_python_graph_symbol(src), normalize_python_graph_symbol(dst)] for src, dst in graph.edges()],
            }
            for path, graph in per_file_graphs.items()
        },
        "symbol_index": symbol_index,
    }
    with output_path.open(
        "w",
        encoding="utf-8"
    ) as f:

        json.dump(
            payload,
            f,
            indent=2
        )
    ordered_path = output_path.with_name("python_ordered_call_sequence.json")
    write_ordered_call_sequence(
        ordered_calls,
        str(ordered_path),
        parser="python-analyzer-pycg",
        source_callgraph=output_path.name,
    )

    # TODO - remove this - testing only
    # print(f"[DEBUG] py_files count: {len(py_files)}") # ← crashes here

    # REPLACE with this if you want the file count:
    #print(f"[DEBUG] py_files count: {len(list(repo_root.rglob('*.py')))}")
    
    #print(f"[DEBUG] function_graph edges: {function_graph.number_of_edges()}")
    #print(f"[DEBUG] function_graph nodes: {function_graph.number_of_nodes()}")
    #print(f"[DEBUG] function_symbols count: {len(function_symbols)}")
    #print(f"[DEBUG] edges after filter: {len(edges)}")

    # Then in run_pycg:
    #print(f"[DEBUG] py_files count: {results['py_file_count']}")

    return output_path



def build_cytoscape_html(json_path, html_out_path):
    logger.info("Building Cytoscape HTML: json=%s html=%s", json_path, html_out_path)
    logger.debug("Loading Cytoscape template from %s", CYTOSCAPE_TEMPLATE_HTML_PATH)

    # Load template
    with open(CYTOSCAPE_TEMPLATE_HTML_PATH, "r") as f:
        html = f.read()

    #breakpoint()

    # Compute path relative to the /output mount.
    relative_to_output = os.path.relpath(json_path, BASE_OUTPUT)
    relative_to_output = relative_to_output.replace("\\", "/")

    with open(json_path, "r", encoding="utf-8") as f:
        graph_data = json.load(f)

    # Inject correct URL and embedded fallback data
    html = html.replace("__JSON_PATH__", f"{OUTPUT_URL_PREFIX}/{relative_to_output}")
    html = html.replace("__GRAPH_TITLE__", str(graph_data.get("title") or "Graph") if isinstance(graph_data, dict) else "Graph")
    html = html.replace("__GRAPH_DATA__", json.dumps(graph_data, separators=(",", ":")))

    # Write final HTML
    with open(html_out_path, "w") as f:
        f.write(html)

    logger.info("Cytoscape HTML written: %s", html_out_path)

    output_relative_html_path = os.path.relpath(html_out_path, BASE_OUTPUT).replace("\\", "/")

    #return html_out

    return f'{OUTPUT_URL_PREFIX}/{output_relative_html_path}'











def build_javalang_callgraph(repo_src, output_dir, progress_callback=None):
    import os, json
    import javalang

    INCLUDE_ISOLATED_FUNCTIONS_LIMIT = 150
    edges = set()
    user_methods = set()
    parse_errors = []
    parse_error_keys = set()
    java_files = []
    for root, _, files in os.walk(repo_src):
        for f in files:
            if f.endswith(".java"):
                java_files.append(os.path.join(root, f))
    java_files.sort()
    total_files = len(java_files)

    def progress(message, current_file=None):
        if progress_callback:
            try:
                progress_callback(message, current_file=current_file)
            except TypeError:
                progress_callback(message)

    def append_parse_errors(items):
        for item in items:
            key = (
                item.get("file"),
                item.get("error_type"),
                item.get("line"),
                item.get("column"),
                item.get("message"),
            )
            if key in parse_error_keys:
                continue
            parse_error_keys.add(key)
            parse_errors.append(item)

    def parse_java_file(text, path):
        errors = []
        tree = safe_parse(text, path, repo_src=repo_src, parse_errors=errors)
        append_parse_errors(errors)
        return tree

    progress(f"Collecting Java methods from {total_files} files...")
    # -----------------------------------------
    # PASS 1 — Collect all user-defined methods
    # -----------------------------------------
    for index, path in enumerate(java_files, start=1):
        rel_path = os.path.relpath(path, repo_src)
        progress(f"Collecting Java methods from file {index}/{total_files}.", current_file=rel_path)
        with open(path, "r", encoding="utf-8", errors="ignore") as fh:
            text = fh.read()

        tree = parse_java_file(text, path)
        if tree is None:
            continue

        def class_prefix(path_nodes, class_name):
            names = [
                p.name for p in path_nodes
                if isinstance(p, javalang.tree.ClassDeclaration)
            ]
            names.append(class_name)
            return ".".join(names)

        # Class methods
        for _, node in tree.filter(javalang.tree.ClassDeclaration):
            class_name = class_prefix(_, node.name)
            for method in node.methods:
                if method.name:  # only add valid names
                    user_methods.add(f"{class_name}.{method.name}")
            for constructor in node.constructors:
                user_methods.add(f"{class_name}.<init>")

        # Top-level methods (rare)
        for path2, method in tree.filter(javalang.tree.MethodDeclaration):
            if not isinstance(path2[-2], javalang.tree.ClassDeclaration) and method.name:
                user_methods.add(method.name)

    progress(f"Resolving Java call relationships across {len(user_methods)} methods...")
    # -----------------------------------------
    # PASS 2 — Collect edges between user methods
    # -----------------------------------------
    for index, path in enumerate(java_files, start=1):
        rel_path = os.path.relpath(path, repo_src)
        progress(f"Resolving Java calls from file {index}/{total_files}.", current_file=rel_path)
        with open(path, "r", encoding="utf-8", errors="ignore") as fh:
            text = fh.read()

        tree = parse_java_file(text, path)
        if tree is None:
            continue

        # CLASS METHODS
        for _, node in tree.filter(javalang.tree.ClassDeclaration):
            class_name = ".".join(
                [
                    p.name for p in _
                    if isinstance(p, javalang.tree.ClassDeclaration)
                ] + [node.name]
            )

            for constructor in node.constructors:
                caller = f"{class_name}.<init>"
                for _, call in constructor.filter(javalang.tree.MethodInvocation):
                    callee = call.member
                    if not callee:
                        continue
                    same_class = f"{class_name}.{callee}"
                    if same_class in user_methods:
                        edges.add((caller, same_class))

            for method in node.methods:
                if not method.name:
                    continue
                caller = f"{class_name}.{method.name}"

                # Walk the AST inside the method
                for _, call in method.filter(javalang.tree.MethodInvocation):
                    callee = call.member
                    if not callee:
                        continue
                    target = None

                    # Skip trivial self-recursion
                    if callee == method.name:
                        continue

                    # 1. Same-class call
                    same_class = f"{class_name}.{callee}"
                    if same_class in user_methods:
                        target = same_class

                    # 2. Qualifier-based resolution. Only resolve when the
                    # qualifier names a known class/type. Do not guess from a
                    # variable name or a repo-wide simple method name.
                    elif call.qualifier:
                        q = call.qualifier
                        guesses = [
                            f"{q}.{callee}",
                            f"{class_name.rsplit('.', 1)[0]}.{q}.{callee}" if "." in class_name else "",
                        ]
                        for g in guesses:
                            if g in user_methods:
                                target = g
                                break

                    # Add edge if valid
                    if target and caller != target:
                        edges.add((caller, target))

        # TOP-LEVEL METHODS
        for path2, method in tree.filter(javalang.tree.MethodDeclaration):
            if len(path2) < 2 or not isinstance(path2[-2], javalang.tree.ClassDeclaration):
                if not method.name:
                    continue
                caller = method.name

                for _, call in method.filter(javalang.tree.MethodInvocation):
                    callee = call.member
                    if not callee:
                        continue

                    same_scope = f"{caller.rsplit('.', 1)[0]}.{callee}" if "." in caller else callee
                    if same_scope in user_methods and same_scope != caller:
                        edges.add((caller, same_scope))

    # -----------------------------------------
    # Write compact JSON
    # -----------------------------------------
    os.makedirs(output_dir, exist_ok=True)
    out = os.path.join(output_dir, "javalang_callgraph.json")

    # Convert to list of lists of strings, skip None
    clean_edges = [[str(s), str(t)] for s, t in edges if s and t]
    connected_nodes = {node for edge in clean_edges for node in edge[:2]}
    include_isolated = len(user_methods) <= INCLUDE_ISOLATED_FUNCTIONS_LIMIT
    graph = {
        "mode": "all_user_functions" if include_isolated else "connected_user_functions",
        "node_count_total": len(user_methods),
        "node_limit_for_isolated": INCLUDE_ISOLATED_FUNCTIONS_LIMIT,
        "nodes": sorted(user_methods if include_isolated else connected_nodes),
        "edges": clean_edges,
        "parse_errors": parse_errors[:50],
        "parse_error_count": len(parse_errors),
    }
    with open(out, "w", encoding="utf-8") as f:
        json.dump(graph, f, separators=(",", ":"))

    ordered_out = os.path.join(output_dir, "javalang_ordered_call_sequence.json")
    write_ordered_sequence_from_edges(
        edges,
        ordered_out,
        parser="javalang",
        source_callgraph=os.path.basename(out),
    )

    logger.info(
        "Minimal user-only callgraph written: %s methods=%s edges=%s mode=%s parse_errors=%s",
        out,
        len(user_methods),
        len(clean_edges),
        graph["mode"],
        len(parse_errors),
    )

    return out


def _node_text(source_bytes, node):
    if not node:
        return ""
    return source_bytes[node.start_byte:node.end_byte].decode("utf-8", errors="ignore")


def _node_name(source_bytes, node):
    if not node:
        return ""
    name_node = node.child_by_field_name("name")
    if name_node:
        return _node_text(source_bytes, name_node)
    for child in node.children:
        if child.type in {"identifier", "type_identifier"}:
            return _node_text(source_bytes, child)
    return ""


def _node_start_line(node):
    point = node.start_point
    row = getattr(point, "row", None)
    if row is None:
        row = point[0]
    return row + 1


def _first_descendant(node, node_types):
    stack = list(node.children)
    while stack:
        current = stack.pop()
        if current.type in node_types:
            return current
        stack.extend(reversed(current.children))
    return None


def _java_package_name(source_bytes, root):
    package_node = _first_descendant(root, {"package_declaration"})
    if not package_node:
        return ""
    scoped = _first_descendant(package_node, {"scoped_identifier", "identifier"})
    return _node_text(source_bytes, scoped)


def _java_type_name(source_bytes, node):
    type_node = node.child_by_field_name("type")
    if type_node:
        scoped = _first_descendant(type_node, {"scoped_type_identifier", "type_identifier", "identifier"})
        return _node_text(source_bytes, scoped or type_node).split("<", 1)[0].strip()
    return ""


def _tree_sitter_java_language():
    from tree_sitter import Language, Parser
    import tree_sitter_java

    language_fn = getattr(tree_sitter_java, "language", None)
    if not language_fn:
        raise RuntimeError("tree_sitter_java.language() is unavailable")

    language = Language(language_fn())
    parser = Parser()
    if hasattr(parser, "set_language"):
        parser.set_language(language)
    else:
        parser.language = language
    return parser


def build_tree_sitter_java_callgraph(repo_src, output_dir):
    parser = _tree_sitter_java_language()
    class_types = {
        "class_declaration",
        "interface_declaration",
        "enum_declaration",
        "record_declaration",
        "annotation_type_declaration",
    }
    method_types = {"method_declaration", "constructor_declaration"}
    call_types = {
        "method_invocation",
        "object_creation_expression",
        "explicit_constructor_invocation",
    }
    include_isolated_limit = 150
    user_methods = set()
    method_files = {}
    raw_calls = []
    parse_error_count = 0
    parse_errors = []
    recovered_error_samples = []
    files_seen = 0

    def class_full_name(package_name, class_stack):
        pieces = ([package_name] if package_name else []) + class_stack
        return ".".join(part for part in pieces if part)

    def resolve_call_name(source_bytes, call_node):
        if call_node.type == "method_invocation":
            name = _node_name(source_bytes, call_node)
            qualifier_node = (
                call_node.child_by_field_name("object")
                or call_node.child_by_field_name("type")
                or call_node.child_by_field_name("qualifier")
            )
            qualifier = _node_text(source_bytes, qualifier_node).strip() if qualifier_node else ""
            return f"{qualifier}.{name}" if qualifier and name else name
        if call_node.type == "object_creation_expression":
            type_name = _java_type_name(source_bytes, call_node)
            return f"{type_name}.<init>" if type_name else ""
        if call_node.type == "explicit_constructor_invocation":
            return "<init>"
        return ""

    def walk(source_bytes, node, package_name, class_stack, rel_path, current_method=None):
        next_class_stack = class_stack
        next_method = current_method

        if node.type in class_types:
            name = _node_name(source_bytes, node)
            if name:
                next_class_stack = class_stack + [name]

        if node.type in method_types:
            method_name = _node_name(source_bytes, node)
            if node.type == "constructor_declaration":
                method_name = "<init>"
            owner = class_full_name(package_name, next_class_stack)
            full_name = f"{owner}.{method_name}" if owner else method_name
            if method_name:
                user_methods.add(full_name)
                method_files[full_name] = rel_path
                next_method = {
                    "full_name": full_name,
                    "method_name": method_name,
                    "class_name": owner,
                    "file": rel_path,
                }

        if current_method and node.type in call_types:
            callee = resolve_call_name(source_bytes, node)
            if callee:
                raw_calls.append({
                    "caller": current_method["full_name"],
                    "caller_method": current_method["method_name"],
                    "caller_class": current_method["class_name"],
                    "caller_file": current_method["file"],
                    "callee": callee,
                    "line": _node_start_line(node),
                    "column": getattr(node, "start_point", [None, None])[1] if getattr(node, "start_point", None) else None,
                    "call_text": _node_text(source_bytes, node)[:300],
                })

        for child in node.children:
            walk(source_bytes, child, package_name, next_class_stack, rel_path, next_method)

    for path in iter_supported_repo_files(repo_src, {".java"}):
            files_seen += 1
            with open(path, "rb") as fh:
                source_bytes = fh.read()
            rel_path = os.path.relpath(path, repo_src).replace("\\", "/")
            tree = parser.parse(source_bytes)
            if tree.root_node.has_error:
                parse_error_count += 1
                if len(parse_errors) < 50:
                    parse_errors.append({
                        "file": rel_path,
                        "error_type": "syntax_error",
                        "language": "java",
                        "parser": "tree-sitter-java",
                        "line": None,
                        "column": None,
                        "message": "tree-sitter recovered syntax error while parsing file",
                    })
                if len(recovered_error_samples) < 5:
                    recovered_error_samples.append(rel_path)
            package_name = _java_package_name(source_bytes, tree.root_node)
            walk(source_bytes, tree.root_node, package_name, [], rel_path)

    edges = set()
    ordered_calls = []
    class_method_index = defaultdict(set)
    simple_class_index = defaultdict(set)
    for method in user_methods:
        owner, _, method_name = method.rpartition(".")
        if owner:
            class_method_index[(owner, method_name)].add(method)
            simple_class_index[owner.rsplit(".", 1)[-1]].add(owner)

    def unique_match(matches):
        return next(iter(matches)) if len(matches) == 1 else None

    for call in raw_calls:
        callee = call["callee"]
        if callee == call["caller_method"]:
            continue

        target = None
        if callee == "<init>":
            same_class_init = f"{call['caller_class']}.<init>"
            if same_class_init in user_methods:
                target = same_class_init
        elif callee.endswith(".<init>"):
            type_name = callee.rsplit(".", 1)[0]
            owner = unique_match(simple_class_index.get(type_name, set())) or type_name
            target = unique_match(class_method_index.get((owner, "<init>"), set()))
        else:
            qualifier = ""
            method_name = callee
            if "." in callee:
                qualifier, method_name = callee.rsplit(".", 1)
            same_class = f"{call['caller_class']}.{method_name}"
            if same_class in user_methods:
                target = same_class
            elif qualifier and qualifier[:1].isupper():
                owner = unique_match(simple_class_index.get(qualifier, set())) or qualifier
                target = unique_match(class_method_index.get((owner, method_name), set()))

        if target and target != call["caller"]:
            edges.add((call["caller"], target))
            ordered_calls.append({
                "caller": call["caller"],
                "callee": target,
                "file": call.get("caller_file", ""),
                "line": call.get("line"),
                "column": call.get("column"),
                "order": len(ordered_calls) + 1,
                "call_text": call.get("call_text", ""),
            })

    clean_edges = [[str(src), str(dst)] for src, dst in sorted(edges)]
    connected_nodes = {node for edge in clean_edges for node in edge[:2]}
    include_isolated = len(user_methods) <= include_isolated_limit
    graph = {
        "mode": "tree_sitter_all_user_functions" if include_isolated else "tree_sitter_connected_user_functions",
        "parser": "tree-sitter-java",
        "files_seen": files_seen,
        "parse_error_count": parse_error_count,
        "parse_errors": parse_errors,
        "node_count_total": len(user_methods),
        "node_limit_for_isolated": include_isolated_limit,
        "function_files": method_files,
        "nodes": sorted(user_methods if include_isolated else connected_nodes),
        "edges": clean_edges,
    }

    os.makedirs(output_dir, exist_ok=True)
    out = os.path.join(output_dir, "tree_sitter_java_callgraph.json")
    with open(out, "w", encoding="utf-8") as f:
        json.dump(graph, f, separators=(",", ":"))

    ordered_out = os.path.join(output_dir, "tree_sitter_java_ordered_call_sequence.json")
    write_ordered_call_sequence(
        ordered_calls,
        ordered_out,
        parser="tree-sitter-java",
        source_callgraph=os.path.basename(out),
    )

    logger.info(
        "Tree-sitter Java graph written: %s files=%s methods=%s edges=%s recovered_errors=%s",
        out,
        files_seen,
        len(user_methods),
        len(clean_edges),
        parse_error_count,
    )
    if parse_error_count:
        logger.info(
            "Tree-sitter Java recovered syntax errors in %s/%s files; graph generation continued. Sample files: %s",
            parse_error_count,
            files_seen,
            ", ".join(recovered_error_samples),
        )
    return out


TREE_SITTER_JAVA_TIMEOUT_SECONDS = int(os.getenv("CODEVAL_TREE_SITTER_JAVA_TIMEOUT_SECONDS", "90") or 90)


def _tree_sitter_java_worker(repo_src, output_dir, result_queue):
    try:
        graph_path = build_tree_sitter_java_callgraph(repo_src, output_dir)
        ordered_path = os.path.join(output_dir, "tree_sitter_java_ordered_call_sequence.json")
        result_queue.put({
            "ok": True,
            "graph_path": graph_path,
            "ordered_path": ordered_path if os.path.exists(ordered_path) else "",
        })
    except BaseException as exc:
        result_queue.put({
            "ok": False,
            "error": f"{type(exc).__name__}: {exc}",
        })


def run_tree_sitter_java_callgraph_isolated(repo_src, output_dir, timeout_seconds=None):
    timeout_seconds = timeout_seconds or TREE_SITTER_JAVA_TIMEOUT_SECONDS
    result_queue = multiprocessing.Queue(maxsize=1)
    process = multiprocessing.Process(
        target=_tree_sitter_java_worker,
        args=(repo_src, output_dir, result_queue),
        name="codeval-tree-sitter-java",
    )
    process.start()
    process.join(timeout_seconds)

    if process.is_alive():
        process.terminate()
        process.join(5)
        if process.is_alive():
            process.kill()
            process.join(5)
        result_queue.close()
        result_queue.join_thread()
        raise TimeoutError(f"tree-sitter Java analysis timed out after {timeout_seconds}s")

    try:
        result = result_queue.get(timeout=2)
    except queue.Empty:
        exit_code = process.exitcode
        raise RuntimeError(f"tree-sitter Java analysis worker exited without a result (exit code {exit_code})")
    finally:
        result_queue.close()
        result_queue.join_thread()

    if process.exitcode not in (0, None):
        raise RuntimeError(f"tree-sitter Java analysis worker exited with code {process.exitcode}")
    if not result.get("ok"):
        raise RuntimeError(result.get("error") or "tree-sitter Java analysis failed")
    return result


JS_SOURCE_EXTENSIONS = {".js", ".jsx", ".ts", ".tsx", ".mjs", ".cjs"}
JS_MAX_TREE_SITTER_PARSE_BYTES = int(os.getenv("CODEVAL_JS_MAX_PARSE_BYTES", "1500000"))
JS_TREE_SITTER_ENABLED = os.getenv("CODEVAL_JS_TREE_SITTER", "").strip().lower() in {"1", "true", "yes", "on"}
JS_TOOLING_CONFIG_FILENAMES = {
    ".eslintrc.js",
    ".eslintrc.cjs",
    ".eslintrc.mjs",
    ".prettierrc.js",
    ".prettierrc.cjs",
    ".prettierrc.mjs",
}
JS_RESERVED_CALLS = {
    "if", "for", "while", "switch", "catch", "function", "return", "typeof",
    "new", "class", "import", "export", "await", "yield", "else", "do",
}


def is_js_tooling_config_file(path):
    return os.path.basename(str(path or "")).lower() in JS_TOOLING_CONFIG_FILENAMES


def is_large_js_source_file(path):
    try:
        return os.path.getsize(path) > JS_MAX_TREE_SITTER_PARSE_BYTES
    except OSError:
        return False


def collect_javascript_callgraph_source_paths(repo_src):
    source_paths = []
    skipped_large = []
    for path in iter_supported_repo_files(repo_src, JS_SOURCE_EXTENSIONS):
        if is_js_tooling_config_file(path):
            continue
        if is_large_js_source_file(path):
            skipped_large.append(path)
            continue
        source_paths.append(path)
    if skipped_large:
        logger.info(
            "Skipping %s oversized JavaScript/TypeScript files over %s bytes. Sample: %s",
            len(skipped_large),
            JS_MAX_TREE_SITTER_PARSE_BYTES,
            ", ".join(os.path.relpath(path, repo_src).replace("\\", "/") for path in skipped_large[:5]),
        )
    return source_paths, skipped_large


def js_module_name_for(path, repo_src):
    rel = os.path.relpath(path, repo_src).replace("\\", "/")
    return os.path.splitext(rel)[0].replace("/", ".")


def mask_js_non_code(source: str):
    chars = list(source)
    i = 0
    state = "code"
    quote = ""
    while i < len(chars):
        ch = chars[i]
        nxt = chars[i + 1] if i + 1 < len(chars) else ""
        if state == "code":
            if ch == "/" and nxt == "/":
                chars[i] = chars[i + 1] = " "
                i += 2
                while i < len(chars) and chars[i] != "\n":
                    chars[i] = " "
                    i += 1
                continue
            if ch == "/" and nxt == "*":
                chars[i] = chars[i + 1] = " "
                i += 2
                while i + 1 < len(chars) and not (chars[i] == "*" and chars[i + 1] == "/"):
                    if chars[i] != "\n":
                        chars[i] = " "
                    i += 1
                if i + 1 < len(chars):
                    chars[i] = chars[i + 1] = " "
                    i += 2
                continue
            if ch in {"'", '"', "`"}:
                quote = ch
                state = "string"
                chars[i] = " "
                i += 1
                continue
        elif state == "string":
            if ch == "\\":
                chars[i] = " "
                if i + 1 < len(chars) and chars[i + 1] != "\n":
                    chars[i + 1] = " "
                    i += 2
                    continue
            if ch == quote:
                state = "code"
            if ch != "\n":
                chars[i] = " "
        i += 1
    return "".join(chars)


def find_matching_brace(source: str, open_index: int):
    depth = 0
    for index in range(open_index, len(source)):
        if source[index] == "{":
            depth += 1
        elif source[index] == "}":
            depth -= 1
            if depth == 0:
                return index
    return -1


def line_for_offset(source: str, offset: int):
    return source.count("\n", 0, max(0, offset)) + 1


def add_js_function(functions, function_files, module_name, source_file, name, body_start, body_end, source, class_name=""):
    if not name:
        return
    if class_name:
        full_name = f"{module_name}.{class_name}.{name}"
    else:
        full_name = f"{module_name}.{name}"
    functions[full_name] = {
        "name": name,
        "class_name": class_name,
        "body_start": body_start,
        "body_end": body_end,
        "start_line": line_for_offset(source, body_start),
        "end_line": line_for_offset(source, body_end),
    }
    function_files[full_name] = source_file


def collect_js_functions(masked, source, module_name, source_file):
    functions = {}
    function_files = {}
    occupied_ranges = []

    def record(name, open_brace, class_name=""):
        close_brace = find_matching_brace(masked, open_brace)
        if close_brace < 0:
            return
        add_js_function(
            functions,
            function_files,
            module_name,
            source_file,
            name,
            open_brace,
            close_brace,
            source,
            class_name,
        )

    class_pattern = re.compile(r"\bclass\s+([A-Za-z_$][\w$]*)[^{]*\{", re.MULTILINE)
    method_pattern = re.compile(
        r"(?:^|[;\n{}])\s*(?:async\s+)?(?:static\s+)?([A-Za-z_$][\w$]*)\s*\([^)]*\)\s*\{",
        re.MULTILINE,
    )
    for class_match in class_pattern.finditer(masked):
        class_name = class_match.group(1)
        class_open = masked.find("{", class_match.start())
        class_close = find_matching_brace(masked, class_open)
        if class_close < 0:
            continue
        occupied_ranges.append((class_match.start(), class_close))
        class_body = masked[class_open + 1:class_close]
        for method_match in method_pattern.finditer(class_body):
            method_name = method_match.group(1)
            if method_name in JS_RESERVED_CALLS:
                continue
            method_open = class_open + 1 + method_match.end() - 1
            record(method_name if method_name != "constructor" else "<init>", method_open, class_name)

    patterns = [
        re.compile(r"\b(?:export\s+default\s+|export\s+)?(?:async\s+)?function\s+([A-Za-z_$][\w$]*)\s*\([^)]*\)\s*\{", re.MULTILINE),
        re.compile(r"\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*=\s*(?:async\s+)?function\b[^{]*\{", re.MULTILINE),
        re.compile(r"\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*=\s*(?:async\s*)?(?:\([^)]*\)|[A-Za-z_$][\w$]*)\s*=>\s*\{", re.MULTILINE),
        re.compile(r"\b(?:export\s+)?([A-Za-z_$][\w$]*)\s*:\s*(?:async\s*)?(?:function\b[^{]*|\([^)]*\)\s*=>)\s*\{", re.MULTILINE),
    ]
    for pattern in patterns:
        for match in pattern.finditer(masked):
            if any(start <= match.start() <= end for start, end in occupied_ranges):
                continue
            open_brace = masked.find("{", match.start(), match.end() + 1)
            if open_brace >= 0:
                record(match.group(1), open_brace)

    return functions, function_files


def js_call_text_to_name(call_text: str):
    if not call_text:
        return ""
    parts = [part for part in call_text.split(".") if part]
    if not parts:
        return ""
    if len(parts) >= 2 and parts[-2] in {"this", "self"}:
        return parts[-1]
    return ".".join(parts[-2:]) if len(parts) >= 2 else parts[-1]


def _tree_sitter_parser_from_language(language_callable):
    from tree_sitter import Language, Parser

    language = Language(language_callable())
    parser = Parser()
    if hasattr(parser, "set_language"):
        parser.set_language(language)
    else:
        parser.language = language
    return parser


def _tree_sitter_javascript_parser(ext):
    ext = ext.lower()
    if ext in {".ts", ".tsx"}:
        import tree_sitter_typescript

        if ext == ".tsx" and hasattr(tree_sitter_typescript, "language_tsx"):
            return _tree_sitter_parser_from_language(tree_sitter_typescript.language_tsx)
        if hasattr(tree_sitter_typescript, "language_typescript"):
            return _tree_sitter_parser_from_language(tree_sitter_typescript.language_typescript)
        raise RuntimeError("tree_sitter_typescript language function is unavailable")

    import tree_sitter_javascript

    language_fn = getattr(tree_sitter_javascript, "language", None)
    if not language_fn:
        raise RuntimeError("tree_sitter_javascript.language() is unavailable")
    return _tree_sitter_parser_from_language(language_fn)


def js_ast_name(source_bytes, node):
    if not node:
        return ""
    if node.type in {"identifier", "property_identifier", "private_property_identifier"}:
        return _node_text(source_bytes, node).lstrip("#")
    name_node = node.child_by_field_name("name")
    if name_node:
        return _node_text(source_bytes, name_node).lstrip("#")
    property_node = node.child_by_field_name("property")
    if property_node:
        return _node_text(source_bytes, property_node).lstrip("#")
    for child in node.children:
        if child.type in {"identifier", "property_identifier", "private_property_identifier"}:
            return _node_text(source_bytes, child).lstrip("#")
    return ""


def js_ast_call_name(source_bytes, node):
    if not node:
        return ""
    text = _node_text(source_bytes, node)
    if node.type == "identifier":
        return text
    if node.type == "member_expression":
        obj = node.child_by_field_name("object")
        prop = node.child_by_field_name("property")
        object_name = js_ast_call_name(source_bytes, obj)
        property_name = js_ast_name(source_bytes, prop)
        return f"{object_name}.{property_name}" if object_name and property_name else property_name
    if node.type == "subscript_expression":
        obj = node.child_by_field_name("object")
        return js_ast_call_name(source_bytes, obj)
    return text.split("(", 1)[0].strip()


def js_ast_string_value(source_bytes, node):
    if not node:
        return ""
    text = _node_text(source_bytes, node).strip()
    if len(text) >= 2 and text[0] in {"'", '"', "`"} and text[-1] == text[0]:
        return text[1:-1]
    return text


def js_ast_child_text(source_bytes, node, node_types):
    if not node:
        return ""
    for child in node.children:
        if child.type in node_types:
            return _node_text(source_bytes, child)
    return ""


def js_module_node(module_name):
    return f"module.{module_name}" if module_name else ""


def js_route_slug(value: str, fallback: str = "route"):
    return html_ui_slug(str(value or "").strip("/[]()") or fallback, fallback)


def next_route_from_file(source_file: str):
    rel = str(source_file or "").replace("\\", "/")
    stem = os.path.splitext(rel)[0]
    parts = stem.split("/")
    if "app" in parts:
        app_index = parts.index("app")
        route_parts = [part for part in parts[app_index + 1:] if part not in {"page", "layout", "template", "loading", "error", "not-found", "route"}]
        if parts[-1] == "route":
            return "/" + "/".join(route_parts), "next_api_route"
        if parts[-1] in {"page", "layout", "template", "loading", "error", "not-found"}:
            return "/" + "/".join(route_parts), "next_page"
    if "pages" in parts:
        pages_index = parts.index("pages")
        route_parts = parts[pages_index + 1:]
        if route_parts and route_parts[0] == "api":
            return "/" + "/".join(route_parts), "next_api_route"
        if route_parts:
            if route_parts[-1] == "index":
                route_parts = route_parts[:-1]
            return "/" + "/".join(route_parts), "next_page"
    return "", ""


def resolve_js_import_path(importer_path: str, specifier: str, module_by_file: dict):
    specifier = str(specifier or "").strip()
    if not specifier.startswith("."):
        return ""
    importer_dir = posixpath.dirname(str(importer_path or "").replace("\\", "/"))
    base = posixpath.normpath(posixpath.join(importer_dir, specifier)).strip("./")
    candidates = [base]
    for ext in sorted(JS_SOURCE_EXTENSIONS):
        candidates.append(f"{base}{ext}")
    for ext in sorted(JS_SOURCE_EXTENSIONS):
        candidates.append(posixpath.join(base, f"index{ext}"))
    for candidate in candidates:
        normalized = candidate.replace("\\", "/").lstrip("./")
        if normalized in module_by_file:
            return module_by_file[normalized]
    return ""


def js_extract_imports_and_exports(source_bytes, root):
    imports = []
    exports = {"default": "", "named": set()}
    for node in root.children:
        if node.type == "import_statement":
            module = ""
            local_names = []
            namespace_name = ""
            for child in node.children:
                if child.type in {"string", "template_string"}:
                    module = js_ast_string_value(source_bytes, child)
                elif child.type == "import_clause":
                    for grandchild in child.children:
                        if grandchild.type == "identifier":
                            local_names.append(_node_text(source_bytes, grandchild))
                        elif grandchild.type == "namespace_import":
                            namespace_name = js_ast_child_text(source_bytes, grandchild, {"identifier"})
                        elif grandchild.type == "named_imports":
                            local_names.extend(
                                _node_text(source_bytes, item)
                                for item in grandchild.children
                                if item.type == "identifier"
                            )
                            for specifier in grandchild.children:
                                if specifier.type == "import_specifier":
                                    alias = specifier.child_by_field_name("alias")
                                    name = specifier.child_by_field_name("name")
                                    local_names.append(_node_text(source_bytes, alias or name))
            if module:
                imports.append({
                    "module": module,
                    "locals": sorted(set(name for name in local_names if name)),
                    "namespace": namespace_name,
                    "line": _node_start_line(node),
                })
        elif node.type == "export_statement":
            declaration = node.child_by_field_name("declaration")
            if declaration:
                name = js_ast_name(source_bytes, declaration)
                if "default" in _node_text(source_bytes, node).split()[:3]:
                    exports["default"] = name
                elif name:
                    exports["named"].add(name)
            else:
                for child in node.children:
                    if child.type == "identifier":
                        exports["named"].add(_node_text(source_bytes, child))
    exports["named"] = sorted(exports["named"])
    return imports, exports


def js_collect_framework_edges(source_file, module_name, module_node, source_functions, exports):
    nodes = set()
    edges = set()
    node_labels = {}
    edge_labels = {}
    entry_points = []
    route_path, route_kind = next_route_from_file(source_file)
    if route_kind == "next_page":
        route_node = f"next.page.{js_route_slug(route_path, 'root')}"
        nodes.update([route_node, module_node])
        node_labels[route_node] = f"Next page {route_path or '/'}"
        edge_labels[f"{route_node}->{module_node}"] = "renders module"
        edges.add((route_node, module_node))
        entry_points.append(route_node)
        default_name = exports.get("default") or "default"
        targets = [
            fn for fn in source_functions
            if fn == f"{module_name}.{default_name}" or fn.endswith(f".{default_name}")
        ]
        if not targets and len(source_functions) == 1:
            targets = list(source_functions)
        for target in targets[:3]:
            nodes.update([route_node, target])
            edge_labels[f"{route_node}->{target}"] = "renders"
            edges.add((route_node, target))
    elif route_kind == "next_api_route":
        route_node = api_route_symbol(route_path or "/")
        nodes.update([route_node, module_node])
        node_labels[route_node] = api_route_label(route_path or "/")
        edge_labels[f"{route_node}->{module_node}"] = "handled by module"
        edges.add((route_node, module_node))
        entry_points.append(route_node)
        http_handlers = [fn for fn in source_functions if fn.rsplit(".", 1)[-1].upper() in {"GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS", "HEAD"}]
        for target in http_handlers:
            nodes.update([route_node, target])
            edge_labels[f"{route_node}->{target}"] = "handles request"
            edges.add((route_node, target))
    return nodes, edges, node_labels, edge_labels, entry_points


def js_ast_function_body(node):
    body = node.child_by_field_name("body")
    if body:
        return body
    for child in reversed(node.children):
        if child.type in {"statement_block", "function_body"}:
            return child
    return node


def write_javascript_graph(
    output_dir,
    functions,
    function_files,
    edges,
    ordered_calls,
    parse_errors,
    parser_name,
    node_labels=None,
    edge_labels=None,
    entry_points=None,
    imports=None,
    framework=None,
):
    os.makedirs(output_dir, exist_ok=True)
    out = os.path.join(output_dir, "javascript_callgraph.json")
    graph_nodes = set(functions)
    for src, dst in edges:
        graph_nodes.add(src)
        graph_nodes.add(dst)
    graph = {
        "mode": "javascript_ast_static" if parser_name.startswith("tree-sitter") else "javascript_regex_static",
        "parser": parser_name,
        "nodes": sorted(graph_nodes),
        "edges": [[src, dst] for src, dst in sorted(edges)],
        "function_files": function_files,
        "node_labels": node_labels or {},
        "edge_labels": edge_labels or {},
        "entry_points": sorted(set(entry_points or [])),
        "imports": imports or {},
        "framework": framework or {},
        "parse_errors": parse_errors[:50],
        "parse_error_count": len(parse_errors),
    }
    with open(out, "w", encoding="utf-8") as f:
        json.dump(graph, f, indent=2)

    ordered_out = os.path.join(output_dir, "javascript_ordered_call_sequence.json")
    write_ordered_call_sequence(
        ordered_calls,
        ordered_out,
        parser=parser_name,
        source_callgraph=os.path.basename(out),
    )
    logger.info(
        "JavaScript callgraph written: %s parser=%s functions=%s edges=%s",
        out,
        parser_name,
        len(functions),
        len(edges),
    )
    return out


def build_javascript_tree_sitter_callgraph(repo_src, output_dir, progress_callback=None):
    logger.info("Building tree-sitter JavaScript/TypeScript callgraph: repo_src=%s output=%s", repo_src, output_dir)
    functions = {}
    function_files = {}
    raw_calls = []
    parse_errors = []
    module_by_file = {}
    file_by_module = {}
    source_functions_by_file = defaultdict(set)
    imports_by_file = {}
    exports_by_file = {}
    local_symbols_by_file = defaultdict(dict)
    node_labels = {}
    edge_labels = {}
    entry_points = set()
    framework = {
        "typescript_ast": "tree-sitter-typescript",
        "react_patterns": True,
        "nextjs_patterns": True,
        "import_resolution": "relative_extension_and_index",
    }

    def add_function(module_name, source_file, source_bytes, name, node, class_name=""):
        if not name:
            return ""
        full_name = f"{module_name}.{class_name}.{name}" if class_name else f"{module_name}.{name}"
        body = js_ast_function_body(node)
        functions[full_name] = {
            "name": name,
            "class_name": class_name,
            "start_line": _node_start_line(node),
            "end_line": _node_start_line(body),
        }
        function_files[full_name] = source_file
        source_functions_by_file[source_file].add(full_name)
        local_symbols_by_file[source_file][name] = full_name
        return full_name

    def walk(source_bytes, node, module_name, source_file, class_stack, current_function=""):
        class_types = {"class_declaration", "class", "class_expression"}
        function_types = {"function_declaration"}
        value_function_types = {"function", "function_expression", "arrow_function", "generator_function"}
        method_types = {"method_definition", "public_field_definition", "pair"}

        if node.type in class_types:
            class_name = js_ast_name(source_bytes, node)
            next_stack = class_stack + ([class_name] if class_name else [])
            for child in node.children:
                walk(source_bytes, child, module_name, source_file, next_stack, current_function)
            return

        if node.type in function_types:
            fn_name = js_ast_name(source_bytes, node)
            current_function = add_function(module_name, source_file, source_bytes, fn_name, node, ".".join(class_stack))

        elif node.type == "variable_declarator":
            name_node = node.child_by_field_name("name")
            value_node = node.child_by_field_name("value")
            if value_node and value_node.type in value_function_types:
                current_function = add_function(
                    module_name,
                    source_file,
                    source_bytes,
                    js_ast_name(source_bytes, name_node),
                    value_node,
                    ".".join(class_stack),
                )

        elif node.type in method_types:
            name_node = node.child_by_field_name("name") or node.child_by_field_name("key")
            value_node = node.child_by_field_name("value")
            function_node = value_node if value_node and value_node.type in value_function_types else node
            method_name = js_ast_name(source_bytes, name_node or node)
            if method_name and (class_stack or (value_node and value_node.type in value_function_types)):
                current_function = add_function(
                    module_name,
                    source_file,
                    source_bytes,
                    "<init>" if method_name == "constructor" else method_name,
                    function_node,
                    ".".join(class_stack),
                )

        elif current_function and node.type == "call_expression":
            callee_node = node.child_by_field_name("function")
            raw = js_ast_call_name(source_bytes, callee_node)
            tail = raw.split(".")[-1]
            if tail and tail not in JS_RESERVED_CALLS and not raw.startswith(("console.", "Math.", "JSON.", "Object.", "Array.", "String.", "Number.", "Promise.")):
                raw_calls.append({
                    "caller": current_function,
                    "raw": raw,
                    "callee_name": js_call_text_to_name(raw),
                    "file": source_file,
                    "line": _node_start_line(node),
                    "column": getattr(getattr(node, "start_point", None), "column", None),
                    "call_text": raw[:120],
                    "class_name": functions.get(current_function, {}).get("class_name", ""),
                })

        elif current_function and node.type in {"jsx_opening_element", "jsx_self_closing_element"}:
            name_node = node.child_by_field_name("name")
            component_name = js_ast_call_name(source_bytes, name_node)
            if component_name and component_name[:1].isupper():
                raw_calls.append({
                    "caller": current_function,
                    "raw": component_name,
                    "callee_name": component_name,
                    "file": source_file,
                    "line": _node_start_line(node),
                    "column": getattr(getattr(node, "start_point", None), "column", None),
                    "call_text": component_name[:120],
                    "class_name": functions.get(current_function, {}).get("class_name", ""),
                    "kind": "jsx_component",
                })

        for child in node.children:
            walk(source_bytes, child, module_name, source_file, class_stack, current_function)

    def report_progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    parser_cache = {}
    source_paths, skipped_large_paths = collect_javascript_callgraph_source_paths(repo_src)
    for skipped_path in skipped_large_paths:
        parse_errors.append({
            "file": skipped_path,
            "error_type": "skipped_oversized_file",
            "error": f"skipped oversized JavaScript/TypeScript file over {JS_MAX_TREE_SITTER_PARSE_BYTES} bytes",
        })
    total_files = len(source_paths)
    report_progress(f"Preparing JavaScript and TypeScript file list ({total_files} files).", current_file="")

    for path in source_paths:
        source_file = os.path.relpath(path, repo_src).replace("\\", "/")
        module_name = js_module_name_for(path, repo_src)
        module_by_file[source_file] = module_name
        file_by_module[module_name] = source_file

    for index, path in enumerate(source_paths, start=1):
        ext = os.path.splitext(path)[1].lower()
        source_file = os.path.relpath(path, repo_src).replace("\\", "/")
        module_name = module_by_file.get(source_file) or js_module_name_for(path, repo_src)
        report_progress(f"Parsing JavaScript and TypeScript file {index}/{total_files}.", source_file)
        started_at = time.monotonic()
        source_bytes = None
        tree = None
        try:
            parser = parser_cache.get(ext)
            if parser is None:
                parser = _tree_sitter_javascript_parser(ext)
                parser_cache[ext] = parser
            source_bytes = Path(path).read_bytes()
            tree = parser.parse(source_bytes)
            if tree.root_node.has_error:
                parse_errors.append({"file": path, "error": "tree-sitter parse error"})
            imports, exports = js_extract_imports_and_exports(source_bytes, tree.root_node)
            imports_by_file[source_file] = imports
            exports_by_file[source_file] = exports
            walk(source_bytes, tree.root_node, module_name, source_file, [])
        except Exception as e:
            parse_errors.append({"file": path, "error": f"{type(e).__name__}: {e}"})
        finally:
            elapsed = time.monotonic() - started_at
            if elapsed >= 5:
                logger.warning(
                    "Slow JavaScript/TypeScript parse: file=%s seconds=%.1f size=%s",
                    source_file,
                    elapsed,
                    os.path.getsize(path) if os.path.exists(path) else "",
                )
            del tree
            del source_bytes
            if index % 10 == 0:
                gc.collect()

    gc.collect()

    report_progress("Resolving JavaScript and TypeScript imports.", current_file="")
    module_imports = {}
    import_symbol_index_by_file = defaultdict(dict)
    import_namespace_index_by_file = defaultdict(dict)
    for source_file, imports in imports_by_file.items():
        source_module = module_by_file.get(source_file) or js_module_name_for(os.path.join(repo_src, source_file), repo_src)
        module_node = js_module_node(source_module)
        node_labels[module_node] = source_file
        module_imports[source_file] = []
        for item in imports:
            target_module = resolve_js_import_path(source_file, item.get("module", ""), module_by_file)
            module_imports[source_file].append({**item, "resolved_module": target_module})
            if not target_module:
                continue
            target_file = file_by_module.get(target_module, "")
            target_node = js_module_node(target_module)
            node_labels[target_node] = target_file or target_module
            edge = (module_node, target_node)
            edge_labels[f"{edge[0]}->{edge[1]}"] = "imports"
            for local_name in item.get("locals") or []:
                import_symbol_index_by_file[source_file][local_name] = target_module
            if item.get("namespace"):
                import_namespace_index_by_file[source_file][item["namespace"]] = target_module

    report_progress("Building JavaScript and TypeScript framework links.", current_file="")
    framework_nodes = set()
    framework_edges = set()
    for source_file, source_functions in source_functions_by_file.items():
        module_name = module_by_file.get(source_file, "")
        module_node = js_module_node(module_name)
        if not module_node:
            continue
        node_labels[module_node] = source_file
        framework_nodes.add(module_node)
        for fn in source_functions:
            framework_edges.add((module_node, fn))
            edge_labels[f"{module_node}->{fn}"] = "defines"
        nodes, fw_edges, labels, fw_edge_labels, fw_entries = js_collect_framework_edges(
            source_file,
            module_name,
            module_node,
            source_functions,
            exports_by_file.get(source_file, {}),
        )
        framework_nodes.update(nodes)
        framework_edges.update(fw_edges)
        node_labels.update(labels)
        edge_labels.update(fw_edge_labels)
        entry_points.update(fw_entries)

    report_progress("Indexing JavaScript and TypeScript symbols.", current_file="")
    suffix_index = defaultdict(set)
    class_method_index = defaultdict(set)
    for full_name, info in functions.items():
        suffix_index[".".join(full_name.split(".")[-2:])].add(full_name)
        suffix_index[info["name"]].add(full_name)
        if info.get("class_name"):
            class_method_index[(info["class_name"].split(".")[-1], info["name"])].add(full_name)
            class_method_index[(info["class_name"], info["name"])].add(full_name)

    def unique(matches):
        return next(iter(matches)) if len(matches) == 1 else None

    def resolve(call):
        raw = call.get("raw", "")
        tail = raw.split(".")[-1]
        class_name = call.get("class_name", "")
        if raw.startswith("this.") and class_name:
            resolved = unique(class_method_index.get((class_name, tail), set()) or class_method_index.get((class_name.split(".")[-1], tail), set()))
            if resolved:
                return resolved
        callee_name = call.get("callee_name", "")
        if "." in raw and callee_name in suffix_index:
            resolved = unique(suffix_index[callee_name])
            if resolved:
                return resolved
        source_file = call.get("file", "")
        if raw in local_symbols_by_file.get(source_file, {}):
            return local_symbols_by_file[source_file][raw]
        if raw in import_symbol_index_by_file.get(source_file, {}):
            target_module = import_symbol_index_by_file[source_file][raw]
            target_file = file_by_module.get(target_module, "")
            return (
                local_symbols_by_file.get(target_file, {}).get(raw)
                or unique(suffix_index.get(f"{target_module}.{raw}", set()))
                or unique([
                    symbol for symbol in source_functions_by_file.get(target_file, set())
                    if symbol.endswith(f".{raw}")
                ])
            )
        if "." in raw:
            qualifier, member = raw.split(".", 1)
            target_module = import_namespace_index_by_file.get(source_file, {}).get(qualifier)
            target_file = file_by_module.get(target_module, "") if target_module else ""
            if target_file:
                return local_symbols_by_file.get(target_file, {}).get(member.split(".")[-1])
        return None

    report_progress("Resolving JavaScript and TypeScript calls.", current_file="")
    edges = set(framework_edges)
    for source_file, imports in module_imports.items():
        source_module = module_by_file.get(source_file, "")
        source_node = js_module_node(source_module)
        for item in imports:
            target_node = js_module_node(item.get("resolved_module", ""))
            if source_node and target_node:
                edges.add((source_node, target_node))
    ordered_calls = []
    for call in raw_calls:
        callee = resolve(call)
        if callee and callee != call["caller"]:
            edges.add((call["caller"], callee))
            if call.get("kind") == "jsx_component":
                edge_labels[f"{call['caller']}->{callee}"] = "renders component"
            ordered_calls.append({
                "caller": call["caller"],
                "callee": callee,
                "file": call.get("file", ""),
                "line": call.get("line"),
                "column": call.get("column"),
                "order": len(ordered_calls) + 1,
                "call_text": call.get("call_text", ""),
            })

    report_progress("Writing JavaScript and TypeScript graph artifacts.", current_file="")
    fatal_parse_errors = [
        item for item in parse_errors
        if item.get("error_type") != "skipped_oversized_file"
    ]
    if not functions and fatal_parse_errors:
        raise RuntimeError("; ".join(str(item.get("error", "")) for item in fatal_parse_errors[:3]))

    return write_javascript_graph(
        output_dir,
        functions,
        function_files,
        edges,
        ordered_calls,
        parse_errors,
        "tree-sitter-javascript/typescript",
        node_labels=node_labels,
        edge_labels=edge_labels,
        entry_points=entry_points,
        imports=module_imports,
        framework=framework,
    )


def build_javascript_regex_callgraph(repo_src, output_dir, progress_callback=None):
    logger.info("Building JavaScript/TypeScript callgraph: repo_src=%s output=%s", repo_src, output_dir)
    os.makedirs(output_dir, exist_ok=True)
    functions = {}
    function_files = {}
    parse_errors = []
    raw_calls = []

    def report_progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    source_paths, skipped_large_paths = collect_javascript_callgraph_source_paths(repo_src)
    for skipped_path in skipped_large_paths:
        parse_errors.append({
            "file": skipped_path,
            "error_type": "skipped_oversized_file",
            "error": f"skipped oversized JavaScript/TypeScript file over {JS_MAX_TREE_SITTER_PARSE_BYTES} bytes",
        })
    total_files = len(source_paths)
    for index, path in enumerate(source_paths, start=1):
        source_file = os.path.relpath(path, repo_src).replace("\\", "/")
        report_progress(f"Parsing JavaScript and TypeScript file {index}/{total_files}.", source_file)
        try:
            source = Path(path).read_text(encoding="utf-8", errors="ignore")
            masked = mask_js_non_code(source)
        except OSError as e:
            parse_errors.append({"file": path, "error": str(e)})
            continue

        module_name = js_module_name_for(path, repo_src)
        file_functions, file_function_files = collect_js_functions(masked, source, module_name, source_file)
        functions.update(file_functions)
        function_files.update(file_function_files)

    suffix_index = defaultdict(set)
    class_method_index = defaultdict(set)
    local_symbols_by_file = defaultdict(dict)
    for full_name, info in functions.items():
        suffix_index[".".join(full_name.split(".")[-2:])].add(full_name)
        if info.get("class_name"):
            class_method_index[(info["class_name"], info["name"])].add(full_name)
        local_symbols_by_file[function_files.get(full_name, "")][info["name"]] = full_name

    call_pattern = re.compile(r"\b([A-Za-z_$][\w$]*(?:\.[A-Za-z_$][\w$]*)*)\s*\(", re.MULTILINE)
    for caller, info in functions.items():
        try:
            path = os.path.join(repo_src, function_files.get(caller, ""))
            source = Path(path).read_text(encoding="utf-8", errors="ignore")
            masked = mask_js_non_code(source)
        except OSError:
            continue
        body = masked[info["body_start"]:info["body_end"]]
        for match in call_pattern.finditer(body):
            raw = match.group(1)
            tail = raw.split(".")[-1]
            if tail in JS_RESERVED_CALLS or raw.startswith(("console.", "Math.", "JSON.", "Object.", "Array.", "String.", "Number.", "Promise.")):
                continue
            offset = info["body_start"] + match.start()
            raw_calls.append({
                "caller": caller,
                "raw": raw,
                "callee_name": js_call_text_to_name(raw),
                "file": function_files.get(caller, ""),
                "line": line_for_offset(source, offset),
                "column": offset - source.rfind("\n", 0, offset) - 1,
                "call_text": raw,
                "class_name": info.get("class_name", ""),
            })

    def unique(matches):
        return next(iter(matches)) if len(matches) == 1 else None

    def resolve(call):
        raw = call["raw"]
        callee_name = call["callee_name"]
        class_name = call.get("class_name", "")
        tail = raw.split(".")[-1]
        if raw.startswith("this.") and class_name:
            resolved = unique(class_method_index.get((class_name, tail), set()))
            if resolved:
                return resolved
        if "." in raw and callee_name in suffix_index:
            resolved = unique(suffix_index[callee_name])
            if resolved:
                return resolved
        # Plain, unqualified call (no `this.`, no dot) — check whether a function by this
        # exact name is defined in the same file before giving up. Without this, a same-file
        # call like `setLocaleCookie(x)` inside another function in the same module never
        # resolves to an edge, even though the target function is right there, which produces
        # false-positive "isolated_file"/"dead_function" static quality findings.
        source_file = call.get("file", "")
        if raw in local_symbols_by_file.get(source_file, {}):
            return local_symbols_by_file[source_file][raw]
        return None

    edges = set()
    ordered_calls = []
    for call in raw_calls:
        callee = resolve(call)
        if callee and callee != call["caller"]:
            edges.add((call["caller"], callee))
            ordered_calls.append({
                "caller": call["caller"],
                "callee": callee,
                "file": call.get("file", ""),
                "line": call.get("line"),
                "column": call.get("column"),
                "order": len(ordered_calls) + 1,
                "call_text": call.get("call_text", ""),
            })

    return write_javascript_graph(
        output_dir,
        functions,
        function_files,
        edges,
        ordered_calls,
        parse_errors,
        "javascript-regex",
    )


def build_javascript_callgraph(repo_src, output_dir, progress_callback=None):
    if os.name == "nt" and not JS_TREE_SITTER_ENABLED:
        logger.warning(
            "tree-sitter JavaScript analysis disabled on Windows to avoid native parser crashes; "
            "using regex parser. Set CODEVAL_JS_TREE_SITTER=1 to opt in."
        )
        return build_javascript_regex_callgraph(repo_src, output_dir, progress_callback=progress_callback)
    try:
        return build_javascript_tree_sitter_callgraph(repo_src, output_dir, progress_callback=progress_callback)
    except Exception as e:
        logger.warning("tree-sitter JavaScript analysis unavailable; falling back to regex parser: %s", e)
        return build_javascript_regex_callgraph(repo_src, output_dir, progress_callback=progress_callback)


CSHARP_CALL_KEYWORDS = {
    "if", "for", "foreach", "while", "switch", "catch", "using", "lock", "return",
    "throw", "new", "typeof", "nameof", "sizeof", "default", "checked", "unchecked",
}


def strip_csharp_comments_and_strings(text: str) -> str:
    result = []
    i = 0
    length = len(text)
    state = "code"
    while i < length:
        ch = text[i]
        nxt = text[i + 1] if i + 1 < length else ""
        if state == "code":
            if ch == "/" and nxt == "/":
                result.extend("  ")
                i += 2
                state = "line_comment"
                continue
            if ch == "/" and nxt == "*":
                result.extend("  ")
                i += 2
                state = "block_comment"
                continue
            if ch == "@":
                result.append(" ")
                i += 1
                if i < length and text[i] == '"':
                    result.append(" ")
                    i += 1
                    state = "verbatim_string"
                continue
            if ch == '"':
                result.append(" ")
                i += 1
                state = "string"
                continue
            if ch == "'":
                result.append(" ")
                i += 1
                state = "char"
                continue
            result.append(ch)
            i += 1
        elif state == "line_comment":
            result.append("\n" if ch == "\n" else " ")
            state = "code" if ch == "\n" else state
            i += 1
        elif state == "block_comment":
            if ch == "*" and nxt == "/":
                result.extend("  ")
                i += 2
                state = "code"
            else:
                result.append("\n" if ch == "\n" else " ")
                i += 1
        elif state == "string":
            if ch == "\\" and nxt:
                result.extend("  ")
                i += 2
            else:
                result.append("\n" if ch == "\n" else " ")
                state = "code" if ch == '"' else state
                i += 1
        elif state == "verbatim_string":
            if ch == '"' and nxt == '"':
                result.extend("  ")
                i += 2
            else:
                result.append("\n" if ch == "\n" else " ")
                state = "code" if ch == '"' else state
                i += 1
        elif state == "char":
            if ch == "\\" and nxt:
                result.extend("  ")
                i += 2
            else:
                result.append("\n" if ch == "\n" else " ")
                state = "code" if ch == "'" else state
                i += 1
    return "".join(result)


def find_matching_brace(text: str, open_index: int) -> int:
    depth = 0
    for index in range(open_index, len(text)):
        if text[index] == "{":
            depth += 1
        elif text[index] == "}":
            depth -= 1
            if depth == 0:
                return index
    return -1


def build_csharp_callgraph(repo_src, output_dir, progress_callback=None):
    method_decl = re.compile(
        r"(?m)^\s*(?:\[[^\]]+\]\s*)*"
        r"(?:(?:public|private|protected|internal|static|virtual|override|async|sealed|partial|extern|unsafe|new)\s+)*"
        r"(?:(?P<return_type>[\w<>\[\],?.]+\s+)+)?"
        r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*"
        r"(?:<[^>{};=]*>\s*)?\([^;{}]*\)\s*"
        r"(?:where\s+[^{]+)?\{"
    )
    class_decl = re.compile(r"\b(?:class|struct|record|interface)\s+([A-Za-z_][A-Za-z0-9_]*)[^{;]*\{")
    call_pattern = re.compile(r"(?:\b([A-Za-z_][A-Za-z0-9_]*)\s*\.\s*)?\b([A-Za-z_][A-Za-z0-9_]*)\s*\(")
    namespace_block = re.compile(r"\bnamespace\s+([A-Za-z_][\w.]*)\s*\{")
    namespace_file = re.compile(r"(?m)^\s*namespace\s+([A-Za-z_][\w.]*)\s*;")

    nodes = set()
    edges = set()
    edge_meta = {}
    ordered_calls = []
    function_files = {}
    method_records = []

    def report_progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    cs_files = []
    for path in iter_supported_repo_files(repo_src, {".cs"}):
        cs_files.append(path)
    cs_files.sort()

    for path in cs_files:
        rel_path = os.path.relpath(path, repo_src).replace("\\", "/")
        report_progress("Parsing C# files.", rel_path)
        raw_text = Path(path).read_text(encoding="utf-8", errors="ignore")
        text = strip_csharp_comments_and_strings(raw_text)
        namespaces = []
        file_namespace_match = namespace_file.search(text)
        file_namespace = file_namespace_match.group(1) if file_namespace_match else ""
        for match in namespace_block.finditer(text):
            open_index = text.find("{", match.end() - 1)
            close_index = find_matching_brace(text, open_index)
            if close_index > open_index:
                namespaces.append((match.start(), close_index, match.group(1)))
        classes = []
        for match in class_decl.finditer(text):
            open_index = text.find("{", match.end() - 1)
            close_index = find_matching_brace(text, open_index)
            if close_index > open_index:
                classes.append((match.start(), close_index, match.group(1)))
        for match in method_decl.finditer(text):
            name = match.group("name")
            if name in CSHARP_CALL_KEYWORDS:
                continue
            open_index = text.find("{", match.end() - 1)
            close_index = find_matching_brace(text, open_index)
            if close_index <= open_index:
                continue
            containing_class = next((item for item in classes if item[0] <= match.start() <= item[1]), None)
            class_name = containing_class[2] if containing_class else Path(path).stem
            namespace_name = file_namespace or next((item[2] for item in namespaces if item[0] <= match.start() <= item[1]), "")
            full_name = ".".join(part for part in (namespace_name, class_name, name) if part)
            body = text[open_index + 1:close_index]
            start_line = raw_text.count("\n", 0, match.start()) + 1
            record = {
                "symbol": full_name,
                "name": name,
                "class_name": class_name,
                "namespace": namespace_name,
                "path": rel_path,
                "body": body,
                "body_offset": open_index + 1,
                "start_line": start_line,
            }
            method_records.append(record)
            nodes.add(full_name)
            function_files[full_name] = rel_path

    by_class_method = {}
    for record in method_records:
        by_class_method[(record["class_name"], record["name"])] = record["symbol"]

    edge_order = 1
    for record in method_records:
        caller = record["symbol"]
        for match in call_pattern.finditer(record["body"]):
            qualifier, call_name = match.groups()
            if call_name in CSHARP_CALL_KEYWORDS or call_name == record["name"]:
                continue
            target = ""
            if qualifier:
                target = by_class_method.get((qualifier, call_name), "")
            if not target:
                target = by_class_method.get((record["class_name"], call_name), "")
            if not target or target == caller:
                continue
            line = record["body"][:match.start()].count("\n") + record["start_line"]
            edge = (caller, target)
            edges.add(edge)
            previous = edge_meta.get(edge)
            if previous is None or edge_order < (previous.get("order") or edge_order):
                edge_meta[edge] = {"order": edge_order, "line": line}
            ordered_calls.append({
                "caller": caller,
                "callee": target,
                "order": edge_order,
                "line": line,
                "file": record["path"],
                "call_text": call_name,
            })
            edge_order += 1

    os.makedirs(output_dir, exist_ok=True)
    json_path = os.path.join(output_dir, "csharp_callgraph.json")
    graph = {
        "mode": "csharp_regex_callgraph",
        "parser": "csharp-regex",
        "nodes": sorted(nodes),
        "edges": [
            [src, dst, edge_meta.get((src, dst), {}).get("order"), edge_meta.get((src, dst), {}).get("line")]
            for src, dst in sorted(edges, key=lambda edge: (
                edge_meta.get(edge, {}).get("order") if edge_meta.get(edge, {}).get("order") is not None else 10**12,
                edge[0],
                edge[1],
            ))
        ],
        "function_files": function_files,
        "file_count": len(cs_files),
    }
    Path(json_path).write_text(json.dumps(graph, separators=(",", ":")), encoding="utf-8")
    ordered_path = os.path.join(output_dir, "csharp_ordered_call_sequence.json")
    if ordered_calls:
        write_ordered_call_sequence(
            ordered_calls,
            ordered_path,
            parser="csharp-regex",
            source_callgraph=os.path.basename(json_path),
        )
    return json_path, "", ordered_path if ordered_calls else ""


def detect_languages(repo_src):
    # Boolean map: True if the repo contains at least one file of that language
    lang_map = {
        "python": False,
        "java": False,
        "javascript": False,
        "go": False,
        "c": False,
        "cpp": False,
        "rust": False,
        "kotlin": False,
        "csharp": False,
        "html": False,
        "others": False
    }
    EXT_MAP = {
        ".py": "python",
        ".java": "java",
        ".js": "javascript",
        ".jsx": "javascript",
        ".ts": "javascript",
        ".tsx": "javascript",
        ".mjs": "javascript",
        ".cjs": "javascript",
        ".go": "go",
        ".c": "c",
        ".h": "c",
        ".cpp": "cpp",
        ".cc": "cpp",
        ".cxx": "cpp",
        ".hpp": "cpp",
        ".hh": "cpp",
        ".rs": "rust",
        ".kt": "kotlin",
        ".kts": "kotlin",
        ".cs": "csharp",
        ".html": "html",
        ".htm": "html",
        ".xhtml": "html",
    }
    detect_extensions = ALLOWED_CODE_EXTENSIONS | HTML_UI_EXTENSIONS_FOR_ANALYSIS
    for path in iter_supported_repo_files(repo_src, detect_extensions):
        ext = os.path.splitext(path)[1].lower()
        if ext in EXT_MAP:
            lang = EXT_MAP[ext]
            lang_map[lang] = True
        else:
            lang_map["others"] = True
    return lang_map


