def build_repo_stats(repo_src, owner, repo, repo_info=None, default_branch="", source="downloaded_zip"):
    extension_counts = defaultdict(int)
    language_counts = defaultdict(int)
    total_files = 0
    source_line_count = 0
    source_files_counted = 0

    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), repo_src)]
        for filename in files:
            path = os.path.join(root, filename)
            if should_skip_path(path, repo_src):
                continue
            total_files += 1
            ext = os.path.splitext(filename)[1].lower() or "[no extension]"
            extension_counts[ext] += 1
            language = LANGUAGE_BY_EXTENSION.get(ext)
            if language:
                language_counts[language] += 1
            if ext in CODE_LINE_EXTENSIONS:
                try:
                    with open(path, "r", encoding="utf-8", errors="ignore") as handle:
                        source_line_count += sum(1 for _ in handle)
                    source_files_counted += 1
                except OSError:
                    logger.warning("Unable to count source lines for %s", path)

    return {
        "repo_full_name": f"{owner}/{repo}",
        "default_branch": default_branch or (repo_info or {}).get("default_branch", ""),
        "source": source or "downloaded_zip",
        "total_files_seen": total_files,
        "source_line_count": source_line_count,
        "source_files_counted": source_files_counted,
        "unique_extension_count": len(extension_counts),
        "extension_counts": dict(sorted(extension_counts.items(), key=lambda item: (-item[1], item[0]))),
        "language_counts": dict(sorted(language_counts.items(), key=lambda item: (-item[1], item[0]))),
        "known_from_github_repo_metadata": github_metadata_summary(repo_info, default_branch),
        "not_available_from_downloaded_zip": [
            "Git history",
            "Pull requests",
            "Issues",
            "Branch protection",
        ],
    }


