TODO_RE = re.compile(r"\b(TODO|FIXME|XXX|HACK)\b[:\s-]*(.*)", re.IGNORECASE)


def is_false_todo_item(rel_path: str, text: str):
    lower_path = str(rel_path or "").replace("\\", "/").lower()
    cleaned = str(text or "").strip()
    lower_text = cleaned.lower()
    if cleaned.startswith("<module ") or cleaned.startswith("<property "):
        return True
    if lower_path.endswith("checkstyle.xml") and (
        "<module" in lower_text
        or "<property" in lower_text
        or "javadoc" in lower_text
        or "linelength" in lower_text
        or "filelength" in lower_text
        or "filetabcharacter" in lower_text
    ):
        return True
    return False


def repo_text_kind(rel_path: str):
    path = str(rel_path or "").replace("\\", "/")
    lower_path = path.lower()
    name = Path(lower_path).name
    stem = Path(lower_path).stem
    parts = set(lower_path.split("/"))
    if name.startswith("readme") or stem == "readme":
        return "readme"
    if "docs" in parts or "doc" in parts or name in REPO_TEXT_PRIORITY_NAMES or stem in REPO_TEXT_PRIORITY_NAMES:
        return "document"
    return "text"


def normalize_human_text(text: str, max_chars: int = 4000):
    cleaned = str(text or "")
    cleaned = re.sub(r"\r\n?", "\n", cleaned)
    cleaned = re.sub(r"[ \t]+", " ", cleaned)
    cleaned = re.sub(r"\n[ \t]+", "\n", cleaned)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    return cleaned.strip()[:max_chars]


def visible_html_text(text: str, max_chars: int = 4000):
    import html as html_lib

    cleaned = re.sub(r"(?is)<(script|style|svg|noscript)\b.*?</\1>", " ", str(text or ""))
    cleaned = re.sub(r"(?is)<!--.*?-->", " ", cleaned)
    cleaned = re.sub(r"(?is)<br\s*/?>", "\n", cleaned)
    cleaned = re.sub(r"(?is)</(p|div|section|article|header|footer|li|h[1-7]|tr)>", "\n", cleaned)
    cleaned = re.sub(r"(?is)<[^>]+>", " ", cleaned)
    cleaned = html_lib.unescape(cleaned)
    lines = [line.strip() for line in cleaned.splitlines()]
    return normalize_human_text("\n".join(line for line in lines if line), max_chars)


def extract_markup_ui_text(text: str, max_chars: int = 4000):
    import html as html_lib

    values = []
    attr_names = (
        "android:text", "android:hint", "android:contentDescription",
        "aria-label", "alt", "title", "placeholder", "label",
        "text", "summary", "description", "name", "value",
    )
    attr_pattern = "|".join(re.escape(name) for name in attr_names)
    for match in re.finditer(rf"""(?i)\b(?:{attr_pattern})\s*=\s*(['"])(.*?)\1""", str(text or ""), re.DOTALL):
        value = html_lib.unescape(match.group(2)).strip()
        if value and not value.startswith("@") and not value.startswith("$") and len(value) >= 2:
            values.append(value)
    return normalize_human_text("\n".join(dict.fromkeys(values)), max_chars)


def extract_source_comment_text(text: str, ext: str, max_chars: int = 4000):
    source = str(text or "")
    comments = []
    for match in re.finditer(r"(?s)/\*+(.*?)\*/", source):
        comments.append(match.group(1))
    for line in source.splitlines():
        stripped = line.strip()
        marker = ""
        if stripped.startswith("//"):
            marker = "//"
        elif ext in {".py", ".rb"} and stripped.startswith("#"):
            marker = "#"
        if marker:
            comment = stripped[len(marker):].strip()
            if comment:
                comments.append(comment)
    cleaned_comments = []
    for comment in comments:
        cleaned = re.sub(r"^\s*[*#/\-]+\s?", "", comment.strip(), flags=re.MULTILINE)
        cleaned = normalize_human_text(cleaned, 800)
        if cleaned and not cleaned.startswith("<") and len(cleaned) >= 4:
            cleaned_comments.append(cleaned)
    return normalize_human_text("\n\n".join(dict.fromkeys(cleaned_comments)), max_chars)


def extract_source_ui_literals(text: str, max_chars: int = 4000):
    source = str(text or "")
    values = []
    key_pattern = r"(?:title|label|message|placeholder|description|summary|tooltip|button|heading|caption|error|empty|success|warning|help|text)"
    assignment = rf"""(?i)\b{key_pattern}\b[^=\n:]*[:=]\s*(['"`])(.{{3,240}}?)\1"""
    object_value = rf"""(?i)(['"]){key_pattern}\1\s*:\s*(['"`])(.{{3,240}}?)\2"""
    call_value = rf"""(?i)\b(?:setText|setTitle|setMessage|setContentDescription|toast|alert)\s*\(\s*(['"`])(.{{3,240}}?)\1"""
    for pattern, group_index in ((assignment, 2), (object_value, 3), (call_value, 2)):
        for match in re.finditer(pattern, source, re.DOTALL):
            value = match.group(group_index).strip()
            if re.search(r"[A-Za-z]{3,}", value) and not re.search(r"^[A-Za-z0-9_.-]+$", value):
                values.append(value)
    return normalize_human_text("\n".join(dict.fromkeys(values)), max_chars)


def extract_json_text_values(text: str, max_chars: int = 4000):
    interesting_keys = {
        "title", "label", "name", "description", "summary", "message", "text",
        "placeholder", "tooltip", "help", "caption", "heading", "alt",
    }
    values = []

    def walk(value, key=""):
        if isinstance(value, dict):
            for child_key, child_value in value.items():
                walk(child_value, str(child_key).lower())
        elif isinstance(value, list):
            for child in value:
                walk(child, key)
        elif isinstance(value, str) and key in interesting_keys and re.search(r"[A-Za-z]{3,}", value):
            values.append(value)

    try:
        walk(json.loads(text))
    except Exception:
        return ""
    return normalize_human_text("\n".join(dict.fromkeys(values)), max_chars)


def extract_yaml_properties_text(text: str, max_chars: int = 4000):
    values = []
    key_pattern = r"(title|label|name|description|summary|message|text|placeholder|tooltip|help|caption|heading|alt)"
    for line in str(text or "").splitlines():
        match = re.match(rf"\s*{key_pattern}\s*[:=]\s*['\"]?(.+?)['\"]?\s*$", line, flags=re.IGNORECASE)
        if match:
            value = match.group(2).strip()
            if re.search(r"[A-Za-z]{3,}", value):
                values.append(value)
    return normalize_human_text("\n".join(dict.fromkeys(values)), max_chars)


def extract_human_text_from_file(text: str, rel_path: str, ext: str, max_chars: int = 5000):
    ext = ext.lower()
    lower_path = str(rel_path or "").lower()
    
    if ext in {".html", ".htm", ".xhtml"}:
        visible_text = extract_html_visible_text(text, max_chars)
        return normalize_human_text(visible_text, max_chars), "ui_text"
    
    
    if ext == ".xml":
        return extract_markup_ui_text(text, max_chars), "ui_text"
    if ext == ".json":
        return extract_json_text_values(text, max_chars), "ui_text"
    if ext in {".yaml", ".yml", ".properties", ".strings", ".resx"}:
        return extract_yaml_properties_text(text, max_chars), "ui_text"
    if ext in REPO_UI_TEXT_SOURCE_EXTENSIONS:
        comments = extract_source_comment_text(text, ext, max_chars // 2)
        ui_literals = extract_source_ui_literals(text, max_chars // 2)
        return normalize_human_text("\n\n".join(item for item in (comments, ui_literals) if item), max_chars), "comments_ui_text"
    if "readme" in lower_path or ext in REPO_TEXT_EXTENSIONS:
        return clean_repo_text(text, max_chars), repo_text_kind(rel_path)
    return "", "text"


def clean_repo_text(text: str, max_chars: int = 4000):
    lines = []
    in_code_fence = False
    for raw_line in str(text or "").splitlines():
        line = raw_line.rstrip()
        stripped = line.strip()
        if stripped.startswith("```") or stripped.startswith("~~~"):
            in_code_fence = not in_code_fence
            continue
        if in_code_fence:
            continue
        if not stripped:
            if lines and lines[-1]:
                lines.append("")
            continue
        if re.match(r"^\s*(\||[-*:]+\s*$)", line):
            continue
        lines.append(line)
        if sum(len(item) + 1 for item in lines) >= max_chars:
            break
    cleaned = "\n".join(lines).strip()
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    return cleaned[:max_chars]


def extract_repo_text(
        repo_src, 
        limit=None, 
        max_file_bytes=None, 
        max_item_chars=None, 
        max_total_chars=None,
        progress_callback=None):
    limit = int(os.getenv("REPO_TEXT_ITEM_LIMIT", str(limit or 350)) or 350)
    max_file_bytes = int(os.getenv("REPO_TEXT_MAX_FILE_BYTES", str(max_file_bytes or 400_000)) or 400_000)
    max_item_chars = int(os.getenv("REPO_TEXT_MAX_ITEM_CHARS", str(max_item_chars or 6000)) or 6000)
    max_total_chars = int(os.getenv("REPO_TEXT_MAX_TOTAL_CHARS", str(max_total_chars or 800_000)) or 800_000)
    items = []
    total_chars_seen = 0
    total_chars_indexed = 0
    skipped_large_files = 0
    processed_files = 0

    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), repo_src)]
        dirs.sort()
        files = sorted(
            files,
            key=lambda name: (
                0 if Path(name.lower()).stem == "readme" else 1,
                0 if os.path.splitext(name)[1].lower() in REPO_TEXT_EXTENSIONS else 1,
                name.lower(),
            ),
        )
        for filename in files:
            path = os.path.join(root, filename)
            ext = os.path.splitext(filename)[1].lower()
            lower_name = filename.lower()
            lower_stem = Path(lower_name).stem
            is_named_text_file = lower_name in REPO_TEXT_PRIORITY_NAMES or lower_stem in REPO_TEXT_PRIORITY_NAMES
            is_extractable_source = ext in REPO_UI_TEXT_SOURCE_EXTENSIONS
            if (ext not in REPO_TEXT_EXTENSIONS and not is_named_text_file and not is_extractable_source) or should_skip_path(path, repo_src):
                continue
            processed_files += 1
            rel_path = os.path.relpath(path, repo_src).replace("\\", "/")
            progress(f"Reading repository text from file {processed_files}.", current_file=rel_path)
            try:
                size = os.path.getsize(path)
                if size > max_file_bytes:
                    skipped_large_files += 1
                    progress(f"Skipping large text file ({size:,} bytes).", current_file=rel_path)
                    continue
                text = Path(path).read_text(encoding="utf-8", errors="ignore")
            except OSError:
                continue

            cleaned, kind = extract_human_text_from_file(text, rel_path, ext, max_item_chars)
            if not cleaned:
                continue

            total_chars_seen += len(text)
            item = {
                "kind": kind,
                "file": rel_path,
                "line": 1,
                "text": cleaned,
                "char_count": len(text),
                "indexed_char_count": len(cleaned),
            }
            items.append(item)
            total_chars_indexed += len(cleaned)
            if len(items) >= limit or total_chars_indexed >= max_total_chars:
                break
        if len(items) >= limit or total_chars_indexed >= max_total_chars:
            break

    def priority(item):
        kind_rank = {"readme": 0, "document": 1, "text": 2}.get(item.get("kind"), 3)
        return (kind_rank, item.get("file", "").count("/"), item.get("file", "").lower())

    items.sort(key=priority)
    readme_items = [item for item in items if item["kind"] == "readme"]
    document_items = [item for item in items if item["kind"] in {"document", "html_text"}]
    text_items = [item for item in items if item["kind"] in {"text", "comments_ui_text"}]
    ui_text_items = [item for item in items if item["kind"] == "ui_text"]
    return {
        "generated_at": datetime.now().isoformat(),
        "source": "downloaded_repository_text_files",
        "supported_extensions": sorted(REPO_TEXT_EXTENSIONS),
        "supported_source_extensions": sorted(REPO_UI_TEXT_SOURCE_EXTENSIONS),
        "item_count": len(items),
        "readme_count": len(readme_items),
        "document_count": len(document_items),
        "text_file_count": len(text_items),
        "ui_text_count": len(ui_text_items),
        "total_chars_seen": total_chars_seen,
        "total_chars_indexed": total_chars_indexed,
        "skipped_large_files": skipped_large_files,
        "readme_items": readme_items,
        "document_items": document_items,
        "text_items": text_items,
        "ui_text_items": ui_text_items,
    }


def extract_repo_comments(repo_src, limit=500, progress_callback=None):
    comments = []
    todos = []
    files_with_comments = set()
    in_block = False
    block_start = 0
    block_parts = []
    processed_files = 0

    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    def add_comment(rel_path, line_no, kind, text):
        cleaned = text.strip()
        if not cleaned:
            return
        # Ignore bare XML/HTML tags like <module name="..."/> which are not comments
        if cleaned.startswith("<") and not cleaned.startswith("<!--") and cleaned.endswith(">"):
            return
        files_with_comments.add(rel_path)
        if len(comments) < limit:
            comments.append({
                "file": rel_path,
                "line": line_no,
                "kind": kind,
                "text": cleaned,
            })
        match = TODO_RE.search(cleaned)
        if match and not is_false_todo_item(rel_path, match.group(2).strip() or cleaned):
            todos.append({
                "tag": match.group(1).upper(),
                "file": rel_path,
                "line": line_no,
                "text": match.group(2).strip() or cleaned,
            })

    for root, dirs, files in os.walk(repo_src):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), repo_src)]
        for filename in files:
            ext = os.path.splitext(filename)[1].lower()
            if ext not in COMMENT_EXTENSIONS:
                continue
            path = os.path.join(root, filename)
            if should_skip_path(path, repo_src):
                continue
            rel_path = os.path.relpath(path, repo_src).replace("\\", "/")
            processed_files += 1
            progress(f"Extracting comments from file {processed_files}.", current_file=rel_path)
            in_block = False
            block_start = 0
            block_parts = []
            try:
                with open(path, "r", encoding="utf-8", errors="ignore") as fh:
                    for line_no, line in enumerate(fh, start=1):
                        stripped = line.strip()

                        if in_block:
                            end = stripped.find("*/")
                            if end >= 0:
                                block_parts.append(stripped[:end])
                                add_comment(rel_path, block_start, "block", " ".join(block_parts))
                                in_block = False
                                block_parts = []
                                stripped = stripped[end + 2:].strip()
                            else:
                                block_parts.append(stripped)
                                continue

                        if stripped.startswith("/*"):
                            end = stripped.find("*/", 2)
                            if end >= 0:
                                add_comment(rel_path, line_no, "block", stripped[2:end])
                            else:
                                in_block = True
                                block_start = line_no
                                block_parts = [stripped[2:]]
                            continue

                        for marker, kind in (("//", "line"), ("#", "line"), ("<!--", "block")):
                            idx = stripped.find(marker)
                            if idx >= 0:
                                text = stripped[idx + len(marker):]
                                if marker == "<!--":
                                    text = text.split("-->", 1)[0]
                                add_comment(rel_path, line_no, kind, text)
                                break
            except OSError:
                continue

    return {
        "comment_count": len(comments),
        "todo_count": len(todos),
        "files_with_comments_count": len(files_with_comments),
        "supported_comment_forms": ["//", "#", "/* */", "<!-- -->"],
        "comments": comments,
        "todos": todos[:200],
    }


def write_json_artifact(data, output_repo_dir, filename):
    path = repo_text_artifact_path(output_repo_dir, filename) if filename in REPO_TEXT_ARTIFACT_FILENAMES else Path(output_repo_dir) / filename
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)
    return str(path)


def load_repo_text_artifact(output_repo_dir):
    path = repo_text_artifact_path(output_repo_dir, "repo_text.json", legacy_ok=True)
    if not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception as e:
        logger.warning("Unable to load repo text artifact: %s", e)
        return {}





def build_scim_artifacts_old(output_repo_dir, owner="", repo="", repo_info=None, default_branch="", repo_text=None, source_dir=None, progress_callback=None):
    return {}
    scim_enabled = os.getenv("ENABLE_SCIM", "true").lower() not in {"0", "false", "no", "off"}
    if not scim_enabled:
        return {}
    try:
        from scim import feature_catalog_payload, write_dataset
    except Exception as e:
        logger.warning("SCIM import failed; skipping embedding artifacts: %s", e)
        return {"scim_error": str(e)}

    output_dir = Path(output_repo_dir) / "scim"
    if repo_text is None:
        repo_text = load_repo_text_artifact(output_repo_dir)
    repo_context = build_repo_context(owner, repo, repo_info, default_branch, repo_text)
    
    #source_root = Path(source_dir or find_cached_source_dir(output_repo_dir) or output_repo_dir)

    # =========================================================
    # SOURCE ROOT
    # MUST point to extracted repository source code
    # NEVER artifact output directories
    # =========================================================
    resolved_source = (
        source_dir
        or find_cached_source_dir(output_repo_dir)
    )
    if not resolved_source:
        raise RuntimeError(
            "No repository source directory found. "
            "Refusing to index artifact/output directory."
        )
    source_root = Path(resolved_source).resolve()
    project_root = PROJECT_ROOT.resolve()
    # =========================================================
    # SAFETY:
    # NEVER INDEX THE SERVER ITSELF
    # =========================================================
    if str(source_root).startswith(
        str(project_root)
    ):
        raise RuntimeError(
            f"Refusing to index PROJECT_ROOT: "
            f"{source_root}"
        )

    logger.info(
    "SCIM indexing source_root=%s",
    source_root
    )


    evidence_result = {}
    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file or "")
        except TypeError:
            progress_callback(message)

    try:
        progress("Building search and feature artifacts from source files.", current_file="")

        logger.info(
            "SCIM indexing source_root=%s",
            source_root
        )
        write_dataset(
            input_root=source_root,
            output_dir=output_dir,
            include_code=True,
            backend="tfidf",
            make_vector_db=True,
            make_faiss=False,
            sbert_model=None,
            batch_size=32,
            generic_graphs=True,
            max_chunks_per_repo=int(os.getenv("SCIM_MAX_CHUNKS_PER_REPO", "3000")),
            max_file_bytes=int(os.getenv("SCIM_MAX_FILE_BYTES", "300000")),
            max_record_code_chars=int(os.getenv("SCIM_MAX_RECORD_CODE_CHARS", "2000")),
            progress_callback=progress,
        )
        progress("Deriving product feature summaries from the search model.", current_file="")
        feature_data = feature_catalog_payload(output_dir, None, examples=5, repo_context=repo_context)
        architecture_dir = architecture_dir_for_output(output_repo_dir)
        feature_path = architecture_dir / "feature_catalog.json"
        feature_path.write_text(json.dumps(feature_data, indent=2), encoding="utf-8")
        progress("Skipping disabled static quality signal generation.", current_file="")
        quality_signal_path = ensure_static_quality_signals(output_repo_dir)
        progress("Writing generated evidence as architecture artifacts.", current_file="")
        evidence_result = index_typed_scim_evidence(output_repo_dir)
        layer_manifest_path = write_scim_layer_manifest(Path(output_repo_dir), evidence_result)
        callgraph_code_result = build_callgraph_code_index(output_repo_dir)
    except Exception as e:
        logger.warning("SCIM artifact build failed; search will fall back to graph search: %s", e)
        return {"scim_error": str(e)}

    logger.info("SCIM artifacts written: %s", output_dir)
    return {
        "scim_dir": str(output_dir),
        "scim_manifest_path": str(architecture_dir_for_output(output_repo_dir) / "manifest.json"),
        "scim_vector_db_path": str(output_dir / "vectors.sqlite"),
        "scim_embedding_model_path": str(output_dir / "embedding_model.json"),
        "scim_functions_path": str(output_dir / "functions.jsonl"),
        "scim_train_pairs_path": str(architecture_dir_for_output(output_repo_dir) / "train_pairs.jsonl"),
        "feature_catalog_path": str(architecture_dir_for_output(output_repo_dir) / "feature_catalog.json"),
        "typed_evidence_indexed": evidence_result.get("indexed", 0) if isinstance(evidence_result, dict) else 0,
        "scim_layer_manifest_path": layer_manifest_path,
        "callgraph_code_index_path": callgraph_code_result.get("path", "") if isinstance(callgraph_code_result, dict) else "",
        "callgraph_code_index_jsonl_path": callgraph_code_result.get("jsonl_path", "") if isinstance(callgraph_code_result, dict) else "",
        "callgraph_code_indexed": callgraph_code_result.get("indexed", 0) if isinstance(callgraph_code_result, dict) else 0,
        "static_quality_signals_path": quality_signal_path,
    }


def scim_artifacts_current(scim_manifest_path):
    if not scim_manifest_path or not os.path.exists(scim_manifest_path):
        return False
    try:
        from scim import SCIM_EXTRACTOR_VERSION
        with open(scim_manifest_path, "r", encoding="utf-8") as f:
            manifest = json.load(f)
        return int(manifest.get("extractor_version", 0)) >= int(SCIM_EXTRACTOR_VERSION)
    except Exception:
        return False


def latest_source_mtime(src_dir, extensions=None):
    """Latest mtime among files under src_dir. If `extensions` is given (a set
    of lowercase suffixes, e.g. {".py"}), only those files count — so editing
    a Java file doesn't make a Python-only staleness check look stale, and
    vice versa. `extensions=None` keeps the old whole-tree behavior, for
    checks that intentionally care about any language changing at once
    (e.g. the combined multi-language graph_artifacts_current check)."""
    if not src_dir or not os.path.isdir(src_dir):
        return 0.0
    latest = 0.0
    for root, dirs, files in os.walk(src_dir):
        dirs[:] = [d for d in dirs if not should_skip_path(os.path.join(root, d), src_dir)]
        for filename in files:
            if extensions is not None and os.path.splitext(filename)[1].lower() not in extensions:
                continue
            path = os.path.join(root, filename)
            if should_skip_path(path, src_dir):
                continue
            try:
                latest = max(latest, os.path.getmtime(path))
            except OSError:
                continue
    return latest


def artifacts_newer_than_source(paths, src_dir, extensions=None):
    latest_source = latest_source_mtime(src_dir, extensions=extensions)
    if not latest_source:
        return True
    existing_paths = [Path(path) for path in paths if path and os.path.exists(path)]
    if not existing_paths:
        return False
    try:
        return min(path.stat().st_mtime for path in existing_paths) >= latest_source
    except OSError:
        return False


def scim_artifacts_current_for_source(scim_manifest_path, src_dir):
    if not scim_artifacts_current(scim_manifest_path):
        return False
    dataset_dir = Path(scim_manifest_path).parent
    artifact_root = dataset_dir.parent if dataset_dir.name == "architecture" else dataset_dir.parent
    required = [
        artifact_root / "scim" / "functions.jsonl",
        artifact_root / "scim" / "vectors.sqlite",
        artifact_root / "scim" / "embedding_model.json",
        artifact_root / "architecture" / "feature_catalog.json",
    ]
    return artifacts_newer_than_source(required, src_dir)


def repo_cache_token(repo_info: dict, default_branch: str = ""):
    raw = (
        (repo_info or {}).get("pushed_at")
        or (repo_info or {}).get("updated_at")
        or (repo_info or {}).get("default_branch")
        or default_branch
        or "latest"
    )
    return hashlib.sha1(str(raw).encode("utf-8", errors="ignore")).hexdigest()[:12]


def repo_zip_cache_path(owner: str, repo: str, default_branch: str, repo_info: dict | None = None):
    safe_owner = safe_upload_name(owner, "owner")
    safe_repo = safe_upload_name(repo, "repo")
    safe_branch = safe_upload_name(default_branch or "default", "branch")
    token = repo_cache_token(repo_info or {}, default_branch)
    return os.path.join(BASE_OUTPUT, "cache", f"{safe_owner}_{safe_repo}_{safe_branch}_{token}.zip")


def repo_zip_cache_metadata_path(zip_path) -> Path:
    return Path(f"{zip_path}.json")


def repo_zip_cache_prefix(owner: str, repo: str, default_branch: str) -> Path:
    safe_owner = safe_upload_name(owner, "owner")
    safe_repo = safe_upload_name(repo, "repo")
    safe_branch = safe_upload_name(default_branch or "default", "branch")
    return Path(BASE_OUTPUT) / "cache" / f"{safe_owner}_{safe_repo}_{safe_branch}_"


def load_repo_zip_cache_metadata(zip_path) -> dict:
    metadata_path = repo_zip_cache_metadata_path(zip_path)
    if not metadata_path.exists():
        return {}
    try:
        with open(metadata_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception as e:
        logger.warning("Unable to read repository ZIP cache metadata %s: %s", metadata_path, e)
        return {}


def write_repo_zip_cache_metadata(zip_path, owner: str, repo: str, default_branch: str, repo_info: dict | None, response=None):
    metadata = {
        "owner": owner,
        "repo": repo,
        "default_branch": default_branch or "",
        "cache_token": repo_cache_token(repo_info or {}, default_branch),
        "repo_pushed_at": (repo_info or {}).get("pushed_at") or "",
        "repo_updated_at": (repo_info or {}).get("updated_at") or "",
        "github_default_branch": (repo_info or {}).get("default_branch") or "",
        "saved_at": datetime.now(timezone.utc).isoformat(),
    }
    if response is not None:
        metadata.update({
            "etag": response.headers.get("ETag", ""),
            "last_modified": response.headers.get("Last-Modified", ""),
            "content_length": response.headers.get("Content-Length", ""),
            "content_type": response.headers.get("Content-Type", ""),
            "final_url": getattr(response, "url", "") or "",
        })
    metadata_path = repo_zip_cache_metadata_path(zip_path)
    metadata_path.parent.mkdir(parents=True, exist_ok=True)
    with open(metadata_path, "w", encoding="utf-8") as f:
        json.dump(metadata, f, indent=2)
    return metadata


def find_previous_repo_zip_cache(owner: str, repo: str, default_branch: str) -> Path | None:
    prefix = repo_zip_cache_prefix(owner, repo, default_branch)
    cache_dir = prefix.parent
    if not cache_dir.exists():
        return None
    candidates = [
        path for path in cache_dir.glob(f"{prefix.name}*.zip")
        if path.is_file()
    ]
    if not candidates:
        return None
    return max(candidates, key=lambda path: path.stat().st_mtime)


def github_remote_source_enabled():
    mode = repo_source_mode()
    if mode == "zip":
        return False
    if mode == "remote":
        return True
    return normalize_env_value(os.getenv("CODEVAL_REMOTE_SOURCE_ENABLED", "true")).lower() not in {"0", "false", "no", "off"}


def repo_source_mode():
    value = normalize_env_value(os.getenv("CODEVAL_REPO_SOURCE_MODE", "auto")).lower()
    aliases = {
        "archive": "zip",
        "download_zip": "zip",
        "tree": "remote",
        "trees": "remote",
        "git_tree": "remote",
        "git_trees": "remote",
        "github_tree": "remote",
        "github_trees": "remote",
        "enumerate": "remote",
    }
    value = aliases.get(value, value)
    if value not in {"auto", "zip", "remote"}:
        logger.warning("Unknown CODEVAL_REPO_SOURCE_MODE=%r; using auto.", value)
        return "auto"
    return value


def should_prefer_remote_source(repo_info: dict | None):
    mode = repo_source_mode()
    if mode == "remote":
        return True
    if mode == "zip" or not github_remote_source_enabled():
        return False
    threshold = REMOTE_SOURCE_REPO_SIZE_KB_THRESHOLD
    if threshold <= 0:
        return False
    try:
        repo_size_kb = int((repo_info or {}).get("size") or 0)
    except (TypeError, ValueError):
        repo_size_kb = 0
    return repo_size_kb > threshold


def should_background_analyze_repo(repo_info: dict | None):
    return repo_source_mode() == "remote" or should_prefer_remote_source(repo_info)


def remote_source_allowed_extensions():
    return (
        ALLOWED_CODE_EXTENSIONS
        | HTML_UI_EXTENSIONS_FOR_ANALYSIS
        | REPO_TEXT_EXTENSIONS
        | REPO_UI_TEXT_SOURCE_EXTENSIONS
    )


def should_fetch_remote_source_path(path: str):
    normalized = str(path or "").replace("\\", "/").strip("/")
    if not normalized or should_skip_path(normalized):
        return False
    filename = posixpath.basename(normalized).lower()
    stem = posixpath.splitext(filename)[0]
    ext = posixpath.splitext(filename)[1].lower()
    return ext in remote_source_allowed_extensions() or filename in REPO_TEXT_PRIORITY_NAMES or stem in REPO_TEXT_PRIORITY_NAMES


def safe_remote_source_target(root: Path, rel_path: str):
    parts = []
    for part in str(rel_path or "").replace("\\", "/").split("/"):
        part = part.strip()
        if not part or part in {".", ".."}:
            continue
        safe = re.sub(r'[<>:"\\|?*\x00-\x1f]', "_", part).rstrip(" .")
        if not safe:
            safe = "_"
        if len(safe) > 150:
            stem, suffix = os.path.splitext(safe)
            digest = hashlib.sha1(safe.encode("utf-8", errors="ignore")).hexdigest()[:12]
            suffix = suffix[:24]
            keep = max(1, 150 - len(digest) - len(suffix) - 1)
            safe = f"{stem[:keep]}_{digest}{suffix}"
        parts.append(safe)
    if not parts:
        return None
    target = (root / Path(*parts)).resolve()
    if root.resolve() not in target.parents:
        return None
    return target


def github_api_get_json(url: str, headers: dict, description: str):
    resp = requests.get(url, headers=headers, timeout=GITHUB_REQUEST_TIMEOUT)
    if headers.get("Authorization") and resp.status_code in (401, 403):
        logger.warning("GitHub %s request failed with auth: status=%s; retrying without auth", description, resp.status_code)
        resp = requests.get(url, headers=github_headers(""), timeout=GITHUB_REQUEST_TIMEOUT)
    if resp.status_code != 200:
        message = ""
        try:
            message = resp.json().get("message", "")
        except Exception:
            message = resp.text[:160]
        detail = f"GitHub {description} request failed with {resp.status_code}"
        if message:
            detail = f"{detail}: {message}"
        raise RuntimeError(detail)
    return resp.json()


def raw_github_content_url(owner: str, repo: str, ref: str, path: str):
    safe_ref = quote(str(ref or "HEAD"), safe="")
    safe_path = quote(str(path or "").replace("\\", "/").lstrip("/"), safe="/")
    return f"https://raw.githubusercontent.com/{owner}/{repo}/{safe_ref}/{safe_path}"


def fetch_raw_github_file(owner: str, repo: str, ref: str, path: str):
    url = raw_github_content_url(owner, repo, ref, path)
    headers = {"User-Agent": "CodeVal"}
    resp = requests.get(url, headers=headers, stream=True, timeout=GITHUB_REQUEST_TIMEOUT)
    if resp.status_code != 200:
        message = resp.text[:160] if not resp.raw.closed else ""
        raise RuntimeError(f"raw.githubusercontent.com returned {resp.status_code} for {path}. {message}".strip())
    try:
        content_length = int(resp.headers.get("Content-Length") or 0)
    except (TypeError, ValueError):
        content_length = 0
    if content_length > REMOTE_SOURCE_MAX_FILE_BYTES:
        raise RuntimeError(f"Raw file is too large ({content_length:,} bytes).")
    chunks = []
    bytes_read = 0
    for chunk in resp.iter_content(chunk_size=8192):
        if not chunk:
            continue
        bytes_read += len(chunk)
        if bytes_read > REMOTE_SOURCE_MAX_FILE_BYTES:
            raise RuntimeError(f"Raw file exceeded {REMOTE_SOURCE_MAX_FILE_BYTES:,} byte limit.")
        chunks.append(chunk)
    return b"".join(chunks)


def fetch_github_blob_file(owner: str, repo: str, item: dict, headers: dict):
    blob_url = item.get("url") or f"https://api.github.com/repos/{owner}/{repo}/git/blobs/{item['sha']}"
    blob = github_api_get_json(blob_url, headers, "blob")
    encoding = str(blob.get("encoding") or "").lower()
    content = str(blob.get("content") or "")
    if encoding != "base64" or not content:
        raise RuntimeError("GitHub blob response did not contain base64 file content.")
    return base64.b64decode(content, validate=False)


def fetch_remote_source_file_content(owner: str, repo: str, ref: str, item: dict, headers: dict):
    path = str(item.get("path") or "")
    try:
        return fetch_raw_github_file(owner, repo, ref, path), "raw"
    except Exception as raw_error:
        logger.info("Raw GitHub content fetch failed for %s/%s:%s; falling back to blob API: %s", owner, repo, path, raw_error)
    return fetch_github_blob_file(owner, repo, item, headers), "blob_api"


def download_github_remote_source(owner: str, repo: str, default_branch: str, output_repo_dir: str, headers: dict, progress_callback=None):
    """
    Build a sparse local source tree from read-only GitHub tree/blob and raw content calls.
    This is not a checkout; it downloads only filtered source/text blobs one file at a time.
    """
    src_root = Path(output_repo_dir) / "src" / f"{safe_upload_name(repo, 'repo')}-{safe_upload_name(default_branch or 'default', 'branch')}-remote"
    src_root.mkdir(parents=True, exist_ok=True)

    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    ref = quote(default_branch or "HEAD", safe="")
    tree_url = f"https://api.github.com/repos/{owner}/{repo}/git/trees/{ref}?recursive=1"
    progress("Reading GitHub repository tree without downloading ZIP.")
    tree_payload = github_api_get_json(tree_url, headers, "tree")
    tree_entries = tree_payload.get("tree") if isinstance(tree_payload, dict) else []
    if not isinstance(tree_entries, list):
        tree_entries = []

    selected = []
    skipped_large = 0
    skipped_unsupported = 0
    for entry in tree_entries:
        if not isinstance(entry, dict) or entry.get("type") != "blob":
            continue
        path = str(entry.get("path") or "")
        if not should_fetch_remote_source_path(path):
            skipped_unsupported += 1
            continue
        try:
            size = int(entry.get("size") or 0)
        except (TypeError, ValueError):
            size = 0
        if size > REMOTE_SOURCE_MAX_FILE_BYTES:
            skipped_large += 1
            continue
        selected.append({
            "path": path,
            "sha": str(entry.get("sha") or ""),
            "size": size,
            "url": str(entry.get("url") or ""),
        })

    selected.sort(key=lambda item: (
        0 if posixpath.basename(item["path"]).lower().startswith("readme") else 1,
        item["path"].count("/"),
        item["path"].lower(),
    ))

    downloaded = 0
    total_bytes = 0
    skipped_limits = 0
    raw_downloaded = 0
    blob_api_downloaded = 0
    empty_downloaded = 0
    files = []
    for item in selected:
        if downloaded >= REMOTE_SOURCE_MAX_FILES or total_bytes + item["size"] > REMOTE_SOURCE_MAX_TOTAL_BYTES:
            skipped_limits += 1
            continue
        if not item["sha"]:
            skipped_limits += 1
            continue
        target = safe_remote_source_target(src_root, item["path"])
        if target is None:
            skipped_limits += 1
            continue
        progress(f"Reading GitHub source file {downloaded + 1}.", current_file=item["path"])
        if item["size"] == 0:
            # Empty blobs are valid repository files. GitHub's blob response has
            # an empty content field, so no content request is necessary.
            data, content_source = b"", "tree_empty"
        else:
            try:
                data, content_source = fetch_remote_source_file_content(owner, repo, default_branch or "HEAD", item, headers)
            except Exception as e:
                logger.warning("Unable to fetch GitHub source file %s/%s:%s: %s", owner, repo, item["path"], e)
                skipped_limits += 1
                continue
        if len(data) > REMOTE_SOURCE_MAX_FILE_BYTES or total_bytes + len(data) > REMOTE_SOURCE_MAX_TOTAL_BYTES:
            skipped_limits += 1
            continue
        target.parent.mkdir(parents=True, exist_ok=True)
        with open(target, "wb") as f:
            f.write(data)
        downloaded += 1
        total_bytes += len(data)
        if content_source == "raw":
            raw_downloaded += 1
        elif content_source == "blob_api":
            blob_api_downloaded += 1
        else:
            empty_downloaded += 1
        files.append({"path": item["path"], "bytes": len(data), "sha": item["sha"], "content_source": content_source})

    if downloaded == 0:
        raise RuntimeError("GitHub remote source fallback did not download any supported source files.")

    metadata = {
        "source": "github_remote_tree_blobs",
        "owner": owner,
        "repo": repo,
        "default_branch": default_branch or "",
        "tree_truncated": bool(tree_payload.get("truncated")) if isinstance(tree_payload, dict) else False,
        "tree_entry_count": len(tree_entries),
        "selected_file_count": len(selected),
        "downloaded_file_count": downloaded,
        "raw_downloaded_file_count": raw_downloaded,
        "blob_api_downloaded_file_count": blob_api_downloaded,
        "empty_file_count": empty_downloaded,
        "downloaded_bytes": total_bytes,
        "skipped_large_files": skipped_large,
        "skipped_unsupported_files": skipped_unsupported,
        "skipped_limit_or_decode_files": skipped_limits,
        "max_files": REMOTE_SOURCE_MAX_FILES,
        "max_file_bytes": REMOTE_SOURCE_MAX_FILE_BYTES,
        "max_total_bytes": REMOTE_SOURCE_MAX_TOTAL_BYTES,
        "files": files[:1000],
    }
    metadata_path = Path(output_repo_dir) / "remote_source_manifest.json"
    with open(metadata_path, "w", encoding="utf-8") as f:
        json.dump(metadata, f, indent=2)
    progress(f"GitHub remote source loaded: {downloaded} files, {total_bytes:,} bytes.")
    return str(src_root), metadata


def download_or_reuse_repo_zip(owner: str, repo: str, default_branch: str, repo_info: dict | None, headers: dict):
    zip_url = f"https://api.github.com/repos/{owner}/{repo}/zipball/{default_branch}"
    cache_zip = Path(repo_zip_cache_path(owner, repo, default_branch, repo_info))
    cache_zip.parent.mkdir(parents=True, exist_ok=True)

    current_token = repo_cache_token(repo_info or {}, default_branch)
    if cache_zip.exists():
        metadata = load_repo_zip_cache_metadata(cache_zip)
        if not metadata:
            write_repo_zip_cache_metadata(cache_zip, owner, repo, default_branch, repo_info)
        return str(cache_zip), True, "Using cached repository ZIP."

    previous_zip = find_previous_repo_zip_cache(owner, repo, default_branch)
    conditional_headers = dict(headers or {})
    previous_metadata = load_repo_zip_cache_metadata(previous_zip) if previous_zip else {}
    if previous_zip and previous_metadata.get("cache_token") == current_token:
        return str(previous_zip), True, "Using cached repository ZIP."
    if previous_metadata.get("etag"):
        conditional_headers["If-None-Match"] = previous_metadata["etag"]
    if previous_metadata.get("last_modified"):
        conditional_headers["If-Modified-Since"] = previous_metadata["last_modified"]

    resp = requests.get(zip_url, headers=conditional_headers, stream=True, timeout=GITHUB_REQUEST_TIMEOUT)
    if conditional_headers.get("Authorization") and resp.status_code in (401, 403):
        logger.warning(
            "GitHub ZIP request failed with auth for %s/%s: status=%s; retrying without auth",
            owner,
            repo,
            resp.status_code,
        )
        public_headers = github_headers("")
        if previous_metadata.get("etag"):
            public_headers["If-None-Match"] = previous_metadata["etag"]
        if previous_metadata.get("last_modified"):
            public_headers["If-Modified-Since"] = previous_metadata["last_modified"]
        resp = requests.get(zip_url, headers=public_headers, stream=True, timeout=GITHUB_REQUEST_TIMEOUT)
    if resp.status_code == 304 and previous_zip and previous_zip.exists():
        write_repo_zip_cache_metadata(previous_zip, owner, repo, default_branch, repo_info, resp)
        return str(previous_zip), True, "Repository ZIP unchanged; using cached ZIP."
    resp.raise_for_status()
    try:
        content_length = int(resp.headers.get("Content-Length") or 0)
    except (TypeError, ValueError):
        content_length = 0
    if REPO_ZIP_MAX_BYTES > 0 and content_length > REPO_ZIP_MAX_BYTES:
        raise RuntimeError(f"Repository ZIP is too large to download ({content_length:,} bytes > {REPO_ZIP_MAX_BYTES:,} byte limit).")

    temp_zip = cache_zip.with_suffix(".zip.tmp")
    bytes_written = 0
    try:
        with open(temp_zip, "wb") as f:
            for chunk in resp.iter_content(chunk_size=8192):
                if chunk:
                    bytes_written += len(chunk)
                    if REPO_ZIP_MAX_BYTES > 0 and bytes_written > REPO_ZIP_MAX_BYTES:
                        raise RuntimeError(f"Repository ZIP exceeded {REPO_ZIP_MAX_BYTES:,} byte download limit.")
                    f.write(chunk)
    except Exception:
        try:
            temp_zip.unlink(missing_ok=True)
        except OSError:
            pass
        raise
    os.replace(temp_zip, cache_zip)
    write_repo_zip_cache_metadata(cache_zip, owner, repo, default_branch, repo_info, resp)
    return str(cache_zip), False, "Repository ZIP downloaded."


def prepare_repository_source_dir(owner: str, repo: str, default_branch: str, repo_info: dict | None, headers: dict, output_repo_dir: str, progress_callback=None):
    mode = repo_source_mode()
    source_info = {"source": "downloaded_zip", "source_mode": mode}

    def progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    if should_prefer_remote_source(repo_info):
        reset_output_repo_dir(output_repo_dir)
        progress(
            "Using configured read-only GitHub file-by-file source instead of ZIP."
            if mode == "remote"
            else "Repository is large; using read-only GitHub file-by-file source instead of ZIP."
        )
        src_dir, metadata = download_github_remote_source(owner, repo, default_branch, output_repo_dir, headers, progress_callback=progress)
        source_info = {
            "source": "github_remote_tree_blobs",
            "source_mode": mode,
            "message": "Repository source loaded from GitHub tree/blob API without ZIP download.",
            "remote_source_manifest_path": str(Path(output_repo_dir) / "remote_source_manifest.json"),
            "remote_source": metadata,
        }
        return src_dir, source_info

    try:
        progress("Checking repository ZIP cache.")
        zip_path, reused_zip, zip_message = download_or_reuse_repo_zip(owner, repo, default_branch, repo_info, headers)
        progress(zip_message)
        reset_output_repo_dir(output_repo_dir)
        extracted_src_dir = os.path.join(output_repo_dir, "src")
        os.makedirs(extracted_src_dir, exist_ok=True)
        src_dir = extract_zip(zip_path, extracted_src_dir)
        source_info = {
            "source": "downloaded_zip",
            "source_mode": mode,
            "zip_path": zip_path,
            "reused_zip": reused_zip,
            "message": zip_message,
        }
        return src_dir, source_info
    except Exception as e:
        if not github_remote_source_enabled():
            raise
        logger.warning("Repository ZIP source failed for %s/%s; falling back to GitHub remote source: %s", owner, repo, e)
        reset_output_repo_dir(output_repo_dir)
        progress(f"Repository ZIP unavailable ({e}); using read-only GitHub file-by-file source.")
        src_dir, metadata = download_github_remote_source(owner, repo, default_branch, output_repo_dir, headers, progress_callback=progress)
        source_info = {
            "source": "github_remote_tree_blobs",
            "source_mode": mode,
            "zip_error": str(e),
            "message": "Repository source loaded from GitHub tree/blob API after ZIP failed.",
            "remote_source_manifest_path": str(Path(output_repo_dir) / "remote_source_manifest.json"),
            "remote_source": metadata,
        }
        return src_dir, source_info


def reset_output_repo_dir(output_repo_dir):
    target = Path(output_repo_dir).resolve()
    base = Path(BASE_OUTPUT).resolve()
    if target == base or base not in target.parents:
        raise RuntimeError(f"Refusing to clear output directory outside BASE_OUTPUT: {target}")
    if target.exists():
        remove_output_tree_safely(target)
    target.mkdir(parents=True, exist_ok=True)


def remove_output_tree_safely(target: Path, attempts: int = 3):
    target = Path(target)
    retryable_errors = {errno.ENOTEMPTY, 39, errno.EBUSY, errno.EACCES, errno.EPERM}
    last_error = None
    for attempt in range(max(1, attempts)):
        try:
            shutil.rmtree(target)
            return
        except FileNotFoundError:
            return
        except OSError as exc:
            last_error = exc
            if getattr(exc, "errno", None) not in retryable_errors:
                raise
            gc.collect()
            time.sleep(0.12 * (attempt + 1))

    quarantine = target.with_name(f"{target.name}.deleting.{uuid.uuid4().hex[:8]}")
    try:
        target.rename(quarantine)
    except FileNotFoundError:
        return
    except OSError:
        if last_error:
            raise last_error
        raise

    try:
        shutil.rmtree(quarantine)
    except Exception as exc:
        logger.warning("Unable to fully remove quarantined output directory %s: %s", quarantine, exc)


def cached_repo_matches_github(output_repo_dir, repo_info: dict | None):
    repo_stats_path = ensure_repo_text_artifact_path(output_repo_dir, "repo_stats.json")
    if not repo_info or not repo_stats_path.exists():
        return True
    try:
        with repo_stats_path.open("r", encoding="utf-8") as f:
            repo_stats = json.load(f)
        previous = (repo_stats.get("known_from_github_repo_metadata") or {})
    except Exception:
        return False
    for key in ("pushed_at", "updated_at"):
        current_value = str((repo_info or {}).get(key) or "")
        previous_value = str(previous.get(key) or "")
        if current_value and previous_value and current_value != previous_value:
            return False
    return True


def python_callgraph_current(python_callgraph_json, src_dir):
    if not python_callgraph_json or not os.path.exists(python_callgraph_json):
        return False
    try:
        with open(python_callgraph_json, "r", encoding="utf-8") as f:
            graph = json.load(f)
        return (
            isinstance(graph, dict)
            and graph.get("mode") == "python_semantic"
            and int(graph.get("version", 0) or 0) >= PYTHON_CALLGRAPH_VERSION
            and artifacts_newer_than_source([python_callgraph_json], src_dir, extensions={".py"})
        )
    except Exception:
        return False


def graph_artifact_info(graph_json_path):
    info = {"mode": "", "version": 0, "parser": "", "nodes": 0, "edges": 0}
    if not graph_json_path or not os.path.exists(graph_json_path):
        return info
    try:
        with open(graph_json_path, "r", encoding="utf-8") as f:
            graph = json.load(f)
        if not isinstance(graph, dict):
            return info
        nodes = graph.get("nodes") or []
        edges = graph.get("edges") or []
        info.update({
            "mode": str(graph.get("mode") or ""),
            "version": int(graph.get("version", 0) or 0),
            "parser": str(graph.get("parser") or graph.get("source") or ""),
            "nodes": len(nodes) if isinstance(nodes, list) else 0,
            "edges": len(edges) if isinstance(edges, list) else 0,
        })
    except Exception as e:
        logger.warning("Unable to read graph artifact info for %s: %s", graph_json_path, e)
    return info


def file_graph_current(file_graph_json):
    if not file_graph_json or not os.path.exists(file_graph_json):
        return False
    try:
        with open(file_graph_json, "r", encoding="utf-8") as f:
            graph = json.load(f)
        return (
            graph.get("mode") == "file_dependency_graph" and
            int(graph.get("version", 0)) >= FILE_GRAPH_VERSION and
            isinstance(graph.get("nodes"), list)
        )
    except Exception:
        return False


