def sanitize_id(s):
    # Keep only characters Cytoscape allows in IDs
    return re.sub(r'[^a-zA-Z0-9_\-]', '_', s)

def write_cytoscape_json(reduced, out_path):
    nodes = []
    edges = []

    for n in reduced["nodes"]:
        sid = sanitize_id(n)
        nodes.append({
            "data": {
                "id": sid,
                "label": n  # label can stay original
            }
        })

    for e in reduced["edges"]:
        caller = sanitize_id(e["caller"])
        callee = sanitize_id(e["callee"])

        edges.append({
            "data": {
                "id": f"{caller}->{callee}",
                "source": caller,
                "target": callee
            }
        })

    with open(out_path, "w") as f:
        json.dump({
            "nodes": nodes,
            "edges": edges
        }, f, indent=2)

def to_cytoscape_elements(reduced):
    elements = []
    node_set = set(clean(n) for n in reduced["nodes"])
    # Nodes
    for n in node_set:
        elements.append({
            "data": {
                "id": n,
                "label": n
            }
        })
    # Edges
    for edge in reduced["edges"]:
        caller = clean(edge["caller"])
        callee = clean(edge["callee"])
        # 🔥 critical safety check
        if caller not in node_set or callee not in node_set:
            continue
        elements.append({
            "data": {
                "id": f"{caller}->{callee}",
                "source": caller,
                "target": callee
            }
        })
    return elements

# ---------------------------------------------------------
# Helper: determine if a function is user-defined
# ---------------------------------------------------------
def is_user_defined(func_name):
    if not func_name:
        return False

    # Remove obvious junk only
    if "<unresolvedSignature>" in func_name:
        return False

    if "<iterator>" in func_name:
        return False

    # MUST contain a package + method
    if "." not in func_name:
        return False

    return True

def clean(s):
    return s.strip()

# ---------------------------------------------------------
# Main reducer
# ---------------------------------------------------------
def reduce_callgraph(path="joern_callgraph.json"):
    with open(path, "r") as f:
        data = json.load(f)

    nodes = set()
    edges = []

    for entry in data:
        caller = clean(entry.get("caller"))
        callee = clean(entry.get("callee"))

        if not caller or not callee:
            continue

        # Only require caller to be user-defined
        if not is_user_defined(caller):
            continue

        nodes.add(caller)
        nodes.add(callee)

        edges.append({
            "caller": caller,
            "callee": callee
        })

    return {
        "nodes": list(nodes),
        "edges": edges
    }


def joern_enabled_by_default():
    value = os.getenv("ENABLE_JOERN")
    if value is None:
        return True
    return value.lower() not in {"0", "false", "no", "off"}


def build_javalang_outputs(repo_src, output_repo_dir, results, progress_callback=None):
    javalang_path = os.path.join(output_repo_dir, "javalang")
    os.makedirs(javalang_path, exist_ok=True)
    callgraph_javalang_json_path = build_javalang_callgraph(repo_src, javalang_path, progress_callback=progress_callback)
    results["callgraph_javalang_json_path"] = callgraph_javalang_json_path
    javalang_ordered_path = os.path.join(javalang_path, "javalang_ordered_call_sequence.json")
    if os.path.exists(javalang_ordered_path):
        results["javalang_ordered_call_sequence_path"] = javalang_ordered_path
    logger.info("DONE build_javalang_callgraph %s", results["callgraph_javalang_json_path"])

    return results


def build_tree_sitter_java_outputs(repo_src, output_repo_dir, results):
    tree_sitter_path = os.path.join(output_repo_dir, "tree_sitter_java")
    os.makedirs(tree_sitter_path, exist_ok=True)
    worker_result = run_tree_sitter_java_callgraph_isolated(repo_src, tree_sitter_path)
    tree_sitter_json_path = worker_result.get("graph_path", "")
    if not tree_sitter_json_path or not os.path.exists(tree_sitter_json_path):
        raise RuntimeError("tree-sitter Java analysis completed without a callgraph JSON artifact")
    results["tree_sitter_java_json_path"] = tree_sitter_json_path
    tree_sitter_ordered_path = worker_result.get("ordered_path") or os.path.join(tree_sitter_path, "tree_sitter_java_ordered_call_sequence.json")
    if tree_sitter_ordered_path and os.path.exists(tree_sitter_ordered_path):
        results["tree_sitter_java_ordered_call_sequence_path"] = tree_sitter_ordered_path
    logger.info("DONE build_tree_sitter_java_callgraph %s", results["tree_sitter_java_json_path"])

    return results


def ordered_sequence_candidates_for_graph(path):
    if not path:
        return []
    graph_path = Path(path)
    parent = graph_path.parent
    name = graph_path.name
    candidates = []
    explicit = {
        "python_callgraph.json": "python_ordered_call_sequence.json",
        "javascript_callgraph.json": "javascript_ordered_call_sequence.json",
        "java_merged_callgraph.json": "java_merged_ordered_call_sequence.json",
        "tree_sitter_java_callgraph.json": "tree_sitter_java_ordered_call_sequence.json",
        "javalang_callgraph.json": "javalang_ordered_call_sequence.json",
        "combined_callgraph.json": "combined_ordered_call_sequence.json",
        "joern_callgraph.json": "joern_ordered_call_sequence.json",
        "reduced_joern_callgraph.json": "joern_ordered_call_sequence.json",
    }
    if name in explicit:
        candidates.append(parent / explicit[name])
    stem = graph_path.stem
    for candidate_name in (
        f"{stem}_ordered_call_sequence.json",
        f"{stem}_ordered.json",
        "ordered_call_sequence.json",
    ):
        candidates.append(parent / candidate_name)
    seen = set()
    unique = []
    for candidate in candidates:
        key = str(candidate)
        if key not in seen:
            seen.add(key)
            unique.append(candidate)
    return unique


def load_ordered_edge_meta_for_graph(path):
    edge_meta = {}
    for ordered_path in ordered_sequence_candidates_for_graph(path):
        if not ordered_path.exists():
            continue
        try:
            with open(ordered_path, "r", encoding="utf-8") as f:
                payload = json.load(f)
        except Exception:
            continue
        calls = payload.get("calls", []) if isinstance(payload, dict) else payload
        for index, call in enumerate(calls or [], start=1):
            if not isinstance(call, dict):
                continue
            src = call.get("caller") or call.get("source") or call.get("method") or ""
            dst = call.get("callee") or call.get("target") or call.get("callee_fullName") or ""
            if not src or not dst:
                continue
            try:
                order = int(call.get("order")) if call.get("order") not in (None, "") else index
            except (TypeError, ValueError):
                order = index
            try:
                line = int(call.get("line")) if call.get("line") not in (None, "") else None
            except (TypeError, ValueError):
                line = None
            key = (str(src), str(dst))
            previous = edge_meta.get(key)
            if previous is None or order < (previous.get("order") or order):
                edge_meta[key] = {"order": order, "line": line}
    return edge_meta


def _load_edge_graph_with_meta(path):
    if not path or not os.path.exists(path):
        return set(), set(), {}
    with open(path, "r", encoding="utf-8") as f:
        graph = json.load(f)
    raw_edges = graph.get("edges", graph) if isinstance(graph, dict) else graph
    raw_edges = raw_edges if isinstance(raw_edges, list) else []
    nodes = set()
    if isinstance(graph, dict):
        for node in graph.get("nodes", []) or []:
            if isinstance(node, str):
                nodes.add(node)
            elif isinstance(node, dict):
                node_data = node.get("data") if isinstance(node.get("data"), dict) else node
                node_id = node_data.get("id") or node_data.get("name") or node_data.get("label")
                if node_id:
                    nodes.add(str(node_id))
    edges = set()
    edge_meta = load_ordered_edge_meta_for_graph(path)
    for edge in raw_edges:
        src = ""
        dst = ""
        order = None
        line = None
        if isinstance(edge, list) and len(edge) >= 2:
            src, dst = str(edge[0]), str(edge[1])
            if len(edge) >= 3:
                order = edge[2]
            if len(edge) >= 4:
                line = edge[3]
        elif isinstance(edge, dict):
            edge_data = edge.get("data") if isinstance(edge.get("data"), dict) else edge
            src = edge_data.get("caller") or edge_data.get("source")
            dst = edge_data.get("callee") or edge_data.get("target")
            order = edge_data.get("order")
            line = edge_data.get("line")
            if src is not None:
                src = str(src)
            if dst is not None:
                dst = str(dst)
        else:
            continue
        if src and dst:
            nodes.add(src)
            nodes.add(dst)
            edges.add((src, dst))
            if order is not None or line is not None:
                try:
                    order = int(order) if order not in (None, "") else None
                except (TypeError, ValueError):
                    order = None
                try:
                    line = int(line) if line not in (None, "") else None
                except (TypeError, ValueError):
                    line = None
                previous = edge_meta.get((src, dst))
                if previous is None or (order is not None and order < (previous.get("order") or order)):
                    edge_meta[(src, dst)] = {"order": order, "line": line}
    return nodes, edges, edge_meta


def _load_edge_graph(path):
    nodes, edges, _ = _load_edge_graph_with_meta(path)
    return nodes, edges


def _load_graph_entry_points(path, nodes=None):
    if not path or not os.path.exists(path):
        return []
    try:
        with open(path, "r", encoding="utf-8") as f:
            graph = json.load(f)
    except Exception:
        return []
    if not isinstance(graph, dict):
        return []
    if nodes:
        node_set = set(nodes)
    else:
        node_set = set()
        for node in graph.get("nodes", []) or []:
            if isinstance(node, str):
                node_set.add(node)
            elif isinstance(node, dict):
                node_data = node.get("data") if isinstance(node.get("data"), dict) else node
                node_id = node_data.get("id") or node_data.get("name") or node_data.get("label")
                if node_id:
                    node_set.add(str(node_id))
    entry_points = []
    seen = set()
    for raw in graph.get("entry_points", []) or []:
        node = raw.get("node") if isinstance(raw, dict) else raw
        node = str(node or "").strip()
        if node and (not node_set or node in node_set) and node not in seen:
            seen.add(node)
            entry_points.append(node)
    return entry_points


def _load_graph_node_labels(path):
    if not path or not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            graph = json.load(f)
    except Exception:
        return {}
    if not isinstance(graph, dict) or not isinstance(graph.get("node_labels"), dict):
        return {}
    return {str(key): str(value) for key, value in graph.get("node_labels", {}).items() if key and value}


def _load_graph_edge_labels(path):
    try:
        with open(path, "r", encoding="utf-8") as f:
            graph = json.load(f)
    except Exception:
        return {}
    if not isinstance(graph, dict) or not isinstance(graph.get("edge_labels"), dict):
        return {}
    return {str(key): str(value) for key, value in graph.get("edge_labels", {}).items() if key and value}


def build_merged_java_outputs(output_repo_dir, results):
    source_paths = [
        ("tree-sitter-java", results.get("tree_sitter_java_json_path", "")),
        ("javalang", results.get("callgraph_javalang_json_path", "")),
    ]
    merged_nodes = set()
    merged_edges = set()
    merged_edge_meta = {}
    merged_ordered_calls = []
    sources = []

    for source, path in source_paths:
        nodes, edges, edge_meta = _load_edge_graph_with_meta(path)
        if nodes or edges:
            sources.append(source)
            merged_nodes.update(nodes)
            merged_edges.update(edges)
            for edge, meta in edge_meta.items():
                previous = merged_edge_meta.get(edge)
                order = meta.get("order")
                if previous is None or (order is not None and order < (previous.get("order") or order)):
                    merged_edge_meta[edge] = meta

        ordered_path = ""
        if source == "tree-sitter-java":
            ordered_path = results.get("tree_sitter_java_ordered_call_sequence_path", "")
        elif source == "javalang":
            ordered_path = results.get("javalang_ordered_call_sequence_path", "")
        if ordered_path and os.path.exists(ordered_path):
            try:
                with open(ordered_path, "r", encoding="utf-8") as f:
                    ordered_data = json.load(f)
                for call in ordered_data.get("calls", []):
                    merged_ordered_calls.append({**call, "parser": source})
            except Exception as e:
                logger.warning("Unable to merge ordered Java sequence %s: %s", ordered_path, e)

    if not merged_nodes and not merged_edges:
        return results

    merged_path = os.path.join(output_repo_dir, "java_merged")
    os.makedirs(merged_path, exist_ok=True)
    merged_json_path = os.path.join(merged_path, "java_merged_callgraph.json")
    graph = {
        "mode": "merged_java_graph",
        "parser": "+".join(sources),
        "nodes": sorted(merged_nodes),
        "edges": [
            [src, dst, merged_edge_meta.get((src, dst), {}).get("order"), merged_edge_meta.get((src, dst), {}).get("line")]
            if (src, dst) in merged_edge_meta else [src, dst]
            for src, dst in sorted(merged_edges)
        ],
        "source_count": len(sources),
    }
    with open(merged_json_path, "w", encoding="utf-8") as f:
        json.dump(graph, f, separators=(",", ":"))

    merged_ordered_path = os.path.join(merged_path, "java_merged_ordered_call_sequence.json")
    if merged_ordered_calls:
        write_ordered_call_sequence(
            merged_ordered_calls,
            merged_ordered_path,
            parser="+".join(sources),
            source_callgraph=os.path.basename(merged_json_path),
        )
        results["java_merged_ordered_call_sequence_path"] = merged_ordered_path

    logger.info(
        "Merged Java graph written: %s sources=%s nodes=%s edges=%s",
        merged_json_path,
        ",".join(sources),
        len(merged_nodes),
        len(merged_edges),
    )
    results["java_merged_json_path"] = merged_json_path
    return results


def normalize_joern_ordered_call_sequence(joern_ordered_path, output_dir):
    if not joern_ordered_path or not os.path.exists(joern_ordered_path):
        return ""
    try:
        with open(joern_ordered_path, "r", encoding="utf-8") as f:
            rows = json.load(f)
    except Exception as e:
        logger.warning("Unable to load Joern ordered calls from %s: %s", joern_ordered_path, e)
        return ""

    calls = []
    for item in rows if isinstance(rows, list) else []:
        if not isinstance(item, dict):
            continue
        caller = item.get("method", "")
        for call in item.get("calls", []) or []:
            if not isinstance(call, dict):
                continue
            calls.append({
                "caller": caller,
                "callee": call.get("callee_fullName", ""),
                "line": call.get("line"),
                "order": call.get("order"),
                "call_text": call.get("call_code") or call.get("call_name") or "",
            })
    output_path = os.path.join(output_dir, "joern_ordered_call_sequence.json")
    return write_ordered_call_sequence(
        calls,
        output_path,
        parser="joern",
        source_callgraph=os.path.basename(joern_ordered_path),
    )


def method_to_file_node(method_name):
    parts = str(method_name or "").split(".")
    if len(parts) >= 2:
        return "/".join(parts[:-1])
    return str(method_name or "")


def collect_file_graph_known_file_nodes(output_repo_dir):
    output_repo_dir = Path(output_repo_dir)
    files = set()

    def add_file(value):
        file_path = str(value or "").replace("\\", "/").strip()
        if file_path and not should_skip_file_graph_path(file_path):
            files.add(file_path)

    repo_text_path = ensure_repo_text_artifact_path(output_repo_dir, "repo_text.json")
    if repo_text_path.exists():
        try:
            payload = json.loads(repo_text_path.read_text(encoding="utf-8"))
            for key in ("readme_items", "document_items", "text_items", "ui_text_items"):
                for item in payload.get(key, []) or []:
                    if isinstance(item, dict):
                        add_file(item.get("file") or item.get("path"))
        except Exception as e:
            logger.debug("Unable to read repo text files for file graph nodes: %s", e)

    repo_comments_path = ensure_repo_text_artifact_path(output_repo_dir, "repo_comments.json")
    if repo_comments_path.exists():
        try:
            payload = json.loads(repo_comments_path.read_text(encoding="utf-8"))
            items = payload.get("comments", payload) if isinstance(payload, dict) else payload
            for item in items or []:
                if isinstance(item, dict):
                    add_file(item.get("file") or item.get("path"))
        except Exception as e:
            logger.debug("Unable to read repo comment files for file graph nodes: %s", e)

    return files


def normalize_local_resource_path(value: str, known_files: set[str]):
    raw = str(value or "").strip()
    if not raw or raw.startswith(("#", "mailto:", "tel:", "javascript:", "data:", "http://", "https://", "//")):
        return ""
    raw = raw.split("#", 1)[0].split("?", 1)[0].replace("\\", "/").lstrip("/")
    if not raw:
        return ""
    candidates = [raw]
    if raw.startswith("static/"):
        candidates.append(raw[len("static/"):])
    else:
        candidates.append(f"static/{raw}")
    tail = raw.rsplit("/", 1)[-1]
    matches = [
        known for known in known_files
        if known in candidates or known.endswith(f"/{raw}") or (tail and known.endswith(f"/{tail}"))
    ]
    unique_matches = sorted(set(matches), key=lambda item: (len(item), item))
    if len(unique_matches) == 1:
        return unique_matches[0]
    if Path(raw).suffix.lower() in {".html", ".htm", ".js", ".mjs", ".cjs", ".ts", ".tsx", ".jsx", ".css", ".json"}:
        return raw
    return ""


def html_ui_symbol_file_index(graph: dict):
    symbol_to_file = {}
    for item in graph.get("elements", []) or []:
        if not isinstance(item, dict):
            continue
        symbol = str(item.get("symbol") or "")
        file_path = str(item.get("file") or "").replace("\\", "/")
        if symbol and file_path and not should_skip_file_graph_path(file_path):
            symbol_to_file[symbol] = file_path
    for item in graph.get("edge_details", []) or []:
        if not isinstance(item, dict):
            continue
        file_path = str(item.get("file") or "").replace("\\", "/")
        if not file_path or should_skip_file_graph_path(file_path):
            continue
        for key in ("source", "target"):
            symbol = str(item.get(key) or "")
            if symbol and not symbol.startswith(("api.", "url.", "event.", "file_ref.")):
                symbol_to_file.setdefault(symbol, file_path)
    return symbol_to_file


def resolve_synthetic_symbol_file(symbol: str, symbol_to_file: dict[str, str], known_files: set[str]):
    symbol = str(symbol or "")
    if symbol in symbol_to_file:
        return symbol_to_file[symbol]
    if symbol.startswith(("file_ref.", "url.")):
        raw = symbol.split(".", 1)[1].replace("_", "/")
        return normalize_local_resource_path(raw, known_files)
    if symbol.startswith("js."):
        handler = symbol.split(".", 1)[1]
        matches = [
            file_path for known_symbol, file_path in symbol_to_file.items()
            if known_symbol.endswith(f".{handler}") or known_symbol.endswith(f".{handler}.<anonymous>")
        ]
        unique = sorted(set(matches))
        return unique[0] if len(unique) == 1 else ""
    return ""


def is_synthetic_non_file_symbol(symbol: str):
    return str(symbol or "").startswith(("api.", "url.", "event.", "file_ref."))


def html_generated_prefix_for_file(file_path: str):
    suffix = Path(str(file_path or "").replace("\\", "/")).suffix.lower()
    if suffix not in {".html", ".htm", ".xhtml"}:
        return ""
    return html_ui_path_key(file_path)


def generated_symbol_file(symbol: str, prefix_to_file: dict[str, str]):
    symbol = str(symbol or "")
    for prefix, file_path in prefix_to_file.items():
        if symbol == prefix or symbol.startswith(f"{prefix}.") or symbol.startswith(f"{prefix}/"):
            return file_path
    return ""


def file_graph_edge_label(kind: str, detail: str = ""):
    kind = str(kind or "").strip()
    detail = str(detail or "").strip()
    labels = {
        "function_call": "function call",
        "inferred_call": "inferred call",
        "script_src": "script src",
        "resource_src": "resource src",
        "link_href": "link href",
        "form_action": "form action",
        "onclick_api": "onclick API",
        "onclick_handler": "onclick handler",
        "dom_event_listener": "event handler",
        "inline_script_api": "fetch/API",
    }
    label = labels.get(kind, kind.replace("_", " ") if kind else "link")
    if detail and kind in {"script_src", "resource_src", "link_href", "form_action"}:
        clean_detail = detail.split("?", 1)[0].split("#", 1)[0].strip()
        if clean_detail and len(clean_detail) <= 48:
            return f"{label}: {clean_detail}"
    return label


def build_file_graph_outputs(output_repo_dir, results):
    source_paths = [
        results.get("python_callgraph_json_path", ""),
        results.get("javascript_callgraph_json_path", ""),
        results.get("csharp_callgraph_json_path", ""),
        results.get("html_ui_graph_json_path", ""),
        results.get("combined_callgraph_json_path", ""),
        Path(output_repo_dir) / "combined_callgraph" / "combined_callgraph.json",
        results.get("java_merged_json_path", ""),
        results.get("tree_sitter_java_json_path", ""),
        results.get("callgraph_javalang_json_path", ""),
        results.get("reduced_joern_callgraph_json_path", ""),
    ]
    file_nodes = set()
    all_exact_file_nodes = set()
    exact_file_edges = set()
    heuristic_file_edges = set()
    file_edge_reasons = defaultdict(list)
    sources_used = []
    symbol_to_file = {}
    graph_payloads = []
    endpoint_source_files = defaultdict(set)
    endpoint_source_reasons = defaultdict(list)

    for path in source_paths:
        if not path or not os.path.exists(path):
            continue
        sources_used.append(os.path.relpath(path, output_repo_dir).replace("\\", "/"))
        with open(path, "r", encoding="utf-8") as f:
            graph = json.load(f)
        graph_payloads.append((path, graph))
        function_files = graph.get("function_files", {}) if isinstance(graph, dict) else {}
        symbol_to_file.update({
            str(symbol): str(file_path).replace("\\", "/")
            for symbol, file_path in function_files.items()
            if file_path and not should_skip_file_graph_path(file_path)
        })
        if isinstance(graph, dict) and graph.get("mode") == "html_ui_graph":
            symbol_to_file.update(html_ui_symbol_file_index(graph))
            for detail in graph.get("edge_details", []) or []:
                if not isinstance(detail, dict):
                    continue
                target = str(detail.get("target") or "")
                source_file = str(detail.get("file") or "").replace("\\", "/")
                if not target.startswith(("api.", "url.")) or not source_file or should_skip_file_graph_path(source_file):
                    continue
                endpoint_source_files[target].add(source_file)
                reason = file_graph_edge_label(str(detail.get("kind") or "fetch/API"), str(detail.get("detail") or ""))
                if reason and reason not in endpoint_source_reasons[target]:
                    endpoint_source_reasons[target].append(reason)
        all_exact_file_nodes.update(
            file_path
            for file_path in function_files.values()
            if file_path and not should_skip_file_graph_path(file_path)
        )
    known_files = set(symbol_to_file.values()) | collect_file_graph_known_file_nodes(output_repo_dir)
    prefix_to_file = {
        prefix: file_path
        for file_path in known_files
        for prefix in [html_generated_prefix_for_file(file_path)]
        if prefix
    }

    def symbol_file(symbol):
        symbol = str(symbol or "")
        return (
            symbol_to_file.get(symbol)
            or resolve_synthetic_symbol_file(symbol, symbol_to_file, known_files)
            or generated_symbol_file(symbol, prefix_to_file)
        )

    for path, graph in graph_payloads:
        function_files = graph.get("function_files", {}) if isinstance(graph, dict) else {}
        html_detail_by_edge = {}
        if isinstance(graph, dict) and graph.get("mode") == "html_ui_graph":
            for detail in graph.get("edge_details", []) or []:
                if isinstance(detail, dict):
                    html_detail_by_edge[(str(detail.get("source") or ""), str(detail.get("target") or ""))] = detail
        _, method_edges = _load_edge_graph(path)
        for src, dst in method_edges:
            src_file = function_files.get(src) or symbol_file(src)
            if src_file and str(dst).startswith(("api.", "url.")):
                endpoint_source_files[dst].add(src_file)
                reason = file_graph_edge_label("inline_script_api" if str(dst).startswith("api.") else "link_href")
                if reason and reason not in endpoint_source_reasons[dst]:
                    endpoint_source_reasons[dst].append(reason)
        for src, dst in method_edges:
            has_exact_files = src in function_files and dst in function_files
            html_detail = html_detail_by_edge.get((src, dst), {})
            src_file = (
                function_files.get(src)
                or symbol_file(src)
            )
            dst_file = (
                function_files.get(dst)
                or symbol_file(dst)
            )
            if not src_file and not is_synthetic_non_file_symbol(src):
                src_file = method_to_file_node(src)
            if not dst_file and not is_synthetic_non_file_symbol(dst):
                dst_file = method_to_file_node(dst)
            if not src_file and src in endpoint_source_files and dst_file:
                for frontend_file in sorted(endpoint_source_files[src]):
                    if frontend_file == dst_file or should_skip_file_graph_path(frontend_file):
                        continue
                    file_nodes.add(frontend_file)
                    file_nodes.add(dst_file)
                    exact_file_edges.add((frontend_file, dst_file))
                    for reason_label in endpoint_source_reasons.get(src, []) or [file_graph_edge_label("inline_script_api")]:
                        if reason_label not in file_edge_reasons[(frontend_file, dst_file)]:
                            file_edge_reasons[(frontend_file, dst_file)].append(reason_label)
                continue
            if should_skip_file_graph_path(src_file) or should_skip_file_graph_path(dst_file):
                continue
            if not src_file or not dst_file or src_file == dst_file:
                continue
            file_nodes.add(src_file)
            file_nodes.add(dst_file)
            reason_kind = str(html_detail.get("kind") or ("function_call" if has_exact_files else "inferred_call"))
            reason_detail = str(html_detail.get("detail") or "")
            reason_label = file_graph_edge_label(reason_kind, reason_detail)
            if reason_label and reason_label not in file_edge_reasons[(src_file, dst_file)]:
                file_edge_reasons[(src_file, dst_file)].append(reason_label)
            if has_exact_files or src in symbol_to_file or dst in symbol_to_file:
                exact_file_edges.add((src_file, dst_file))
            else:
                heuristic_file_edges.add((src_file, dst_file))

    file_edges = exact_file_edges or heuristic_file_edges

    if not file_nodes and not file_edges:
        return results

    graph_dir = os.path.join(output_repo_dir, "file_graph")
    os.makedirs(graph_dir, exist_ok=True)
    json_path = os.path.join(graph_dir, "file_graph.json")
    graph = {
        "mode": "file_dependency_graph",
        "version": FILE_GRAPH_VERSION,
        "sources": sources_used,
        "nodes": sorted(file_nodes),
        "edges": [[src, dst] for src, dst in sorted(file_edges)],
        "edge_labels": {
            f"{src}->{dst}": ", ".join(file_edge_reasons.get((src, dst), [])[:3])
            for src, dst in sorted(file_edges)
            if file_edge_reasons.get((src, dst))
        },
        "edge_details": [
            {
                "source": src,
                "target": dst,
                "reasons": file_edge_reasons.get((src, dst), []),
            }
            for src, dst in sorted(file_edges)
            if file_edge_reasons.get((src, dst))
        ],
    }
    with open(json_path, "w", encoding="utf-8") as f:
        json.dump(graph, f, separators=(",", ":"))
    logger.info("File graph written: %s files=%s edges=%s", json_path, len(file_nodes), len(file_edges))
    results["file_graph_json_path"] = json_path
    return results


FEATURE_CALLGRAPH_VERSION = 1
FEATURE_CALLGRAPH_MAX_FEATURES = 25
FEATURE_CALLGRAPH_MAX_EVIDENCE_PER_FEATURE = 8
FEATURE_CALLGRAPH_MAX_IMPL_NODES_PER_FEATURE = 14
FEATURE_CALLGRAPH_IMPL_DEPTH = 2


def feature_graph_slug(value: str, fallback: str = "feature", max_len: int = 72) -> str:
    value = html_unescape(str(value or "")).strip()
    value = re.sub(r"\s+", "_", value)
    value = re.sub(r"[^A-Za-z0-9_.:-]+", "_", value).strip("_")
    if not value:
        value = fallback
    if value and value[0].isdigit():
        value = f"{fallback}_{value}"
    return value[:max_len] or fallback


def feature_graph_terms(value: str) -> set[str]:
    terms = {
        term.lower()
        for term in re.findall(r"[A-Za-z][A-Za-z0-9]{2,}", str(value or ""))
    }
    return {
        term
        for term in terms
        if term not in {
            "the", "and", "for", "with", "from", "that", "this", "your", "into",
            "code", "data", "user", "users", "feature", "features", "details",
        }
    }


def feature_graph_similarity(left: str, right: str) -> float:
    left_terms = feature_graph_terms(left)
    right_terms = feature_graph_terms(right)
    if not left_terms or not right_terms:
        return 0.0
    return len(left_terms & right_terms) / max(1, len(left_terms | right_terms))


def feature_graph_int(value, default=0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def feature_graph_required_targets(feature_names: list[dict]) -> list[dict]:
    targets = []
    for index, item in enumerate(feature_names or []):
        if not isinstance(item, dict) or item.get("deleted"):
            continue
        name = str(item.get("name") or item.get("feature") or "").strip()
        if not name:
            continue
        targets.append({
            "index": item.get("index", index),
            "feature_id": item.get("feature_id", ""),
            "original": item.get("original") or item.get("original_feature") or name,
            "name": name,
            "source": item.get("source") or "feature_list",
            "user_feedback": bool(item.get("description")),
        })
    return targets


def feature_graph_feature_rows(feature_catalog: dict, feature_names: list[dict] | None = None) -> list[dict]:
    rows = []
    seen = set()

    def add_row(name, source="", payload=None, score=0):
        clean_name = str(name or "").strip()
        if not clean_name:
            return
        key = clean_name.lower()
        if key in seen:
            return
        seen.add(key)
        row = dict(payload or {})
        row.setdefault("feature", clean_name)
        row["_feature_graph_source"] = source
        row["_feature_graph_score"] = score
        rows.append(row)

    catalog_features = [feature for feature in (feature_catalog.get("features") or []) if isinstance(feature, dict)]
    normalized_names = normalize_feature_name_edits(feature_names or [])
    if normalized_names:
        feature_blacklist = feature_blacklist_from_edits(normalized_names)
        catalog_features = filter_deleted_feature_rows(catalog_features, normalized_names, feature_blacklist)
        catalog_features = apply_required_feature_targets(catalog_features, feature_graph_required_targets(normalized_names))

    for index, feature in enumerate(catalog_features):
        if not isinstance(feature, dict):
            continue
        score = feature_graph_int(feature.get("priority"), 0)
        score += feature_graph_int(feature.get("match_count"), 0)
        if feature.get("source") == "ui_feature_seed":
            score += 1000
        elif feature.get("source") == "human_facing_text":
            score += 500
        add_row(feature.get("feature") or feature.get("name"), feature.get("source") or "feature_catalog", feature, score - index)

    for index, seed in enumerate(feature_catalog.get("ui_feature_seeds") or []):
        add_row(seed, "ui_feature_seed", {"feature": seed, "source": "ui_feature_seed"}, 900 - index)

    rows.sort(key=lambda row: (int(row.get("_feature_graph_score", 0) or 0), str(row.get("feature") or "")), reverse=True)
    return rows[:FEATURE_CALLGRAPH_MAX_FEATURES]


def feature_graph_evidence_items(feature: dict) -> list[dict]:
    items = []
    for key in ("ui_evidence", "evidence", "comment_evidence"):
        for item in feature.get(key) or []:
            if isinstance(item, dict):
                items.append(item)
    for subfeature in feature.get("subfeatures") or []:
        if not isinstance(subfeature, dict):
            continue
        for item in subfeature.get("evidence") or []:
            if isinstance(item, dict):
                items.append(item)
    deduped = []
    seen = set()
    for item in items:
        key = (str(item.get("symbol") or ""), str(item.get("path") or item.get("file") or ""), str(item.get("start_line") or item.get("line") or ""))
        if key in seen:
            continue
        seen.add(key)
        deduped.append(item)
    return deduped[:FEATURE_CALLGRAPH_MAX_EVIDENCE_PER_FEATURE]


def feature_graph_load_json(path):
    if not path or not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            payload = json.load(f)
        return payload if isinstance(payload, dict) else {}
    except Exception:
        return {}


def feature_graph_collect_callgraph(output_repo_dir, results):
    source_paths = [
        results.get("combined_callgraph_json_path", ""),
        Path(output_repo_dir) / "combined_callgraph" / "combined_callgraph.json",
        results.get("html_ui_graph_json_path", ""),
        results.get("java_merged_json_path", ""),
        results.get("tree_sitter_java_json_path", ""),
        results.get("callgraph_javalang_json_path", ""),
        results.get("python_callgraph_json_path", ""),
        results.get("javascript_callgraph_json_path", ""),
        results.get("csharp_callgraph_json_path", ""),
        results.get("reduced_joern_callgraph_json_path", ""),
    ]
    nodes = set()
    edges = set()
    edge_meta = {}
    node_labels = {}
    sources = []
    for raw_path in source_paths:
        path = str(raw_path or "")
        if not path or not os.path.exists(path):
            continue
        sources.append(os.path.relpath(path, output_repo_dir).replace("\\", "/"))
        graph_nodes, graph_edges, graph_edge_meta = _load_edge_graph_with_meta(path)
        nodes.update(graph_nodes)
        edges.update(graph_edges)
        edge_meta.update(graph_edge_meta)
        node_labels.update(_load_graph_node_labels(path))
        graph_payload = feature_graph_load_json(path)
        if isinstance(graph_payload.get("function_files"), dict):
            for symbol, file_path in graph_payload.get("function_files", {}).items():
                if symbol and file_path:
                    clean_file_path = str(file_path).replace("\\", "/")
                    node_labels.setdefault(str(symbol), f"{symbol} ({clean_file_path})")
    return nodes, edges, edge_meta, node_labels, sources


def feature_graph_ui_nodes(output_repo_dir, results):
    html_graph_path = results.get("html_ui_graph_json_path", "") or Path(output_repo_dir) / "html_ui" / "html_ui_graph.json"
    graph = feature_graph_load_json(str(html_graph_path))
    if not graph:
        return {}, []
    node_labels = _load_graph_node_labels(str(html_graph_path))
    nodes = {}
    for node in graph.get("nodes") or []:
        node_id = str(node)
        label = node_labels.get(node_id) or node_id
        nodes[node_id] = label
    for detail in graph.get("edge_details") or []:
        if not isinstance(detail, dict):
            continue
        for key in ("source", "target"):
            node_id = str(detail.get(key) or "")
            if node_id and node_id not in nodes:
                nodes[node_id] = node_labels.get(node_id) or node_id
    return nodes, graph.get("edge_details") or []


def feature_graph_add_impl_neighborhood(seed_symbols, call_edges, max_nodes=FEATURE_CALLGRAPH_MAX_IMPL_NODES_PER_FEATURE):
    outgoing = defaultdict(list)
    incoming = defaultdict(list)
    for src, dst in call_edges:
        outgoing[src].append(dst)
        incoming[dst].append(src)
    selected_nodes = set()
    selected_edges = set()
    queue = deque((symbol, 0) for symbol in seed_symbols if symbol)
    while queue and len(selected_nodes) < max_nodes:
        node, depth = queue.popleft()
        if node in selected_nodes and depth:
            continue
        selected_nodes.add(node)
        if depth >= FEATURE_CALLGRAPH_IMPL_DEPTH:
            continue
        neighbors = []
        for dst in sorted(outgoing.get(node, []))[:6]:
            selected_edges.add((node, dst))
            neighbors.append(dst)
        for src in sorted(incoming.get(node, []))[:4]:
            selected_edges.add((src, node))
            neighbors.append(src)
        for neighbor in neighbors:
            if neighbor not in selected_nodes and len(selected_nodes) + len(queue) < max_nodes:
                queue.append((neighbor, depth + 1))
    return selected_nodes, selected_edges


def build_feature_callgraph_outputs(output_repo_dir, results):
    feature_catalog_path = results.get("feature_catalog_path", "")
    if not feature_catalog_path or not os.path.exists(feature_catalog_path):
        return results
    feature_catalog = feature_graph_load_json(feature_catalog_path)
    if not feature_catalog:
        return results

    features = feature_graph_feature_rows(feature_catalog, results.get("feature_names") or [])
    if not features:
        return results

    call_nodes, call_edges, call_edge_meta, call_node_labels, call_sources = feature_graph_collect_callgraph(output_repo_dir, results)
    ui_nodes, ui_edge_details = feature_graph_ui_nodes(output_repo_dir, results)

    graph_nodes = set()
    graph_edges = set()
    node_labels = {}
    node_types = {}
    edge_labels = {}
    edge_details = []
    entry_points = []

    def add_node(node_id, label, node_type):
        if not node_id:
            return
        graph_nodes.add(node_id)
        node_labels.setdefault(node_id, str(label or node_id))
        node_types.setdefault(node_id, node_type)

    def add_edge(src, dst, label, kind):
        if not src or not dst:
            return
        graph_edges.add((src, dst))
        if label:
            edge_labels[f"{src}->{dst}"] = label
        edge_details.append({"source": src, "target": dst, "kind": kind, "label": label})

    for index, feature in enumerate(features, start=1):
        feature_name = str(feature.get("feature") or feature.get("name") or "").strip()
        if not feature_name:
            continue
        feature_node = f"feature.{feature_graph_slug(feature_name)}"
        add_node(feature_node, feature_name, "feature")
        entry_points.append(feature_node)

        feature_terms = feature_graph_terms(feature_name)
        evidence_items = feature_graph_evidence_items(feature)
        seed_symbols = []
        seed_paths = set()

        for item in evidence_items:
            symbol = str(item.get("symbol") or "").strip()
            path = str(item.get("path") or item.get("file") or "").replace("\\", "/").strip()
            if path:
                seed_paths.add(path)
            if symbol and symbol in call_nodes:
                seed_symbols.append(symbol)
                add_node(symbol, call_node_labels.get(symbol) or symbol, "function")
                add_edge(feature_node, symbol, "implemented by", "feature_to_function")
            elif symbol:
                evidence_node = f"evidence.{feature_graph_slug(symbol)}"
                add_node(evidence_node, symbol, "evidence")
                add_edge(feature_node, evidence_node, "evidence", "feature_to_evidence")
            elif path:
                file_node = f"file.{feature_graph_slug(path)}"
                add_node(file_node, path, "file")
                add_edge(feature_node, file_node, "evidence file", "feature_to_file")

        for ui_node, ui_label in sorted(ui_nodes.items(), key=lambda item: item[0]):
            ui_text = f"{ui_node} {ui_label}"
            matched = feature_graph_similarity(feature_name, ui_text)
            if matched >= 0.2 or (feature_terms and feature_terms <= feature_graph_terms(ui_text)):
                add_node(ui_node, ui_label, "ui")
                add_edge(feature_node, ui_node, "visible in UI", "feature_to_ui")
                feature_ui_edge_count = sum(
                    1
                    for edge in graph_edges
                    if edge[0] == feature_node and node_types.get(edge[1]) == "ui"
                )
                if feature_ui_edge_count >= 4:
                    break

        for detail in ui_edge_details:
            if not isinstance(detail, dict):
                continue
            src = str(detail.get("source") or "")
            dst = str(detail.get("target") or "")
            if src in graph_nodes and dst in call_nodes:
                add_node(dst, call_node_labels.get(dst) or dst, "function")
                add_edge(src, dst, file_graph_edge_label(str(detail.get("kind") or "ui link"), str(detail.get("detail") or "")), "ui_to_function")
                seed_symbols.append(dst)
            elif src in graph_nodes and dst:
                add_node(dst, ui_nodes.get(dst) or call_node_labels.get(dst) or dst, "ui")
                add_edge(src, dst, file_graph_edge_label(str(detail.get("kind") or "ui link"), str(detail.get("detail") or "")), "ui_link")

        neighborhood_nodes, neighborhood_edges = feature_graph_add_impl_neighborhood(seed_symbols, call_edges)
        for node in neighborhood_nodes:
            add_node(node, call_node_labels.get(node) or node, "function")
        for src, dst in neighborhood_edges:
            if src in graph_nodes and dst in graph_nodes:
                meta = call_edge_meta.get((src, dst), {})
                label = "calls"
                if meta.get("line"):
                    label = f"calls line {meta.get('line')}"
                add_edge(src, dst, label, "function_call")

    if len(graph_nodes) <= len(entry_points):
        return results

    graph_dir = os.path.join(output_repo_dir, "feature_graph")
    os.makedirs(graph_dir, exist_ok=True)
    json_path = os.path.join(graph_dir, "feature_callgraph.json")
    graph = {
        "mode": "feature_callgraph",
        "version": FEATURE_CALLGRAPH_VERSION,
        "title": "Feature to Implementation Callgraph",
        "sources": sorted(set(call_sources + [os.path.relpath(feature_catalog_path, output_repo_dir).replace("\\", "/")])),
        "nodes": sorted(graph_nodes),
        "edges": [[src, dst, call_edge_meta.get((src, dst), {}).get("order"), call_edge_meta.get((src, dst), {}).get("line")] for src, dst in sorted(graph_edges)],
        "entry_points": entry_points,
        "node_labels": node_labels,
        "node_types": node_types,
        "edge_labels": edge_labels,
        "edge_details": edge_details,
        "note": "Feature nodes are anchors from extracted feature/UI labels. User descriptions are not embedded here. UI and implementation edges come from extracted UI graph, SCIM feature evidence, and callgraph artifacts.",
    }
    with open(json_path, "w", encoding="utf-8") as f:
        json.dump(graph, f, separators=(",", ":"))
    results["feature_callgraph_json_path"] = json_path
    logger.info("Feature callgraph written: %s nodes=%s edges=%s", json_path, len(graph_nodes), len(graph_edges))
    return results


def feature_callgraph_source_results(artifact_root: Path, feature_names: list[dict] | None = None) -> dict:
    root = Path(artifact_root)
    return {
        "feature_names": feature_names or [],
        "feature_catalog_path": str(core_helpers.feature_catalog_path_for_output(root)),
        "python_callgraph_json_path": str(root / "python" / "python_callgraph.json"),
        "javascript_callgraph_json_path": str(root / "javascript" / "javascript_callgraph.json"),
        "csharp_callgraph_json_path": str(root / "csharp" / "csharp_callgraph.json"),
        "html_ui_graph_json_path": str(root / "html_ui" / "html_ui_graph.json"),
        "combined_callgraph_json_path": str(root / "combined_callgraph" / "combined_callgraph.json"),
        "java_merged_json_path": str(root / "java_merged" / "java_merged_callgraph.json"),
        "tree_sitter_java_json_path": str(root / "tree_sitter_java" / "tree_sitter_java_callgraph.json"),
        "callgraph_javalang_json_path": str(root / "javalang" / "javalang_callgraph.json"),
        "reduced_joern_callgraph_json_path": str(root / "joern" / "reduced_joern_callgraph.json"),
    }


HTML_UI_GRAPH_VERSION = 2
HTML_UI_EXTENSIONS = {".html", ".htm", ".xhtml"}
HTML_UI_INTERACTIVE_TAGS = {"a", "button", "form", "input", "select", "textarea", "option", "label"}
HTML_UI_TEXT_ATTRS = ("aria-label", "title", "alt", "placeholder", "value", "name")


def html_ui_path_key(rel_path: str):
    clean_path = re.sub(r"[^A-Za-z0-9]+", "_", str(rel_path or "").replace("\\", "/")).strip("_")
    return clean_path or "html"


def html_ui_slug(value: str, fallback: str = "item", max_len: int = 48):
    clean_value = html_unescape(str(value or "")).strip()
    clean_value = re.sub(r"\s+", "_", clean_value)
    clean_value = re.sub(r"[^A-Za-z0-9_.$:-]+", "_", clean_value).strip("_")
    if not clean_value:
        clean_value = fallback
    if clean_value and clean_value[0].isdigit():
        clean_value = f"{fallback}_{clean_value}"
    return clean_value[:max_len] or fallback


def html_ui_symbol(rel_path: str, element_key: str):
    return f"{html_ui_path_key(rel_path)}.{html_ui_slug(element_key)}"


def html_ui_api_targets(text: str):
    targets = set()
    quote = r"""['"`]"""
    for pattern in (
        rf"\bfetch\(\s*{quote}([^'\"`]+){quote}",
        rf"\bnew\s+URL\(\s*{quote}([^'\"`]+){quote}",
        rf"\baxios\.(?:get|post|put|patch|delete)\(\s*{quote}([^'\"`]+){quote}",
        rf"\bopen\(\s*{quote}([^'\"`]+){quote}",
        rf"\blocation(?:\.href)?\s*=\s*{quote}([^'\"`]+){quote}",
        rf"\bwindow\.location(?:\.href)?\s*=\s*{quote}([^'\"`]+){quote}",
    ):
        for match in re.finditer(pattern, text or "", re.IGNORECASE):
            target = match.group(1).strip()
            if target:
                route_matches = re.findall(r"(?<![:\w])/[A-Za-z0-9_.~!$&'()*+,;=:@%/-]+", target)
                if route_matches:
                    targets.update(route_matches)
                else:
                    targets.add(target)
    return sorted(targets)


def html_ui_handler_names(text: str):
    names = set()
    for match in re.finditer(r"\b([A-Za-z_$][A-Za-z0-9_$]*)\s*\(", text or ""):
        name = match.group(1)
        if name not in {"if", "for", "while", "switch", "return", "fetch", "open"}:
            names.add(name)
    return sorted(names)


class HtmlUiGraphParser(HTMLParser):
    def __init__(self, rel_path: str):
        super().__init__(convert_charrefs=True)
        self.rel_path = rel_path
        self.elements = []
        self.script_blocks = []
        self._current = None
        self._capture_script = False
        self._script_parts = []

    def handle_starttag(self, tag, attrs):
        tag = tag.lower()
        attr = {str(key).lower(): str(value or "") for key, value in attrs}
        line_no, _ = self.getpos()
        if tag == "script":
            self._capture_script = True
            self._script_parts = []
        is_interactive = (
            tag in HTML_UI_INTERACTIVE_TAGS
            or (tag == "script" and attr.get("src"))
            or (tag == "link" and attr.get("href"))
            or attr.get("onclick")
            or (tag in {"a", "area"} and attr.get("href"))
            or attr.get("role") == "button"
            or attr.get("type") in {"button", "submit", "reset"}
        )
        if not is_interactive:
            self._current = None
            return
        element_key = (
            attr.get("id")
            or attr.get("name")
            or attr.get("data-testid")
            or attr.get("aria-label")
            or attr.get("src")
            or attr.get("href")
            or f"{tag}_{line_no}"
        )
        element = {
            "tag": tag,
            "attrs": attr,
            "line": line_no,
            "text": "",
            "symbol": html_ui_symbol(self.rel_path, element_key),
            "element_key": element_key,
        }
        self.elements.append(element)
        self._current = element

    def handle_endtag(self, tag):
        if tag.lower() == "script":
            self._capture_script = False
            script = "\n".join(self._script_parts).strip()
            if script:
                self.script_blocks.append(script)
            self._script_parts = []
        if self._current and tag.lower() == self._current.get("tag"):
            self._current = None

    def handle_data(self, data):
        if self._capture_script:
            self._script_parts.append(data)
        if self._current and data.strip():
            existing = self._current.get("text", "")
            self._current["text"] = f"{existing} {data.strip()}".strip()


def build_html_ui_graph(repo_src, output_dir, progress_callback=None):
    nodes = set()
    edges = set()
    elements = []
    edge_details = []
    element_by_id = {}
    script_blocks_by_file = defaultdict(list)

    def add_edge(source, target, kind, rel_path, detail=""):
        if not source or not target or source == target:
            return
        nodes.add(source)
        nodes.add(target)
        edges.add((source, target))
        edge_details.append({
            "source": source,
            "target": target,
            "kind": kind,
            "file": rel_path,
            "detail": detail,
        })

    def report_progress(message, current_file=None):
        if not progress_callback:
            return
        try:
            progress_callback(message, current_file=current_file)
        except TypeError:
            progress_callback(message)

    for path in iter_supported_repo_files(repo_src, HTML_UI_EXTENSIONS, sniff_browser_metadata=False):
        ext = os.path.splitext(path)[1].lower()
        rel_path = os.path.relpath(path, repo_src).replace("\\", "/")
        report_progress("Parsing HTML and UI files.", rel_path)
        try:
            text = Path(path).read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        parser = HtmlUiGraphParser(rel_path)
        try:
            parser.feed(text)
        except Exception as e:
            logger.warning("HTML UI parser recovered from %s: %s", rel_path, e)
        file_node = html_ui_symbol(rel_path, "<file>")
        nodes.add(file_node)
        script_blocks_by_file[rel_path].extend(parser.script_blocks)
        for element in parser.elements:
            symbol = element["symbol"]
            attrs = element.get("attrs", {})
            text_value = element.get("text") or next((attrs.get(key, "") for key in HTML_UI_TEXT_ATTRS if attrs.get(key)), "")
            nodes.add(symbol)
            add_edge(file_node, symbol, "contains_ui_element", rel_path, element.get("tag", ""))
            element_payload = {
                "symbol": symbol,
                "file": rel_path,
                "line": element.get("line"),
                "tag": element.get("tag"),
                "id": attrs.get("id", ""),
                "name": attrs.get("name", ""),
                "role": attrs.get("role", ""),
                "type": attrs.get("type", ""),
                "text": text_value[:300],
                "href": attrs.get("href", ""),
                "src": attrs.get("src", ""),
                "action": attrs.get("action", ""),
                "onclick": attrs.get("onclick", ""),
            }
            elements.append(element_payload)
            if attrs.get("id"):
                element_by_id[(rel_path, attrs["id"])] = symbol
            if attrs.get("href"):
                add_edge(symbol, f"url.{html_ui_slug(attrs['href'], 'link')}", "link_href", rel_path, attrs["href"])
            if attrs.get("src"):
                add_edge(symbol, f"file_ref.{html_ui_slug(attrs['src'], 'src')}", "script_src" if element.get("tag") == "script" else "resource_src", rel_path, attrs["src"])
            if attrs.get("action"):
                add_edge(symbol, f"api.{html_ui_slug(attrs['action'], 'action')}", "form_action", rel_path, attrs["action"])
            if attrs.get("onclick"):
                for handler in html_ui_handler_names(attrs["onclick"]):
                    add_edge(symbol, f"js.{handler}", "onclick_handler", rel_path, attrs["onclick"][:180])
                for target in html_ui_api_targets(attrs["onclick"]):
                    add_edge(symbol, f"api.{html_ui_slug(target, 'api')}", "onclick_api", rel_path, target)

    for rel_path, blocks in script_blocks_by_file.items():
        script_text = "\n".join(blocks)
        script_node = html_ui_symbol(rel_path, "inline_script")
        if script_text.strip():
            nodes.add(script_node)
        dom_lookup_names = {"getElementById"}
        for pattern in (
            r"\bfunction\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*\([^)]*\)\s*\{[^{}]{0,500}document\.getElementById\s*\(",
            r"\b(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:\([^)]*\)|[A-Za-z_$][A-Za-z0-9_$]*)\s*=>[^;\n]{0,500}document\.getElementById\s*\(",
        ):
            for match in re.finditer(pattern, script_text, re.IGNORECASE | re.DOTALL):
                dom_lookup_names.add(match.group(1))
        dom_lookup_pattern = "|".join(re.escape(name) for name in sorted(dom_lookup_names, key=len, reverse=True))
        listener_pattern = re.compile(
            rf"(?:(?:document\.)?getElementById|{dom_lookup_pattern})\(\s*['\"]([^'\"]+)['\"]\s*\)\??\.addEventListener\(\s*['\"]([^'\"]+)['\"]\s*,\s*([A-Za-z_$][A-Za-z0-9_$]*)?",
            re.IGNORECASE,
        )
        variable_to_id = {
            match.group(1): match.group(2)
            for match in re.finditer(
                rf"\b(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:(?:document\.)?getElementById|{dom_lookup_pattern})\(\s*['\"]([^'\"]+)['\"]\s*\)",
                script_text,
            )
        }
        for match in listener_pattern.finditer(script_text):
            element_id, event_name, handler = match.groups()
            element_symbol = element_by_id.get((rel_path, element_id)) or html_ui_symbol(rel_path, element_id)
            if handler in {"async", "function"}:
                handler = ""
            target = f"js.{handler}" if handler else f"event.{html_ui_slug(event_name, 'event')}"
            add_edge(element_symbol, target, "dom_event_listener", rel_path, event_name)
        for match in re.finditer(
            r"\b([A-Za-z_$][A-Za-z0-9_$]*)\??\.addEventListener\(\s*['\"]([^'\"]+)['\"]\s*,\s*([A-Za-z_$][A-Za-z0-9_$]*)?",
            script_text,
        ):
            variable_name, event_name, handler = match.groups()
            element_id = variable_to_id.get(variable_name)
            if not element_id:
                continue
            element_symbol = element_by_id.get((rel_path, element_id)) or html_ui_symbol(rel_path, element_id)
            if handler in {"async", "function"}:
                handler = ""
            target = f"js.{handler}" if handler else f"event.{html_ui_slug(event_name, 'event')}"
            add_edge(element_symbol, target, "dom_event_listener", rel_path, event_name)
        for api_target in html_ui_api_targets(script_text):
            add_edge(script_node, f"api.{html_ui_slug(api_target, 'api')}", "inline_script_api", rel_path, api_target)

    output_path = Path(output_dir)
    output_path.mkdir(parents=True, exist_ok=True)
    json_path = output_path / "html_ui_graph.json"
    graph = {
        "mode": "html_ui_graph",
        "version": HTML_UI_GRAPH_VERSION,
        "nodes": sorted(nodes),
        "edges": [[src, dst] for src, dst in sorted(edges)],
        "elements": elements,
        "edge_details": edge_details,
    }
    json_path.write_text(json.dumps(graph, indent=2), encoding="utf-8")
    logger.info("HTML UI graph written: %s elements=%s edges=%s", json_path, len(elements), len(edges))
    return str(json_path), ""


def dispatch_parsers(lang_map, repo_src, output_repo_dir, progress_callback=None):
    results = {}
    progress_lock = threading.Lock()

    def progress(message, current_file=None):
        with progress_lock:
            if progress_callback:
                try:
                    progress_callback(message, current_file=current_file)
                except TypeError:
                    progress_callback(message)
            logger.info(message)

    def build_html_lane():
        lane_results = {}
        try:
            progress("Building HTML UI interaction graph...")
            html_ui_path = os.path.join(output_repo_dir, "html_ui")
            html_ui_json_path, html_ui_html_path = build_html_ui_graph(
                repo_src,
                html_ui_path,
                progress_callback=progress,
            )
            lane_results["html_ui_graph_json_path"] = html_ui_json_path
            progress("HTML UI interaction graph built.")
        except Exception as e:
            logger.warning("HTML UI graph analysis failed; continuing with available graphs: %s", e)
            lane_results["html_ui_graph_error"] = str(e)
        return lane_results

    parser_parallelism_enabled = (
        os.getenv("CODEVAL_PARSER_TWO_LANE_ENABLED", "true").strip().lower()
        not in {"0", "false", "no", "off"}
    )
    light_thread = None
    light_results = {}
    if lang_map["html"] and parser_parallelism_enabled:
        progress("Starting bounded parser lanes: one heavy parser and one HTML/UI parser.")
        def run_light_lane():
            light_results.update(build_html_lane())

        light_thread = threading.Thread(
            target=run_light_lane,
            name="codeval-light-parser",
            daemon=True,
        )
        light_thread.start()

    if lang_map["python"]:
        progress("Analyzing Python code structure...")
        python_path = os.path.join(output_repo_dir, "python")
        os.makedirs(python_path, exist_ok=True)
        python_callgraph_json_path = build_python_callgraph(repo_src, python_path, progress_callback=progress)
        results["python_callgraph_json_path"] = python_callgraph_json_path
        python_ordered_path = os.path.join(python_path, "python_ordered_call_sequence.json")
        if os.path.exists(python_ordered_path):
            results["python_ordered_call_sequence_path"] = python_ordered_path

        progress("Python code structure analysis complete.")

    if lang_map["javascript"]:
        try:
            progress("Analyzing JavaScript and TypeScript code structure...")
            javascript_path = os.path.join(output_repo_dir, "javascript")
            os.makedirs(javascript_path, exist_ok=True)
            javascript_callgraph_json_path = build_javascript_callgraph(repo_src, javascript_path, progress_callback=progress)
            results["javascript_callgraph_json_path"] = javascript_callgraph_json_path
            javascript_ordered_path = os.path.join(javascript_path, "javascript_ordered_call_sequence.json")
            if os.path.exists(javascript_ordered_path):
                results["javascript_ordered_call_sequence_path"] = javascript_ordered_path
            progress("JavaScript and TypeScript code structure analysis complete.")
        except Exception as e:
            logger.warning("JavaScript/TypeScript analysis failed; continuing with available graphs: %s", e)
            results["javascript_error"] = str(e)

    if lang_map["csharp"]:
        try:
            progress("Analyzing C# code structure...")
            csharp_path = os.path.join(output_repo_dir, "csharp")
            csharp_callgraph_json_path, _csharp_callgraph_html_path, csharp_ordered_path = build_csharp_callgraph(repo_src, csharp_path, progress_callback=progress)
            results["csharp_callgraph_json_path"] = csharp_callgraph_json_path
            if csharp_ordered_path:
                results["csharp_ordered_call_sequence_path"] = csharp_ordered_path
            progress("C# code structure analysis complete.")
        except Exception as e:
            logger.warning("C# analysis failed; continuing with available graphs: %s", e)
            results["csharp_error"] = str(e)

    logger.info("Dispatching parsers: repo_src=%s output_repo_dir=%s", repo_src, output_repo_dir)
    output_joern_dir = os.path.join(output_repo_dir, f"joern")
    joern_enabled = joern_enabled_by_default()
    should_try_joern = (
        lang_map["c"] or
        lang_map["cpp"] or
        lang_map["java"] or
        lang_map["kotlin"] or
        lang_map["go"]
    )

    if lang_map["java"]:
        try:
            progress("Analyzing Java code structure...")
            build_tree_sitter_java_outputs(repo_src, output_repo_dir, results)
            progress("Java code structure analysis complete.")
        except Exception as e:
            logger.warning("Tree-sitter Java analysis failed; continuing with javalang: %s", e)
            results["tree_sitter_java_error"] = str(e)

        try:
            progress("Extracting Java call relationships...")
            build_javalang_outputs(repo_src, output_repo_dir, results, progress_callback=progress)
            progress("Java call relationships extracted.")
        except Exception as e:
            logger.warning("javalang analysis failed; continuing with available Java graphs: %s", e)
            results["javalang_error"] = str(e)

        progress("Consolidating Java analysis results.")
        build_merged_java_outputs(output_repo_dir, results)
        progress("Java insights are ready.")

    if should_try_joern:
        if not joern_enabled:
            results["joern_error"] = "Joern analysis is disabled. Set ENABLE_JOERN=true to run Joern."
        else:
            os.makedirs(output_joern_dir, exist_ok=True)
            try:
                progress("Trying Joern graph extraction.")
                resultsTemp = run_joern(repo_src, output_joern_dir)
            except Exception as e:
                log_message = "Joern analysis unavailable; falling back where possible: %s"
                if "Joern executable was not found" in str(e):
                    logger.info(log_message, e)
                else:
                    logger.warning("Joern analysis failed; falling back where possible: %s", e)
                results["joern_error"] = str(e)
            else:
                progress("Joern graph extraction completed.")
                results.update({
                    "joern_callgraph.json": resultsTemp["joern_callgraph.json"],
                    "joern_callgraph_ordered.json": resultsTemp["joern_callgraph_ordered.json"],
                    "joern_cfg.json": resultsTemp["joern_cfg.json"],
                    "joern_comments.json": resultsTemp["joern_comments.json"],
                    "joern_functions.json": resultsTemp["joern_functions.json"],
                    "joern_roots.json": resultsTemp["joern_roots.json"],
                })
                joern_ordered_sequence_path = normalize_joern_ordered_call_sequence(
                    results.get("joern_callgraph_ordered.json", ""),
                    output_joern_dir,
                )
                if joern_ordered_sequence_path:
                    results["joern_ordered_call_sequence_path"] = joern_ordered_sequence_path


    if "joern_callgraph.json" in results:
        joern_callgraph_json_path = results.get("joern_callgraph.json", "")
        reduced_joern_callgraph_json_name = "reduced_joern_callgraph.json"
        reduced_joern_callgraph_json_path = os.path.join(output_joern_dir, reduced_joern_callgraph_json_name)
        reduced = reduce_callgraph(joern_callgraph_json_path)
        logger.info(
            "Reduced Joern callgraph: json=%s nodes=%s edges=%s",
            reduced_joern_callgraph_json_path,
            len(reduced["nodes"]),
            len(reduced["edges"]),
        )

        write_cytoscape_json(reduced, reduced_joern_callgraph_json_path)
        results["reduced_joern_callgraph_json_path"] = reduced_joern_callgraph_json_path
        progress("Joern graph JSON reduced.")

    if light_thread is not None:
        progress("Waiting for the HTML/UI parser lane before graph merging.")
        light_thread.join()
        results.update(light_results)
        progress("Heavy and light parser lanes complete.")
    elif lang_map["html"]:
        results.update(build_html_lane())

    progress("Building navigable function and UI callgraph.")
    build_combined_navigatable_callgraph(output_repo_dir, results, repo_src)
    progress("Navigable function and UI callgraph built.")

    progress("Building file dependency graph.")
    build_file_graph_outputs(output_repo_dir, results)
    progress("File dependency graph built.")

    # Convert json to HTML graph
    #reduced_joern_cfg_html_name = "reduced_joern_cfg.html"
    #reduced_joern_cfg_html_path = os.path.join(output_joern_dir, reduced_joern_cfg_html_name)
    #print("reduced_joern_cfg_json_path = " + reduced_joern_callgraph_json_path)
    #print("reduced_joern_cfg_html_name = " + reduced_joern_cfg_html_name)
    #print("reduced_joern_cfg_html_path = " + reduced_joern_cfg_html_path)
    #results["reduced_joern_cfg_html"] = build_cytoscape_html( reduced_joern_callgraph_json_path, reduced_joern_cfg_html_path)

        # Copy the HTML template into javalang_dir
        # shutil.copy(CYTOSCAPE_TEMPLATE_HTML_PATH, callgraph_javalang_cytoscape_html_path)

        # Ensure the HTML loads the correct JSON file
        # (optional: dynamically inject the JSON filename)



    # 2. Joern bucket (C, C++, Java, Kotlin, Go)
    # if (
    #    lang_map["c"] or
    #    lang_map["cpp"] or
    #    lang_map["java"] or
    #    lang_map["kotlin"] or
    #    lang_map["go"]
    # ):
    #    joern_dir = os.path.join(output_repo_dir, f"joern")
    #    os.makedirs(javalang_dir, exist_ok=True)    
    #    run_joern(repo_src, joern_dir)
    
    # 3. Python bucket
    #if lang_map["python"]:
    #    build_python_callgraph(repo_src, output_dir)
    
    # 4. HTML bucket
    #if lang_map["html"]:
    #    build_html_graph(repo_src, output_dir)
    
    return results


import hashlib

def short_id(owner, repo):
    base = f"{owner}/{repo}"
    h = hashlib.sha1(base.encode()).hexdigest()[:8]
    return f"{owner[:6]}_{repo[:6]}_{h}"





