    callgraph_json = os.path.join(javalang_dir, "javalang_callgraph.json")
    javalang_ordered_sequence = os.path.join(javalang_dir, "javalang_ordered_call_sequence.json")
    callgraph_html = os.path.join(javalang_dir, "callgraph_javalang_cytoscape.html")
    tree_sitter_dir = os.path.join(output_repo_dir, "tree_sitter_java")
    tree_sitter_java_json = os.path.join(tree_sitter_dir, "tree_sitter_java_callgraph.json")
    tree_sitter_java_ordered_sequence = os.path.join(tree_sitter_dir, "tree_sitter_java_ordered_call_sequence.json")
    tree_sitter_java_html = os.path.join(tree_sitter_dir, "tree_sitter_java_cytoscape.html")
    java_merged_dir = os.path.join(output_repo_dir, "java_merged")
    java_merged_json = os.path.join(java_merged_dir, "java_merged_callgraph.json")
    java_merged_ordered_sequence = os.path.join(java_merged_dir, "java_merged_ordered_call_sequence.json")
    java_merged_html = os.path.join(java_merged_dir, "java_merged_cytoscape.html")
    java_merged_navigatable_html = os.path.join(java_merged_dir, "java_merged_navigatable_callgraph.html")
    file_graph_dir = os.path.join(output_repo_dir, "file_graph")
