def code_md_json_section(title: str, payload: dict) -> str:
    return f"## {title}\n{json.dumps(payload, indent=2, ensure_ascii=False)}\n"


def code_md_short_text(text: str, max_chars: int = 280) -> str:
    cleaned = re.sub(r"\s+", " ", str(text or "")).strip()
    if len(cleaned) <= max_chars:
        return cleaned
    return cleaned[: max(0, max_chars - 1)].rstrip() + "…"


def code_md_read_json(path: str | Path):
    if not path or not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def code_md_path_candidates(repo_text: dict, repo_comments: dict, graph_nodes=None) -> list[str]:
    paths = set()
    if isinstance(repo_text, dict):
        for key in ("readme_items", "document_items", "text_items", "ui_text_items"):
            for item in repo_text.get(key) or []:
                path = str(item.get("file") or "").replace("\\", "/").strip("/")
                if path and "." in Path(path).name:
                    paths.add(path)
    if isinstance(repo_comments, dict):
        for key in ("comments", "todos"):
            for item in repo_comments.get(key) or []:
                path = str(item.get("file") or "").replace("\\", "/").strip("/")
                if path and "." in Path(path).name:
                    paths.add(path)
    for node in graph_nodes or []:
        text = str(node or "").replace("\\", "/")
        if "/" in text and "." in Path(text).name:
            paths.add(text.strip("/"))
    return sorted(paths)


def code_md_folder_summary(paths: list[str], limit: int = 14) -> dict:
    counts = Counter()
    for path in paths:
        parts = [part for part in str(path).split("/") if part]
        if len(parts) >= 2:
            folder = "/".join(parts[:2]) if parts[0] in {"src", "app", "apps", "packages", "frontend", "backend", "server", "client"} else parts[0]
            counts[folder] += 1
    return {
        folder: f"{count} analyzed file reference{'s' if count != 1 else ''}"
        for folder, count in counts.most_common(limit)
    }


def code_md_infer_modules(paths: list[str], feature_names: list[str], graph_summary: dict) -> dict:
    modules = {}
    folder_counts = Counter()
    for path in paths:
        first = str(path).split("/", 1)[0]
        if first and first not in {".", ".."}:
            folder_counts[first] += 1
    for folder, count in folder_counts.most_common(10):
        modules[folder] = {
            "responsibility": f"Inferred from {count} analyzed file reference{'s' if count != 1 else ''} under `{folder}`.",
            "dependencies": [],
            "invariants": [],
            "high_risk": folder in graph_summary.get("core_files", []),
        }
    for name in feature_names[:8]:
        key = html_ui_slug(name, "feature", max_len=42)
        modules.setdefault(key, {
            "responsibility": f"Detected product feature: {name}",
            "dependencies": [],
            "invariants": [],
        })
    return modules


def code_md_graph_summary(graph_path: str, file_graph_path: str = "") -> dict:
    nodes, edges, edge_meta = _load_edge_graph_with_meta(graph_path)
    file_nodes, file_edges = _load_edge_graph(file_graph_path) if file_graph_path else (set(), set())
    outgoing = defaultdict(set)
    incoming = defaultdict(set)
    for src, dst in edges:
        outgoing[src].add(dst)
        incoming[dst].add(src)
    degree_ranked = sorted(
        nodes,
        key=lambda node: (len(incoming.get(node, ())) + len(outgoing.get(node, ())), str(node)),
        reverse=True,
    )
    entrypoints = _load_graph_entry_points(graph_path, nodes)[:12]
    if not entrypoints:
        entrypoints = [
            node for node in degree_ranked
            if re.search(r"(^|[._/])(main|app|index|server|handler|route|api|page)([._/]|$)", str(node), re.I)
        ][:12]
    core_files = []
    for node in degree_ranked:
        text = str(node).replace("\\", "/")
        if "/" in text and "." in Path(text).name:
            core_files.append(text)
        if len(core_files) >= 12:
            break
    if not core_files:
        core_files = sorted(str(node) for node in file_nodes)[:12]
    critical_paths = [
        f"{src} → {dst}"
        for src, dst in sorted(edges, key=lambda edge: (edge_meta.get(edge, {}).get("order") or 10**9, edge[0], edge[1]))[:12]
    ]
    return {
        "node_count": len(nodes),
        "edge_count": len(edges),
        "file_node_count": len(file_nodes),
        "file_edge_count": len(file_edges),
        "entrypoints": entrypoints,
        "critical_paths": critical_paths,
        "core_files": core_files,
        "high_risk_paths": [node for node in degree_ranked[:10]],
        "cycles": [],
    }


def code_md_feature_names(feature_catalog: dict, feature_summaries: list, ui_feature_seeds: list) -> list[str]:
    return []


@app.post("/code-md")
def code_md_endpoint(payload: dict):
    """Return a CODE.md file for a GitHub repository.

    If the repository has already been analyzed by CodeVal the artifacts are
    loaded from disk immediately (fast).  If not, a 404 is returned with
    instructions to run /analyze first — keeping this endpoint synchronous and
    avoiding unbounded analysis time inside a single HTTP request.
    """
    from fastapi.responses import Response as FastAPIResponse
    repo_url = str(payload.get("repo_url") or "").strip()
    if not repo_url:
        raise HTTPException(status_code=400, detail="repo_url is required. Example: {'repo_url': 'https://github.com/user/repo'}")
    match = re.search(r"github\.com/([^/\s]+)/([^/\s?#]+)", repo_url)
    if not match:
        raise HTTPException(status_code=400, detail="Only public GitHub URLs are currently supported. Example: https://github.com/user/repo")
    owner = match.group(1).strip()
    repo = match.group(2).rstrip(".git").strip()
    output_dir = repo_output_dir(owner, repo)
    artifact_root = artifact_root_for_output(output_dir)
    repo_stats_path = ensure_repo_text_artifact_path(output_dir, "repo_stats.json")
    if not repo_stats_path.exists():
        raise HTTPException(
            status_code=404,
            detail=(
                f"No analysis found for {owner}/{repo}. "
                "Analyze it first: POST /analyze with {\"repoUrl\": \"" + repo_url + "\"}, "
                "then call POST /code-md again."
            ),
        )
    def _load(path):
        return code_md_read_json(str(path)) or {}
    repo_stats = _load(repo_stats_path)
    repo_text = _load(ensure_repo_text_artifact_path(output_dir, "repo_text.json"))
    repo_comments = _load(ensure_repo_text_artifact_path(output_dir, "repo_comments.json"))
    static_quality_signals = _load(Path(output_dir) / "static_quality_signals.json")
    feature_catalog = {}
    feature_summaries = []
    ui_feature_seeds = []
    for fc_path in [
        artifact_root / "scim" / "feature_catalog.json",
        Path(output_dir) / "feature_catalog.json",
    ]:
        if fc_path.exists():
            feature_catalog = _load(fc_path)
            ui_feature_seeds = feature_catalog.get("ui_feature_seeds") or []
            break
    for fs_path in [
        Path(output_dir) / "feature_summaries.json",
        artifact_root / "scim" / "feature_summaries.json",
    ]:
        if fs_path.exists():
            feature_summaries = _load(fs_path) if isinstance(_load(fs_path), list) else []
            break
    graph_candidates = [
        artifact_root / "combined_callgraph" / "combined_callgraph.json",
        artifact_root / "python" / "python_callgraph.json",
        artifact_root / "javascript" / "javascript_callgraph.json",
    ]
    graph_path = next((str(p) for p in graph_candidates if p.exists()), "")
    file_graph_candidates = [
        artifact_root / "file_graph" / "file_graph.json",
        Path(output_dir) / "file_graph" / "file_graph.json",
    ]
    file_graph_path = next((str(p) for p in file_graph_candidates if p.exists()), "")
    output_file = build_code_md_artifact(
        str(output_dir), owner, repo,
        repo_stats, repo_text, repo_comments,
        feature_catalog, feature_summaries, ui_feature_seeds,
        static_quality_signals, graph_path, file_graph_path,
    )
    try:
        content = Path(output_file).read_text(encoding="utf-8")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"CODE.md was generated but could not be read: {e}")
    return FastAPIResponse(
        content=content,
        media_type="text/plain; charset=utf-8",
        headers={
            "Content-Disposition": f'attachment; filename="code.md"',
            "X-CodeVal-Repo": f"{owner}/{repo}",
            "X-CodeVal-Artifact": output_url(output_file),
        },
    )


def build_code_md_artifact(
    output_repo_dir,
    owner: str,
    repo: str,
    repo_stats: dict,
    repo_text: dict,
    repo_comments: dict,
    feature_catalog: dict,
    feature_summaries: list,
    ui_feature_seeds: list,
    static_quality_signals: dict,
    graph_path: str,
    file_graph_path: str,
    daily_change_cache: dict | None = None,
):
    graph_summary = code_md_graph_summary(graph_path, file_graph_path)
    paths = code_md_path_candidates(repo_text, repo_comments, graph_summary.get("core_files"))
    feature_names = code_md_feature_names(feature_catalog, feature_summaries, ui_feature_seeds)
    readme_text = ""
    if isinstance(repo_text, dict) and repo_text.get("readme_items"):
        readme_text = str((repo_text.get("readme_items") or [{}])[0].get("text") or "")
    architecture = []
    language_counts = repo_stats.get("language_counts") or {}
    if language_counts:
        architecture.append(", ".join(list(language_counts.keys())[:5]))
    if graph_summary.get("node_count"):
        architecture.append(f"{graph_summary['node_count']} graph nodes / {graph_summary['edge_count']} edges")
    quality_groups = (static_quality_signals or {}).get("groups") or {}
    flat_quality = [item for group in quality_groups.values() if isinstance(group, list) for item in group]
    high_risk_files = []
    for item in flat_quality:
        path = str(item.get("path") or "").replace("\\", "/")
        if path and path not in high_risk_files:
            high_risk_files.append(path)
        if len(high_risk_files) >= 10:
            break
    todo_flows = [
        str(item.get("text") or item.get("tag") or "")
        for item in (repo_comments.get("todos") if isinstance(repo_comments, dict) else [])[:8]
    ]
    generated_at = datetime.now(timezone.utc).isoformat()
    sections = [
        code_md_json_section("system", {
            "name": (repo_stats.get("repo_full_name") or f"{owner}/{repo}"),
            "description": code_md_short_text(readme_text, 360) or "Repository analyzed by CodeVal.",
            "primary_flows": feature_names[:10] or todo_flows[:5],
            "architecture": " + ".join(architecture) or "Static repository analysis artifacts",
            "generated_at": generated_at,
        }),
        code_md_json_section("repository_structure", {
            "folders": code_md_folder_summary(paths),
            "naming_conventions": {
                "files": "Inferred from repository paths; no enforced convention detected statically.",
                "components": "Detected from UI/source names when present.",
            },
            "allowed_imports": {},
            "forbidden_imports": {},
        }),
        code_md_json_section("modules", code_md_infer_modules(paths, feature_names, graph_summary)),
        code_md_json_section("callgraph", {
            "entrypoints": graph_summary.get("entrypoints", []),
            "critical_paths": graph_summary.get("critical_paths", []),
            "high_risk_paths": graph_summary.get("high_risk_paths", []),
            "node_count": graph_summary.get("node_count", 0),
            "edge_count": graph_summary.get("edge_count", 0),
        }),
        code_md_json_section("filegraph", {
            "layers": ["UI", "API", "Domain", "DB"],
            "cycles": graph_summary.get("cycles", []),
            "clusters": {
                key.replace("/", "_"): [folder]
                for key, folder in zip(code_md_folder_summary(paths).keys(), code_md_folder_summary(paths).keys())
            },
            "core_files": graph_summary.get("core_files", []),
        }),
        code_md_json_section("behavior", {
            "function_meaning": {
                str(item.get("name") or item.get("feature") or f"feature_{index + 1}"): code_md_short_text(item.get("description") or item.get("summary") or "", 220)
                for index, item in enumerate(feature_summaries or [])
                if isinstance(item, dict) and (item.get("description") or item.get("summary"))
            },
            "constraints": {},
            "error_rules": {
                "static_quality": "Use CodeVal static quality signals as validation evidence; do not treat heuristics as runtime proof."
            },
        }),
        code_md_json_section("commit_intent", {
            "patterns": ["UI updates", "API contract changes", "business logic adjustments"],
            "risk_level": {"high": high_risk_files},
            "impact_paths": ["UI → API → Domain → DB"],
            "recent_change_cache_available": bool(daily_change_cache),
        }),
        code_md_json_section("drift", {
            "structure_drift": "new dependencies violating intended module direction",
            "semantic_drift": "function or feature meaning changes compared with saved summaries",
            "behavior_drift": "control flow changed in critical paths",
            "risk_drift": "commits touching multiple core files or high-degree graph nodes",
            "score": 0,
            "timeline": [],
        }),
        code_md_json_section("errors", {
            "mapping": {
                str(item.get("id") or item.get("type") or index): item.get("path") or item.get("symbol") or ""
                for index, item in enumerate(flat_quality[:20])
                if isinstance(item, dict)
            },
            "clusters": {},
            "regressions": {},
        }),
        code_md_json_section("validation", {
            "critical_flows": feature_names[:12],
            "invariants": [],
            "browser_tests": ["product_url_smoke", "page_load", "console_errors"],
        }),
        code_md_json_section("autoheal", {
            "fix_patterns": {
                "search": "sanitize inputs → rerun query → present fallback evidence",
                "session": "validate token → refresh/retry → fallback to login",
            },
            "safe_rules": ["never modify DB schema automatically", "never remove validation logic", "require user approval before applying code changes"],
            "risky_areas": high_risk_files[:8],
            "validation_steps": ["api_smoke_tests", "drift_check"],
        }),
        code_md_json_section("glossary", {
            "critical_path": "a flow that must always succeed",
            "drift": "deviation from intended architecture or behavior",
            "semantic_diff": "change in function meaning measured from saved summaries or embeddings",
        }),
    ]
    output_path = Path(output_repo_dir) / "CODE.md"
    output_path.write_text("\n".join(sections), encoding="utf-8")
    return str(output_path)


def build_code_md_artifact(
    output_repo_dir,
    owner: str,
    repo: str,
    repo_stats: dict,
    repo_text: dict,
    repo_comments: dict,
    feature_catalog: dict,
    feature_summaries: list,
    ui_feature_seeds: list,
    static_quality_signals: dict,
    graph_path: str,
    file_graph_path: str,
    daily_change_cache: dict | None = None,
    source_dir: str | None = None,
):
    """Build Code.md from deterministic repo evidence only."""
    artifact_root = artifact_root_for_output(Path(output_repo_dir))
    source_root = Path(source_dir).resolve() if source_dir and Path(source_dir).exists() else None
    if source_root is None:
        source_root = source_root_for_artifact(artifact_root)
    if source_root is None:
        source_root = find_cached_source_dir(Path(output_repo_dir))
    source_root = Path(source_root) if source_root else None

    def md_table(headers, rows):
        if not rows:
            return "_No rows found from the available direct evidence._\n"
        output = ["| " + " | ".join(headers) + " |", "| " + " | ".join(["---"] * len(headers)) + " |"]
        for row in rows:
            output.append("| " + " | ".join(("" if cell is None else str(cell)).replace("|", "\\|").replace("\n", " ") for cell in row) + " |")
        return "\n".join(output) + "\n"

    def normalize_edges(raw_edges):
        return [(str(edge[0]), str(edge[1])) for edge in (raw_edges or []) if isinstance(edge, (list, tuple)) and len(edge) >= 2]

    def source_files(suffixes):
        if not source_root or not source_root.exists():
            return []
        excluded = {".git", "node_modules", "__pycache__", ".pytest_cache", ".mypy_cache", ".ruff_cache", ".venv", "venv"}
        files = []
        for path in source_root.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in suffixes:
                continue
            try:
                parts = path.relative_to(source_root).parts
            except ValueError:
                parts = path.parts
            if (
                should_skip_path(str(path), str(source_root))
                or any(part in excluded or (part.startswith(".") and part not in {".github"}) for part in parts)
            ):
                continue
            files.append(path)
        return sorted(files)

    def source_rel(path):
        try:
            return path.relative_to(source_root).as_posix()
        except Exception:
            return path.name

    graph_payload = code_md_read_json(graph_path)
    graph_nodes = [str(node) for node in graph_payload.get("nodes") or []] if isinstance(graph_payload, dict) else []
    graph_edges = normalize_edges(graph_payload.get("edges") if isinstance(graph_payload, dict) else [])
    entry_points = [str(node) for node in graph_payload.get("entry_points") or []] if isinstance(graph_payload, dict) else []
    indegree = Counter(dst for _, dst in graph_edges)
    outdegree = Counter(src for src, _ in graph_edges)
    total_degree = Counter({node: indegree[node] + outdegree[node] for node in graph_nodes})

    api_routes = []
    for path in source_files({".py"}):
        try:
            tree = ast.parse(path.read_text(encoding="utf-8", errors="ignore"))
        except Exception:
            continue
        for node in ast.walk(tree):
            if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                continue
            for decorator in node.decorator_list:
                call = decorator if isinstance(decorator, ast.Call) else None
                target = call.func if call else decorator
                if not isinstance(target, ast.Attribute) or not call or not call.args or not isinstance(call.args[0], ast.Constant):
                    continue
                method = target.attr
                if method not in {"get", "post", "put", "patch", "delete", "options", "head", "api_route", "route"}:
                    continue
                methods = None
                for keyword in call.keywords:
                    if keyword.arg == "methods":
                        try:
                            methods = ast.literal_eval(keyword.value)
                        except Exception:
                            methods = None
                method_text = ",".join(str(item) for item in methods) if method in {"api_route", "route"} and methods else method.upper()
                api_routes.append([method_text, call.args[0].value, node.name, source_rel(path), getattr(decorator, "lineno", node.lineno)])
    js_route_re = re.compile(r"\b(?:app|router|server|route)\s*\.\s*(get|post|put|patch|delete|options|head|all)\s*\(\s*['\"]([^'\"]+)['\"]", re.I)
    for path in source_files({".js", ".jsx", ".ts", ".tsx"}):
        try:
            lines = path.read_text(encoding="utf-8", errors="ignore").splitlines()
        except OSError:
            continue
        for line_number, line in enumerate(lines, start=1):
            for match in js_route_re.finditer(line):
                api_routes.append([match.group(1).upper(), match.group(2), "", source_rel(path), line_number])
    api_routes = sorted(api_routes, key=lambda row: (str(row[3]), int(row[4] or 0), str(row[1])))

    entry_rows = [[node, outdegree[node], indegree[node]] for node in sorted(entry_points)[:80]]
    risky_rows = [[node, indegree[node], outdegree[node], total_degree[node]] for node in sorted(graph_nodes, key=lambda item: (-indegree[item], item)) if indegree[node] > 0][:30]
    top_rows = [[node, total_degree[node], indegree[node], outdegree[node]] for node in sorted(graph_nodes, key=lambda item: (-total_degree[item], item)) if total_degree[node] > 0][:30]
    complex_rows = [[node, outdegree[node], indegree[node], total_degree[node]] for node in sorted(graph_nodes, key=lambda item: (-outdegree[item], item)) if outdegree[node] > 0][:30]

    file_payload = code_md_read_json(file_graph_path)
    file_edges = normalize_edges(file_payload.get("edges") if isinstance(file_payload, dict) else [])
    file_reasons = {}
    for detail in (file_payload.get("edge_details") if isinstance(file_payload, dict) else []) or []:
        if isinstance(detail, dict):
            file_reasons[(str(detail.get("source")), str(detail.get("target")))] = ", ".join(detail.get("reasons") or []) or str(detail.get("kind") or "")
    file_dependency_rows = [[src, dst, file_reasons.get((src, dst), "")] for src, dst in sorted(file_edges)[:80]]
    file_indegree = Counter(dst for src, dst in file_edges)
    file_outdegree = Counter(src for src, dst in file_edges)
    file_nodes = set(str(item) for item in (file_payload.get("nodes") if isinstance(file_payload, dict) else []) or []) | set(file_indegree) | set(file_outdegree)
    core_file_rows = [[path, file_indegree[path] + file_outdegree[path], file_indegree[path], file_outdegree[path]] for path in sorted(file_nodes, key=lambda item: (-(file_indegree[item] + file_outdegree[item]), item)) if file_indegree[path] + file_outdegree[path] > 0][:30]

    python_ranges = {}
    for path in source_files({".py"}):
        try:
            tree = ast.parse(path.read_text(encoding="utf-8", errors="ignore"))
        except Exception:
            continue
        ranges = []
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                ranges.append((node.lineno, getattr(node, "end_lineno", node.lineno), node.name))
        python_ranges[path] = sorted(ranges)

    def enclosing_python_function(path, line_number):
        owners = [item for item in python_ranges.get(path, []) if item[0] <= line_number <= item[1]]
        return max(owners, key=lambda item: item[0])[2] if owners else ""

    database_rows = []
    db_write_re = re.compile(r"\.(insert|update|delete|upsert|rpc)\s*\(")
    for path in source_files({".py", ".js", ".jsx", ".ts", ".tsx"}):
        try:
            lines = path.read_text(encoding="utf-8", errors="ignore").splitlines()
        except OSError:
            continue
        for line_number, line in enumerate(lines, start=1):
            match = db_write_re.search(line)
            if not match:
                continue
            window = "\n".join(lines[max(0, line_number - 8): min(len(lines), line_number + 4)]).lower()
            if not any(token in window for token in ("client.table", ".table(", "supabase", ".from(", "collection(")):
                continue
            function_name = enclosing_python_function(path, line_number) if path.suffix.lower() == ".py" else ""
            symbol = f"{source_rel(path).replace('/', '.').rsplit('.', 1)[0]}.{function_name}" if function_name else ""
            database_rows.append([source_rel(path), line_number, match.group(1), function_name, indegree[symbol] if symbol else "", line.strip()[:180]])
    database_rows = sorted(database_rows, key=lambda row: (row[0], int(row[1] or 0)))[:120]

    stdlib_names = set(getattr(sys, "stdlib_module_names", set()))
    local_tops = ({path.name for path in source_root.iterdir() if path.is_dir()} | {path.stem for path in source_root.glob("*.py")}) if source_root and source_root.exists() else set()
    external_counts = Counter()
    external_examples = defaultdict(list)
    for path in source_files({".py"}):
        try:
            tree = ast.parse(path.read_text(encoding="utf-8", errors="ignore"))
        except Exception:
            continue
        for node in ast.walk(tree):
            names = []
            if isinstance(node, ast.Import):
                names = [alias.name.split(".")[0] for alias in node.names]
            elif isinstance(node, ast.ImportFrom) and node.module and node.level == 0:
                names = [node.module.split(".")[0]]
            for name in names:
                if not name or name in stdlib_names or name in local_tops:
                    continue
                external_counts[name] += 1
                if len(external_examples[name]) < 5:
                    external_examples[name].append(f"{source_rel(path)}:{getattr(node, 'lineno', '')}")
    js_import_re = re.compile(r"(?:from\s+['\"]([^.'\"/][^'\"]*)['\"]|require\(['\"]([^.'\"/][^'\"]*)['\"]\)|import\s+['\"]([^.'\"/][^'\"]*)['\"])", re.I)
    for path in source_files({".js", ".jsx", ".ts", ".tsx"}):
        try:
            lines = path.read_text(encoding="utf-8", errors="ignore").splitlines()
        except OSError:
            continue
        for line_number, line in enumerate(lines, start=1):
            for match in js_import_re.finditer(line):
                module_name = next((group for group in match.groups() if group), "")
                package = module_name.split("/")[0] if not module_name.startswith("@") else "/".join(module_name.split("/")[:2])
                if package in local_tops:
                    continue
                external_counts[package] += 1
                if len(external_examples[package]) < 5:
                    external_examples[package].append(f"{source_rel(path)}:{line_number}")
    external_rows = [[name, count, ", ".join(external_examples[name])] for name, count in external_counts.most_common(40)]

    html_ui_payload = code_md_read_json(artifact_root / "html_ui" / "html_ui_graph.json")
    ui_rows = []
    for element in (html_ui_payload.get("elements") if isinstance(html_ui_payload, dict) else []) or []:
        if not isinstance(element, dict):
            continue
        tag = str(element.get("tag") or "")
        attrs = {key: element.get(key) for key in ("id", "name", "role", "type", "text", "href") if element.get(key)}
        if tag in {"button", "a", "input", "select", "textarea", "form", "summary"} or attrs.get("role") == "button" or attrs.get("href"):
            ui_rows.append([element.get("file", ""), element.get("line", ""), tag, json.dumps(attrs, ensure_ascii=False)[:220]])
    ui_rows = sorted(ui_rows, key=lambda row: (str(row[0]), int(row[1]) if str(row[1]).isdigit() else 0))[:100]
    todo_rows = [[item.get("file", ""), item.get("line", ""), item.get("tag", "TODO"), str(item.get("text") or "")[:240]] for item in ((repo_comments or {}).get("todos") if isinstance(repo_comments, dict) else []) or [] if isinstance(item, dict)]

    def run_git(args):
        if not source_root or not (source_root / ".git").exists():
            return ""
        try:
            completed = subprocess.run(["git", *args], cwd=str(source_root), text=True, encoding="utf-8", errors="replace", stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, timeout=15, check=False)
            return completed.stdout if completed.returncode == 0 else ""
        except Exception:
            return ""

    recent_rows, high_churn_rows, stable_rows = [], [], []
    git_log = run_git(["log", "--name-only", "--pretty=format:COMMIT:%H|%ad|%s", "--date=iso", "-n", "50"])
    if git_log:
        commits, current = [], None
        for line in git_log.splitlines():
            if line.startswith("COMMIT:"):
                if current:
                    commits.append(current)
                parts = line[len("COMMIT:"):].split("|", 2)
                current = {"hash": parts[0], "date": parts[1] if len(parts) > 1 else "", "subject": parts[2] if len(parts) > 2 else "", "files": []}
            elif current is not None and line.strip() and not should_skip_path(line.strip(), str(source_root)):
                current["files"].append(line.strip())
        if current:
            commits.append(current)
        recent_rows = [[item["hash"][:10], item["date"], item["subject"], ", ".join(item["files"][:8]) + (" ..." if len(item["files"]) > 8 else "")] for item in commits[:20]]
        churn = Counter(
            line.strip()
            for line in run_git(["log", "--name-only", "--pretty=format:", "-n", "100"]).splitlines()
            if line.strip() and not should_skip_path(line.strip(), str(source_root))
        )
        high_churn_rows = [[path, count] for path, count in churn.most_common(40)]
        stable_rows = [[path] for path in sorted(path for path in run_git(["ls-files"]).splitlines() if path.strip() and path.strip() not in churn and not should_skip_path(path.strip(), str(source_root)))[:80]]
    elif isinstance(daily_change_cache, dict):
        commits = [item for item in daily_change_cache.get("commits") or [] if isinstance(item, dict)]
        recent_rows = [[str(item.get("short_sha") or item.get("sha") or "")[:10], item.get("date", ""), item.get("message", ""), ", ".join(str(file_item.get("filename") or file_item) for file_item in (item.get("changed_files") or [])[:8]) if isinstance(item.get("changed_files"), list) else ""] for item in commits[:20]]
        churn = Counter()
        for file_item in daily_change_cache.get("changed_files") or []:
            if isinstance(file_item, dict) and file_item.get("filename"):
                churn[str(file_item.get("filename"))] += int(file_item.get("changes") or 1)
        for item in commits:
            for file_item in item.get("changed_files") or []:
                filename = file_item.get("filename") if isinstance(file_item, dict) else str(file_item)
                if filename:
                    churn[filename] += 1
        high_churn_rows = [[path, count] for path, count in churn.most_common(40)]

    sections = [
        "# code.md",
        "Machine-generated structural truth for this repository.",
        "Used by coding agents to understand architecture, flow, and dependencies.",
        "",
        f"Generated for {owner}/{repo} from direct repository evidence only. No LLM summaries, feature catalog, embeddings, vectors, train pairs, or model-layer files are used.",
        "Only deterministic sections requested by the user are included.",
        "",
        "## api_routes", "Evidence: deterministic Python decorator parsing plus exact JavaScript/TypeScript route-call parsing from source files.", md_table(["Method", "Path", "Handler", "File", "Line"], api_routes),
        "## entry_points", "Evidence: exact `entry_points` array from the selected callgraph artifact.", md_table(["Node", "Out-degree", "In-degree"], entry_rows),
        "## risky_functions", "Evidence: callgraph in-degree count only. Higher in-degree means more callers in the extracted graph.", md_table(["Node", "In-degree", "Out-degree", "Total degree"], risky_rows),
        "## top_connected_nodes", "Evidence: total callgraph degree count only.", md_table(["Node", "Total degree", "In-degree", "Out-degree"], top_rows),
        "## complex_functions", "Evidence: callgraph out-degree count only. Higher out-degree means the node calls more extracted targets.", md_table(["Node", "Out-degree", "In-degree", "Total degree"], complex_rows),
        "## file_dependencies", "Evidence: direct file graph edges from the file graph artifact.", md_table(["Source file", "Target file", "Evidence reason"], file_dependency_rows),
        "## core_files", "Evidence: file graph degree count only.", md_table(["File", "Total degree", "In-degree", "Out-degree"], core_file_rows),
        "## database_writes", "Evidence: actual source matches to `table/from/collection` write operations, plus caller count for the enclosing Python callgraph function when available. No name-only matching is used.", md_table(["File", "Line", "Operation", "Enclosing function", "Caller count", "Source line"], database_rows),
        "## external_calls", "Evidence: direct Python/JavaScript/TypeScript import detection, excluding stdlib and local top-level modules.", md_table(["Package/module", "Import count", "Examples"], external_rows),
        "## ui_interactions", "Evidence: direct HTML/UI element extraction from the HTML UI graph artifact.", md_table(["File", "Line", "Tag", "Attributes"], ui_rows),
        "## known_todos", "Evidence: literal TODO/FIXME-style comment extraction from repo comments.", md_table(["File", "Line", "Tag", "Text"], todo_rows),
        "## recently_changed", "Evidence: local `git log` when a `.git` directory is available; otherwise concrete GitHub commit payload from analysis if present.", md_table(["Commit", "Date", "Subject", "Files"], recent_rows),
        "## high_churn_files", "Evidence: file occurrence/change count from local git history when available; otherwise concrete GitHub changed-file payload from analysis if present.", md_table(["File", "Commit touch/change count"], high_churn_rows),
        "## stable_files", "Evidence: tracked files with zero touches in the latest 100 local git commits. Empty when no local `.git` evidence is available.", md_table(["File"], stable_rows),
    ]
    content = "\n".join(sections).rstrip() + "\n"
    output_path = Path(output_repo_dir) / "CODE.md"
    output_path.write_text(content, encoding="utf-8")
    if source_root and source_root.exists():
        try:
            source_root_resolved = source_root.resolve()
            output_root_resolved = Path(output_repo_dir).resolve()
            if source_root_resolved == output_root_resolved or output_root_resolved in source_root_resolved.parents:
                analyzed_repo_codeval_dir = source_root_resolved / "codeval"
                analyzed_repo_codeval_dir.mkdir(parents=True, exist_ok=True)
                (analyzed_repo_codeval_dir / "code.md").write_text(content, encoding="utf-8")
        except Exception as exc:
            logger.warning("Unable to copy Code.md into analyzed repository source for %s/%s: %s", owner, repo, exc)
    return str(output_path)


def analyze_response(owner, repo, repo_id, output_repo_dir, results):
    repo_stats_path = results.get("repo_stats_path", "")
    repo_comments_path = results.get("repo_comments_path", "")
    repo_text_path = results.get("repo_text_path", "")
    scim_manifest_path = results.get("scim_manifest_path", "")
    scim_vector_db_path = results.get("scim_vector_db_path", "")
    scim_embedding_model_path = results.get("scim_embedding_model_path", "")
    scim_functions_path = results.get("scim_functions_path", "")
    scim_train_pairs_path = results.get("scim_train_pairs_path", "")
    feature_catalog_path = results.get("feature_catalog_path", "")
    callgraph_code_index_path = results.get("callgraph_code_index_path", "")
    callgraph_code_index_jsonl_path = results.get("callgraph_code_index_jsonl_path", "")
    repo_stats = {}
    repo_comments = {}
    repo_text = {}
    if repo_stats_path:
        repo_stats = load_json_file(Path(repo_stats_path), {})
    if repo_comments_path:
        repo_comments = load_json_file(Path(repo_comments_path), {})
    if repo_text_path:
        repo_text = load_json_file(Path(repo_text_path), {})

    python_callgraph_html_path = results.get("python_callgraph_html_path", "")
    python_callgraph_json_path = results.get("python_callgraph_json_path", "")
    python_ordered_call_sequence_path = results.get("python_ordered_call_sequence_path", "")
    javascript_callgraph_html_path = results.get("javascript_callgraph_html_path", "")
    javascript_callgraph_json_path = results.get("javascript_callgraph_json_path", "")
    javascript_ordered_call_sequence_path = results.get("javascript_ordered_call_sequence_path", "")
    csharp_callgraph_html_path = results.get("csharp_callgraph_html_path", "")
    csharp_callgraph_json_path = results.get("csharp_callgraph_json_path", "")
    csharp_ordered_call_sequence_path = results.get("csharp_ordered_call_sequence_path", "")
    callgraph_javalang_cytoscape_html_path = results.get("callgraph_javalang_cytoscape_html_path", "")
    callgraph_javalang_json_path = results.get("callgraph_javalang_json_path", "")
    javalang_ordered_call_sequence_path = results.get("javalang_ordered_call_sequence_path", "")
